const a=[{dz:null,name_han:"道德经",name_vi:"Đạo Đức Kinh",bu:"太玄",author:"老子 (李耳)",era:"Xuân Thu",topic:"philosophy",essence:"5000 chữ nền tảng toàn đạo giáo. «Đạo» = bản thể vô hình sinh thiên địa; «đức» = đạo ứng dụng. Vô vi nhi vô bất vi, «đạo pháp tự nhiên», nhu thắng cương.",key_text:"道可道，非常道；名可名，非常名。",use:"tu tâm · 治 quốc · dưỡng sinh",sources:["https://ctext.org/dao-de-jing/zhs (CTEXT)","https://zh.wikisource.org/zh-hans/%E9%81%93%E5%BE%B7%E7%B6%93 (維基文库)"],textual_certainty:"high",notes:"老子/Xuân Thu; bản gốc không có 1 DZ# duy nhất."},{dz:null,name_han:"南华真经（庄子）",name_vi:"Nam Hoa Kinh (Trang Tử)",bu:"太玄",author:"庄周",era:"Chiến Quốc",topic:"philosophy",essence:"33 thiên. «Tề vật luận» (vạn vật bình đẳng), «tiêu dao du» (du tâm tự do tuyệt đối), «tâm trai/tọa vong». Cùng Lão → «lão trang» nền triết đạo.",key_text:"天地与我并生，而万物与我为一。",use:"tu tâm · giải thoát tinh thần",sources:["https://ctext.org/zhuangzi/zhs (CTEXT)","https://zh.wikisource.org/zh-hans/%E8%8E%8A%E5%AD%90 (維基文库)"],textual_certainty:"high",notes:"庄周/Chiến Quốc chuẩn."},{dz:null,name_han:"冲虚真经（列子）",name_vi:"Liệt Tử",bu:"太玄",author:"列御寇",era:"Chiến Quốc",topic:"philosophy",essence:"8 thiên. Chủ «quý hư» («vạn vật sinh ư hư»). «Lực-mệnh», «ngụ ngôn» kinh điển (Sở nhân ưu thiên). «Tiên» phái.",key_text:"生者，理之必终者也。",use:"tu tâm hư tịch · tiên học",sources:["https://ctext.org/liezi/zhs (CTEXT)","https://zh.wikisource.org/zh-hans/%E5%88%97%E5%AD%90 (維基文库)"],textual_certainty:"high",notes:"列御寇/Chiến Quốc."},{dz:null,name_han:"通玄真经（文子）",name_vi:"Văn Tử",bu:"太玄",author:"辛钘 (Tân Hình)",era:"Chiến Quốc-Tây Hán",topic:"philosophy",essence:"Diễn Lão tử + hợp đạo-nho-pháp. 12 thiên. «Cửu thủ» (thủ hư/tĩnh/nhược), «vô vi nhi vô bất vi» vi chính trị thực dụng.",key_text:"老子曰：道者，所谓无状之状，无物之象也。",use:"治 quốc vô vi · binh pháp",sources:["https://ctext.org/wiki.pl?if=gb&res=240539 (CTEXT)","https://zh.wikisource.org/zh-hans/%E6%96%87%E5%AD%90 (維基文库)"],textual_certainty:"partial",notes:"Tác giả/niên đại tranh cãi."},{dz:null,name_han:"淮南子",name_vi:"Hoài Nam Tử",bu:"太玄",author:"刘安 (Hoài Nam Vương)",era:"Tây Hán",topic:"philosophy",essence:"21 thiên — tập đại thành đạo gia Hán, dung hợp nho-pháp-âm dương. «Nguyên Đạo/Sơ Chân/Thiên Văn huấn». Chủ «vô vi nhi trị», thiên nhân cảm ứng.",key_text:"夫道者，覆天载地，廓四方，柝八极。",use:"治 quốc · thiên văn · thiên nhân hợp nhất",sources:["https://ctext.org/huainanzi/zhs (CTEXT)","https://zh.wikisource.org/zh-hans/%E6%B7%AE%E5%8D%97%E5%AD%90 (維基文库)"],textual_certainty:"high",notes:"Lưu An/Tây Hán; bản gốc KHÔNG thuộc chính thống 道藏."},{dz:"DZ0001",name_han:"度人经（元始无量度人上品妙经）",name_vi:"Độ Nhân Kinh",bu:"洞玄",author:"古灵宝经",era:"Đông Tấn末-Nam Triều",topic:"classic",essence:"«Đạo tạng thủ kinh» (DZ0001, mở đầu đạo tạng). Nguyên Thủy Thiên Tôn phổ độ chi pháp, dùng «phạm khí chân văn» khai độ u minh. «Tiên đạo quý sinh, vô lượng độ nhân».",key_text:"仙道贵生，无量度人",use:"度亡 · 诵经 · 灵宝斋醮",sources:["https://zh.wikisource.org/zh-hans/%E9%9D%88%E5%AF%B6%E7%84%A1%E9%87%8F%E5%BA%A6%E4%BA%BA%E4%B8%8A%E5%93%81%E5%A6%99%E7%B6%93/1 (維基文库)","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E5%85%83%E5%A7%8B%E7%84%A1%E9%87%8F%E5%BA%A6%E4%BA%BA%E4%B8%8A%E5%93%81%E5%A6%99%E7%B6%93 (daoinfo)"],textual_certainty:"high",notes:"DZ0001 đạo tạng thủ kinh."},{dz:"DZ0318",name_han:"九天生神章经",name_vi:"Cửu Thiên Sinh Thần Chương Kinh",bu:"洞玄",author:"古灵宝经",era:"Đông Tấn",topic:"cultivation",essence:"Tam nguyên hóa cửu khí → cửu thiên, mỗi thiên 1 «sinh thần chương» an trấn hồn phách. «Cửu quá vi nhất biến» → vong giả trừ tử thăng chân nhân.",key_text:"九过为一遍，一遍周竟，三界举名，五帝友敬，称为真人。",use:"度亡 · an trấn hồn phách · sinh thần",sources:["https://zh.wikisource.org/zh-hans/%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E8%87%AA%E7%84%B6%E4%B9%9D%E5%A4%A9%E7%94%9F%E7%A5%9E%E7%AB%A0%E7%B6%93 (維基文库)","https://www.shidianguji.com/book/DZ0318 (識典古籍 DZ0318)"],textual_certainty:"high",notes:"DZ0318 洞玄部本文類."},{dz:"DZ1439",name_han:"洞玄灵宝玉京山步虚经",name_vi:"Ngọc Kinh Sơn Bộ Hư Kinh",bu:"洞玄",author:"古灵宝经",era:"Đông Tấn末-Nam Triều初",topic:"ritual",essence:"Ngọc Kinh Sơn = trung tâm thế giới bộ hư nghi. Định «bộ hư» khoa thức (tụng + tuyên hành «tượng phi thăng»). Nền mọi «bộ hư từ» +斋醮 tiết tấu.",key_text:"修灵宝洞玄斋，诵空洞步虚章，先叩齿三通，咽漱三过。",use:"步虚仪 · 灵宝斋醮",sources:["https://zh.wikisource.org/zh-hans/%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E7%8E%89%E4%BA%AC%E5%B1%B1%E6%AD%A5%E8%99%9B%E7%B6%93 (維基文库)","https://www.shidianguji.com/book/DZ1439 (識典古籍 DZ1439)"],textual_certainty:"high",notes:"DZ1439 (Vạn Lịch tục đạo tạng)."},{dz:null,name_han:"灵宝无量度人上经大法",name_vi:"Linh Bảo Vô Lượng Độ Nhân Đại Pháp",bu:"洞真",author:" (đề «thiên chân hoàng nhân»; thực Tống-Nguyên-Minh biên)",era:"Tống-Nguyên",topic:"ritual",essence:"72卷 linh bảo đạo pháp TỔNG TẬP — chú疏 + 符籙 nghi + đàn trượng hành trì. «Bách khoa» khoa nghi linh bảo. ⚠ KHÔNG phải cổ linh bảo kinh, là Tống-Nguyên-Minh biên tập.",key_text:null,use:"科仪 tổng tập · 符籙斋醮",sources:["https://zh.wikisource.org/zh-hans/%E9%9D%88%E5%AF%B6%E7%84%A1%E9%87%8F%E5%BA%A6%E4%BA%BA%E4%B8%8A%E7%B6%93%E5%A4%A7%E6%B3%95 (維基文库)","https://zh.daoinfo.org/index.php?title=%E7%81%B5%E5%AF%B6%E7%84%A1%E9%87%8F%E5%BA%A6%E4%BA%BA%E4%B8%8A%E7%B6%93%E5%A4%A7%E6%B3%95 (daoinfo)"],textual_certainty:"partial",notes:"⚠ KHÔNG phải cổ linh bảo kinh; 道藏 = 洞真部·方法類 (KHÔNG phải 洞玄)."},{dz:"DZ1016",name_han:"真诰",name_vi:"Chân Cáo",bu:"太玄",author:"陶弘景",era:"Lương (~499)",topic:"classic",essence:"Bộ thư nền tảng thượng thanh — ghi «chân nhân giáng cơ» cho Dương Hi + họ Hứa (Đông Tấn); Ngụy Hoa Tồn trao truyền thượng thanh. Ghi «Bắc Đế sát quỷ đại pháp» (天蓬 chú nguồn).",key_text:"伏寻上清真经出世之源，始于晋哀帝兴宁二年…紫虚元君上真司命南岳魏夫人下降，授弟子…杨某，使作隶字写出。",use:"thư tịch gốc thượng thanh · 存思/giới 诫",sources:["https://zh.wikisource.org/wiki/%E7%9C%9F%E8%AA%A5 (維基文库)","https://ctext.org/wiki.pl?if=gb&res=80529 (CTEXT)"],textual_certainty:"high",notes:"陶弘景/Lương."},{dz:"DZ421",name_han:"登真隐诀",name_vi:"Đăng Chân Ẩn Quyết",bu:"洞玄",author:"陶弘景",era:"Lương",topic:"cultivation",essence:"Tổng tập mật quyết «đăng chân» thượng thanh — 佩符 + 存思 cửu cung chân thần + thủ nhất + phục khí + đạo dẫn. Nguyên 24-25 quyển, NAY CHỈ CÒN 3 quyển (tàn). Bổ sung «Chân Cáo».",key_text:"知白守黑，欲死不得，知黑守白，万邪消却。",use:"tu hành mật quyết · thượng thanh cultivation manual",sources:["https://zh.wikisource.org/zh-hans/%E7%99%BB%E7%9C%9F%E9%9A%B1%E8%A8%A3 (維基文库 全文)","https://www.kanripo.org/text/KR5b0105/ (Kanripo KR5b0105)"],textual_certainty:"partial",notes:"DZ421; ⚠ 洞玄部·玉诀類 (không phải 洞真); tàn 3卷."},{dz:"DZ331",name_han:"黄庭内景经",name_vi:"Hoàng Đình Nội Cảnh Kinh",bu:"洞玄",author:"魏华存 (truyền) / 上清派",era:"Đông Tấn",topic:"cultivation",essence:"Kinh cốt tủy thượng thanh do Ngụy Hoa Tồn truyền — thể thất ngôn 36 chương. Pháp «tồn tư» thân thần: ngũ tạng lục phủ đều có thần (tâm thần Đan Nguyên thủ Linh...), tâm thần chủ cung «Hoàng Đình». Tồn thần + phục khí + trừ tam thi → trường sinh.",key_text:"六腑五脏神体精，皆在心内运天经，昼夜存之自长生",use:"存思 · 存神养神 · 服气咽津 · 去三尸",sources:["https://zh.wikisource.org/zh-hans/%E9%BB%83%E5%BA%AD%E5%85%A7%E6%99%AF%E7%B6%93 (維基文库)","https://www.kanripo.org/text/KR5b0015/ (Kanripo KR5b0015)"],textual_certainty:"high",notes:"DZ331 洞玄部本文類 (verified); 魏华存/上清."},{dz:null,name_han:"上清大洞真经",name_vi:"Thượng Thanh Đại Đồng Chân Kinh",bu:"洞真",author:"三茅/杨羲 truyền → 陶弘景",era:"Đông Tấn-Lương",topic:"cultivation",essence:"«Thượng thanh nhất đại kinh» — 39 chương, mỗi chương = 1 thần chân nhân ứng 1 môn huyệt. 存思 thần + «hồi phong hỗn hợp» — tu pháp cao nhất thượng thanh.",key_text:null,use:"存思 · tu chân",sources:["https://ctext.org/wiki.pl?if=gb&res=71843 (CTEXT)","https://zh.wikipedia.org/wiki/%E4%B8%8A%E6%B8%85%E5%A4%A7%E6%B4%9E%E7%9C%9F%E7%BB%8F (維基百科)"],textual_certainty:"partial",notes:"39 chương/thần-môn hệ chuẩn."},{dz:"DZ1167",name_han:"太上感应篇",name_vi:"Thái Thượng Cảm Ứng Thiên",bu:"太清",author:" (khuyết danh; 南宋 李昌龄 truyền chú — KHÔNG phải «李昌世»)",era:"Bắc Tống末-Nam Tống",topic:"classic",essence:"Kinh khuyên thiện nền tảng đạo giáo: thiên địa có thần (司过之神/tam thi/táo thần) giám sát ghi tội phạt, «hoạ phúc vô môn, duy nhân tự triệu», «thiện ác chi báo, như ảnh tùy hình». Tích thiện trừ ác, cốt lõi tịnh âm tà/cải mệnh.",key_text:"太上曰：祸福无门，惟人自召；善恶之报，如影随形。",use:"劝善 · 改过 · cải mệnh",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%84%9F%E5%BA%94%E7%AF%87 (維基文库)","https://www.shidianguji.com/book/DZ1167 (識典古籍 DZ1167)"],textual_certainty:"high",notes:"DZ1167 太清部(辅洞神); 南宋 李昌龄 truyền chú."},{dz:null,name_han:"文昌帝君阴骘文",name_vi:"Văn Xương Đế Quân Âm Chỉ Văn",bu:"道藏辑要",author:" (khuyết danh, 托文昌; 宋-Nguyên phù bút)",era:"宋-Nguyên",topic:"classic",essence:"Khuyên «quảng hành âm chất» (tích âm đức ngầm, hành thiện không ai biết): cứu nạn/tế cấp/mẫn cô/ấn kinh/giới sát. «Âm chất = trời ngầm bảo độ người thiện»; trọng «tâm địa».",key_text:"欲广福田，须凭心地。",use:"劝善 · tích âm đức · văn vận",sources:["https://zh.wikisource.org/zh-hans/%E6%96%87%E6%98%8C%E5%B8%9D%E5%90%9B%E9%98%B4%E9%99%9F%E6%96%87 (維基文库)","https://zh.daoinfo.org/index.php?title=%E6%96%87%E6%98%8C%E5%B8%9D%E5%90%9B%E9%99%B0%E9%A8%AD%E6%96%87 (daoinfo)"],textual_certainty:"high",notes:"⚠ KHÔNG thuộc 正统道藏; chỉ 清《道藏辑要》/《藏外道书》 thu."},{dz:"DZ645",name_han:"太上老君内日用妙经",name_vi:"Thái Thượng Lão Quân Nội Nhật Dụng Diệu Kinh",bu:"洞神",author:" (khuyết danh, 托太上老君)",era:"约 Tống",topic:"cultivation",essence:"Nội nhật dụng — tĩnh tọa nội đan: «ẩm thực tắc định, cấm khẩu độc tọa, mạc khởi nhất niệm», điều tức miên miên, tâm hỏa tự giáng, thận thủy tự thăng, «thập nhị thời thường yếu thanh tĩnh». ⚠ «太上玄門日用妙 kinh» KHÔNG tồn tại — thực là «太上老君 nội/ngoại nhật dụng diệu kinh» DZ645.",key_text:"夫日用者，饮食则定，禁口独坐，莫起一念。万事俱忘，存神定意。",use:"修真 · nội đan tĩnh tọa · nhật dụng hành trì",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E5%85%A7%E6%97%A5%E7%94%A8%E5%A6%99%E7%B6%93 (維基文库)","https://www.kanripo.org/text/KR5c0026/ (Kanripo KR5c0026)"],textual_certainty:"partial",notes:"DZ645 洞神部本文類 (傷字号, thất kinh đồng quyển)."},{dz:"DZ1138",name_han:"无上秘要",name_vi:"Vô Thượng Bí Yếu",bu:"太平",author:"北周武帝/通道观学士 (王延 tham biên)",era:"Bắc Chu (~574–578)",topic:"classic",essence:"Loại thư (bách khoa) Đạo giáo xưa nhất — nguyên 100卷/292 phẩm (nay tàn 67-68卷). Hệ thống hóa vũ trụ quan/giới uy nghi/tu chân,调和 giáo phái. Cẩm nang tra cứu giáo nghĩa thời Lục triều, trước 云笈七签.",key_text:null,use:"bách khoa · tham chiếu giáo nghĩa",sources:["https://zh.wikisource.org/zh-hans/%E7%84%A1%E4%B8%8A%E7%A7%98%E8%A6%81 (維基文库)","https://www.shidianguji.com/book/DZ1138 (識典古籍 DZ1138)","https://github.com/kanripo/KR5e0040 (Kanripo KR5e0040)"],textual_certainty:"high",notes:"DZ1138 太平部; 北周武帝/通道观学士 (王延 tham biên, phi độc soạn)."},{dz:"DZ13",name_han:"高上玉皇心印妙经（心印经）",name_vi:"Tâm Ấn Kinh",bu:"洞真",author:" (khuyết danh)",era:"Đường末-Ngũ Đại-Bắc Tống",topic:"cultivation",essence:"Tâm pháp nội đan cốt tủy — tinh-khí-thần = «thượng dược tam phẩm», «thần hợp khí, khí hợp chân». 50 câu/200 chữ, «tồn vô thủ hữu/hồi phong hỗn hợp». Công khóa tất tụng hằng ngày (cùng常清静经).",key_text:"上药三品，神与气精。恍恍惚惚，杳杳冥冥。",use:"nội đan · 日诵功课",sources:["https://zh.wikisource.org/wiki/%E9%AB%98%E4%B8%8A%E7%8E%89%E7%9A%87%E5%BF%83%E5%8D%B0%E7%B6%93 (維基文库)","https://zh.daoinfo.org/index.php?title=%E9%AB%98%E4%B8%8A%E7%8E%89%E7%9A%87%E5%BF%83%E5%8D%B0%E7%B6%93 (daoinfo)"],textual_certainty:"high",notes:"DZ13 洞真部本文類; 玉皇 hệ."},{dz:"DZ332",name_han:"黄庭外景经",name_vi:"Hoàng Đình Ngoại Cảnh Kinh",bu:"太清",author:" (khuyết danh; truyền Lão Quân/魏华存)",era:"Đông Tấn (~4c, sớm hơn nội cảnh DZ331)",topic:"cultivation",essence:"Kinh dưỡng sinh tối cổ — thể thất ngôn, nền nội đan sau. Lấy Hoàng Đình-Đan Điền làm gốc, phối ân tân (nuốt «ngọc thanh») + thủ tinh + hô hấp; «tử dục bất tử tu Côn Lôn» (đỉnh đầu/thượng đan điền). Đơn giản + sớm hơn nội cảnh; Vương Hi Chi thư pháp truyền sao.",key_text:"上有黄庭下关元，后有幽阙前命门……子欲不死修昆仑。",use:"dưỡng sinh · tồn tư · nội đan sơ kỳ",sources:["https://zh.wikisource.org/zh-hans/黄庭外景经 (維基文库)","https://ctext.org/wiki.pl?if=gb&chapter=560368 (CTEXT DZ332)"],textual_certainty:"high",notes:"DZ332 (Schipper-Verellen/Brill); sớm hơn nội cảnh DZ331."},{dz:"DZ880",name_han:"太清金液神丹经",name_vi:"Thái Thanh Kim Dịch Thần Đan Kinh",bu:"太清",author:" (khuyết danh; truyền 葛玄, 葛洪 bảo tồn)",era:"Đông Tấn-Lục Triều",topic:"cultivation",essence:"Kinh quan trọng nhất hệ «Thái Thanh đạo» NGOẠI ĐAN (Pregadio: Great Clarity). Bản đạo tạng hợp nhất tam kinh (Thái Thanh/ Cửu Đan/ Kim Dịch). Dược pháp luyện đan khoáng (chu sa-kim-lưu huỳnh-thủy ngân) thành «Kim Dịch-Cửu Đan» — «ngoại luyện chi cực».",key_text:"金液丹華是天經，泰清神仙諒分明。當立精誠乃可營，玩之不休必長生。",use:"ngoại đan · luyện đan khoáng",sources:["https://ctext.org/wiki.pl?if=gb&res=559064 (CTEXT DZ880)","https://baike.baidu.com/item/%E5%A4%AA%E6%B8%85%E9%87%91%E6%B6%B2%E7%A5%9E%E4%B8%B9%E7%BB%8F (百度百科)"],textual_certainty:"high",notes:"DZ880 (Pregadio Great Clarity); tam kinh hợp nhất."},{dz:"DZ821",name_han:"太上老君养生诀",name_vi:"Thái Thượng Lão Quân Dưỡng Sinh Quyết",bu:"太清",author:" (khuyết danh, ngụy; đề «Hoa Đà truyền Ngô Phổ»)",era:"Lục Triều-Đường",topic:"cultivation",essence:"3 thiên: (1) Ngũ cầm hí (hổ-hùng-lộc-viên-ô); (2) LỤC TỰ khẩu quyết Sát-Ha-Hô-Hư-Xuy-Hi (phổi-tim-lách-gan-thận-tam tiêu); (3) Dưỡng sinh chân quyết. «Trừ lục hại, thập lục thiểu»; «thân như quốc: thần do quân, huyết do thần, khí do dân». Văn bản nguồn của «lục tự quyết» khí công.",key_text:"一人之身，一国之象也……神犹君也，血犹臣也，气犹民也。",use:"dưỡng sinh · đạo y · lục tự quyết · ngũ cầm hí",sources:["https://zh.wikisource.org/zh-hans/太上老君养生诀 (維基文库)","https://ctext.org/wiki.pl?if=gb&chapter=913232 (CTEXT DZ821)"],textual_certainty:"high",notes:"DZ821 (Schipper-Verellen Vol.3 / Jia Jinhua 2015)."},{dz:"DZ818",name_han:"太清导引养生经",name_vi:"Thái Thanh Đạo Dẫn Dưỡng Sinh Kinh",bu:"太清",author:" (khuyết danh)",era:"Lục Triều-Đường (~4c)",topic:"cultivation",essence:"Kinh tối trọng về ĐẠO DẪN (khởi công thể dục trị liệu). Ghi phép đạo dẫn của Xích Tùng Tử/Ninh tiên sinh/Vương Kiều/Bành Tổ + «bắt chước loài vật» (hạp miêu/quy/long hành khí). «Hấp nhật tinh ba thời» (nhật xuất/trung/nhập), trị bệnh cụ thể. Liên quan Mã Vương Đôi đạo dẫn.",key_text:"日初出、日中、日入，此三时向日正立，不息九通，仰头吸日精光，九咽之，益精百倍。",use:"đạo y · dưỡng sinh · đạo dẫn · hành khí",sources:["https://zh.wikisource.org/zh-hans/太清导引养生经 (維基文库)","https://ctext.org/wiki.pl?if=gb&res=297375 (CTEXT DZ818)"],textual_certainty:"high",notes:"DZ818 (Verellen 2004 / Despeux 2018 / Kohn 2008); trùng «Cổ Tiên Đạo Dẫn Án Ma Pháp»."},{dz:"DZ1208",name_han:"太上三五正一盟威箓",name_vi:"Chính Nhất Minh Uy Lục",bu:"正一",author:" (khuyết danh; truyền thống Trương Đạo Lăng/Thiên Sư đạo)",era:"Hán mạt-Ngụy Tấn (truyền 142 CN)",topic:"fu",essence:"Kinh lục TỔ của chính nhất đạo — 6 quyển ghi 24 giai pháp lục (Đồng Tử → Diên Sinh Bảo Mệnh). Truyền Lão Quân giáng thụ Trương Đạo Lăng tại Hạc Minh Sơn (142 CN); mỗi lục kèm thần tướng/khí để đạo sĩ役使. Định lập cấp bậc «Phong Lục/授箓» cốt yếu thiên sư đạo, nền chế độ授箓 đời sau.",key_text:"上屬北斗某星君，言被五炁神童君召",use:"符籙 · 24 giai Phong Lục · 役使 thần tướng · bảo mệnh trừ tà",sources:["https://www.shidianguji.com/book/DZ1208 (識典古籍 DZ1208)","https://zh.daoinfo.org/index.php?title=太上三五正一盟威箓 (daoinfo)"],textual_certainty:"high",notes:"DZ1208 正一部; truyền 142 CN Hạc Minh Sơn."},{dz:"DZ0789",name_han:"正一法文天师教戒科经",name_vi:"Chính Nhất Pháp Văn Giáo Giới Khoa Kinh",bu:"正一",author:" (khuyết danh; khả năng hậu duệ Trương Lỗ)",era:"Tào Ngụy-Lục Triều (3-5c)",topic:"ritual",essence:"5 thiên giáo giới hợp nhất quyển — mượn khung Lão Quân truyền giới cho Trương Đạo Lăng để quy phạm đạo dân: tấn kính thờ sư, hiếu dưỡng song thân, cứu bần cấp nạn, cấm dâm-bạo-ninh-độc. Nền giới luật + khoa nghi thiên sư đạo sơ kỳ, ảnh hưởng cải cách Khấu Khiêm Chi.",key_text:"奉道不可不勤，事师不可不敬，事亲不可不孝",use:"教戒/戒律 · quy phạm đạo dân · 24 trị khoa nghi",sources:["https://www.shidianguji.com/zh/book/DZ0789 (識典古籍 DZ0789)","https://zh.daoinfo.org/index.php?title=正一法文天师教戒科经 (daoinfo)"],textual_certainty:"high",notes:"DZ0789 (chính thống đạo藏 洞神部·giới luật loại; hệ Chính Nhất Pháp Văn)."},{dz:"DZ1101",name_han:"太平经",name_vi:"Thái Bình Kinh",bu:"太平",author:" (truyền 于吉 thụ thần nhân; 宫崇 hiến thư)",era:"Đông Hán mạt (2c)",topic:"classic",essence:"Kinh điển LỚN NHẤT sơ kỳ đạo giáo — nguyên 170 quyển 10 bộ (giáp-quý), hiện tồn 57. «Nguyên khí» sinh thiên-địa-nhân; «thượng hoàng thái bình khí» sắp đến; công bằng xã hội (三合相通, chống tích lũy bóc lột). Tư tưởng gốc Thái Bình Đạo (Trương Giác) + ảnh hưởng Thiên Sư đạo; dưỡng sinh thủ nhất + trị quốc trị thân song tu.",key_text:"天地开辟贵本根，乃气之元也。欲致太平，念本根也",use:"trị quốc thái bình · dưỡng sinh thủ nhất · âm dương ngũ hành",sources:["https://ctext.org/wiki.pl?if=gb&chapter=84713 (CTEXT DZ1101 合校)","https://zh.wikipedia.org/zh-cn/太平经 (維基百科)","https://en.daoinfo.org/wiki/The_Book_of_Supreme_Peace (daoinfo EN)"],textual_certainty:"high",notes:"DZ1101 太平部; nguyên 170卷 hiện 57."},{dz:"DZ1101b",name_han:"太平经钞",name_vi:"Thái Bình Kinh Sao",bu:"太平",author:"闾丘方远 (Lữ Khưu Phương Viễn, Đường mạt)",era:"Đường mạt (9-10c)",topic:"classic",essence:"Tiết lục 10 quyển do Lữ Khưu Phương Viễn soạn, theo thiên can (giáp-quý) ứng 10 bộ nguyên Thái Bình Kinh (đã tản thất). Văn bản quan trọng nhất PHỤC CỔ — Vương Minh «Thái Bình Kinh Hợp Hiệu» dựa vào nó + 27 dẫn thư khôi phục ~170 quyển.",key_text:"天下凡事，皆一阴一阳，乃能相生，乃能相养",use:"节钞 · phục cổ Thái Bình Kinh",sources:["https://zh.wikisource.org/zh-hans/太平經鈔 (維基文库)","https://www.shidianguji.com/book/DZ1101b (識典古籍 DZ1101b)"],textual_certainty:"partial",notes:"DZ1101b; Lữ Khưu Phương Viễn/Đường mạt; giáp bộ nghi hậu nhân bổ sung."},{dz:"DZ1401",name_han:"太上黄庭中景经",name_vi:"Hoàng Đình Trung Cảnh Kinh",bu:"正一",author:" (Lý Thiên Thừa 注)",era:"约 Tùy-Đường (bản hiện Tống)",topic:"cultivation",essence:"Tỳ tồn tư ngũ tạng lục phủ thần — mỗi tạng có «chân nhân» thị vệ, cả não/cơ quan đều có thần. «Thân là nơi chứa thần khí»; «luyện tồn hình thần, khắc thành vũ hóa, dĩ trí trường sinh». Hệ riêng (Hoàng Lão) nhưng hậu xuất hệ Hoàng Đình.",key_text:"为道者，莫不炼存形神，克成羽化，以致长生。",use:"tồn tư nội quan ngũ tạng · thủ hình thần bất ly",sources:["https://www.shidianguji.com/book/DZ1401 (識典古籍 DZ1401)","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E9%BB%83%E5%BA%AD%E4%B8%AD%E6%99%AF%E7%B6%93 (daoinfo)"],textual_certainty:"high",notes:"DZ1401 正一部; Lý Thiên Thừa 注."},{dz:"DZ834",name_han:"存神炼气铭（太清存神炼气五时七候诀）",name_vi:"Tồn Thần Luyện Khí Minh",bu:"洞神",author:"孙思邈 (581–682)",era:"Đường",topic:"cultivation",essence:"«Khí vi thần mẫu, thần vi khí tử» — luyện nguyên khí để an thần. «Ngũ thời» (5 thời từ tâm động → tâm thuần tịnh) + «thất hậu» (7 chứng ngộ: cố tật tiêu → thân siêu vật ngoại). «Bách nhật tiểu thành, tam niên đại thành». 云笈七签 quyển 33 đề khác.",key_text:"夫身为神气之窟宅，神气若存，身康力健；神气若散，身乃死焉。",use:"an tâm khí hải · tồn thần · luyện khí nhập tịnh",sources:["https://zh.wikisource.org/wiki/%E5%AD%98%E7%A5%9E%E9%8D%8A%E6%B0%A3%E9%8A%98 (維基文库 存神炼气铭)","https://www.shidianguji.com/book/DZ0834 (識典古籍 DZ834)"],textual_certainty:"high",notes:"DZ834 洞神部方法類; 孙思邈; 云笈七签 vol.33 = ngũ thời thất hậu quyết."},{dz:"DZ838",name_han:"养性延命录",name_vi:"Dưỡng Tính Diên Mệnh Lục",bu:"洞神",author:"陶弘景 (456–536)",era:"Nam Bắc Triều-Lương",topic:"cultivation",essence:"Tập đại thành dưỡng sinh từ Thần Nông-Hoàng Đế tới Ngụy Tấn — 2 quyển 6 thiên (giáo giới/thực giới/tạp giới/phục khí liệu bệnh/đạo dẫn án ma/ngự nữ). Trích >30 cổ tịch (nhiều thất truyền → quý phục cổ). «Ngã mệnh tại ngã, bất tại ư thiên» — chủ động tu dưỡng hình thần kiêm tu.",key_text:"夫禀气含灵，惟人为贵。人所贵者，盖贵于生。生者神之本，形者神之具。",use:"dưỡng sinh · đạo dẫn · phục khí · án ma",sources:["https://zh.wikisource.org/zh-hans/%E5%85%BB%E6%80%A7%E5%BB%B6%E5%91%BD%E5%BD%95 (維基文库)","https://ctext.org/wiki.pl?if=gb&res=733381&remap=gb (CTEXT DZ838)"],textual_certainty:"high",notes:"DZ838 洞神部方法類; 陶弘景; «我命在我不在天» khẩu hiệu."},{dz:"DZ642",name_han:"太上老君说了心经",name_vi:"Thái Thượng Lão Quân Thuyết Liễu Tâm Kinh",bu:"洞神",author:" (khuyết danh, 托太上老君)",era:"Đường (~8c)",topic:"cultivation",essence:"Kinh cực giản (~100 chữ) — «nội quan liễu tâm». «Tâm vi thần chủ, động tĩnh tòng tâm» — tâm vừa «hoạ bản» vừa «đạo tông». «Vô tâm vô động, vô tưởng vô tồn» → «liễu tâm chân tính». Thường biên cùng Nội Quan Kinh (DZ641).",key_text:"心为神主，动静从心……心为祸本，心为道宗。",use:"nội quan tu tâm · tọa vọng liễu tâm",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E4%BA%86%E5%BF%83%E7%B6%93 (維基文库)","https://ctext.org/wiki.pl?if=gb&chapter=358021 (CTEXT DZ642)"],textual_certainty:"high",notes:"DZ642 洞神部本文類; biên cùng Nội Quan Kinh DZ641."},{dz:"DZ31",name_han:"黄帝阴符经",name_vi:"Hoàng Đế Âm Phù Kinh",bu:"洞真",author:" (khuyết danh; tranh cãi 战国/寇谦之/李筌)",era:"约 Chiến Quốc-Nam Bắc Triều",topic:"classic",essence:"Kinh điển cốt tủy ~300-400 chữ, 3 thiên (thần tiên抱一演道/phú quốc an dân diễn pháp/cường binh chiến thắng diễn thuật). «Ám hợp thiên đạo» — nắm «thiên địa vạn vật chi đạo», luận «ngũ tặc/tam đạo». Hiệp dưỡng sinh-đạo thuật-binh pháp; ngắn hàm súc, Đạo gia tất tụng; Chu Hy soạn «Âm phù kinh khảo dị».",key_text:"观天之道，执天之行，尽矣。天有五贼，见之者昌。",use:"kinh điển gốc đạo gia · thiên đạo · dưỡng sinh · binh pháp",sources:["https://zh.wikisource.org/zh-hans/%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93 (維基文库)","https://baike.baidu.com/item/%E9%BB%84%E5%B8%9D%E9%98%B4%E7%AC%A6%E7%BB%8F/1404133 (百度百科)"],textual_certainty:"high",notes:"DZ31 洞真部本文類; tác giả tranh cãi (李筌 phát hiện+注)."},{dz:"DZ135",name_han:"入药镜（崔公入药镜）",name_vi:"Nhập Dược Kính",bu:"洞真",author:"崔希范 (Đường, 至一真人) / 王道渊 chú (Nguyên)",era:"Đường (nguyên tác) / Nguyên (chú)",topic:"cultivation",essence:"Khai môn nội đan — luyện «tiên thiên khí» hội «hậu thiên khí» thành đại dược. Dùng thuật ngữ chu thiên hỏa hậu (can long thăng/hồ giáng/càn khôn nung đan) hệ thống hóa luyện dược. Truyền 吕洞宾 học nội đan nơi 崔希范; ảnh hưởng 悟真篇. Bản gốc (三字诀 82 câu) KHÔNG riêng trong 道藏 — chỉ qua chú 王道渊 DZ135.",key_text:"先天炁，后天气，得之者，常似醉",use:"hệ thống «dược-hỏa hậu-chu thiên» nội đan sớm",sources:["https://zh.wikisource.org/zh-hans/%E5%85%A5%E8%97%A5%E9%8F%A1 (維基文库 入药镜)","https://ctext.org/wiki.pl?if=gb&chapter=55952 (CTEXT DZ135 王道渊注)"],textual_certainty:"high",notes:"DZ135 洞真部玉诀類 (bản注); bản gốc 82 câu không riêng trong 道藏."},{dz:"DZ130",name_han:"胎息经",name_vi:"Thai Tức Kinh",bu:"洞真",author:" (khuyết danh kinh văn; 幻真先生 chú)",era:"Lục Triều-Đường sơ (kinh); Đường (chú)",topic:"cultivation",essence:"Kinh ngắn nhất nội đan sớm — kinh văn gốc chỉ 83 chữ. «Thai từ phục khí mà kết»: cốt PHỤC KHÍ (lặng hơi thở) + «thần khí tương抱» kết «thánh thai» nơi đan điền. «Giả danh thai tức, thực viết nội đan» (chú). Nguyên lý hô hấp điểm thành cốt lõi nội đan.",key_text:"假名胎息，实曰内丹",use:"điều tức/phục khí nền nội đan",sources:["https://zh.wikisource.org/zh-hans/%E8%83%8E%E6%81%AF%E7%B6%93%E8%A8%BB (維基文库 胎息经注)","https://www.shidianguji.com/book/DZ0130 (識典古籍 DZ130)"],textual_certainty:"high",notes:"DZ130 洞真部玉诀類; kinh 83 chữ + 幻真先生 chú."},{dz:"DZ1191",name_han:"秘传正阳真人灵宝毕法",name_vi:"Linh Bảo Tất Pháp",bu:"太清",author:" (đề 钟离权 trình/吕洞宾传; thực五代-北宋 biên)",era:"Đường mạt-Ngũ Đại/Bắc Tống",topic:"cultivation",essence:"Bí điển nội đan hệ «Chung-Lã» — TAM THỪA pháp: tiểu thừa (an lạc diên niên: phối âm dương/tụ tán thủy hỏa), trung thừa (chu thiên hỏa hầu), đại thừa (quy nguyên siêu phàm). Lấy thiên địa thăng giáng + nhật nguyệt giao hội làm mẫu luyện nội đan; ảnh hưởng 钟吕传道集.",key_text:"总为三乘之法，是因阴中有阳、阳中有阴，本天地升降之宜、日月交合之理",use:"nền tảng nội đan Chung-Lã · khung tam thừa",sources:["https://zh.wikisource.org/zh-hans/%E7%A7%98%E5%82%B3%E6%AD%A3%E9%99%BD%E7%9C%9F%E4%BA%BA%E9%9D%88%E5%AF%B6%E7%95%A2%E6%B3%95 (維基文库)","https://zh.daoinfo.org/index.php?title=%E7%A7%98%E5%82%B3%E6%AD%A3%E9%99%BD%E7%9C%9F%E4%BA%BA%E9%9D%88%E5%AF%B6%E7%95%A2%E6%B3%95 (daoinfo)"],textual_certainty:"high",notes:"DZ1191 太清部 (hiệu chỉnh từ CRTA/Komjathy)."},{dz:"DZ263",name_han:"钟吕传道集（真仙传道集）",name_vi:"Chung Lã Truyền Đạo Tập",bu:"洞真",author:" (đề 钟离权述/吕岩集/施肩吾传; thực 施肩吾 hệ biên)",era:"Đường mạt-Ngũ Đại/Bắc Tống sơ",topic:"cultivation",essence:"Hệ thống hóa đỉnh cao hệ Chung-Lã — 18 đàm luận (chân tiên/đại đạo/thiên địa/nhật nguyệt/ngũ hành/thủy hỏa/long hổ/đan dược/.../chứng hiệu). Lần đầu phân linh cấp NGŨ BẬC: «quỷ tiên-nhân tiên-địa tiên-thần tiên-thiên tiên». Nền tảng lý luận nội đan全真 đạo.",key_text:"纯阴而无阳者，鬼也；纯阳而无阴者，仙也；阴阳相杂者，人也",use:"kinh nền nội đan hệ thống · ngũ tiên thuyết",sources:["https://zh.wikisource.org/zh-hans/%E9%8D%BE%E5%91%82%E5%82%B3%E9%81%93%E9%9B%86 (維基文库)","https://ctext.org/wiki.pl?if=gb&res=734873 (CTEXT DZ263)"],textual_certainty:"high",notes:"DZ263 (độc lập) + DZ1017 修真十书 q.39-41; 洞真部."},{dz:null,name_han:"老子想尔注",name_vi:"Lão Tử Tưởng Nhĩ Chú",bu:"敦煌写本",author:" (truyền 张道陵; hoặc 张鲁托名)",era:"Đông Hán (~2c, 五斗米道)",topic:"classic",essence:"Bản chú Đạo Đức kinh ĐẦU TIÊN của đạo giáo hữu tổ chức (chính nhất/thiên sư đạo). Chuyển «Đạo» triết Lão-Trang thành thần WAY hóa: đồng nhất Đạo=Nhất=Thái Thượng Lão Quân. Hệ «đạo giới», «thủ giới bất việt=thủ nhất», tích tinh thành thần → nền tảng giáo lý đạo giáo tôn giáo. ⚠ KHÔNG thuộc 道藏; chỉ 敦煌 S.6825.",key_text:"一散形为气，聚形为太上老君",use:"nguồn gốc đạo giáo tôn giáo · thiên sư đạo sơ kỳ",sources:["https://zh.wikisource.org/wiki/%E8%80%81%E5%AD%90%E6%83%B3%E7%88%BE%E6%B3%A8 (維基文库)","https://baike.baidu.com/item/%E8%80%81%E5%AD%90%E6%83%B3%E5%B0%94%E6%B3%A8/7687285 (百度百科)"],textual_certainty:"high",notes:"⚠ KHÔNG thuộc 道藏 (thất truyền cuối Đường); chỉ 敦煌 S.6825; 饶宗颐 1956 hiệu笺."},{dz:null,name_han:"老子化胡经",name_vi:"Lão Tử Hóa Hồ Kinh",bu:"敦煌残卷",author:"王浮 (Tây Tấn thiên sư đạo祭酒)",era:"Tây Tấn (~3c)",topic:"classic",essence:"Kinh TRANH LUẬN: Lão tử xuất Hàm Cốc quan Tây độ Thiên Trúc, hóa thân thành Thích Ca Mâu Ni sáng lập Phật giáo — đề cao đạo, biếm Phật. Văn bản trung tâm tranh luận Phật-Đạo nhiều thế kỷ. Bị Đường Trung Tông cấm (705), bị Nguyên triều (Möngke/1258) tàn phá — chỉ còn 敦煌 tàn quyển.",key_text:null,use:"quan hệ Phật-Đạo · «hóa hồ thuyết»",sources:["https://zh.wikipedia.org/wiki/%E8%80%81%E5%AD%90%E5%8C%96%E8%83%A1%E7%B6%93 (維基百科)","https://en.wikipedia.org/wiki/Huahujing (Wikipedia EN)"],textual_certainty:"partial",notes:"⚠ KHÔNG thuộc 道藏 (Nguyên焚毁); chỉ 敦煌 P.2004/2007/3404, S.1857/6963."},{dz:"DZ725",name_han:"道德真经广圣义",name_vi:"Đạo Đức Chân Kinh Quảng Thánh Nghĩa",bu:"洞神",author:"杜光庭 (Đỗ Quang Đình)",era:"Đường mạt-Ngũ Đại (~901)",topic:"philosophy",essence:"Bộ sớ giải lớn trên cơ sở Đường Huyền Tông «Đạo Đức chân kinh» ngự chú+sớ. Nguyên 30 quyển (道藏 bản 50). Tổng kết TRỌNG HUYỀN học Tùy-Đường (kế Thành Huyền Anh/Lý Vinh), «trọng huyền vi tông» hội tam giáo + «kinh quốc lý thân». Đại biểu chú Lão cuối Đường.",key_text:null,use:"chú Lão học Đường · trọng huyền học",sources:["https://ctext.org/wiki.pl?if=gb&res=880177 (CTEXT DZ725)","https://baike.baidu.com/item/%E9%81%93%E5%BE%B7%E7%9C%9F%E7%BB%8F%E5%B9%BF%E5%9C%A3%E4%B9%89/20106898 (百度百科)"],textual_certainty:"high",notes:"DZ725 洞神部玉诀類; 杜光庭; nguyên 30卷 道藏 bản 50卷."},{dz:"DZ662",name_han:"关尹子（无上妙道文始真经）",name_vi:"Quan Doãn Tử / Văn Thủy Chân Kinh",bu:"洞神",author:" (truyền 关令尹喜; bản hiện 余嘉锡考 hoặc Nam Tống ngụy托)",era:"truyền Xuân Thu; bản hiện Đường-Tống",topic:"philosophy",essence:"9 thiên (Nhất Vũ→Cửu Dược). Chủ: Đạo siêu việt ngôn-tư-hành-thức, «ngôn chi như xuy ảnh, tư chi như lậu trần» — thánh phàm bình đẳng cụ túc Đạo. Đạo giáo ngũ đại kinh (cùng 阴符/道德/南华/黄庭). Văn phong ngắn mật độ cao, dung nho-đạo + nội đan.",key_text:"言之如吹影，思之如镂尘",use:"triết lý đạo giáo · nội đan · chú Lão học",sources:["https://ctext.org/wiki.pl?if=gb&chapter=815201 (CTEXT DZ662)","https://zh.daoinfo.org/index.php?title=%E6%96%87%E5%A7%8B%E7%9C%9F%E7%B6%93%E8%A8%BB (daoinfo)"],textual_certainty:"high",notes:"DZ662 洞神部本文類 (hệ太玄 phụ); chú: 牛道淳直解(Nguyên)/陈显微言外旨(Nam Tống)."},{dz:"DZ16",name_han:"九天应元雷声普化天尊玉枢宝经（玉枢经）",name_vi:"Ngọc Xu Kinh (Lôi Kinh)",bu:"洞真",author:" (khuyết danh; liên hệ 白玉蟾/神霄 phái)",era:"Bắc Tống末-Nam Tống",topic:"classic",essence:"Kinh cốt lõi LÔI PHÁP thần tiếu phái — Cửu Thiên Ứng Nguyên Lôi Thanh Phổ Hóa Thiên Tôn (tối cao lôi thần) thuyết pháp. Xưng niệm một tiếng danh hiệu → Ngài hóa hình mười phương, giải 15 thứ tai ách (ôn dịch/quan phi/hình khắc/thổ kỵ/sản nạn...). «Khí số» trói thiên mệnh, vượt qua bằng trì tụng xưng danh.",key_text:"愿于未来世，一切众生……一称吾名，悉使超涣。",use:"trì tụng hóa giải tai ách · xưng danh giải nạn · nền 神霄 lôi pháp",sources:["https://zh.wikisource.org/zh-hans/九天应元雷声普化天尊玉枢宝经 (維基文库)","https://ctext.org/wiki.pl?if=gb&chapter=426046 (CTEXT DZ16)"],textual_certainty:"high",notes:"DZ16 洞真部本文類 (CRTA verified); 集注 DZ99 玄阳子."},{dz:"DZ1442",name_han:"太上三元赐福赦罪解厄消灾延生保命妙经（三官经）",name_vi:"Tam Quan Kinh",bu:"续道藏",author:" (khuyết danh)",era:"Minh (Vạn Lịch tục đạo tạng)",topic:"classic",essence:"Kinh tụng nhật dụng đạo giáo (cùng 早/晚坛 công khóa + 北斗 kinh hợp «tứ kinh cơ bản»). Nương Tam Nguyên tam quan đại đế: THƯỢNG nguyên Thiên quan TỨ PHÚC, TRUNG nguyên Địa quan XÁ TỘI, HẠ nguyên Thủy quan GIẢI ÁCH. Trì tụng sám tội → tiêu tai diên sinh «bảo mệnh».",key_text:"天官赐福，地官赦罪，水官解厄。",use:"tụng kinh sám tội tiêu tai · cầu phúc giải ách",sources:["https://zh.wikisource.org/wiki/太上三元賜福赦罪解厄消災延生保命妙經 (維基文库)","https://baike.baidu.com/item/太上三元赐福赦罪解厄消灾延生保命妙经 (百度百科)"],textual_certainty:"high",notes:"DZ1442 续道藏 (Vạn Lịch); «tứ kinh cơ bản» đạo tục."},{dz:"DZ1233",name_han:"重阳立教十五论",name_vi:"Trùng Dương Lập Giáo Thập Ngũ Luận",bu:"正一",author:"王嚞 (王重阳, 1112–1170)",era:"Kim",topic:"cultivation",essence:"Văn hiến NHẬP MÔN cốt lõi toàn chân đạo — tổ Vương Trùng Dương soạn, 1 quyển ngắn. 15 điều chia 3 nhóm: quy phạm xuất gia (trú am/vân du/học thư/hợp đạo bạn), công phu nội đan tâm tánh (đả tọa/giáng tâm/luyện tánh), tông chỉ lập giáo. Cốt: động-tĩnh điều hòa, nội luyện tâm tánh, nền教 chế toàn chân.",key_text:"凡出家者，先须投庵。庵者舍也，一身依倚……心渐得安，气神和畅，入真道矣。",use:"cương yếu lập giáo + nội đan nhập môn toàn chân",sources:["https://zh.wikisource.org/wiki/重陽立教十五論 (維基文库)","https://www.shidianguji.com/zh/book/DZ1233 (識典古籍 DZ1233)"],textual_certainty:"high",notes:"DZ1233 正一部; 王重阳/全真."},{dz:"DZ466",name_han:"灵宝领教济度金书",name_vi:"Linh Bảo Lãnh Giáo Tế Độ Kim Thư",bu:"洞玄",author:" (宁全真 truyền; 林灵真 编; Nguyên-Minh tăng bổ)",era:"Nam Tống-Minh sơ",topic:"ritual",essence:"TỔNG TẬP khoa nghi trai độ LỚN NHẤT linh bảo đông hoa phái — ~320 quyển, ĐỒ SỘ NHẤT đạo tạng. Trù bị nghi quỹ: khai độ/thí thực/thủy hỏa luyện độ/phá ngục(huyết hồ)/thượng chương/thiết độ/chuyển kinh/phù-trụện. Tông chỉ «tế độ vong hồn, thoát minh quan, trọc chất hoàng hoa». Tư liệu gốc quan trọng bậc nhất lịch sử nghi lễ Tống-Nguyên-Minh.",key_text:null,use:"khoa nghi trai độ tổng tập · tế độ vong hồn · linh bảo đông hoa",sources:["https://ctext.org/wiki.pl?if=gb&res=311747 (CTEXT DZ466)","https://www.shidianguji.com/zh/book/DZ0466 (識典古籍 DZ466)"],textual_certainty:"high",notes:"DZ466 洞玄部威仪類; ~320卷 (đồ sộ nhất đạo tạng); 目录 DZ465."},{dz:"DZ1110",name_han:"净明忠孝全书",name_vi:"Tịnh Minh Trung Hiếu Toàn Thư",bu:"太平",author:"黄元吉 编 (Lưu Ngọc ngữ lục chủ thể)",era:"Nguyên (~1320s)",topic:"cultivation",essence:"Kinh điển cốt lõi TỊNH MINH đạo — 6 quyển (q.3-5 ngữ lục tổ Lưu Ngọc). Dung hợp NHO-ĐẠO: «Tịnh minh chỉ là chính tâm thành ý, trung hiếu chỉ là phù duy cương thường». Công phu «trừng phẫn trất dục, minh lý bất muội tâm thiên» — tu tiên đạo trước hết tu nhân đạo, bất ly nhật dụng thường hành.",key_text:"净明只是正心诚意，忠孝只是扶植纲常。",use:"cương yếu tịnh minh đạo · trung hiếu lập bản + nội luyện tâm tánh",sources:["https://ctext.org/wiki.pl?if=gb&chapter=213566 (CTEXT DZ1110)","https://www.shidianguji.com/zh/book/DZ1110 (識典古籍 DZ1110)"],textual_certainty:"high",notes:"DZ1110 太平部; 黄元吉编/刘玉语 lục; Nguyên."},{dz:"DZ1220",name_han:"道法会元",name_vi:"Đạo Pháp Hội Nguyên",bu:"正一",author:" (khuyết danh; Thanh Vi phái; Triệu Nghi Chân hệ)",era:"Nguyên mạt-Minh sơ (~1382-1445)",topic:"ritual",essence:"TỔNG TẬP đạo pháp LỚN THỨ NHÌ Minh đạo tạng (268卷), thu >150 thiên pháp thuật Tống-Nguyên lấy LÔI PHÁP làm cốt. «Căn ở tâm, pháp ở thiên» — nội đan nội luyện kết hợp phù chú ngoại dụng. Văn hiến then chốt nghiên cứu lôi pháp/phù chú/ấn khế/thần tướng (Vương Linh Quan/Mã Nguyên Soái...) Tống-Minh.",key_text:null,use:"lôi pháp · phù chú · thần tướng · khoa nghi Tống-Minh",sources:["https://zh.wikisource.org/zh-hans/道法會元 (維基文库)","https://www.shidianguji.com/zh/book/DZ1220 (識典古籍 DZ1220)"],textual_certainty:"high",notes:"DZ1220 正一部 (Schipper vol.28-30); 268卷; lôi pháp đại biên."},{dz:"DZ856",name_han:"三皇内文遗秘（三皇经/三皇文）",name_vi:"Tam Hoàng Kinh",bu:"洞神",author:" (khuyết danh; truyền Bão Tĩnh Tây Tấn; 葛洪/陆修静 từng đắc)",era:"Lục Triều (bản nguyên) / Đường-Tống (bản Di Bí)",topic:"fu",essence:"Kinh cốt tủy ĐỘNG THẦN bộ — hợp Thiên Hoàng/Địa Hoàng/Nhân Hoàng «Nội Văn» + Hoàng Thần Việt Chương bí ấn + Ngũ Nhạc Chân Hình Đồ. Nguyên Tam Hoàng kinh bị Đường hoàng thất (ngữ thiệp yêu vọng) PHÂN HỦY; bản Di Bí = tàn dư duy nhất. Chủ «hạt triệu quỷ thần», 符图 + tồn tư chân hình — nguồn gốc phù chú đạo giáo.",key_text:null,use:"nguồn gốc động thần bộ phù chú · triệu quỷ thần",sources:["https://www.shidianguji.com/zh/book/DZ0856 (識典古籍 DZ856)","https://zh.wikipedia.org/zh-cn/三皇文 (維基百科)"],textual_certainty:"partial",notes:"DZ856 洞神部; nguyên kinh 唐焚, bản Di Bí = tàn dư; 「太上三皇内秘遗 kinh」 là biến thể tên."},{dz:"DZ441",name_han:"洞玄灵宝五岳古本真形图（五岳真形图）",name_vi:"Ngũ Nhạc Chân Hình Đồ",bu:"洞玄",author:" (đề Hán·东方朔 biên; thực Hán mạt-Ngụy Tấn)",era:"Hán mạt-Ngụy Tấn",topic:"fu",essence:"Một trong những PHÙ-ĐỒ CỔ NHẤT đạo giáo — kết hợp bản đồ thần thánh + phù-asemic: vẽ hình thế 5 Nhạc (Thái/Hành/Tung/Hoa/Hằng) + 4山镇 thành ký hiệu uốn lượn như chữ. Chức năng kép: bản đồ tu-phương (không lạc núi) + phù trừ «binh hung nghịch». 葛洪《抱朴子》tôn là đạo thư tối trọng cùng Tam Hoàng Nội Văn.",key_text:"家有五岳真形图，能避兵凶逆，人欲害之者皆还反受其殃。",use:"phù-đồ sơn nhạc · địa lý thần thánh · nguồn gốc «đồ sấm/phù đồ»",sources:["https://zh.wikisource.org/zh-hans/洞玄灵宝五岳古本真形图 (維基文库)","https://www.shidianguji.com/book/DZ0441 (識典古籍 DZ441)"],textual_certainty:"high",notes:"DZ441 洞玄部·灵图類 (KHÔNG 洞神); 葛洪抱朴子 trích dẫn."},{dz:"DZ171",name_han:"清微仙谱",name_vi:"Thanh Vi Tiên Phổ",bu:"洞真",author:"陈泰 编 (đệ tử Hoàng Thuấn Thân hệ)",era:"Nguyên (1293, Chí Nguyên quý tỵ)",topic:"classic",essence:"ĐẠO PHẢ chính thức thanh vi phái — 1 quyển (+phụ lục 3), thuật truyền thừa «thủy ư Nguyên Thủy → Ngọc Thần+Lão Quân →» tới tổ Đường mạt Tổ Thư → chín đời Nam Tất Đạo → Hoàng Thuấn Thân (Nam Tống) đại hoằng. Văn hiến then chốt xây hệ phổ thanh vi; giải thích vì sao đa số tác phẩm thanh vi trong đạo tạc (kể cả 道法会元 q.1-7) xuất tự hệ Hoàng Thuấn Thân.",key_text:null,use:"đạo phả thanh vi phái · lôi pháp lịch sử",sources:["https://zh.wikisource.org/wiki/清微仙譜 (維基文库)","https://zh.daoinfo.org/index.php?title=清微仙譜 (daoinfo)"],textual_certainty:"high",notes:"DZ171 洞真部·谱录類 (CRTA/Brill/Schipper verified; ⚠ KHÔNG phải DZ930)."},{dz:"DZ666",name_han:"西升经（老子西升经）",name_vi:"Tây Thăng Kinh",bu:"太玄",author:" (托老君授关令尹喜; thực Ngụy Tấn-Lưu Tống lâu quán đạo; Tống Huy Tông chú)",era:"Ngụy Tấn-Lưu Tống (5-6c)",topic:"classic",essence:"Kinh ghi Lão quân dạy quan lệnh Doãn Hỷ khi «tây thăng» du 竺干 (Ấn Độ). Đạo = tự nhiên vô vi («không nói, kẻ nói không biết»), kết hợp dưỡng sinh + tĩnh tịch + TRỌNG HUYỀN. Một trong kinh nền mở đường đạo giáo dung hợp Phật-Lão.",key_text:"老君西升，开道竺干；号古先生，善入无为；不终不始，永存绵绵。",use:"trọng huyền triết học · Lão-Doãn Hỷ truyền thuyết · Phật-Lão đối thoại",sources:["https://zh.wikisource.org/zh-hans/%E8%A5%BF%E6%98%87%E7%B6%93 (維基文库 西升经)","https://baike.baidu.com/item/%E8%80%81%E5%AD%90%E8%A5%BF%E5%8D%87%E7%BB%8F/15625084 (百度百科)"],textual_certainty:"high",notes:"DZ666 (Tống Huy Tông 政和注); 集注 DZ726 陈景元."},{dz:"DZ1437",name_han:"太上老君开天经",name_vi:"Khai Thiên Kinh",bu:"续道藏",author:" (khuyết danh; 《广弘明集》quy na 张泮 tạo)",era:"Nam Bắc Triều (5-6c)",topic:"classic",essence:"Kinh SÁNG THẾ — Thái Thượng Lão Quân giáng làm «sư» mỗi kỷ vũ trụ: Hồng Nguyên→Hỗn Nguyên→Thái Sơ→Thái Thủy→Thái Tố→Hỗn Độn→Cửu Cung→Nguyên Hoàng — mỗi lần «khẩu thổ kinh» khai thiên lập địa, sinh nhật nguyệt, dạy dân củ hỏa/canh tác/lập quân sư. Kiến «Lão Quân sáng thế thần phổ» cạnh tranh Phật Bàn Cổ/Nho thánh thần.",key_text:"太初之时，老君从虚空而下，为太初之师，口吐《开天经》一部，四十八万卷。",use:"đạo giáo sáng thế thần thoại · Lão Quân hóa thân phổ · phản Phật biện luận",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E9%96%8B%E5%A4%A9%E7%B6%93 (維基文库)","https://baike.baidu.com/item/%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E5%BC%80%E5%A4%A9%E7%BB%8F/9698838 (百度百科)"],textual_certainty:"high",notes:"DZ1437 万历续道藏 (Schipper)."},{dz:"DZ296",name_han:"历世真仙体道通鉴（仙鉴）",name_vi:"Lịch Thế Chân Tiên Thể Đạo Thông Giám",bu:"洞真",author:"赵道一 (全阳子, 1294)",era:"Nguyên (1294)",topic:"classic",essence:"TIÊN TRUYỆN TẬP ĐẠI THÀNH — 53 quyển chính biên (Hoàng Đế→Tống mạt: Vương Trùng Dương/Lâm Linh Tố/Vương Văn Khanh...) + 5 tục biên + 6 hậu tập (nữ tiên). Biên niên + kỷ truyện, hàng trăm chân tiên. Soạn vì «nho có Tư Trị Thông Giám, Phật có Thích Thị Thông Giám, đạo giáo độc阙» — lấp trống sử ký đạo giáo.",key_text:"常观儒家有《资治通鉴》，释门有《释氏通鉴》，惟吾道教斯文独阙。",use:"đạo giáo tiên truyện · sử liệu chân nhân lịch đại",sources:["https://ctext.org/wiki.pl?if=gb&res=591421 (CTEXT DZ296)","https://zh.wikipedia.org/zh-cn/%E5%8E%86%E4%B8%96%E7%9C%9F%E4%BB%99%E4%BD%93%E9%81%93%E9%80%9A%E9%89%B4 (維基百科)"],textual_certainty:"high",notes:"DZ296 (chính); 续 DZ297, 后 DZ298; 洞真部记传類; 赵道一 1294."},{dz:"DZ770",name_han:"犹龙传",name_vi:"Do Long Truyện",bu:"洞神",author:"贾善翔 (Tự Hồng Cử, Bắc Tống)",era:"Bắc Tống (~1086-1100)",topic:"classic",essence:"Thái Thượng Lão Quân THẦN THOẠI HÓA truyện 6 quyển — từ «khởi vô thủy, bẩm tự nhiên» qua vô số kiếp, Lão Quân hóa thân làm sư các thiên đế/vua nhân gian. Tên mượn lời Khổng Tử khen Lão Tử «kỳ do long tà» (như rồng khó dò).",key_text:"老子之号，因元而出，在天地之前，无衰老之期，故曰老子。",use:"Lão Tử/Lão Quân thần thoại phổ · đạo giáo tự thần thánh sử quan",sources:["https://ctext.org/wiki.pl?if=gb&res=466275 (CTEXT DZ770)","https://zh.daoinfo.org/index.php?title=%E7%8C%B6%E9%BE%8D%E5%82%B3 (daoinfo)"],textual_certainty:"high",notes:"DZ770 洞神部谱录類; 贾善翔/北 Tống."},{dz:"DZ240",name_han:"玉清金笥青华秘文金宝内炼丹诀（青华秘文）",name_vi:"Thanh Hoa Bí Văn",bu:"洞真",author:" (đề 张伯端; 门人 王邦叔 辑; học giới nghi ngụy托)",era:"Bắc Tống (11-12c)",topic:"cultivation",essence:"Bí văn nội đan nam tông — hệ thống theo tinh-khí-thần, «tâm vi quân, thần vi chủ»: lấy nguyên thần làm chủ tể, nguyên tinh/khí làm kim đan đại dược. «Học đạo tiên tu liễu tâm kiến tính». Thiền-đạo dung hợp. Các thiên «tâm vi quân luận/thần vi chủ luận/khí vi dụng thuyết/tinh tòng khí thuyết/ý vi môi thuyết» kèm đồ.",key_text:"心者，神之舍也，为万化纲维枢纽。",use:"nền tâm-tính nội đan hạ thủ · thu tâm tĩnh định",sources:["https://zh.wikisource.org/zh-hans/玉清金笥青华秘文金宝内炼丹诀 (維基文库)","https://www.shidianguji.com/book/DZ0240 (識典古籍 DZ240)"],textual_certainty:"high",notes:"DZ240 洞真部方法類; đề张伯端/王邦叔辑 (nghi ngụy托)."},{dz:"DZ1081",name_han:"金丹四百字",name_vi:"Kim Đan Tứ Bách Tự",bu:"太玄",author:" (đề 张伯端; 黄自如 chú 1241)",era:"Bắc Tống (nguyên) / Nam Tống (chú)",topic:"cultivation",essence:"Đúc kết yếu chỉ kim đan trong ~400 chữ ca quyết — chân thổ cầm chân chì, chân chì chế chân thủy, «đồng quy chân thổ». Dùng chì-thủy-thổ làm ẩn ngữ cho tiên thiên nhất khí. Chú 黄自如 giải dược-vật-hỏa hầu.",key_text:"真土擒真铅，真铅制真汞；铅汞归真土，身心寂不动。",use:"khẩu quyết dược-vật(thổ/铅/汞) · thủ ý",sources:["https://ctext.org/wiki.pl?if=gb&chapter=456536 (CTEXT DZ1081)","https://www.shidianguji.com/book/DZ1081 (識典古籍 DZ1081)"],textual_certainty:"high",notes:"DZ1081 太玄部; 张伯端/黄自如注."},{dz:"DZ1091",name_han:"还源篇",name_vi:"Hoàn Nguyên Thiên",bu:"太玄",author:"石泰 (字得之, 杏林/翠玄子, 南宗二祖)",era:"Bắc Tống",topic:"cultivation",essence:"81 bài ngũ ngôn tuyệt cú (ứng 9×9 dương số) của NHỊ TỔ Thạch Thái — tự thuật sau «kim dịch giao kết, thánh thai viên thành» được 张伯端 truyền khẩu. Chủ ý «hoàn nguyên» (trả bản nguồn), khuyến tu giả mau tầm sư luyện kim đan («lão lai chì hư thủy thiểu»).",key_text:"及其金液交结、圣胎圆成，泰故作《还源篇》八十一章。",use:"giáo khoa 81 Arya tiến cảnh · Nam tông nhị tổ đích truyền",sources:["https://zh.wikisource.org/wiki/還源篇 (維基文库)","https://ctext.org/wiki.pl?if=gb&chapter=907600 (CTEXT DZ1091)"],textual_certainty:"high",notes:"DZ1091 太玄部; 石泰/南宗二祖; sư 张伯端."},{dz:null,name_han:"还丹复命篇（附丹髓歌）",name_vi:"Hoàn Đơn Phục Mệnh Thiên",bu:"太玄",author:"薛道光 (紫贤/道源, 南宗三祖, 1078–1191)",era:"Bắc Tống末-Nam Tống初 (序 1126)",topic:"cultivation",essence:"Ngũ ngôn tuyệt cú (16) + thất ngôn tuyệt cú (32) + «đan tủy ca» của TAM TỔ Tiết Đạo Quang (原 tăng pháp hiệu tử hiền, sau ngộ 石泰 được kim đan khẩu quyết chuyển đạo). Tông thừa «ngộ chân thiên», luận thái dược-trừu thêm-hỏa hầu-cân lượng, «phiến thời kiến hiệu».",key_text:null,use:"khẩu quyết hỏa hầu-trừu thêm · Nam tông tam tổ đích truyền",sources:["https://zh.wikisource.org/zh-hans/还丹复命篇 (維基文库)","https://zh.daoinfo.org/wiki/還丹復命篇 (daoinfo)"],textual_certainty:"partial",notes:"太玄部 (正统道藏 742; 中华道藏 1077 — hệ khác); DZ Schipper chưa xác nhận → null."},{dz:"DZ1090",name_han:"翠虚篇（紫清指玄集 — 白玉蟾, 藏外）",name_vi:"Thúy Hư Thiên",bu:"太玄",author:"翠虚篇: 陈楠 (南木, 翠虚/陈泥丸, 南宗四祖) / 紫清指玄集: 白玉蟾 (葛长庚, 紫清, 南宗五祖)",era:"Nam Tống",topic:"cultivation",essence:"翠虚篇 1 quyển (紫庭经/大道歌/罗浮翠虚吟/金丹诗诀) — cốt «thiên cú vạn cú hội nhất ngôn: giáo nhân chỉ tại tầm chì-thủy nhị vật, thái nhập đỉnh trung tiễn». Truyền THÁI ẤT ĐAO QUÂ kim đan quyết cho ngũ tổ 白玉蟾. 紫清指玄集 (Bạch Ngọc Đường) KHÔNG độc lập trong正统道藏 (nội dung tương quan trong DZ1088 修真十书).",key_text:"篇篇皆露金丹旨，千句万句会一言。",use:"kim châm «thái chì-thủy nhị vật nhập đỉnh» · Nam tông tứ-ngũ tổ đích truyền",sources:["https://zh.wikisource.org/zh-hans/翠虚篇 (維基文库)","https://baike.baidu.com/item/翠虚篇/9687021 (百度百科)"],textual_certainty:"high",notes:"DZ1090 太玄部 (陈楠四祖); 紫清指玄集(白玉蟾五祖)=藏外, tương quan DZ1088."},{dz:"DZ1114",name_han:"太上洞玄灵宝本行宿缘经",name_vi:"Bản Hành Túc Duyên Kinh",bu:"太平",author:" (khuyết danh; 托 葛玄/太极真人 vấn đáp)",era:"Đông Tấn (~4-5c)",topic:"classic",essence:"Giả托葛仙公 hỏi:因何 tu hành mà hiện thế thụ phúc, tử tôn xướng xích? Chân nhân đáp — mỗi người có «BẢN HÀNH TÚC DUYÊN MỆNH CĂN», họa phúc đều do tiên thế BẢN NGUYỆN. Phát bản nguyện + phụng thượng thập giới + quảng kiến phước điền → chuyển nghiệp/đổi mệnh («tội phúc chi báo như ảnh tùy hình»). Trực tiếp phục vụ «cải mệnh/nghịch thiên» — nhấn mạnh nghiệp có thể chuyển bằng bản nguyện.",key_text:"夫人生各有本行宿缘命根，种种相因，愿愿相随……祸福相引，皆由先愿也。",use:"linh bảo 宿缘/业力 + 本愿 chuyển hóa · cải mệnh",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E6%9C%AC%E8%A1%8C%E5%AE%BF%E7%B7%A3%E7%B6%93 (維基文库)","https://ctext.org/wiki.pl?if=gb&chapter=229132 (CTEXT DZ1114)"],textual_certainty:"high",notes:"DZ1114 太平部 (=《太极左仙公请问经》下卷); «改命/转业» giáo nghĩa cốt."},{dz:"DZ23",name_han:"太上洞玄灵宝诸天灵书度命妙经",name_vi:"Chư Thiên Linh Thư Độ Mệnh Diệu Kinh",bu:"洞真",author:" (khuyết danh)",era:"Đông Tấn末-Nam Triều初",topic:"classic",essence:"Nguyên Thủy Thiên Tôn «tại Đại Phúc Đường Quốc Trường Lạc Xá» cùng chư thiên đại thánh + phi thiên thần vương, nghe chúng sinh bi khấp → vi thượng đạo quân quảng thuyết «chư thiên linh thư độ mệnh phẩm» 4 chương — thiên trung linh âm/ngọc thư. Tụng → chiêu thần thị vệ/điệu hình hồn; vong giả đắc độ, sinh giả diên niên. Nền linh bảo độ vong/cứu khổ.",key_text:"元始天尊时于大福堂国长乐舍中，与诸天大圣众、飞天神王俱坐七色宝云。",use:"度亡 · 临终 độ mệnh · linh bảo thiên giới",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E8%AB%B8%E5%A4%A9%E9%9D%88%E6%9B%B8%E5%BA%A6%E5%91%BD%E5%A6%99%E7%B6%93 (維基文库)","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E8%AB%B8%E5%A4%A9%E9%9D%8F%E6%9B%B8%E5%BA%A6%E5%91%BD%E5%A6%99%E7%B6%93 (daoinfo)"],textual_certainty:"high",notes:"DZ23 洞真部本文類; 陆修静《灵宝经目》已著录; nghĩa疏 DZ98."},{dz:"DZ87",name_han:"元始无量度人上品妙经四注",name_vi:"Độ Nhân Kinh Tứ Chú",bu:"洞真",author:"陈景元 (碧虚子) tập chú (hội 严东/薛幽栖/李少微/成玄英 tứ gia)",era:"Bắc Tống (1067, trị bình tứ niên)",topic:"classic",essence:"《Độ nhân kinh》(đạo tạng thủ kinh) TỐI QUYỀN UY TẬP CHÚ — 陈景元 hội nam Tề-Đường tứ gia chú sớ (严东/薛幽栖/李少微/成玄英), chủ hãm vũ trụ nguyên thỉ/tam giới ngũ khí/thần chân nội húy/ma vương danh húy/«tiên đạo quý sinh độ nhân vô lượng». Nghiên cứu «độ nhân kinh» lục triều-Đường-Bắc Tống diễn dịch sử.",key_text:"道言：昔于始青天中，碧落空歌，大浮黎土，受元始度人无量上品。",use:"đường-tống vũ trụ luận/độ nhân tư tưởng · độ nhân kinh tất 读 chú",sources:["https://ctext.org/wiki.pl?if=gb&res=452900 (CTEXT DZ87)","https://zh.daoinfo.org/index.php?title=%E5%85%83%E5%A7%8B%E7%84%A1%E9%87%8F%E5%BA%A6%E4%BA%BA%E4%B8%8A%E5%93%81%E5%A6%99%E7%B6%93%E5%9B%9B%E6%B3%A8 (daoinfo)"],textual_certainty:"high",notes:"DZ87 洞真部玉诀類; 陈景元 tập chú 1067 (⚠ KHÔNG phải 徽宗注; 徽宗 chỉ thu vào政和道藏)."},{dz:"DZ22",name_han:"元始五老赤书玉篇真文天书经",name_vi:"Ngũ Lão Xích Thư Ngọc Thiên Chân Văn Kinh",bu:"洞真",author:" (khuyết danh)",era:"Đông Tấn (~4-5c); 陆修静《灵宝经目》著录",topic:"fu",essence:"CỔ LINH BẢO KINH THỦ KINH — «chân văn/thiên thư» tín ngưỡng cốt. Quyển thượng: 5 phương XÍCH THƯ NGỌC THIÊN CHÂN VĂN ~680 chữ triện, sinh nguyên thỉ chi tiên/không động chi trung, do ngũ phương NGŨ LÃO chưởng lục (4 vạn kiếp nhất xuất). Quyển trung: thần phù triệu thần sắc quỷ/phong sơn chế hà. Thư phù phục/đái → triệu thần nhiếp quỷ/tai tai phục ma. NGUỒN GỐC PHÙ LỤC khoa nghi đạo giáo.",key_text:"《元始洞玄灵宝赤书玉篇真文》，生于元始之先，空洞之中……幽幽冥冥，无祖无宗，灵文晻蔼，乍存乍亡。",use:"phù lục/khoa nghi根基 · ngũ phương ngũ lão · chân văn tín ngưỡng",sources:["https://zh.wikisource.org/zh-hans/%E5%85%83%E5%A7%8B%E4%BA%94%E8%80%81%E8%B5%A4%E6%9B%B8%E7%8E%89%E7%AF%87%E7%9C%9F%E6%96%87%E5%A4%A9%E6%9B%B8%E7%B6%93 (維基文库)","https://ctext.org/wiki.pl?if=gb&chapter=563548 (CTEXT DZ22)"],textual_certainty:"partial",notes:"DZ22 洞真部本文類 (cổ linh bảo kinh thủ); 5 phương xích thư chân văn ~680 tự triện."},{dz:null,name_han:"性命圭旨",name_vi:"Tính Mệnh Khuê Chỉ",bu:"道藏辑要",author:" (tương truyền 尹真人 cao đệ ghi; Dư Vĩnh Ninh tựa khắc)",era:"Minh (in 1615, Vạn Lịch 43)",topic:"cultivation",essence:"Kinh điển ĐỒ-THUYẾT nội đan Minh đại tiêu biểu — chia nguyên-han-lợi-trinh TỨ TẬP, dùng hệ tranh đồ diễn giải TOÀN BỘ tính mệnh song tu: trúc cơ luyện kỹ → luyện tinh hóa khí → luyện khí hóa thần → luyện thần hoàn hư. Nho-Thích-Đạo đều «tính mệnh song tu»; trọng tâm-tính; sách nhập môn nội đan lưu truyền rộng nhất. ⚠ KHÔNG thuộc正统道藏; 道藏辑要.",key_text:"欲修长生，须识所生之本；欲求不死，当明不死之人……认得不死人。",use:"hệ thống nội đan 4 giai đoạn · tính-mệnh song tu đồ thuyết",sources:["https://zh.wikisource.org/zh-hans/性命圭旨 (維基文库)","https://baike.baidu.com/item/性命双修万神圭旨/17618917 (百度百科)"],textual_certainty:"high",notes:"⚠ KHÔNG thuộc正统道藏; Minh 1615 in; 道藏辑要 thu."},{dz:"DZ699",name_han:"道德会元",name_vi:"Đạo Đức Hội Nguyên",bu:"洞神",author:"李道纯 (清庵/莹蟾子, 中派)",era:"Nguyên (1290, chí nguyên 27)",topic:"cultivation",essence:"Cương yếu «TRUNG PHÁI» nội đan — chú giải Đạo Đức kinh từ góc nội đan, lấy «thủ trung/hư trung» làm cốt tủy, hội đạo đức chi chỉ quy nhất nguyên. Dùng Đạo Đức kinh làm khung, dung nho-thích-đạo, khai «trung phái» nội đan.",key_text:"窃谓伏羲画易，剖露先天；老子著书，全彰道德。此二者，其诸经之祖乎。",use:"trung phái nội đan · chú道德-by-đan đạo · «thủ trung» huyền quan khiếu",sources:["https://zh.wikisource.org/zh-hans/道德会元 (維基文库)","https://www.shidianguji.com/book/DZ0699 (識典古籍 DZ699)"],textual_certainty:"high",notes:"DZ699 洞神部玉诀類; 李道纯/中派; Nguyên 1290."},{dz:"DZ250",name_han:"三天易髓",name_vi:"Tam Thiên Dị Tủy",bu:"洞真",author:"李道纯 (莹蟾子) soạn; 王道渊 (混然子) hiệu chỉnh",era:"Nguyên",topic:"cultivation",essence:"Tác phẩm «TAM GIÁO HỢP NHẤT» tiêu biểu trung phái — 4 thiên (Nho-thái cực/Đạo-kim đan/Thích-viên giác/Âm phù kinh), dùng quẻ hào Kinh Dịch (tiềm long vật dụng/kiến long tại điền...) giải HỎA HẬU nội đan, chứng tam giáo đồng nguyên = nội đan phục khí chi đạo.",key_text:"下手立丹基，休将子午推。",use:"chứng tam giáo đồng nguyên · Dịch lý giải nội đan hỏa hầu",sources:["https://www.shidianguji.com/zh/book/DZ0250 (識典古籍 DZ250)","https://zh.wikisource.org/wiki/三天易髓 (維基文库)"],textual_certainty:"high",notes:"DZ250 洞真部方法類; 李道纯 soạn/王道渊 hiệu."},{dz:"DZ105",name_han:"太上大通经（李道纯注）",name_vi:"Thái Thượng Đại Thông Kinh",bu:"洞真",author:" (kinh khuyết danh; 李道纯 chú)",era:"kinh Đường-trước / chú Nguyên",topic:"cultivation",essence:"Đoản kinh 3 chương (Chân Không/Huyền Lý/Huyền Diệu) ngôn giản ý sâu — «đạo tiên thiên nhi sinh, sinh nhi vô hình», tâm-tính biện chứng «TÂM SINH TÍNH DIỆT, TÂM DIỆT TÍNH HIỆN», cảnh «như không vô tướng, trạm nhiên viên mãn». 李道纯 chú, gắn trung hoà tâm-học; cương yếu nội quan tâm-tính toàn chân.",key_text:"先天而生，生而无形；后天而存，存而无体……心生性灭，心灭性现。",use:"nội quan tâm-tính · «tâm diệt tính hiện» tu trì",sources:["https://ctext.org/wiki.pl?if=gb&chapter=387109 (CTEXT DZ105)","https://www.shidianguji.com/book/DZ0105 (識典古籍 DZ105)"],textual_certainty:"high",notes:"DZ105 洞真部玉诀類 (Schipper 3-2428); 李道纯 chú."},{dz:"DZ1168",name_han:"太上老君中经（老子中经）",name_vi:"Lão Tử Trung Kinh",bu:"太清",author:" (khuyết danh; 托老君/Lão tử)",era:"Ngụy-Tấn (~3c; có lẽ cuối Đông Hán)",topic:"cultivation",essence:"Kinh TỒN TƯ THÂN THẦN nền tảng bậc nhất Ngụy-Tấn (ngang Hoàng Đình kinh). Mô tả hệ thân thần cư ngụ: Đạo Quân/Thái Nhất ngự Tử Phương cung, Xích Tử (Chân Nhân Tử Đan) ngồi hướng nam trong Vị Quản/Thái Thương + các thần đan điền-tâm-can-tỳ-phế-thận. Quan tưởng + hoàn đan kim dịch + dưỡng khí lễ tuyền. «Nhân thân chính là Lão tử/Xích Tử»; tương ứng vũ trụ (Côn Luân/ngũ nhạc/tinh tú) soi nội tạng — TIỀN ĐỀ trực tiếp cho tồn tư + nội đan sau.",key_text:"常存真人子丹，居胃管太仓之中，坐而南向，食黄精赤气，饮而飨醴泉。",use:"nguồn gốc tồn tư thân thần · nền nội đan học (Pregadio: Origins of Inner Alchemy)",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E4%B8%AD%E7%B6%93 (維基文库)","https://www.goldenelixir.com/taoism/texts_laozi_zhongjing.html (Golden Elixir)"],textual_certainty:"high",notes:"DZ1168 太清部 (2卷); cũng trong 云笈七签 q.18-19; Pregadio nghiên cứu nguồn nội đan."},{dz:"DZ871",name_han:"太上除三尸九虫保生经（三尸中经）",name_vi:"Trừ Tam Thi Cửu Trùng Bảo Sanh Kinh",bu:"洞神",author:" (khuyết danh)",era:"六朝-Đường (kinh) / 唐末-Ngũ đại (DZ871 bản)",topic:"cultivation",essence:"Văn nền tín ngưỡng TAM THI — trong bụng có 3 «giun xác»: thượng thi Bành Cư (đầu: mờ mắt/rụng tóc), trung thi Bành Chất (bụng: tham thực), hạ thi Bành Kiệu (chân: hiếu sắc). Đêm CANH THÂN lên trời tâu tội Thiên Đế → tuyệt sinh tịch/giảm lộc mệnh. Phương cốt: THỦ CANH THÂN (thức trắng đêm, 7 lần → tam thi trường tuyệt) + tị cốc + phù dược trừ cửu trùng.",key_text:"人之生也，皆寄形于父母胞胎，饱味于五谷精气，是以人之腹中各有三尸九虫，为人大害。常以庚申之日，上告天帝。",use:"守庚申 tục · tị cốc trừ thi · tín ngưỡng tam thi",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E9%99%A4%E4%B8%89%E5%B0%B8%E4%B9%9D%E8%9F%B2%E4%BF%9D%E7%94%9F%E7%B6%93 (維基文库)","https://ctext.org/wiki.pl?if=gb&res=997344 (CTEXT DZ871)"],textual_certainty:"partial",notes:"DZ871 洞神部方法類 (唐末-Ngũ đại); «太上三尸中经» (=「说」phi chuẩn) lưu qua云笈七签 q.81-83/永乐大典 q.912."},{dz:"DZ786",name_han:"太上老君经律",name_vi:"Thái Thượng Lão Quân Kinh Luật",bu:"洞神",author:" (khuyết danh; thiên sư đạo sớm)",era:"Nam Bắc Triều (~6c)",topic:"classic",essence:"Tập GIỚI LUẬT ordination thiên sư đạo sớm. Nguyên 5 thiên, nay 2: «đạo đức tôn kinh giới»(cửu hành, nhị thập thất giới) + «LÃO QUÂN BÁT THẬP GIỚI»(180 giới, nam-quan đồng thụ). 180 giới nổi danh với nhiều giới bảo vệ môi trường/sinh thái (cấm thiêu dã điền sơn lâm) — ngày nay nghiên cứu dưới góc đạo đức sinh thái.",key_text:null,use:"giới luật ordination thiên sư đạo sớm · đạo đức/môi trường giới luật",sources:["https://www.shidianguji.com/book/DZ0786 (識典古籍 DZ786)","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E7%B6%93%E5%BE%8B (維基文库)"],textual_certainty:"high",notes:"DZ786 洞神部戒律類; 老君百八十戒 (sinh thái giới luật)."},{dz:"DZ1207",name_han:"太上明鉴真经",name_vi:"Minh Giám Chân Kinh",bu:"正一",author:" (khuyết danh; 托老君)",era:"Nam Bắc Triều-Đường",topic:"cultivation",essence:"Kinh KÍNH GIÁM TỒN TƯ — Lão tử dạy «TỨ QUY CHI ĐẠO»: 4 gương trong suốt (9 thốn/1尺2寸) treo trước-sau-trái-phải, soi mặt thanh minh vô tì vết, tồn tư thông thần → kiến thần đồng ngọc nữ/phân thân tán hình/nhập thủy hỏa/trường sinh. Kết hợp nhật nguyệt kính pháp (tri cát hung) + phục dược + trừ tam thi. Văn nền kính giám thuật thượng thanh (cùng DZ1206 上清明鉴要经).",key_text:"昔我先师，以尺二寸镜，前后左右各一焉，名曰四规。",use:"kính giám tồn tư · soi gương thông thần · nghệ thuật gương đạo giáo",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%98%8E%E9%91%91%E7%9C%9F%E7%B6%93 (維基文库)","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%98%8E%E9%91%91%E7%9C%9F%E7%B6%93 (daoinfo)"],textual_certainty:"high",notes:"DZ1207 正一部 (满字号); kính giám tứ quy thượng thanh."},{dz:"DZ186",name_han:"太微仙君功过格",name_vi:"Thái Vi Công Quá Cách",bu:"洞真",author:"又玄子 (西山会真堂无忧轩)",era:"Kim (1171, đại định tân mão)",topic:"ritual",essence:"CÔNG-QUÁ CÁCH (sổ ghi điểm thiện-ác) CỔ NHẤT còn sót — 又玄子 mộng du Tử Phủ bái yết Thái Vi Tiên Quân được thụ. «Công cách» 36 điều (cứu tế/giáo điển/phân tu/dụng sự) + «quá luật» 39 điều; mỗi ngày ghi công-quá vào sổ đầu giường «không được giấu quá ghi công». MẪU GỐC toàn hệ công-quá cách Đạo-Phật-Nho sau → nền TRỰC TIẾP cho thuyết «NGHỊCH THIÊN CẢI MỆNH».",key_text:"余于大定辛卯之岁，仲春二月子正之时，梦游紫府，朝礼太微仙君，得受功过之格，令传信心之士。",use:"khung điểm số công-quá · tự đánh giá thiện-ác · công cụ cải mệnh tại gia",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E5%BE%AE%E4%BB%99%E5%90%9B%E5%8A%9F%E8%BF%87%E6%A0%BC (維基文库)","https://www.shidianguji.com/zh/book/DZ0186 (識典古籍 DZ186)"],textual_certainty:"high",notes:"DZ186 洞真部戒律類; công quá cách cổ nhất; 又玄子 Kim 1171; nền «Nghịch Thiên Cải Mệnh»."},{dz:"DZ10",name_han:"高上玉皇本行集经（玉皇经）",name_vi:"Ngọc Hoàng Bản Hành Tập Kinh",bu:"洞真",author:" (khuyết danh; 托原始天尊 thuyết)",era:"Đường末-Nam Tống",topic:"classic",essence:"Kinh cốt lõi tín ngưỡng NGỌC HOÀNG — 3 quyển 5 phẩm, Nguyên Thủy Thiên Tôn tại Thanh Vi Thiên cung thuyết về «bản hành» (tiểu sử tu hành) của Ngọc Hoàng Đại Thiên Tôn + công đức quả báo tụng kinh. Nền cho Ngọc Hoàng sám pháp + lễ Ngọc Hoàng hội.",key_text:null,use:"tụng/khấn Ngọc Hoàng · cầu phước/tiêu tai/hộ mệnh",sources:["https://zh.wikisource.org/zh-hans/%E9%AB%98%E4%B8%8A%E7%8E%89%E7%9A%87%E6%9C%AC%E8%A1%8C%E9%9B%86%E7%B6%93 (維基文库)","https://ctext.org/wiki.pl?if=en&res=122537&remap=gb (CTEXT DZ10)"],textual_certainty:"high",notes:"DZ10 洞真部本文類 (Schipper Companion 3.B.7); 玉皇 tín ngưỡng."},{dz:"DZ457",name_han:"太上洞玄灵宝智慧罪根上品大戒经",name_vi:"Trí Huệ Tội Căn Đại Giới Kinh",bu:"洞玄",author:" (khuyết danh; cổ linh bảo kinh quần)",era:"Đông Tấn末-Nam Triều初 (陆修静灵宝经目)",topic:"ritual",essence:"Một trong GIỚI KINH LINH BẢO CỔ XƯA NHẤT — Nguyên Thủy Thiên Tôn tại Tây Na Ngọc Quốc uất sát sơn phù la cảnh truyền «trí huệ thượng phẩm đại giới». Thiết lập cơ chế SÁM HỐI TIÊU TỘI (đốt hương/thắp đèn/thiết trai/sám tội) để tiêu diệt «tội căn» — gốc rễ nghi thức linh bảo sám sau.",key_text:"尔时天尊以开皇元年七月一日午时，于西那玉国郁察山中浮罗之境香桑林，所授太上道君智慧上品大戒法文。",use:"giới luật · sám hối tiêu tội · tịnh hóa «tội căn»",sources:["https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E6%99%BA%E6%85%A7%E7%BD%AA%E6%A0%B9%E4%B8%8A%E5%93%81%E5%A4%A7%E6%88%92%E7%B6%93 (維基文库)","https://ctext.org/wiki.pl?if=gb&chapter=889269 (CTEXT DZ457)"],textual_certainty:"high",notes:"DZ457 洞玄部戒律類 (Companion 1.B.3 Lingbao); cổ linh bảo giới kinh."},{dz:null,name_han:"太上老君说百病崇百药经",name_vi:"Bách Bệnh Sùng Bách Dược Kinh",bu:"洞神",author:" (khuyết danh; 托老君)",era:"约 Lục Triều-Đường",topic:"classic",essence:"Khuynh thiện đoản kinh — Lão Quân khẩu kể 100 «bệnh» (thiếu sót đạo đức/tâm hành) + 100 «dược» (thiện hạnh đối trị). Chủ chỉ: «phòng dễ hơn cứu, bị tốt hơn trị» — tu thân tích đức là thuốc hay nhất, nhân có bệnh do lỗi ác ẩn. ⚠ Schipper Companion KHÔNG có entry «shuo baibing»; nội dung đồng源 玄都律文 (DZ188, 洞真戒律) phần «bách dược luật».",key_text:"老君曰：救灾解难，不如防之为易；疗疾治病，不如备之为吉。",use:"check-list 100 bệnh đức + 100 thuốc thiện · tự soi/sửa mình · cải mệnh tại gia",sources:["https://zh.wikisource.org/wiki/%E7%8E%84%E9%83%BD%E5%BE%8B%E6%96%87 (維基文库 玄都律文)","https://zh.daoinfo.org/index.php?title=%E7%8E%84%E9%83%BD%E5%BE%8B%E6%96%87 (daoinfo)"],textual_certainty:"partial",notes:"⚠ đồng源 玄都律文 DZ188 (Schipper); «shuo baibing» phi entry độc lập."},{dz:"DZ1122",name_han:"太上洞玄灵宝升玄内教经（升玄经）",name_vi:"Thăng Huyền Kinh",bu:"洞玄",author:" (khuyết danh; 托太上道君/老君 vi thiên sư张道陵 thuyết; Đường có述议疏)",era:"Nam Bắc Triều (~5c, 刘宋); nguyên 10卷 Nguyên sơ vong dật",topic:"classic",essence:"Thiên sư đạo + linh bảo dung hợp đại kinh — giả托张道陵 vấn đạo太上, lập «TRUNG HÒA» chi giáo + cấm giới thứ đệ, hệ thống hóa giới luật + kinh lục truyền thụ nghi. Nguyên kinh 10卷 Nguyên sơ vong dật; nay nương 敦煌 tàn + 道藏 q.7 «trung hòa phẩm» Đường sơ.(partial: DZ# = bản Đường chú疏, phi nguyên kinh).",key_text:"太上道君告天师张道陵曰：修道明诀，得道原由，次第品格，谨敬之法，中和之科，长生之教，禁戒之仪。",use:"giới luật đạo giáo Đường-Lục triều · truyền kinh-lộ nghi · «中和之科»",sources:["https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%8A%E9%9D%88%E5%AF%B6%E6%98%87%E7%8E%84%E5%85%A7%E6%95%99%E7%B6%93%E4%B8%AD%E5%92%8C%E5%93%81%E8%BF%B0%E8%AD%B0%E7%96%8F (維基文库 中和品述议疏)","https://baike.baidu.com/item/%E5%8D%87%E7%8E%84%E7%BB%8F/18825371 (百度百科 升玄经)"],textual_certainty:"partial",notes:"DZ1122 (太平部, bản Đường chú疏); nguyên kinh 10卷 lost; 敦煌 ~20 tàn + 道藏 trung hòa phẩm tồn."},{dz:"DZ400",name_han:"洞玄灵宝定观经",name_vi:"Định Quan Kinh",bu:"洞玄",author:" (kinh khuyết danh; 冷虚子 chú Đường)",era:"Nam Bắc Triều末-Đường",topic:"cultivation",essence:"Đạo giáo TÍNH CÔNG hai đại căn kinh (cùng 常清静经). Thiên tôn cáo tả huyền chân nhân: XẢ SỰ → an tọa → NỘI QUAN tâm khởi → trừ diệt vọng niệm → vật ngã cụ vong, liệt «ĐẮC ĐẠO THẤT HẬU» (tâm định→cố tật tiêu→hoàn niên→tiên nhân→chân nhân→thần nhân→chí nhân) làm chứng nghiệm thứ đệ.",key_text:"夫欲修道，先能舍事，外事都绝，无与忤心，然后安坐，内观心起；若觉一念起，须除灭，务令安静。",use:"tĩnh tọa/định lực · nội quán niệm đầu · 7 tầng chứng nghiệm",sources:["https://zh.wikisource.org/zh-hans/%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E5%AE%9A%E8%A7%80%E7%B6%93 (維基文库)","https://www.shidianguji.com/book/DZ0400 (識典古籍 DZ400)"],textual_certainty:"high",notes:"DZ400 洞玄部玉诀類 (冷虚子 chú Đường); 杜光庭广圣义 đã dẫn; 云笈七签 thu."},{dz:"DZ18",name_han:"太上虚皇天尊四十九章经",name_vi:"Hư Hoàng Kinh (49 Chương)",bu:"洞真",author:" (khuyết danh; 托虚皇天尊 vi diệu hành chân nhân diễn thuyết)",era:"约 Tùy-Đường",topic:"classic",essence:"Hư Hoàng Thiên Tôn diễn 49 chương tu đạo cương lĩnh: lập công/zhai giới/thức bản lai/thiện ứng/tích thiện vi bảo/trừ cấu/vị đạo... lấy thanh tĩnh vô vi vi tông, phân TAM THỪA học đạo, khuyến zhai giới bố thí đoạn phiền não — nhập đạo + giới hành giản minh cương yếu.",key_text:"天尊曰：凡欲修道，建功为先。是以诸天上帝、诸天高尊……咸以功勤超圣真位。",use:"cẩm nang 49 chương giới điều tu đạo · «lập công/thập thiện/đoạn phiền não»",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E8%99%9B%E7%9A%87%E5%A4%A9%E5%B0%8A%E5%9B%9B%E5%8D%81%E4%B9%9D%E7%AB%A0%E7%B6%93 (維基文库)","https://ctext.org/wiki.pl?if=gb&res=713444 (CTEXT DZ18)"],textual_certainty:"high",notes:"DZ18 洞真部本文類 (CRTA); pairing 初真十戒."},{dz:"DZ35",name_han:"太上玄都妙本清净身心经",name_vi:"Huyền Đô Diệu Bản Kinh",bu:"洞真",author:" (khuyết danh)",era:"约 Tùy-Đường",topic:"cultivation",essence:"Nguyên Thủy Thiên Tôn tại Huyền Đô thất bảo lâm tử ngọc cung, đối thượng đạo quân/pháp giải chân nhân thuyết: chúng sinh thân tâm BẢN LAI THANH TỊNH, cấu nị đều do vọng chấp nghiệp lụy; thị «tẩy dục thân tâm» vô vi pháp môn, dung phật gia tâm tính luận, xuất ly sinh tử luân hồi.",key_text:"妙本常清净，身心无垢腻；众生习业人，迷惑怀疑贰。",use:"thanh tịnh tâm-thân · sám nghiệp/tẩy tâm (pairing常清静经 + 定观经 thành bộ tâm-thân thanh tịnh)",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E7%8E%84%E9%83%BD%E5%A6%99%E6%9C%AC%E6%B8%85%E9%9D%9C%E8%BA%AB%E5%BF%83%E7%B6%93 (維基文库)","https://ctext.org/wiki.pl?if=gb&chapter= (CTEXT DZ35)"],textual_certainty:"partial",notes:"DZ35 洞真部本文類 (Schipper/CRTA; đạo藏提要/Baidu hoặc ghi洞神部 — phân loại nhỏ tranh cãi)."},{dz:"DZ885",name_han:"黄帝九鼎神丹经诀",name_vi:"Cửu Đỉnh Thần Đan Kinh Quyết",bu:"洞神",author:" (khuyết danh; 托黄帝/玄女; kinh本文 Hán mạt, chú quyết Ngụy-Tấn-Đường)",era:"Hán mạt-Đường (20卷)",topic:"cultivation",essence:"Kinh ĐẠI BIỂU NGOẠI ĐAN đạo giáo — chủ chỉ: muốn trường sinh mà chỉ hô hấp đạo dẫn/uống thảo mộc thì chỉ diên niên rồi cũng chết, duy «THẦN ĐAN KIM DỊCH» mới giúp thành tiên độ thế. Ghi cửu đỉnh 9 đan (Huyền Hoàng/Đan Hoa/Thần Phù/Hoàn Đan...) + phương luyện chế-phục dụng + chọn sư thụ quyết. Nguồn sử liệu trọng yếu luyện đan Hán-Đường.",key_text:"凡欲长生，而不得神丹金液，徒自苦耳。",use:"lý luận nền ngoại đan · «thảo mộc diên niên, thần đan độ thế thành tiên»",sources:["https://zh.wikisource.org/zh-hans/%E9%BB%83%E5%B8%9D%E4%B9%9D%E9%BC%8E%E7%A5%9E%E4%B8%B9%E7%B6%93%E8%A8%A3 (維基文库)","https://ctext.org/wiki.pl?if=gb&res=104526&remap=gb (CTEXT DZ885)"],textual_certainty:"high",notes:"DZ885 洞神部众术類; 20卷; kinh本文 Hán mạt + chú quyết Ngụy-Tấn-Đường."},{dz:"DZ410",name_han:"太上老君内观经",name_vi:"Nội Quan Kinh",bu:"洞神",author:" (khuyết danh; 托老君; «thất kinh đồng quyển»)",era:"约 Nam Bắc Triều末-Tùy-Đường",topic:"cultivation",essence:"Kinh ngắn NỘI QUAN (quán chiếu bên trong) — nền tâm tính luận đạo giáo. «Tĩnh thần định tâm, loạn tưởng bất khởi, tà vọng bất xâm»; nhắm mắt nội sát → thanh tịnh hợp đạo. Mô tả thụ thai thành hình từng tháng (nhất nguyệt vi bào...thập nguyệt thành hình) + phương tu tâm kiến tính. Kế Liệt tử «quý hư», chịu thượng thanh ảnh hưởng.",key_text:"内观之道，静神定心，乱想不起，邪妄不侵，固身及物，闭目思寻，表里虚寂，神道微深。",use:"nội quan tâm pháp · «tu tâm kiến tính»",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E5%85%A7%E8%A7%80%E7%B6%93 (維基文库)","https://www.quanxue.cn/ct_daojia/neiguan/neiguan02.html (quanxue)"],textual_certainty:"partial",notes:"DZ410 洞神部本文類 (thất kinh đồng quyển cùng 说了心经/内丹经/真定经); DZ# web chưa trực tiếp xác nhận."},{dz:"DZ1193",name_han:"太上正一咒鬼经（老君咒鬼）",name_vi:"Chính Nhất Chú Quỷ Kinh",bu:"正一",author:" (khuyết danh; ngụy托正一真人/天师)",era:"Nam Bắc Triều (Lục triều)",topic:"ritual",essence:"Kinh thần chú TRỪ TÀ của chính nhất thiên sư đạo — ngụy托天 sư lên Thái Sơn yết Hoàng Lão Quân nhận «sát quỷ ngữ» thần phương. Mượn chú triệu LỤC GIÁP/LỤC ĐINH/Hoàng Thần/Việt Chương/Hoa Cái/Khôi Cương thiên binh → chém quỷ diệt yêu/trị tà bệnh/giải tai. Cốt tủy «lão quân咒 quỷ» hệ chú thuật, ảnh hưởng 后世《太上三洞神咒》.",key_text:"天师曰：吾上太山，谒见黄老君，教吾杀鬼，语我神方。上呼玉女，收捕非殃，登天左契，佩带印章，头戴华盖，足蹑魁罡。",use:"trừ tà trảm quỷ · trị tà bệnh · giải quan ngục/thủy hỏa · hộ thân trấn trạch",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%AD%A3%E4%B8%80%E5%92%92%E9%AC%BC%E7%B6%93 (維基文库)","https://ctext.org/wiki.pl?if=gb&res=534468 (CTEXT DZ1193)"],textual_certainty:"high",notes:"DZ1193 正一部; Lục triều; ảnh hưởng 太上三洞神咒."},{dz:"DZ673",name_han:"太上老君混元三部符",name_vi:"Hỗn Nguyên Tam Bộ Phù",bu:"洞神",author:" (khuyết danh; có thuyết Đường-Tống)",era:"Đường",topic:"fu",essence:"KHO PHÙ LỤC LỚN của hỗn nguyên bộ — 3 quyển thu 740+ đạo THẦN PHÙ theo thượng/trung/hạ tam bộ. Loại: Đô Tượng/Giải Uế/An Trạch/Diên Niên/Tịch Quỷ/Tịch Ôn/Hộ Thân/Yểm Bách Quái/Tỉnh Quái/Tri Chu Trùng/Tuyển Phong/An Thai/Lợi Điền Tằm... — bao trùm trừ tà/yểm quái dị/an trạch hộ thai/nông tang cát tường.",key_text:null,use:"phù lục thủy · yểm trấn quái dị · an trạch hộ thai · trừ ôn dịch · nông tang cát",sources:["https://ctext.org/wiki.pl?if=gb&res=500668 (CTEXT DZ673)","https://www.shidianguji.com/zh/book/DZ0673 (識典古籍 DZ673)"],textual_certainty:"low",notes:"DZ673 洞神部神符類; 740+ 符; ⚠ «tam bộ bí lục» phi chuẩn (đạo tạng chỉ có «tam bộ phù»)."},{dz:"DZ295",name_han:"续仙传",name_vi:"Tục Tiên Truyện",bu:"洞真",author:"沈汾 (Nam Đường phò mã)",era:"Đường mạt-Ngũ Đại/Nam Đường (k.937-975)",topic:"classic",essence:"Tiếp dòng tiên truyện (Liệt Tiên/Thần Tiên truyện) — chép 36 vị đắc đạo từ Đường-Ngũ Đại đủ mọi giai tầng. Tự «sinh nhi mộ đạo», sợ tiên sự tán thất nên biên lục. Nguồn quan trọng cho 云笈七签 + sau là 历世真仙体道通鉴.",key_text:"古今神仙，举世知之，然飞腾隐化，俗难可睹。",use:"tiên truyện/hagiography Đường mạt-Ngũ Đại",sources:["https://ctext.org/wiki.pl?if=gb&res=735257&remap=gb (CTEXT DZ295)","https://baike.baidu.com/item/%E7%BB%AD%E4%BB%99%E4%BC%A0/6237216 (百度百科)"],textual_certainty:"high",notes:"DZ295 洞真部记传類; 沈汾/Nam Đường; 36 vị."},{dz:"DZ299",name_han:"疑仙传",name_vi:"Nghi Tiên Truyện",bu:"洞真",author:"隐夫玉简 (Tứ khố suy nối Tống nhân)",era:"Ngũ Đại-Bắc Tống sơ",topic:"classic",essence:"Chép 22 DỊ NHÂN (Lý Nguyên/Cát Dụng/bán dược ông...) đời Đường Khai Nguyên về sau. Đặc: «không dám tiện lấy tiên thần làm tên» mà đề «Nghi Tiên» — lưỡng lự giữa hoài nghi + tín ngưỡng, tự định vị hiếm trong dòng tiên truyện. Thường bị 三洞群仙录 (DZ1238) trích dẫn.",key_text:"夫神仙之事，自古有之。其间混迹，固不可容易而测也。",use:"tiên truyện Tống sơ · thường pairing 三洞群仙录 DZ1238",sources:["https://zh.wikisource.org/zh-hans/%E7%96%91%E4%BB%99%E5%82%83 (維基文库)","https://baike.baidu.com/item/%E7%96%91%E4%BB%99%E4%BC%A0/6237268 (百度百科)"],textual_certainty:"high",notes:"DZ299 洞真部记传類; 隐夫玉简; 22 dị nhân."},{dz:"DZ335",name_han:"太上洞渊神咒经",name_vi:"Động Uyên Thần Chú Kinh",bu:"洞玄",author:" (khuyết danh; 托太上道君; 杜光庭 đặt tự)",era:"Đông Tấn mạt-Lưu Tống (~400-420 lõi) → Đường-Ngũ Đại (20卷)",topic:"ritual",essence:"Kinh NỀN ĐỘNG UYÊN PHÁI — Thái Thượng cùng chư thiên ma vương/quỷ vương lập «thệ ước» hộ đạo trừ tai; đạo sĩ dùng THẦN CHÚ + CHUYỂN KINH để trừng ma phạt quỷ/trị bệnh tiêu tai. Nguồn trực tiếp hệ Động Uyên Thần Chú Trai nghi (DZ525-527) + tiền thân giáo lý LÔI PHÁP/BẮC ĐẾ pháp.",key_text:"道言：吾昔在三天之上，为诸男女说无量经，教化一切。",use:"kinh mẫu thần chú-phạt ma · nền động uyên phái · trừ ôn dịch",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E6%B7%B5%E7%A5%9E%E5%92%92%E7%B6%93/1 (維基文库)","https://www.shidianguji.com/zh/book/DZ0335 (識典古籍 DZ335)"],textual_certainty:"high",notes:"DZ335 洞玄部本文類; 20卷 (lõi Đông Tấn ~400-420); 敦煌 k.664 + đạo tạng 20卷 bản."},{dz:"DZ9",name_han:"太上一乘海空智藏经",name_vi:"Hải Không Trí Tạng Kinh",bu:"洞真",author:"黎元兴 + 方惠长 (Đường Cao Tông)",era:"Đường sơ (~nửa sau 7c)",topic:"classic",essence:"ĐẠI THỪA ĐẠO GIÁO kinh điển tiêu biểu — mượn «nhất thừa»(Pháp Hoa) + «hải-không»(Bát-nhã không) + danh tướng Phật giáo diễn nói hư tĩnh vô vi đạo gia. 10 phẩm, đối thoại Nguyên Thủy Thiên Tôn—Hải Không Trí Tàng chân sĩ, dấu Duy-ma/Bát-nhã/Nê-hoàn — ĐỈNH CAO DUNG HỢP PHẬT-ĐẠO đời Đường.",key_text:"尔时，海空智藏见元始天尊遍游他土，至极乐国妙岳之山，安坐正心……与诸弟子千三百人皆得洞观，了达无碍。",use:"Đường đại đạo giáo dung nhiếp Phật giáo · «hải-không» tam tướng nghĩa",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E4%B8%80%E4%B9%98%E6%B5%B7%E7%A9%BA%E6%99%BA%E8%97%8F%E7%B6%93 (維基文库)","https://www.shidianguji.com/zh/book/DZ0009 (識典古籍 DZ9)"],textual_certainty:"high",notes:"DZ9 洞真部本文類 (Komjathy+Pregadio verified; ⚠ net nhầm DZ10/HY369 — đều sai)."},{dz:"DZ78",name_han:"太上三洞神咒",name_vi:"Tam Động Thần Chú",bu:"洞真",author:" (khuyết danh)",era:"Tống-Nguyên (11-13c)",topic:"mantra",essence:"Bộ ĐẠI TẬP thần chú LỚN NHẤT đạo giáo — hợp 780+ chú ngữ, chủ yếu LÔI CHÚ (triệu dịch lôi tướng, cầu mưa/tạnh, trừ tà, hàng ma, tịnh đàn). Câu thức tứ ngôn. KHO THAM CHIẾU TRUNG TÂM cho mọi hệ lôi pháp (thần tiêu/thanh vi/thiên tâm); nguồn gốc đa số chú ngữ đạo giáo hiện đại.",key_text:"天地玄宗，万炁本根。（卷一·金光神咒起首）",use:"tra cứu/tụng niệm chú ngữ lôi pháp · triệu thỉ/sách役 thần tướng · trừ tà/tịnh đàn",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E4%B8%89%E6%B4%9E%E7%A5%9E%E5%91%92 (維基文库)","https://www.shidianguji.com/zh/book/DZ0078 (識典古籍 DZ78)"],textual_certainty:"high",notes:"DZ78 洞真部本文類; 12卷; 780+ chú; kho thần chú trung tâm."},{dz:"DZ1225",name_han:"道门科范大全集",name_vi:"Đạo Môn Khoa Phạm Đại Toàn Tập",bu:"正一",author:" (主体 杜光庭 删定; 仲励 续修 27卷)",era:"Đường mạt-Ngũ Đại (主体 901-933) / Nam Tống-Nguyên",topic:"ritual",essence:"Zhai jiao KHOA PHẠM TẬP ĐẠI THÀNH đạo giáo — 87 quyển, hệ thống hóa + quy phạm hóa nghi thức các phái Nam-Bắc triều→Đường-Tống. 16 loại zhai nghi (sanh nhật bản mệnh/sám nhường tật bệnh/tiêu tai tinh diệu/lính bảo thái nhất cầu vũ/cầu tự đại tế/an trạch/giải nhường tinh vận/nam-bắc nhị đẩu diên sanh...). Khoa phạm Đỗ Quang Đình định ra DÙNG ĐẾN NAY — nền quy phạm đạo giáo hiện đại.",key_text:null,use:"nguồn quy phạm mẫu cho zhai jiao: thiết đàn/bái chương/sám bệnh/tiêu tai/cầu tự/an trạch/lễ đẩu",sources:["https://zh.wikisource.org/zh-hans/%E9%81%93%E9%96%80%E7%A7%91%E7%AF%84%E5%A4%A7%E5%85%A8%E9%9B%86 (維基文库)","https://www.shidianguji.com/zh/book/DZ1225 (識典古籍 DZ1225)"],textual_certainty:"high",notes:"DZ1225 正一部; 87卷; 杜光庭主体 + 仲励续修 27卷."},{dz:"DZ1227",name_han:"太上助国救民总真秘要",name_vi:"Tổng Chân Bí Yếu",bu:"正一",author:"元妙宗 (天心派 đạo sĩ) 编集",era:"Bắc Tống (1116, chính hòa 6)",topic:"fu",essence:"Bí thư NỀN TẢNG THIÊN TÂM PHÁI — chủ thuật «thượng thanh bắc cực thiên tâm chính pháp», 10 quyển hợp 符/咒/印/禹步/考召/trừ tà trị bệnh. Trung tâm quyền phép = «Bắc Cực Trà Tà Viện». THIÊN TÂM chính pháp = TIỀN THÂN + nền tảng hệ lôi pháp thanh vi/thần tiêu sau (⚠ KHÔNG phải thanh vi bí chỉ; «秘要» phi «秘旨»).",key_text:"上清北极天心正法（卷一·主法名）",use:"phép trừ tà/chữa bệnh/phá tà mị 符-chú-ấn-禹步-考召 · thiên tâm nhập môn",sources:["https://ctext.org/wiki.pl?if=gb&res=587983 (CTEXT DZ1227)","https://www.shidianguji.com/book/DZ1227 (識典古籍 DZ1227)"],textual_certainty:"high",notes:"DZ1227 正一部; 天心派 (tiền-lôi pháp); 元妙宗 1116; ⚠ «秘要» phi «秘旨»."},{dz:null,name_han:"道藏目录详注",name_vi:"Đạo Tạng Mục Lục Tường Chú",bu:"四库",author:"白云霁 (字明之, 在虚子, Nam Kinh trì thiên cung đạo sĩ)",era:"Minh (1626, thiên启 6)",topic:"classic",essence:"Catalog/chỉ mục HỆ THỐNG NHẤT đầu tiên của toàn 正统道藏 + 万历续道藏 — 4 quyển, theo phân loại tam động/tứ phụ/thập nhị loại, ghi tên-thể loại-số-quyển-tác giả + đề giải ngắn. NỀN TẢNG THƯ MỤC HỌC cho mọi nghiên cứu đạo tạng sau (Wiegode 1911 dịch Pháp).",key_text:null,use:"tra cứu/chỉ mục đạo tạng · định vị tác phẩm trong canon",sources:["https://baike.baidu.com/item/%E9%81%93%E8%97%8F%E7%9B%AE%E5%BD%95%E8%AF%A6%E6%B3%A8/3963183 (百度百科)","https://zh.daoinfo.org/index.php?title=%E9%81%93%E8%97%8F%E7%9B%AE%E9%8C%84 (daoinfo)"],textual_certainty:"high",notes:"⚠ phi正统道藏 nội (四库/đạo tạng 36册 phụ); 白云霁 1626."},{dz:null,name_han:"张三丰先生全集（道言浅近说/玄机直讲/大道论）",name_vi:"Trương Tam Phong Toàn Tập",bu:"道藏辑要",author:" (张三丰 原著; 清·李涵虚 西派 编纂)",era:"Nguyên mạt-Minh sơ (原作 14c) / Thanh đạo quang (汇编)",topic:"cultivation",essence:"Tổng tập tư tưởng nội đan + tây phái — quyển 3 «ĐẠI ĐẠO LUẬN/ HUYỀN CƠ TRỰC GIẢNG/ ĐẠO NGÔN THIỂN CẬN THUYẾT» cốt tủy: lý luận «đại đạo» + luyện đan hỏa hầu + «TU TÂM LUYỆN TÍNH» làm gốc, truyền nội đan công pháp hệ thống. ⚠ KHÔNG thuộc正统道藏; 道藏辑要.",key_text:"大道从「中」字入门。",use:"nội đan/toàn chân công pháp · hỏa hầu/huyền quan/tu tâm tham chiếu",sources:["https://zh.wikisource.org/zh-hans/%E5%BC%B5%E4%B8%89%E8%B1%90%E5%85%88%E7%94%9F%E5%85%A8%E9%9B%86/%E5%8D%B73 (維基文库 卷3)","https://zh.daoinfo.org/index.php?title=%E5%BC%B5%E4%B8%89%E8%B1%90%E5%85%88%E7%94%9F%E5%85%A8%E9%9B%86 (daoinfo)"],textual_certainty:"high",notes:"⚠ 道藏辑要 (phi正统); 张三丰原著 + 李涵虚(西派)编纂."},{dz:"DZ570",name_han:"灵剑子",name_vi:"Linh Kiếm Tử",bu:"洞玄",author:" (原题 旌阳许真君=许逊 述; học giới [朱越利]考 Bắc Tống 净明-閭山 phái 托名)",era:"托名 Đông Tấn·许逊; thực Bắc Tống",topic:"cultivation",essence:"Tác phẩm luyện dưỡng trên nền «khí» — «tiên nội đan hậu ngoại đan». 8 thiên (Đại Hùng/Tùng Sa Ký/Phục Khí...). «TÙNG SA KÝ» thuật 许逊 trảm yêu trừ hại; tư liệu cốt yếu 净明 đạo-閭山 (Lushan) pháp mạch + là nguồn XUẤT HIỆN SỚM thuật ngữ «khí công».",key_text:"术为先，阴功为首。",use:"nội đan sớm · 净明-閭山 pháp luyện khí · nguồn thuật ngữ «khí công»",sources:["https://zh.wikisource.org/zh-hans/%E9%9D%88%E5%8A%8D%E5%AD%90 (維基文库)","https://www.shidianguji.com/book/DZ0570 (識典古籍 DZ570)"],textual_certainty:"high",notes:"DZ570 洞玄部众术類; 姊妹篇 灵剑子引导子午记 DZ571; 许逊/净明-閭山."},{dz:"DZ263",name_han:"修真十书",name_vi:"Tu Chân Thập Thư",bu:"洞真",author:" (khuyết danh biên tập)",era:"Nguyên sơ (cuối Tống-đầu Nguyên, ~13c)",topic:"cultivation",essence:"ĐẠI TỔNG TẬP nội đan 60 quyển chia 10 thư, thu >60 loại thư tịch Tùy-Đường→Tống-Nguyên. Nòng cốt nam tông (Bạch Ngọc Thàm hệ: 张伯端/钟吕/白玉蟾) — «thượng phẩm đan pháp vô quái hào, chân hỏa bản vô hậu». NGUỒN TIÊN LƯỢNG nội đan nam tông/dưỡng sinh/khí công. (⚠ DZ263 = 修真十书; DZ1017 thực là 道枢 — net nhầm).",key_text:null,use:"nguồn tiên lượng nội đan nam tông · dưỡng sinh · khí công",sources:["https://zh.daoinfo.org/wiki/修真十书 (daoinfo)","https://baike.baidu.com/item/修真十书/9682294 (百度百科)"],textual_certainty:"high",notes:"DZ263 洞真部方法類 (Schipper tr.816); 60卷; 包钟吕传道集 q.39-41."},{dz:"DZ1056",name_han:"晋真人语录",name_vi:"Tấn Chân Nhân Ngữ Lục",bu:"太玄",author:" (晋真人 thuật; đệ tử 马丹阳 biên tập)",era:"Kim (12c, toàn chân sơ kỳ)",topic:"cultivation",essence:"Văn hiến ngữ lục QUAN TRỌNG BẬC NHẤT toàn chân giáo sơ kỳ. Định nghĩa KINH ĐIỂN về «TOÀN CHÂN»: «phù toàn chân giả, hợp thiên tâm chi đạo» — thần bất tẩu/khí bất tán/tinh bất lậu, tam giả câu bị, ngũ hành đô tụ → «vi chi toàn chân». Dùng Trùng Dương + Đàm Xứ Đoan huấn đồ.",key_text:"夫全真者，合天心之道也……神不走，气不散，精不漏，三者俱备，五行都聚，四象安和，为之全真也。",use:"giáo nghĩa/tâm pháp/toàn chân tu trì sơ kỳ",sources:["https://zh.wikisource.org/zh-hans/晉真人語錄 (維基文库)","https://ctext.org/wiki.pl?if=gb&res=798725 (CTEXT DZ1056)"],textual_certainty:"high",notes:"DZ1056 太玄部; Kim; đinh nghĩa «全真» kinh điển."},{dz:"DZ1141",name_han:"仙乐集",name_vi:"Tiên Nhạc Tập",bu:"太平",author:"刘处玄 (trưởng sinh tử, toàn chân thất chân thứ 4, tùy sơn phái)",era:"Kim (1147-1203)",topic:"cultivation",essence:"Tập thơ-từ-ca-tụng >560 thủ của LƯU XỨ HUYỀN — tuyên dương giáo chỉ toàn chân: «nhân sinh trăm năm đoản, luân hồi nan đào» → sớm ngộ huyền lý. Quyển 2 có «thập khuyến/thập nhị khuyến» (cùng Mã Đan Dương thập khuyến). Quán triệt «bất tranh», thanh tĩnh vô vi. ⚠ 仙乐集 = 刘处玄 (KHÔNG phải 王处一; 王处一 = 云光集 DZ~1153).",key_text:"善觉不争空，忘尘见道功。",use:"thi văn + giáo lý toàn chân · giáo đoàn quy củ sơ kỳ",sources:["https://zh.daoinfo.org/wiki/仙乐集 (daoinfo)","http://www.taoist.org.cn/getDjzsById.do?id=370 (中国道教协会)"],textual_certainty:"high",notes:"DZ1141 太平部; ⚠ 刘处玄 (phi 王处一); >560 thủ."},{dz:"DZ881",name_han:"太清石壁记",name_vi:"Thái Thanh Thạch Bích Ký",bu:"洞神",author:"苏玄朗 (青霞子) soạn; 唐·楚泽先生 编",era:"Tùy mạt-Đường sơ",topic:"cultivation",essence:"NGOẠI ĐAN-PHỤC THẠCH kinh điển Tùy-Đường. Ghi vài chục phương luyện đan ngoài (Thái Nhất Kim Anh Thần Đan/Đại Hoàn Đan/Hoàng Đế Cửu Đỉnh Đan/Kim Cao Đan) + pháp phục dụng/kiêng kỵ/trị bệnh. Nổi bật: GẮN LUYỆN ĐAN VỚI LÂM SÀNG Y (Bát Thạch Đan chữa phong=hủi chứng) — vừa tư liệu ngoại đan, vừa cứ liệu y học phục thạch.",key_text:"太一金英神丹方",use:"ngoại đan · phục thạch phương · đạo y thời Đường",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E6%B8%85%E7%9F%B3%E5%A3%81%E8%AE%B0 (維基文库)","https://www.shidianguji.com/book/DZ0881 (識典古籍 DZ881)"],textual_certainty:"high",notes:"DZ881 洞神部众术類; 苏玄朗/楚泽; luyện đan+y học."},{dz:"DZ420",name_han:"神仙服饵丹石行药法",name_vi:"Phục Nhĩ Đan Thạch Hành Dược Pháp",bu:"洞玄",author:"京里先生 (kính lý tiên sinh, 题名; ~Đường)",era:"约 Đường",topic:"cultivation",essence:"Kinh điển PHỤC NHĨ-NGOẠI ĐAN thời Đường — 38 pháp luyện chế + phục nhĩ tiên đan thạch dược (đan sa/hùng hoàng/tằng thanh/phàn thạch/điên kim...), trình bày trọn pháp độ: trì trai/tuyển địa/phối hợp/hỏa hậu/phục pháp/hành dược. Song hành Bão Phác Tử, phản ánh hệ phục thạch thành tiên thời Đường.",key_text:"雌黄千岁化为雄黄，雄黄千岁化为黄金，服食黄金命曰真人。",use:"phục nhĩ/ngoại đan · pháp độ hành dược thời Đường",sources:["https://www.shidianguji.com/book/DZ0420/chapter/1k1vho6cc074r (識典古籍 DZ420)","https://zh.wikisource.org/zh-hans/%E7%A5%9E%E4%BB%99%E6%9C%8D%E9%A4%8C%E4%B8%B9%E7%9F%B3%E8%A1%8C%E8%97%A5%E6%B3%95 (維基文库)"],textual_certainty:"high",notes:"DZ420 洞玄部玉诀類; 京里先生; 38 pháp; (gần «神仙服饵方» — đó là phạm trù, phi tên sách)."},{dz:null,name_han:"仙授理伤续断秘方",name_vi:"Tiên Thụ Lý Thương Tục Đoạn Bí Phương",bu:"太平",author:"蔺道人 (đạo nhân=đường đại phế xưng; khả năng y tăng)",era:"Đường (841-846, hội chung)",topic:"cultivation",essence:"Chuyên luận TRUNG Y THƯƠNG-CHỈNH CỐT sớm nhất hiện tồn — 14 bước khẩu quyết chữa thương (tẩy dược/chỉnh cốt/phục vị/cố định/dụng dược) + Hắc Long Tán/Đại Hoàn Huyết Đan; sáng «ỷ bội phục vị pháp» trị sai khớp vai — CỘT MỐC chỉnh cốt. ⚠ Bản thân KHÔNG属正统道藏; chỉ lưu gián tiếp qua «急救仙方»(Thái Bình Bộ).",key_text:"医治整理补接次第口诀",use:"trung y chỉnh cốt · đạo y văn hiến (tham chiếu bối cảnh, phi chính đạo tạng)",sources:["https://zh.wikisource.org/wiki/%E4%BB%99%E6%8E%88%E7%90%86%E4%BC%A4%E7%BB%AD%E6%96%B7%E7%A7%98%E6%96%B9 (維基文库)","https://baike.baidu.com/item/%E7%90%86%E4%BC%A4%E7%BB%AD%E6%96%AD%E6%96%B9/8454697 (百度百科)"],textual_certainty:"high",notes:"⚠ KHÔNG属正统道藏 (via 急救仙方 太平部); 蔺道人/Đường hội chung; cột mốc chỉnh cốt."},{dz:"DZ1238",name_han:"三洞群仙录",name_vi:"Tam Động Quần Tiên Lục",bu:"正一",author:"陈葆光 (正一道士, 江阴静应庵)",era:"Nam Tống (1154, triệu hưng giáp tuất)",topic:"classic",essence:"Tập truyện ký ~1000 vị tiên chân từ thượng cổ→Bắc Tống, viết bằng thể TỰ TỰ LỆ NGỮ (4 chữ cách ngẫu) kèm tự chú. Mục đích: tập kỷ thật thần tiên chứng minh «THẦN TIÊN KHẢ HỌC», phản bác nghi ngờ «tu luyện thành tiên».",key_text:"阙地求泉，虽至愚知其可得；炼形致仙，虽贤者不能笃信。",use:"nguồn gốc thần tiên phổ hệ + truyện ký văn học đạo giáo thời Tống",sources:["https://ctext.org/wiki.pl?if=gb&res=957098&remap=gb (CTEXT DZ1238)","https://baike.baidu.com/item/%E4%B8%89%E6%B4%9E%E7%BE%A4%E4%BB%99%E5%BD%95/4742497 (百度百科)"],textual_certainty:"high",notes:"DZ1238 正一部; 陈葆光 1154; ~1000 tiên chân."},{dz:"DZ973",name_han:"甘水仙源录",name_vi:"Cam Thủy Tiên Nguyên Lục",bu:"洞神",author:"李道谦 (天乐道人, 谥玄明文靖天乐真人)",era:"Nguyên (1288, chí nguyên戊子)",topic:"classic",essence:"TOÀN TẬP truyện ký + BÍ VĂN toàn chân đạo — «Cam Thủy» = sông Cam Hà (Chung Nam Sơn) nơi Vương Trùng Dương 1159 gặp chân tiên khởi nguyên toàn chân. Thu >60 vị cao đạo toàn chân Kim-Nguyên. TƯ LIỆU GỐC lịch sử toàn chân đạo (pairing 七真年谱 DZ175 + 终南山祖庭仙真内传).",key_text:null,use:"tư liệu sơ cấp #1 lịch sử toàn chân đạo Kim-Nguyên",sources:["https://ctext.org/wiki.pl?if=gb&res=453569&remap=gb (CTEXT DZ973)","https://zh.wikisource.org/zh-hans/%E7%94%98%E6%B0%B4%E4%BB%99%E6%BA%90%E5%BD%95 (維基文库)"],textual_certainty:"high",notes:"DZ973 洞神部记传類; 李道谦/Nguyên 1288; >60 cao đạo toàn chân."},{dz:"DZ958",name_han:"玄天上帝启圣录",name_vi:"Huyền Thiên Khải Thánh Lục",bu:"洞神",author:" (khuyết danh; học giới归 张守清 武当山 đạo sĩ + đệ tử biên)",era:"Nguyên đại trung kỳ (~1310, ⚠ KHÔNG phải Minh)",topic:"classic",essence:"Văn hiến CỐT LÕI tín ngưỡng HUYỀN THIÊN THƯỢNG ĐẾ (Chân Võ đại đế) — 8 quyển bạch thoại, kê bản tích/lai lịch/tu đạo/thần tích Huyền Đế: thị giáng sinh thái tử Tịnh Lạc quốc → nhập Vũ Đang sơn tu hành 42 năm thành đạo. Kế thừa 北宋真武启圣记 + gia tăng.",key_text:"玄帝乃先天始炁，太极别体。",use:"tư liệu then chốt tín ngưỡng Chân Võ-Huyền Thiên + thần thánh hóa Vũ Đang sơn",sources:["https://zh.wikisource.org/zh-hans/%E7%8E%84%E5%A4%A9%E4%B8%8A%E5%B8%9D%E5%95%9F%E8%81%96%E9%8C%84 (維基文库)","https://baike.baidu.com/item/%E7%8E%84%E5%A4%A9%E4%B8%8A%E5%B8%9D%E5%90%AF%E5%9C%A3%E5%BD%95/7785567 (百度百科)"],textual_certainty:"high",notes:"DZ958 洞神部记传類; ⚠ NGUYÊN (~1310, phi Minh); 张守清/武当."},{dz:null,name_han:"神仙传",name_vi:"Thần Tiên Truyện",bu:"四库",author:"葛洪 (字稚川, 283-343)",era:"Đông Tấn (317-318, kiến võ nguyên niên)",topic:"classic",essence:"Hagiography ~84-92 vị thần tiên — tiếp nối Liệt Tiên Truyện (Lưu Hướng). Soạn sau Bão Phác Tử nội thiên, nhân đệ tử Thăng hỏi «tiên nhân hữu vô» mà đáp. Tóm công phu tu luyện/đan đạo/thi giải (cụt giải). NỀN TẢNG văn học hagiography đạo giáo, ảnh hưởng toàn bộ hậu thế tiên truyện. ⚠ KHÔNG收 Minh正统道藏 (hiện hành bản 汉魏丛书/四库).",key_text:"洪撰神仙传十卷，盖于抱朴子内篇既成之后，因其弟子滕升问仙人有无而作。",use:"văn bản nền đạo giáo Lục triều · đan đạo · thi giải thuật",sources:["https://zh.wikisource.org/zh-hans/%E7%A5%9E%E4%BB%99%E5%82%83 (維基文库)","https://en.wikipedia.org/wiki/Shenxian_Zhuan (Wikipedia EN)"],textual_certainty:"high",notes:"⚠ KHÔNG收 Minh正统道藏 (汉魏丛书 1592/四库 1782); 葛洪/Đông Tấn."},{dz:"DZ682",name_han:"老子河上公章句（道德真经注）",name_vi:"Hà Thượng Công Chương Cú",bu:"洞神",author:"河上公 (thác danh; thực ~120-200 CN)",era:"Đông Hán",topic:"classic",essence:"Bản chú giải CÓ HỆ THỐNG SỚM NHẤT còn sót của Đạo Đức kinh — gắn «TRỊ QUỐC» với «TRỊ THÂN» làm một. Đề thanh hư vô vi + TAM BẢO dưỡng sinh (hành khí-cố tinh-dưỡng thần); mỗi chương đặt tiêu đề pháp tu (thể đạo/dưỡng thân/an dân...). Nền tảng thiền đạo + nội đan sau, từng là bản chuẩn đạo tạng Lưu-Đường.",key_text:"道可道，谓经术政教之道也。非常道，非自然生长之道也。",use:"đạo đức kinh qua lăng kính đạo giáo dưỡng-sinh/thanh-hư vô-vi",sources:["https://ctext.org/heshanggong/zhs (CTEXT 河上公)","https://en.wikipedia.org/wiki/Heshang_Gong (Wikipedia)"],textual_certainty:"high",notes:"DZ682 洞神部玉诀類; 河上公/Đông Hán; trị quốc+trị thân."},{dz:"DZ690",name_han:"老子道德经注（王弼本）",name_vi:"Vương Bật Đạo Đức Kinh Chú",bu:"洞神",author:"王弼 (226-249)",era:"Tam Quốc Ngụy",topic:"philosophy",essence:"ĐỈNH CAO HUYỀN HỌC Ngụy-Tấn — đọc đạo đức kinh như hình thượng học «DĨ VÔ VI BẢN» (lấy Vô làm gốc), triệt tiêu lớp đọc công-pháp/dưỡng-sinh Hà Thượng Công → khai triết học thuần túy. 4 quyển = BẢN CHUẨN đạo đức kinh 81 chương lưu hành đến nay; định hình toàn chú giải Lão tử sau.",key_text:null,use:"bản văn bản/chú giải thẩm quyền đạo đức kinh 81 chương · khung «Vô-Hữu/Bản-Mạt»",sources:["https://zh.wikisource.org/wiki/道德经_(王弼本) (維基文库 王弼本)","https://www.chineseclassic.com/content/426 (chineseclassic)"],textual_certainty:"high",notes:"DZ690 洞神部玉诀類; 王弼/Ngụy; huyền học «dĩ vô vi bản»."},{dz:"DZ294",name_han:"列仙传",name_vi:"Liệt Tiên Truyện",bu:"洞真",author:" (thác danh 刘向; thực biên ~2c CN, Đông Hán)",era:"Đông Hán (thác danh Tây Hán)",topic:"classic",essence:"TIÊN TRUYỆN sớm nhất còn sót — chép ~70 vị tiên từ Xích Tùng Tử→Huyền Tục, thể lệ liệt-truyện chính sử. Mỗi truyện ghi lai lịch + phương thuật đắc đạo + tán ngữ; nửa số tiên đắc lực dược thảo/khoáng. KHUÔN MẪU cho Thần Tiên Truyện (葛洪) + Phật giáo Cao Tăng Truyện.",key_text:null,use:"hồ sơ tiên-nhân (tên/hiệu/tiên-tích/phương thuật) · mỏ điển cổ phú chú",sources:["https://en.wikipedia.org/wiki/Liexian_Zhuan (Wikipedia)","https://www.chinaknowledge.de/Literature/Daoists/liexianzhuan.html (chinaknowledge)"],textual_certainty:"high",notes:"DZ294 洞真部记传類; thác danh 刘向/Đông Hán; ~70 vị tiên."},{dz:null,name_han:"老子变化经（敦煌本 S.2295）",name_vi:"Lão Tử Biến Hóa Kinh",bu:"敦煌写本",author:" (khuyết danh; lục triều đạo giáo)",era:"Lục triều (bản sao 612 CN, Tùy đại nghiệp 8)",topic:"classic",essence:"Kinh đạo giáo sớm về LÃO QUÂN HÓA THÂN — đồng nhất Lão Tử với Đạo («Lão Tử=Đạo», tiền thiên địa), thuật Ngài hóa sinh qua Huyền Diệu Ngọc Nữ → giáng sinh họ Lý + các lần biến hóa cứu độ. Còn ~95 dòng/~1600 chữ. ⚠ KHÔNG thu正统道藏; chỉ 敦煌 S.2295.",key_text:"化生玄妙玉女。自玄妙玉女生后，三气变化，五色玄黄，大如弹丸，入玄妙口中。",use:"Lão-quân hóa-thân giáo nghĩa · thần thoại vũ trụ luận",sources:["https://baike.baidu.com/item/老子变化经/18832712 (百度百科)","https://zh.daoinfo.org/index.php?title=老子變化經(敦煌本) (daoinfo)"],textual_certainty:"high",notes:"⚠ KHÔNG thu正统道藏; chỉ 敦煌 S.2295 (bản sao 612); lục triều."},{dz:"DZ180",name_han:"三坛圆满天仙大戒（初真戒·中极戒·天仙大戒）",name_vi:"Tam Đàn Đại Giới",bu:"洞真",author:" (戒本 khuyết danh Lục triều-Đường sơ; 制度 清·王常月 hệ thống hóa)",era:"戒本 Đông Tấn-Nam triều-Đường sơ; 制度 Thanh sơ (1656)",topic:"ritual",essence:"Hệ thống GIỚI LUẬT TỐI CAO toàn chân đạo — 王常月 thanh sơ định hình 3 cấp thụ: SƠ CHÂN (10 giới, nhập đạo chi môn) → TRUNG CỰC (300 giới, dựa 智慧观身大戒文 DZ1364) → THIÊN TIÊN (viên mãn giới). Lấy giới luật nền tu tâm; chỉ ai trì Trung Cực vô phạm mới tiến thọ Thiên Tiên → «Diệu Đạo Sư».",key_text:"出家超俗，皆宿有良契……若慎终如始，精至修炼，当福及七祖，庆流一门。",use:"toàn chân thụ giới · luật tông · đạo sĩ nhật dụng",sources:["https://zh.wikisource.org/zh-hans/%E8%99%9B%E7%9A%87%E5%A4%A9%E5%B0%8A%E5%88%9D%E7%9C%9F%E5%8D%81%E6%88%92%E6%96%87 (維基 初真十戒文)","https://zh.wikisource.org/zh-hans/%E4%B8%8A%E6%B8%85%E6%B4%9E%E7%9C%9F%E6%99%BA%E6%85%A7%E8%A7%80%E8%BA%AB%E5%A4%A7%E6%88%92%E6%96%87 (維基 智慧观身大戒文 DZ1364)"],textual_certainty:"high",notes:"DZ180 初真戒文 (洞真戒律) + DZ1364 中极戒; 制度 清·王常月 1656."},{dz:"DZ1411",name_han:"洞玄灵宝长夜之府九幽玉匮明真科",name_vi:"Cửu U Ngọc Quỹ Minh Chân Khoa",bu:"正一",author:" (khuyết danh; cổ linh bảo kinh)",era:"Đông Tấn末-Nam triều初 (陆修静灵宝经目)",topic:"ritual",essence:"CỔ LINH BẢO kinh cốt tủy ĐỘ VONG — Nguyên Thỉ Thiên Tôn vì 7240 đồng tử tuyên tội phúc nhân quả/thiện ác báo ứng. Mô tả vô số tội nhân chịu hình CỬU U địa ngục + thiết 24 điều khoa giới (10 thiện nhân duyên + tội phúc duyên đối). NGUỒN GỐC Minh Chân trai khoa nghi sau.",key_text:null,use:"linh bảo độ亡 · minh chân trai khoa nghi · cứu抜 cô hồn/giải tội/độ thất tổ",sources:["https://zh.wikisource.org/zh-hans/%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E9%95%B7%E5%A4%9C%E4%B9%8B%E5%BA%9C%E4%B9%9D%E5%B9%BD%E7%8E%89%E5%8C%B1%E6%98%8E%E7%9C%9F%E7%A7%91 (維基文库)","https://www.shidianguji.com/book/DZ1411 (識典古籍 DZ1411)"],textual_certainty:"high",notes:"DZ1411 (正一部, bản源 cổ linh bảo); 24 khoa giới; cửu u địa ngục."},{dz:"DZ1219",name_han:"高上神霄玉清真王紫书大法",name_vi:"Thần Tiêu Tử Thư Đại Pháp",bu:"正一",author:" (khuyết danh; thần tiêu phái, liên hệ 王文卿 1093-1153 truyền)",era:"Bắc Tống末-Nam Tống初",topic:"fu",essence:"Kinh CỐT TỦY THẦN TIÊU PHÁI — 神霄玉清真王 (Nam cực trường sinh đại đế) năng thụ pháp. Chủ «NỘI ĐAN VI THỂ, LÔI PHÁP VI DỤNG»: nội luyện tinh-khí-thần nền, cảm thông thiên lôi. NGŨ LÔI THẦN PHÙ triệu役 lôi bộ chư tướng (cửu thiên lôi bộ đại tướng), cầu vũ/trừ tà/trị bệnh. 12 quyển. (⚠ thay «神霄玉诀» — kinh đó KHÔNG tồn tại độc lập, chỉ trích引).",key_text:null,use:"thần tiêu ngũ lôi đại pháp · cầu vũ/trừ tà/trị bệnh · sư thụ phù lục",sources:["https://zh.wikisource.org/wiki/%E9%AB%98%E4%B8%8A%E7%A5%9E%E9%9C%84%E7%8E%89%E6%B8%85%E7%9C%9F%E7%8E%8B%E7%B4%AB%E6%9B%B8%E5%A4%A7%E6%B3%95 (維基文库)","https://www.shidianguji.com/book/DZ1219 (識典古籍 DZ1219)"],textual_certainty:"partial",notes:"DZ1219 正一部 (12卷); ⚠ thay «神霄玉诀» (kinh đó phi độc lập, chỉ trích引 trong玉匣记序/道法会元)."},{dz:"DZ555",name_han:"高上月宫太阴元君孝道仙王灵宝净明黄素书",name_vi:"Tịnh Minh Hoàng Tố Thư",bu:"洞玄",author:" (khuyết danh Tống-Nguyên tịnh minh đạo; 元·傅飞卿 chú)",era:"Tống-Nguyên",topic:"classic",essence:"Kinh TRUNG TÂM TỊNH MINH TRUNG HIẾU ĐẠO — nguyệt cung thái âm nguyên quân tôn xưng «HIẾU ĐẠO TIÊN VƯƠNG/MINH VƯƠNG linh bảo tịnh minh hoàng tố thiên tôn». Lấy TRUNG HIẾU làm gốc thành tiên + kết hợp phù lục khoa nghi với nội đan. 10 quyển (含 hoàng tố thư nhập đạo phẩm) = giáo nghĩa cốt tủy tịnh minh phái 刘玉. (⚠ thay «孝道明王经» — kinh đó chưa verify đích xác trong đạo tạng).",key_text:"黃素交光，垂芒照耀，映於月宮，故号月宮太陰元君孝道仙王灵宝净明黄素天尊。",use:"tịnh minh đạo hiếu đạo tu tiên · nhật dụng tu trì · hoàng tố pháp",sources:["https://zh.wikisource.org/zh-hans/%E9%AB%98%E4%B8%8A%E6%9C%88%E5%AE%AE%E5%A4%AA%E9%99%B0%E5%85%83%E5%90%9B%E5%AD%9D%E9%81%93%E4%BB%99%E7%8E%8B%E9%9D%88%E5%AF%B6%E6%B7%A8%E6%98%8E%E9%BB%83%E7%B4%A0%E6%9B%B8 (維基文库)","https://www.shidianguji.com/book/DZ0555 (識典古籍 DZ555)"],textual_certainty:"partial",notes:"DZ555 洞玄部方法類 (10卷); ⚠ thay «孝道明王经» (kinh đó chưa verify trong đạo tạng); 傅飞卿 chú."},{dz:"DZ167",name_han:"洞玄灵宝真灵位业图",name_vi:"Chân Linh Vị Nghiệp Đồ",bu:"洞真",author:"陶弘景 纂 (唐·闾丘方远 校 định bản truyền thế)",era:"Nam triều Lương (~499-517)",topic:"classic",essence:"Đạo giáo ĐẦU TIÊN lập hệ THẦN CHỨC CÓ CẤP BẬC rõ ràng — chia tiên chân 7 phẩm giai tầng, mỗi phẩm có «trung vị» chủ thần + tả/hữu vị. Đỉnh = Nguyên Thỉ Thiên Tôn ở Ngọc Thanh. DỌN NỀN toàn bộ thần phổ đạo giáo sau. (陶弘景 biên, cùng tác giả Chân Cáo + Đăng Chân Ẩn Quyết.)",key_text:"玉清三元宫，上第一中位：上合虚皇道君应号元始天尊。",use:"tra thần vị/bậc phẩm/danh xưng tiên chân · nền thần phổ đạo giáo lục triều",sources:["https://zh.wikisource.org/zh-hans/%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E7%9C%9F%E9%9D%88%E4%BD%8D%E6%A5%AD%E5%9C%96 (維基文库)","https://ctext.org/wiki.pl?if=gb&res=758084 (CTEXT DZ167)"],textual_certainty:"high",notes:"DZ167 洞真部谱录類 (腾字号); 陶弘景/梁 + 闾丘方远/Đường; 7 phẩm thần phổ."},{dz:"DZ140",name_han:"上清握中诀",name_vi:"Thượng Thanh Ức Trung Quyết",bu:"洞真",author:" (khuyết danh; 《通志·艺文略》 ghi 陶弘景; thực Lục triều tập tục)",era:"Nam Bắc Triều (thượng thanh phái tập)",topic:"cultivation",essence:"Tập hợp BÍ QUYẾT tu luyện sớm phái thượng thanh: PHỤC NHẬT KHÍ/PHỤC TINH NGUYỆT + CÚC TAM HỒN/CHẾ THẤT PHÁCH + thủ huyền đan + bộ tinh đẩu + tồn thần nội quán. Văn ghi «đây là quyết của Chu quân» → liên hệ dòng Chu Tử Dương.",key_text:"玄上太微，北极紫盖，下有太真，游翔九外。",use:"công pháp tu luyện thượng thanh · tồn tưởng/phù chú/nội quán lục triều",sources:["https://ctext.org/wiki.pl?if=gb&res=112133 (CTEXT DZ140)","https://zh.wikisource.org/wiki/%E4%B8%8A%E6%B8%85%E6%8F%A1%E4%B8%AD%E8%A8%A3 (維基文库)"],textual_certainty:"high",notes:"DZ140 洞真部玉诀類 (3卷); thượng thanh bí quyết tập."},{dz:"DZ426",name_han:"上清太上八素真经",name_vi:"Bát Tố Chân Kinh",bu:"洞玄",author:" (khuyết danh; thượng thanh sớm)",era:"Đông Tấn-Nam triều (bát tố hệ kinh)",topic:"cultivation",essence:"Một biến «BÁT TỐ CHÂN KINH» (kinh của 8 tinh khiết) = đạo Huyền Thanh Ngọc Hoàng. Thuật dòng truyền: Thượng Hoàng Thiên Đế → Thái Vi Thiên Đế Quân → Tam Nguyên Tử Tinh Đạo Quân → Chân Dương Nguyên Lão Quân → Thái Thượng Đạo Quân. Liệt kinh tịch cần tu theo bậc thượng/trung/hạ chân để đăng thăng.",key_text:"《太上隐书八素真经》者，乃玄清玉皇之道也。",use:"giáo lý thượng thanh «bát tố» hệ · tu chân phẩm vị thời lục triều",sources:["https://zh.wikisource.org/zh-hans/%E4%B8%8A%E6%B8%85%E5%A4%AA%E4%B8%8A%E5%85%AB%E7%B4%A0%E7%9C%9F%E7%B6%93 (維基文库)","https://brill.com/display/book/9781684175161/BP000011.pdf (Brill bibliography)"],textual_certainty:"high",notes:"DZ426 洞玄部玉诀類; bát tố hệ kinh thượng thanh."},{dz:"DZ1220",name_han:"火师汪真君雷霆奥旨",name_vi:"Hỏa Sư Ôn Chân Quân Lôi Đình Áo Chỉ",bu:"正一",author:"Uông Tử Hoa (火师, Đường Khai nguyên 714-789) thuật; 王文卿 (thần tiêu) truyền; Chử Chấp Trung chú; 白玉蟾 tự",era:"Đường (nguyên) / Tống (truyền-chú-tự)",topic:"ritual",essence:"Kinh cốt tủy THẦN TIÊU LÔI ĐIỆN phái — «NỘI ĐAN LA THỂ, LÔI ĐIỆN PHÁP LA DỤNG» («không luyện nội đan, hình hoàn bại hoại»). Công: tồn tưởng ngũ tạng khí → ngũ phương lôi điện thần + ngũ khí triều nguyên + tam hoa tụ đỉnh; «Lôi thành tức tại tâm trung», «Ngã tức lôi điện thần». Dùng cầu vư/tế tà/chữa bệnh («vận lôi điện ư chưởng thượng»). (Trong DZ1220 đạo pháp hội nguyên q.76; không có số DZ độc lập.)",key_text:"火师曰：凡受五雷大法，非上品仙官之职，不能悟此玄机。内则修炼自己还丹，固外则廓邪治病。",use:"thần tiêu ngũ lôi đại pháp · nội luyện nền (王文卿→白玉蟾 hệ)",sources:["https://ctext.org/wiki.pl?if=gb&chapter=793144 (CTEXT 道法会元 q.76)","http://www.daoist.org/BookSearch(test)/list014/r2-012.pdf (道教在线)"],textual_certainty:"high",notes:"Trong DZ1220 道法会元 q.76 (phi số DZ độc lập); 火师 Uông Tử Hoa/Đường + 王文卿 truyền."},{dz:"DZ567",name_han:"上清北极天心正法",name_vi:"Thiên Tâm Chính Pháp",bu:"洞玄",author:" (khuyết danh; dẫn 张虚靖 thiên sư ngữ)",era:"Nam Tống (~thao)",topic:"fu",essence:"Kinh cốt tủy THIÊN TÂM PHÁI (1 trong 3 đại lôi điện phái) — «tự Thái Thượng giáng Hạc Minh Sơn nhật thụ thiên sư chỉ Đông Bắc Cực chi thư tị trà tà ma cứu dân thị vụ». Sơ truyền CHỈ 3 PHÙ: Thiên Không Đại Thánh phù / Hắc Sát phù / Tam Quang phù + Bắc Cực trà tà viện ấn («tam phù nhất ấn»). Nhấn «hành pháp tiên tu nội công», thượng thừa thiên sư đạo, hạ khởi lôi điện hệ.",key_text:"凡天心法者，自太上降鹤鸣山，日授天师，指东北极之书，僻除邪魔，救民是务……初传惟有三符：一乃天空大圣符，二乃黑杀符，三乃三光符。",use:"thiên tâm phái «tam phù nhất ấn» · trừ tà/trị bệnh/hộ thân",sources:["https://ctext.org/wiki.pl?if=gb&res=664129 (CTEXT DZ567)","https://www.shidianguji.com/book/DZ0567 (識典古籍 DZ567)"],textual_certainty:"high",notes:"DZ567 洞玄部方法類 (⚠ SỬA từ DZ999 — DZ999 thực là 周易参同契); thiên tâm tam phù nhất ấn."},{dz:"DZ175",name_han:"七真年谱",name_vi:"Thất Chân Niên Phổ",bu:"洞真",author:"李道谦 (天乐子, 1219-1296; 马 đan dương đích truyền)",era:"Nguyên (1271, chí nguyên tân vị)",topic:"classic",essence:"TOÀN CHÂN GIÁO SỬ biên niên cốt cán — khởi Trùng Dương giáng thế (1112) → Trường Xuân chân nhân thăng tiên (1227), thông 116 năm. Ký Vương Trùng Dương THẤT ĐẠI ĐỆ TỬ (马丹阳/谭处端/刘处玄/丘处机/王处一/郝大通/孙不二). «Biến khảo sư chân văn tập + chư gia truyện ký» biên thứ thành nhất phổ. Sử liệu cực cao, cùng 金莲正宗记 + 甘水仙源录 tham chiếu.",key_text:"遍考师真文集及诸家所撰传记，起重阳祖师降世之岁，至长春真人升仙之秋，一百一十六年之间出处事迹，编次通为一谱。",use:"hạch tâm sử liệu toàn chân đạo sớm · định niên đại",sources:["https://zh.wikisource.org/wiki/%E4%B8%83%E7%9C%9F%E5%B9%B4%E8%AD%9C (維基文库)","https://github.com/kanripo/KR5a0176 (Kanripo KR5a0176)"],textual_certainty:"high",notes:"DZ175 洞真部谱录類; 李道谦 1271; 116 năm toàn chân sử."},{dz:"DZ955",name_han:"终南山祖庭仙真内传",name_vi:"Chung Nam Sơn Tổ Đình Nội Truyện",bu:"洞神",author:"李道谦 (天乐真人)",era:"Nguyên (~1284, chí nguyên nhị thập niên)",topic:"classic",essence:"Toàn chân TIÊN TRUYỆN — 3 quyển ghi 37 vị Kim-Nguyên toàn chân cao đạo sự tích. Quyển thượng ký cùng Vương Trùng Dương ư Lưu Tương thôn kết mao tu đạo 的 Hòa Ngọc Thiền + Lệ Linh Dương + đệ tử. Chung Nam Sơn Lâu Quan = đạo giáo tiên hiền Doãn Hỉ cố cư («Tổ Đình» danh ra đây). Cùng 七真年谱 + 甘水仙源录 TRÙ TAM BỘ sử liệu toàn chân Kim-Nguyên.",key_text:null,use:"toàn chân đạo sử · chung nam sơn tổ đình (trùng dương vạn thọ cung) · lâu quan đạo phái",sources:["https://ctext.org/wiki.pl?if=gb&res=210171 (CTEXT DZ955)","https://www.shidianguji.com/book/DZ0955 (識典古籍 DZ955)"],textual_certainty:"high",notes:"DZ955 洞神部记传類; 李道谦 ~1284; 37 vị cao đạo; trù tam bộ (DZ175/955/973)."},{dz:"DZ1455",name_han:"太微帝君二十四神回元经",name_vi:"Nhị Thập Tứ Thần Hồi Nguyên Kinh",bu:"洞真",author:" (khuyết danh; thượng thanh phái)",era:"Lục triều (Đông Tấn-Nam triều, 4-6c)",topic:"cultivation",essence:"Kinh dạy phép TỒN TƯ 24 THÂN THẦN cư trú trong cơ thể — chia thượng/trung/hạ cảnh mỗi cảnh 8 vị (bát cảnh). Niệm danh hiệu + vị trí các thần để «trị trấn nhất thân, bảo thủ nguyên tinh», tán giải bào kết, thông quan nguyên. Công phu 18 năm → Thái Vi Đế Quân sai Thái Nhất Ngũ Thần lai độ hóa thân thăng thiên. (Ngyen 1 thiên của《Động Phòng Thượng Kinh》sau tách.)",key_text:"太微帝君，太一造形，紫元内神，二十四真人，混气变生，主仙上精，散解胞结，释滞关元。",use:"tồn tư thân thần · nội đan thượng thanh · «nhân thể tức vũ trụ»",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E5%BE%AE%E5%B8%9D%E5%90%9B%E4%BA%8C%E5%8D%81%E5%9B%9B%E7%A5%9E%E5%9B%9E%E5%85%83%E7%B6%93 (維基文库)","https://www.shidianguji.com/zh/book/DZ1455 (識典古籍 DZ1455)"],textual_certainty:"high",notes:"DZ1455 (Schipper/Robinet phân 洞真; vật lý vạn lịch tục đạo tạng 正一 — bu tranh nghị)."},{dz:"DZ1421",name_han:"太上紫微中天七元真经",name_vi:"Tử Vi Thất Nguyên Chân Kinh",bu:"正一",author:" (khuyết danh)",era:"Nam Bắc Triều mạt-Tùy/Đường (6-7c)",topic:"cultivation",essence:"Kinh ngụy thác THẤT NGUYÊN CHÂN NHÂN (BẮC ĐẤU thất tinh quân) thuyết pháp, do Nguyên Thỉ Thiên Tôn tuyên diễn tại Tử Vi Trung Cung. 7 thiên thư văn/chú quyết, mỗi thiên = thần chú công đức 1 vị bắc đẩu tinh quân. Pháp: tồn thần tụng chú + đái phục phù lục → trường sinh/tiêu tai/độ ách/chiêu chân phục ma. TRUNG TÂM tín ngưỡng Bắc Đẩu-Bắc Đế.",key_text:"元始天尊演化诸天上皇之劫，镇治紫微中宫，大会说法。",use:"bắc đẩu tín ngưỡng · tụng chú tiêu tai diên sinh · phù lục hộ thân",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E7%B4%AB%E5%BE%AE%E4%B8%AD%E5%A4%A9%E4%B8%83%E5%85%83%E7%9C%9F%E7%B6%93 (維基文库)","https://www.shidianguji.com/zh/book/DZ1421 (識典古籍 DZ1421)"],textual_certainty:"high",notes:"DZ1421 正一部; Bắc Đẩu thất tinh; ⚠ đề chuẩn «真经» (phi «真人经»)."},{dz:"DZ1327",name_han:"洞真太上三九素语玉精真诀",name_vi:"Tam Cửu Tố Ngữ Ngọc Tinh Chân Quyết",bu:"洞真",author:" (khuyết danh; thượng thanh phái)",era:"Đông Tấn (《Chân Cáo》q.5 đã dẫn → tiền Đường)",topic:"cultivation",essence:"BÍ QUYẾT tu chân thượng thanh — 3 chương: (1) tồn tư NGŨ ĐẾ an định ngũ tạng, (2) BÁT TIẾT ĐẦU THÍCH PHÁP (tấu sớ tạ tội theo 8 tiết khí), (3) khắc phù hành đạo. Cốt: «thích ngũ tạng, khai lý u quan» — vạn khí bất cố/chân linh bất hân thì «vạn bất đắc tiên». «Tam cửu tố ngữ» = 27 (3×9) âm tiết bí ngữ mở linh quan. Khinh truyền «thương diệt tử thân».",key_text:"三九素语，披解灵关，玉精真诀，理命长存。",use:"tồn tư ngũ tạng-thất quan · khai linh quan · phù quyết hành đạo · sám tạ tội bát tiết",sources:["https://ctext.org/wiki.pl?if=gb&chapter=839351 (CTEXT DZ1327)","https://www.shidianguji.com/book/DZ1327 (識典古籍 DZ1327)"],textual_certainty:"high",notes:"DZ1327 洞真部玉诀類; 《Chân Cáo》q.5 dẫn chứng; tam cửu = 27 âm tiết bí ngữ."},{dz:"DZ1373",name_han:"上清外国放品青童内文",name_vi:"Ngoại Quốc Phóng Phẩm Thanh Đồng Nội Văn",bu:"正一",author:" (khuyết danh; thượng thanh phái)",era:"Lục triều (4-5c)",topic:"classic",essence:"2 quyển, THƯỢNG THANH KỲ THƯ (tương truyền Cao Thượng Ngọc Đế truyện Thượng Tướng Thanh Đồng Quân). «Ngoại quốc phóng phẩm» = THẦN THÁNH ĐỊA LÝ chư phương ngoại quốc (cửu quốc hệ thống): «kết khí ngưng quốc, phân thế vi danh» → thể hiện thế giới quan thần thánh hóa địa lý độc đáo thượng thanh. Tồn tư niệm chú + đọc chân danh + đới phù. (Được《Vô Thượng Bí Yếu》dẫn như«Động Chân ngoại quốc phóng phẩm kinh».)",key_text:"元始自然，青阳郁冥，玄化空洞，无量无形，结气凝国，芬世为名。",use:"thần thánh địa lý thượng thanh · tồn tư phù lục · vũ trụ quan thần tiên hóa thế giới",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%8A%E6%B8%85%E5%A4%96%E5%9C%8B%E6%94%BE%E5%93%81%E9%9D%92%E7%AB%A5%E5%85%A7%E6%96%87 (daoinfo)","https://www.shidianguji.com/book/DZ1373 (識典古籍 DZ1373)"],textual_certainty:"high",notes:"DZ1373 (vật lý 正一; nội dung thượng thanh kỳ thư); 《Thượng Thanh đại chân kinh mục》trước 500 ghi."},{dz:"DZ824",name_han:"嵩山太无先生气经",name_vi:"Tung Sơn Thái Vô Khí Kinh",bu:"洞神",author:" (khuyết danh; truyền từ Vương công núi La phù)",era:"Đường (Đại lịch ~766-779)",topic:"cultivation",essence:"Kinh phân biệt rõ NGOẠI KHÍ (các pháp phục khí như nhị cảnh/ngũ nha/lục vật — cương kính khó phục) với NỘI KHÍ/ĐẠI TỨC sẵn có trong thân. Cốt: phục dưỡng nội khí kết thành huyền châu ở đan điền = «đại tức», KHÔNG cần mượn ngoài. >16 khẩu quyết (phục-tiến-đào-điều-yết-hành-luyện-ủy-bế-bố khí + lục khí ha-hư-xuy-hu...). «Mệnh ở ta không ở trời đất».",key_text:"至如内气已正，一是曰胎息；身中自有，非假外求。",use:"phục khí/đại tức · dưỡng sinh diên niên · nội đan cơ sở",sources:["https://ctext.org/wiki.pl?if=gb&chapter=853568 (CTEXT DZ824)","https://baike.baidu.com/item/嵩山太无先生气经/8582036 (百度百科)"],textual_certainty:"high",notes:"DZ824 洞神部方法類; 唐 大历; «mệnh ở ta» khẩu quyết."},{dz:"DZ872",name_han:"太上肘后玉经方",name_vi:"Trửu Hậu Ngọc Kinh Phương",bu:"洞神",author:"卢遵元 (hiệu 霞栖子/栖霞子) biên",era:"Đường (825, bảo lịch ất mùi)",topic:"cultivation",essence:"Phương thư PHỤC THỰC dưỡng sinh — lấy BÁT QUÁI làm cương, liệt 8 phương thuốc huyền diệu («Thái Thượng Bát Phương Yên Uẩn Huyền Bảo»): Càn-thất tinh tán / Khôn-tứ phiến tán / Cấn-hà xa phương / Tốn-tứ đồng tán / Ly-lộc giác phân / Đoái-kiếm kim đan / Khảm-nam nhạc chân nhân phương / Chấn... Truyền Sào Cư Tử phụng sự Đông Hải Thanh Đồng Quân 20 năm mới khẩu thụ.",key_text:"宝历乙未岁，霞栖子卢遵元持太上八方絪縕玄宝一轴以授隐栖施君。",use:"phục thực dược-đan · thảo mộc/khoáng vật dưỡng sinh diên niên",sources:["https://zh.wikisource.org/zh-hans/太上肘后玉经方 (維基文库)","https://zh.daoinfo.org/index.php?title=太上肘后玉经方 (daoinfo)"],textual_certainty:"high",notes:"DZ872 洞神部方法類; 卢遵元/Đường 825; bát quái 8 phương thuốc."},{dz:"DZ1405",name_han:"长生胎元神用经",name_vi:"Trường Sinh Thai Nguyên Thần Dụng Kinh",bu:"正一",author:" (kinh khuyết danh Đường; 仵任郎赵 chú)",era:"Đường",topic:"cultivation",essence:"Luận PHỤC KHÍ-HÀNH KHÍ — trích sao từ 嵩山太无先生气经 + 幼真先生服内元气诀. Cốt: thần-khí = mẹ-con («khí kết thành hình, hình là gốc nhận khí, khí là rễ của hình»); thủ hạ nguyên «huyền châu» + thần nội thị + «thai từ phục khí mà kết» + «hoàn tinh bổ não». Kèm điều khí/hành khí khẩu quyết + tồn tưởng 24 thần + phương trừ cửu trùng (cửu trùng/thi).",key_text:"炁结为形，形是受炁之本宗，炁是形之根元。",use:"phục nguyên khí · dưỡng thần-kết thai · đạo y trừ cửu trùng",sources:["https://ctext.org/wiki.pl?if=gb&chapter=957608 (CTEXT DZ1405)","https://www.shidianguji.com/zh/book/DZ1405 (識典古籍 DZ1405)"],textual_certainty:"high",notes:"DZ1405 正一部 (Schipper=1394); Đường; trích sao 嵩山太无气经."},{dz:"DZ677",name_han:"唐玄宗御注道德真经",name_vi:"Đường Huyền Tông Ngự Chú",bu:"洞神",author:"李隆基 (唐玄宗)",era:"Đường (Khai nguyên ~732-735)",topic:"philosophy",essence:"Bản chú giải ĐẦU TIÊN do HOÀNG ĐẾ Trung Hoa đích thân soạn — ban hành Khai Nguyên, xuống chiếu nhà nhà phải có để đọc. Thần chỉ «LÝ THÂN LÝ QUỐC»: tu thân + trị quốc đồng nhất thể. Lấy 河上公 bản làm底 bản → đưa đạo giáo thành Ý THỨC HỆ QUỐC GIA nhà Đường, đặt khuôn mẫu «tứ đế ngự chú» (Đường Huyền Tông/Tống Huy Tông/Minh Thái Tổ/Thanh Thế Tổ).",key_text:null,use:"khuôn mẫu hoàng gia chú Lão · tham chiếu truyền thống «lý thân lý quốc»",sources:["https://zh.wikisource.org/wiki/%E5%94%90%E7%8E%84%E5%AE%97%E5%BE%A1%E8%A8%BB%E9%81%93%E5%BE%B7%E7%9C%9F%E7%B6%93 (維基文库)","https://www.shidianguji.com/zh/book/DZ0677 (識典古籍 DZ677)"],textual_certainty:"high",notes:"DZ677 洞神部玉诀類; Đường Huyền Tông ~732-735; first emperor 注; «lý thân lý quốc»."},{dz:"DZ685",name_han:"道德真经传（陆希声）",name_vi:"Lục Hy Thanh · Đạo Đức Truyện",bu:"洞神",author:"陆希声",era:"Đường (~880-895, mạt Đường)",topic:"philosophy",essence:"Lấy NHO GIÁO kinh nghĩa giải Lão tử — «LÃO TỬ CHI THUẬT BẢN Ư CHẤT, CHẤT DĨ PHỤC TÍNH»: gốc đạo Lão là chất phác, mục đích là phục tính. Động cơ «hóa tình phục tính, dĩ tính chính tình». Tự序 điều hòa Khổng-Lão: hai thánh cùng cứu thế, chỉ khác văn-chất. Đại biểu «DĨ NHO GIẢI LÃO» đời Đường (đối trọng thành huyền anh/đỗ quang đình trọng đạo phái).",key_text:"老子之术本于质，质以复性。",use:"khuynh hướng «dĩ Nho giải Lão» Đường · hội thông Nho-Đạo",sources:["https://zh.wikisource.org/zh-hans/%E9%81%93%E5%BE%B7%E7%9C%9F%E7%B6%93%E5%82%B3_(%E9%99%B8%E5%B8%8C%E8%81%B2) (維基文库)","https://www.shidianguji.com/book/DZ0685 (識典古籍 DZ685)"],textual_certainty:"high",notes:"DZ685 洞神部玉诀類; 陆希声/mạt Đường; «dĩ Nho giải Lão»."},{dz:"DZ680",name_han:"宋徽宗御解道德真经",name_vi:"Tống Huy Tông Ngự Giải",bu:"洞神",author:"赵佶 (宋徽宗)",era:"Bắc Tống (1118, trọng hòa nguyên niên)",topic:"philosophy",essence:"Hoang đế Tống Huy Tông hạ chiếu 1118 — dung hợp TAM GIÁO (Nho-Thích-Đạo), dẫn庄子/列子/Luận ngữ/Mạnh/Thi/Thư giải Lão. Tự định nghĩa «ĐẠO giả nhân chi sở cộng do, ĐỨC giả tâm chi sở tự đắc»; Đạo亘 vạn thế bất hao, Đức đầy trọn nhất tính thường còn. Biến Lão tử thành cơ sở triết học-thần thánh hóa chính sách «tôn Đạo hưng giáo». Một trong «tứ đế ngự chú».",key_text:"道者，人之所共由；德者，心之所自得。",use:"chính sách hưng Đạo + tam giáo dung hợp cuối Bắc Tống · «tứ đế ngự chú»",sources:["https://zh.wikisource.org/wiki/%E5%AE%8B%E5%BE%BD%E5%AE%97%E5%BE%A1%E8%A7%A3%E9%81%93%E5%BE%B7%E7%9C%9F%E7%B6%93 (維基文库)","https://www.shidianguji.com/book/DZ680 (識典古籍 DZ680)"],textual_certainty:"high",notes:"DZ680 洞神部玉诀類; 宋徽宗 1118; tam giáo dung hợp; sớ giải DZ683 章安."},{dz:"DZ689",name_han:"道德真经论（司马光）",name_vi:"Tư Mã Quang · Đạo Đức Luận",bu:"洞神",author:"司马光 (1019-1086)",era:"Bắc Tống",topic:"philosophy",essence:"Tư Mã Quang (tác giả Tư Trị Thông Giám) đọc Lão tử theo lăng kính NHO GIA CHÍNH THỐNG nhưng độc lập. Cho «ĐẠO ĐỨC LIÊN THỂ, BẤT KHẢ THIÊN CỬ» → phục hồi bản danh nguyên thủy, không chia thượng/hạ thành đạo kinh-đức kinh. Khác đa số chú gia, chủ «đạo diệc khả ngôn đạo» (đạo vẫn có thể nói được) → giảm thần bí hóa Lão. Đại biểu «dĩ Nho lý giải Lão» Bắc Tống (đối trọng Vương An Thạch phái).",key_text:"夫道德连体，不可偏举，今从本名。",use:"Lão học Bắc Tống Nho gia chính thống · đối chiếu Vương An Thạch/Tô Trách",sources:["https://zh.wikisource.org/zh-hans/%E9%81%93%E5%BE%B7%E7%9C%9F%E7%B6%93%E8%AB%96 (維基文库)","https://www.shidianguji.com/zh/book/DZ689 (識典古籍 DZ689)"],textual_certainty:"high",notes:"DZ689 洞神部玉诀類; 司马光/Bắc Tống; «dĩ Nho lý giải Lão» chính thống."},{dz:"DZ97",name_han:"太上洞玄灵宝诸天内音自然玉字",name_vi:"Chư Thiên Nội Âm Tự Nhiên Ngọc Tự",bu:"洞真",author:" (khuyết danh)",era:"Đông Tấn末-Nam triều初 (4-5c, cổ linh bảo)",topic:"classic",essence:"Cổ linh bảo kinh cốt lõi — «NỘI ÂM THIÊN THƯ/TỰ NHIÊN NGỌC TỰ»: 32 trời × 8 chữ = 256 CHỮ VÂN TRIỆN THIÊN VĂN do khí trời kết thành. Nguyên Thỉ Thiên Tôn thuyết tại Xích Lương thế giới, dẫn «Đại Phạm Ẩn Ngữ Vô Lượng Động Chương Ngọc Quyết». NỀN TẢNG thiên thư hệ Linh Bảo-Độ Nhân kinh.",key_text:"凝飞玄之气以成灵文，合八会以成音，和五合而成章。",use:"linh bảo thiên thư truyền thụ hệ · vân篆 chân văn · vũ trụ luận linh bảo",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E9%9D%88%E5%AF%B6%E8%AB%B8%E5%A4%A9%E5%85%A7%E9%9F%B3%E8%87%AA%E7%84%B6%E7%8E%89%E5%AD%97 (維基文库)","https://www.shidianguji.com/book/DZ0097 (識典古籍 DZ97)"],textual_certainty:"high",notes:"DZ97 洞真部玉诀類; 256 thiên văn chữ; 陆修静灵宝经目."},{dz:"DZ444",name_han:"太上洞玄灵宝三元品戒功德轻重经",name_vi:"Tam Nguyên Phẩm Giới Kinh",bu:"洞玄",author:" (khuyết danh)",era:"Đông Tấn末-Lưu Tống sơ (cổ linh bảo)",topic:"classic",essence:"Cổ linh bảo GIỚI LUẬT kinh — phân thượng/trung/hạ nguyên (thiên-địa-thủy quan), liệt 180 điều «TAM NGUYÊN PHẨM GIỚI TỘI MỤC» với công đức khinh trọng. EARLIEST xác lập thượng nguyên(15/1)/trung nguyên(15/7)/hạ nguyên(15/10) TAM QUAN khảo giáo hệ; kết hợp giới luật Phật giáo + thiên sư đạo + phương sĩ.",key_text:"天尊曰：上元一品天官，元气始凝，三光开明，结青黄白之气，置上元三宫。",use:"đạo giáo giới luật hình thành · tam nguyên tiết khí · tam quan khảo giáo",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E4%B8%89%E5%85%83%E5%93%81%E6%88%92%E5%8A%9F%E5%BE%B7%E8%BC%95%E9%87%8D%E7%B6%93 (維基文库)","https://ctext.org/wiki.pl?if=gb&res=403939 (CTEXT DZ444)"],textual_certainty:"high",notes:"DZ444 洞玄部本文類; 180 tam nguyên phẩm giới; 《Vô Thượng Bí Yếu》 đã dẫn."},{dz:"DZ369",name_han:"太上洞玄灵宝灭度五炼生尸妙经",name_vi:"Ngũ Luyện Sinh Thi Diệu Kinh",bu:"洞玄",author:" (khuyết danh)",era:"Đông Tấn末-Nam triều初 (cổ linh bảo)",topic:"ritual",essence:"Cổ linh bảo ĐỘ VONG/LUYỆN THI kinh cốt lõi — 32 thiên đế xuất «linh âm tự nhiên thiên thư» giao địa quan, độ nhất thiết nhân, an thi trấn linh, bảo hồn lục thần. Lập NGŨ PHƯƠNG NGŨ ĐẾ (Thanh-Xích-Hoàng-Bạch-Hắc) «luyện độ ngũ tiên an linh trấn thần» thiên văn + hoàng tăng chương pháp, đào độ cửu u địa ngục hồn.",key_text:"三十二天帝君即坐，各命飞天神人披紫阳玉台，开明真玉匮，出天中灵音自然玉书无量洞章，以属地官，度一切人，安尸镇灵，保魂录神。",use:"linh bảo độ亡/luyện thi nghi quỹ · ngũ phương ngũ đế · cửu u địa ngục cứu độ",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E6%BB%85%E5%BA%A6%E4%BA%94%E9%8D%8A%E7%94%9F%E5%B1%8D%E5%A6%99%E7%B6%93 (維基文库)","https://www.shidianguji.com/book/DZ0369 (識典古籍 DZ369)"],textual_certainty:"high",notes:"DZ369 洞玄部本文類; ngũ phương ngũ đế luyện độ; 敦煌 P.2865+S.298."},{dz:"DZ817",name_han:"太清中黄真经",name_vi:"Trung Hoàng Chân Kinh",bu:"洞神",author:" (đề 九仙君 soạn / trung hoàng chân nhân chú)",era:"Đường (~7-10c)",topic:"cultivation",essence:"Kinh thể thất ngôn cổ thi — 18 chương (nội dưỡng hình thần/thực khí huyền vi/ngũ nha hàm ác...). Cốt: thực khí tịnh cốc + thai tức + tồn tư nội thần → nuôi phôi «trung hoàng» (khí giữa) kết nội đan. Một trong những văn bản THAI TỨC SỚM NHẤT đạo giáo. (Khác thai tức kinh DZ818/819 — đây «thai tạng luận/trung hoàng chân kinh» độc lập.)",key_text:null,use:"thai tức/tịnh cốc/ngũ nha · nội luyện «cải mệnh»",sources:["https://www.shidianguji.com/zh/book/DZ0817 (識典古籍 DZ817)","https://baike.baidu.com/item/太清中黄真经 (百度百科)"],textual_certainty:"high",notes:"DZ817 洞神部方法類 (⚠ KHÔNG phải DZ842); 18 chương; thai tức sớm."},{dz:"DZ763",name_han:"太上老君说五厨经（尹愔注）",name_vi:"Ngũ Trù Kinh",bu:"洞神",author:" (kinh khuyết danh Lục triều; 尹愔 chú Đường Huyền Tông thời)",era:"Kinh Lục triều / chú Đường (~8c)",topic:"cultivation",essence:"Kinh thể ngũ ngôn vận ngữ — CHỈ 20 câu, 5 chương. «Ngũ trù» = ngũ tạng/khí ngũ phương, tồn dưỡng ngũ phương sinh khí. Tông: «TỒN NHẤT KHÍ HOÀ THÁI HOÀ» → ngũ tạng sung mãn, ngũ thần tĩnh chính. Tư tưởng nền phái phục khí/tồn tư (司马承祯 dẫn trong phục khí tinh nghĩa luận).",key_text:"一气和泰和",use:"mantra ngắn điều hoà ngũ tạng/phục khí · tồn tư",sources:["https://zh.wikisource.org/zh-hans/老子說五廚經注 (維基文库)","https://ctext.org/wiki.pl?if=gb&chapter=92813 (CTEXT DZ763)"],textual_certainty:"high",notes:"DZ763 洞神部玉诀類; 20 câu/5 chương; 尹愔 chú; ngũ trù=ngũ tạng/khí."},{dz:"DZ1040",name_han:"皇极经世",name_vi:"Hoàng Cực Kinh Thế",bu:"太玄",author:"邵雍 (Shào Yōng, tự Nghiêu Phu, thụy Khang Tiết)",era:"Bắc Tống (11c)",topic:"classic",essence:"12 quyển: Nguyên Hội Vận Thế (6) + Thanh Âm Luật Phẩm (4) + Quan Vật Nội/Ngoại thiên (2). Cốt: dùng hà lạc tượng số + «NGUYÊN-HỘI-VẬN-THẾ» (1 nguyên = 129.600 năm) suy diễn lịch sử vũ trụ hưng suy; «dĩ vật quan vật». ĐỈNH CAO tượng số học / tiên thiên học. Thu Chính thống đạo tạng 太玄 bộ. (App đã có huangji-engine → entry này = metadata/định vị đạo tạng, tránh duplicate engine.)",key_text:null,use:"象数/先天 học · nguyên hội vận thế vũ trụ suy diễn · (overlap app huangji-engine)",sources:["https://www.shidianguji.com/zh/book/DZ1040 (識典古籍 DZ1040)","https://a.daorenjia.com/daozang18-786 (道人家)"],textual_certainty:"high",notes:"DZ1040 太玄部 (q.705-719); 邵雍/Bắc Tống; ⚠ overlap app huangji-engine (kb.js) — entry này = metadata."},{dz:"DZ173",name_han:"金莲正宗记",name_vi:"Kim Liên Chánh Tông Ký",bu:"洞真",author:"秦志安 (樗栎道人, 1188-1244)",era:"Nguyên (1241, thái tông 13)",topic:"classic",essence:"Cuốn SỬ ĐẠO GIÁO TOÀN CHÂN ĐẦU TIÊN còn tồn tại — kiến tạo hệ phổ «NGŨ TỔ THẤT CHÂN» từ thái thượng lão quân → tây vương mẫu → vương huyền甫 → 钟离权 → 吕洞宾 → 刘海蟾 → 王重阳 → 7 đại đệ tử. ĐẶT NỀN MÓNG tính chính thống cho giáo phái toàn chân. 1 trong 2 tác phẩm toàn chân hiếm hoi thu cả Huyền Đô bảo tạng(Nguyên) + Chính thống đạo tạng(Minh).",key_text:null,use:"văn bản nền móng lịch sử + pháp hệ toàn chân · ngũ tổ thất chân",sources:["https://ctext.org/wiki.pl?if=gb&res=518686 (CTEXT DZ173)","https://zh.daoinfo.org/wiki/金莲正宗记 (daoinfo)"],textual_certainty:"high",notes:"DZ173 洞真部谱录類; 秦志安/Nguyên 1241; ngũ tổ thất chân."},{dz:"DZ1161",name_han:"太古集",name_vi:"Thái Cổ Tập",bu:"太平",author:"郝大通 (號廣寧/太古, 1140-1212, toàn chân thất chân, khai tổ hoa sơn phái)",era:"Kim (1178 / định bản ~1236)",topic:"cultivation",essence:"Tập thơ-văn-nghị luận郝大通 — nguyên 15 quyển nay 4. Lõi: «DỊCH TƯỢNG SỐ học» nền «TOÀN CHÂN ĐAN ĐẠO DỊCH học» — lấy quẻ hào càn khốn/hà đồ/lạc thư + đồ («càn khốn sinh lục tử đồ/«bát quái số hào thành tuế đồ») diễn nội đan. Thượng thừa Hán dịch tượng số, trung kế đồ thư dịch học, hạ khải toàn chân đan dịch hệ.",key_text:null,use:"giao thoa Dịch học-nội đan toàn chân · tượng số Dịch phái hoa sơn",sources:["https://ctext.org/wiki.pl?if=gb&res=943514 (CTEXT DZ1161)","https://zh.daoinfo.org/wiki/太古集 (daoinfo)"],textual_certainty:"high",notes:"DZ1161 太平部; 郝大通/全真七真; Dịch tượng số + nội đan."},{dz:"DZ1160",name_han:"水云集",name_vi:"Thủy Vân Tập",bu:"太平",author:"谭处端 (號長真子, 1123-1185, toàn chân thất chân)",era:"Kim (~1167-1185)",topic:"cultivation",essence:"Tập thi-từ-ca >240 bài 谭处端 — thơ từ BÌNH DÂN KHẨU NGỮ, trực chỉ nội đan tâm pháp, xoáy điều tâm/khí/hồn. Xiển dương giáo nghĩa toàn chân thanh tĩnh vô vi. Một trong TỪ TẬP QUAN TRỌNG BẬC NHẤT toàn chân thất chân (cùng đan dương từ/bàn khê tập).",key_text:null,use:"văn học + nội đan tâm pháp 谭处端/thất chân · nhập môn tu hành toàn chân",sources:["https://zh.wikisource.org/zh-hans/水云集 (維基文库)","https://zh.daoinfo.org/wiki/水云集 (daoinfo)"],textual_certainty:"high",notes:"DZ1160 太平部; 谭处端/全真七真; >240 thơ-từ bình dân."},{dz:"DZ1142",name_han:"渐悟集",name_vi:"Tiệm Ngộ Tập",bu:"太平",author:"马钰 (號丹阳子, 1123-1183, toàn chân thất chân之首, đệ nhị đại chưởng giáo)",era:"Kim (~1182-1183)",topic:"cultivation",essence:"Tập từ khúc >340 bài 马钰 — chủ đề «TIỆM NGÔ» (tu chứng dần dần, ĐỐI LẬP với «đốn ngộ» 丘处机). Nhấn «dần tu dần chứng», tự vịnh tự miễn, tả sinh hoạt tu hành; «chánh tâm thành ý kiêm tu tính mệnh». Xiển dương «thanh tĩnh» tông phong Vương Trùng Dương truyền thụ.",key_text:null,use:"trung tâm «tiệm tu» pháp môn 马丹阳 (đối chiếu «đốn ngộ» 丘长春)",sources:["https://ctext.org/wiki.pl?if=gb&res=178181 (CTEXT DZ1142)","https://zh.daoinfo.org/wiki/渐悟集 (daoinfo)"],textual_certainty:"high",notes:"DZ1142 太平部; 马钰/全真七真之首; >340 từ khúc; «tiệm ngộ»."},{dz:"DZ691",name_han:"道德真经注（苏辙）",name_vi:"Tô Triệt · Đạo Đức Chú",bu:"洞神",author:"苏辙 (1039-1112)",era:"Bắc Tống (~1100)",topic:"philosophy",essence:"Chú Lão tiêu biểu «TAM GIÁO ĐỒNG NGUYÊN» Bắc Tống — Tô Triệt dùng nhân nghĩa Nho giáo giải đạo đức kinh, chủ Nho-Phật-Đạo đồng nguyên; lấy «tâm tính» làm phương pháp giải Đạo, nối «cùng lý→tận tính→phục mệnh».",key_text:"莫非道也。而可道者不可常，惟不可道，而后可常耳。",use:"tam giáo dung hợp Bắc Tống · «dĩ tâm tính giải Lão»",sources:["https://www.shidianguji.com/book/DZ0691 (識典古籍 DZ691)","https://ctext.org/wiki.pl?if=gb&res=90512&remap=gb (CTEXT DZ691)"],textual_certainty:"high",notes:"DZ691 洞神部玉诀類; 苏辙/Bắc Tống; tam giáo đồng nguyên."},{dz:"DZ686",name_han:"道德真经传（吕惠卿）",name_vi:"Lã Huệ Khanh · Đạo Đức Truyện",bu:"洞神",author:"吕惠卿 (1032-1111)",era:"Bắc Tống (1078, nguyên phong nguyên niên)",topic:"philosophy",essence:"«Truyện» giải Lão thiên về TRỊ QUỐC CHI ĐẠO — dâng vua thuyết minh «dĩ đạo đức vi trị». Lấy «thập lục tự tâm truyền»(Thượng thư·Đại Vũ Mô) làm khung, tham Nho-Đạo, bàn tu thân-trị quốc, xưng «Đạo» = «hoàng vương chi tông».",key_text:"凡幽而不测者，阴也；明而可见者，阳也。",use:"Lão học Bắc Tống gắn biến pháp + chính trị luận",sources:["https://www.shidianguji.com/zh/book/DZ0686 (識典古籍 DZ686)","https://ctext.org/wiki.pl?if=gb&res=460797&remap=gb (CTEXT DZ686)"],textual_certainty:"high",notes:"DZ686 洞神部玉诀類; 吕惠卿/Bắc Tống 1078; «dĩ đạo đức vi trị»."},{dz:null,name_han:"老子注（王安石）",name_vi:"Vương An Thạch · Lão Tử Chú",bu:"四库",author:"王安石 (1021-1086)",era:"Bắc Tống",topic:"philosophy",essence:"Chú Lão của VƯƠNG AN THẠCH nay chỉ còn 11 chương đầu + dật văn phục dựng qua tập chú. Tư tưởng: «ĐẠO BẢN BẤT KHẢ ĐẠO», phân biệt «đạo thể» với «tích» (dấu vết), điều hòa hình thượng học Đạo gia + danh giáo Nho gia — «dĩ Nho giải Đạo» đặc trưng thời Bắc Tống (Kinh Công Tân học). ⚠ KHÔNG thu正统道藏 (nguyên thư thất truyền, dật văn qua DZ714 彭耜集注 etc.).",key_text:"道本不可道，若其可道，则是其迹也。",use:"Lão học phái Kinh Công (Tân học) + biến pháp Bắc Tống",sources:["https://baike.baidu.com/item/%E7%8E%8B%E5%AE%89%E7%9F%B3%E8%80%81%E5%AD%90%E6%B3%A8%E8%BE%91%E4%BD%87%E4%BC%9A%E9%92%9E/56396064 (百度百科)","https://homeinmists.ilotus.org/DaoZang/Tiyao4.pdf (homeinmists)"],textual_certainty:"partial",notes:"⚠ KHÔNG thu正统道藏 (thất truyền, chỉ 11 chương + dật văn qua tập chú); 王安石/Bắc Tống Kinh Công."},{dz:"DZ704",name_han:"道德真经注（吴澄）",name_vi:"Ngô Trừng · Đạo Đức Chú",bu:"洞神",author:"吴澄 (1249-1333, hiệu thảo lư)",era:"Nguyên (~đại đức-chí đại)",topic:"philosophy",essence:"Chú Lão đại biểu thời Nguyên của LÝ HỌC GIA — dùng thể-dụng luận Tống-Nguyên lý học giải đạo đức kinh: «hư vô tự nhiên vi thể, nhược nhuy bất doanh vi dụng». Chú giải tinh xác minh晰; cải biên 81 chương Lão → 68 chương. Mẫu hình điển hình «dĩ lý giải Lão»; được đánh giá «tất độc» cho Lão học.",key_text:"万物始于微而后成，始于无而后生。故常无欲空虚，可以观其始物之妙。",use:"Lão học thời Nguyên · hội thông lý học-đạo gia · «dĩ lý giải Lão»",sources:["https://ctext.org/dao-de-jing-zhu/zhs (CTEXT DZ704)","https://www.shidianguji.com/zh/book/DZ0704 (識典古籍 DZ704)"],textual_certainty:"high",notes:"DZ704 洞神部玉诀類; 吴澄/Nguyên; 68 chương; lý học giải Lão."},{dz:"DZ1146",name_han:"磻溪集（长春子磻溪集）",name_vi:"Bàn Khê Tập",bu:"太平",author:"丘处机 (长春子, 1148-1227, toàn chân thất chân, long môn phái)",era:"Kim mạt-Nguyên sơ (~1180-1210)",topic:"cultivation",essence:"470+ thơ-từ của Khâu Xứ Cơ — hermit-poet spiritual autobiography: năm khổ hạnh (cave-dwelling, một bữa/ngày, «chiến thụy ma»). Nền văn học + hagiographic long môn phái; thi phẩm được công nhận văn học nhất trong thất chân.",key_text:null,use:"lịch sử toàn chân · khổ hạnh thực hành · long môn nguồn",sources:["https://zh.wikisource.org/zh-hans/%E7%A3%BB%E6%BA%AA%E9%9B%86 (維基文库)","https://zh.daoinfo.org/index.php?title=%E7%A3%BB%E6%BA%AA%E9%9B%86 (daoinfo)"],textual_certainty:"high",notes:"DZ1146 太平部; 丘处机; 470+ thơ; «chiến thụy ma»."},{dz:"DZ1153",name_han:"云光集",name_vi:"Vân Quang Tập",bu:"太平",author:"王处一 (玉阳子, 1142-1217, toàn chân thất chân, du sơn phái)",era:"Kim (~1197)",topic:"cultivation",essence:"600+ thơ-từ-ca-tụng của Vương Xứ Nhất — xã hội học revealing nhất trong thất chân: maps toàn chân rapid spread all strata. Cặp nội đan tâm pháp (tính mệnh song tu) + ethical exhortation; «tửu sắc khí tài tồy bản bính».",key_text:null,use:"toàn chân social history · nội đan · Jin-era spread",sources:["https://zh.wikisource.org/zh-hans/%E9%9B%B2%E5%85%89%E9%9B%86 (維基文库)","https://zh.daoinfo.org/wiki/%E9%9B%B2%E5%85%89%E9%9B%86 (daoinfo)"],textual_certainty:"high",notes:"DZ1153 太平部; 王处一/全真七真; 600+ thơ; «tửu sắc khí tài»."},{dz:null,name_han:"孙不二元君法语",name_vi:"Tôn Bất Nhị Pháp Ngữ",bu:"道藏辑要",author:" (attributed 孙不二 1119-1182, toàn chân thất chân duy nhất nữ đạo; ⚠ attribution disputed, likely Minh-Thanh ngụy)",era:"Attributed Kim (~1175-1182); thực earliest witness Thanh (~early 19c)",topic:"cultivation",essence:"CANONICAL TEXTBOOK of DAOIST WOMEN'S INTERNAL ALCHEMY (女丹/坤道). 14-stage sequence: thu tâm→dưỡng khí→hành công→CHẾN LONG (斩赤龙/stop menstruation, female-specific)→...→xuất thần→xung cử. «Ngã thân vị hữu nhật, nhất khí dĩ tiên tồn». ⚠ KHÔNG thuộc正统道藏; 藏外 (đạo tạng tập yếu).",key_text:"吾身未有日，一气已先存。",use:"女丹/khôn đạo nội đan · female-specific physiology · thanh tĩnh phái",sources:["https://zh.wikisource.org/zh-hans/%E5%AD%AB%E4%B8%8D%E4%BA%8C%E5%85%83%E5%90%9B%E6%B3%95%E8%AA%9E (維基文库)","https://ctext.org/wiki.pl?if=gb&chapter=177422 (CTEXT)"],textual_certainty:"partial",notes:"⚠ KHÔNG thuộc正统道藏 (道藏辑要/藏外道书); ⚠ attribution disputed (likely Minh-Thanh ngụy托); 14-stage 女 đan."},{dz:"DZ1148",name_han:"丹阳神光灿",name_vi:"Đan Dương Thần Quang Xán",bu:"太平",author:"马钰 (丹阳子, 1123-1183, toàn chân thất chân之首)",era:"Kim (1175, đại định ất mùi)",topic:"cultivation",essence:"100 lyrics ALL in single tune «Mãn Đình Phương» — formally radical single-tune experiment: toàn chân sermon. Mỗi lyric = conversion appeal (từ bỏ tửu sắc tài khí → trở bản chân). Purest expression of Mã Ngọc's evangelistic use of ci. KHÁC 渐悟 tập (different scope/format/compilation).",key_text:null,use:"mã ngọc/du tiên phái · fixed-tune ci as toàn chân homiletic",sources:["https://baike.baidu.com/item/%E6%BB%A1%E5%BA%AD%E8%8A%B3/23188535 (百度百科)","https://www.cuhk.edu.hk/ics/journal/articles/v28p135.pdf (CUHK)"],textual_certainty:"high",notes:"DZ1148 太平部; 马钰; ~100 満庭芳 lyrics; preface 宁师常 1175; distinct from 渐悟集."},{dz:"DZ283",name_han:"黄帝龙首经",name_vi:"Long Thủ Kinh",bu:"洞真",author:" (khuyết danh; 托黄帝受玄女)",era:"Hán-Ngụy-Lục triều",topic:"classic",essence:"Sớm nhất LỤC NHÂM chiêm bốc — 72占法; 「黄帝六壬 tam kinh」trì (cùng kim quỹ ngọc hành + thụ tam tử huyền nữ). Nền Lục Nhâm system.",key_text:null,use:"lục nhâm thức pháp · chiêm bốc",sources:["https://zh.wikisource.org/zh-hans/黄帝龙首经 (維基)","https://www.shidianguji.com/book/DZ0283 (DZ283)"],textual_certainty:"high",notes:"DZ283 洞真部众术類; 72 占; lục nhâm (phi độn giáp)."},{dz:"DZ284",name_han:"黄帝金匮玉衡经",name_vi:"Kim Quỹ Ngọc Hành Kinh",bu:"洞真",author:" (khuyết danh; 托黄帝)",era:"Hán-Ngụy-Lục triều",topic:"classic",essence:"Sớm LỤC NHÂM — «Kim Quỹ»+«Ngọc Hành» 2 chương ×10 kinh = 20 kinh; 11 thần tướng (thanh long/bạch hồ/chu tước/huyền võ...). «黄帝 lục nhâm tam kinh».",key_text:null,use:"lục nhâm thần tướng + phát dụng thiệp hại",sources:["https://zh.wikisource.org/zh-hans/黄帝金匮玉衡经 (維基)","https://www.shidianguji.com/book/DZ0284 (DZ284)"],textual_certainty:"high",notes:"DZ284 洞真部众术類; lục nhâm (phi độn giáp)."},{dz:"DZ287",name_han:"通占大象历星经（甘石星经）",name_vi:"Thông Chiêm Đại Tượng Lịch Tinh Kinh",bu:"洞真",author:" (khuyết danh; 托甘德/石申)",era:"约 Đường-Tống (tập dật)",topic:"classic",essence:"Cổ thiên văn TINH CHIÊM — 甘石星经 hệ; 3 viên 28 tú + tinh đồ + chiêm nghiệm («thiên nhân cảm ứng»). Nền Đạo giáo thiên văn chiêm.",key_text:null,use:"thiên văn chiêm · 3 viên 28 tú · tinh quan",sources:["https://zh.wikisource.org/zh-hans/通占大象历星经 (維基)","https://www.shidianguji.com/book/DZ0287 (DZ287)"],textual_certainty:"high",notes:"DZ287 洞真部众术類; = 甘石星经 hệ; 2/3卷 tồn."},{dz:"DZ662",name_han:"太上老君说报父母恩重经",name_vi:"Báo Phụ Mẫu Ân Trọng Kinh",bu:"洞神",author:" (khuyết danh)",era:"Đường (~7-9c)",topic:"classic",essence:"Khuyên HIẾU ĐẠO — Lão Quân vì Hải Không Trí Tàng thuyết 10 tháng thai nghén/nhau đớn sinh nở/nuôi con của mẹ → tu sĩ báo hiếu. Dung hợp Phật nhân quả + Hoa Hạ hiếu thuận. Pháp: chép/khóa/đọc ngày trung nguyên.",key_text:"父母恩重，昊天罔极。",use:"báo ân cha mẹ · hiếu đạo · trung nguyên siêu độ",sources:["https://ctext.org/wiki.pl?if=gb&chapter=911196 (DZ662)","https://www.shidianguji.com/book/DZ0662 (DZ662)"],textual_certainty:"high",notes:"DZ662 洞神部本文類; Đường; Phật-Đạo dung hợp hiếu."},{dz:"DZ634",name_han:"太上老君说安宅八阳经",name_vi:"An Trạch Bát Dương Kinh",bu:"洞神",author:" (khuyết danh)",era:"Đường-Tống (~8-10c)",topic:"classic",essence:"AN TRẠCH nhương tai — động thổ kinh long thần/thần sát; chuyển tụng → tạ thổ thần, thần sát ẩn, nhà yên. Giao thoa Phật giáo Bát Dương thần chú kinh.",key_text:null,use:"trấn trạch · động thổ nhương tai · an gia",sources:["https://ctext.org/wiki.pl?if=gb&chapter=219323 (DZ634)","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E5%AE%89%E5%AE%85%E5%85%AB%E9%99%BD%E7%B6%93 (維基)"],textual_certainty:"partial",notes:"DZ634 洞神部本文類; giao thoa Phật Bát Dương kinh."},{dz:null,name_han:"太上老君说天妃救苦灵验经（天妃经/妈祖经）",name_vi:"Thiên Phi Cứu Khổ Kinh (Mẫu Tử)",bu:"洞神",author:" (khuyết danh)",era:"Minh sơ (~1409+, vĩnh lạc)",topic:"classic",essence:"MẪU TỬ (妈祖) kinh — Lão Quân sắc Diệu Hạnh Ngọc Nữ giáng sinh thành Thiên Phi (妈祖), 15 đại thệ: cứu thuyền/hộ khách/trục tà/bình tai/hộ sản. Ai xưng danh hiệu/đọc kinh trên sông nước → ứng cứu. Gắn tín ngưỡng妈祖 Minh-Vĩnh Lạc hải ngoại.",key_text:"一者，誓救舟船达于彼岸。二者，誓护客商，咸令安乐。",use:"hộ hàng hải · cầu bình an đường thủy ·妈祖",sources:["https://ctext.org/wiki.pl?if=gb&chapter=500311 (ctext)","https://zh.wikisource.org/wiki/太上老君说天妃救苦灵验经 (維基)"],textual_certainty:"high",notes:"洞神部本文 (DZ 未 verify Schipper); Minh ~1409; 妈祖 15 thệ."},{dz:null,name_han:"太上洞玄灵宝天尊说救苦妙经（救苦经）",name_vi:"Cứu Khổ Diệu Kinh",bu:"洞玄",author:" (khuyết danh)",era:"Đường-Tống (~8-11c)",topic:"classic",essence:"Kinh ngắn ~542 chữ toàn ngũ ngôn — tán dương THÁI ẤT CỨU KHỔ THIÊN TÔN do tam khí hóa thành, khắp mười phương; cứu chúng sinh ra mê đồ. «Khánh vân khai sinh môn, tường yên tễ tử hộ». Cốt kinh Đạo giáo độ vong đạo tràng + wăn khóa.",key_text:"尔时救苦天尊，遍满十方界。常以威神力，救拔诸众生。",use:"độ vong đạo tràng · wăn khóa · tiêu tội bạt tội",sources:["https://zh.wikisource.org/zh-hans/太上洞玄灵宝天尊说救苦妙经 (維基)","https://ctext.org/wiki.pl?if=gb&chapter=819344 (ctext)"],textual_certainty:"partial",notes:"洞玄部本文 (DZ 未 verify); Thái Ất Cứu Khổ Thiên Tôn; 542 chữ ngũ ngôn."},{dz:"1139",name_han:"三洞珠囊",name_vi:"Tam Động Châu Nang",bu:"太玄部",author:"王悬河",era:"唐",topic:"百科类编",essence:"Bộ bách khoa Đạo giáo đời Đường do Vương Huyền Hà biên soạn, trích dẫn kinh điển Tam Động theo chủ đề (thần tiên, giới luật, nghi thức, địa lý tiên). Là nguồn quan trọng để phục hồi các đoạn kinh thất lạc và đối chiếu văn bản Đạo tạng.",key_text:"三洞者，洞真、洞玄、洞神是也。",use:"tra cứu thuật ngữ / trích dẫn kinh",sources:["https://zh.wikipedia.org/wiki/%E4%B8%89%E6%B4%9E%E7%8F%A0%E5%9B%8A","https://www.daozang.org/","Schipper & Verellen, The Taoist Canon (2004), DZ 1139"],textual_certainty:"high",notes:"DZDZ1139"},{dz:"1129",name_han:"道教义枢",name_vi:"Đạo Giáo Nghĩa Khu",bu:"太平部",author:"孟安排",era:"唐",topic:"教义纲要",essence:"Cương yếu giáo nghĩa Đạo giáo đời Đường do Mạnh An Bài biên soạn, hệ thống hóa các phạm trù triết-giáo (đạo, đức, tam洞, ngũ气, nhân quả). Được dùng như sách giáo khoa giáo lý, không phải kinh huyền ký.",key_text:"夫道者，虚无之系，造化之根，神明之本，天地之元。",use:"học giáo nghĩa / đối chiếu thuật ngữ",sources:["https://zh.wikipedia.org/wiki/%E9%81%93%E6%95%99%E4%B9%89%E6%9E%A2","Schipper & Verellen, The Taoist Canon (2004), often listed as DZ 1129 (not 1123)","https://ctext.org/"],textual_certainty:"partial",notes:"DZDZ1129"},{dz:"1132",name_han:"道典论",name_vi:"Đạo Điển Luận",bu:"太玄部",author:"佚名",era:"唐–五代?",topic:"类书/义理",essence:"Sách luận-điển Đạo giáo theo lối loại thư, trích và bàn các khái niệm kinh điển (thần, tiên, đạo, đức, thiên địa). Ít chi tiết tác giả; thường được xếp gần nhóm bách khoa đời Đường–Ngũ Đại.",key_text:"null",use:"tham chiếu khái niệm",sources:["Schipper & Verellen, The Taoist Canon (2004), DZ 1132","https://www.daozang.org/","Daozang catalog lists (Zhengtong)"],textual_certainty:"partial",notes:"DZDZ1132"},{dz:"1123",name_han:"一切道经音义妙门由起",name_vi:"Nhất Thiết Đạo Kinh Âm Nghĩa Diệu Môn Do Khởi",bu:"太平部",author:"史崇玄等",era:"唐",topic:"音义/目录序",essence:"Công trình âm nghĩa và dẫn khởi về nguồn gốc kinh Đạo, do sử thần đời Đường (Sử Sùng Huyền và đồng sự) biên soạn theo chiếu. Gồm phần ‘Diệu môn do khởi’ giải thích nguồn kinh và bảng âm nghĩa thuật ngữ.",key_text:"夫道经者，盖三洞之枢要，众经之总会。",use:"âm nghĩa / lịch sử kinh",sources:["Schipper catalog: often DZ 1123 (verify vs. neighbor numbers)","https://zh.wikisource.org/","Daozang / Tang imperial collations scholarship"],textual_certainty:"partial",notes:"DZDZ1123"},{dz:null,name_han:"太玄经",name_vi:"Thái Huyền Kinh",bu:"n/a (儒家/象数; 非道藏正典主体)",author:"扬雄",era:"西汉",topic:"象数哲学",essence:"Tác phẩm của Dương Hùng mô phỏng Kinh Dịch bằng hệ 81 ‘thủ’ (theo số 3), thuộc dòng Nho–tượng số, không phải kinh Đạo giáo điển hình. Một số bản chú/tham chiếu có thể xuất hiện quanh Đạo tạng nhưng bản chính Thái Huyền không được coi là kinh Đạo tạng chuẩn (Schipper).",key_text:"玄者，幽摛万类而不见形者也。",use:"triết học tượng số / so sánh Dịch",sources:["https://zh.wikipedia.org/wiki/%E5%A4%AA%E7%8E%84","https://ctext.org/tai-xuan-jing","Schipper & Verellen — not a core Daoist scripture entry under Yang Xiong"],textual_certainty:"high",notes:"DZnot_in_Daozang_as_YangXiong"},{dz:null,name_han:"五显灵官大帝",name_vi:"Ngũ Hiển Linh Quan Đại Đế",bu:"正一/民间信仰 (经文分散)",author:"佚名/民间",era:"宋–明流行",topic:"神祇/灵官信仰",essence:"Hệ thần Ngũ Hiển / Linh Quan (liên hệ Vương Linh Quan, Hỏa thần bảo hộ) phổ biến từ Tống–Minh, vừa trong Đạo giáo chính thức vừa trong tín ngưỡng dân gian. Kinh và sớ tụng rải rác; không gói gọn một DZ# duy nhất như kinh cổ.",key_text:"null",use:"thờ cúng / sớ tụng bảo hộ",sources:["scholarship on Wuxian / Lingguan cult","Daozang & folk liturgy catalogs","temple gazetteers / 灵官王天君 materials"],textual_certainty:"low",notes:"DZvarious_cult_texts"},{dz:null,name_han:"玄天上帝百字圣号",name_vi:"Huyền Thiên Thượng Đế Bách Tự Thánh Hiệu",bu:"斋醮科仪",author:"佚名",era:"明以后流行",topic:"圣号/称谓",essence:"Bài ‘trăm chữ’ xưng tụng hiệu danh Huyền Thiên Thượng Đế (Chân Vũ), dùng trong nghi thức và tụng niệm. Thuộc văn bản nghi lễ phổ biến hơn là kinh DZ cổ định số; nhiều bản chùa miếu và đạo viện lưu hành.",key_text:"混元六天传法教主修真悟道降魔护道天尊",use:"tụng hiệu / nghi lễ Chân Vũ",sources:["Xuantian Shangdi / Zhenwu liturgical collections","temple 宝诰 / 圣号 editions","Daoist ritual handbooks"],textual_certainty:"partial",notes:"DZliturgical_not_fixed_DZ"},{dz:"1400",name_han:"太上九真明科",name_vi:"Thái Thượng Cửu Chân Minh Khoa",bu:"洞真部·戒律类",author:"上清系佚名",era:"东晋–南朝 (上清)",topic:"上清戒律",essence:"Kinh giới luật Thượng Thanh nêu ‘Cửu Chân’ và các khoa điều tu trì, cấm kỵ, truyền kinh. Là một trong các bản minh khoa quan trọng của dòng Động Chân, định hình kỷ luật truyền thụ và hành trì.",key_text:"九真明科，上清之要戒也。",use:"giới luật / truyền thụ Thượng Thanh",sources:["Schipper & Verellen, Shangqing precept literature","Daozang 洞真部戒律类 catalogs","studies on Shangqing Mingke texts"],textual_certainty:"partial",notes:"DZDZ1400_or_Shangqing_code"},{dz:"DZ828",name_han:"幼真先生服內元炁訣",name_vi:"Ấu Chân tiên sinh phục nội nguyên khí quyết",bu:"洞神",author:"佚名（序稱天寶中得羅浮王公傳；《新唐書》或聯康仲熊）",era:"唐",topic:"服气",essence:"Kinh phục khí thai tức thời Đường, còn gọi là 幻真/服內元炁訣, chép khoảng 15 quyết: tiến thủ, đào khí, điều khí, yến khí, hành khí, luyện khí, ủy khí, bế khí, bố khí, lục khí, điều dịch, ẩm thực, hưu lương, thủ chân, thai tức. Cốt lõi là phục nội khí (thai tức) sẵn trong thân, không cậy ngoại khí; nội dung gần với 《嵩山太无先生气经》. Trong chính thống đạo tạng thuộc 洞神部方法類; 中华道藏 xếp nhóm Thái Thanh nhiếp dưỡng. Số 道藏提要 (khoảng 822) khác hệ Schipper DZ828.",key_text:"外氣剛勁，非俗中之士所宜服也。至如內炁，是曰胎息，身中自有，非假外求。",use:"Module phục khí/thai tức: checklist 15 quyết, phân biệt nội–ngoại khí, cảnh báo không luyện mù.",sources:["https://zh.daoinfo.org/index.php?title=%E5%B9%BC%E7%9C%9F%E5%85%88%E7%94%9F%E6%9C%8D%E5%85%A7%E5%85%83%E7%82%81%E8%A8%A3&variant=zh-hans (daoinfo)","https://www.shidianguji.com/zh/book/DZ0828 (shidianguji)","https://crta.info/wiki/%E5%B9%BC%E7%9C%9F%E5%85%88%E7%94%9F%E6%9C%8D%E5%85%A7%E5%85%83%E7%82%81%E8%A8%A3_-_D52.12 (crta)"],textual_certainty:"high",notes:"Grok-4.5 web-search · batch13"},{dz:"DZ930",name_han:"三十六水法",name_vi:"Tam thập lục thủy pháp",bu:"洞神",author:"佚名",era:"魏晋南北朝",topic:"外丹",essence:"Sách thủy pháp ngoại đan cổ: hóa khoáng thạch (phàn thạch, hùng hoàng, thư hoàng, đan sa, tằng thanh… v.v.) thành “thủy” bằng trúc thùng, tiêu thạch, hoa trì (dấm đặc) hoặc chôn đất. Gốc gắn 《抱朴子·遐览》 《三十六水经》; bản chính thống 洞神部众术類. Có 36 pháp gốc và phần bổ sung (thạch đảm, đồng thanh…); dùng làm dung môi/phụ liệu luyện đan, không phải “dược uống” hiện đại.",key_text:"取礬石一斤，無膽而馬齒者，納青竹筒中，薄削筒表，以硝石四兩，覆薦上下，深固其口，納華池中，三十日成水。",use:"Từ điển thuật ngữ ngoại đan/thủy pháp; hiển thị công thức tóm tắt + cảnh báo độc hại, không hướng dẫn thực hành.",sources:["https://zh.wikisource.org/wiki/%E4%B8%89%E5%8D%81%E5%85%AD%E6%B0%B4%E6%B3%95 (zh.wikisource)","https://zh.daoinfo.org/index.php?title=%E4%B8%89%E5%8D%81%E5%85%AD%E6%B0%B4%E6%B3%95&variant=zh-hans (daoinfo)","https://www.shidianguji.com/zh/book/DZ0930 (shidianguji)"],textual_certainty:"high",notes:"Grok-4.5 web-search · batch13"},{dz:"DZ883",name_han:"太清經天師口訣",name_vi:"Thái Thanh kinh Thiên Sư khẩu quyết",bu:"洞神",author:"佚名",era:"南北朝",topic:"外丹",essence:"Một quyển 洞神部众术類: nửa đầu khẩu quyết Thái Thanh thần đan (hoa trì, thủy chân châu, tiêu chì thiếc thành thủy ngân, hùng tuyết…), gần 《抱朴子·金丹》; nửa sau 《赤松子肘后药诀》 mười tán/cao (độ tai linh phi tán, ngọc linh phi hà tán…). Nhấn mạnh chọn sơn lâm tĩnh xứ, phù dược trừ tà khi hợp đại dược. Tiêu đề rút gọn “天师口诀” dễ nhầm; tên chuẩn trong tạng là 《太清經天師口訣》.",key_text:"經名：太清經天師口訣。撰人不詳，約出於南北朝。",use:"Lược đồ khẩu quyết ngoại đan + danh mục 10 phương Xích Tùng; chỉ khảo cứu lịch sử, cấm hướng dẫn chế dược.",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E6%B8%85%E7%B6%93%E5%A4%A9%E5%B8%AB%E5%8F%A3%E8%A8%A3 (zh.wikisource)","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E6%B8%85%E7%B6%93%E5%A4%A9%E5%B8%AB%E5%8F%A3%E8%A8%A3&variant=zh-hans (daoinfo)","https://www.shidianguji.com/zh/book/DZ0883 (shidianguji)"],textual_certainty:"high",notes:"Grok-4.5 web-search · batch13"},{dz:"DZ873",name_han:"黃庭遁甲緣身經",name_vi:"Hoàng Đình độn giáp duyên thân kinh",bu:"太玄",author:"佚名（託名老子/黃庭系統）",era:"唐宋间",topic:"cultivation",essence:"Kinh dưỡng sinh–trừ tà gắn Hoàng Đình và lục giáp: bệnh tật, ác mộng thì bế khí tụng danh thần lục giáp theo can chi; viết phù lục giáp/lục bính… để tị quỷ, binh tặc, thủy hỏa. Phần sau giải thuật ngữ 《黃庭外景》, chỉ vị tạng phủ và nội thị trị bệnh (ưu thương can → tư tâm dưỡng…), kèm tụng 《黃庭》 và tồn tư thần diện/tạng. Chính thống xếp 太玄部 (không phải 洞玄 như một số nhãn phụ); CRTA xác nhận DZ873.",key_text:"老子《黃庭遁甲緣身經》，若有疾病腫痛惡夢，各徵眾怪，皆讀之。",use:"Map lục giáp + Hoàng Đình nội thị trị liệu; UI đọc/tụng + sơ đồ tạng thần (phi y khoa).",sources:["https://zh.daoinfo.org/index.php?title=%E9%BB%83%E5%BA%AD%E9%81%81%E7%94%B2%E7%B7%A3%E8%BA%AB%E7%B6%93&variant=zh-hans (daoinfo)","https://crta.info/wiki/%E9%BB%83%E5%BA%AD%E9%81%81%E7%94%B2%E7%B7%A3%E8%BA%AB%E7%B6%93_-_C89 (crta)","https://zh.wikisource.org/wiki/%E9%BB%83%E5%BA%AD%E9%81%81%E7%94%B2%E7%B7%A3%E8%BA%AB%E7%B6%93 (zh.wikisource)"],textual_certainty:"high",notes:"Grok-4.5 web-search · batch13"},{dz:"DZ820",name_han:"太清調氣經",name_vi:"Thái Thanh điều khí kinh",bu:"洞神",author:"佚名",era:"唐",topic:"服气",essence:"Một quyển 洞神部方法類: nửa đầu bác bỏ pháp phục khí cũ (đếm theo giờ tử–ngọ, sinh khí/tử khí ngày, tồn tưởng ngũ phương, bế khí công bệnh mù quáng, cố khí không tiết…); nửa sau trình bày điều khí–thai tức lấy nguyên khí, cửa mũi–miệng, lục khí (hý/ha/hô/hu/xuy/hi) và chế độ ẩm thực dần. CRTA và shidianguji thống nhất DZ820.",key_text:"蓋由不服元氣，不識深根，諸如此流，舉世共矣。",use:"FAQ “sai lầm phổ biến khi tập khí” + so sánh với các kinh phục khí khác.",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E6%B8%85%E8%AA%BF%E6%B0%A3%E7%B6%93 (zh.wikisource)","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E6%B8%85%E8%AA%BF%E6%B0%A3%E7%B6%93&variant=zh-hans (daoinfo)","https://crta.info/wiki/%E5%A4%AA%E6%B8%85%E8%AA%BF%E6%B0%A3%E7%B6%93_-_D52.04 (crta)"],textual_certainty:"high",notes:"Grok-4.5 web-search · batch13"},{dz:"DZ847",name_han:"太上肘後玉經方",name_vi:"Thái Thượng trụ hậu ngọc kinh phương",bu:"洞神",author:"盧遵元（霞栖子）編",era:"晚唐",topic:"外丹",essence:"Một quyển phương phục thực Thượng Thanh theo Bát quái: thất tinh tán, tứ phiến tán, hà xa phương, tứ đồng tán, mi lộc phấn, hạnh kim đan, câu kỷ tiễn, sàm mễ…—chủ yếu thảo dược/động vật, không phải lô đan khoáng độc điển hình. Hệ truyền thụ Thanh Đồng quân → Sào Cư tử → Hàn Thê tử → Hà Thê tử (Lư) → Ẩn Thê tử (Thi Kiên Ngô). Tên đầy đủ có “方”; Komjathy DZ847 (CRTA đôi chỗ ghi 848—ưu tiên 847).",key_text:"昔巢居子奉事東海青童君，以節苦心寂奉師禮，冒暑雨祁寒，無懈無息，僅二十年，乃口授玄法，手錄聖方。",use:"Catalog 8 phương bát quái + dòng truyền thụ; gắn module phục thực lịch sử, không khuyến khích pha chế.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E8%82%98%E5%BE%8C%E7%8E%89%E7%B6%93%E6%96%B9&variant=zh-hans (daoinfo)","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E8%82%98%E5%BE%8C%E7%8E%89%E7%B6%93%E6%96%B9 (zh.wikisource)","https://www.jstor.org/stable/26768560 (Komjathy Zhonghua Daozang index)"],textual_certainty:"high",notes:"Grok-4.5 web-search · batch13"},{dz:"null",name_han:"神仙傳",name_vi:"Thần Tiên truyện",bu:"太玄",author:"葛洪",era:"东晋",topic:"仙传",essence:"Tiên truyện Cát Hồng (sau 《抱朴子》), khoảng 84 nhân vật, chứng minh tiên thực hữu và nhấn minh sư–thử luyện. KHÔNG thu trong 《正統道藏》 (nhiều thư mục ghi “道藏未收”); lưu truyền qua 《汉魏丛书》《四库全书》《道藏精华录》… Nên dz=null; đừng gán nhầm số DZ của 《列仙傳》 hay truyện khác. Dùng làm nguồn văn hóa/tiên thoại song song với DZ294.",key_text:"予今復抄集古之仙者，見於仙經服食方及百家之書、先師所說、耆儒所論，以為十卷，以傳知真識遠之士。",use:"Corpus tiên truyện ngoại tạng: so sánh với 《列仙傳》; ghi rõ “ngoài chính thống đạo tạng”.",sources:["https://zh.wikisource.org/wiki/%E7%A5%9E%E4%BB%99%E5%82%B3 (zh.wikisource)","https://zh.daoinfo.org/index.php?title=%E7%A5%9E%E4%BB%99%E5%82%B3&variant=zh-hans (daoinfo)","https://www.daoist.org/BookSearch(test)/list012/038-1.pdf (daoist.org: 道藏未收)"],textual_certainty:"high",notes:"Grok-4.5 web-search · batch13"},{dz:"DZ297",name_han:"历世真仙体道通鉴续编",name_vi:"Lịch Thế Chân Tiên Thể Đạo Thông Giám Tục Biên",bu:"洞真",author:"赵道一",era:"元（约至元末）",topic:"仙传",essence:"Đây là phần tục biên năm quyển của bộ tiên truyện lớn 《历世真仙体道通鉴》 do đạo sĩ núi Phù Vân Triệu Đạo Nhất biên soạn. Sách chủ yếu bổ sung các nhân vật đạo giáo Kim–Nguyên, trọng tâm là Bắc Thất Chân và dòng Toàn Chân như Vương Trùng Dương, Mã Ngọc, Khâu Xử Cơ. Cùng chính biên và hậu tập, bộ sách tạo thành hệ phổ lục tiên truyện quy mô lớn trong Chính Thống Đạo Tạng.",key_text:"null",use:"Tra cứu tiên truyện Toàn Chân Kim–Nguyên; đối chiếu lịch sử giáo đoàn và hagiography",sources:["https://www.shidianguji.com/book/DZ0297","https://ctext.org/wiki.pl?if=gb&res=591421&remap=gb","https://zh.wikisource.org/zh-hans/%E6%AD%B7%E4%B8%96%E7%9C%9F%E4%BB%99%E9%AB%94%E9%81%93%E9%80%9A%E9%91%91%E7%BA%8C%E7%B7%A8","https://baike.baidu.com/item/%E5%8E%86%E4%B8%96%E7%9C%9F%E4%BB%99%E4%BD%93%E9%81%93%E9%80%9A%E9%89%B4/4742564"],textual_certainty:"high",notes:"batch14 · Grok-4.5 web-search"},{dz:"DZ956",name_han:"终南山说经台历代真仙碑记",name_vi:"Chung Nam Sơn Thuyết Kinh Đài Lịch Đại Chân Tiên Bi Ký",bu:"洞神",author:"朱象先",era:"元（至元己卯 1279）",topic:"仙传",essence:"Đạo sĩ Mao Sơn Chu Tượng Tiên khi lễ tổ đình Toàn Chân và Lâu Quan Đài ở Chung Nam đã tiết lục 《楼观先师传》 và các truyền bản cũ, soạn thành bi ký một quyển. Sách chép từ Văn Thủy chân nhân Doãn Hỷ trở xuống các chân tiên liên quan Lâu Quan/Thuyết Kinh Đài, mỗi người có truyện ngắn kèm tán. Đây là phổ lục địa phương quan trọng kết nối truyền thống Lâu Quan với môi trường Toàn Chân đời Nguyên.",key_text:"楼观为天下道林张本之地，自文始上仙之后，登真之士，无世无之。",use:"Nghiên cứu Lâu Quan, phổ hệ tiên chân Chung Nam; tư liệu bi ký–phổ lục",sources:["https://www.shidianguji.com/book/DZ0956","https://zh.wikisource.org/zh-hans/%E7%B5%82%E5%8D%97%E5%B1%B1%E8%AA%AA%E7%B6%93%E8%87%BA%E6%AD%B7%E4%BB%A3%E7%9C%9F%E4%BB%99%E7%A2%91%E8%A8%98","https://zh.daoinfo.org/index.php?title=%E7%B5%82%E5%8D%97%E5%B1%B1%E8%AA%AA%E7%B6%93%E8%87%BA%E6%AD%B7%E4%BB%A3%E7%9C%9F%E4%BB%99%E7%A2%91%E8%A8%98&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&res=947920"],textual_certainty:"high",notes:"batch14 · Grok-4.5 web-search"},{dz:"DZ784",name_han:"太上老君戒经",name_vi:"Thái Thượng Lão Quân Giới Kinh",bu:"洞神",author:"khuyết danh（约南北朝；旧录或题葛洪，未确）",era:"南北朝（约）",topic:"戒律",essence:"Kinh một quyển thuộc Động Thần bộ giới luật, thuật Lão Quân trao 《道德》 cho Doãn Hỷ rồi dạy trì thân phụng kinh. Cốt lõi là ngũ giới: không sát, không đạo, không dâm, không vọng ngữ, không rượu, coi giới là gốc giữ thân và gốc giữ pháp. Sách liên hệ ngũ giới với ngũ hành, ngũ tạng, ngũ đế, nhấn mạnh trì giới mới tiến tới kinh pháp và thành đạo.",key_text:"老君曰：第一戒殺。第二戒盜。第三戒媱。第四戒妄語。第五戒酒。是爲五戒。",use:"Giới bản sơ cấp; nền tảng ngũ giới đạo sĩ và cư sĩ; đối chiếu với 《云笈七签》节录",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E6%88%92%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E6%88%92%E7%B6%93","https://ctext.org/wiki.pl?if=gb&chapter=190444"],textual_certainty:"high",notes:"batch14 · Grok-4.5 web-search"},{dz:"null",name_han:"初真戒（初真戒律）",name_vi:"Sơ Chân Giới",bu:"续道藏",author:"王常月（崑阳子）述/编；渊源出《虚皇天尊初真十戒文》等",era:"清初（顺治–康熙；戒本定型见道藏辑要）",topic:"戒律",essence:"Đàn đầu trong Toàn Chân Tam Đàn Đại Giới: gồm tam quy, ngũ giới, sơ chân thập giới, nữ chân cửu giới và các uy nghi. Truyền thống gán cho Long Môn luật sư Vương Thường Nguyệt công khai truyền giới; nguyên tắc tiến bậc: thụ Sơ Chân rồi mới Trung Cực và Thiên Tiên. Bản đầy đủ lưu trong 《道藏辑要》, không phải đơn hành độc lập trong Chính Thống Đạo Tạng; cốt lõi thập giới bắt nguồn từ giới văn Đạo Tạng thời sớm hơn.",key_text:"戒者，禁止之辞，益善止恶，皈真捨妄之谓也。",use:"Giới đàn Toàn Chân hiện hành; quy phạm xuất gia và uy nghi cung quán",sources:["https://crta.info/wiki/%E5%88%9D%E7%9C%9F%E6%88%92%E5%BE%8B_-_K81","https://baike.baidu.com/item/%E4%B8%89%E5%A0%82%E5%A4%A7%E6%88%92/4966768","https://www.qztao.org/dissert_15.htm","https://dao.crs.cuhk.edu.hk/Main/wp-content/uploads/2018/08/Daoist_newsletter_issue08.pdf"],textual_certainty:"partial",notes:"batch14 · Grok-4.5 web-search"},{dz:"DZ1125",name_han:"洞玄灵宝三洞奉道科戒营始",name_vi:"Động Huyền Linh Bảo Tam Động Phụng Đạo Khoa Giới Doanh Thủy",bu:"太平",author:"托名金明七真（非张万福；张万福另撰《传授三洞经戒法箓略说》等）",era:"南北朝末–隋唐之际（玄宗前已行世）",topic:"戒律",essence:"Khoa giới–uy nghi quan trọng thời sớm: phần “chỉ tu thời yếu” liệt khoa điều sinh hoạt, y phục, kiến quán, tạo tượng, tả kinh; phần “nghi phạm” gồm tụng kinh, giảng kinh, pháp thứ, pháp phục, thường triều, trai hội, độ nhân. 《法次仪》 ghi giai thứ thụ kinh giới pháp lục và mục lục gần 250 đạo thư, cực quý cho khảo chứng kinh điển. Lưu ý: nhan đề mang “Động Huyền Linh Bảo” nhưng bản Chính Thống xếp vào Thái Bình bộ; tác giả thư tịch là Kim Minh Thất Chân chứ không phải Trương Vạn Phúc.",key_text:"寻三洞大经，率备威仪科戒。",use:"Nghiên cứu chế độ khoa giới–truyền lục Sui–Tang; mục lục kinh sách; quy phạm cung quán",sources:["https://www.shidianguji.com/book/DZ1125","https://zh.daoinfo.org/index.php?title=%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E4%B8%89%E6%B4%9E%E5%A5%89%E9%81%93%E7%A7%91%E6%88%92%E7%87%9F%E5%A7%8B&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E4%B8%89%E6%B4%9E%E5%A5%89%E9%81%93%E7%A7%91%E6%88%92%E7%87%9F%E5%A7%8B","https://ctext.org/wiki.pl?if=gb&res=170314"],textual_certainty:"high",notes:"batch14 · Grok-4.5 web-search"},{dz:"DZ223",name_han:"清微元降大法",name_vi:"Thanh Vi Nguyên Giáng Đại Pháp",bu:"洞真",author:"khuyết danh（元清微派道士编集）",era:"元（谱系止于黄舜申）",topic:"fu",essence:"Tổng tập đạo pháp phái Thanh Vi khoảng 25 quyển: nửa trước kể nguồn gốc và sư thừa, tuyên bố hội tụ Nguyên Thủy–Thượng Thanh–Linh Bảo–Đạo Đức–Chính Nhất; nửa sau liệt chư tướng và ~50 loại lôi pháp, phù chú, thiên thư. 《道法枢纽》 nhấn mạnh nội tu tâm tính và “điểm linh quang” là gốc, phù chú chỉ là ngọn—đánh dấu lý luận phù lục–nội đan chín muồi đời Tống–Nguyên.",key_text:"null",use:"Nghiên cứu Thanh Vi phái và lôi pháp; lý thuyết nội đan–ngoại phù",sources:["https://www.shidianguji.com/zh/book/DZ0223","https://zh.daoinfo.org/index.php?title=%E6%B8%85%E5%BE%AE%E5%85%83%E9%99%8D%E5%A4%A7%E6%B3%95&variant=zh-hans","https://zh.wikisource.org/wiki/%E6%B8%85%E5%BE%AE%E5%85%83%E9%99%8D%E5%A4%A7%E6%B3%95","https://ctext.org/wiki.pl?if=gb&res=724335"],textual_certainty:"high",notes:"batch14 · Grok-4.5 web-search"},{dz:"DZ1166",name_han:"法海遗珠",name_vi:"Pháp Hải Di Châu",bu:"太平",author:"khuyết danh",era:"元末明初",topic:"fu",essence:"Tổng tập 46 quyển hợp pháp thuật Tống–Nguyên (Thần Tiêu, Thái Ất, Bắc Đế, Chính Nhất, Tịnh Minh, Tây Hà, Nam Tông…), hơn 40 loại phù chú, trọng tâm lôi pháp. Đặc trưng “nội đan ngoại phù”: trước tồn tư luyện khí, rồi mới thư phù triệu lôi thần; dùng để hô phong hoán vũ, trục quỷ trị bệnh, luyện độ. Là “biển pháp” thực dụng quan trọng để khảo dị các dòng lôi pháp.",key_text:"null",use:"Đối chiếu lôi pháp đa phái; nghi thức cầu mưa–trục tà–luyện độ",sources:["https://zh.daoinfo.org/index.php?title=%E6%B3%95%E6%B5%B7%E9%81%BA%E7%8F%A0&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E6%B3%95%E6%B5%B7%E9%81%BA%E7%8F%A0","https://ctext.org/wiki.pl?if=gb&res=588781","https://baike.baidu.com/item/%E6%B3%95%E6%B5%B7%E9%81%97%E7%8F%A0/7936190"],textual_certainty:"high",notes:"batch14 · Grok-4.5 web-search"},{dz:"DZ693",name_han:"道德真经指归",name_vi:"Đạo Đức Chân Kinh Chỉ Quy",bu:"洞神",author:"严遵（君平）撰；谷神子注",era:"西汉（严遵）；唐注；道藏本残",topic:"philosophy",essence:"Chú giải 《老子》 sớm nhất còn lại một phần: chia 72 chương, lấy tự nhiên vô vi làm tông, từ đạo–đức sinh thần minh, thái hòa rồi hóa sinh vạn vật. Kết hợp Dịch–Lão, hướng tới trị thân và trị quốc theo tinh thần Hoàng–Lão. Bản Chính Thống Đạo Tạng khuyết quyển 1–6, chỉ còn 7 quyển sau kèm chú Cốc Thần Tử.",key_text:"道德为母，効经列首，天地为象。",use:"Lão học Hán đại; tư tưởng huyền học sớm; đối chiếu các bản chỉ quy",sources:["https://www.shidianguji.com/book/DZ0693","https://zh.daoinfo.org/index.php?title=%E9%81%93%E5%BE%B7%E7%9C%9F%E7%B6%93%E6%8C%87%E6%AD%B8%EF%BC%88%E5%9A%B4%E9%81%B5%EF%BC%89&variant=zh-hant","https://ctext.org/wiki.pl?if=gb&res=78961&remap=gb","https://baike.baidu.com/item/%E9%81%93%E5%BE%B7%E7%9C%9F%E7%BB%8F%E6%8C%87%E5%BD%92/23145724"],textual_certainty:"high",notes:"batch14 · Grok-4.5 web-search"},{dz:"null",name_han:"老子铭",name_vi:"Lão Tử Minh",bu:"续道藏",author:"边韶",era:"东汉延熹八年（165）",topic:"classic",essence:"Bia minh do Trần tướng Biên Thiều soạn khi Hán Hoàn Đế sai tế Lão Tử ở Khổ huyện (Lộc Ấp). Văn bản kết hợp tiểu sử Lão Tử kiểu Sử ký với xu hướng thần hóa: ly hợp hỗn độn, tồn tưởng đan điền, Thái Nhất tử phòng. Không thuộc Chính Thống Đạo Tạng; là bia khắc then chốt chứng kiến Lão Tử từ hiền triết sang đối tượng tế tự–thần tính hóa cuối Đông Hán.",key_text:"老子姓李，字伯阳，楚相县人也。",use:"Lịch sử thần hóa Lão Tử; tư liệu Hán bi; nghiên cứu Hoàng–Lão tế tự",sources:["https://zh.wikisource.org/zh-hans/%E8%80%81%E5%AD%90%E9%8A%98","https://baike.baidu.com/item/%E8%80%81%E5%AD%90%E9%93%AD/3781667","https://www.laoziguli.cn/2022/02/51.html"],textual_certainty:"high",notes:"batch14 · Grok-4.5 web-search"},{dz:"null",name_han:"太上玄门早晚功课经",name_vi:"Thái Thượng Huyền Môn Tảo Vãn Công Khóa Kinh",bu:"续道藏",author:"khuyết danh（全真丛林日课集成；见《道藏辑要》）",era:"明中晚期成型，清初普及；辑要本",topic:"mantra",essence:"Kinh nhật tụng cung quán Toàn Chân: tảo đàn và vãn đàn, chọn lọc kinh chú tinh yếu (thường gồm 《清静经》…), mở đầu bằng bộ hư–thanh trừng. Không thấy bản độc lập trong Chính Thống Đạo Tạng; lưu trong 《道藏辑要》 và thực hành cung quán. Công năng: định khóa tu trì hằng ngày, tịnh tâm, siêu độ, củng cố kỷ luật tòng lâm.",key_text:"大道洞玄虚，有念无不契。鍊质入仙真，遂成金刚体。",use:"Nhật khóa đạo sĩ Toàn Chân; tụng kinh sáng–tối tại cung quán",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E7%8E%84%E9%96%80%E6%99%9A%E5%A3%87%E5%8A%9F%E8%AA%B2%E7%B6%93","https://ctext.org/wiki.pl?if=gb&chapter=2405631","https://www.qztao.org/dissert_7.htm"],textual_certainty:"partial",notes:"batch14 · Grok-4.5 web-search"},{dz:"null",name_han:"道德真经义疏（老子道德经开题序诀义疏）",name_vi:"Đạo Đức Chân Kinh Nghĩa Sớ",bu:"太玄",author:"成玄英",era:"唐初",topic:"philosophy",essence:"Chú sớ Lão học trọng yếu đời Đường của Thành Huyền Anh (Trùng Huyền học), thường gọi 《义疏》; tên đầy đủ gần với 《老子道德经开题序诀义疏》. Dùng “trùng huyền” (huyền chi hựu huyền) giải vô, hữu, đạo, nhấn mạnh quên ngôn–quên tượng để hợp đạo. Không còn bản độc lập hoàn chỉnh trong Chính Thống Đạo Tạng; văn bản hiện hành chủ yếu phục nguyên từ trích dẫn (như trong 《道德真经玄德纂疏》 của Cường Tư Tề) và các bản hiệu đính cận đại.",key_text:"null",use:"Nghiên cứu Trùng Huyền học Đường; Lão chú triết lý; đối chiếu mảnh vụn chú sớ",sources:["https://a.daorenjia.com/daozang15-659","https://www.mdpi.com/2077-1444/10/1/66","https://baike.baidu.com/item/%E9%81%93%E5%BE%B7%E7%BB%8F/327138"],textual_certainty:"partial",notes:"batch14 · Grok-4.5 web-search"},{dz:"DZ624",name_han:"太上说南斗六司延寿度人妙经",name_vi:"Thái Thượng Thuyết Nam Đẩu Lục Tư Diên Thọ Độ Nhân Diệu Kinh",bu:"洞神",author:"khuyết danh（托名张道陵等记述）",era:"约北宋初（蜀中）",topic:"classic",essence:"Một thiên trong hệ Ngũ Đẩu Kinh, giả thác Lão Quân đời Vĩnh Thọ giảng cho Trương Đạo Lăng tại Ngọc Cục. Nam Đẩu lục tư (ly cung, chủ hồn–sinh) cùng Bắc Đẩu (khảm, chủ phách–tử) nắm tuổi thọ, lộc bổng, họa phúc. Dạy thành tâm chiêm tinh, dâng sớ thiết tiếu, đeo phù lục tinh quân để tiêu tai diên thọ. Là kinh điển cốt lõi của tế Nam Đẩu và nghi “diên sinh” trong Đẩu bộ.",key_text:"南斗位處离宮，名同日曜，降神於人，名之爲魂也，主司陽官。",use:"Tế Nam Đẩu; nghi diên thọ độ ách; hệ Ngũ Đẩu Kinh",sources:["https://www.shidianguji.com/book/DZ0624","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E8%AA%AA%E5%8D%97%E6%96%97%E5%85%AD%E5%8F%B8%E5%BB%B6%E5%A3%BD%E5%BA%A6%E4%BA%BA%E5%A6%99%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E8%AA%AC%E5%8D%97%E6%96%97%E5%85%AD%E5%8F%B8%E5%BB%B6%E5%A3%BD%E5%BA%A6%E4%BA%BA%E5%A6%99%E7%B6%93","https://ctext.org/wiki.pl?if=gb&res=642896"],textual_certainty:"high",notes:"batch14 · Grok-4.5 web-search"},{dz:"DZ927",name_han:"太清玉碑子",name_vi:"Thái Thanh Ngọc Bi Tử",bu:"洞神部（众术类；理属太清外丹传统）",author:"佚名（假托葛洪与郑思远问答）",era:"唐宋间",topic:"外丹",essence:"Sách mượn hình thức vấn đáp giữa Cát Hồng và Trịnh Tư Viễn để bàn đạo toàn thần tồn thân và luyện kim thạch thành đan. Cốt tủy nằm ở câu “nhất âm nhất dương chi vị đạo, nhất kim nhất thạch chi vị đan”: hợp kim tinh thạch dịch, âm dương đắc trung thì thành đan dược. Phần sau chép các ca quyết cả ngoại đan lẫn nội đan, đều lấy chì-thủy ngân và âm dương hòa hợp làm then chốt.",key_text:"神以道全，形以術延。",use:"Nghiên cứu lịch sử ngoại đan/nội đan thời Đường–Tống; đối chiếu thuyết âm dương–diên ngân trong thuật luyện đan.",sources:["https://zh.wikisource.org/wiki/太清玉碑子","https://zh.daoinfo.org/index.php?title=太清玉碑子&variant=zh-hans","https://www.shidianguji.com/book/DZ0927"],textual_certainty:"high",notes:"batch15 · Grok-4.5 web-search"},{dz:"DZ132",name_han:"太清真人络命诀",name_vi:"Thái Thanh Chân Nhân Lạc Mệnh Quyết",bu:"洞神部方法类（亦见归入洞真部玉诀类之著录）",author:"佚名",era:"南北朝（约六朝）",topic:"服气",essence:"Kinh thuộc dòng tồn tư/thủ thân thần, mượn lời Hoàng Lão và thần nhân để dạy câu giữ hồn phách, tồn ngũ tạng lục phủ chi thần. Cốt lõi: hồn phách như nhật nguyệt, ngũ tạng đều có thần danh; ngày thủ phách, đêm thủ hồn, tồn ngũ thú và tam nhất (thiên–nhân–địa) để trừ bệnh, vững hình, hướng tiên. Không phải kinh ngoại đan kim thạch thuần túy, mà là pháp tồn tư–dưỡng mạng đời Lục triều.",key_text:"魂者非谓魂也，自吾鬼也，鬼者人之先也，有气乃有魂。",use:"Thực hành tồn tư thân thần, câu hồn giữ phách; tài liệu so sánh Thượng Thanh tồn tư và dưỡng sinh.",sources:["https://zh.wikisource.org/zh-hans/太清真人络命诀","https://zh.daoinfo.org/index.php?title=太清真人络命诀&variant=zh-hans","https://www.iwenyan.com/dao/taiqingzhenrenluomingjue"],textual_certainty:"partial",notes:"batch15 · Grok-4.5 web-search"},{dz:"DZ255",name_han:"太微灵书紫文琅玕华丹神真上经",name_vi:"Thái Vi Linh Thư Tử Văn Lang Can Hoa Đan Thần Chân Thượng Kinh",bu:"洞真部方法类",author:"佚名（上清派；假托太极左仙公葛玄启金阙帝君）",era:"东晋南朝",topic:"外丹",essence:"Kinh ngoại đan quan trọng của Thượng Thanh, nguyên là một thiên trong hệ Linh Thư Tử Văn, sau tách thành sách riêng. Dạy phối 14 dược (đan sa, hùng hoàng, thạch anh, v.v.) luyện trong thần nê phủ trăm ngày thành “lang can hoa đan”; tiếp tục luyện thành hoàng thủy nguyệt hoa đan, hồi thủy ngọc tinh đan, thủy dương thanh ánh dịch. Uống đan có thể hóa hình, phi hành Thượng Thanh; cũng chép thuật hoàng bạch (chì thủy ngân thành kim bạc). Đây là ngoại đan Thượng Thanh sớm, không phải nội đan.",key_text:"仙道有琅玕华丹，服之化为飞龙。",use:"Nghiên cứu ngoại đan Thượng Thanh; đối chiếu Chân Cáo và hệ Linh Thư Tử Văn.",sources:["https://zh.wikisource.org/wiki/太微靈書紫文琅玕華丹神真上經","https://zh.daoinfo.org/index.php?title=太微灵书紫文琅玕华丹神真上经&variant=zh-hans"],textual_certainty:"high",notes:"batch15 · Grok-4.5 web-search"},{dz:"DZ819",name_han:"太上养生胎息气经",name_vi:"Thái Thượng Dưỡng Sinh Thai Tức Khí Kinh",bu:"洞神部方法类",author:"佚名",era:"唐代",topic:"服气",essence:"Kinh phục khí–thai tức đời Đường: lấy tâm như thai nhi trong bào thai, minh tâm tức niệm để hòa khí tự đến, phu lục dương thời (tý–dần–thìn–ngọ–thân–tuất). Kết hợp phục khí ngũ phương, thủ tinh bảo khí, và đồ bổ tả lục khí (hư, ha, hư, hô, xuy, hy) trị ngũ tạng. Cốt tủy: khí đạo chủ vạn khí, bảo tinh trọng khí thì trường sinh; luyện cửu hoàn thì khí–huyết–mạch–cốt tuần tự thay đổi thành chân nhân.",key_text:"凡服气法，存心如婴儿在母胎，十月成就，筋骨和柔。",use:"Hướng dẫn phục khí thai tức, dưỡng sinh trị bệnh theo lục khí ngũ tạng; nghiên cứu y–đạo giao thoa thời Đường.",sources:["https://zh.wikisource.org/zh-hans/太上养生胎息气经","https://zh.daoinfo.org/index.php?title=太上养生胎息气经&variant=zh-hans","https://www.shidianguji.com/zh/book/DZ0819","https://ctext.org/wiki.pl?if=gb&chapter=442691"],textual_certainty:"high",notes:"batch15 · Grok-4.5 web-search"},{dz:"DZ329",name_han:"太上洞玄灵宝开演秘密藏经",name_vi:"Thái Thượng Động Huyền Linh Bảo Khai Diễn Bí Mật Tạng Kinh",bu:"洞玄部本文类",author:"佚名（原《本际经》卷九，唐时析出单行）",era:"唐代（思想承南北朝本际学）",topic:"philosophy",essence:"Vốn là quyển 9 của Bản Tế Kinh, sau tách ra độc hành. Mượn vấn đáp Thái Thượng Đạo Quân và Thái Vi Thiên Đế Quân để khai diễn “bí mật tạng”: phân biệt đạo thân (tịch thể hư vô, bất sinh bất diệt) và sinh thân (thị hiện tùy duyên). Nhấn mạnh đạo tính bản tịnh như hư không, phi nhân phi quả; phá chấp hữu–không, nửa–mãn, trung đạo, để nhập nhất thừa. Đây là triết học Linh Bảo–Bản Tế mang màu sắc đốn ngộ và Phật–Đạo giao thoa, không phải khoa nghi hay phục khí.",key_text:"至真妙理，寂绝无形，清净凝湛，不可言名。",use:"Nghiên cứu Bản Tế học, triết lý đạo thân/sinh thân; đối chiếu Phật–Đạo thời Trung Đường.",sources:["https://zh.wikisource.org/wiki/太上洞玄靈寶開演秘密藏經","https://zh.daoinfo.org/index.php?title=太上洞玄灵宝开演秘密藏经&variant=zh-hans","https://www.shidianguji.com/zh/book/DZ0329"],textual_certainty:"high",notes:"batch15 · Grok-4.5 web-search"},{dz:"DZ442",name_han:"上清后圣道君列纪",name_vi:"Thượng Thanh Hậu Thánh Đạo Quân Liệt Kỷ",bu:"洞玄部谱箓类（内容属上清谱录）",author:"佚名（原题方诸东宫青童君传弟子王远游）",era:"东晋南朝（真诰已提及）",topic:"仙传",essence:"Phổ lục Thượng Thanh sớm: chép danh húy, xuất thân và sự tích tu chân độ thế của Thượng Thanh Kim Khuyết Hậu Thánh Đế Quân (họ Lý, húy Huyền Thủy, tự Tử Quang/Sơn Uyên). Phần sau lược truyện Hậu Thánh Bành Quân và các thần như Phương Chư Thanh Đồng, Thái Đan Nam Cực Nguyên Quân, Tây Thành Tổng Chân Vương Quân. Dùng để xác lập phả hệ tiên chân và sứ mệnh cứu thế của hậu thánh, nền tảng thần học Thượng Thanh.",key_text:"《圣君列纪》，唯以付王君一人，使择可授者。",use:"Đối chiếu Chân Cáo; nghiên cứu thần phổ Thượng Thanh và cứu thế luận thời Lục triều.",sources:["https://zh.wikisource.org/wiki/上清後聖道君列紀","https://zh.daoinfo.org/index.php?title=上清后圣道君列纪&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&res=686381"],textual_certainty:"high",notes:"batch15 · Grok-4.5 web-search"},{dz:"DZ1067",name_han:"上阳子金丹大要",name_vi:"Thượng Dương Tử Kim Đan Đại Yếu",bu:"太玄部",author:"陈致虚（号上阳子）",era:"元代（约至元改元1335前后）",topic:"cultivation",essence:"Bộ nội đan trọng yếu đời Nguyên: nguyên 10 quyển, Đạo tạng tách thành 16 quyển (kèm đồ, liệt tiên chí, tiên phái). Lấy tiên thiên chân nhất khí làm gốc đan; tinh–khí–thần là thượng dược tam phẩm; thuận thì thành người, nghịch thì thành đan. Hòa Nam–Bắc tông, chủ trương tính mệnh song tu, tam giáo nhất trí (Nho–Thích–Đạo đồng quy kim đan). Phê bình tà thuật, nhấn mạnh ngưng kết tinh khí thần và hoàn hư hợp đạo.",key_text:"金丹之道……三物交感，顺则为人，逆则成仙。",use:"Học nội đan toàn chân–nam tông hợp lưu; tham chiếu cùng Ngộ Chân Thiên chú và Tham Đồng Khế chú của Trần Trí Hư.",sources:["https://zh.daoinfo.org/index.php?title=上阳子金丹大要&variant=zh-hans","https://zh.wikisource.org/zh-hans/上阳子金丹大要","https://ctext.org/wiki.pl?if=gb&res=258621","https://baike.baidu.com/item/金丹大要/7964924"],textual_certainty:"high",notes:"batch15 · Grok-4.5 web-search"},{dz:"DZ244",name_han:"大丹直指",name_vi:"Đại Đan Trực Chỉ",bu:"洞真部方法类",author:"题丘处机撰（后世弟子编刊；现代考证归属有争议）",era:"金元（全真）",topic:"cultivation",essence:"Kinh nội đan Toàn Chân hai quyển, nói thẳng bí quyết tính–mệnh: tính tiềm ở đỉnh (tính căn), mệnh tiềm ở rốn (mệnh đế); long hổ (tâm thủy–thận khí) giao cấu thành đại đan. Chia chín tầng công pháp (long hổ giao cấu → chu thiên hỏa hầu → phiêu hậu phi kim tinh → kim dịch hoàn đan → thái dương luyện hình → tam điền ký tế → luyện thần nhập đỉnh → luyện thần hợp đạo → khí xác thăng tiên), và tiểu–trung–đại thành. Cốt tủy là tính mệnh song tu theo đường lối Toàn Chân, bỏ trường sinh nhục thân thuần túy.",key_text:"金丹之秘在一性一命而已。性者天也，常潜于顶；命者地也，常潜于脐。",use:"Nhập môn nội đan Toàn Chân/Long Môn; đối chiếu Chung–Lữ và Linh Bảo Bí Pháp.",sources:["https://zh.daoinfo.org/index.php?title=大丹直指&variant=zh-hans","https://zh.wikisource.org/wiki/大丹直指","https://ctext.org/wiki.pl?if=gb&res=123259"],textual_certainty:"high",notes:"batch15 · Grok-4.5 web-search"},{dz:"DZ1235",name_han:"全真清规",name_vi:"Toàn Chân Thanh Quy",bu:"正一部",author:"陆道和（通玄子）编集",era:"元明间（约13–14世纪）",topic:"戒律",essence:"Tập quy chế cung quán Toàn Chân: chỉ mông, trâm phi, du phương lễ sư, đường môn giới lạp, tọa bát quy thức, tam bất khởi thân, cùng trách phạt bảng của Vương Trùng Dương và quy bảng của Khâu Xử Cơ. Vừa giữ ngoại quy (xuất gia, trụ am, tọa bát) vừa hướng nội (kiến tính vi thể, dưỡng mệnh vi dụng, từ bi khiêm hòa). Là tài liệu then chốt về chế độ tăng đoàn Toàn Chân.",key_text:"见性为体，养命为用，柔弱谦和，慈悲为本。",use:"Nghiên cứu thanh quy cung quán Toàn Chân; tham chiếu khi thiết kế giới luật–cư trú đạo viện.",sources:["https://zh.daoinfo.org/index.php?title=全真清规&variant=zh-hans","https://zh.wikisource.org/zh-hans/全真清规","https://ctext.org/wiki.pl?if=gb&res=316407","https://www.shidianguji.com/book/DZ1235"],textual_certainty:"high",notes:"batch15 · Grok-4.5 web-search"},{dz:"DZ1226",name_han:"道门通教必用集",name_vi:"Đạo Môn Thông Giáo Tất Dụng Tập",bu:"正一部",author:"吕太古编集；马道逸改编",era:"南宋至元（吕太古目录嘉泰辛酉1201；元贞年间序）",topic:"ritual",essence:"Cẩm nang đào tạo đạo sĩ đời Tống–Nguyên, chín quyển, chọn lọc kinh huấn, tông sư lược truyện, từ tán, chú quyết, bảo chương, chân văn, bộ hư, cùng khải tấu–nghi văn thường dùng. Dùng làm “thông giáo tất dụng”: giáo dục đệ tử, truyền đạo độ người, chuẩn bị khoa nghi. Phản ánh nghi thức đạo giáo Tây Thục và chuẩn mực hành đạo phổ thông.",key_text:"天师立教於西蜀，广成终老於益州，故蜀之人奉道为盛，而仪注亦甚详。",use:"Sổ tay khoa nghi–giáo huấn; tra từ tán, chú quyết, nghi tiết thường dụng.",sources:["https://zh.daoinfo.org/index.php?title=道门通教必用集&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&res=489567","https://www.shidianguji.com/zh/book/DZ1226"],textual_certainty:"high",notes:"batch15 · Grok-4.5 web-search"},{dz:"DZ1221",name_han:"上清灵宝大法",name_vi:"Thượng Thanh Linh Bảo Đại Pháp",bu:"正一部",author:"宁全真授；王契真纂（另有金允中编本DZ1223，体系不同）",era:"南宋",topic:"ritual",essence:"Bộ đại pháp Linh Bảo 66 quyển của phái Đông Hoa/Linh Bảo đời Nam Tống: 27 môn, gồm giới luật, khai tông minh nghĩa, phù chú, trai đàn, luyện độ, trấn nhiễu, triệu hồn, đăng đồ, chương biểu… Tự xưng Linh Bảo đại pháp “quán thông tam động, tổng bị vạn pháp”. Là bách khoa toàn thư khoa nghi–phù lục lớn nhất phái Linh Bảo hậu kỳ, nền tảng cho nghi thức độ vong và trai tiếu sau này.",key_text:"灵宝大法，贯通三洞，总备万法。",use:"Tra cứu khoa nghi trai tiếu, luyện độ, phù lục; nghiên cứu lịch sử đạo pháp Tống–Nguyên.",sources:["https://zh.daoinfo.org/index.php?title=上清灵宝大法（王契真编）&variant=zh-hans","https://zh.wikisource.org/zh-hant/上清靈寶大法_(王契真)","https://www.shidianguji.com/book/DZ1221","https://ctext.org/wiki.pl?if=gb&res=869801"],textual_certainty:"high",notes:"batch15 · Grok-4.5 web-search"},{dz:"DZ636",name_han:"太上说十炼生神救护经",name_vi:"Thái Thượng Thuyết Thập Luyện Sinh Thần Cứu Hộ Kinh",bu:"洞神部本文类",author:"佚名",era:"唐宋间（约唐代）",topic:"mantra",essence:"Kinh cứu độ ngắn: Thái Thượng Lão Quân dạy tụng mười phương Cứu Khổ Thiên Tôn danh hiệu để bạt độ khổ hồn, tiêu tội, diên thọ. Nhắm vào chúng sinh có tam nghiệp lục căn, tội căn vô lượng; tụng kinh–thánh hiệu thì cô hồn được sinh thiên đường, tội khiên tiêu trừ, người còn sống cũng được miễn ách. Thuộc loại kinh niệm tụng cứu độ phổ thông, không phải luận đan hay khoa nghi phức tạp.",key_text:"若能奉此真经圣号，俱蒙解脱，孤魂滞魄获生天堂，尘沙罪咎尽使消除。",use:"Niệm tụng cứu khổ, bạt độ cô hồn; nghi lễ siêu tiến đơn giản.",sources:["https://zh.wikisource.org/zh-hans/太上说十炼生神救护经","https://zh.daoinfo.org/index.php?title=太上说十炼生神救护经&variant=zh-hans","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT03洞神部/CMT0301本文類/CMT0301ALL/CH030117太上說十煉生神救護經.htm"],textual_certainty:"partial",notes:"batch15 · Grok-4.5 web-search"},{dz:"null",name_han:"关圣帝君觉世真经",name_vi:"Quan Thánh Đế Quân Giác Thế Chân Kinh",bu:"续道藏外／民间善书（不入正統道藏）",author:"托名关圣帝君（扶鸾降笔；明清善书传统）",era:"明清民间（与文昌阴骘文、太上感应篇并称三大善书）",topic:"philosophy",essence:"Thiện thư khoảng sáu trăm chữ, mượn lời Quan Đế răn đời: lấy trung hiếu tiết nghĩa làm gốc làm người; tâm tức thần, dối lòng là dối thần. Liệt kê điều thiện (kính thiên địa, hiếu song thân, tích âm công, phóng sinh, công bình đấu xứng…) và điều ác (dâm tà, hại người, phỉ báng thần thánh, đại đấu tiểu xứng…). Thiện–ác báo ứng rõ ràng, gần báo thân, xa báo con cháu. Không thuộc chính thống Đạo tạng mà là đạo đức hóa dân gian Nho–Đạo–Thích.",key_text:"人生在世，贵尽忠孝节义等事，方于人道无愧，可立于天地之间。",use:"Khuyên thiện, tụng trì tích đức; nghiên cứu thiện thư và tín ngưỡng Quan Đế–Văn Xương đời Minh Thanh.",sources:["https://zh.wikisource.org/zh-hans/關聖帝君覺世真經","https://baike.baidu.com/item/关圣帝君觉世经文/14694512","https://religion.moi.gov.tw/Knowledge/Content?ci=2&cid=669"],textual_certainty:"high",notes:"batch15 · Grok-4.5 web-search"},{dz:"DZ671",name_han:"太上无极大道自然真一五称符上经",name_vi:"Thái Thượng Vô Cực Đại Đạo Tự Nhiên Chân Nhất Ngũ Xưng Phù Thượng Kinh",bu:"洞神部神符类（古灵宝经；中华道藏归洞玄灵宝）",author:"佚名",era:"东晋末南朝初（陆修静《灵宝经目》已著录）",topic:"fu",essence:"Cổ Linh Bảo kinh, còn gọi Chân Nhất Ngũ Xưng Kinh / Tự Nhiên Ngũ Thắng Văn; Đôn Hoàng P.2440 còn bản sớm. Quyển thượng chép năm đại phù “ngũ xưng phù” (ứng ngũ tinh, ngũ nhạc, ngũ tạng, ngũ hành chi mẫu), dạy thư viết–đeo phù để trường sinh, sai khiển vạn thần, trị bệnh cầu phúc. Quyển hạ: bát quái thần danh, lục giáp, tế tự triệu thần, và Linh Bảo nhị thập tứ chân đồ. Cốt tủy là phù mệnh–triệu thần của Linh Bảo sơ kỳ.",key_text:"老君曰：太上灵宝，生乎天地万物之先，乘於无象空洞大道之常。",use:"Nghiên cứu cổ Linh Bảo phù lục; so sánh với Ngũ Phù Tự (DZ388) và nghi đeo phù triệu thần.",sources:["https://zh.daoinfo.org/index.php?title=太上无极大道自然真一五称符上经&variant=zh-hans","https://www.shidianguji.com/book/DZ0671","https://www.daorenjia.com/daozang9-280","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT03洞神部/CMT0302神符類/CMT0302ALL/CH030201太上無極大道自然真一五稱符上經/CH030201-1太上無極大道自然真一五稱符上經卷上.htm"],textual_certainty:"high",notes:"batch15 · Grok-4.5 web-search"},{dz:"DZ225",name_han:"太上九要心印妙经",name_vi:"Thái Thượng Cửu Yếu Tâm Ấn Diệu Kinh",bu:"洞真",author:"原题仙人张果老述（托名；约晚唐至北宋）",era:"晚唐—北宋",topic:"cultivation",essence:"Kinh nội đan chia pháp luyện thành chín “yếu” ứng với cửu chuyển hoàn đan, lấy thần–khí–tinh và tính–mệnh làm cương. Cốt lõi là thần khí tương bão, dĩ thần điều khí, dĩ khí định thần, luyện tinh hóa thần, hợp đạo tự nhiên. Phân pháp thành thượng–trung–hạ (luyện thần / luyện khí / luyện tinh) và phân nội đan (chân nhất chi khí) với ngoại đan (ngũ cốc chi khí) phải tương thành.",key_text:"夫九要者，乃機要也。以應大丹九轉，故以道分九篇，法顯九門。",use:"Nội đan tâm ấn, cửu chuyển hoàn đan, tham chiếu luyện dưỡng tính mệnh.",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E4%B9%9D%E8%A6%81%E5%BF%83%E5%8D%B0%E5%A6%99%E7%B6%93","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E4%B9%9D%E8%A6%81%E5%BF%83%E5%8D%B0%E5%A6%99%E7%B6%93&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&res=646349","https://www.shidianguji.com/book/DZ0225"],textual_certainty:"high",notes:"batch16 · Grok-4.5 web-search"},{dz:"DZ325",name_han:"太上洞玄灵宝智慧定志通微经",name_vi:"Thái Thượng Động Huyền Linh Bảo Trí Tuệ Định Chí Thông Vi Kinh",bu:"洞玄",author:"佚名（古灵宝经）",era:"东晋末—南朝初",topic:"classic",essence:"Cổ Linh Bảo kinh, một tên Tư Vi Định Chí Kinh; Nguyên Thủy/Linh Bảo Thiên Tôn trao “tư vi định chí yếu quyết” cho Tả Huyền–Hữu Huyền chân nhân. Chủ đề “minh không ái đạo”: biết tam giới tam thế giai không, quên thân, chỉ ái đạo; diễn thành “lưỡng bán thành nhất” (Lưỡng Bán Đồ Cục) và thập giới. Phần sau kể báo ứng thiện ác, khuyên phụng kinh, trì giới, bố thí cầu phúc.",key_text:"當知三界之中，三世皆空。知三世空，雖有我身，皆應歸空。",use:"Linh Bảo bản văn, giới luật, định chí minh không, nghi thức thụ giới.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E6%99%BA%E6%85%A7%E5%AE%9A%E5%BF%97%E9%80%9A%E5%BE%AE%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E6%99%BA%E6%85%A7%E5%AE%9A%E5%BF%97%E9%80%9A%E5%BE%AE%E7%B6%93","https://ctext.org/wiki.pl?if=gb&res=947230","https://www.shidianguji.com/zh/book/DZ0325"],textual_certainty:"high",notes:"batch16 · Grok-4.5 web-search"},{dz:"null",name_han:"文昌帝君孝经",name_vi:"Văn Xương Đế Quân Hiếu Kinh",bu:"续道藏",author:"托名文昌帝君（劝善书；非正统道藏本经）",era:"南宋以降（明清善书流行）",topic:"philosophy",essence:"Kinh thiện thư của tín ngưỡng Văn Xương, lấy hiếu làm gốc văn hóa và căn bản bách hạnh. Nội dung gồm các chương như dục tử, thể thân, biện hiếu, thủ thân, giáo hiếu, hiếu cảm: tả công lao cha mẹ nuôi con, cách con đáp hiếu, và cảm ứng thần minh. Không thấy trong chính mục Schipper–Verellen của Chính thống Đạo tạng; lưu hành qua Đạo tạng Tập yếu và bản khắc thiện thư.",key_text:"奉行諸善，不孝我親，終為小善。奉行諸善能孝我親，是為至善。",use:"Khuyên thiện, trì tụng cầu khoa cử/phúc lộc, giáo dục hiếu đạo dân gian.",sources:["https://zh.wikisource.org/zh-hans/%E6%96%87%E6%98%8C%E5%B8%9D%E5%90%9B%E5%AD%9D%E7%B6%93","https://baike.baidu.com/item/%E6%96%87%E6%98%8C%E5%AD%9D%E7%BB%8F/858934","https://www.dysy.org.tw/Scripture/Index?ID=6c595832-a66e-4c1f-8f2d-5e159b9df46e"],textual_certainty:"high",notes:"batch16 · Grok-4.5 web-search"},{dz:"DZ1438",name_han:"太上老君虚无自然本起经",name_vi:"Thái Thượng Lão Quân Hư Vô Tự Nhiên Bản Khởi Kinh",bu:"续道藏",author:"佚名",era:"约南北朝—隋唐（万历续道藏收录；云笈七签亦存）",topic:"philosophy",essence:"Kinh vũ trụ luận và tu đạo: Đạo khởi từ thái sơ–thái tố–thái thủy (tinh–thần–khí / xích–hoàng–bạch), “đạo vi tam nhất” là hư–vô–không, hỗn độn sinh vạn vật. Thần con người gốc thanh tịnh, vì ngũ dục lục tình mà trôi trong ngũ đạo; tu là hư không kỳ tâm, đoạn dục, thủ hư vô tự nhiên (đại/trung/tiểu), kết hợp công đức, không chỉ tĩnh tọa cưỡng đoạn.",key_text:"道者，謂太初也。太初者，道之初也。",use:"Vũ trụ luận Lão học, lý thuyết tam nhất, pháp thủ hư vô tự nhiên.",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%99%9B%E7%84%A1%E8%87%AA%E7%84%B6%E6%9C%AC%E8%B5%B7%E7%B6%93","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%99%9B%E7%84%A1%E8%87%AA%E7%84%B6%E6%9C%AC%E8%B5%B7%E7%B6%93&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&res=190621","https://www.shidianguji.com/book/DZ1438"],textual_certainty:"high",notes:"batch16 · Grok-4.5 web-search"},{dz:"null",name_han:"老子变化经",name_vi:"Lão Tử Biến Hóa Kinh",bu:"太玄",author:"佚名（早期道教；疑汉末）",era:"汉末—魏晋（敦煌写本 S.2295，隋大业八年抄）",topic:"classic",essence:"Kinh Đôn Hoàng không vào Chính thống Đạo tạng: đồng nhất Lão Tử với Đạo, trình bày thần hóa và các lần biến hóa của Lão quân trong lịch sử. Phần trước kế thừa quan niệm Hán đại về Lão Tử–Đạo; phần sau ghi truyền thuyết biến hóa thời Hán. Thuộc hệ Lão học/thần hóa Lão quân, quan trọng cho nghiên cứu Đạo giáo sơ kỳ.",key_text:"null",use:"Nghiên cứu thần học Lão Tử, biến hóa thị hiện, Đôn Hoàng đạo kinh.",sources:["https://zh.daoinfo.org/index.php?title=%E8%80%81%E5%AD%90%E8%AE%8A%E5%8C%96%E7%B6%93&variant=zh-hant","https://baike.baidu.com/item/%E8%80%81%E5%AD%90%E5%8F%98%E5%8C%96%E7%BB%8F/18832712","https://a.daorenjia.com/daozang13-584"],textual_certainty:"high",notes:"batch16 · Grok-4.5 web-search"},{dz:"DZ684",name_han:"道德真经四子古道集解",name_vi:"Đạo Đức Chân Kinh Tứ Tử Cổ Đạo Tập Giải",bu:"太玄",author:"寇才质（金）",era:"金朝",topic:"classic",essence:"Chú giải Đạo Đức Chân Kinh mười quyển, dùng “tứ tử” (Nam Hoa, Xung Hư, Thông Huyền, Động Linh) để chứng minh “cổ đạo” Lão học, phá chú cựu và thuyết thần quỷ quá mức. Mục tiêu khôi phục nghĩa lý đạo đức gốc qua đối chiếu tứ kinh Đạo gia, thuộc dòng chú Lão học thời Kim. (Tựa người dùng rút gọn “四子古道”; bản tạng là “集解”.)",key_text:"null",use:"Chú sớ Đạo Đức Kinh, đối chiếu tứ tử, nghiên cứu Lão học thời Kim.",sources:["https://zh.wikisource.org/zh-hans/%E9%81%93%E5%BE%B7%E7%9C%9F%E7%B6%93%E5%9B%9B%E5%AD%90%E5%8F%A4%E9%81%93%E9%9B%86%E8%A7%A3","https://www.shidianguji.com/zh/book/DZ0684","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch16 · Grok-4.5 web-search"},{dz:"null",name_han:"太上三五禹步经",name_vi:"Thái Thượng Tam Ngũ Vũ Bộ Kinh",bu:"洞神",author:"未见独立正统道藏本（禹步诀散见于正一/道法文献）",era:"禹步传统自上古方术至六朝—宋元道法",topic:"ritual",essence:"Không thấy thư mục Schipper–Verellen mục đúng “太上三五禹步经”. Vũ bộ là bộ pháp “tam bộ cửu tích / tam ngũ” bắt nguồn truyền thuyết Đại Vũ, dùng trong bộ cang đạp đẩu, triệu thần chế ma. Gần nhất trong tạng: Thái Thượng Động Huyền… Phong Lôi Vũ Bộ Chế Ma Thần Chú Kinh (DZ385) và thuyết vũ bộ trong Đạo Pháp Hội Nguyên / chính nhất khoa pháp.",key_text:"而稱禹步者，大禹治水而成厥功，天授此步，以制神靈，誅斬馘伐，因名禹步焉。",use:"Bộ cang đạp đẩu, pháp thuật triệu khiển, tham chiếu khoa nghi chính nhất.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","http://www.ctcwri.org/CTCW-CMTS/CMT07%E6%AD%A3%E4%B9%99%E9%83%A8/CH07XX/CH07029-2%E9%81%93%E6%B3%95%E6%9C%83%E5%85%83(%E4%BA%8C)/CH07029-2XX/CH07029-2-160%E5%8D%B7%E4%B8%80%E7%99%BE%E5%85%AD%E5%8D%81%E4%B8%8A%E6%B8%85%E5%A4%A9%E8%93%AC%E4%BC%8F%E9%AD%94%E5%A4%A7%E6%B3%95.htm","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"low",notes:"batch16 · Grok-4.5 web-search"},{dz:"DZ282",name_han:"黄帝宅经",name_vi:"Hoàng Đế Trạch Kinh",bu:"洞真",author:"托名黄帝（约唐前后成书）",era:"唐—宋前（道藏本二卷）",topic:"方术",essence:"Kinh kham dư dương trạch: nhà ở là then chốt âm dương và khuôn mẫu nhân luân; người nhờ nhà mà an, nhà nhờ người mà tồn. Bàn hướng–vị, âm trạch/dương trạch, thiện ác họa phúc theo bố cục chỗ ở. Là nguồn quan trọng của thuật chọn nhà, khác hệ âm trạch (mộ địa) của Táng Thư.",key_text:"夫宅者，乃是陰陽之樞紐，人倫之軌模。",use:"Dương trạch phong thủy, chọn hướng lập cư, kham dư thực hành.",sources:["https://ctext.org/wiki.pl?if=en&chapter=182804&remap=gb","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/zh-hant/%E5%AE%85%E7%B6%93/%E5%8D%B7%E4%B8%8A"],textual_certainty:"high",notes:"batch16 · Grok-4.5 web-search"},{dz:"null",name_han:"葬书",name_vi:"Táng Thư",bu:"null",author:"托名郭璞（东晋；宋志始著录，多后人增益）",era:"托名东晋；文本宋以后定型（蔡元定、吴澄删定）",topic:"方术",essence:"Kinh điển âm trạch/phong thủy: “táng giả thừa sinh khí”; khí thừa phong tắc tán, giới thủy tắc chỉ — gốc chữ “phong thủy”. Bàn long–huyệt–sa–thủy, thừa sinh khí để âm trạch che chở hậu duệ. Không vào Chính thống Đạo tạng; lưu trong Tứ khố và truyền bản địa lý. Tác giả thật sự tranh cãi, nhưng ảnh hưởng cực lớn tới phái hình thế và lý khí.",key_text:"氣乘風則散，界水則止，古人聚之使不散，行之使有止，故謂之風水。",use:"Âm trạch kham dư, lý thuyết sinh khí phong thủy, địa lý hình thế.",sources:["https://zh.wikisource.org/zh-hans/%E8%91%AC%E6%9B%B8","https://zh.wikipedia.org/wiki/%E8%91%AC%E4%B9%A6","https://ctext.org/wiki.pl?if=gb&res=404104","https://baike.baidu.com/item/%E8%91%AC%E7%BB%8F/4395206"],textual_certainty:"high",notes:"batch16 · Grok-4.5 web-search"},{dz:"DZ73",name_han:"元始天尊说酆都灭罪经",name_vi:"Nguyên Thủy Thiên Tôn Thuyết Phong Đô Diệt Tội Kinh",bu:"洞真",author:"佚名",era:"约宋元",topic:"classic",essence:"Kinh cứu độ u minh: Nguyên Thủy Thiên Tôn nói pháp diệt tội/bạt độ vong hồn nơi Phong Đô địa ngục, liên hệ thập điện/thập hội tu trai. Khuyên lập trai công đức, tụng kinh sám hối để phóng xá tội nhân. (Tựa người dùng “太上说酆都拔罪妙经” không khớp đúng một mục; gần nhất DZ73 Phong Đô diệt tội; gần nghĩa bạt tội còn DZ74 Thái Thượng thuyết Cửu U bạt tội tâm ấn.)",key_text:"null",use:"Trai đàn bạt độ, siêu độ vong linh, sám tội Phong Đô.",sources:["https://zh.wikisource.org/zh-hans/%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E9%85%86%E9%83%BD%E6%BB%85%E7%BD%AA%E7%B6%93","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT01%E6%B4%9E%E7%9C%9F%E9%83%A8/CMT0101%E6%9C%AC%E6%96%87%E9%A1%9E/CMT0101ALL/CNDZ010173%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E9%85%86%E9%83%BD%E6%BB%85%E7%BD%AA%E7%B6%93.htm","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"partial",notes:"batch16 · Grok-4.5 web-search"},{dz:"DZ653",name_han:"太上老君说五斗金章受生经",name_vi:"Thái Thượng Lão Quân Thuyết Ngũ Đẩu Kim Chương Thụ Sinh Kinh",bu:"洞神",author:"佚名",era:"唐宋间",topic:"classic",essence:"Lão quân triệu ngũ lão đế quân và đông–nam–tây–bắc–trung đẩu tinh quân, nói nguồn gốc sinh mệnh: người do ngũ phương chân khí/kim chương linh phù hóa sinh, thọ–phú–quí do tinh quân chú sinh chú lộc theo nghiệp. Gắn “thụ sinh trái / bản mệnh tiền”: đầu thai vay kho thiên tào, đời này phải trai giới, bố thí, tụng kinh hoàn trả. (Tựa rút “五斗妙经” thường chỉ bản này.)",key_text:"且人生下土，命係上天，人之生也，頂天履地，有陰有陽，各有五行正氣，各有五斗所管。",use:"Thờ ngũ đẩu, hoàn thụ sinh trái, trai giáo bản mệnh, cầu thọ lộc.",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E4%BA%94%E6%96%97%E9%87%91%E7%AB%A0%E5%8F%97%E7%94%9F%E7%B6%93","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E4%BA%94%E6%96%97%E9%87%91%E7%AB%A0%E5%8F%97%E7%94%9F%E7%B6%93&variant=zh-hans","https://www.shidianguji.com/zh/book/DZ0653"],textual_certainty:"high",notes:"batch16 · Grok-4.5 web-search"},{dz:"DZ4",name_han:"无上内秘真藏经",name_vi:"Vô Thượng Nội Bí Chân Tạng Kinh",bu:"洞真",author:"佚名",era:"南北朝末—隋唐之际",topic:"philosophy",essence:"Kinh trọng huyền hệ Nguyên Thủy, mười quyển (hiển đạo, biện tam bảo, tứ chân, huệ trạch, giải thoát…): mượn đối thoại Thiên Tôn–chúng tiên bàn đạo thể, chân tạng nội tại và giải thoát. Chủ trương bất trệ hữu vô, huyền chi hựu huyền; đệ tử ngộ “đạo tâm” thì thị chúng sinh đều là đạo tâm. Đạo tạng xếp Động chân bản văn (không phải Động huyền như gợi ý thường gặp).",key_text:"null",use:"Trọng huyền triết học, lý luận tu đạo, đọc tụng bản văn.",sources:["https://zh.daoinfo.org/wiki/%E7%84%A1%E4%B8%8A%E5%85%A7%E7%A7%98%E7%9C%9F%E8%97%8F%E7%B6%93","https://www.shidianguji.com/zh/book/DZ0004","https://ctext.org/wiki.pl?if=gb&res=402485","https://baike.baidu.com/item/%E6%97%A0%E4%B8%8A%E5%86%85%E7%A7%98%E7%9C%9F%E8%97%8F%E7%BB%8F/2518854"],textual_certainty:"high",notes:"batch16 · Grok-4.5 web-search"},{dz:"DZ386",name_han:"太上洞渊三昧帝心光明正印太极紫微伏魔制鬼拯救恶道集福吉祥神咒",name_vi:"Thái Thượng Động Uyên Tam Muội Đế Tâm Quang Minh Chính Ấn Thái Cực Tử Vi Phục Ma Chế Quỷ Chứngng Cứu Ác Đạo Tập Phúc Cát Tường Thần Chú",bu:"洞玄",author:"佚名",era:"中古道教（洞渊系；正统道藏洞玄部本文）",topic:"mantra",essence:"Thần chú Động Uyên một quyển (thường đồng quyển với chú khác): lấy “đế tâm / quang minh chính ấn” Tử Vi phục ma chế quỷ, cứu ác đạo, tập phúc cát tường. Thuộc dòng Động Uyên thần chú (cùng hệ với Động Uyên thần chú kinh), dùng trong khoa nghi trấn tà, cứu độ, cầu phúc hơn là luận triết. (Tựa rút “帝心经” chỉ bản dài này, DZ386.)",key_text:"null",use:"Thần chú phục ma, cứu ác đạo, khoa nghi Động Uyên.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://fabriziopregadio.com/files/PREGADIO_and_ESPOSITO_Daozang_jiyao_Catalogue.pdf","https://ctext.org/wiki.pl?if=en&chapter=534670&remap=gb"],textual_certainty:"high",notes:"batch16 · Grok-4.5 web-search"},{dz:"DZ0622",name_han:"太上玄灵北斗本命延生真经",name_vi:"Thái Thượng Huyền Linh Bắc Đẩu Bản Mệnh Diên Sinh Chân Kinh",bu:"洞神",author:"佚名（托名太上老君）",era:"宋（约北宋–南宋）",topic:"classic",essence:"Kinh Bắc Đẩu Bản Mệnh là kinh phổ biến nhất trong hệ Bắc Đẩu, dạy cầu sao bản mệnh, sám hối, cầu thọ và giải ách. Bản văn mô tả các tinh quân Bắc Đẩu chủ sinh tử họa phúc, khuyên tụng kinh, lập đàn, cúng tế vào ngày bản mệnh. Trong thực hành dân gian và khoa nghi, đây là kinh lõi cho nghi thức “bái Bắc Đẩu” và cầu an mạng.",key_text:"北斗垂象，而众星拱之。",use:"Tụng niệm cầu an mạng, giải hạn, cầu thọ; khoa nghi bái Bắc Đẩu.",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E7%8E%84%E9%9D%88%E5%8C%97%E6%96%97%E6%9C%AC%E5%91%BD%E5%BB%B6%E7%94%9F%E7%9C%9F%E7%B6%93","https://www.kanripo.org/text/KR5a0222/","https://ctext.org/wiki.pl?if=en&res=916077","https://dao.crs.cuhk.edu.hk/en/"],textual_certainty:"high",notes:"batch17 · Grok-4.5 web-search"},{dz:"DZ0629",name_han:"太上说东斗护命妙经",name_vi:"Thái Thượng Thuyết Đông Đẩu Hộ Mệnh Diệu Kinh",bu:"洞神",author:"佚名（托名太上）",era:"宋",topic:"classic",essence:"Kinh Đông Đẩu thuộc nhóm kinh Ngũ Đẩu, chuyên về hộ mệnh, cứu khổ và bảo vệ sinh mệnh. Nội dung trình bày uy lực các tinh quân Đông Đẩu, khuyến khích tụng trì để giải trừ tai ách và giữ mạng. Thường được dùng cùng các kinh Bắc/Nam/Tây/Trung Đẩu trong khoa nghi cầu an và hộ thân.",key_text:"东斗主算，西斗记名。",use:"Tụng cầu hộ mệnh, giải tai, phối hợp khoa nghi Ngũ Đẩu.",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E8%AA%AA%E6%9D%B1%E6%96%97%E8%AD%B7%E5%91%BD%E5%A6%99%E7%B6%93","https://www.kanripo.org/","https://ctext.org/searchbooks.pl?if=en&searchu=%E6%9D%B1%E6%96%97%E8%AD%B7%E5%91%BD"],textual_certainty:"high",notes:"batch17 · Grok-4.5 web-search"},{dz:"DZ0630",name_han:"太上说西斗记名护身妙经",name_vi:"Thái Thượng Thuyết Tây Đẩu Ký Danh Hộ Thân Diệu Kinh",bu:"洞神",author:"佚名（托名太上）",era:"宋",topic:"classic",essence:"Kinh Tây Đẩu nhấn mạnh chức năng “ký danh” (ghi tên vào sổ sống/phúc) và hộ thân. Bản văn liên hệ Tây Đẩu với việc ghi nhận công đức, bảo vệ thân mệnh và giải trừ sát khí. Trong truyền thống dân gian, tụng kinh này nhằm cầu “đăng danh” phúc bộ và tránh họa hình thương.",key_text:"西斗记名，北斗落死。",use:"Tụng cầu ký danh phúc sổ, hộ thân, giải sát.",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E8%AA%AA%E8%A5%BF%E6%96%97%E8%A8%98%E5%90%8D%E8%AD%B7%E8%BA%AB%E5%A6%99%E7%B6%93","https://www.kanripo.org/","https://baike.baidu.com/item/%E5%A4%AA%E4%B8%8A%E8%AF%B4%E8%A5%BF%E6%96%97%E8%AE%B0%E5%90%8D%E6%8A%A4%E8%BA%AB%E5%A6%99%E7%BB%8F"],textual_certainty:"high",notes:"batch17 · Grok-4.5 web-search"},{dz:"DZ0371",name_han:"太上三生解冤妙经",name_vi:"Thái Thượng Tam Sinh Giải Oan Diệu Kinh",bu:"洞玄",author:"佚名",era:"唐–宋",topic:"classic",essence:"Kinh giải oan theo quan điểm nhân quả ba đời (quá khứ–hiện tại–vị lai), dạy sám hối và giải kết oan khiên. Nội dung nêu nguồn gốc oan nghiệp từ sát sinh, tranh chấp, nợ nần, và cách tụng kinh, lập nguyện để hóa giải. Thường dùng trong nghi thức giải oan, siêu độ và hòa giải oan thân trái chủ.",key_text:"三生冤业，皆由心造。",use:"Giải oan, sám hối nghiệp chướng, siêu độ oan hồn.",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E4%B8%89%E7%94%9F%E8%A7%A3%E5%86%A4%E5%A6%99%E7%B6%93","https://ctext.org/wiki.pl?if=gb&chapter=144904","https://baike.baidu.com/item/%E5%A4%AA%E4%B8%8A%E4%B8%89%E7%94%9F%E8%A7%A3%E5%86%A4%E5%A6%99%E7%BB%8F"],textual_certainty:"partial",notes:"batch17 · Grok-4.5 web-search"},{dz:"DZ0336",name_han:"太上洞玄灵宝业报因缘经",name_vi:"Thái Thượng Động Huyền Linh Bảo Nghiệp Báo Nhân Duyên Kinh",bu:"洞玄",author:"佚名（灵宝系）",era:"南北朝–唐",topic:"classic",essence:"Kinh Linh Bảo luận về nghiệp báo và nhân duyên, giải thích thiện ác chiêu cảm quả báo, khuyến thiện trừ ác. Bản văn thuộc hệ Động Huyền Linh Bảo, kết hợp triết lý nhân quả với nghi thức sám hối. Dùng để giáo hóa đạo đức và làm nền cho khoa nghi sám nghiệp, cầu phước.",key_text:"业由心造，报因业生。",use:"Giáo hóa nhân quả, sám nghiệp, khoa nghi Linh Bảo.",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E6%A5%AD%E5%A0%B1%E5%9B%A0%E7%B7%A3%E7%B6%93","https://ctext.org/wiki.pl?if=gb&res=250967","https://www.kanripo.org/"],textual_certainty:"high",notes:"batch17 · Grok-4.5 web-search"},{dz:"DZ0456",name_han:"太上说五苦三戒经",name_vi:"Thái Thượng Thuyết Ngũ Khổ Tam Giới Kinh",bu:"洞玄",author:"佚名",era:"南北朝–唐",topic:"戒律",essence:"Kinh trình bày năm nỗi khổ (ngũ khổ) và ba giới cốt yếu (tam giới) trong tu đạo, răn đe dục vọng và ác nghiệp. Nội dung gắn giới luật với giải thoát khỏi khổ luân, mang tính giáo huấn đạo đức rõ rệt. Được dùng trong truyền giới, giáo hóa tín đồ và nghi thức thụ giới cơ bản.",key_text:"五苦缠身，皆由三毒。",use:"Truyền giới, giáo hóa đạo đức, răn dục vọng.",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E8%AA%AA%E4%BA%94%E8%8B%A6%E4%B8%89%E6%88%92%E7%B6%93","https://ctext.org/searchbooks.pl?if=en&searchu=%E4%BA%94%E8%8B%A6%E4%B8%89%E6%88%92","https://baike.baidu.com/"],textual_certainty:"partial",notes:"batch17 · Grok-4.5 web-search"},{dz:"DZ0045",name_han:"太上九天延祥涤邪经",name_vi:"Thái Thượng Cửu Thiên Diên Tường Địch Tà Kinh",bu:"洞真",author:"佚名",era:"宋–元",topic:"ritual",essence:"Kinh cầu diên tường (kéo dài cát tường) và địch tà (rửa sạch tà khí), thuộc loại kinh trấn trạch, trừ tà, cầu an. Nội dung mô tả uy lực Cửu Thiên và các thần chú/kinh văn dùng để thanh tẩy không gian, hóa giải tà mị. Thường dùng trong nghi thức trừ tà, an trạch, cầu phúc lộc.",key_text:"涤邪荡秽，延祥集福。",use:"Trừ tà, an trạch, cầu cát tường, khoa nghi thanh tẩy.",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E4%B9%9D%E5%A4%A9%E5%BB%B6%E7%A5%A5%E6%BB%A4%E9%82%AA%E7%B6%93","https://ctext.org/","https://www.kanripo.org/"],textual_certainty:"partial",notes:"batch17 · Grok-4.5 web-search"},{dz:"DZ0022",name_han:"太上赤书玉篇真文",name_vi:"Thái Thượng Xích Thư Ngọc Thiên Chân Văn",bu:"洞真",author:"佚名（上清/灵宝天文传统）",era:"东晋–南北朝",topic:"fu",essence:"Xích Thư Ngọc Thiên Chân Văn là văn bản “thiên văn” gốc trong truyền thống Linh Bảo/Thượng Thanh, gồm các đồ văn/chân văn màu đỏ (xích thư) dùng trấn ngũ phương, triệu thần, hộ thân. Đây là “bản văn” (本文) mang tính huyền cơ, không phải kinh thuyết pháp dài, mà là phù-văn cốt lõi cho nghi thức. Trong Đạo Tạng, thuộc tầng cao của khoa nghi Linh Bảo và biểu tượng vũ trụ.",key_text:"赤书玉字，生于元始。",use:"Phù lục, trấn phương, triệu thần, nghi thức Linh Bảo gốc.",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E8%B5%A4%E6%9B%B8%E7%8E%89%E7%AF%87%E7%9C%9F%E6%96%87","https://ctext.org/wiki.pl?if=en&res=142598","https://dao.crs.cuhk.edu.hk/en/"],textual_certainty:"high",notes:"batch17 · Grok-4.5 web-search"},{dz:"DZ0006",name_han:"大洞玉经",name_vi:"Đại Động Ngọc Kinh",bu:"洞真",author:"佚名（上清派；托名）",era:"东晋（上清经系）",topic:"cultivation",essence:"Đại Động Ngọc Kinh là kinh tu luyện trung tâm của phái Thượng Thanh, dạy tụng 39 chương (hoặc hệ liên quan) để hợp thần, tồn tư, đắc đạo. Nội dung kết hợp thiền định nội quan, hô hấp thần danh và kinh tụng để thăng nhập “đại động” — cảnh giới tiên thiên. Đây là kinh lõi nhất của Động Chân bộ và tu tiên Thượng Thanh.",key_text:"大洞之章，三十九真。",use:"Tu luyện Thượng Thanh, tụng kinh tồn tư, cầu thành tiên.",sources:["https://zh.wikisource.org/wiki/%E5%A4%A7%E6%B4%9E%E7%8E%89%E7%B6%93","https://ctext.org/wiki.pl?if=en&res=277147","https://www.kanripo.org/text/KR5a0006/"],textual_certainty:"high",notes:"batch17 · Grok-4.5 web-search"},{dz:"DZ0660",name_han:"太上老君说上七元真人金轩玉字经",name_vi:"Thái Thượng Lão Quân Thuyết Thượng Thất Nguyên Chân Nhân Kim Hiên Ngọc Tự Kinh",bu:"太玄",author:"佚名（托名太上老君）",era:"唐–宋",topic:"classic",essence:"Kinh thuộc dòng Lão Quân thuyết pháp, nói về Thất Nguyên chân nhân và “kim hiên ngọc tự” — chữ ngọc huyền cơ dùng tu chân. Nội dung kết hợp tín ngưỡng tinh quân/thất nguyên với giáo huấn tu đạo, hộ mệnh. Ít phổ biến hơn Bắc Đẩu kinh, nhưng nằm trong nhóm kinh Thái Huyền/Lão học dân gian.",key_text:"七元真宰，金轩玉字。",use:"Tụng cầu hộ mệnh, tu chân theo hệ Lão Quân/thất nguyên.",sources:["https://zh.wikisource.org/","https://ctext.org/","https://baike.baidu.com/"],textual_certainty:"low",notes:"batch17 · Grok-4.5 web-search"},{dz:"DZ0319",name_han:"灵宝自然经诀",name_vi:"Linh Bảo Tự Nhiên Kinh Quyết",bu:"洞玄",author:"佚名（灵宝派）",era:"南北朝–唐",topic:"ritual",essence:"Kinh quyết Linh Bảo trình bày “tự nhiên” đạo thể và các quyết yếu khoa nghi Linh Bảo: tụng kinh, lập đàn, thỉnh thần, sám hối. Bản văn mang tính cẩm nang nghi thức hơn là triết luận dài, phục vụ hành trì Động Huyền. Dùng làm nền cho khoa nghi Linh Bảo và hiểu về tự nhiên chi đạo trong hành pháp.",key_text:"自然之教，灵宝为先。",use:"Khoa nghi Linh Bảo, tụng kinh lập đàn, quyết hành trì.",sources:["https://zh.wikisource.org/wiki/%E9%9D%88%E5%AF%B6%E8%87%AA%E7%84%B6%E7%B6%93%E8%A8%A3","https://ctext.org/","https://www.kanripo.org/"],textual_certainty:"partial",notes:"batch17 · Grok-4.5 web-search"},{dz:"DZ1291",name_han:"太上三五正一盟威修真玉经",name_vi:"Thái Thượng Tam Ngũ Chính Nhất Minh Uy Tu Chân Ngọc Kinh",bu:"正一",author:"佚名（正一派传统）",era:"唐–宋（正一盟威系统）",topic:"cultivation",essence:"Kinh thuộc hệ Chính Nhất Minh Uy, dạy tu chân theo pháp “tam ngũ” và minh uy lục (lục bộ chính nhất). Nội dung kết hợp giới luật, phù lục, và công phu tu chân của đạo sĩ Chính Nhất. Dùng trong truyền thừa Chính Nhất, thụ lục và hành trì tu chân cơ bản.",key_text:"三五正一，盟威修真。",use:"Tu chân Chính Nhất, thụ lục minh uy, hành pháp cơ bản.",sources:["https://zh.wikisource.org/","https://ctext.org/","https://dao.crs.cuhk.edu.hk/en/"],textual_certainty:"partial",notes:"batch17 · Grok-4.5 web-search"},{dz:"DZ0016",name_han:"太上紫微玄都雷霆玉经",name_vi:"Thái Thượng Tử Vi Huyền Đô Lôi Đình Ngọc Kinh",bu:"正一",author:"佚名（神霄/雷法传统）",era:"宋（神霄雷法兴盛期）",topic:"ritual",essence:"Kinh Lôi Đình thuộc dòng Thần Tiêu/lôi pháp, lấy Tử Vi Huyền Đô làm trung tâm uy lực sấm sét. Nội dung mô tả lôi thần, lôi phủ, và công dụng trừ tà, trấn yêu, hành pháp lôi đình. Đây là kinh văn then chốt cho đạo sĩ hành lôi pháp và khoa nghi thỉnh lôi.",key_text:"雷霆号令，号令十方。",use:"Hành lôi pháp, trừ tà trấn yêu, khoa nghi thỉnh lôi.",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E7%B4%AB%E5%BE%AE%E7%8E%84%E9%83%BD%E9%9B%B7%E9%9C%86%E7%8E%89%E7%B6%93","https://ctext.org/","https://baike.baidu.com/item/%E5%A4%AA%E4%B8%8A%E7%B4%AB%E5%BE%AE%E7%8E%84%E9%83%BD%E9%9B%B7%E9%9C%86%E7%8E%89%E7%BB%8F"],textual_certainty:"high",notes:"batch17 · Grok-4.5 web-search"},{dz:"DZ0754",name_han:"玄天上帝感应经",name_vi:"Huyền Thiên Thượng Đế Cảm Ứng Kinh",bu:"正一",author:"佚名",era:"元–明（玄武/玄天信仰高峰）",topic:"仙传",essence:"Kinh cảm ứng của Huyền Thiên Thượng Đế (Chân Vũ/Huyền Vũ), kể uy lực trấn Bắc, diệt ma, hộ quốc an dân và các sự tích cảm ứng. Nội dung khuyến khích thành tâm phụng thờ, tụng kinh cầu phù hộ. Phổ biến trong tín ngưỡng dân gian miền Nam Trung Quốc, Đài Loan, Việt Nam (Huyền Thiên).",key_text:"玄天上帝，威镇北方。",use:"Tụng cầu phù hộ Huyền Thiên, trừ tà, tín ngưỡng dân gian.",sources:["https://zh.wikisource.org/wiki/%E7%8E%84%E5%A4%A9%E4%B8%8A%E5%B8%9D%E6%84%9F%E6%87%89%E7%B6%93","https://baike.baidu.com/item/%E7%8E%84%E5%A4%A9%E4%B8%8A%E5%B8%9D%E6%84%9F%E5%BA%94%E7%BB%8F","https://ctext.org/"],textual_certainty:"high",notes:"batch17 · Grok-4.5 web-search"},{dz:"DZ1444",name_han:"太上说三官大帝本行经",name_vi:"Thái Thượng Thuyết Tam Quan Đại Đế Bản Hành Kinh",bu:"续道藏",author:"佚名（托名太上）",era:"明（续道藏系统）",topic:"仙传",essence:"Kinh bản hành (tiểu sử thần thánh) của Tam Quan Đại Đế — Thiên Quan, Địa Quan, Thủy Quan — kể nguồn gốc, chức năng ban phúc, xá tội, giải ách. Nội dung nền tảng cho tín ngưỡng Tam Quan và ngày vía Tam Quan (thượng/trung/hạ nguyên). Dùng tụng niệm cầu xá tội, ban phúc, và khoa nghi cúng Tam Quan.",key_text:"天官赐福，地官赦罪，水官解厄。",use:"Tụng cầu ban phúc xá tội giải ách; cúng Thượng/Trung/Hạ Nguyên.",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E8%AA%AA%E4%B8%89%E5%AE%98%E5%A4%A7%E5%B8%9D%E6%9C%AC%E8%A1%8C%E7%B6%93","https://baike.baidu.com/item/%E4%B8%89%E5%AE%98%E5%A4%A7%E5%B8%9D","https://ctext.org/"],textual_certainty:"partial",notes:"batch17 · Grok-4.5 web-search"},{dz:"DZ0658",name_han:"太上妙始经",name_vi:"Thái Thượng Diệu Thủy Kinh",bu:"太玄",author:"佚名（重玄/老学传统）",era:"唐（重玄学兴盛）",topic:"philosophy",essence:"Kinh luận về “diệu thủy” — nguồn khởi huyền diệu của đạo — mang màu sắc Trùng Huyền và Lão học. Nội dung bàn đạo thể, khởi nguyên vũ trụ và chỗ huyền diệu của “thủy/vô”, không nghiêng về phù lục mà về triết lý. Dùng cho đọc tụng suy ngẫm, nghiên cứu tư tưởng Thái Huyền/Trùng Huyền hơn là khoa nghi thực dụng.",key_text:"妙始希夷，道之根也。",use:"Đọc tụng suy ngẫm, nghiên cứu Lão học/Trùng Huyền.",sources:["https://zh.wikisource.org/","https://ctext.org/","https://dao.crs.cuhk.edu.hk/en/"],textual_certainty:"low",notes:"batch17 · Grok-4.5 web-search"},{dz:"DZ627",name_han:"太上说中斗大魁保命妙经",name_vi:"Thái Thượng thuyết Trung Đẩu Đại Khôi bảo mệnh diệu kinh",bu:"洞神",author:"佚名（宋初蜀中道士；《五斗经》之一）",era:"北宋（约11世纪）",topic:"ritual",essence:"Kinh thuộc nhóm Ngũ Đẩu, giả thác Thái Thượng Lão Quân truyền cho Trương Thiên Sư tại Thục. Trung Đẩu ở trung ương, “Đông Đẩu chủ toán, Tây Đẩu ký danh, Bắc Đẩu lạc tử, Nam Đẩu thượng sinh, Trung Đẩu Đại Khôi nguy nhiên chí tôn”. Trì tụng, cúng tế, tạ tội vào ngày bản mệnh hay tam nguyên để kéo dài tuổi thọ, tiêu họa, bảo mệnh.",key_text:"東斗主算。西斗記名。北斗落死。南斗上生。中斗大魁。巍然至尊。",use:"Đọc tụng, lập đàn, cúng Trung Đẩu / Ngũ Đẩu để bảo mệnh, ích toán, trừ tai",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E8%AA%AA%E4%B8%AD%E6%96%97%E5%A4%A7%E9%AD%81%E4%BF%9D%E5%91%BD%E5%A6%99%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E8%AA%AA%E4%B8%AD%E6%96%97%E5%A4%A7%E9%AD%81%E4%BF%9D%E5%91%BD%E5%A6%99%E7%B6%93","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch18 · Grok-4.5 web-search"},{dz:"DZ672",name_han:"太上老君说益筭神符妙经",name_vi:"Thái Thượng Lão Quân thuyết Ích toán thần phù diệu kinh",bu:"洞神",author:"佚名",era:"唐宋间",topic:"fu",essence:"Kinh thuộc thần phù, giả thác Lão Quân và Trương Thiên Sư bàn nguồn tai họa tội báo cùng cách giải. Khuyến trai giới, trì kinh, đeo phù Bắc Đẩu / tam đài để trừ bệnh, ích toán, tăng lộc thọ. Cuối kinh kèm phù Bắc Đẩu thất tinh và tam đài tinh quân.",key_text:"佩帶之者，當須精勤，心常敬信，無不安寧，千灾萬禍，俱時消化。",use:"Đeo phù, trì tụng để tăng tuổi thọ, tiêu tai, trị bệnh",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E7%9B%8A%E7%AD%AD%E7%A5%9E%E7%AC%A6%E5%A6%99%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E7%9B%8A%E7%AD%AD%E7%A5%9E%E7%AC%A6%E5%A6%99%E7%B6%93","https://www.shidianguji.com/book/DZ0672"],textual_certainty:"high",notes:"batch18 · Grok-4.5 web-search"},{dz:"null",name_han:"太上老君说七十二灶王经",name_vi:"Thái Thượng Lão Quân thuyết Thất thập nhị Táo Vương kinh",bu:"洞玄（近本）/民间",author:"佚名（正统道藏无此精确书名）",era:"不明；民间灶神信仰",topic:"ritual",essence:"Không có đúng tựa này trong Chính thống Đạo tạng. Gần nhất là Thái Thượng Linh Bảo bổ tạ Táo Vương kinh (DZ364, động huyền), nói Táo thần là “chủng hỏa chi mẫu”, chủ tư mệnh, ghi thiện ác, dâng tấu thiên tào; văn bản có cụm “thất thập nhị táo thị tòng”. Dân gian còn lưu các bản Táo Vương kinh tục lưu.",key_text:"七十二灶侍从。神众弟子。",use:"Tạ Táo, cúng bếp, xin tha phạm kỵ, cầu an gia",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E9%9D%88%E5%AF%B6%E8%A3%9C%E8%AC%9D%E7%AB%88%E7%8E%8B%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E9%9D%88%E5%AF%B6%E8%A3%9C%E8%AC%9D%E7%AB%83%E7%8E%8B%E7%B6%93","https://baike.baidu.com/item/%E7%81%B6%E7%8E%8B%E7%BB%8F/4863401"],textual_certainty:"partial",notes:"batch18 · Grok-4.5 web-search"},{dz:"DZ1447",name_han:"太上老君说城隍感应消灾集福妙经",name_vi:"Thái Thượng Lão Quân thuyết Thành Hoàng cảm ứng tiêu tai tập phúc diệu kinh",bu:"续道藏",author:"佚名",era:"明初（洪武九年置十三布政使司之后）",topic:"ritual",essence:"Kinh thuộc Vạn lịch Tục Đạo tạng, giả thác Lão Quân giảng về Thành Hoàng công chính, chưởng sinh tử họa phúc. Nói chúng sinh số mệnh do Thành Hoàng thân tấu; trì tụng kinh, lễ phán quan thì tiêu tội, trừ tai, hộ quốc an dân. Có khai kinh kệ, danh mục thập tam bố chính / thập bát ty và Đô Thành Hoàng chân cáo.",key_text:"稽首皈衣城隍尊，威靈烜赫鎮乾坤。護國安邦扶社稷，降施甘澤救生民。",use:"Trì tụng, cúng Thành Hoàng để tiêu tai, cầu phúc, hộ quốc an bang",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E5%9F%8E%E9%9A%8D%E6%84%9F%E6%87%89%E6%B6%88%E7%81%BD%E9%9B%86%E7%A6%8F%E5%A6%99%E7%B6%93&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&chapter=935872","https://www.shidianguji.com/zh/book/DZ1447"],textual_certainty:"high",notes:"batch18 · Grok-4.5 web-search"},{dz:"null",name_han:"太上说东岳大帝护国保民妙经",name_vi:"Thái Thượng thuyết Đông Nhạc Đại Đế hộ quốc bảo dân diệu kinh",bu:"续道藏（近本）/民间",author:"佚名（正统/续藏无此精确书名）",era:"明或稍后（民间东岳信仰）",topic:"ritual",essence:"Không tìm thấy đúng tựa trong mục lục Schipper. Gần nhất trong Tục Đạo tạng là Nguyên Thủy Thiên Tôn thuyết Đông Nhạc hóa thân tế sinh độ tử… huyền phạm cáo chú diệu kinh (DZ1441): quy mệnh Đông Nhạc / ngũ nhạc để hộ quốc an dân, bạt tội, tế sinh độ tử. Còn có Đông Nhạc đại sinh bảo sám (DZ541) và các kinh Bích Hà liên quan.",key_text:"null",use:"Lễ Đông Nhạc Đại Đế, cầu hộ quốc bảo dân, tiêu tội, độ vong",sources:["https://zh.daoinfo.org/index.php?title=%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E6%9D%B1%E5%B6%BD%E5%8C%96%E8%BA%AB%E6%BF%9F%E7%94%9F%E5%BA%A6%E6%AD%BB%E6%8B%94%E7%BD%AA%E8%A7%A3%E5%86%A4%E4%BF%9D%E5%91%BD%E7%8E%84%E7%AF%84%E8%AA%A5%E5%92%92%E5%A6%99%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E6%9D%B1%E5%B6%BD%E5%8C%96%E8%BA%AB%E6%BF%9F%E7%94%9F%E5%BA%A6%E6%AD%BB%E6%8B%94%E7%BD%AA%E8%A7%A3%E5%86%A4%E4%BF%9D%E5%91%BD%E7%8E%84%E7%AF%84%E8%AA%A5%E5%91%AA%E5%A6%99%E7%B6%93","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"low",notes:"batch18 · Grok-4.5 web-search"},{dz:"DZ596",name_han:"仙苑编珠",name_vi:"Tiên Uyển biên châu",bu:"洞玄",author:"王松年（天台山道士）",era:"唐末五代（约10世纪）",topic:"仙传",essence:"Bộ tiên truyện ba quyển theo thể “Mông cầu”: mỗi điều hai câu tứ ngôn, kèm chú giải. Trích Liệt tiên truyện, Thần tiên truyện, Chân cáo… và kiến văn đời Lương–Đường, chép hơn ba trăm vị thần tiên, đế vương hiếu đạo. Giá trị ở chỗ bảo tồn nhiều mẩu truyện / đạo thư đã thất lạc.",key_text:"null",use:"Tra cứu tiên truyện, học gương tu tiên, bổ sung sử đạo",sources:["https://zh.daoinfo.org/index.php?title=%E4%BB%99%E8%8B%91%E7%B7%A8%E7%8F%A0&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&res=675609","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch18 · Grok-4.5 web-search"},{dz:"DZ781",name_han:"玄品录",name_vi:"Huyền phẩm lục",bu:"洞神",author:"张天雨（张雨；非张君房）",era:"元（约至元元年/1335）",topic:"仙传",essence:"Tiên truyện–đạo sử năm quyển của đạo sĩ Mao Sơn Trương Vũ (Trương Thiên Vũ). Theo triều đại (Chu→Tống) chia phẩm loại (đạo đức, đạo phẩm, đạo quyền…), chép khoảng 146 vị thần tiên và đạo lưu. Không phải tác phẩm của Trương Quân Phòng (Vân Cấp Thất Thiêm).",key_text:"null",use:"Đọc truyện tiên, phân phẩm đạo sĩ, tham khảo lịch sử Đạo giáo",sources:["https://zh.wikisource.org/zh-hans/%E7%8E%84%E5%93%81%E9%8C%84","https://ctext.org/wiki.pl?if=gb&res=149251","https://baike.baidu.com/item/%E7%8E%84%E5%93%81%E5%BD%95/9681104"],textual_certainty:"high",notes:"batch18 · Grok-4.5 web-search"},{dz:"DZ019",name_han:"太上升玄消灾护命妙经",name_vi:"Thái Thượng thăng huyền tiêu tai hộ mệnh diệu kinh",bu:"洞真",author:"佚名",era:"南北朝末至隋唐",topic:"philosophy",essence:"Kinh ngắn (~300 chữ), Nguyên Thủy Thiên Tôn thuyết; còn tên Thái Thượng Linh Bảo thăng huyền tiêu tai hộ mệnh kinh (Vân Cấp Thất Thiêm; Đôn Hoàng P.2471, S.3747). Dùng lý hữu–vô, sắc–không kiểu trung quán để “song khiển”, lìa biên; trì tụng để tiêu tai hộ mệnh, là văn bản then chốt của phái trùng huyền.",key_text:"視不見我，聽不得聞。離種種邊，名曰妙道。",use:"Trì tụng hộ mệnh tiêu tai; tham cứu tư tưởng trùng huyền / không quán",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%98%87%E7%8E%84%E6%B6%88%E7%81%BE%E8%AD%B7%E5%91%BD%E5%A6%99%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%98%87%E7%8E%84%E6%B6%88%E7%81%BE%E8%AD%B7%E5%91%BD%E5%A6%99%E7%B6%93","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT01%E6%B4%9E%E7%9C%9F%E9%83%A8/CMT0101%E6%9C%AC%E6%96%87%E9%A1%9E/CMT0101ALL/CNDZ010119%E5%A4%AA%E4%B8%8A%E6%98%87%E7%8E%84%E6%B6%88%E7%81%BD%E8%AD%B7%E5%91%BD%E5%A6%99%E7%B6%93.htm"],textual_certainty:"high",notes:"batch18 · Grok-4.5 web-search"},{dz:"null",name_han:"太上洞玄灵宝圆明大义经",name_vi:"Thái Thượng Động Huyền Linh Bảo viên minh đại nghĩa kinh",bu:"洞玄（题属）",author:"不详 / 未见可靠著录",era:"不详",topic:"philosophy",essence:"Không thấy đúng tựa trong mục lục Chính thống Đạo tạng (Schipper/Golden Elixir), ctext, wikisource hay daoinfo. Có thể nhầm với kinh Linh Bảo nghĩa lý khác hoặc tựa tục lưu. Không đủ bằng chứng để gán DZ hay tóm cốt tủy nội dung.",key_text:"null",use:"Chưa xác định; cần đối chiếu thêm mục lục/đơn bản",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://ctext.org/wiki.pl?if=gb","https://zh.daoinfo.org/"],textual_certainty:"low",notes:"batch18 · Grok-4.5 web-search"},{dz:"DZ1255",name_han:"老子微旨例略",name_vi:"Lão Tử vi chỉ lệ lược",bu:"正一（藏本归部）/太玄传统",author:"王弼（魏）",era:"三国魏（3世纪）",topic:"philosophy",essence:"Còn gọi Lão Tử chỉ lược; Vương Bật tóm cốt lõi Lão học bằng bản thể luận: “sùng bản tức mạt”, vật sinh từ vô hình vô danh. Luận biện danh–định thực, trọng huyền vô. Bản Đạo tạng thuộc Chính nhất bộ; cũng thấy trong Vân Cấp Thất Thiêm.",key_text:"夫物之所以生，功之所以成，必生乎无形，由乎无名。",use:"Đọc–chú Lão Tử, nghiên cứu huyền học / bản thể luận",sources:["https://zh.wikisource.org/wiki/%E8%80%81%E5%AD%90%E5%BE%AE%E6%97%A8%E4%BE%8B%E7%95%A5","https://zh.daoinfo.org/index.php?title=%E8%80%81%E5%AD%90%E5%BE%AE%E6%97%A8%E4%BE%8B%E7%95%A5%EF%BC%88%E7%8E%8B%E5%BC%BC%EF%BC%89&variant=zh-hans","https://www.shidianguji.com/zh/book/DZ1255"],textual_certainty:"high",notes:"batch18 · Grok-4.5 web-search"},{dz:"DZ1111",name_han:"太玄真一本际经",name_vi:"Thái Huyền chân nhất bản tế kinh",bu:"太平",author:"刘进喜造（隋），李仲卿续成（唐初）",era:"隋–唐初",topic:"philosophy",essence:"Kinh trọng huyền quan trọng: Nguyên Thủy Thiên Tôn và chư chân vấn đáp về bản tế, đạo tính, giới luật, thứ bậc tu. Chủ trương đạo “phi hữu phi vô”, “kiêm vong trùng huyền” (quên hữu rồi quên không, rồi quên cả quên). Chính thống Đạo tạng chỉ còn quyển 2 (Phó chúc phẩm); bản đủ ~10 quyển phục nguyên từ Đôn Hoàng.",key_text:"正觀之人前空諸有，於有無著；次遣於空，空心亦淨，乃曰兼忘。",use:"Nghiên cứu trùng huyền, đạo tính; tụng giảng giáo lý",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E7%8E%84%E7%9C%9F%E4%B8%80%E6%9C%AC%E9%9A%9B%E7%B6%93%EF%BC%88%E6%95%A6%E7%85%8C%E6%9C%AC%EF%BC%89&variant=zh-hans","https://www.shidianguji.com/book/DZ1111","https://ctext.org/wiki.pl?if=gb&chapter=332203"],textual_certainty:"high",notes:"batch18 · Grok-4.5 web-search"},{dz:"null",name_han:"太清真人授道经",name_vi:"Thái Thanh chân nhân thụ đạo kinh",bu:"太清（题属）",author:"不详 / 未见可靠著录",era:"不详",topic:"cultivation",essence:"Không thấy đúng tựa trong mục lục Schipper. Gần tựa có Thái Thanh chân nhân lạc mệnh quyết (DZ132) hoặc các nghi “thụ đạo / truyền thụ” khác, nhưng không đồng nhất với “Thái Thanh chân nhân thụ đạo kinh”. Không đủ bằng chứng gán DZ hay tóm cốt tủy.",key_text:"null",use:"Chưa xác định",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://ctext.org/wiki.pl?if=gb","https://zh.daoinfo.org/"],textual_certainty:"low",notes:"batch18 · Grok-4.5 web-search"},{dz:"null",name_han:"太上说百解消灾妙经",name_vi:"Thái Thượng thuyết Bách giải tiêu tai diệu kinh",bu:"不明",author:"不详 / 未见可靠著录",era:"不详",topic:"ritual",essence:"Không thấy đúng tựa “bách giải tiêu tai” trong mục lục Chính thống Đạo tạng. Có các kinh tiêu tai liên quan (như Thái Thượng Lão Quân thuyết tiêu tai kinh) nhưng không đồng nhất. Không đủ bằng chứng gán DZ hay tóm cốt tủy an toàn.",key_text:"null",use:"Chưa xác định; có thể là kinh tiêu tai tục lưu ngoài tạng",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E6%B6%88%E7%81%BE%E7%B6%93&variant=zh-hans","https://ctext.org/wiki.pl?if=gb"],textual_certainty:"low",notes:"batch18 · Grok-4.5 web-search"},{dz:"DZ547",name_han:"灵宝玉鉴",name_vi:"Linh Bảo ngọc giám",bu:"洞玄",author:"佚名",era:"北宋末–南宋初",topic:"ritual",essence:"Tổng tập khoa nghi Linh Bảo 43 quyển (+ mục lục DZ546): 25 môn từ đạo pháp thích nghi, trai tu, phù lục, triệu nhiếp, luyện độ… Xem Linh Bảo đại pháp là tông vạn pháp; được Kim Doãn Trung dẫn trong Thượng Thanh Linh Bảo đại pháp. Là “cẩm nang” trai tiếu–phù lục phái Linh Bảo đời Tống–Nguyên.",key_text:"null",use:"Tra cứu và hành trì khoa nghi Linh Bảo, phù lục, trai tiếu, luyện độ",sources:["https://zh.daoinfo.org/index.php?title=%E9%9D%88%E5%AF%B6%E7%8E%89%E9%91%92&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E9%9D%88%E5%AF%B6%E7%8E%89%E9%91%91","https://www.shidianguji.com/book/DZ0546"],textual_certainty:"high",notes:"batch18 · Grok-4.5 web-search"},{dz:"null",name_han:"洞神三皇经",name_vi:"Động Thần Tam Hoàng kinh",bu:"洞神",author:"传说系（鲍靓得文，传葛洪等）；古本多佚",era:"汉魏六朝成形；唐前必读",topic:"fu",essence:"Tức Tam Hoàng văn / Tam Hoàng nội văn (Thiên–Địa–Nhân hoàng), gốc bộ Động Thần: phù đồ hặc triệu quỷ thần, tồn tư, bí quyết trị thế. Bản cổ đã thất; trong tạng còn mảnh/biến thể như Tam Hoàng nội văn di bí (DZ856), Thái Thượng Động Thần Tam Hoàng nghi (DZ803), bát đế kinh… Tùy từng thời bị triều đình cấm hoặc thay bằng Đạo Đức kinh.",key_text:"null",use:"Hặc triệu, phù cấm, tồn tư; lịch sử giáo đoàn Động Thần (nghiên cứu)",sources:["https://zh.wikipedia.org/zh-hans/%E4%B8%89%E7%9A%87%E6%96%87","https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%A5%9E%E4%B8%89%E7%9A%87%E5%84%80","https://baike.baidu.com/item/%E4%B8%89%E7%9A%87%E7%BB%8F/9680525"],textual_certainty:"partial",notes:"batch18 · Grok-4.5 web-search"},{dz:"null",name_han:"太上说上元一品赐福天官妙经",name_vi:"Thái Thượng thuyết Thượng Nguyên nhất phẩm tứ phúc Thiên quan diệu kinh",bu:"续道藏",author:"佚名",era:"宋—明（三官经系统成熟期）",topic:"ritual",essence:"Đây không phải một quyển độc lập với đúng nhan đề trong mục lục 正统道藏, mà là danh xưng phổ biến gắn với Thượng Nguyên Thiên quan (紫微大帝) trong hệ kinh Tam quan. Cốt tủy là Thiên quan chưởng phúc, khảo xét thiện ác, ban phước cho chúng sinh vào ngày Thượng Nguyên. Thực tế văn bản thường gắn với 《元始天尊说三官宝号经》(洞真部, 道藏提要约DZ71) và 《太上三元赐福赦罪解厄消灾延生保命妙经》(续道藏, 约DZ1429).",key_text:"上元一品赐福天官紫微大帝",use:"Tụng niệm, cầu phúc Thượng Nguyên; nhập nghi thức Tam quan",sources:["https://zh.daoinfo.org/index.php?title=%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E4%B8%89%E5%AE%98%E5%AF%B6%E8%99%9F%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E4%B8%89%E5%85%83%E8%B3%9C%E7%A6%8F%E8%B5%A6%E7%BD%AA%E8%A7%A3%E5%8E%84%E6%B6%88%E7%81%BD%E5%BB%B6%E7%94%9F%E4%BF%9D%E5%91%BD%E5%A6%99%E7%B6%93","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E4%B8%89%E5%85%83%E8%B3%9C%E7%A6%8F%E8%B5%A6%E7%BD%AA%E8%A7%A3%E5%8E%84%E6%B6%88%E7%81%BE%E5%BB%B6%E7%94%9F%E4%BF%9D%E5%91%BD%E5%A6%99%E7%B6%93&variant=zh-hans"],textual_certainty:"partial",notes:"batch19 · Grok-4.5 web-search"},{dz:"null",name_han:"太上说中元二品赦罪地官妙经",name_vi:"Thái Thượng thuyết Trung Nguyên nhị phẩm xá tội Địa quan diệu kinh",bu:"续道藏",author:"佚名",era:"宋—明",topic:"ritual",essence:"Nhan đề lưu hành chỉ Trung Nguyên Địa quan (清虚/青灵大帝), chủ chưởng địa phủ, xá tội, khảo lục họa phúc. Trong kinh Tam quan hợp nhất, Địa quan vào Trung Nguyên (tháng 7) xá tội, xóa sổ tội, độ thoát u hồn. Không thấy mục lục độc lập đúng nhan đề trong 正统道藏; nội dung nằm trong 三官宝号/三官经.",key_text:"中元二品赦罪地官清虚大帝",use:"Tụng xá tội Trung Nguyên, siêu độ, sám hối",sources:["https://zh.daoinfo.org/index.php?title=%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E4%B8%89%E5%AE%98%E5%AF%B6%E8%99%9F%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E4%B8%89%E5%85%83%E8%B3%9C%E7%A6%8F%E8%B5%A6%E7%BD%AA%E8%A7%A3%E5%8E%84%E6%B6%88%E7%81%BD%E5%BB%B6%E7%94%9F%E4%BF%9D%E5%91%BD%E5%A6%99%E7%B6%93","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E4%B8%89%E5%AE%98%E5%AF%B6%E7%B6%93"],textual_certainty:"partial",notes:"batch19 · Grok-4.5 web-search"},{dz:"null",name_han:"太上说下元三品解厄水官妙经",name_vi:"Thái Thượng thuyết Hạ Nguyên tam phẩm giải ách Thủy quan diệu kinh",bu:"续道藏",author:"佚名",era:"宋—明",topic:"ritual",essence:"Danh xưng gắn Hạ Nguyên Thủy quan (洞阴大帝), chủ giải ách, thủy phủ, tai ương sông biển và vận hạn. Trong 三官经, tụng kinh khiến Thủy quan giải ách, gió yên sóng lặng, bệnh tật tiêu trừ. Cũng không phải bộ độc lập đúng nhan đề trong 正统道藏, mà là nhánh chức năng trong hệ Tam quan.",key_text:"下元三品解厄水官洞阴大帝",use:"Cầu giải ách Hạ Nguyên, bình an thủy lộ, tiêu tai",sources:["https://zh.daoinfo.org/index.php?title=%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E4%B8%89%E5%AE%98%E5%AF%B6%E8%99%9F%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E4%B8%89%E5%85%83%E8%B3%9C%E7%A6%8F%E8%B5%A6%E7%BD%AA%E8%A7%A3%E5%8E%84%E6%B6%88%E7%81%BD%E5%BB%B6%E7%94%9F%E4%BF%9D%E5%91%BD%E5%A6%99%E7%B6%93","https://baike.baidu.com/item/%E5%A4%AA%E4%B8%8A%E4%B8%89%E5%85%83%E8%B5%90%E7%A6%8F%E8%B5%A6%E7%BD%AA%E8%A7%A3%E5%8E%84%E6%B6%88%E7%81%BE%E5%BB%B6%E7%94%9F%E4%BF%9D%E5%91%BD%E5%A6%99%E7%BB%8F/5259110"],textual_certainty:"partial",notes:"batch19 · Grok-4.5 web-search"},{dz:"DZ845",name_han:"三元延寿参赞书",name_vi:"Tam nguyên diên thọ tham tán thư",bu:"洞神",author:"李鹏飞（九华澄心老人）",era:"元（约1291–1294）",topic:"cultivation",essence:"Sách dưỡng sinh năm quyển của Lý Bằng Phi đời Nguyên, thu vào 道藏洞神部方法类. Lấy thuyết “thiên—địa—nhân tam nguyên” mỗi nguyên 60 tuổi, tổng 180 tuổi; hao tinh khí, khởi cư vô thường, ẩm thực thất tiết thì giảm thọ. Ba quyển đầu bàn tiết dục, khởi cư, ẩm thực; hai quyển sau thuật quyết tu dưỡng và khuyến thiện.",key_text:"人之寿天元六十，地元六十，人元六十，共一百八十岁",use:"Dưỡng sinh y đạo, tiết dục thận thực, tham chiếu y học Đạo giáo",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%89%E5%85%83%E5%BB%B6%E5%A3%BD%E5%8F%83%E8%B4%8A%E6%9B%B8&variant=zh-hans","https://www.shidianguji.com/book/DZ0851","https://baike.baidu.com/item/%E4%B8%89%E5%85%83%E5%BB%B6%E5%AF%BF%E5%8F%82%E8%B5%9E%E4%B9%A6/9680489","https://zh.wikisource.org/zh-hans/%E4%B8%89%E5%85%83%E5%8F%83%E8%B4%8A%E5%BB%B6%E5%A3%BD%E6%9B%B8"],textual_certainty:"high",notes:"batch19 · Grok-4.5 web-search"},{dz:"DZ74",name_han:"太上说九幽拔罪心印妙经",name_vi:"Thái Thượng thuyết Cửu u bạt tội tâm ấn diệu kinh",bu:"洞真",author:"佚名",era:"唐宋间（约）",topic:"classic",essence:"Kinh ngắn 洞真部本文类: Nguyên Thủy Thiên Tôn giảng cho Cứu Khổ Chân Nhân. Chủ trương mọi nghiệp ác do tâm vọng tưởng điên đảo; tội căn từ tâm, thiên đường cũng từ tâm. Nói kệ bốn chữ khuyên không tham dục, thân tâm thanh tịnh, khế hợp tâm ấn, thoát cửu u.",key_text:"一切罪根，皆从心起，天堂快乐，自由心生，三界沉沦，亦从心起",use:"Tụng bạt tội, siêu u, tịnh tâm sám hối",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E8%AA%AA%E4%B9%9D%E5%B9%BD%E6%8B%94%E7%BD%AA%E5%BF%83%E5%8D%B0%E5%A6%99%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E8%AA%AA%E4%B9%9D%E5%B9%BD%E6%8B%94%E7%BD%AA%E5%BF%83%E5%8D%B0%E5%A6%99%E7%B6%93","https://www.shidianguji.com/book/LSDZ0071"],textual_certainty:"high",notes:"batch19 · Grok-4.5 web-search"},{dz:"DZ717",name_han:"道德真经注",name_vi:"Đạo Đức chân kinh chú",bu:"洞神",author:"李荣（任真子，元天观道士）",era:"唐（高宗—武后）",topic:"philosophy",essence:"Chú Lão Tử theo học phái Trùng huyền đời Đường sơ, cùng hàng với Thành Huyền Anh. Bản 道藏洞神部玉诀类 còn chú đạo kinh ch.1–36; phần đức kinh bổ sung từ Đôn Hoàng và 《玄德纂疏》. Lấy “trùng huyền” phá chấp hữu—vô, đề cao thánh quân vô vi, tâm tính hợp đạo.",key_text:"null",use:"Nghiên cứu Trùng huyền học, chú giải Đạo Đức kinh",sources:["https://zh.daoinfo.org/index.php?title=%E9%81%93%E5%BE%B7%E7%9C%9F%E7%B6%93%E8%A8%BB%EF%BC%88%E6%9D%8E%E6%A6%AE%EF%BC%89&variant=zh-hans","https://www.shidianguji.com/zh/book/DZ0722","https://ctext.org/wiki.pl?if=gb&res=842943"],textual_certainty:"high",notes:"batch19 · Grok-4.5 web-search"},{dz:"DZ1176",name_han:"抱朴子别旨",name_vi:"Bão Phác Tử biệt chỉ",bu:"太清",author:"题葛洪（后人疑伪）",era:"题东晋；著录见南宋（疑出后）",topic:"服气",essence:"Một quyển phụ sau 《抱朴子内篇》 trong 太清部. Bàn đạo dẫn, hành khí: phân chúng khí, thô khí, nguyên khí; dưỡng sinh chủ bảo nguyên khí ít mà khó tán. Nghi không phải bút Cát Hồng nguyên bản, nhưng thuộc truyền thống ngoại đan—dưỡng sinh Bão Phác.",key_text:"null",use:"Đạo dẫn hành khí, dưỡng nguyên khí",sources:["https://zh.daoinfo.org/wiki/%E6%8A%B1%E6%9C%B4%E5%AD%90%E5%88%A5%E6%97%A8","https://ctext.org/wiki.pl?if=gb&chapter=7691311","https://gj.zdic.net/zibu/497/12536.html"],textual_certainty:"high",notes:"batch19 · Grok-4.5 web-search"},{dz:null,name_han:"上清三真旨要玉诀",name_vi:"Thượng Thanh tam chân chỉ yếu ngọc quyết",bu:"洞玄",author:"佚名（上清派；或与陶弘景《登真隐诀》相关）",era:"南北朝（约）",topic:"cultivation",essence:"Tập yếu quyết tu chân Thượng Thanh: đạo dẫn, phục khí, yết dịch, khấu xỉ, tồn tư, nội thị, tụng chú. Lưu Bồi cho rằng có thể là quyển khuyết của 《登真隐诀》. Bản 道藏洞玄部玉诀类 còn khuyết; Đôn Hoàng P.2576V bổ sung hơn 200 hàng. (Nhan đề người dùng viết “玉经” — bản chuẩn là “玉诀”.)",key_text:"夫修真之诀每以旦夕凝神定息",use:"Thực tu Thượng Thanh: tồn tư, đạo dẫn, bí quyết đăng chân",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%8A%E6%B8%85%E4%B8%89%E7%9C%9F%E6%97%A8%E8%A6%81%E7%8E%89%E8%A8%A3&variant=zh-hans","https://zh.wikisource.org/wiki/%E4%B8%8A%E6%B8%85%E4%B8%89%E7%9C%9F%E6%97%A8%E8%A6%81%E7%8E%89%E8%A8%A3","https://ctext.org/wiki.pl?if=gb&chapter=964633"],textual_certainty:"partial",notes:"batch19 · Grok-4.5 web-search"},{dz:"null",name_han:"太上玄都太妙经",name_vi:"Thái Thượng Huyền Đô thái diệu kinh",bu:"洞真",author:"未详",era:"未详",topic:"classic",essence:"Không xác minh được bộ đúng nhan đề “太上玄都太妙经” trong 正统道藏. Gần nhất là 《太上玄都妙本清静身心经》(洞真部本文类, 道藏提要约DZ35, Sui–Tang): bàn diệu bản thanh tĩnh thân tâm, sớm hơn 《洗浴身心经》 của Lý Vinh. Có thể nhầm/tên biến thể; cần đối chiếu mục lục Schipper/CRTA trước khi gán DZ.",key_text:"null",use:"（若即妙本清静身心经）清心寡欲、身心修持",sources:["http://www.ctcwri.idv.tw/CTCW-CMTS/CMT01%E6%B4%9E%E7%9C%9F%E9%83%A8/CMT0101%E6%9C%AC%E6%96%87%E9%A1%9E/CMT0101ALL/CNDZ010135%E5%A4%AA%E4%B8%8A%E7%8E%84%E9%83%BD%E5%A6%99%E6%9C%AC%E6%B8%85%E9%9D%9C%E8%BA%AB%E5%BF%83%E7%B6%93.htm","https://upload.wikimedia.org/wikipedia/commons/f/f1/SSID-10489785_%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F%E7%9B%AE%E9%8C%84%E7%B4%A2%E5%BC%95.pdf","https://www.jstor.org/stable/26768560"],textual_certainty:"low",notes:"batch19 · Grok-4.5 web-search"},{dz:"DZ1370",name_han:"上清九丹上化胎精中记经",name_vi:"Thượng Thanh cửu đan thượng hóa thai tinh trung ký kinh",bu:"正一",author:"佚名（早期上清）",era:"东晋（约）",topic:"cultivation",essence:"Kinh Thượng Thanh sơ kỳ, 《真诰》 đã nhắc “九丹变化胎精中记”. Nói người thai từ cửu thiên chi khí, mang mười hai kết tiết khiến bệnh tật yểu tử; phải giải kết bằng tồn tư nhị thập tứ chân, huyền phụ huyền mẫu, phục phù thượng hóa cửu đan. Tuy người dùng ghi 洞真, bản 道藏 xếp 正一部.",key_text:"null",use:"Giải thai kết, tồn tư bát cảnh nhị thập tứ thần, cầu trường sinh",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%8A%E6%B8%85%E4%B9%9D%E4%B8%B9%E4%B8%8A%E5%8C%96%E8%83%8E%E7%B2%BE%E4%B8%AD%E8%A8%98%E7%B6%93&variant=zh-hans","https://www.shidianguji.com/zh/book/DZ1382","https://ctext.org/wiki.pl?if=gb&res=66638","https://github.com/kanripo/KR5g0191"],textual_certainty:"high",notes:"batch19 · Grok-4.5 web-search"},{dz:"DZ338",name_han:"太上洞玄灵宝出家因缘经",name_vi:"Thái Thượng Động Huyền Linh Bảo xuất gia nhân duyên kinh",bu:"洞玄",author:"佚名",era:"隋—唐（约；《妙门由起》已引）",topic:"戒律",essence:"Linh Bảo kinh khuyên xuất gia: Thái Thượng Thiên Tôn nói nhân duyên xuất gia, giải thoát sinh tử. Có sơ chân thập giới, thường phát đại tâm bát sự, thập thệ thập nguyện, tiếp nhận độ thoát. Phản ánh chế độ đạo sĩ và giới luật thời Sui–Tang.",key_text:"夫出家者，因缘甚重",use:"Giới luật xuất gia, khuyên nhập đạo, nghi thức phát nguyện",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E5%87%BA%E5%AE%B6%E5%9B%A0%E7%B7%A3%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E5%87%BA%E5%AE%B6%E5%9B%A0%E7%B7%A3%E7%B6%93","https://ctext.org/wiki.pl?if=gb&chapter=253356"],textual_certainty:"high",notes:"batch19 · Grok-4.5 web-search"},{dz:"null",name_han:"太上说五斗星君本行真经",name_vi:"Thái Thượng thuyết Ngũ đẩu tinh quân bản hành chân kinh",bu:"洞神",author:"未详",era:"未详（五斗信仰唐宋以后盛行）",topic:"classic",essence:"Không tìm thấy đúng nhan đề “五斗星君本行真经” trong 正统道藏. Hệ ngũ đẩu thường gồm 《太上玄灵北斗本命延生真经》 và các kinh Đông/Nam/Tây/Trung đẩu; gần “bản mệnh/thụ sinh” là 《太上老君说五斗金章受生经》(约DZ648): ngũ đẩu chú sinh chú lộc, khuyên trai giới, chương kiếu, nạp bổn mệnh tiền. Có thể là tên dân gian hoặc biến thể ngoài mục lục chuẩn.",key_text:"五斗星君、九天众圣，注生注禄、注富注贫、注长注短、注吉注凶，皆由众生自作自受",use:"（近缘五斗经）本命延生、章醮五斗、补财库",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E4%BA%94%E6%96%97%E9%87%91%E7%AB%A0%E5%8F%97%E7%94%9F%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E4%BA%94%E6%96%97%E9%87%91%E7%AB%A0%E5%8F%97%E7%94%9F%E7%B6%93","https://dao.crs.cuhk.edu.hk/Main/wp-content/uploads/2022/09/DAO14_05_%E6%96%BD%E7%A7%A6%E7%94%9F.pdf"],textual_certainty:"low",notes:"batch19 · Grok-4.5 web-search"},{dz:"DZ1094",name_han:"太上灵宝净明洞神上品经",name_vi:"Thái Thượng Linh Bảo Tịnh Minh động thần thượng phẩm kinh",bu:"太平",author:"佚名（南宋净明道；托许真君西山传授）",era:"南宋",topic:"ritual",essence:"Kinh chính Tịnh Minh đạo, còn gọi 《净明秘法》/《净明真经》, 35 thiên, 2 quyển, 太平部 (không phải洞神部). Lấy trung hiếu làm gốc, luyện hình tu kỷ; có tụng 《灵书》 (Phạn âm thần danh), bội phù bảo lục, phi bộ huyền cương, trị bệnh siêu độ. Nhiều phù lục khuyết, bổ bằng 《净明秘法篇》.",key_text:"null",use:"Giáo nghĩa Tịnh Minh, trung hiếu, phù chú luyện độ",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E9%9D%88%E5%AF%B6%E6%B7%A8%E6%98%8E%E6%B4%9E%E7%A5%9E%E4%B8%8A%E5%93%81%E7%B6%93&variant=zh-hans","https://www.shidianguji.com/book/DZ1103","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E9%9D%88%E5%AF%B6%E6%B7%A8%E6%98%8E%E6%B4%9E%E7%A5%9E%E4%B8%8A%E5%93%81%E7%B6%93","https://ctext.org/wiki.pl?if=gb&res=775890&remap=gb"],textual_certainty:"high",notes:"batch19 · Grok-4.5 web-search"},{dz:"DZ645",name_han:"太上说长生益算妙经",name_vi:"Thái Thượng thuyết trường sinh ích toán diệu kinh",bu:"洞神",author:"佚名",era:"唐（约）",topic:"classic",essence:"Bản chuẩn nhan đề đầy đủ thường là 《太上老君说长生益算妙经》, 洞神部本文类. Lão Quân tại Thiền Lê quốc thổ thấy chúng sinh bệnh tật yểu thọ, triệu Đông cực Trường Sinh chân quân và lục giáp chủ toán, ban phù lục (khai tâm, ích toán, hộ mệnh…), khuyên chuyển kinh trai giới để trừ khổ, tăng thọ.",key_text:"null",use:"Ích toán trường sinh, trừ bệnh, bội phù tụng kinh",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E9%95%B7%E7%94%9F%E7%9B%8A%E7%AD%AD%E5%A6%99%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E9%95%B7%E7%94%9F%E7%9B%8A%E7%AD%AD%E5%A6%99%E7%B6%93","https://baike.baidu.com/item/%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AF%B4%E9%95%BF%E7%94%9F%E7%9B%8A%E7%AE%97%E5%A6%99%E7%BB%8F/17623740","https://ctext.org/wiki.pl?if=gb&res=514932"],textual_certainty:"high",notes:"batch19 · Grok-4.5 web-search"},{dz:"DZ526",name_han:"太上洞玄灵宝三元威仪自然经",name_vi:"Thái Thượng Động Huyền Linh Bảo tam nguyên uy nghi tự nhiên kinh",bu:"洞玄",author:"佚名（古灵宝经）",era:"东晋末—南朝初",topic:"ritual",essence:"Tương ứng 《洞玄灵宝玉箓简文三元威仪自然真经》, cổ Linh Bảo, Lục Tu Tĩnh 《灵宝经目》 đã lục. Nguyên ba thiên Kim/Ngọc/Hoàng lục giản văn; 道藏 chỉ còn 《中元玉箓简文》 khoảng 80 điều uy nghi thầy—trò (phụng sư, nghệ sư, vi sư). Đôn Hoàng và 《无上秘要》 còn mảnh Hạ nguyên/Thượng nguyên. Là khuôn mẫu khoa nghi đạo giáo sơ kỳ.",key_text:"灵宝中元宫中，旧有三部威仪二千四百条",use:"Khoa nghi uy nghi, giới luật sư đệ, nghi thức cổ Linh Bảo",sources:["https://zh.daoinfo.org/index.php?title=%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E7%8E%89%E7%B1%99%E7%B0%A1%E6%96%87%E4%B8%89%E5%85%83%E5%A8%81%E5%84%80%E8%87%AA%E7%84%B6%E7%9C%9F%E7%B6%93&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&chapter=173204","http://www.homeinmists.com/TaoistCanon.html"],textual_certainty:"high",notes:"batch19 · Grok-4.5 web-search"},{dz:"DZ554",name_han:"太上灵宝净明法序",name_vi:"Thái Thượng Linh Bảo Tịnh Minh pháp tự",bu:"洞玄",author:"佚名（宋元净明道）",era:"南宋—元",topic:"philosophy",essence:"Tựa ngắn 洞玄部方法类 cho pháp Tịnh Minh: xưng pháp do Thượng Đế nói cho Thái Dương chân quân Hiếu Đạo Minh Vương, Hứa Chân Quân được truyền, soạn “đạo kinh 35 thiên” — tức 《太上灵宝净明洞神上品经》. Vài trăm chữ tóm nguồn gốc, tông chỉ trung hiếu—tịnh minh, tư liệu then chốt nghiên cứu Tịnh Minh đạo.",key_text:"null",use:"Dẫn nhập giáo pháp Tịnh Minh; đối chiếu với 35 thiên thượng phẩm kinh",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E9%9D%88%E5%AF%B6%E6%B7%A8%E6%98%8E%E6%B3%95%E5%BA%8F&variant=zh-hans","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E9%9D%88%E5%AF%B6%E6%B7%A8%E6%98%8E%E6%B4%9E%E7%A5%9E%E4%B8%8A%E5%93%81%E7%B6%93&variant=zh-hans","https://baike.baidu.com/item/%E5%A4%AA%E4%B8%8A%E7%81%B5%E5%AE%9D%E5%87%80%E6%98%8E%E6%B4%9E%E7%A5%9E%E4%B8%8A%E5%93%81%E7%BB%8F/6162958"],textual_certainty:"high",notes:"batch19 · Grok-4.5 web-search"},{dz:"DZ711",name_han:"道德真经玄德纂疏",name_vi:"Đạo Đức Chân Kinh Huyền Đức Toản Sớ",bu:"洞神",author:"强思齐",era:"前蜀 / 唐末五代",topic:"classic",essence:"Bộ chú sớ Đạo Đức Kinh 20 quyển do đạo sĩ tiền Thục Cường Tư Tề (hiệu Huyền Đức đại sư) biên soạn, thu thập chú của Đường Huyền Tông, Hà Thượng Công, Nghiêm Tuân, Lý Vinh và sớ của Thành Huyền Anh. Mỗi chương có đề giải về thứ tự và đại ý; là nguồn quan trọng để phục nguyên sớ Thành Huyền Anh và chú Lý Vinh.",key_text:"唐玄宗御注并疏河上公严君平李荣注西华法师成玄英疏濛阳强思齐纂",use:"Đối chiếu lão học Đường–Ngũ đại, phục nguyên chú sớ trùng huyền, tra cứu Đạo Đức Kinh trong Đạo tạng.",sources:["https://zh.daoinfo.org/index.php?title=%E9%81%93%E5%BE%B7%E7%9C%9F%E7%B6%93%E7%8E%84%E5%BE%B7%E7%BA%82%E7%96%8F%EF%BC%88%E5%BC%B7%E6%80%9D%E9%BD%8A%EF%BC%89&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&res=269169","https://www.mdpi.com/2077-1444/10/1/66"],textual_certainty:"high",notes:"batch20 · Grok-4.5 web-search"},{dz:"null",name_han:"老子道德经序诀",name_vi:"Lão Tử Đạo Đức Kinh Tự Quyết",bu:"太玄",author:"题太极左仙公葛玄（伪托/早期灵宝传承层）",era:"南北朝（梁前已著录）",topic:"classic",essence:"Còn gọi Lão Tử tự quyết hay Ngũ thiên văn tự; năm đoạn thần hóa Lão Tử–Doãn Hỷ, Hà Thượng Công–Hán Văn Đế, truyền thừa Linh Bảo (Từ Lai Lặc–Cát Huyền–Trịnh Tư Viễn) và Thái Cực ẩn quyết tụng kinh. Chính thống Đạo tạng không thu sách độc lập; văn bản phục nguyên chủ yếu từ bản chép Đôn Hoàng.",key_text:"老子之号因玄而出，在天地之先，无衰老之期，故曰老子",use:"Nghiên cứu thần hóa Đạo Đức Kinh thành kinh Đạo giáo sớm; đối chiếu truyền thừa Linh Bảo và nghi tụng Ngũ thiên văn.",sources:["https://zh.daoinfo.org/index.php?title=%E8%80%81%E5%AD%90%E9%81%93%E5%BE%B7%E7%B6%93%E5%BA%8F%E8%A8%A3%EF%BC%88%E8%91%9B%E7%8E%84%EF%BC%89&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E8%80%81%E5%AD%90%E9%81%93%E5%BE%B7%E7%B6%93_(%E5%9B%9B%E9%83%A8%E5%8F%A2%E5%88%8A%E6%9C%AC)/%E5%BA%8F","https://baike.baidu.com/item/%E8%80%81%E5%AD%90%E9%81%93%E5%BE%B7%E7%BB%8F%E5%BA%8F%E8%AF%80/20113050"],textual_certainty:"high",notes:"batch20 · Grok-4.5 web-search"},{dz:"DZ548",name_han:"太极祭炼内法",name_vi:"Thái Cực Tế Luyện Nội Pháp",bu:"洞玄",author:"郑思肖（所南；三外老夫）",era:"宋末元初（约1270；元至正重刻）",topic:"ritual",essence:"Ba quyển tế luyện Linh Bảo siêu độ vong hồn, quy cho truyền Cát Huyền, do Trịnh Tư Tiêu biên tập. Thượng quyển ghi nghi thức–bùa chú–bảo lục; trung–hạ là nghị lược nhấn mạnh nội luyện tâm thành quan trọng hơn hình thức khoa nghi, hòa Nho–Thích–Đạo.",key_text:"太极祭炼内法者，葛仙公祭鬼之法也",use:"Nghi tế luyện–thí thực–độ vong; nghiên cứu nội đan thâm nhập khoa nghi công cộng.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E6%A5%B5%E7%A5%AD%E9%8D%8A%E5%85%A7%E6%B3%95&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E6%A5%B5%E7%A5%AD%E9%8D%8A%E5%85%A7%E6%B3%95","https://baike.baidu.com/item/%E5%A4%AA%E6%9E%81%E7%A5%AD%E7%82%BC%E5%86%85%E6%B3%95/23150295"],textual_certainty:"high",notes:"batch20 · Grok-4.5 web-search"},{dz:"DZ907",name_han:"金石簿",name_vi:"Kim Thạch Bộ",bu:"太清",author:"佚名",era:"唐代（文内提麟德甲子岁，约664）",topic:"外丹",essence:"Tên đầy đủ Kim thạch bộ ngũ cửu số quyết, một quyển trong Động thần bộ chúng thuật. Liệt kê khoảng 45 loại kim thạch khoáng vật (chu sa, hùng hoàng, tiêu thạch…): xuất xứ, hình chất, phẩm cấp thượng–trung–hạ để luyện đan. “Ngũ cửu” = 45 loại.",key_text:"夫学道欲求丹宝先须识金石定其形质知美恶",use:"Cẩm nang nhận thuốc khoáng ngoại đan; lịch sử dược vật học–luyện kim Đạo giáo.",sources:["https://zh.daoinfo.org/index.php?title=%E9%87%91%E7%9F%B3%E7%B0%BF%E4%BA%94%E4%B9%9D%E6%95%B8%E8%A8%A3&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&chapter=999557&remap=gb","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch20 · Grok-4.5 web-search"},{dz:"null",name_han:"太清五髓经",name_vi:"Thái Thanh Ngũ Tủy Kinh",bu:"太清",author:"不明（未见可靠著录）",era:"不明",topic:"养生",essence:"Không xác minh được kinh độc lập này trong Chính thống Đạo tạng hay các mục lục chuẩn (Schipper–Verellen / CRTA). Có thể là tên nhầm, thất truyền, hoặc biến thể hiếm của nhóm Thái Thanh dưỡng sinh; không nên gán nội dung cụ thể khi chưa có bản.",key_text:"null",use:"Chỉ dùng khi có bản cổ/đối chiếu mục lục khuyết kinh; tránh trích dẫn như kinh Đạo tạng chuẩn.",sources:["https://ctext.org/wiki.pl?if=gb&chapter=898600","http://www.homeinmists.com/Tao_Sutra_Contents.htm","https://zh.daoinfo.org/wiki/%E5%A4%AA%E6%B8%85%E5%85%83%E9%81%93%E7%9C%9F%E7%B6%93"],textual_certainty:"low",notes:"batch20 · Grok-4.5 web-search"},{dz:"null",name_han:"太上正一盟威朝仪",name_vi:"Thái Thượng Chính Nhất Minh Oai Triều Nghi",bu:"正一",author:"佚名（天师道仪轨层）",era:"南北朝–隋唐（仪名见于科戒目录）",topic:"ritual",essence:"Không thấy sách độc lập đúng tên này trong Chính thống Đạo tạng. “Chính nhất triều nghi / Chính nhất minh oai” xuất hiện trong hệ thụ lục và Tam động phụng đạo khoa giới doanh thủy như nghi triều bái–chương tấu sau khi thụ lục minh oai. Gần với nhóm khoa nghi Chính nhất (chương, tấu, triều) hơn là kinh độc lập.",key_text:"null",use:"Tham chiếu khung thụ lục–triều nghi Chính nhất; đối chiếu S.203 và khoa giới Đôn Hoàng / Đạo tạng.",sources:["https://zh.wikisource.org/zh-hans/%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E4%B8%89%E6%B4%9E%E5%A5%89%E9%81%93%E7%A7%91%E6%88%92%E7%87%9F%E5%A7%8B","https://baike.baidu.com/item/%E4%B8%89%E6%B4%9E%E5%A5%89%E9%81%93%E7%A7%91%E6%88%92%E8%90%A5%E5%A7%8B/2657234","https://www11.ihp.sinica.edu.tw/storage/w2_file/2995SgIKCqA.pdf"],textual_certainty:"partial",notes:"batch20 · Grok-4.5 web-search"},{dz:"DZ1415",name_han:"太上说豁落七元经",name_vi:"Thái Thượng Thuyết Hoát Lạc Thất Nguyên Kinh",bu:"正一",author:"佚名",era:"约唐–宋（北帝/七元系统）",topic:"ritual",essence:"Trong Đạo tạng thường đề Bắc Đế thuyết hoạt lạc thất nguyên kinh (chính bộ). Mượn lời Bắc Đế/thất chân nói về bùa hoạt lạc thất nguyên, đàn Bắc Đẩu, nhiên đăng, chương biểu để tiêu ma, trấn tà, diên sinh. Gắn Bắc Đế–Phong Đô–thất nguyên tinh thần.",key_text:"三界之上北帝大魔王，下治在北海天地北方罗酆绝顶之山",use:"Khoa nghi Bắc Đế / thất nguyên; trấn tà–diên mệnh–hộ quốc.",sources:["https://zh.wikisource.org/zh-hans/%E5%8C%97%E5%B8%9D%E8%AA%AA%E8%B1%81%E8%90%BD%E4%B8%83%E5%85%83%E7%B6%93","https://www.shidianguji.com/book/DZ1415","https://ctext.org/library.pl?if=gb&res=85088&by_collection=132&remap=gb"],textual_certainty:"high",notes:"batch20 · Grok-4.5 web-search"},{dz:"DZ1454",name_han:"灵宝施食科仪",name_vi:"Linh Bảo Thí Thực Khoa Nghi",bu:"续道藏",author:"佚名",era:"约宋元（续道藏所收）",topic:"ritual",essence:"Bản Đạo tạng gần nhất là Linh Bảo thí thực pháp (Vạn Lịch tục Đạo tạng): khoa thí thực–hộc thực cứu độ u hồn. Thứ tự gồm tịnh tam nghiệp, thổ địa, cứu khổ, cam lộ khai yết hầu, hóa thực, ngũ trù, tam quy–cửu giới, tán thực. Tên “khoa nghi” thường chỉ truyền bản hành dụng; bản tạng là “pháp”.",key_text:"null",use:"Nghi thí thực / phóng diệm khẩu Đạo giáo; so sánh với tế luyện–hộc thực các phái.",sources:["https://zh.daoinfo.org/index.php?title=%E9%9D%88%E5%AF%B6%E6%96%BD%E9%A3%9F%E6%B3%95&variant=zh-hans","https://zh.wikisource.org/zh-hant/%E9%9D%88%E5%AF%B6%E6%96%BD%E9%A3%9F%E6%B3%95","https://www.jstor.org/stable/26768560"],textual_certainty:"partial",notes:"batch20 · Grok-4.5 web-search"},{dz:"DZ298",name_han:"历世真仙体道通鉴后编",name_vi:"Lịch Thế Chân Tiên Thể Đạo Thông Giám Hậu Biên",bu:"洞真",author:"赵道一",era:"元代",topic:"仙传",essence:"Tên mục lục chuẩn không có “hậu biên”; bộ Tiên giám gồm chính biên (DZ296), tục biên (DZ297) và hậu tập (DZ298). “Hậu biên” thường chỉ phần sau—hậu tập 6 quyển ghi khoảng 120 nữ tiên (Vô Thượng Nguyên Quân, Tây Vương Mẫu…), bổ sung phổ lục tiên truyện.",key_text:"null",use:"Tra cứu nữ tiên–tiên truyện; sử liệu Đạo giáo Nguyên–Minh.",sources:["https://zh.daoinfo.org/index.php?title=%E6%AD%B7%E4%B8%96%E7%9C%9F%E4%BB%99%E9%AB%94%E9%81%93%E9%80%9A%E9%91%92&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&res=148681&remap=gb","https://zh.wikipedia.org/wiki/%E5%8E%86%E4%B8%96%E7%9C%9F%E4%BB%99%E4%BD%93%E9%81%93%E9%80%9A%E9%89%B4"],textual_certainty:"partial",notes:"batch20 · Grok-4.5 web-search"},{dz:"null",name_han:"太清阴阳五行经",name_vi:"Thái Thanh Âm Dương Ngũ Hành Kinh",bu:"太清",author:"不明",era:"不明",topic:"philosophy",essence:"Không tìm thấy kinh đúng tên này trong Chính thống Đạo tạng hay chỉ mục Schipper–Verellen/CRTA đáng tin. Có thể thất truyền, tên nhầm, hoặc trích đoạn trong nhóm Thái Thanh / ngũ hành–âm dương rải rác; không đủ bằng chứng để gán DZ hay nội dung.",key_text:"null",use:"Chờ đối chiếu bản cổ hoặc mục lục khuyết kinh; không dùng như kinh chuẩn.",sources:["http://www.homeinmists.com/Tao_Sutra_Contents.htm","https://ctext.org/wiki.pl?if=gb&chapter=170126","https://homeinmists.ilotus.org/docs/cnTaoSutra_contents.htm"],textual_certainty:"low",notes:"batch20 · Grok-4.5 web-search"},{dz:"DZ588",name_han:"黄帝太一八门逆顺生死诀",name_vi:"Hoàng Đế Thái Nhất Bát Môn Nghịch Thuận Sinh Tử Quyết",bu:"洞玄",author:"佚名",era:"唐代（文内贞观三年李靖传说）",topic:"ritual",essence:"Một quyển Động huyền bộ chúng thuật: thuật Thái Ất bát môn, cô hư, ẩn hình, trạch thời, phục ma, trị bệnh. Phần trước tạp thuật–đồ–chú; phần sau Thái âm huyền nữ kinh (lục đinh ngọc nữ). Thuộc phương thuật–bát môn, không phải nội đan thuần.",key_text:"昔贞观三年八月，李靖将兵四十余万与突厥战，夜垒三更，九天玄女赐孤虚法与李靖",use:"Thái Ất bát môn / cô hư / ẩn độn; so sánh với Hoàng đế Thái nhất bát môn nhập thức quyết (DZ586–587).",sources:["https://zh.daoinfo.org/index.php?title=%E9%BB%83%E5%B8%9D%E5%A4%AA%E4%B8%80%E5%85%AB%E9%96%80%E9%80%86%E9%A0%86%E7%94%9F%E6%AD%BB%E8%A8%A3&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&chapter=2706507&remap=gb","https://www.persee.fr/doc/asie_0766-1177_1989_num_5_1_942"],textual_certainty:"high",notes:"batch20 · Grok-4.5 web-search"},{dz:"DZ425",name_han:"上清太极隐注玉经宝诀",name_vi:"Thượng Thanh Thái Cực Ẩn Chú Ngọc Kinh Bảo Quyết",bu:"洞玄",author:"佚名",era:"东晋末–南朝初（古灵宝经；陆修静已著录）",topic:"classic",essence:"Cổ Linh Bảo kinh một quyển (tuy đề Thượng Thanh): ẩn chú nghi thức thụ kinh, khai kinh, độc kinh cho Đạo Đức, Đại động, Linh Bảo, Tam Hoàng… Gồm khấu xỉ, yết dịch, tồn thần, chúc ngữ; nhấn mạnh sư thụ và tụng Ngũ thiên văn vạn biến.",key_text:"夫太上玄微，三洞初元。至赜之辞，幽而难闻",use:"Nghi truyền kinh–độc kinh Tam động; lịch sử cổ Linh Bảo và ý thức Tam động.",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%8A%E6%B8%85%E5%A4%AA%E6%A5%B5%E9%9A%B1%E6%B3%A8%E7%8E%89%E7%B6%93%E5%AF%B6%E8%A8%A3&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E4%B8%8A%E6%B8%85%E5%A4%AA%E6%A5%B5%E9%9A%B1%E6%B3%A8%E7%8E%89%E7%B6%93%E5%AF%B6%E8%A8%A3","https://baike.baidu.com/item/%E4%B8%8A%E6%B8%85%E5%A4%AA%E6%9E%81%E9%9A%90%E6%B3%A8%E7%8E%89%E7%BB%8F%E5%AE%9D%E8%AF%80/20113224"],textual_certainty:"high",notes:"batch20 · Grok-4.5 web-search"},{dz:"null",name_han:"太上灵宝胞胎经",name_vi:"Thái Thượng Linh Bảo Bào Thai Kinh",bu:"洞玄",author:"不明",era:"不明（古灵宝“受生/胞胎”主题相关）",topic:"classic",essence:"Không xác minh kinh đúng tên trong Chính thống Đạo tạng. Chủ đề bào thai–thụ sinh xuất hiện rải trong cổ Linh Bảo (như Cửu thiên sinh thần chương, bản hành túc duyên…), nhưng không đủ để đồng nhất với một DZ số.",key_text:"null",use:"Chỉ tham chiếu nhóm Linh Bảo thụ sinh–sinh thần; không trích như kinh độc lập đã định.",sources:["https://zh.daoinfo.org/index.php?title=%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E8%87%AA%E7%84%B6%E4%B9%9D%E5%A4%A9%E7%94%9F%E7%A5%9E%E7%AB%A0%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E6%9C%AC%E8%A1%8C%E5%AE%BF%E7%B7%A3%E7%B6%93","https://zh.wikipedia.org/wiki/%E9%9D%88%E5%AF%B6%E7%B6%93"],textual_certainty:"low",notes:"batch20 · Grok-4.5 web-search"},{dz:"null",name_han:"太上说消魔经",name_vi:"Thái Thượng Thuyết Tiêu Ma Kinh",bu:"洞玄",author:"不明（多名同题/近题）",era:"南北朝–宋（视具体文本）",topic:"classic",essence:"Không có một kinh duy nhất đúng tên ngắn này. Gần nhất: Động chân Thái thượng thuyết trí tuệ tiêu ma chân kinh (DZ1333, thượng thanh tiêu ma); Thái thượng thuyết tử vi thần binh hộ quốc tiêu ma kinh; hoặc phẩm Tiêu ma trong Tam thập lục bộ tôn kinh. Cần chỉ rõ bản trước khi gán DZ.",key_text:"null",use:"Đối chiếu tiêu ma–trừ tà theo từng bản cụ thể; tránh gộp nhiều kinh thành một.",sources:["https://zh.daoinfo.org/index.php?title=%E6%B4%9E%E7%9C%9F%E5%A4%AA%E4%B8%8A%E8%AA%AA%E6%99%BA%E6%85%A7%E6%B6%88%E9%AD%94%E7%9C%9F%E7%B6%93&variant=zh-hant","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E8%AA%AA%E7%B4%AB%E5%BE%AE%E7%A5%9E%E5%85%B5%E8%AD%B7%E5%9C%8B%E6%B6%88%E9%AD%94%E7%B6%93&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&chapter=412046&remap=gb"],textual_certainty:"low",notes:"batch20 · Grok-4.5 web-search"},{dz:"null",name_han:"太上说西王母益算经",name_vi:"Thái Thượng Thuyết Tây Vương Mẫu Ích Toán Kinh",bu:"正一",author:"不明",era:"不明",topic:"classic",essence:"Không xác minh kinh đúng tên trong Chính thống Đạo tạng. Chủ đề Tây Vương Mẫu–ích toán/diên mệnh tồn tại trong nhiều kinh–khoa (Bắc Đẩu, ích toán, nữ tiên truyện), nhưng không có bằng chứng thư mục cho đúng đề này như một DZ.",key_text:"null",use:"Chỉ dùng khi có bản cổ độc lập; tạm tham chiếu nhóm ích toán–diên sinh và truyện Tây Vương Mẫu.",sources:["https://ctext.org/wiki.pl?if=gb&res=148681&remap=gb","https://zh.daoinfo.org/index.php?title=%E6%AD%B7%E4%B8%96%E7%9C%9F%E4%BB%99%E9%AB%94%E9%81%93%E9%80%9A%E9%91%92&variant=zh-hans","http://www.homeinmists.com/Tao_Sutra_Contents.htm"],textual_certainty:"low",notes:"batch20 · Grok-4.5 web-search"},{dz:"DZ251",name_han:"谷神篇",name_vi:"Cốc Thần Thiên",bu:"洞真",author:"林辕（玄巢子、五福玄巢子）",era:"元（大德八年序，1304）",topic:"cultivation",essence:"Tác phẩm nội đan thời Nguyên của Lâm Viện, hai quyển, thuộc Động Chân bộ phương pháp loại. Lấy nguyên khí làm gốc mệnh, bàn đại dược hoàn đan, hỏa hầu và dưỡng khí, nhấn mạnh bảo mệnh hiện thế, bạc danh lợi. Phê Phật chỉ tu tính, chủ trương luyện khí–tu đan để trường sinh.",key_text:"了身第一艺",use:"Nghiên cứu nội đan Nguyên; tham chiếu dưỡng khí–hoàn đan và phê phán tính mệnh lệch.",sources:["https://zh.daoinfo.org/index.php?title=%E8%B0%B7%E7%A5%9E%E7%AF%87&variant=zh-hans","https://baike.baidu.com/item/%E8%B0%B7%E7%A5%9E%E7%AF%87/9725753","https://ctext.org/library.pl?if=en&res=83904&remap=gb"],textual_certainty:"high",notes:"batch21 · Grok-4.5 web-search"},{dz:"DZ232",name_han:"还丹众仙论",name_vi:"Hoàn Đan Chúng Tiên Luận",bu:"洞真",author:"杨在（抱腹山人）",era:"北宋皇祐四年（1052）",topic:"外丹",essence:"Dương Tại biên tập khoảng 1052, một quyển, Động Chân bộ phương pháp loại. Tập hơn ba mươi nhà luyện đan từ Nguyên Thủy, Lão Quân đến Âm Chân Quân, Nguyên Dương Tử, Lữ tiên sinh, Hải Thiềm Tử. Chủ yếu ngoại đan: chân chì–chân thủy ngân, tạo lò, hỏa hầu, xuất hỏa độc; bảo tồn nhiều đan quyết đã thất truyền. Dù user gán nội đan, nguồn catalog xếp ngoại đan là chính.",key_text:"粤还丹者，华池为初也。",use:"Nghiên cứu ngoại đan Tống; phục nguyên đan quyết cổ và pháp lô hỏa.",sources:["https://zh.daoinfo.org/wiki/%E9%82%84%E4%B8%B9%E7%9C%BE%E4%BB%99%E8%AB%96","https://zh.wikisource.org/zh-hans/%E9%82%84%E4%B8%B9%E7%9C%BE%E4%BB%99%E8%AB%96","https://baike.baidu.com/item/%E8%BF%98%E4%B8%B9%E4%BC%97%E4%BB%99%E8%AE%BA/23146231","https://ctext.org/library.pl?if=gb&res=83885&by_collection=132&remap=gb"],textual_certainty:"high",notes:"batch21 · Grok-4.5 web-search"},{dz:"DZ1055",name_han:"玄宗直指万法同归",name_vi:"Huyền Tông Trực Chỉ Vạn Pháp Đồng Quy",bu:"太玄",author:"牧常晁撰，黄本仁编",era:"元（全真）",topic:"cultivation",essence:"Bảy quyển Toàn Chân của Mục Thường Sào, Hoàng Bản Nhân biên, Thái Huyền bộ. Gồm luận thuyết, hoặc vấn, thi kệ, khuyến giới; hợp tam giáo, luận vô cực–thái cực, tính mệnh song tu. Chủ trương vạn pháp đồng quy, giới–định–tuệ gắn tinh–khí–thần; đốn pháp thanh tĩnh, lục căn thanh tĩnh tức chân đan.",key_text:"六根清静，方寸澄澈，便是真丹。",use:"Học Toàn Chân triết–công; tham chiếu tam giáo hợp nhất và tính mệnh song tu.",sources:["https://zh.daoinfo.org/index.php?title=%E7%8E%84%E5%AE%97%E7%9B%B4%E6%8C%87%E8%90%AC%E6%B3%95%E5%90%8C%E6%AD%B8&variant=zh-hans","https://zh.wikisource.org/wiki/%E7%8E%84%E5%AE%97%E7%9B%B4%E6%8C%87%E8%90%AC%E6%B3%95%E5%90%8C%E6%AD%B8","https://www.shidianguji.com/zh/book/DZ1066","https://ctext.org/wiki.pl?if=gb&res=912778&remap=gb"],textual_certainty:"high",notes:"batch21 · Grok-4.5 web-search"},{dz:"null",name_han:"老子节解",name_vi:"Lão Tử Tiết Giải",bu:"太玄",author:"传葛玄（系统待考；今多严灵峰辑本）",era:"魏晋至唐以前（著录有争议）",topic:"philosophy",essence:"Chú giải Lão Tử theo lối tiết giải ngắn, truyền hệ Lão học–dưỡng sinh, nhấn mạnh thân quốc nhất thể và thần tiên. Tống sử có mục 葛玄《老子道德经节解》 hai quyển; không thấy bản hoàn chỉnh trong Chính thống Đạo tạng, chủ yếu còn qua trích dẫn và bản chỉnh lý hiện đại. Không gán DZ khi chưa đối khớp catalog Schipper–Verellen.",key_text:"null",use:"Nghiên cứu Lão học sớm / chú sớ Đạo Đức kinh (bản tái cấu).",sources:["https://baike.baidu.com/item/%E8%80%81%E5%AD%90%E8%8A%82%E8%A7%A3/19890323","https://ctext.org/datawiki.pl?if=gb&res=784339","https://homeinmists.ilotus.org/%E4%B8%B9%E7%B6%93%E9%81%93%E6%9B%B8/%E8%80%81%E5%AD%90-%E9%81%93%E5%BE%B7%E7%B6%93/%E8%80%81%E5%AD%90%E9%9B%86%E6%88%90%E7%9B%AE%E9%8C%84/"],textual_certainty:"low",notes:"batch21 · Grok-4.5 web-search"},{dz:"DZ1032",name_han:"灵棋经",name_vi:"Linh Kỳ Kinh",bu:"太玄",author:"东晋襄城寺僧法味（俞嘉锡考）；题颜幼明注、何承天续注",era:"东晋–南朝（道藏本定型至南宋）",topic:"ritual",essence:"Tức《灵棋本章正经》, hai quyển, Thái Huyền bộ. Bói bằng mười hai quân kỳ thượng–trung–hạ, khoảng 124 quẻ, từ–tượng mô phỏng Chu Dịch. Dùng để quyết nghi nhân sự, không phải nội đan. Có tựa và chú của người Nam triều cùng tự đời Đường–Tống về nghi thức gieo kỳ.",key_text:"null",use:"Chiêm bốc linh kỳ; nghiên cứu phương thuật và nghi quyết nghi.",sources:["https://zh.daoinfo.org/index.php?title=%E9%9D%88%E6%A3%8B%E6%9C%AC%E7%AB%A0%E6%AD%A3%E7%B6%93&variant=zh-hans","https://www.shidianguji.com/book/DZ1041","https://ctext.org/wiki.pl?if=gb&res=491768"],textual_certainty:"high",notes:"batch21 · Grok-4.5 web-search"},{dz:"DZ177",name_han:"三洞众戒文",name_vi:"Tam Động Chúng Giới Văn",bu:"洞真",author:"张万福",era:"唐",topic:"戒律",essence:"Trương Vạn Phúc biên soạn, nguyên hai quyển (Đạo tạng hợp một), giới luật lớp. Trích giới văn tam động: tam quy, lục tình, tam giới, ngũ giới, bát bại, thập tam cấm, thất bách nhị thập môn yếu giới… Nhấn mạnh học đạo phải trì trai giới, lấy thủ tâm chế lục tình làm gốc. Tài liệu chuẩn cho nghiên cứu giới đàn và thứ bậc giới điều.",key_text:"学道求真，莫不先持斋戒",use:"Thụ giới / nghiên cứu giới luật và nghi trì giới đạo sĩ.",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%89%E6%B4%9E%E7%9C%BE%E6%88%92%E6%96%87&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&res=493776&remap=gb","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch21 · Grok-4.5 web-search"},{dz:"null",name_han:"太清玉炉经",name_vi:"Thái Thanh Ngọc Lô Kinh",bu:"太清",author:"佚名（未核）",era:"未核（外丹炉火传统语境）",topic:"外丹",essence:"Theo nhãn đề thuộc Thái Thanh / lô hỏa ngoại đan (ngọc lô–hỏa hầu). Tra cứu ctext, daoinfo, wikisource, baike, shidianguji không xác nhận được đúng một bản có tiêu đề《太清玉炉经》trong Chính thống Đạo tạng; có thể nhầm với các kinh Thái Thanh luyện đan khác hoặc bản ngoài tạng. Không gán DZ khi chưa khớp catalog.",key_text:"null",use:"Chỉ tham khảo bối cảnh ngoại đan Thái Thanh khi có bản xác minh; tránh gán nhầm.",sources:["https://ctext.org","https://zh.daoinfo.org","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"low",notes:"batch21 · Grok-4.5 web-search"},{dz:"DZ404",name_han:"上清丹元玉经",name_vi:"Thượng Thanh Đan Nguyên Ngọc Kinh",bu:"洞玄",author:"佚名（上清系统；假托西城王君传大茅君）",era:"南北朝或隋唐",topic:"cultivation",essence:"Khớp catalog gần nhất là《上清丹元玉真帝皇飞仙上经》(Schipper/Komjathy DZ404; 提要体系同序). Một quyển, Động Huyền bộ ngọc quyết loại (không phải Động Chân như nhãn user). Bàn đạo Đan Nguyên Ngọc Chân Đế Hoàng, tồn tư Quỳnh Hoa Ngọc Phi, phi tiên lên cung trăng, thực khí ẩm châu. Thuộc Thượng Thanh tồn tư–phi thăng, không phải hoàn đan dược công.",key_text:"上清丹元玉真帝皇之道",use:"Thượng Thanh tồn tư / nghi phi tiên; nghiên cứu nội cảnh đan nguyên.",sources:["https://zh.wikisource.org/zh-hans/%E4%B8%8A%E6%B8%85%E4%B8%B9%E5%85%83%E7%8E%89%E7%9C%9F%E5%B8%9D%E7%9A%87%E9%A3%9B%E4%BB%99%E4%B8%8A%E7%B6%93","https://www.shidianguji.com/book/DZ0404","https://ctext.org/library.pl?if=en&res=84067&remap=gb","https://www.jstor.org/stable/26768560"],textual_certainty:"partial",notes:"batch21 · Grok-4.5 web-search"},{dz:"DZ316",name_han:"太上说洪恩灵济真君妙经",name_vi:"Thái Thượng Thuyết Hồng Ân Linh Tế Chân Quân Diệu Kinh",bu:"洞玄",author:"佚名（卷前明成祖永乐十八年御序）",era:"明初（约永乐前后）",topic:"ritual",essence:"Tên đầy đủ trong tạng là《灵宝天尊说洪恩灵济真君妙经》, một quyển, Động Huyền bộ bản văn loại. Tín ngưỡng nhị Từ (Từ Tri Chứng, Từ Tri Ngạc) được phong Hồng Ân Linh Tế Chân Quân; Thành Tổ tự xưng được phù hộ, in kinh lưu hành. Khuyên trung hiếu nhân nghĩa, lễ niệm chân quân để tăng phúc tiêu tai, siêu độ tổ tiên. Phản ánh đạo giáo hóa tín ngưỡng dân gian Phúc Châu thời Minh.",key_text:"内可以增福延年，外可以消灾度厄",use:"Cúng Linh Tế Chân Quân; nghi cầu an–báo ân; nghiên cứu tín ngưỡng Minh triều.",sources:["https://zh.daoinfo.org/index.php?title=%E9%9D%88%E5%AF%B6%E5%A4%A9%E5%B0%8A%E8%AA%AA%E6%B4%AA%E6%81%A9%E9%9D%88%E6%BF%9F%E7%9C%9F%E5%90%9B%E5%A6%99%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E9%9D%88%E5%AF%B6%E5%A4%A9%E5%B0%8A%E8%AA%AA%E6%B4%AA%E6%81%A9%E9%9D%88%E6%BF%9F%E7%9C%9F%E5%90%9B%E5%A6%99%E7%B6%93","https://www.shidianguji.com/book/DZ0317","https://baike.baidu.com/item/%E6%B4%AA%E6%81%A9%E7%81%B5%E6%B5%8E%E7%9C%9F%E5%90%9B/4478496"],textual_certainty:"high",notes:"batch21 · Grok-4.5 web-search"},{dz:"DZ043",name_han:"太上说十一曜大消灾神咒经",name_vi:"Thái Thượng Thuyết Thập Nhất Diệu Đại Tiêu Tai Thần Chú Kinh",bu:"洞真",author:"佚名",era:"唐宋间（约）",topic:"mantra",essence:"Tên catalog đầy đủ là《元始天尊说十一曜大消灾神咒经》, một quyển, Động Chân bộ bản văn loại. Nguyên Thủy nói với Thanh La chân nhân: tai họa do thập nhất diệu (nhật nguyệt ngũ tinh, La Hầu, Kế Đô, Tử Khí, Nguyệt Bột…). Lập đàn, tạc tượng, trì chú bảy–hai mươi mốt ngày để thượng tiêu thiên tai, hạ trừ độc hại. Gồm cửu tinh đô chú, ngũ tinh chú và chú từng diệu.",key_text:"即得上消天灾，保镇帝土，下禳毒害，以度兆民",use:"Nghi lễ tiêu tai tinh diệu; tụng chú bảo an xã tắc–dân sinh.",sources:["https://zh.daoinfo.org/index.php?title=%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E5%8D%81%E4%B8%80%E6%9B%9C%E5%A4%A7%E6%B6%88%E7%81%BD%E7%A5%9E%E5%92%92%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/wiki/%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E5%8D%81%E4%B8%80%E6%9B%9C%E5%A4%A7%E6%B6%88%E7%81%BD%E7%A5%9E%E5%91%AA%E7%B6%93","https://ctext.org/library.pl?if=gb&res=83696"],textual_certainty:"high",notes:"batch21 · Grok-4.5 web-search"},{dz:"DZ1429",name_han:"太上说三元经",name_vi:"Thái Thượng Thuyết Tam Nguyên Kinh",bu:"续道藏",author:"佚名",era:"明（流行本）；另有古《太上三元经》仅见类书引文",topic:"classic",essence:"Tiêu đề user rút gọn; bản phổ biến nhất khớp hệ tam nguyên–tam quan là《太上三元赐福赦罪解厄消灾延生保命妙经》(Đạo tạng đề yếu 1429, Vạn Lịch tục tạng), tục gọi Tam Quan Kinh. Cầu thiên quan ban phúc, địa quan xá tội, thủy quan giải ách; tụng trước phải trai giới, tịnh khẩu thân tâm. Cổ《太上三元经》chỉ còn trích trong Thái Bình Ngự Lãm (dưỡng khí tồn thần, thổ nạp), không còn bản trọn trong Chính thống tạng.",key_text:"天官赐福、地官赦罪，水官解厄",use:"Trai sám tam nguyên / tụng Tam Quan Kinh; phân biệt bản Minh với cổ kinh đã thất.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E4%B8%89%E5%85%83%E8%B3%9C%E7%A6%8F%E8%B5%A6%E7%BD%AA%E8%A7%A3%E5%8E%84%E6%B6%88%E7%81%BE%E5%BB%B6%E7%94%9F%E4%BF%9D%E5%91%BD%E5%A6%99%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E4%B8%89%E5%85%83%E8%B3%9C%E7%A6%8F%E8%B5%A6%E7%BD%AA%E8%A7%A3%E5%8E%84%E6%B6%88%E7%81%BD%E5%BB%B6%E7%94%9F%E4%BF%9D%E5%91%BD%E5%A6%99%E7%B6%93","https://ctext.org/taiping-yulan/668","https://www.shidianguji.com/zh/book/DZ1442"],textual_certainty:"partial",notes:"batch21 · Grok-4.5 web-search"},{dz:"DZ713",name_han:"道德真经取善集",name_vi:"Đạo Đức Chân Kinh Thủ Thiện Tập",bu:"洞神",author:"李霖",era:"金（原六卷，道藏析十二卷）",topic:"philosophy",essence:"Lý Lâm biên soạn, Động Thần bộ ngọc quyết loại (không thuộc Thái Huyền). Lối “thủ thiện”: chọn lời hay từ hàng chục nhà chú (Nghiêm Tuân, Hà Thượng Công, Vương Bật, Thành Huyền Anh, Đào Hoằng Cảnh…). Giữ nhiều chú đã thất, trọng nội thánh ngoại vương và đạo đức nhất thể. Công cụ so sánh chú sớ Đạo Đức kinh trung cổ.",key_text:"null",use:"Nghiên cứu Lão học / phục nguyên chú sớ thất truyền; đối chiếu kim–tống chú gia.",sources:["https://zh.daoinfo.org/index.php?title=%E9%81%93%E5%BE%B7%E7%9C%9F%E7%B6%93%E5%8F%96%E5%96%84%E9%9B%86%EF%BC%88%E6%9D%8E%E9%9C%96%EF%BC%89&variant=zh-hans","https://zh.wikisource.org/wiki/%E9%81%93%E5%BE%B7%E7%9C%9F%E7%B6%93%E5%8F%96%E5%96%84%E9%9B%86","https://www.shidianguji.com/book/DZ0718","https://ctext.org/wiki.pl?if=gb&res=724634"],textual_certainty:"high",notes:"batch21 · Grok-4.5 web-search"},{dz:"null",name_han:"太上老君说牛王妙经",name_vi:"Thái Thượng Lão Quân Thuyết Ngưu Vương Diệu Kinh",bu:"正一",author:"佚名（民间牛王信仰）",era:"宋元以后民间（善书系统）",topic:"ritual",essence:"Kinh dân gian xưng Lão Quân nói về Ngưu Vương (đôi khi kèm Mã Tổ) bảo hộ canh nông–gia súc. Hiện hành chủ yếu qua thiện thư / bản khắc địa phương; tra ctext–daoinfo–chính thống mục lục không xác nhận bản chính thức trong Chính thống Đạo tạng. Phản ánh đạo giáo hóa tín ngưỡng Ngưu Vương nông thôn, không nên gán DZ khi chưa có catalog.",key_text:"null",use:"Cúng Ngưu Vương / nghi nông–súc; nghiên cứu tín ngưỡng dân gian ngoài tạng.",sources:["https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F","https://ctext.org","https://www.taolibrary.com/video.aspx"],textual_certainty:"low",notes:"batch21 · Grok-4.5 web-search"},{dz:"DZ008",name_han:"太上三十六部尊经",name_vi:"Thái Thượng Tam Thập Lục Bộ Tôn Kinh",bu:"洞真",author:"佚名",era:"南北朝末（无上秘要已著录）",topic:"classic",essence:"Sáu quyển, Động Chân bộ bản văn loại, Đạo tạng đề yếu số 8. Gồm 36 thiên ngắn theo ba cảnh: ngọc thanh / thượng thanh / thái thanh mỗi cảnh 12 bộ. Dung hợp Phật–Đạo, bàn đạo tính, chân không, tu tâm hành thiện, trai tụng; hạ thấp thổ nạp–luyện đan. Ảnh hưởng lớn đến kết cấu “ba mươi sáu bộ tôn kinh” và giáo lý Tùy–Đường.",key_text:"null",use:"Nghiên cứu kết cấu tam động / giáo lý đạo tính; mục lục và nghi tụng kinh.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E4%B8%89%E5%8D%81%E5%85%AD%E9%83%A8%E5%B0%8A%E7%B6%93&variant=zh-hans","https://zh.daoinfo.org/index.php?title=%E4%B8%89%E5%8D%81%E5%85%AD%E9%83%A8%E5%B0%8A%E7%B6%93&variant=zh-hans","https://ctext.org"],textual_certainty:"high",notes:"batch21 · Grok-4.5 web-search"},{dz:"DZ1376",name_han:"上清九真中经（上清太上帝君九真中经）",name_vi:"Thượng Thanh Cửu Chân Trung Kinh",bu:"正一（内容属洞真/上清）",author:"佚名",era:"东晋–南朝",topic:"cultivation",essence:"Kinh Thượng Thanh sớm, còn gọi đủ là Thượng Thanh Thái Thượng Đế Quân Cửu Chân Trung Kinh. Cốt tủy là tồn tư Cửu Chân–Ngũ Thần trấn cửu cung–ngũ tạng, bát đạo bí ngôn và các pháp bôn nhật nguyệt (Uất Nghi–Kết Lân), kèm phương luyện đan–dược. Mục tiêu: hợp chân khí, trường sinh và phi thăng Thượng Thanh.",key_text:"子得鬱儀結璘，乃成上清之真，不修上道，不得見三元君。",use:"Tồn tư nội thần, tu nhật nguyệt, luyện đan dược theo khoa Thượng Thanh",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%8A%E6%B8%85%E5%A4%AA%E4%B8%8A%E5%B8%9D%E5%90%9B%E4%B9%9D%E7%9C%9F%E4%B8%AD%E7%B6%93&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&res=282624","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch22 · Grok-4.5 web-search (filtered: 9 unverifiable/dup dropped)"},{dz:"null",name_han:"太上灵宝十部经",name_vi:"Thái Thượng Linh Bảo Thập Bộ Kinh",bu:"洞玄（古灵宝经总称）",author:"null（概念群经，非单部）",era:"东晋–刘宋（古灵宝）",topic:"classic",essence:"Không phải một thiên đơn lập trong Chính Thống Đạo Tạng theo đúng tựa này. “Linh Bảo thập bộ diệu kinh” là tổng danh chỉ hệ cổ Linh Bảo (thập bộ / khoảng ba mươi sáu quyển) mà Nguyên Thủy Thiên Tôn–Thái Thượng Đạo Quân khai diễn để độ nhân. Nguồn catalog và nghiên cứu Linh Bảo đều nói về khối kinh, không gán một DZ số cho đúng tên Thái Thượng Linh Bảo Thập Bộ Kinh.",key_text:"今當為諸來生說十部妙經，以度天人。",use:"Khung giáo pháp–truyền thụ–khoa nghi cổ Linh Bảo (nhóm kinh, không phải đơn bản)",sources:["https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E8%AB%B8%E5%A4%A9%E9%9D%88%E6%9B%B8%E5%BA%A6%E5%91%BD%E5%A6%99%E7%B6%93","https://zh.daoinfo.org/index.php?title=%E7%9C%9F%E6%96%87&variant=zh-hant","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"partial",notes:"batch22 · Grok-4.5 web-search (filtered: 9 unverifiable/dup dropped)"},{dz:"DZ663",name_han:"玄天上帝报恩经（玄天上帝说报父母恩重经）",name_vi:"Huyền Thiên Thượng Đế Báo Ân Kinh",bu:"洞神",author:"佚名（附赵宜真跋）",era:"南宋–元明（道门定制已见真武报恩经）",topic:"经典",essence:"Tựa đầy đủ trong Tạng là Huyền Thiên Thượng Đế thuyết báo phụ mẫu ân trọng kinh. Mượn Huyền Thiên Thượng Đế (Chân Vũ) giảng nỗi khó sinh dưỡng, khuyên tu hành–trì thánh hiệu để báo ân cha mẹ hiện tiền và siêu độ cha mẹ quá vãng. Gắn tín ngưỡng Bắc đế với đạo hiếu.",key_text:"持念平等，用報始相。使我始相，大得快樂，無諸苦惱。",use:"Tụng kinh–lễ thánh hiệu báo ân cha mẹ; khoa hiếu đạo–Chân Vũ",sources:["https://zh.daoinfo.org/index.php?title=%E7%8E%84%E5%A4%A9%E4%B8%8A%E5%B8%9D%E8%AA%AA%E5%A0%B1%E7%88%B6%E6%AF%8D%E6%81%A9%E9%87%8D%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E7%8E%84%E5%A4%A9%E4%B8%8A%E5%B8%9D%E8%AA%AA%E5%A0%B1%E7%88%B6%E6%AF%8D%E6%81%A9%E9%87%8D%E7%B6%93","https://ctext.org/wiki.pl?if=gb&res=379111","https://baike.baidu.com/item/%E7%8E%84%E5%A4%A9%E4%B8%8A%E5%B8%9D%E8%AF%B4%E6%8A%A5%E7%88%B6%E6%AF%8D%E6%81%A9%E9%87%8D%E7%BB%8F/17623040"],textual_certainty:"high",notes:"batch22 · Grok-4.5 web-search (filtered: 9 unverifiable/dup dropped)"},{dz:"DZ632",name_han:"太上洞玄灵宝天童经（近题：太上太清天童护命妙经）",name_vi:"Thái Thượng Động Huyền Linh Bảo Thiên Đồng Kinh",bu:"洞神（正统本为太清天童，非洞玄部）",author:"托名太上；茅山梁悟真受（大观三年传说）",era:"北宋–南宋（茅山流传）",topic:"mantra",essence:"Tựa “Thái Thượng Động Huyền Linh Bảo Thiên Đồng Kinh” không có trong Tạng; bản chuẩn là Thái Thượng Thái Thanh Thiên Đồng hộ mệnh diệu kinh (DZ632, Động thần). Kinh ngắn, tụng để thỉnh chư thần–Bắc Đẩu–kim đồng bảo hộ, trừ tà trị bệnh, diên niên. Có phó chú linh phù và truyện cảm ứng ở Mao Sơn.",key_text:"皇天生我，皇地載我，日月照我，星辰榮我。",use:"Tụng trì hộ mệnh, đới phù/thôn phù trị bệnh trừ tà",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E5%A4%AA%E6%B8%85%E5%A4%A9%E7%AB%A5%E8%AD%B7%E5%91%BD%E5%A6%99%E7%B6%93","https://www.shidianguji.com/zh/book/DZ0632","https://baike.baidu.com/item/%E5%A4%AA%E4%B8%8A%E5%A4%AA%E6%B8%85%E5%A4%A9%E7%AB%A5%E6%8A%A4%E5%91%BD%E5%A6%99%E7%BB%8F/17614810","https://ctext.org/wiki.pl?if=gb&chapter=404342"],textual_certainty:"partial",notes:"batch22 · Grok-4.5 web-search (filtered: 9 unverifiable/dup dropped)"},{dz:"DZ1366",name_han:"上清天关三图经",name_vi:"Thượng Thanh Thiên Quan Tam Đồ Kinh",bu:"正一（内容属洞真/上清）",author:"佚名",era:"南北朝（早期上清）",topic:"cultivation",essence:"Kinh Thượng Thanh sớm, một quyển trong Chính Thống Đạo Tạng. Nội dung phần lớn trùng Động chân Thượng Thanh khai thiên tam đồ thất tinh di độ kinh (DZ1317), rút gọn–bổ thần đồ. Thuộc pháp quan thiên–thất tinh di độ, giải tử độ sinh theo khoa Thượng Thanh.",key_text:"null",use:"Tồn tư–phù đồ thiên quan, thất tinh di độ, độ sinh giải tử",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%8A%E6%B8%85%E5%A4%A9%E9%97%9C%E4%B8%89%E5%9C%96%E7%B6%93&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&res=160392&remap=gb","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch22 · Grok-4.5 web-search (filtered: 9 unverifiable/dup dropped)"},{dz:"DZ382",name_han:"太上说大帝延寿妙经（近题：太上灵宝天尊说延寿妙经）",name_vi:"Thái Thượng Thuyết Đại Đế Diên Thọ Diệu Kinh",bu:"洞玄",author:"佚名",era:"唐宋",topic:"经典",essence:"Tựa “Đại đế diên thọ” không khớp catalog; bản chuẩn là Thái Thượng Linh Bảo Thiên Tôn thuyết diên thọ diệu kinh (DZ382). Linh Bảo diên thọ thiên tôn giảng “chân đạo” bất sinh bất diệt, khuyên đốt hương hành đạo, bố thí phóng sinh, tụng kinh–bản mệnh trai dáo để chú toán thần vương tấu công, diên mệnh tập phúc.",key_text:"不生不滅，名為真道。無去無來，亦名真道。",use:"Tụng kinh cầu thọ, tạo công đức, bản mệnh trai dáo",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E9%9D%88%E5%AF%B6%E5%A4%A9%E5%B0%8A%E8%AA%AA%E5%BB%B6%E5%A3%BD%E5%A6%99%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E5%A4%A9%E5%B0%8A%E8%AA%AA%E5%BB%B6%E5%A3%BD%E5%A6%99%E7%B6%93","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"partial",notes:"batch22 · Grok-4.5 web-search (filtered: 9 unverifiable/dup dropped)"},{dz:"DZ1192",name_han:"太上说五圣始生真经（近题：大惠静慈妙乐天尊说福德五圣经）",name_vi:"Thái Thượng Thuyết Ngũ Thánh Thủy Sinh Chân Kinh",bu:"正一",author:"佚名",era:"宋–元",topic:"经典",essence:"Tựa “ngũ thánh thủy sinh” không có trong catalog; bản ngũ thánh trong Tạng là Đại Huệ Tĩnh Từ Diệu Nhạc Thiên Tôn thuyết phúc đức ngũ thánh kinh (DZ1192). Giảng danh hiệu–hình tượng–chú nguyện Ngũ hiển linh quan (Ngũ thánh), tụng trì tiêu tai ban phúc, có thể thỉnh chính nhất đạo sĩ lập đàn tế.",key_text:"靈觀大帝，睿聖聰明。日光菩薩，氣射帝宸。",use:"Tụng hiệu–chú Ngũ hiển/Ngũ thánh, cầu phúc trừ tà",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%A7%E6%83%A0%E9%9D%9C%E6%85%88%E5%A6%99%E6%A8%82%E5%A4%A9%E5%B0%8A%E8%AA%AA%E7%A6%8F%E5%BE%B7%E4%BA%94%E8%81%96%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E5%A4%A7%E6%83%A0%E9%9D%9C%E6%85%88%E5%A6%99%E6%A8%82%E5%A4%A9%E5%B0%8A%E8%AA%AA%E7%A6%8F%E5%BE%B7%E4%BA%94%E8%81%96%E7%B6%93","https://www.shidianguji.com/book/DZ1192","https://baike.baidu.com/item/%E5%A4%A7%E6%83%A0%E9%9D%99%E6%85%88%E5%A6%99%E4%B9%90%E5%A4%A9%E5%B0%8A%E8%AF%B4%E7%A6%8F%E5%BE%B7%E4%BA%94%E5%9C%A3%E7%BB%8F/6095929"],textual_certainty:"partial",notes:"batch22 · Grok-4.5 web-search (filtered: 9 unverifiable/dup dropped)"},{dz:"DZ1185",name_han:"抱朴子內篇",name_vi:"Bão Phác Tử Nội Thiên",bu:"太清",author:"葛洪",era:"Đông Tấn / thế kỷ 4",topic:"外丹",essence:"Kinh điển ngoại đan và thuật trường sinh quan trọng nhất thời Lục triều. Luận về kim đan, kim dịch, phục thực, hành khí, bùa chú và phê phán dị đoan. Chứng minh “tiên khả học” bằng thực nghiệm luyện đan và dược liệu.",key_text:"還丹金液為大要者焉。然則此二事，蓋仙道之極也。",use:"Nguồn gốc lý thuyết ngoại đan Thái Thanh; nền tảng cho nghiên cứu giả kim và y dược đạo giáo.",sources:["https://ctext.org/baopuzi","https://blackmoonharbor.com/uploads/1/1/5/3/115363763/daoist_texts_in_translation._komjathy.pdf","https://zh.wikisource.org/wiki/%E6%8A%B1%E6%9C%B4%E5%AD%90"],textual_certainty:"high",notes:"batch23 · Grok-4.5 web-search (catalog-driven, high-effort)"},{dz:"DZ1017",name_han:"道樞",name_vi:"Đạo Xu",bu:"太玄",author:"曾慥",era:"Nam Tống / thế kỷ 12",topic:"cultivation",essence:"Bách khoa thư thuật dưỡng sinh và nội đan trước Nam Tống, gồm 42 quyển hơn trăm thiên. Mỗi thiên có tóm lược bốn câu và bình chú của Chí Du tử. Tập trung thủy hỏa đã tế, khảm ly phối hợp, kiêm thu phục khí, thai tức, ngoại đan.",key_text:"彼是莫得其偶，謂之道樞。",use:"Tổng hợp thuật tu luyện tiền Tống; tham chiếu lịch sử nội đan và dưỡng sinh.",sources:["https://ctext.org/wiki.pl?if=gb&res=212023","https://zh.wikisource.org/wiki/%E9%81%93%E6%A8%9E","https://zh.daoinfo.org/wiki/%E9%81%93%E6%A8%9E"],textual_certainty:"high",notes:"batch23 · Grok-4.5 web-search (catalog-driven, high-effort)"},{dz:"DZ1254",name_han:"雷法議玄篇",name_vi:"Lôi Pháp Nghị Huyền Thiên",bu:"正一",author:"萬宗師等",era:"Nam Tống–Nguyên / thế kỷ 12–13",topic:"ritual",essence:"Luận bàn lôi pháp Thần Tiêu, nhấn mạnh “chí đạo bất phồn, chí pháp tối giản”. Giải thích cách dùng 36 khí, tinh tú, bàn tay phong vũ và phù ấn để cầu mưa, trừ tà. Là tài liệu then chốt về lý thuyết lôi pháp đời Tống.",key_text:"至道不繁，至法最簡。",use:"Nghiên cứu lôi pháp Thần Tiêu và nghi thức cầu mưa; tham chiếu hành trì pháp thuật.",sources:["https://ctext.org/library.pl?if=gb&res=84927","https://zh.wikisource.org/wiki/%E9%9B%B7%E6%B3%95%E8%AD%B0%E7%8E%84%E7%AF%87","https://zh.daoinfo.org/wiki/%E9%9B%B7%E6%B3%95%E8%AD%B0%E7%8E%84%E7%AF%87"],textual_certainty:"high",notes:"batch23 · Grok-4.5 web-search (catalog-driven, high-effort)"},{dz:"DZ222",name_han:"清微神烈秘法",name_vi:"Thanh Vi Thần Liệt Bí Pháp",bu:"洞真",author:"佚名（清微派）",era:"Nguyên / thế kỷ 14",topic:"ritual",essence:"Kinh pháp Thanh Vi gồm nguồn phái, thánh vị, tập định tọa pháp và phù mệnh. Xem lôi pháp là diệu dụng của Đạo, nhấn mạnh nội tu kết hợp phù chú. Phản ánh hệ thống nghi thức và nội luyện của phái Thanh Vi.",key_text:"且清微法者，即神霄異名也。實道中之妙法。",use:"Nghiên cứu lôi pháp Thanh Vi; thực hành phù lục và nội tu.",sources:["https://ctext.org/wiki.pl?if=gb&res=347081","https://zh.daoinfo.org/wiki/%E6%B8%85%E5%BE%AE%E7%A5%9E%E7%83%88%E7%A7%98%E6%B3%95","https://www.shidianguji.com/zh/book/DZ0222"],textual_certainty:"high",notes:"batch23 · Grok-4.5 web-search (catalog-driven, high-effort)"},{dz:"DZ1483",name_han:"天皇至道太清玉冊",name_vi:"Thiên Hoàng Chí Đạo Thái Thanh Ngọc Sách",bu:"续道藏",author:"朱權",era:"Minh / thế kỷ 15",topic:"philosophy",essence:"Bách khoa thư đạo giáo do Ninh Hiến vương Chu Quyền biên soạn, thu vào Vạn Lịch Tục Đạo tạng. Hệ thống hóa nguồn gốc Đạo, thần phổ, quan chế cung quán, giới luật và trai giáo. Mục tiêu chỉnh đốn giáo chế thời Minh sơ.",key_text:"稽夫道教之源，昔在混茫，始判人道，未備天命。",use:"Nghiên cứu thể chế và nghi thức đạo giáo thời Minh; tra cứu nguồn gốc giáo lý.",sources:["https://ctext.org/wiki.pl?if=gb&res=715094","https://zh.wikisource.org/wiki/%E5%A4%A9%E7%9A%87%E8%87%B3%E9%81%93%E5%A4%AA%E6%B8%85%E7%8E%89%E5%86%8A","https://zh.daoinfo.org/wiki/%E5%A4%A9%E7%9A%87%E8%87%B3%E9%81%93%E5%A4%AA%E6%B8%85%E7%8E%89%E5%86%8A"],textual_certainty:"high",notes:"batch23 · Grok-4.5 web-search (catalog-driven, high-effort)"},{dz:"DZ1307",name_han:"海瓊白真人語錄",name_vi:"Hải Quỳnh Bạch Chân Nhân Ngữ Lục",bu:"正一",author:"彭耜等編（白玉蟾語）",era:"Nam Tống / thế kỷ 13",topic:"cultivation",essence:"Ngữ lục và thi văn của Bạch Ngọc Thiềm (Hải Quỳnh), do môn nhân biên tập. Kết hợp nội đan Nam Tông, lôi pháp và thiền ngộ. Thể hiện phong cách tu đạo tự do, dung hợp Nho–Thích–Đạo của Nam Tông Kim đan.",key_text:"真師海瓊白君，與鶴林彭相，紫元留元長，於中秋之夕……",use:"Nghiên cứu tư tưởng Nam Tông và lôi pháp Bạch Ngọc Thiềm; tham chiếu nội đan thực hành.",sources:["https://ctext.org/wiki.pl?if=gb&res=906911","https://zh.wikisource.org/wiki/%E6%B5%B7%E7%93%8A%E7%99%BD%E7%9C%9F%E4%BA%BA%E8%AA%9E%E9%8C%84","https://baike.baidu.com/item/%E6%B5%B7%E7%90%BC%E7%99%BD%E7%9C%9F%E4%BA%BA%E8%AF%AD%E5%BD%95/4742684"],textual_certainty:"high",notes:"batch23 · Grok-4.5 web-search (catalog-driven, high-effort)"},{dz:"DZ640",name_han:"洞神八帝妙精經",name_vi:"Động Thần Bát Đế Diệu Tinh Kinh",bu:"洞神",author:"佚名",era:"Đông Tấn / khoảng thế kỷ 4",topic:"philosophy",essence:"Kinh Động Thần hệ Tam Hoàng, nói về cửu hoàng (sơ–trung–hậu tam hoàng) và giới luật bát giới. Kết hợp vũ trụ luận, giới cấm và thuật hành trì. Là văn bản then chốt của truyền thống Động Thần / Tam Hoàng.",key_text:"真仙不為此八事則八敗無從起，八敗無從起則八成自然立。",use:"Nghiên cứu kinh Động Thần và giới luật sớm; tham chiếu thần phổ Tam Hoàng.",sources:["https://ctext.org/wiki.pl?if=gb&res=606951","https://zh.wikisource.org/wiki/%E6%B4%9E%E7%A5%9E%E5%85%AB%E5%B8%9D%E5%A6%99%E7%B2%BE%E7%B6%93","https://zh.daoinfo.org/wiki/%E6%B4%9E%E7%A5%9E%E5%85%AB%E5%B8%9D%E5%A6%99%E7%B2%BE%E7%B6%93"],textual_certainty:"high",notes:"batch23 · Grok-4.5 web-search (catalog-driven, high-effort)"},{dz:"DZ1463",name_han:"漢天師世家",name_vi:"Hán Thiên Sư Thế Gia",bu:"续道藏",author:"張正常（張國祥續補）",era:"Minh / thế kỷ 14–16",topic:"仙传",essence:"Gia phả và sử truyền đời Thiên sư Chính Nhất từ Trương Lăng đến các đời Minh. Kết hợp sử liệu, đạo thư và truyền thuyết, khẳng định dòng pháp và uy quyền giáo chủ Long Hổ Sơn. Thu vào Vạn Lịch Tục Đạo tạng.",key_text:"惟漢天師正一真人三天扶教輔元大法師，體妙闡玄，有大利於天下。",use:"Nghiên cứu lịch sử Chính Nhất và dòng Thiên sư; tra cứu thế hệ truyền thừa.",sources:["https://zh.wikisource.org/wiki/%E6%BC%A2%E5%A4%A9%E5%B8%AB%E4%B8%96%E5%AE%B6","https://zh.daoinfo.org/wiki/%E6%BC%A2%E5%A4%A9%E5%B8%AB%E4%B8%96%E5%AE%B6","https://ctext.org/wiki.pl?if=gb&chapter=881245"],textual_certainty:"high",notes:"batch23 · Grok-4.5 web-search (catalog-driven, high-effort)"},{dz:"DZ1484",name_han:"呂祖志",name_vi:"Lữ Tổ Chí",bu:"续道藏",author:"佚名",era:"Minh / thế kỷ 16",topic:"仙传",essence:"Tập truyện ký, linh tích, thi từ và tư liệu đan pháp về Lữ Động Tân. Gồm hành trạng, độ hóa và thơ văn được gán cho Lữ Tổ. Phản ánh sùng bái Lữ Tổ thời Minh và dòng chảy toàn chân–nội đan.",key_text:"苦志慕黃庭，殷勤求道跡。陰功暗心修，善行長日積。",use:"Nghiên cứu tín ngưỡng Lữ Tổ và văn học tiên truyền; tham chiếu nội đan phổ biến.",sources:["https://zh.wikisource.org/wiki/%E5%91%82%E7%A5%96%E5%BF%97","https://zh.daoinfo.org/wiki/%E5%91%82%E7%A5%96%E5%BF%97","https://www.shidianguji.com/zh/book/DZ1484"],textual_certainty:"high",notes:"batch23 · Grok-4.5 web-search (catalog-driven, high-effort)"},{dz:"DZ1218",name_han:"正一法文經章官品",name_vi:"Chính Nhất Pháp Văn Kinh Chương Quan Phẩm",bu:"正一",author:"佚名",era:"Nam–Bắc triều / khoảng thế kỷ 5–6",topic:"ritual",essence:"Tàn bản quan trọng của hệ Chính Nhất Pháp Văn, liệt kê hàng trăm quan quân thiên đình để dâng sớ. Mỗi chương chỉ định thần quan trị bệnh, tai, quỷ quái, kiện tụng. Nền tảng cho nghi thức dâng chương của Thiên sư đạo sớm.",key_text:"收土公、軍兵收怪、主利宅舍、收官事。",use:"Nghiên cứu nghi thức chương tấu và thần phổ Thiên sư đạo; tham chiếu pháp lục.",sources:["https://ctext.org/wiki.pl?if=gb&res=366827","https://zh.daoinfo.org/wiki/%E6%AD%A3%E4%B8%80%E6%B3%95%E6%96%87%E7%B6%93%E7%AB%A0%E5%AE%98%E5%93%81","https://www.shidianguji.com/book/DZ1218"],textual_certainty:"high",notes:"batch23 · Grok-4.5 web-search (catalog-driven, high-effort)"},{dz:"DZ1468",name_han:"徐仙翰藻",name_vi:"Từ Tiên Hàn Tảo",bu:"续道藏",author:"陳夢根編",era:"Nguyên / đầu thế kỷ 14",topic:"仙传",essence:"Tập văn từ, tán tụng, ký lục về tín ngưỡng Từ tiên (Từ tri huynh) ở Phúc Kiến. Gồm bài văn tế, thơ phú và ghi chép linh ứng. Phản ánh tôn giáo dân gian–đạo giáo địa phương được thu vào Tục Đạo tạng.",key_text:"不怪我徐仙翰藻之集，記贊賦頌一編甚巨。",use:"Nghiên cứu tín ngưỡng địa phương Phúc Kiến và văn học tế tự; sử liệu đạo giáo dân gian.",sources:["https://zh.wikisource.org/wiki/%E5%BE%90%E4%BB%99%E7%BF%B0%E8%97%BB","https://zh.daoinfo.org/wiki/%E5%BE%90%E4%BB%99%E7%BF%B0%E8%97%BB","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT08%E7%BA%8C%E9%81%93%E8%97%8F/CNDZ08-ALL/CH0838%E5%BE%90%E4%BB%99%E7%BF%B0%E8%97%BB/CH0838-04%E5%BE%90%E4%BB%99%E7%BF%B0%E8%97%BB%E5%8D%B7%E5%9B%9B.htm"],textual_certainty:"high",notes:"batch23 · Grok-4.5 web-search (catalog-driven, high-effort)"},{dz:"DZ1306",name_han:"葛仙翁肘後備急方",name_vi:"Cát Tiên Ông Trửu Hậu Bị Cấp Phương",bu:"正一",author:"葛洪（陶弘景、楊用道增補）",era:"Đông Tấn–Kim / thế kỷ 4–12",topic:"服气",essence:"Sách cấp cứu y dược mang tính đạo–y giao thoa, chọn phương thuốc dễ kiếm, châm cứu đơn giản. Nhấn mạnh “bị cấp” cho dân nghèo, không dùng dược quý. Phản ánh truyền thống y thuật gắn với đạo sĩ Cát Hồng.",key_text:"余今采其要約，以為肘後救卒三卷，率多易得之藥。",use:"Nghiên cứu y dược đạo giáo và lịch sử cấp cứu; tham chiếu phương thuốc dân gian.",sources:["https://zh.wikisource.org/wiki/%E8%82%98%E5%BE%8C%E5%82%99%E6%80%A5%E6%96%B9","https://zh.daoinfo.org/wiki/%E8%91%9B%E4%BB%99%E7%BF%81%E8%82%98%E5%BE%8C%E5%82%99%E6%80%A5%E6%96%B9","https://ctext.org/wiki.pl?if=en&res=353089"],textual_certainty:"high",notes:"batch23 · Grok-4.5 web-search (catalog-driven, high-effort)"},{dz:"DZ1485",name_han:"紫微斗數",name_vi:"Tử Vi Đẩu Số",bu:"续道藏",author:"佚名",era:"Minh / trước 1607",topic:"philosophy",essence:"Sách chiêm tinh–toán mệnh trong Tục Đạo tạng, dạy an tinh, lập cách, đại vận và hóa diệu. Dựa trên tứ trụ kết hợp cung mệnh, thân cung và chòm sao Tử Vi. Là bản cổ quan trọng của hệ Tử Vi đẩu số.",key_text:"夫人者，稟天地之氣，受陰陽之精，生其身命，上屬五星，下屬五行。",use:"Nghiên cứu thuật số đạo giáo; tham chiếu lịch sử chiêm tinh Trung Quốc.",sources:["https://zh.wikisource.org/wiki/%E8%90%AC%E6%9B%86%E7%BA%8C%E9%81%93%E8%97%8F","https://zh.daoinfo.org/wiki/%E7%B4%AB%E5%BE%AE%E6%96%97%E6%95%B8","https://www.shidianguji.com/book/DZ1485"],textual_certainty:"high",notes:"batch23 · Grok-4.5 web-search (catalog-driven, high-effort)"},{dz:"DZ566",name_han:"上清天心正法",name_vi:"Thượng Thanh Thiên Tâm Chính Pháp",bu:"正一",author:"鄧有功編",era:"Bắc–Nam Tống / thế kỷ 11–12",topic:"ritual",essence:"Kinh điển chính của phái Thiên Tâm, hệ thống hóa phù lục, ấn quyết, bộ tướng và nghi thức trục tà. Lấy Bắc Cực khu tà viện làm trung tâm quyền lực thần thánh. Ảnh hưởng sâu đến pháp thuật và trai giáo đời Tống.",key_text:"非投詞納信不傳，非盟天告地不度。",use:"Nghiên cứu Thiên Tâm chính pháp và nghi thức trục tà; tham chiếu phù lục Tống.",sources:["https://baike.baidu.com/item/%E4%B8%8A%E6%B8%85%E5%A4%A9%E5%BF%83%E6%AD%A3%E6%B3%95/23148809","https://www.jstor.org/stable/26768560","https://dao.crs.cuhk.edu.hk/Main/wp-content/uploads/2024/12/DAOJrl1_05.pdf"],textual_certainty:"high",notes:"batch23 · Grok-4.5 web-search (catalog-driven, high-effort)"},{dz:"DZ1308",name_han:"海瓊問道集",name_vi:"Hải Quỳnh Vấn Đạo Tập",bu:"正一",author:"白玉蟾（門人編）",era:"Nam Tống / thế kỷ 13",topic:"cultivation",essence:"Tập vấn đáp đạo pháp gắn với Bạch Ngọc Thiềm, bổ sung cho Hải Quỳnh ngữ lục. Đề cập nội đan, tâm pháp và thái độ tu hành. Phản ánh phương pháp truyền thụ vấn đáp của Nam Tông.",key_text:"至道之要，在於自悟；自悟之機，在於問答。",use:"Nghiên cứu tư tưởng Bạch Ngọc Thiềm và sư–đệ truyền thừa Nam Tông.",sources:["https://crta.info/wiki/Daozang_-_DZ","https://baike.baidu.com/item/%E6%B5%B7%E7%90%BC%E7%99%BD%E7%9C%9F%E4%BA%BA%E8%AF%AD%E5%BD%95/4742684","https://www.chinaknowledge.de/Literature/Daoists/daozang.html"],textual_certainty:"partial",notes:"batch23 · Grok-4.5 web-search (catalog-driven, high-effort)"},{dz:"DZ900",name_han:"丹房須知",name_vi:"Đan Phòng Tu Tri",bu:"洞神",author:"吳悮（自然子）",era:"南宋（隆興元年/1163自序）",topic:"外丹",essence:"Sách hướng dẫn thực hành lò đan ngoại đan đời Nam Tống: chọn đất, lập phòng, hợp hương, cấm kỵ, dụng cụ và thứ tự trước khi luyện dược. Nhấn mạnh kỷ luật phòng đan và chuẩn bị nghi thức hơn là chỉ liệt kê công thức. Là cẩm nang thao tác cho người luyện đan.",key_text:"予嘗遇神仙之道，雖曰功行積累，莫不皆憑大丹。",use:"Nghiên cứu quy trình, cấm kỵ và không gian luyện ngoại đan đời Tống.",sources:["https://zh.wikisource.org/wiki/%E4%B8%B9%E6%88%BF%E9%A0%88%E7%9F%A5","https://www.shidianguji.com/zh/book/DZ0900","https://zh.daoinfo.org/index.php?title=%E4%B8%B9%E6%88%BF%E9%A0%88%E7%9F%A5","https://ctext.org/wiki.pl?if=gb&res=344743"],textual_certainty:"high",notes:"batch24 · Grok-4.5 catalog-driven"},{dz:"DZ909",name_han:"龍虎還丹訣",name_vi:"Long Hổ Hoàn Đan Quyết",bu:"洞神",author:"金陵子",era:"Đường–Ngũ Đại (khoảng thế kỷ 9–10)",topic:"外丹",essence:"Kinh ngoại đan hai quyển bàn long–hổ (chu sa–thủy ngân), lò đỉnh, nhiều lần hoàn đan và kiêng kỵ hằng ngày. Mô tả kỹ thuật nung luyện kim thạch theo chu kỳ hỏa hậu. Là tài liệu quan trọng về thuật hoàng bạch và hoàn đan thời Đường.",key_text:"初學道，須認得真鉛。",use:"Đối chiếu kỹ thuật ngoại đan long–hổ, cấu tạo lò và cấm kỵ.",sources:["https://ctext.org/wiki.pl?if=gb&res=654671","https://zh.daoinfo.org/index.php?title=%E9%BE%8D%E8%99%8E%E9%82%84%E4%B8%B9%E8%A8%A3%EF%BC%88%E9%87%91%E9%99%B5%E5%AD%90%EF%BC%89","https://www.shidianguji.com/book/DZ0909","https://zh.wikisource.org/zh-hans/%E9%BE%8D%E8%99%8E%E9%82%84%E4%B8%B9%E8%A8%A3"],textual_certainty:"high",notes:"batch24 · Grok-4.5 catalog-driven"},{dz:"DZ889",name_han:"太極真人九轉還丹經要訣",name_vi:"Thái Cực Chân Nhân Cửu Chuyển Hoàn Đan Kinh Yếu Quyết",bu:"洞神",author:"khuyết danh（託西城王君口訣）",era:"Nam–Bắc triều đến Đường sơ",topic:"外丹",essence:"Mô tả pháp cửu chuyển hoàn đan: làm thần phủ, lục nhất nê, thứ tự nạp dược (phàn thạch, không thanh, đan sa, hùng hoàng, thủy ngân…) và hỏa hậu chín mươi ngày đêm. Kèm phương phục tán trước khi uống đan và các loại linh chi Câu Khúc. Thuộc dòng ngoại đan Thượng Thanh–Tây Thành.",key_text:"欲合九轉，先作神釜，可容三斗半者。",use:"Phục dựng quy trình cửu chuyển, vật liệu và hỏa hậu cổ.",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E6%A5%B5%E7%9C%9F%E4%BA%BA%E4%B9%9D%E8%BD%89%E9%82%84%E4%B8%B9%E7%B6%93%E8%A6%81%E8%A8%A3","https://www.shidianguji.com/zh/book/DZ0889","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E6%A5%B5%E7%9C%9F%E4%BA%BA%E4%B9%9D%E8%BD%89%E9%82%84%E4%B8%B9%E7%B6%93%E8%A6%81%E8%A8%A3"],textual_certainty:"high",notes:"batch24 · Grok-4.5 catalog-driven"},{dz:"DZ915",name_han:"還丹肘後訣",name_vi:"Hoàn Đan Trữu Hậu Quyết",bu:"洞神",author:"khuyết danh（託名葛洪）",era:"Đường–Tống",topic:"外丹",essence:"Ba quyển: thượng quyển luận đan sa, hoàng nha, hỏa hậu và ‘trực phù’; trung–hạ tập hợp ca quyết các nhà, kiêm nội–ngoại đan. Giải thích ‘bảo đan vốn một vật sinh hai’ và chu kỳ thiên phù hàng nghìn năm tạo chu sa–thủy ngân. Nguồn then chốt cho lý thuyết hỏa hậu Đường.",key_text:"寶丹本乎一物，而生二。",use:"Đọc lý thuyết thiên phù–hỏa hậu và phân biệt chân dược.",sources:["https://zh.wikisource.org/zh-hans/%E9%82%84%E4%B8%B9%E8%82%98%E5%BE%8C%E8%A8%A3","https://zh.daoinfo.org/index.php?title=%E9%82%84%E4%B8%B9%E8%82%98%E5%BE%8C%E8%A8%A3","https://www.shidianguji.com/book/DZ0915","https://ctext.org/wiki.pl?if=gb&chapter=325923"],textual_certainty:"high",notes:"batch24 · Grok-4.5 catalog-driven"},{dz:"DZ918",name_han:"諸家神品丹法",name_vi:"Chư Gia Thần Phẩm Đan Pháp",bu:"洞神",author:"khuyết danh（tập hợp nhiều nhà）",era:"Tống trở về trước (tập biên)",topic:"外丹",essence:"Tổng tập sáu quyển các phương đan ‘thần phẩm’ nhiều dòng, ghi liều lượng kim thạch, phục chế và trình tự luyện. Phản ánh sự đa dạng công thức ngoại đan–hoàng bạch trước–trong đời Tống. Tài liệu so sánh hóa học cổ và dược liệu.",key_text:"null",use:"Đối chiếu công thức đan nhiều nhà; lịch sử hóa học–dược.",sources:["https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F","https://www.jstor.org/stable/26768560","https://simple.taolibrary.com/category95.aspx"],textual_certainty:"high",notes:"batch24 · Grok-4.5 catalog-driven"},{dz:"DZ919",name_han:"鉛汞甲庚至寶集成",name_vi:"Duyên Hống Giáp Canh Chí Bảo Tập Thành",bu:"洞神",author:"khuyết danh",era:"Tống–Nguyên (tập biên)",topic:"外丹",essence:"Năm quyển chuyên về chì–thủy ngân (giáp–canh) và các pháp ‘chí bảo’ hoàng bạch. Hệ thống hóa thuốc kim thạch, phục chế và biến chất theo ngôn ngữ can chi ngũ hành. Nguồn then chốt cho thuật luyện kim cổ Trung Quốc.",key_text:"null",use:"Nghiên cứu chì–thủy ngân, hoàng bạch và thuật ngữ can chi trong đan kinh.",sources:["https://www.jstor.org/stable/26768560","https://crta.info/wiki/Daozang_-_DZ","https://simple.taolibrary.com/category95.aspx"],textual_certainty:"high",notes:"batch24 · Grok-4.5 catalog-driven"},{dz:"DZ920",name_han:"丹房奧論",name_vi:"Đan Phòng Áo Luận",bu:"洞神",author:"khuyết danh（đời Tống）",era:"Tống",topic:"外丹",essence:"Luận ‘áo chỉ’ phòng đan: chân dược, hỏa hầu, đỉnh khí và sai lầm thường gặp khi luyện. Thiên về biện chính và nguyên lý hơn là liệt kê đơn thuần. Bổ sung cho các cẩm nang thao tác như Đan Phòng Tu Tri.",key_text:"null",use:"Đọc lý thuyết–phê phán sai lầm trong ngoại đan đời Tống.",sources:["https://www.jstor.org/stable/26768560","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F","http://ztdz.jixiangyun.com/list.php?fid-149-page-14.htm"],textual_certainty:"high",notes:"batch24 · Grok-4.5 catalog-driven"},{dz:"DZ921",name_han:"指歸集",name_vi:"Chỉ Quy Tập",bu:"洞神",author:"吳悮",era:"Nam Tống (khoảng 1163)",topic:"外丹",essence:"Cùng tác giả Đan Phòng Tu Tri; tập ‘chỉ quy’ các yếu chỉ đan gia, nhấn mạnh nhận chân dược và đường về một nguồn. Kết hợp kinh nghiệm lò đan với nguyên lý âm dương ngũ hành. Tài liệu đối chiếu với Đan Phòng Tu Tri và Ngư Trang Giải Ngộ Lục.",key_text:"null",use:"Đọc quan điểm ‘chỉ quy’ và nhận chân dược của Ngô Ngộ.",sources:["https://brill.com/downloadpdf/journals/east/38/1/article-p55_4.pdf","https://www.jstor.org/stable/26768560","https://crta.info/wiki/Daozang_-_DZ"],textual_certainty:"high",notes:"batch24 · Grok-4.5 catalog-driven"},{dz:"DZ924",name_han:"真元妙道要略",name_vi:"Chân Nguyên Diệu Đạo Yếu Lược",bu:"洞神",author:"託名鄭思遠（nội dung dẫn Lý Tích, Ngô Quân, Yên La tử）",era:"Ngũ Đại–Tống sơ",topic:"外丹",essence:"Ba thiên: Truất giả nghiệm chân, Chứng chân, Luyện hình—phân biệt đan giả/thật, phê phán luyện kim thạch mù quáng, hướng tới bảo tinh tồn sinh. Giai đoạn chuyển tiếp từ ngoại đan sang tư duy nội đan.",key_text:"夫道者，黃道赤氣，七九迴精。",use:"Nghiên cứu phê phán ngoại đan giả và chuyển hướng nội tu đời Ngũ Đại–Tống.",sources:["https://zh.wikisource.org/wiki/%E7%9C%9F%E5%85%83%E5%A6%99%E9%81%93%E8%A6%81%E7%95%A5","https://www.shidianguji.com/zh/book/DZ0924","https://zh.daoinfo.org/index.php?title=%E7%9C%9F%E5%85%83%E5%A6%99%E9%81%93%E8%A6%81%E7%95%A5","https://ctext.org/wiki.pl?if=gb&res=871141"],textual_certainty:"high",notes:"batch24 · Grok-4.5 catalog-driven"},{dz:"DZ935",name_han:"丹論訣旨心鑑",name_vi:"Đan Luận Quyết Chỉ Tâm Giám",bu:"洞神",author:"張元德",era:"Đường",topic:"外丹",essence:"Bàn ‘tự nhiên hoàn đan’: thủy ngân ôm ‘Kim công’ (chì) mà thụ thai thành dược. Kết hợp lý thuyết với khẩu quyết hỏa hầu, được trích dẫn trong nghiên cứu thời gian–chu kỳ đan dược. Văn bản ngắn nhưng then chốt cho đan luận Đường.",key_text:"流汞抱金公而孕。",use:"Đọc ẩn dụ long–hổ/chì–thủy ngân và chu kỳ thời gian ngoại đan.",sources:["https://www.fabriziopregadio.com/files/PREGADIO_Time_in_Chinese_Alchemy.pdf","https://crta.info/wiki/Daozang_-_DZ","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch24 · Grok-4.5 catalog-driven"},{dz:"DZ953",name_han:"庚道集",name_vi:"Canh Đạo Tập",bu:"洞神",author:"khuyết danh（có đề ‘Thiệu Hưng Giáp Tý… Mông Hiên cư sĩ’）",era:"Tống–Nguyên (tập biên; phần lớn pháp Đường–Tống)",topic:"外丹",essence:"Chín quyển tổng tập hơn hai mươi pháp ‘canh đạo’ (luyện vàng/hoàng bạch): Tỵ khu dưỡng đan dương, Văn Chân tử kim đan, Cửu chuyển linh sa, Đông Pha tam hoàng quỹ… Ghi liều lượng, phục chế, dụng cụ khá chi tiết; được Bản thảo cương mục tham khảo.",key_text:"null",use:"Nghiên cứu hóa học–dược liệu cổ và công thức hoàng bạch.",sources:["https://zh.daoinfo.org/index.php?title=%E5%BA%9A%E9%81%93%E9%9B%86","https://www.shidianguji.com/book/DZ0953","https://ctext.org/wiki.pl?if=gb&res=254265","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch24 · Grok-4.5 catalog-driven"},{dz:"DZ783",name_han:"墉城集仙錄",name_vi:"Dung Thành Tập Tiên Lục",bu:"洞神",author:"杜光庭",era:"Đường mạt–Ngũ Đại (850–933)",topic:"仙传",essence:"Tập tiên truyện nữ tiên và đạo sĩ nữ, lấy Dung Thành (Tây Vương Mẫu) làm khung. Nguyên bản hơn trăm truyện; bản Đạo tạng còn khoảng vài chục. Nguồn chính cho nữ tiên truyền và mô hình hành đạo nữ đời Đường.",key_text:"null",use:"Nghiên cứu nữ tiên, nữ đạo sĩ và hagiography Đường.",sources:["https://commons.wikimedia.org/wiki/Category:%E5%A2%89%E5%9F%8E%E9%9B%86%E4%BB%99%E9%8C%84","https://www.jstor.org/stable/26768560","https://www.mdpi.com/2077-1444/16/11/1419"],textual_certainty:"high",notes:"batch24 · Grok-4.5 catalog-driven"},{dz:"DZ1127",name_han:"陸先生道門科略",name_vi:"Lục Tiên Sinh Đạo Môn Khoa Lược",bu:"太平",author:"陸修靜",era:"Lưu Tống (thế kỷ 5)",topic:"戒律",essence:"Cương lĩnh chỉnh đốn Thiên sư đạo: lập tĩnh/trị, đặt chức tế tửu, quản đạo dân, phục sức và kỷ luật. Muốn khôi phục chế độ ‘lập trị trí chức’ thời Trương Đạo Lăng giữa cảnh khoa luật suy đồi. Văn bản then chốt về tổ chức đạo giáo Lục triều.",key_text:"夫大道虛寂，絕乎狀貌；至聖體行，寄之言教。",use:"Nghiên cứu cải cách Thiên sư đạo và chế độ tế tửu–đạo dân.",sources:["https://zh.wikisource.org/wiki/%E9%99%B8%E5%85%88%E7%94%9F%E9%81%93%E9%96%80%E7%A7%91%E7%95%A5","https://www.shidianguji.com/zh/book/DZ1127","https://zh.daoinfo.org/index.php?title=%E9%99%B8%E5%85%88%E7%94%9F%E9%81%93%E9%96%80%E7%A7%91%E7%95%A5","https://ctext.org/wiki.pl?if=gb&res=183162"],textual_certainty:"high",notes:"batch24 · Grok-4.5 catalog-driven"},{dz:"DZ1224",name_han:"道門定制",name_vi:"Đạo Môn Định Chế",bu:"正一",author:"呂元素（胡湘龍 hiệu đính）",era:"Nam Tống (1188–1201)",topic:"ritual",essence:"Mười quyển chuẩn hóa sớ biểu, chương tấu, đàn tràng và các khoa trai dã (an trạch, đảo vũ, tru tà…). Tác giả than phiền nghi thức đời sau rườm rà so với xưa chỉ dùng phù triện chu chương, nên ‘biệt vi hiệu định’ cho vừa phải. Cẩm nang trai dã hành chính–nghi lễ đời Tống.",key_text:"至簡易者道，而至詳備者禮。",use:"Soạn thảo/đối chiếu sớ điệp và khoa nghi trai dã.",sources:["https://zh.daoinfo.org/index.php?title=%E9%81%93%E9%96%80%E5%AE%9A%E5%88%B6","https://www.shidianguji.com/zh/book/DZ1224","https://ctext.org/wiki.pl?if=gb&res=488628","https://www.kanripo.org/ed/KR5g0033/ZTDZ/008"],textual_certainty:"high",notes:"batch24 · Grok-4.5 catalog-driven"},{dz:"DZ615",name_han:"赤松子章曆",name_vi:"Xích Tùng Tử Chương Lịch",bu:"洞神",author:"khuyết danh（biên tập đời Đường; vật liệu Thiên sư sớm）",era:"Lục triều–Đường (biên định)",topic:"ritual",essence:"Sáu quyển (khuyết): ‘chương’ (tín vật, từ chương, hơn sáu mươi mẫu chương tấu) và ‘lịch’ (chọn ngày, thiên môn khai–bế, ngũ âm). Là sổ tay thượng chương Thiên sư đạo sớm: cầu mưa, trị bệnh, giải oan, ngôn công… Nguồn chính cho nghi chương tấu.",key_text:"世人求貢章奏，或為家國，或為己身，或為眷屬。",use:"Nghiên cứu thượng chương, pháp tín và lịch ngày Thiên sư đạo.",sources:["https://zh.daoinfo.org/index.php?title=%E8%B5%A4%E6%9D%BE%E5%AD%90%E7%AB%A0%E6%9B%86","https://ctext.org/wiki.pl?if=gb&res=678132","https://baike.baidu.com/item/%E8%B5%A4%E6%9D%BE%E5%AD%90%E7%AB%A0%E5%8E%86/17622990","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch24 · Grok-4.5 catalog-driven"},{dz:"DZ1470",name_han:"徐仙真錄",name_vi:"Từ Tiên Chân Lục",bu:"续道藏",author:"方文照（tập）",era:"Minh (khoảng 1405–1424; Vạn Lịch Tục Đạo tạng)",topic:"仙传",essence:"Thuộc Vạn Lịch Tục Đạo tạng: ghi chép chân tích–linh ứng dòng Từ tiên (Từ tri biết/Từ tiên tín ngưỡng dân gian–đạo giáo). Phản ánh sự bổ sung hagiography địa phương đời Minh vào canon. Nguồn cho tín ngưỡng Từ tiên và cấu trúc Tục tạng.",key_text:"null",use:"Nghiên cứu Tục Đạo tạng và hagiography Từ tiên đời Minh.",sources:["https://brill.com/display/book/9781684176540/BP000014.pdf","https://crta.info/wiki/Daozang_-_DZ","http://www.chinaknowledge.de/Literature/Daoists/daozang.html"],textual_certainty:"high",notes:"batch24 · Grok-4.5 catalog-driven"},{dz:"DZ243",name_han:"陳虛白規中指南",name_vi:"Trần Hư Bạch Quy Trung Chỉ Nam",bu:"洞真",author:"陳沖素（陳虛白）",era:"元（14世紀）",topic:"cultivation",essence:"Bộ chỉ nam nội đan Nam tông, lấy chữ “trung” làm huyền quan nhất khiếu. Dạy quy trung thủ nhất, quy khí quy thần, coi huyền tẫn môn là gốc tạo hóa. Ngắn gọn, thực tiễn, được coi là cửa ngõ nắm quy trình luyện đan.",key_text:"要知玄關一竅，玄牝之門，乃神仙聊指造化之基爾。",use:"Nội đan: tìm huyền quan, quy trung, luyện khí thần",sources:["https://neidanwiki.com/index.php?title=Guizhong_zhinan_%E8%A6%8F%E4%B8%AD%E6%8C%87%E5%8D%97","https://www.shidianguji.com/book/DZ0243","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch25 · Grok-4.5 catalog-driven"},{dz:"DZ249",name_han:"中和集",name_vi:"Trung Hòa Tập",bu:"洞真",author:"李道純（瑩蟾子）；黎志頤編",era:"元（大德前後）",topic:"cultivation",essence:"Tác phẩm chủ chốt của phái Trung nội đan. Lấy “trung hòa” làm tông, dung hợp tam giáo, hội thông Nam–Bắc tông. Luận tính mệnh, huyền quan, kim đan, thái cực–viên giác đồng thể, nhấn mạnh thủ trung trí hòa.",key_text:"釋曰圓覺，道曰金丹，儒曰太極。",use:"Lý luận nội đan trung phái; đối chiếu tam giáo; huyền quan nhất khiếu",sources:["https://ctext.org/wiki.pl?if=en&res=537433","https://ctext.org/library.pl?if=en&res=83901","https://brill.com/display/book/9789004288522/B9789004288522_012.pdf"],textual_certainty:"high",notes:"batch25 · Grok-4.5 catalog-driven"},{dz:"DZ251",name_han:"全真集玄秘要",name_vi:"Toàn Chân Tập Huyền Bí Yếu",bu:"洞真",author:"李道純",era:"元",topic:"cultivation",essence:"Tuyển yếu huyền bí Toàn chân–Nam tông do Lý Đạo Thuần soạn. Cô đọng khẩu quyết tính mệnh song tu, giải thích đồ tượng và yếu chỉ kim đan trong truyền thống trung hòa.",key_text:"null",use:"Khẩu quyết nội đan; đọc kèm Trung Hòa Tập",sources:["https://www.jstor.org/stable/26768560","https://zh.daoinfo.org/index.php?title=%E6%9D%8E%E9%81%93%E7%B4%94&variant=zh-hant"],textual_certainty:"high",notes:"batch25 · Grok-4.5 catalog-driven"},{dz:"DZ1057",name_han:"丹陽真人語錄",name_vi:"Đan Dương Chân Nhân Ngữ Lục",bu:"太玄",author:"馬鈺（口述）；王頤中編",era:"金（大定年間）",topic:"cultivation",essence:"Ngữ lục Mã Đan Dương, đệ tử Vương Trùng Dương. Lấy thanh tĩnh vô vi làm tông: thanh tâm nguyên, tịnh khí hải; dưỡng khí toàn thần, đoạn dục an bần. Thể hiện gia phong Toàn chân “chung lữ thân truyền”.",key_text:"清靜者，清為清其心源，淨為淨其炁海。",use:"Toàn chân nhật dụng; thanh tĩnh; dưỡng khí toàn thần",sources:["https://louiskomjathy.com/wp-content/uploads/2024/05/DaoistLiteratureTranslatedbyLouisKomjathy_Komjathy.pdf","https://zh.daoinfo.org/index.php?title=%E4%B8%B9%E9%99%BD%E7%9C%9F%E4%BA%BA%E8%AA%9E%E9%8C%84&variant=zh-hant","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch25 · Grok-4.5 catalog-driven"},{dz:"DZ1060",name_han:"清庵瑩蟾子語錄",name_vi:"Thanh Am Oánh Thiềm Tử Ngữ Lục",bu:"太玄",author:"李道純述；柴元皋等編",era:"元",topic:"cultivation",essence:"Sáu quyển ngữ lục–thi từ của Lý Đạo Thuần do sáu đệ tử biên soạn. Giảng hạ thủ tri thì, huyền quan, tam giáo hợp nhất và khẩu quyết kim đan thực hành trong dòng Thanh Am.",key_text:"欲煉金丹，先明下手處，若不知下手工夫，萬般扭捏，千種杜撰，都不濟事。",use:"Thực hành nội đan; vấn đáp sư đệ; thi từ ẩn dụ đan đạo",sources:["https://www.shidianguji.com/book/DZ1060","https://zh.daoinfo.org/index.php?title=%E6%B8%85%E5%BA%B5%E7%91%A9%E8%9F%BE%E5%AD%90%E8%AA%9E%E9%8C%84&variant=zh-hans","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch25 · Grok-4.5 catalog-driven"},{dz:"DZ1074",name_han:"還真集",name_vi:"Hoàn Chân Tập",bu:"洞真",author:"王道淵",era:"元",topic:"cultivation",essence:"Tập nội đan ba quyển của Vương Đạo Uyên (Hỗn Nhiên Tử). Bàn hoàn chân phản bản, hỏa hầu, tính mệnh, thuộc dòng Nam tông–trung phái thời Nguyên, nhấn mạnh trực chỉ hoàn nguyên.",key_text:"null",use:"Hoàn đan; hỏa hầu; phản bản hoàn chân",sources:["https://www.jstor.org/stable/26768560","https://crta.info/wiki/Daozang_-_DZ"],textual_certainty:"high",notes:"batch25 · Grok-4.5 catalog-driven"},{dz:"DZ1153",name_han:"重陽全真集",name_vi:"Trùng Dương Toàn Chân Tập",bu:"太平",author:"王嚞（王重陽）",era:"金（12世紀）",topic:"cultivation",essence:"Thi từ tổng tập của tổ sư Toàn chân Vương Trùng Dương (13 quyển). Khuyên đoạn trần duyên, tu tâm luyện tính, dùng hình ảnh hài cốt–khôi lỗi để thức tỉnh vô thường, đặt nền giáo pháp Toàn chân.",key_text:"null",use:"Giáo pháp Toàn chân; tu tâm; thi từ truyền đạo",sources:["https://www.shidianguji.com/book/DZ1153","https://www.mdpi.com/2077-1444/14/6/814","https://static1.squarespace.com/static/51772022e4b09a5dad8185fb/t/6059a54c1a7c672eaed8166e/1616487758664/WangChongyang_Komjathy.pdf"],textual_certainty:"high",notes:"batch25 · Grok-4.5 catalog-driven"},{dz:"DZ1154",name_han:"重陽教化集",name_vi:"Trùng Dương Giáo Hóa Tập",bu:"太平",author:"王嚞（王重陽）",era:"金",topic:"cultivation",essence:"Ba quyển thi từ Vương Trùng Dương hóa độ Mã Đan Dương. Ghi lại quá trình “phân lê thập hóa”, dùng thi họa đáp để khai ngộ đệ tử, thể hiện phương pháp tiếp dẫn Toàn chân.",key_text:"null",use:"Sư đệ truyền thừa; giáo hóa; đối thi chứng đạo",sources:["https://ctext.org/wiki.pl?if=gb&res=136544","https://www.mdpi.com/2077-1444/14/6/814","https://crta.info/wiki/Daozang_-_DZ"],textual_certainty:"high",notes:"batch25 · Grok-4.5 catalog-driven"},{dz:"DZ1155",name_han:"重陽分梨十化集",name_vi:"Trùng Dương Phân Lê Thập Hóa Tập",bu:"太平",author:"王嚞（王重陽）",era:"金",topic:"cultivation",essence:"Tập ghi “phân lê thập hóa”: Vương Trùng Dương mười lần tặng lê–thi ca để độ Mã Đan Dương xuất gia. Biểu tượng “phân lê” (ly) thành ẩn dụ ly tục nhập đạo của Toàn chân.",key_text:"null",use:"Truyền thừa sư đệ; nghi thức hóa độ; ẩn dụ ly tục",sources:["https://thesis.lib.nccu.edu.tw/thesis/detail/91b96643fefd7d24712a83dd1684f77a/","https://crta.info/wiki/Daozang_-_DZ","https://www.mdpi.com/2077-1444/14/6/814"],textual_certainty:"high",notes:"batch25 · Grok-4.5 catalog-driven"},{dz:"DZ1156",name_han:"重陽真人金關玉鎖訣",name_vi:"Trùng Dương Chân Nhân Kim Quan Ngọc Tỏa Quyết",bu:"正一",author:"王嚞（王重陽）傳",era:"金",topic:"cultivation",essence:"Khẩu quyết nội đan gán cho Vương Trùng Dương. Luận kim quan ngọc tỏa, tính mệnh tương hỗ, uống đao quý (nuốt nước bọt–khí), phản đối đơn thuần phù thủy tán đan, nhấn mạnh chân tu tính mệnh.",key_text:"有達性命者，便是真修仙也。",use:"Nội đan Toàn chân sơ kỳ; tính mệnh; phòng thất tinh khí",sources:["https://www.mdpi.com/2077-1444/14/6/814","https://brill.com/display/book/9781684171040/back-3.xml","https://search.proquest.com/openview/46b54952eca46be8a2e3cd67ede49d41/1"],textual_certainty:"high",notes:"batch25 · Grok-4.5 catalog-driven"},{dz:"DZ1313",name_han:"洞真高上玉帝大洞雌一玉檢五老寶經",name_vi:"Động Chân Cao Thượng Ngọc Đế Đại Động Thư Nhất Ngọc Kiểm Ngũ Lão Bảo Kinh",bu:"正一",author:"佚名（上清系）",era:"東晉–南朝（4–6世紀）",topic:"classic",essence:"Một trong “tam kỳ” Thượng thanh (cùng Đại động chân kinh, Tố linh đại hữu). Chuyên về “thư nhất” (cái Một Âm), ngọc kiểm ngũ lão, tồn tư thần nữ–tam tố, là cốt lõi thiền định–thần chú thượng phẩm Động chân.",key_text:"null",use:"Thượng thanh tồn tư; thụ kinh; thư nhất–ngũ lão",sources:["https://crta.info/wiki/Daozang_-_DZ","https://dokumen.pub/a-library-of-clouds-the-scripture-of-the-immaculate-numen-and-the-rewriting-of-daoist-texts-082488292x-9780824882921.html","https://www.researchgate.net/publication/273169426_TITLE_INDEX_TO_THE_ZHONGHUA_DAOZANG"],textual_certainty:"high",notes:"batch25 · Grok-4.5 catalog-driven"},{dz:"DZ1314",name_han:"洞真太上素靈洞元大有妙經",name_vi:"Động Chân Thái Thượng Tố Linh Động Nguyên Đại Hữu Diệu Kinh",bu:"正一",author:"佚名（上清系）",era:"東晉–南朝",topic:"classic",essence:"Kinh “đại hữu” trong tam kỳ Thượng thanh. Gồm thủ tam nguyên chân nhất, thủ nguyên đan, tứ cung thư chân nhất, tam cửu tố ngữ. Dạy tồn tư thần danh, thủ nhất, là nền nghi thức truyền thụ thượng phẩm.",key_text:"三洞之道，結自然之號，輔統三寶，大洞真經、雌一五老、大有素靈，應承三元。",use:"Thượng thanh thủ nhất; tồn tư; truyền thụ tam kỳ",sources:["https://zh.wikisource.org/zh-hans/%E6%B4%9E%E7%9C%9F%E5%A4%AA%E4%B8%8A%E7%B4%A0%E9%9D%88%E6%B4%9E%E5%85%83%E5%A4%A7%E6%9C%89%E5%A6%99%E7%B6%93","https://zh.daoinfo.org/index.php?title=%E6%B4%9E%E7%9C%9F%E5%A4%AA%E4%B8%8A%E7%B4%A0%E9%9D%88%E6%B4%9E%E5%85%83%E5%A4%A7%E6%9C%89%E5%A6%99%E7%B6%93&variant=zh-hans","https://brill.com/display/book/9789004383456/back-1.xml"],textual_certainty:"high",notes:"batch25 · Grok-4.5 catalog-driven"},{dz:"DZ177",name_han:"太上洞真智慧上品大誡",name_vi:"Thái Thượng Động Chân Trí Huệ Thượng Phẩm Đại Giới",bu:"洞真",author:"佚名（古靈寶）",era:"東晉",topic:"戒律",essence:"Cổ Linh bảo giới kinh. Nguyên thủy Thiên tôn trao Thái thượng Đạo quân thập giới–thập nguyện trí tuệ thượng phẩm. Nối giới luật với phát nguyện độ sinh, là gốc giới phẩm Động chân–Linh bảo.",key_text:"元始天尊以開皇元年七月一日午時，於西那玉國鬱剎之山浮羅之嶽，長桑林中，授太上道君智慧上品大誡法文。",use:"Thụ giới; thập giới thập nguyện; giới luật Linh bảo",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%9C%9F%E6%99%BA%E6%85%A7%E4%B8%8A%E5%93%81%E5%A4%A7%E8%AA%A1","https://www.shidianguji.com/book/DZ0177/chapter/DZ0177_1","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch25 · Grok-4.5 catalog-driven"},{dz:"DZ344",name_han:"太上洞玄靈寶智慧本願大戒上品經",name_vi:"Thái Thượng Động Huyền Linh Bảo Trí Huệ Bản Nguyện Đại Giới Thượng Phẩm Kinh",bu:"洞玄",author:"佚名（古靈寶）",era:"東晉末–南朝初",topic:"戒律",essence:"Cổ Linh bảo. Dạng vấn đáp Thái cực tiên công (Cát Huyền) và Thái cực pháp sư (Từ Lai Lặc). Trình bày bản nguyện đại giới, khuyên tiến, nối giới với phát nguyện cứu độ và nghiệp báo.",key_text:"此戒名太上智慧勸進要戒上品，皆大智慧經上卷所言也，法傳太極真人，以治道行矣。",use:"Thụ giới; bản nguyện; khuyến tiến tu hành",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E6%99%BA%E6%85%A7%E6%9C%AC%E9%A1%98%E5%A4%A7%E6%88%92%E4%B8%8A%E5%93%81%E7%B6%93","https://www.shidianguji.com/book/DZ0344","https://zh.daoinfo.org/wiki/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E6%99%BA%E6%85%A7%E6%9C%AC%E9%A1%98%E5%A4%A7%E6%88%92%E4%B8%8A%E5%93%81%E7%B6%93"],textual_certainty:"high",notes:"batch25 · Grok-4.5 catalog-driven"},{dz:"DZ532",name_han:"太極真人敷靈寶齋戒威儀諸經要訣",name_vi:"Thái Cực Chân Nhân Phu Linh Bảo Trai Giới Uy Nghi Chư Kinh Yếu Quyết",bu:"洞玄",author:"佚名（古題鄭隱記）",era:"東晉",topic:"ritual",essence:"Cổ Linh bảo uy nghi. Thái cực chân nhân giảng trai giới, đốt hương chúc nguyện, lập trai cứu nạn bệnh, so sánh trai pháp với Đạo đức–Đại động. Là nền tảng nghi thức trai tế Linh bảo sơ kỳ.",key_text:"諸齋法皆上宗於靈寶本齋矣。",use:"Linh bảo trai nghi; uy nghi; chúc nguyện cứu độ",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E6%A5%B5%E7%9C%9F%E4%BA%BA%E6%95%B7%E9%9D%88%E5%AF%B6%E9%BD%8B%E6%88%92%E5%A8%81%E5%84%80%E8%AB%B8%E7%B6%93%E8%A6%81%E8%A8%A3","https://www.jstor.org/stable/26768560","https://www.mdpi.com/2077-1444/14/6/779"],textual_certainty:"high",notes:"batch25 · Grok-4.5 catalog-driven"},{dz:"DZ370",name_han:"太上洞玄靈寶三元玉京玄都大獻經",name_vi:"Thái Thượng Động Huyền Linh Bảo Tam Nguyên Ngọc Kinh Huyền Đô Đại Hiến Kinh",bu:"洞玄",author:"佚名（一說劉無待擬造）",era:"南北朝（或唐前）",topic:"classic",essence:"Kinh cứu độ–bạt tội theo mô hình Vu lan. Giảng tam nguyên (thiên–địa–thủy quan) khảo lục tội phúc, pháp huyền đô đại hiến cúng dường để bạt độ vong linh, trừ tội nguồn, bảo mệnh tịch.",key_text:"故演此玄都大獻之法，以教人天。普願五道還除罪源，將令四生復保命籍。",use:"Trung nguyên bạt độ; đại hiến cúng; cứu độ ngạ quỷ vong linh",sources:["https://www.shidianguji.com/book/DZ0370","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E4%B8%89%E5%85%83%E7%8E%89%E4%BA%AC%E7%8E%84%E9%83%BD%E5%A4%A7%E7%8D%BB%E7%B6%93&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&chapter=272770"],textual_certainty:"high",notes:"batch25 · Grok-4.5 catalog-driven"},{dz:"DZ285",name_han:"黃帝授三子玄女經",name_vi:"Hoàng Đế Thụ Tam Tử Huyền Nữ Kinh",bu:"洞真",author:"佚名（托名黃帝／玄女）",era:"漢魏六朝（約南北朝定本）",topic:"占验",essence:"Kinh bói thức (式占) cổ, cùng hệ với Long Thủ Kinh, chuyên chọn ngày giờ hôn nhân, hẹn hội và cầu vật. Dùng thần sát Thiên Nhất, Thiên Cương và các thần sáu nhâm để đoán cát hung. Là một trong những văn bản Lục Nhâm sớm nhất còn trong Chính Thống Đạo Tạng.",key_text:"天一所在甲戊庚，旦大吉，夕小吉。",use:"Chọn ngày cưới hỏi, hẹn hội, cầu tài vật theo thức pháp cổ",sources:["https://zh.daoinfo.org/index.php?title=%E9%BB%83%E5%B8%9D%E6%8E%88%E4%B8%89%E5%AD%90%E7%8E%84%E5%A5%B3%E7%B6%93","https://zh.wikisource.org/wiki/%E9%BB%83%E5%B8%9D%E6%8E%88%E4%B8%89%E5%AD%90%E7%8E%84%E5%A5%B3%E7%B6%93","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch26 · Grok-4.5 catalog-driven"},{dz:"DZ288",name_han:"靈臺經",name_vi:"Linh Đài Kinh",bu:"洞真",author:"佚名",era:"唐宋以前（道藏本）",topic:"天文",essence:"Kinh tinh tượng trong Động Chân bộ chúng thuật, bàn đài quan sát trời (linh đài) và cách xem sao, vận hành tinh tú để đoán họa phúc. Thuộc nhóm văn bản chiêm tinh–thiên văn hiếm trong Chính Thống Đạo Tạng, cạnh Thông Chiêm Đại Tượng Lịch Tinh Kinh.",key_text:"null",use:"Đọc sao, định cát hung theo thiên văn đạo giáo",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch26 · Grok-4.5 catalog-driven"},{dz:"DZ289",name_han:"秤星靈臺祕要經",name_vi:"Xứng Tinh Linh Đài Bí Yếu Kinh",bu:"洞真",author:"佚名",era:"唐宋（道藏本）",topic:"天文",essence:"Bí yếu về cân sao (xứng tinh) và pháp tạ tinh, gồm các mục như minh ngũ hành chi tính, nhưỡng tai tinh, nhưỡng hỏa/thổ/mộc. Kết hợp chiêm tinh với nghi thức đạo giáo để giải hạn sao xấu, thuộc loại phương thuật–chiêm nghiệm ít được chú ý.",key_text:"null",use:"Giải hạn sao, tạ tinh, chiêm nghiệm ngũ hành tinh tượng",sources:["https://zh.wikisource.org/zh-hans/%E7%A7%A4%E6%98%9F%E9%9D%88%E8%87%BA%E7%A7%98%E8%A6%81%E7%B6%93","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch26 · Grok-4.5 catalog-driven"},{dz:"DZ302",name_han:"周氏冥通記",name_vi:"Chu Thị Minh Thông Ký",bu:"洞真",author:"周子良述／陶弘景編",era:"梁（約516–517）",topic:"仙传",essence:"Nhật ký cảm giáng của đệ tử Đào Hoằng Cảnh là Chu Tử Lương, ghi lời tiên chân mộng trung và chỉ thị tu hành. Là tư liệu sống động về sinh hoạt Thượng Thanh và mối quan hệ thầy–trò thời Lục triều, bổ sung cho Chân Cáo.",key_text:"null",use:"Nghiên cứu hàng chân Thượng Thanh, mộng thông, tu tiên nhật thường",sources:["https://zh.daoinfo.org/index.php?title=%E5%91%A8%E6%B0%8F%E5%86%A5%E9%80%9A%E8%A8%98","https://www.shidianguji.com/zh/book/DZ0302","https://ctext.org/wiki.pl?if=gb&chapter=98742"],textual_certainty:"high",notes:"batch26 · Grok-4.5 catalog-driven"},{dz:"DZ507",name_han:"太上黃籙齋儀",name_vi:"Thái Thượng Hoàng Lục Trai Nghi",bu:"洞玄",author:"杜光庭",era:"唐末五代",topic:"ritual",essence:"Bộ khoa nghi Hoàng Lục trai lớn do Đỗ Quang Đình biên soạn, chi tiết nghi thức hành đạo sáng–trưa–chiều qua nhiều ngày. Dùng để bạt độ cửu tổ, tạ tội cầu ân, là nền tảng khoa nghi Linh Bảo trung cổ còn trong Đạo Tạng.",key_text:"null",use:"Lập đàn Hoàng Lục, bạt độ tổ tiên, tạ tội cầu phước",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E9%BB%83%E7%B1%99%E9%BD%8B%E5%84%80%EF%BC%88%E6%9D%9C%E5%85%89%E5%BA%AD%E7%B7%A8%EF%BC%89","https://ctext.org/wiki.pl?if=gb&res=72073","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch26 · Grok-4.5 catalog-driven"},{dz:"DZ508",name_han:"無上黃籙大齋立成儀",name_vi:"Vô Thượng Hoàng Lục Đại Trai Lập Thành Nghi",bu:"洞玄",author:"留用光傳／蔣叔輿編",era:"南宋",topic:"ritual",essence:"Toàn thư Hoàng Lục trai pháp 57 quyển, phân môn đàn trường, pháp phục, chương sớ, chú ngữ, đăng nghi, phá ngục, thí thực. Tập đại thành khoa nghi bạt độ thời Tống, kế thừa Lục Tu Tĩnh–Đỗ Quang Đình–Trương Vạn Phúc.",key_text:"null",use:"Tra cứu và thực hành khoa nghi Hoàng Lục toàn diện (lập đàn, chương biểu, luyện độ)",sources:["https://zh.daoinfo.org/index.php?title=%E7%84%A1%E4%B8%8A%E9%BB%83%E7%B1%99%E5%A4%A7%E9%BD%8B%E7%AB%8B%E6%88%90%E5%84%80%EF%BC%88%E8%94%A3%E5%8F%94%E8%BC%BF%E7%B7%A8%EF%BC%89","https://zh.wikisource.org/wiki/%E7%84%A1%E4%B8%8A%E9%BB%83%E7%B1%99%E5%A4%A7%E9%BD%8B%E7%AB%8B%E6%88%90%E5%84%80","https://www.shidianguji.com/book/DZ0508"],textual_certainty:"high",notes:"batch26 · Grok-4.5 catalog-driven"},{dz:"DZ524",name_han:"洞玄靈寶齋說光燭戒罰燈祝願儀",name_vi:"Động Huyền Linh Bảo Trai Thuyết Quang Chúc Giới Phạt Đăng Chúc Nguyện Nghi",bu:"洞玄",author:"陸修靜",era:"南朝宋",topic:"ritual",essence:"Khoa nghi Linh Bảo do Lục Tu Tĩnh soạn, giảng ý nghĩa đèn–nến, giới phạt và chúc nguyện trong trai pháp. Là văn bản then chốt để hiểu cách Lục chuẩn hóa trai nghi và giáo hóa đạo sĩ thời Lục triều.",key_text:"null",use:"Hiểu nền tảng trai nghi Linh Bảo, đăng chúc, giới phạt, chúc nguyện",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch26 · Grok-4.5 catalog-driven"},{dz:"DZ528",name_han:"太上洞玄靈寶授度儀",name_vi:"Thái Thượng Động Huyền Linh Bảo Thụ Độ Nghi",bu:"洞玄",author:"陸修靜",era:"南朝宋",topic:"ritual",essence:"Nghi thức truyền thụ kinh giới pháp lục Linh Bảo, có biểu văn của Lục Tu Tĩnh trình bày lý do biên soạn. Quy định đàn trường, minh thệ, truyền kinh lục—mẫu mực cho hệ thống thụ lục đạo giáo về sau.",key_text:"臣修靜依棲至道，翹竚靈文，造次弗忘。",use:"Nghi truyền thụ kinh lục Linh Bảo, nghiên cứu lịch sử thụ lục",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E6%8E%88%E5%BA%A6%E5%84%80","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E6%8E%88%E5%BA%A6%E5%84%80","https://ctext.org/wiki.pl?if=gb&res=199130"],textual_certainty:"high",notes:"batch26 · Grok-4.5 catalog-driven"},{dz:"DZ607",name_han:"玉音法事",name_vi:"Ngọc Âm Pháp Sự",bu:"洞玄",author:"佚名（宋，徽宗朝系統）",era:"北宋",topic:"ritual",essence:"Tập ghi âm điệu, tán tụng và nhạc nghi đạo giáo (ngọc âm), dùng trong trai tiếu. Là tư liệu quý về âm nhạc nghi lễ đạo giáo thời Tống, thuộc Động Huyền bộ tán tụng loại.",key_text:"null",use:"Hát tụng khoa nghi, nghiên cứu nhạc đạo giáo",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch26 · Grok-4.5 catalog-driven"},{dz:"DZ785",name_han:"老君音誦誡經",name_vi:"Lão Quân Âm Tụng Giới Kinh",bu:"洞神",author:"寇謙之（托太上老君）",era:"北魏神瑞二年（415）以降",topic:"戒律",essence:"Còn gọi Vân Trung Âm Tụng Tân Khoa chi giới. Khấu Khiêm Chi mượn danh Lão Quân ban giới mới: cấm tham ô, cắt bỏ hoàng xích dâm loạn, lập hệ sư hiền, quy định âm tụng giới luật và chương biểu. Văn kiện then chốt của Bắc Thiên Sư đạo cải cách.",key_text:"老君曰：煩道不至，至道不煩。",use:"Giới luật Thiên Sư, cải cách đạo quan, âm tụng giới khoa",sources:["https://zh.wikisource.org/zh-hans/%E8%80%81%E5%90%9B%E9%9F%B3%E8%AA%A6%E6%88%92%E7%B6%93","https://ctext.org/wiki.pl?if=gb&chapter=866938","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch26 · Grok-4.5 catalog-driven"},{dz:"DZ1036",name_han:"坐忘論",name_vi:"Tọa Vong Luận",bu:"太玄",author:"司馬承禎",era:"唐",topic:"philosophy",essence:"Luận tu tâm Thượng Thanh của Tư Mã Thừa Trinh: bảy bậc Kính Tín–Đoạn Duyên–Thu Tâm–Giản Sự–Chân Quán–Thái Định–Đắc Đạo, kèm Tọa Vong Khu Dực. Hợp Lão Trang tọa vong với chỉ quán, đề cao thu tâm ly cảnh, ảnh hưởng sâu đến nội đan và Lý học sau này.",key_text:"夫人之所貴者生，生之所貴者道。人之有道，若魚之有水。",use:"Tu tâm tọa vong, định tuệ, triết lý đạo giáo Đường",sources:["https://zh.daoinfo.org/index.php?title=%E5%9D%90%E5%BF%98%E8%AB%96","https://zh.wikisource.org/wiki/%E5%9D%90%E5%BF%98%E8%AB%96","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT04%E5%A4%AA%E7%8E%84%E9%83%A8/CMT04-ALL/CH04052%E5%9D%90%E5%BF%98%E8%AB%96/CH04052-1%E5%9D%90%E5%BF%98%E8%AB%96.htm"],textual_certainty:"high",notes:"batch26 · Grok-4.5 catalog-driven"},{dz:"DZ1205",name_han:"三天內解經",name_vi:"Tam Thiên Nội Giải Kinh",bu:"正一",author:"佚名（正一天師道）",era:"魏晉南北朝",topic:"classic",essence:"Kinh giải nội về Tam Thiên (Thanh Vi, Vũ Dư, Đại Xích) và chính thống Thiên Sư đạo. Giải thích vũ trụ luận, giáo pháp và quan hệ với các đạo khác, là kinh điển Chính Nhất quan trọng ngoài Minh Uy Lục.",key_text:"null",use:"Hiểu giáo nghĩa Tam Thiên, lịch sử Thiên Sư đạo",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch26 · Grok-4.5 catalog-driven"},{dz:"DZ1266",name_han:"鄧天君玄靈八門報應內旨",name_vi:"Đặng Thiên Quân Huyền Linh Bát Môn Báo Ứng Nội Chỉ",bu:"正一",author:"佚名（託鄧天君）",era:"宋元（道藏本）",topic:"占验",essence:"Nội chỉ về huyền linh bát môn và ứng báo theo ngày trực, gắn Đặng Thiên Quân. Liên hệ hệ thống cửu cung bát môn (cận độn giáp) với pháp đoán báo ứng, thuộc phương thuật–chiêm nghiệm ít được phủ trong các lớp trước.",key_text:"null",use:"Đoán báo ứng theo bát môn, pháp độn dụng ngày trực",sources:["https://zh.wikisource.org/zh-hans/%E9%84%A7%E5%A4%A9%E5%90%9B%E7%8E%84%E9%9D%88%E5%85%AB%E9%96%80%E5%A0%B1%E6%87%89%E5%85%A7%E6%97%A8","https://ctext.org/wiki.pl?if=gb&res=321843","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch26 · Grok-4.5 catalog-driven"},{dz:"DZ1278",name_han:"洞玄靈寶五感文",name_vi:"Động Huyền Linh Bảo Ngũ Cảm Văn",bu:"正一",author:"陸修靜",era:"南朝宋",topic:"ritual",essence:"Văn năm lòng cảm (cha mẹ, tội tổ, chúng sinh, đạo pháp, ân sư) để khích lệ giữ đồ than trai cực khổ. Phần sau thống kê các loại trai (Kim Lục, Hoàng Lục, Minh Chân, Tam Nguyên, Bát Tiết, Tự Nhiên, Đồ Than…). Bản đồ phân loại trai pháp Lục Tu Tĩnh.",key_text:"此五感之文，乃是道士修六齋之法，皆出三洞大經。",use:"Đồ than trai, phân loại trai pháp Linh Bảo, giáo dục đạo tâm",sources:["https://zh.wikisource.org/wiki/%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E4%BA%94%E6%84%9F%E6%96%87","https://zh.daoinfo.org/index.php?title=%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E4%BA%94%E6%84%9F%E6%96%87","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch26 · Grok-4.5 catalog-driven"},{dz:"DZ1288",name_han:"元辰章醮立成曆",name_vi:"Nguyên Thần Chương Tiếu Lập Thành Lịch",bu:"正一",author:"佚名",era:"唐宋（道藏本）",topic:"占验",essence:"Hai quyển: thượng quyển nghi chương tiếu giải tai theo nguyên thần (đàn đồ, phù cửa, chương tín); hạ quyển lịch sáu mươi giáp tí và pháp tiêu tai. Giao điểm hiếm giữa chương tiếu Thiên Sư và thuật mệnh–nguyên thần.",key_text:"null",use:"Chương tiếu nguyên thần, suy mệnh giáp tí, giải hạn theo ngày",sources:["https://zh.daoinfo.org/index.php?title=%E5%85%83%E8%BE%B0%E7%AB%A0%E9%86%AE%E7%AB%8B%E6%88%90%E6%9B%86","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch26 · Grok-4.5 catalog-driven"},{dz:"DZ1294",name_han:"上清黃書過度儀",name_vi:"Thượng Thanh Hoàng Thư Quá Độ Nghi",bu:"正一",author:"佚名（早期天師道）",era:"南北朝",topic:"ritual",essence:"Nghi thức quá độ (hoàng thư) của Thiên Sư đạo sớm: nhập tịnh, tồn tư, bố cửu cung, giải kết, ngôn công. Dù mang danh Thượng Thanh, nội dung thuộc nghi thức sinh khí–âm dương của Chính Nhất, tư liệu then chốt về nghi thức quá độ cổ.",key_text:"夫弟子在師治受道，不得過二十不過度，二十外受道，即過度當沐浴禁誡。",use:"Nghiên cứu nghi quá độ Thiên Sư, tồn tư, cửu cung, chương quan",sources:["http://www.ctcwri.idv.tw/CTCW-CMTS/CMT07%E6%AD%A3%E4%B9%99%E9%83%A8/CMT07-ALL/CH07102%E4%B8%8A%E6%B8%85%E9%BB%83%E6%9B%B8%E9%81%8E%E5%BA%A6%E5%84%80.htm","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch26 · Grok-4.5 catalog-driven"},{dz:"DZ1412",name_han:"太上元始天尊說北帝伏魔神咒妙經",name_vi:"Thái Thượng Nguyên Thủy Thiên Tôn Thuyết Bắc Đế Phục Ma Thần Chú Diệu Kinh",bu:"正一",author:"題歐陽雯受（約宋）",era:"宋",topic:"ritual",essence:"Kinh căn bản của hệ Bắc Đế phục ma: thuật sáu thiên ma vương hại đời, Nguyên Thủy Thiên Tôn sai Bắc Đế dẹp tà. Gồm nhiều phẩm tụng chú, phù lục, trảm quỷ, hộ mệnh; là nền tảng nghi thức Thiên Bồng–Bắc Đế.",key_text:"天蓬天蓬，九元殺童",use:"Tụng kinh/chú Bắc Đế phục ma, trấn tà, sát quỷ, hộ đàn.",sources:["https://www.shidianguji.com/zh/book/DZ1412","https://ctext.org/wiki.pl?if=gb&res=216920","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E5%8C%97%E5%B8%9D%E4%BC%8F%E9%AD%94%E7%A5%9E%E5%92%92%E5%A6%99%E7%B6%93"],textual_certainty:"high",notes:"batch27 · Grok-4.5 catalog-driven"},{dz:"DZ1413",name_han:"北帝伏魔經法建壇儀",name_vi:"Bắc Đế Phục Ma Kinh Pháp Kiến Đàn Nghi",bu:"正一",author:"盧中苓",era:"明",topic:"ritual",essence:"Nghi thức dựng đàn tụng Bắc Đế phục ma kinh pháp. Lấy kinh DZ1412 làm kinh bản, thỉnh Bắc Đế và bộ tướng, tiêu tai diệt ma; thuộc chính nghi hành trì hệ Bắc Đế thời Minh.",key_text:"夫伏魔經法者，教傳自古，派演於今",use:"Kiến đàn, thỉnh tướng, tụng kinh phục ma theo nghi Bắc Đế.",sources:["https://www.shidianguji.com/zh/book/DZ1413","https://zh.wikisource.org/wiki/%E5%8C%97%E5%B8%9D%E4%BC%8F%E9%AD%94%E7%B6%93%E6%B3%95%E5%BB%BA%E5%A3%87%E5%84%80","https://zh.daoinfo.org/index.php?title=%E5%8C%97%E5%B8%9D%E4%BC%8F%E9%AD%94%E7%B6%93%E6%B3%95%E5%BB%BA%E5%A3%87%E5%84%80"],textual_certainty:"high",notes:"batch27 · Grok-4.5 catalog-driven"},{dz:"DZ1215",name_han:"太上北極伏魔神咒殺鬼籙",name_vi:"Thái Thượng Bắc Cực Phục Ma Thần Chú Sát Quỷ Lục",bu:"正一",author:"佚名",era:"明",topic:"fu",essence:"Lục pháp Chính Nhất Bắc Cực phục ma sát quỷ: ghi phù, ấn (Thiên Bồng, Thiên Đinh…), thần danh và phép đeo/luyện. Liên hệ Tử Vi–Bắc Đế–Thiên Bồng, dùng để trừ tà trị bệnh.",key_text:"北極天蓬印，制伏陰魔，救治疾病",use:"Thụ lục, đeo phù ấn, hành trì sát quỷ trấn tà.",sources:["https://www.shidianguji.com/zh/book/DZ1215","https://ctext.org/wiki.pl?if=gb&res=103414","http://www.ctcwri.idv.tw/CTCW-XDJDQJ/CH07024%E5%A4%AA%E4%B8%8A%E5%8C%97%E6%A5%B5%E4%BC%8F%E9%AD%94%E7%A5%9E%E5%92%92%E6%AE%BA%E9%AC%BC%E7%B1%99.htm"],textual_certainty:"high",notes:"batch27 · Grok-4.5 catalog-driven"},{dz:"DZ0027",name_han:"元始天尊說北方真武妙經",name_vi:"Nguyên Thủy Thiên Tôn Thuyết Bắc Phương Chân Vũ Diệu Kinh",bu:"洞真",author:"佚名",era:"宋",topic:"classic",essence:"Kinh bản Chân Vũ/Huyền Thiên: Nguyên Thủy sai Bắc phương Chân Vũ thần tướng thu đoạn yêu ma. Có Ngưỡng khải chú và duyên khởi Chân Vũ trấn Bắc, là kinh cốt của tín ngưỡng Võ Đương–Bắc Đế.",key_text:"仰啟玄天大聖者，北方壬癸至靈神",use:"Tụng kinh Chân Vũ, hộ mệnh, phục ma, cầu trấn phương Bắc.",sources:["https://www.shidianguji.com/book/DZ0027","https://zh.wikisource.org/zh-hans/%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E5%8C%97%E6%96%B9%E7%9C%9F%E6%AD%A6%E5%A6%99%E7%B6%93","https://ctext.org/wiki.pl?if=gb&chapter=528131"],textual_certainty:"high",notes:"batch27 · Grok-4.5 catalog-driven"},{dz:"DZ0362",name_han:"太上洞淵說請雨龍王經",name_vi:"Thái Thượng Động Uyên Thuyết Thỉnh Vũ Long Vương Kinh",bu:"洞玄",author:"佚名",era:"東晉–南北朝",topic:"ritual",essence:"Kinh hệ Động Uyên: liệt danh long vương các phương, tụng để thỉnh mưa, tiêu hạn, cứu dân. Rút gọn từ truyền thống Động Uyên thần chú, chuyên nghi cầu vũ.",key_text:"道君昔於三天之上，以觀世界",use:"Cầu mưa, thỉnh long vương, tiêu hạn dịch.",sources:["https://www.shidianguji.com/zh/book/DZ0362","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E6%B7%B5%E8%AA%AA%E8%AB%8B%E9%9B%A8%E9%BE%8D%E7%8E%8B%E7%B6%93","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B4%9E%E6%B7%B5%E8%AA%AA%E8%AB%8B%E9%9B%A8%E9%BE%8D%E7%8E%8B%E7%B6%93"],textual_certainty:"high",notes:"batch27 · Grok-4.5 catalog-driven"},{dz:"DZ0790",name_han:"女青鬼律",name_vi:"Nữ Thanh Quỷ Luật",bu:"洞神",author:"佚名（天師道）",era:"魏晉",topic:"戒律",essence:"Luật quỷ sớm của Thiên Sư đạo: Thái Thượng truyền Trương Đạo Lăng ghi tên họ quỷ thần, phép hô danh chế quỷ và giới cấm đạo dân. Nền tảng trừ tà–giới luật chính nhất sơ kỳ.",key_text:"太上大道不忍見之……下此鬼律八卷，紀天下鬼神姓名",use:"Hô danh quỷ, trì giới, trị tà theo luật Thiên Sư.",sources:["https://www.shidianguji.com/book/DZ0790","https://zh.wikisource.org/wiki/%E5%A5%B3%E9%9D%92%E9%AC%BC%E5%BE%8B","https://zh.daoinfo.org/index.php?title=%E5%A5%B3%E9%9D%92%E9%AC%BC%E5%BE%8B"],textual_certainty:"high",notes:"batch27 · Grok-4.5 catalog-driven"},{dz:"DZ0599",name_han:"洞天福地嶽瀆名山記",name_vi:"Động Thiên Phúc Địa Nhạc Độc Danh Sơn Ký",bu:"洞玄",author:"杜光庭",era:"唐末五代（天復元年/901）",topic:"仙传",essence:"Bản đồ địa lý thánh Đạo giáo chuẩn: thập đại động thiên, tam thập lục động thiên, thất thập nhị phúc địa, ngũ nhạc, thập châu, tĩnh lư… Ghi quận huyện, đàn quán, chủ thần; là “bản đồ sống” cho hành hương và hành pháp.",key_text:"大天之內，有洞天三十六，別有日月星辰靈仙宮闕",use:"Tra cứu động thiên phúc địa, lập đàn, hành hương, nghiên cứu địa lý thánh.",sources:["https://zh.wikisource.org/wiki/%E6%B4%9E%E5%A4%A9%E7%A6%8F%E5%9C%B0%E5%B6%BD%E7%80%86%E5%90%8D%E5%B1%B1%E8%A8%98","https://www.shidianguji.com/book/DZ0599","https://ctext.org/wiki.pl?if=gb&res=697019"],textual_certainty:"high",notes:"batch27 · Grok-4.5 catalog-driven"},{dz:"DZ0598",name_han:"十洲記",name_vi:"Thập Châu Ký",bu:"洞玄",author:"題東方朔",era:"六朝（託漢）",topic:"仙传",essence:"Ký sự thập châu tam đảo (Tổ Châu, Doanh Châu, Huyền Châu…), tiên dược, bất tử thảo, Côn Lôn. Tiền thân quan trọng của truyền thống động thiên–thập châu trong Đạo tạng.",key_text:"祖洲近在東海之中，地方五百里……上有不死之草",use:"Hiểu vũ trụ quan tiên đảo, tham khảo địa lý huyền ảo Đạo giáo.",sources:["https://zh.wikisource.org/wiki/%E6%B5%B7%E5%85%A7%E5%8D%81%E6%B4%B2%E8%A8%98","https://zh.daoinfo.org/wiki/%E5%8D%81%E6%B4%B2%E8%A8%98","https://ctext.org/wiki.pl?if=gb&res=619683"],textual_certainty:"high",notes:"batch27 · Grok-4.5 catalog-driven"},{dz:"DZ1063",name_han:"洞淵集",name_vi:"Động Uyên Tập",bu:"太玄",author:"李思聰",era:"北宋（皇祐前後）",topic:"图经",essence:"Tập đồ–tán về thập đại động thiên, ngũ nhạc, bồng hồ, danh sơn phúc địa; dâng biểu triều Tống. Bổ sung–hệ thống hóa bản đồ thánh sau Đỗ Quang Đình, mang tính đồ kinh.",key_text:"古存閬苑之文，今有十洲之記",use:"Đối chiếu động thiên phúc địa, nghiên cứu bản đồ thánh Tống.",sources:["https://www.shidianguji.com/zh/book/DZ1063","https://zh.wikisource.org/zh-hans/%E6%B4%9E%E6%B7%B5%E9%9B%86_(%E6%9D%8E%E6%80%9D%E8%81%B0)","https://zh.daoinfo.org/index.php?title=%E6%B4%9E%E6%B7%B5%E9%9B%86%EF%BC%88%E6%9D%8E%E6%80%9D%E8%81%B0%E7%B7%A8%EF%BC%89"],textual_certainty:"high",notes:"batch27 · Grok-4.5 catalog-driven"},{dz:"DZ0304",name_han:"茅山志",name_vi:"Mao Sơn Chí",bu:"洞真",author:"劉大彬等",era:"元",topic:"仙传",essence:"Sơn chí Mao Sơn (Câu Khúc): lịch sử phái Thượng Thanh, tiểu sử tam Mao–Đào Hoằng Cảnh, cung quán, bia ký, truyền thừa. Tư liệu cốt lõi về danh sơn và phổ lục Thượng Thanh.",key_text:"句曲洞天，金壇華陽",use:"Nghiên cứu Mao Sơn, Thượng Thanh, lịch sử sơn môn.",sources:["https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf","https://ctext.org/wiki.pl?if=gb&res=268815","https://www.researchgate.net/publication/273169426_TITLE_INDEX_TO_THE_ZHONGHUA_DAOZANG"],textual_certainty:"high",notes:"batch27 · Grok-4.5 catalog-driven"},{dz:"DZ0962",name_han:"武當福地總真集",name_vi:"Vũ Đương Phúc Địa Tổng Chân Tập",bu:"洞神",author:"劉道明",era:"元（至元末）",topic:"仙传",essence:"Tổng tập phúc địa Võ Đương: địa lý, cung quán, linh tích, truyền thuyết Chân Vũ. Nguồn chính cho địa lý thánh và tín ngưỡng Huyền Thiên tại Võ Đương.",key_text:"武當福地，非真武不足以當之",use:"Nghiên cứu Võ Đương, Chân Vũ, lập tự hành hương.",sources:["https://zh.wikisource.org/zh-hans/%E6%AD%A6%E7%95%B6%E7%A6%8F%E5%9C%B0%E7%B8%BD%E7%9C%9F%E9%9B%86","https://ctext.org/wiki.pl?if=gb&res=268815&remap=gb","https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf"],textual_certainty:"high",notes:"batch27 · Grok-4.5 catalog-driven"},{dz:"DZ0590",name_han:"道教靈驗記",name_vi:"Đạo Giáo Linh Nghiệm Ký",bu:"洞玄",author:"杜光庭",era:"唐末五代",topic:"仙传",essence:"Tập ký linh nghiệm: tụng kinh, đeo phù, dựng quán, trì giới được ứng nghiệm. Dùng chuyện thực–báo ứng để củng cố tín tâm và phổ hóa giáo pháp.",key_text:"為善者天降百祥，為不善者天降百殃",use:"Giáo hóa, chứng tín, tham khảo ứng nghiệm nghi thức.",sources:["https://zh.wikisource.org/wiki/%E9%81%93%E6%95%99%E9%9D%88%E9%A9%97%E8%A8%98","https://ctext.org/wiki.pl?if=gb&res=862831","https://zh.daoinfo.org/index.php?title=%E9%81%93%E6%95%99%E9%9D%88%E9%A9%97%E8%A8%98"],textual_certainty:"high",notes:"batch27 · Grok-4.5 catalog-driven"},{dz:"DZ0592",name_han:"神仙感遇傳",name_vi:"Thần Tiên Cảm Ngộ Truyện",bu:"洞玄",author:"杜光庭",era:"唐末五代",topic:"仙传",essence:"Truyện cảm ngộ thần tiên: người phàm gặp tiên, được điểm hóa, đắc dược hoặc chứng đạo. Văn phong kể chuyện, là phổ lục tiên thoại tiêu biểu đời Đường–Ngũ đại.",key_text:"自古以來，人有感遇神仙之事",use:"Đọc truyện tiên, giáo hóa, nghiên cứu hagiography.",sources:["https://zh.wikisource.org/wiki/%E7%A5%9E%E4%BB%99%E6%84%9F%E9%81%87%E5%82%B3","https://ctext.org/wiki.pl?if=gb&res=115793","https://baike.baidu.com/item/%E7%A5%9E%E4%BB%99%E6%84%9F%E9%81%87%E4%BC%A0/2290812"],textual_certainty:"high",notes:"batch27 · Grok-4.5 catalog-driven"},{dz:"DZ0591",name_han:"錄異記",name_vi:"Lục Dị Ký",bu:"洞玄",author:"杜光庭",era:"唐末五代",topic:"仙传",essence:"Ký dị sự–thần quái–tiên tích; kết hợp chí quái và ký đạo. Bảo tồn truyền thuyết địa phương và nhân vật dị thường thời Đường–Thục.",key_text:"錄古今異事，以廣見聞",use:"Tham khảo dị tích, nghiên cứu văn hóa tín ngưỡng.",sources:["https://www.researchgate.net/publication/273169426_TITLE_INDEX_TO_THE_ZHONGHUA_DAOZANG","https://brill.com/display/book/9781684175161/BP000011.pdf","https://textref.org/mm.pl?method=search&page=3&author=%E6%9D%9C%E5%85%89%E5%BA%AD"],textual_certainty:"high",notes:"batch27 · Grok-4.5 catalog-driven"},{dz:"DZ0300",name_han:"華陽陶隱居內傳",name_vi:"Hoa Dương Đào Ẩn Cư Nội Truyện",bu:"洞真",author:"賈嵩",era:"唐",topic:"仙传",essence:"Nội truyện Đào Hoằng Cảnh: cuộc đời ẩn cư Mao Sơn, biên soạn chân cáo, luyện dưỡng, quan hệ triều đình. Nguồn hagiography chuẩn về tổ sư Thượng Thanh.",key_text:"隱居華陽，總括三洞",use:"Nghiên cứu Đào Hoằng Cảnh, Mao Sơn, Thượng Thanh.",sources:["https://zh.daoinfo.org/index.php?title=%E8%8F%AF%E9%99%BD%E9%99%B6%E9%9A%B1%E5%B1%85%E5%85%A7%E5%82%B3","https://www.researchgate.net/publication/273169426_TITLE_INDEX_TO_THE_ZHONGHUA_DAOZANG","https://brill.com/display/book/9789004313699/B9789004313699_011.pdf"],textual_certainty:"high",notes:"batch27 · Grok-4.5 catalog-driven"},{dz:"DZ1050",name_han:"華陽陶隱居集",name_vi:"Hoa Dương Đào Ẩn Cư Tập",bu:"太玄",author:"陶弘景",era:"梁",topic:"philosophy",essence:"Văn tập Đào Hoằng Cảnh: thư trát, minh, tự, luận đạo. Phản ánh tư tưởng “sơn trung tể tướng”, dung hợp tam giáo và thực tiễn ẩn tu Mao Sơn.",key_text:"山川之美，古來共談",use:"Đọc văn–tư tưởng Đào Hoằng Cảnh, tham chiếu Thượng Thanh.",sources:["https://www.researchgate.net/publication/273169426_TITLE_INDEX_TO_THE_ZHONGHUA_DAOZANG","https://commons.wikimedia.org/wiki/Category:%E8%8F%AF%E9%99%BD%E9%99%B6%E9%9A%B1%E5%B1%85%E9%9B%86","https://www.daorenjia.com/dztu-75"],textual_certainty:"high",notes:"batch27 · Grok-4.5 catalog-driven"},{dz:"DZ1239",name_han:"正一修真略儀",name_vi:"Chính Nhất tu chân lược nghi",bu:"正一",author:"佚名",era:"南北朝末至隋唐初",topic:"ritual",essence:"Sách trình bày thứ bậc và ý nghĩa truyền thụ pháp lục Chính Nhất, nhấn mạnh lục là linh văn của thần chân dùng để kiểm xét tội phúc, sai khiển quỷ thần. Liệt kê hệ thống Thái Thượng tam ngũ chính nhất minh oai bảo lục hai mươi bốn giai cùng các lục tiên quan, linh quan. Là tài liệu then chốt để hiểu nghi thức thụ lục và thứ tự từ Chính Nhất tiến lên Tam Động.",key_text:"籙者，太上神真之靈文，九天眾聖之秘言。",use:"Nghiên cứu thụ lục Chính Nhất, thứ bậc pháp lục, nghi thức truyền đạo.",sources:["https://zh.daoinfo.org/index.php?title=%E6%AD%A3%E4%B8%80%E4%BF%AE%E7%9C%9F%E7%95%A5%E5%84%80","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E4%B8%80%E4%BF%AE%E7%9C%9F%E7%95%A5%E5%84%80","https://ctext.org/wiki.pl?if=gb&res=660439"],textual_certainty:"high",notes:"batch28 · Grok-4.5 catalog-driven"},{dz:"DZ1241",name_han:"傳授三洞經戒法籙略說",name_vi:"Truyền thụ Tam Động kinh giới pháp lục lược thuyết",bu:"正一",author:"張萬福",era:"Đường (先天元年 712)",topic:"ritual",essence:"Tác phẩm hệ thống của đạo sĩ Trương Vạn Phúc về kinh giới pháp lục Tam Động, phân theo đối tượng truyền thụ. Gồm mục lục giới, pháp Chính Nhất, Đạo Đức, Tam Hoàng, Linh Bảo và thứ tự tiến thụ. Là nguồn chính để tái dựng nghi thức thụ giới thụ lục thời Thịnh Đường.",key_text:"大唐先天元年十二月十二日太清觀道士張萬福謹記。",use:"Lịch sử thụ lục, phân tầng kinh giới, nghiên cứu đạo giáo thời Đường.",sources:["https://zh.daoinfo.org/index.php?title=%E5%82%B3%E6%8E%88%E4%B8%89%E6%B4%9E%E7%B6%93%E6%88%92%E6%B3%95%E7%B1%99%E7%95%A5%E8%AA%AA","https://zh.wikisource.org/zh-hans/%E5%82%B3%E6%8E%88%E4%B8%89%E6%B4%9E%E7%B6%93%E6%88%92%E6%B3%95%E7%B1%99%E7%95%A5%E8%AA%AA","https://ctext.org/wiki.pl?if=gb&res=459017"],textual_certainty:"high",notes:"batch28 · Grok-4.5 catalog-driven"},{dz:"DZ1240",name_han:"洞玄靈寶道士受三洞經誡法籙擇日曆",name_vi:"Động Huyền Linh Bảo đạo sĩ thụ Tam Động kinh giới pháp lục trạch nhật lịch",bu:"正一",author:"張萬福",era:"Đường",topic:"ritual",essence:"Lịch chọn ngày lành để đạo sĩ xuất gia thụ kinh giới pháp lục Tam Động, do Trương Vạn Phúc biên soạn. Chỉ rõ mỗi bộ pháp (Chính Nhất, Động Thần, Linh Bảo…) có ngày giờ thích hợp khác nhau. Kết hợp nghi thức thụ lục với thuật chọn ngày truyền thống.",key_text:"京三洞弟子清都觀道士張萬福撰。",use:"Trạch nhật thụ lục, nghi xuất gia, lịch pháp đạo giáo.",sources:["https://zh.daoinfo.org/wiki/%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E9%81%93%E5%A3%AB%E5%8F%97%E4%B8%89%E6%B4%9E%E7%B6%93%E8%AA%A1%E6%B3%95%E7%B1%99%E6%93%87%E6%97%A5%E6%9B%86","https://zh.wikisource.org/zh-hans/%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E9%81%93%E5%A3%AB%E5%8F%97%E4%B8%89%E6%B4%9E%E7%B6%93%E8%AA%A1%E6%B3%95%E7%B1%99%E6%93%87%E6%97%A5%E6%9B%86","https://www.shidianguji.com/zh/book/DZ1240"],textual_certainty:"high",notes:"batch28 · Grok-4.5 catalog-driven"},{dz:"DZ1237",name_han:"三洞修道儀",name_vi:"Tam Động tu đạo nghi",bu:"正一",author:"孫夷中（述劉若拙）",era:"Ngũ Đại–Bắc Tống sơ (khoảng 1003)",topic:"ritual",essence:"Mô tả thứ bậc đạo sĩ từ sơ nhập đạo đến Đại Động, mũ áo, kinh lục và nghi thức thăng giai. Hệ thống hóa lộ trình Chính Nhất → Động Thần → Linh Bảo → Thượng Thanh. Tài liệu chuẩn về tổ chức phẩm vị và thụ lục sau hỗn loạn Ngũ Đại.",key_text:"三洞科格，自正一至大洞，凡七等，籙有一百二十階。",use:"Phẩm vị đạo sĩ, lộ trình thụ lục, lịch sử tổ chức giáo đoàn.",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%89%E6%B4%9E%E4%BF%AE%E9%81%93%E5%84%80","https://zh.wikisource.org/wiki/%E4%B8%89%E6%B4%9E%E4%BF%AE%E9%81%93%E5%84%80","https://ctext.org/wiki.pl?if=gb&res=857585"],textual_certainty:"high",notes:"batch28 · Grok-4.5 catalog-driven"},{dz:"DZ796",name_han:"太上三五正一盟威閱籙醮儀",name_vi:"Thái Thượng tam ngũ chính nhất minh oai duyệt lục tiếu nghi",bu:"洞神",author:"杜光庭（刪定）",era:"Đường mạt–Ngũ Đại",topic:"ritual",essence:"Nghi thức duyệt lục và lập tiếu cho hệ Thái Thượng tam ngũ chính nhất minh oai lục, do Đỗ Quang Đình san định từ nghi thiên sư cổ. Dùng vào các ngày bản mệnh, tam nguyên, bát tiết để kiểm lục, cáo thần, củng cố công đức thụ lục. Điển hình nghi duy trì quan hệ với thần binh trong lục sau khi thụ.",key_text:"原題廣成先生杜光庭刪定。",use:"Nghi duyệt lục, tiếu tế Chính Nhất, thực hành duy trì pháp lục.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E4%B8%89%E4%BA%94%E6%AD%A3%E4%B8%80%E7%9B%9F%E5%A8%81%E9%96%B1%E7%B1%99%E9%86%AE%E5%84%80","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E4%B8%89%E4%BA%94%E6%AD%A3%E4%B8%80%E7%9B%9F%E5%A8%81%E9%96%B1%E7%B1%99%E9%86%AE%E5%84%80"],textual_certainty:"high",notes:"batch28 · Grok-4.5 catalog-driven"},{dz:"DZ797",name_han:"太上正一閱籙儀",name_vi:"Thái Thượng chính nhất duyệt lục nghi",bu:"洞神",author:"杜光庭（編集）",era:"Đường mạt",topic:"ritual",essence:"Bản duyệt lục Chính Nhất do Đỗ Quang Đình biên tập, quy định ngày giờ và trình tự thỉnh lục, đối lục, cáo tạ. Nhấn mạnh định kỳ duyệt lục để thần binh trong lục không rời, công quả không suy. Cặp đôi với các nghi tiếu lục cùng hệ thiên sư.",key_text:"正一法籙本命、三元、三會、五臘、八節、晦朔等日。",use:"Thực hành duyệt lục định kỳ, nghi thiên sư, lịch pháp đạo sĩ.",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%AD%A3%E4%B8%80%E9%96%B1%E7%B1%99%E5%84%80","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E6%AD%A3%E4%B8%80%E9%96%B1%E7%B1%99%E5%84%80"],textual_certainty:"high",notes:"batch28 · Grok-4.5 catalog-driven"},{dz:"DZ1217",name_han:"太上正一解五音咒詛秘籙",name_vi:"Thái Thượng chính nhất giải ngũ âm chú trở bí lục",bu:"正一",author:"佚名",era:"Trung cổ (thuộc hệ pháp lục Chính Nhất)",topic:"fu",essence:"Pháp lục chuyên giải trừ chú chú, ngũ âm oán độc và các loại trù yểm trong truyền thống Chính Nhất. Kết hợp danh hiệu thần binh, phù lục và nghi thức giải kết để hóa giải khẩu thiệt, tà chú. Thuộc nhánh pháp thuật trừ tà, hộ mệnh của chính nhất phù lục.",key_text:"太上正一解五音咒詛秘籙",use:"Giải chú, trừ oán độc, pháp lục trừ tà Chính Nhất.",sources:["https://a.daorenjia.com/c14","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch28 · Grok-4.5 catalog-driven"},{dz:"DZ801",name_han:"正一醮宅儀",name_vi:"Chính Nhất tiếu trạch nghi",bu:"洞神",author:"佚名",era:"Nam Bắc triều–Đường",topic:"ritual",essence:"Nghi tiếu tế nhà cửa theo pháp Chính Nhất: trị hư hao, ôn dịch, trùng thú quấy phá, phạm thổ. Lập đàn sân nhà, an vị ngũ phương, dâng cúng theo ngày vương tướng. Phản ánh thực hành an trạch, trấn trạch trong thiên sư đạo.",key_text:"凡人居宅虛耗，牛馬死失，田蠶不熟，人口嬰害……以四時王相日醮之吉。",use:"An trạch, tẩy uế nhà cửa, nghi tiếu dân gian–đạo giáo.",sources:["https://zh.daoinfo.org/index.php?title=%E6%AD%A3%E4%B8%80%E9%86%AE%E5%AE%85%E5%84%80","https://zh.wikisource.org/wiki/%E6%AD%A3%E4%B8%80%E9%86%AE%E5%AE%85%E5%84%80","https://www.shidianguji.com/zh/book/DZ0801"],textual_certainty:"high",notes:"batch28 · Grok-4.5 catalog-driven"},{dz:"DZ141",name_han:"紫陽真人悟真篇註疏",name_vi:"Tử Dương chân nhân Ngộ chân thiên chú sớ",bu:"洞真",author:"翁葆光注、戴起宗疏（張伯端原著）",era:"Tống–Nguyên",topic:"cultivation",essence:"Chú sớ quan trọng của phái Nam tông âm dương đối với Ngộ chân thiên. Ông Bảo Quang chia pháp thành ba thừa (luyện kim đan, vận hỏa kim dịch, cửu chuyển đại hoàn) theo ý Âm phù. Đái Khởi Tông làm sớ, biện ngụy chú và hệ thống hóa pháp tượng nội đan.",key_text:"上卷以煉金丹為強兵戰勝之術，中卷以運火金液丹為富國安民之法，下卷以九轉大還丹為神仙抱一之道。",use:"Nội đan Nam tông, chú giải Ngộ chân thiên, pháp âm dương.",sources:["https://zh.daoinfo.org/index.php?title=%E7%B4%AB%E9%99%BD%E7%9C%9F%E4%BA%BA%E6%82%9F%E7%9C%9F%E7%AF%87%E8%A8%BB%E7%96%8F","https://zh.wikisource.org/zh-hans/%E7%B4%AB%E9%99%BD%E7%9C%9F%E4%BA%BA%E6%82%9F%E7%9C%9F%E7%AF%87%E8%A8%BB%E7%96%8F","https://ctext.org/wiki.pl?if=gb&res=422440"],textual_certainty:"high",notes:"batch28 · Grok-4.5 catalog-driven"},{dz:"DZ142",name_han:"紫陽真人悟真篇三註",name_vi:"Tử Dương chân nhân Ngộ chân thiên tam chú",bu:"洞真",author:"薛道光、陸墅、陳致虛注（張士弘編）",era:"Nguyên",topic:"cultivation",essence:"Tập hợp ba nhà chú (Tuyết Đạo Quang, Lục Thự, Trần Trí Hư) về Ngộ chân thiên, thuộc hệ Nam tông âm dương. Giải thích dược vật, hỏa hầu, long hổ chì thủy ngân qua thơ từ của Trương Bá Đoan. Ảnh hưởng sâu đến nội đan Tống–Nguyên và các phái hậu thế.",key_text:"原題紫賢薛道光、子野陸墅、上陽子陳致虛注。",use:"Đối chiếu chú giải Ngộ chân, luyện đan Nam tông.",sources:["https://zh.daoinfo.org/index.php?title=%E7%B4%AB%E9%99%BD%E7%9C%9F%E4%BA%BA%E6%82%9F%E7%9C%9F%E7%AF%87%E4%B8%89%E8%A8%BB","https://www.shidianguji.com/book/DZ0142","https://ctext.org/wiki.pl?if=gb&res=956241"],textual_certainty:"high",notes:"batch28 · Grok-4.5 catalog-driven"},{dz:"DZ145",name_han:"悟真篇註釋",name_vi:"Ngộ chân thiên chú thích",bu:"洞真",author:"翁葆光（註）",era:"Nam Tống",topic:"cultivation",essence:"Bản chú riêng của Ông Bảo Quang (Vô Danh tử) cho Ngộ chân thiên, ba quyển. Làm rõ ẩn dụ long hổ, chì thủy, hỏa hầu và đường lối tiên mệnh hậu tính của Nam tông. Cùng hệ với chú sớ Đái Khởi Tông nhưng hình thức gọn, dễ dùng để đọc thơ đan.",key_text:"象川無名子翁葆光註。",use:"Đọc hiểu Ngộ chân thiên, khóa nội đan Nam tông.",sources:["https://www.shidianguji.com/book/DZ0145","https://ctext.org/wiki.pl?if=gb&res=433042"],textual_certainty:"high",notes:"batch28 · Grok-4.5 catalog-driven"},{dz:"DZ146",name_han:"紫陽真人悟真篇講義",name_vi:"Tử Dương chân nhân Ngộ chân thiên giảng nghĩa",bu:"洞真",author:"夏元鼎",era:"Nam Tống (khoảng 1226)",topic:"cultivation",essence:"Giảng nghĩa Ngộ chân thiên theo hướng tam giáo hợp nhất, dẫn Nho–Thích–Đạo để làm sáng tỏ tính mệnh song tu. Hạ Nguyên Đỉnh nhấn mạnh thể nghiệm nội chứng hơn là pháp tượng âm dương thuần túy. Bổ sung góc nhìn thanh tu–tâm tính trong dòng chú Nam tông.",key_text:"紫陽真人悟真篇講義",use:"Nội đan kết hợp tâm tính, giảng dạy Ngộ chân.",sources:["https://www.shidianguji.com/book/DZ0146","https://ctext.org/wiki.pl?if=gb&res=146461"],textual_certainty:"high",notes:"batch28 · Grok-4.5 catalog-driven"},{dz:"DZ1309",name_han:"海瓊傳道集",name_vi:"Hải Quỳnh truyền đạo tập",bu:"正一",author:"白玉蟾（洪知常編集）",era:"Nam Tống",topic:"cultivation",essence:"Tập truyền đạo của Bạch Ngọc Thiềm (Hải Quỳnh), do Hồng Tri Thường biên, gồm Kim đan tiệp kính, Câu tỏa liên hoàn kinh, Trinh sơn khoái hoạt ca… Trình bày đường tắt nội đan, hỏa hầu và khẩu quyết Nam tông ngũ tổ. Cùng hệ với các ngữ lục Hải Quỳnh nhưng tập trung pháp quyết luyện đan.",key_text:"金丹捷徑",use:"Nội đan Nam tông Bạch Ngọc Thiềm, khẩu quyết hỏa hầu.",sources:["https://baike.baidu.com/item/%E6%B5%B7%E7%90%BC%E4%BC%A0%E9%81%93%E9%9B%86/2296847","https://www.shidianguji.com/book/DZ1309","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT07%E6%AD%A3%E4%B9%99%E9%83%A8/CMT07-ALL/CH07117%E6%B5%B7%E7%93%8A%E5%82%B3%E9%81%93%E9%9B%86/CH07117-1%E6%B5%B7%E7%93%8A%E5%82%B3%E9%81%93%E9%9B%86.htm"],textual_certainty:"high",notes:"batch28 · Grok-4.5 catalog-driven"},{dz:"DZ707",name_han:"道德真經集註",name_vi:"Đạo đức chân kinh tập chú",bu:"洞神（太玄系老學）",author:"彭耜",era:"Nam Tống (紹定 1229)",topic:"philosophy",essence:"Tập chú Đạo Đức chân kinh của Bành Tự, gom khoảng hai mươi nhà chú đời Tống, lấy chú Tống Huy Tông làm đầu. Phản ánh lão học triều Tống (Tư Mã Quang, Tô Triệt, Vương An Thạch, Trần Cảnh Nguyên…). Bộ sưu tập then chốt cho nghiên cứu chú sớ Lão Tử thời Tống trong Đạo tạng.",key_text:"宋鶴林彭耜纂集。",use:"Lão học Tống, đối chiếu chú sớ Đạo Đức kinh, triết học Đạo giáo.",sources:["https://zh.daoinfo.org/index.php?title=%E9%81%93%E5%BE%B7%E7%9C%9F%E7%B6%93%E9%9B%86%E8%A8%BB%EF%BC%88%E5%BD%AD%E8%80%9C%EF%BC%89","https://ctext.org/wiki.pl?if=gb&res=381154","https://www.kanripo.org/text/KR5c0095/011"],textual_certainty:"high",notes:"batch28 · Grok-4.5 catalog-driven"},{dz:"DZ701",name_han:"道德真經口義",name_vi:"Đạo đức chân kinh khẩu nghĩa",bu:"洞神（太玄系老學）",author:"林希逸",era:"Nam Tống",topic:"philosophy",essence:"Khẩu nghĩa Đạo Đức chân kinh của Lâm Hy Dật, giải theo lối bạch thoại–nghĩa lý gần Nho, dễ hiểu. Có phát đề bàn về phân chương, mỗi chương lấy câu đầu làm đề. Tiêu biểu lão học Tống mang màu tân Nho, khác với hệ huyền học–trùng huyền thời Đường.",key_text:"道德真經口義發題",use:"Đọc Đạo Đức kinh lối nghĩa lý, lão học Tống–Nho.",sources:["https://www.shidianguji.com/book/DZ0701","https://zh.wikisource.org/wiki/%E9%81%93%E5%BE%B7%E7%9C%9F%E7%B6%93%E5%8F%A3%E7%BE%A9"],textual_certainty:"high",notes:"batch28 · Grok-4.5 catalog-driven"},{dz:"DZ1480",name_han:"許真君玉匣記",name_vi:"Hứa chân quân Ngọc hiệp ký",bu:"续道藏",author:"託名許遜（佚名編集）",era:"Minh (萬曆續道藏)",topic:"占验",essence:"Sách chọn ngày–chiêm nghiệm trong Tục Đạo tạng, thác danh Hứa Chân quân. Ghi ngày tốt xấu cho hôn sự, an táng, động thổ, xuất hành, tế tự và các sao hạn liên quan. Là đại diện loại phương thuật trạch nhật–lịch kỵ trong tạng ngoại–tục tạng, phục vụ thực hành dân gian–đạo quán.",key_text:"許真君玉匣記序",use:"Trạch nhật, lịch kỵ, chiêm nghiệm dân gian đạo giáo.",sources:["http://www.ctcwri.idv.tw/CTCW-CMTS/CMT08%E7%BA%8C%E9%81%93%E8%97%8F/CNDZ08ALL/CH0851%E8%A8%B1%E7%9C%9F%E5%90%9B%E7%8E%89%E5%8C%A3%E8%A8%98/CH0851-1%E8%A8%B1%E7%9C%9F%E5%90%9B%E7%8E%89%E5%8C%A3%E8%A8%98.htm","https://zh.wikisource.org/zh-hans/%E7%8E%89%E5%8C%A3%E8%A8%98","https://upload.wikimedia.org/wikipedia/commons/8/84/NLC892-411999007380-139373_%E7%BA%8C%E9%81%93%E8%97%8F_%E7%AC%AC151%E5%86%8A.pdf"],textual_certainty:"high",notes:"batch28 · Grok-4.5 catalog-driven"},{dz:"DZ089",name_han:"元始無量度人上品妙經通義",name_vi:"Nguyên Thủy Vô Lượng Độ Nhân Thượng Phẩm Diệu Kinh Thông Nghĩa",bu:"洞真",author:"張宇初",era:"明初（約14–15世紀）",topic:"classic",essence:"Tứ thập tam đại Thiên sư Trương Vũ Sơ chú giải *Độ nhân kinh*, thuộc hệ sớ giải Linh Bảo. Sách thông nghĩa kinh văn theo hướng giáo nghĩa chính thống, nối kết độ vong, tụng kinh và trật tự thiên giới. Là mắt xích quan trọng giữa truyền thống Độ nhân đời Tống–Nguyên và *Đạo tạng* Minh.",key_text:"元始祖劫，化生諸天，開明三景，是為天根。",use:"Đọc để nắm khung chú sớ Độ nhân thời Minh và tư tưởng giáo chủ chính nhất.",sources:["https://zh.wikisource.org/zh-hant/%E5%85%83%E5%A7%8B%E7%84%A1%E9%87%8F%E5%BA%A6%E4%BA%BA%E4%B8%8A%E5%93%81%E5%A6%99%E7%B6%93%E9%80%9A%E7%BE%A9","https://zh.daoinfo.org/index.php?title=%E5%85%83%E5%A7%8B%E7%84%A1%E9%87%8F%E5%BA%A6%E4%BA%BA%E4%B8%8A%E5%93%81%E5%A6%99%E7%B6%93%E9%80%9A%E7%BE%A9&variant=zh-hant"],textual_certainty:"high",notes:"batch29 · Grok-4.5 catalog-driven"},{dz:"DZ090",name_han:"元始無量度人上品妙經內義",name_vi:"Nguyên Thủy Vô Lượng Độ Nhân Thượng Phẩm Diệu Kinh Nội Nghĩa",bu:"洞真",author:"蕭應叟",era:"南宋（寶慶二年序，1226）",topic:"cultivation",essence:"Tiêu Ứng Tẩu (Thượng Thanh) lấy nội đan và *Dịch* học chú *Độ nhân kinh*. Xem Linh Bảo và Kim đan “đồng xuất dị danh”, gắn nguyên thủy, xích văn với hỏa hầu, chu thiên. Mở dòng “độ nhân nội đan giải”, ảnh hưởng mạnh các chú đời sau.",key_text:"靈寶、金丹同出而異名。",use:"Đối chiếu độ vong tụng kinh với hỏa hầu nội đan trong hệ Độ nhân.",sources:["https://zh.daoinfo.org/wiki/%E5%85%83%E5%A7%8B%E7%84%A1%E9%87%8F%E5%BA%A6%E4%BA%BA%E4%B8%8A%E5%93%81%E5%A6%99%E7%B6%93%E5%85%A7%E7%BE%A9","https://zh.wikisource.org/zh-hant/%E5%85%83%E5%A7%8B%E7%84%A1%E9%87%8F%E5%BA%A6%E4%BA%BA%E4%B8%8A%E5%93%81%E5%A6%99%E7%B6%93%E5%85%A7%E7%BE%A9","https://www.shidianguji.com/zh/book/DZ0090/chapter/DZ0090_1"],textual_certainty:"high",notes:"batch29 · Grok-4.5 catalog-driven"},{dz:"DZ147",name_han:"靈寶無量度人上品妙經符圖",name_vi:"Linh Bảo Vô Lượng Độ Nhân Thượng Phẩm Diệu Kinh Phù Đồ",bu:"洞真",author:"佚名（卷首有宋徽宗序）",era:"宋（約北宋末–南宋）",topic:"fu",essence:"Ba quyển phù đồ gắn *Độ nhân kinh*: hỗn động xích văn, cửu quang chi khí, các đồ thiên giới và phù dụng. Có ngự tự Tống Huy Tông, thuộc lớp linh đồ–phù lục của hệ vô lượng độ nhân. Bổ sung chiều “đồ–phù” cho dòng chú sớ văn bản.",key_text:"原夫華靈隱藹，藏三炁於鴻濛；神景含輝，濳萬真於至賾。",use:"Nghiên cứu phù đồ, linh đồ và nghi thức độ nhân đời Tống.",sources:["https://ctext.org/wiki.pl?if=gb&res=146479","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch29 · Grok-4.5 catalog-driven"},{dz:"DZ029",name_han:"元始天尊說梓潼帝君本願經",name_vi:"Nguyên Thủy Thiên Tôn Thuyết Tử Đồng Đế Quân Bản Nguyện Kinh",bu:"洞真",author:"佚名",era:"元",topic:"classic",essence:"Kinh thần kỳ Tử Đồng/Văn Xương: Nguyên Thủy Thiên Tôn thuyết bản nguyện, khuyên chính tâm, tam cương ngũ thường để tiêu kiếp. Ba chương tiêu kiếp–chính tâm–báo ứng, gắn đạo đức Nho với tín ngưỡng Văn Xương trong *Đạo tạng*.",key_text:"爾時元始天尊在清微天宮黃金闕內。",use:"Tín ngưỡng Văn Xương–Tử Đồng; đạo đức hóa kiếp nạn.",sources:["https://zh.wikisource.org/wiki/%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E6%A2%93%E6%BD%BC%E5%B8%9D%E5%90%9B%E6%9C%AC%E9%A1%98%E7%B6%93","https://zh.daoinfo.org/wiki/%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E6%A2%93%E6%BD%BC%E5%B8%9D%E5%90%9B%E6%9C%AC%E9%A1%98%E7%B6%93","https://dao.crs.cuhk.edu.hk/Main/wp-content/uploads/2018/08/DAO6_07_Vincent-Goossaert.pdf"],textual_certainty:"high",notes:"batch29 · Grok-4.5 catalog-driven"},{dz:"DZ170",name_han:"梓潼帝君化書",name_vi:"Tử Đồng Đế Quân Hóa Thư",bu:"洞真",author:"佚名（託梓潼帝君自述）",era:"元（延祐前後）",topic:"仙传",essence:"Bốn quyển “hóa thư” tự thuật nhiều kiếp Tử Đồng Đế Quân, từ nguyên mệnh đến hiển linh, thăng chức thiên giới. Vừa là thần thoại Văn Xương vừa là mô hình tích đức–thăng trật. Nguồn chính cho tín ngưỡng Văn Xương trong chính thống *Đạo tạng*.",key_text:"化有二理，有變化之化，有教化之化。",use:"Thần phổ Văn Xương; nghiên cứu giáng bút và thần tích dân gian–quan phương.",sources:["https://zh.wikisource.org/zh-hans/%E6%A2%93%E6%BD%BC%E5%B8%9D%E5%90%9B%E5%8C%96%E6%9B%B8","https://zh.daoinfo.org/index.php?title=%E6%A2%93%E6%BD%BC%E5%B8%9D%E5%90%9B%E5%8C%96%E6%9B%B8&variant=zh-hant","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch29 · Grok-4.5 catalog-driven"},{dz:"DZ188",name_han:"玄都律文",name_vi:"Huyền Đô Luật Văn",bu:"洞真",author:"佚名",era:"南北朝末（約6世紀；今殘一卷）",topic:"戒律",essence:"Luật lệ Huyền Đô: thiện ác báo ứng, phạt toán, nghi phục sắc, thụ lục tuổi tác. Bản *Đạo tạng* chỉ còn tàn một quyển; từng được *Tam động châu nang*, *Yếu tu khoa nghi* trích dẫn. Xương sống luật học đạo sĩ trung cổ.",key_text:"律曰：道士、女官、籙生，身年十八已上，得受大法。",use:"Đối chiếu giới luật, phạt toán, phục sắc và thứ bậc thụ pháp.",sources:["https://zh.wikisource.org/wiki/%E7%8E%84%E9%83%BD%E5%BE%8B%E6%96%87","https://zh.daoinfo.org/index.php?title=%E7%8E%84%E9%83%BD%E5%BE%8B%E6%96%87&variant=zh-hant","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch29 · Grok-4.5 catalog-driven"},{dz:"DZ463",name_han:"要修科儀戒律鈔",name_vi:"Yếu Tu Khoa Nghi Giới Luật Sao",bu:"洞玄",author:"朱法滿（朱君緒）",era:"唐前期（卒開元八年/720）",topic:"类书",essence:"Mười sáu quyển sao lục khoa nghi–giới luật từ *Thái chân khoa*, *Thăng huyền*, *Bản tế*… Hệ thống truyền kinh, viết kinh, thọ trì, trai giới. Bách khoa thực dụng cho đạo sĩ Đường, cầu nối kinh điển và nghi thức.",key_text:"原題三洞道士朱法滿撰。",use:"Tra cứu nghi thức, giới điều và quy trình truyền kinh đời Đường.",sources:["https://zh.daoinfo.org/index.php?title=%E8%A6%81%E4%BF%AE%E7%A7%91%E5%84%80%E6%88%92%E5%BE%8B%E9%88%94&variant=zh-hant","https://ctext.org/wiki.pl?if=gb&res=100832","https://fabriziopregadio.com/files/PREGADIO_and_ESPOSITO_Daozang_jiyao_Catalogue.pdf"],textual_certainty:"high",notes:"batch29 · Grok-4.5 catalog-driven"},{dz:"DZ750",name_han:"太上玄靈北斗本命延生真經註",name_vi:"Thái Thượng Huyền Linh Bắc Đẩu Bản Mệnh Diên Sinh Chân Kinh Chú",bu:"洞神",author:"徐道齡（徐道玄校正）",era:"元統二年（1334）",topic:"ritual",essence:"Chú *Bắc đẩu bản mệnh kinh*: trai giới, nội luyện, phù chú; gắn tinh quân bản mệnh với họa phúc, tiêu tai diên sinh. Có đề từ Tử Đồng Đế Quân và chân phù. Cầu nối kinh sao–bản mệnh với thực hành dân gian–đạo quán.",key_text:"凡人性命五體，悉屬本命星官之所主掌。",use:"Tụng Bắc đẩu, bái bản mệnh, giải nghĩa kinh sao.",sources:["https://www.shidianguji.com/zh/book/DZ0750","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E7%8E%84%E9%9D%88%E5%8C%97%E6%96%97%E6%9C%AC%E5%91%BD%E5%BB%B6%E7%94%9F%E7%9C%9F%E7%B6%93%E8%A8%BB","https://ctext.org/wiki.pl?if=gb&res=128937"],textual_certainty:"high",notes:"batch29 · Grok-4.5 catalog-driven"},{dz:"DZ1048",name_han:"玄珠錄",name_vi:"Huyền Châu Lục",bu:"太玄",author:"王玄覽述；王太霄編",era:"唐",topic:"philosophy",essence:"Ngữ lục Trùng huyền: đạo–vật, tâm–cảnh, chân–vọng, tịch–động. “Tâm sinh chư pháp sinh”; đạo thể thường tịch mà ứng vật. Hóa Phật học vào đạo thể, là văn bản then chốt cho tư tưởng Trùng huyền đời Đường.",key_text:"心生諸法生，心滅諸法滅。",use:"Đọc triết học Trùng huyền và tâm tính học Đường.",sources:["https://ctext.org/wiki.pl?if=gb&res=955213","https://baike.baidu.com/item/%E7%8E%84%E7%8F%A0%E5%BD%95/9681146","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch29 · Grok-4.5 catalog-driven"},{dz:"DZ1052",name_han:"宗玄先生玄綱論",name_vi:"Tông Huyền Tiên Sinh Huyền Cương Luận",bu:"太玄",author:"吳筠",era:"唐（天寶間進表）",topic:"philosophy",essence:"Ngô Quân tóm “huyền cương”: đạo sinh người, đạo đức, tu tiên khả học. Ba thiên dâng Đường Huyền Tông; vừa triết vừa tu luyện. Đại diện tư tưởng Thượng Thanh–trùng huyền trí thức đời Đường.",key_text:"道者何也？虛無之系，造化之根，神明之本，天地之源。",use:"Nắm khung đạo luận và tu tiên khả học đời Đường.",sources:["https://www.shidianguji.com/zh/book/DZ1052","https://zh.wikisource.org/zh-hant/%E7%8E%84%E7%B6%B1%E8%AB%96","https://purplecloudinstitute.com/wp-content/uploads/2023/08/Daoist-Texts-in-Western-Languages-%C2%A9-Purple-Cloud-Press-2023.pdf"],textual_certainty:"high",notes:"batch29 · Grok-4.5 catalog-driven"},{dz:"DZ1059",name_han:"盤山棲雲王真人語錄",name_vi:"Bàn Sơn Thê Vân Vương Chân Nhân Ngữ Lục",bu:"太玄",author:"王志謹述；論志煥編",era:"金末元初（約1247）",topic:"cultivation",essence:"Ngữ lục Toàn Chân phái Bàn Sơn: luyện tâm, thanh tĩnh, đối cảnh vô tâm. Lấy *Thanh tĩnh kinh*, pha Thiền; nhấn khổ kỷ lợi tha, tích công hành. Nguồn sống động cho tâm tính Toàn Chân thế kỷ XIII.",key_text:"心不逐物，謂之安心；心不愛物，謂之虛心。心安而虛，便是清靜，清靜便是道。",use:"Tu tâm Toàn Chân; đối cảnh bất động tâm.",sources:["https://zh.daoinfo.org/index.php?title=%E7%9B%A4%E5%B1%B1%E6%A3%B2%E9%9B%B2%E7%8E%8B%E7%9C%9F%E4%BA%BA%E8%AA%9E%E9%8C%84&variant=zh-hant","https://www.mdpi.com/2077-1444/14/6/814","https://fabriziopregadio.com/files/PREGADIO_and_ESPOSITO_Daozang_jiyao_Catalogue.pdf"],textual_certainty:"high",notes:"batch29 · Grok-4.5 catalog-driven"},{dz:"DZ1128",name_han:"道門經法相承次序",name_vi:"Đạo Môn Kinh Pháp Tương Thừa Thứ Tự",bu:"太平",author:"佚名（載唐高宗問道潘師正）",era:"唐",topic:"类书",essence:"Tiểu loại thư: tam nguyên, tam khí, tam động, thất bộ, tam thập lục bộ, tam giới–tam thanh–Đại La. Dạng vấn đáp Cao Tông–Phan Sư Chính. Bản đồ cấu trúc giáo điển và vũ trụ quan đạo giáo trung cổ.",key_text:"第一洞真為大乘，第二洞玄為中乘，第三洞神為小乘。",use:"Hiểu phân loại tam động tứ phụ và thứ bậc kinh pháp.",sources:["https://zh.wikisource.org/zh-hant/%E9%81%93%E9%96%80%E7%B6%93%E6%B3%95%E7%9B%B8%E6%89%BF%E6%AC%A1%E5%BA%8F","https://zh.daoinfo.org/index.php?title=%E9%81%93%E9%96%80%E7%B6%93%E6%B3%95%E7%9B%B8%E6%89%BF%E6%AC%A1%E5%BA%8F&variant=zh-hant","https://www.shidianguji.com/book/DZ1128/chapter/1jld4bxmxuofn"],textual_certainty:"high",notes:"batch29 · Grok-4.5 catalog-driven"},{dz:"DZ1132",name_han:"上清道類事相",name_vi:"Thượng Thanh Đạo Loại Sự Tướng",bu:"太平",author:"王懸河",era:"唐（約680s）",topic:"类书",essence:"Loại thư Thượng Thanh của Vương Huyền Hà (cùng hệ *Tam động châu nang*): phân loại sự tướng, phẩm mục đạo pháp–thần tiên. Bảo tồn trích đoạn cổ kinh, là công cụ tra cứu thực hành và thuật ngữ Đường sơ.",key_text:"大唐陸海羽客王懸河修。",use:"Tra cứu loại mục Thượng Thanh và trích dẫn cổ kinh.",sources:["https://www.jstor.org/stable/26768560","http://iwr.cass.cn/rjyjs/lw/200912/t20091230_3111452.shtml"],textual_certainty:"high",notes:"batch29 · Grok-4.5 catalog-driven"},{dz:"DZ1140",name_han:"雲山集",name_vi:"Vân Sơn Tập",bu:"太平",author:"姬志真",era:"元初",topic:"cultivation",essence:"Thi văn tập Toàn Chân Cơ Chí Chân: phú, thi từ, bi ký. Tuyên tu tâm, ẩn thế, tính mệnh, dung Nho–Thích–Đạo. Gương mặt văn học–đạo học Toàn Chân thế kỷ XIII.",key_text:"出為生而入為死，靜乃性而動乃心。",use:"Đọc thi đạo Toàn Chân và tâm tính qua văn học.",sources:["https://www.shidianguji.com/zh/book/DZ1140/chapter/1k1rvj1arhmor","https://zh.daoinfo.org/index.php?title=%E9%9B%B2%E5%B1%B1%E9%9B%86&variant=zh-hant","https://ctext.org/wiki.pl?if=gb&res=264346"],textual_certainty:"high",notes:"batch29 · Grok-4.5 catalog-driven"},{dz:"DZ1149",name_han:"洞玄金玉集",name_vi:"Động Huyền Kim Ngọc Tập",bu:"太平",author:"馬鈺（馬丹陽）",era:"金",topic:"cultivation",essence:"Mười quyển thi từ Mã Đan Dương: đoạn duyên, thanh tĩnh, tính mệnh song tu, khổ hạnh lợi người. Văn học giáo hóa Toàn Chân đời Kim, bổ sung cho ngữ lục và các tập đã biết của thất chân.",key_text:"命清得長生，性靜能久視，神氣相合，乃超生死。",use:"Nghiên cứu tu luyện và thi giáo Toàn Chân qua Mã钰.",sources:["https://www.shidianguji.com/zh/book/DZ1149/chapter/1jld5903r4coi","https://ctext.org/wiki.pl?if=gb&res=104555","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch29 · Grok-4.5 catalog-driven"},{dz:"DZ1310",name_han:"清和真人北遊語錄",name_vi:"Thanh Hòa Chân Nhân Bắc Du Ngữ Lục",bu:"正一",author:"尹志平述；段志堅編",era:"元（約1230s）",topic:"cultivation",essence:"Ngữ lục Doãn Chí Bình khi bắc du: so sánh pháp môn Đan Dương–Trường Sinh–Trường Xuân; trọng thực công thực hành, trước hữu vi sau vô vi. Ghi nhận chuyển hướng “tích công hành, khổ kỷ tế thế” của phái Khâu Xử Cơ.",key_text:"丹陽師父以無為主教，長生真人無為有為相半。至長春師父，有為十之九，無為雖有其一，猶存而勿用焉。",use:"Hiểu chiến lược tu–hành Toàn Chân sau Khâu Xử Cơ.",sources:["https://zh.daoinfo.org/index.php?title=%E6%B8%85%E5%92%8C%E7%9C%9F%E4%BA%BA%E5%8C%97%E9%81%8A%E8%AA%9E%E9%8C%84&variant=zh-hant","https://zh.wikisource.org/wiki/%E6%B8%85%E5%92%8C%E7%9C%9F%E4%BA%BA%E5%8C%97%E9%81%8A%E8%AA%9E%E9%8C%84","https://fabriziopregadio.com/files/PREGADIO_and_ESPOSITO_Daozang_jiyao_Catalogue.pdf"],textual_certainty:"high",notes:"batch29 · Grok-4.5 catalog-driven"},{dz:"DZ402",name_han:"黃庭內景玉經註",name_vi:"Hoàng Đình Nội Cảnh Ngọc Kinh Chú",bu:"洞玄",author:"梁丘子（白履忠）",era:"唐（约8世纪）",topic:"cultivation",essence:"Chú giải kinh điển Thượng Thanh về nội cảnh thân thần và tam đơn điền. Lương Khâu Tử giải 'nội giả tâm dã, cảnh giả tượng dã', chỉ cách tồn tư tạng phủ, luyện hồn phách để trường sinh. Đây là chú bản Hoàng Đình Nội Cảnh độc lập quan trọng nhất trong Chính Thống Đạo Tạng.",key_text:"內者，心也。景者，象也。",use:"Nền tảng tồn tư tạng thần, luyện khí Hoàng Đình; tham chiếu khi đọc Nội Cảnh Kinh.",sources:["https://zh.wikisource.org/wiki/%E9%BB%83%E5%BA%AD%E5%85%A7%E6%99%AF%E7%8E%89%E7%B6%93%E8%A8%BB_(%E6%A2%81%E4%B8%98%E5%AD%90)","https://zh.daoinfo.org/index.php?title=%E9%BB%83%E5%BA%AD%E5%85%A7%E6%99%AF%E7%8E%89%E7%B6%93%E6%B3%A8%EF%BC%88%E6%A2%81%E4%B8%98%E5%AD%90%EF%BC%89","https://ctext.org/library.pl?if=gb&res=84065"],textual_certainty:"high",notes:"batch30 · Grok-4.5 catalog-driven"},{dz:"DZ401",name_han:"黃庭內景玉經注",name_vi:"Hoàng Đình Nội Cảnh Ngọc Kinh Chú (Lưu Trường Sinh)",bu:"洞玄",author:"劉處玄（劉長生）",era:"金（12世纪末）",topic:"cultivation",essence:"Chú giải Hoàng Đình Nội Cảnh theo hướng Toàn Chân, nhấn mạnh tâm tính và nội đan hơn là thuần tồn thần tạng phủ. Lưu Xử Huyền (Trường Sinh) đọc kinh qua lăng kính 'chân tính', nối truyền thống Thượng Thanh với tu trì Toàn Chân. Một quyển, thu vào Động Huyền bộ Ngọc quyết loại.",key_text:"夫萬物以人為主，人以一心為宗。",use:"Đối chiếu chú Hoàng Đình thời Đường với cách đọc nội đan Toàn Chân; luyện tâm định.",sources:["https://zh.daoinfo.org/index.php?title=%E9%BB%83%E5%BA%AD%E5%85%A7%E6%99%AF%E7%8E%89%E7%B6%93%E6%B3%A8%EF%BC%88%E5%8A%89%E9%95%B7%E7%94%9F%EF%BC%89","https://www.jstor.org/stable/26768560","https://www.shidianguji.com/book/DZ0401/chapter/DZ0401_26"],textual_certainty:"high",notes:"batch30 · Grok-4.5 catalog-driven"},{dz:"DZ110",name_han:"黃帝陰符經疏",name_vi:"Hoàng Đế Âm Phù Kinh Sớ",bu:"洞真",author:"李筌（题；今本或含宋人编次）",era:"唐 / 宋传本",topic:"philosophy",essence:"Sớ giải Âm Phù Kinh chia ba chương: thần tiên bão nhất (đạo), phú quốc an dân (pháp), cường binh chiến thắng (thuật). Kể chuyện Lý Thuyên gặp Lệ Sơn lão mẫu giải kinh, nhấn 'quan thiên chi đạo, chấp thiên chi hành'. Bản Đạo Tạng là sớ bản ảnh hưởng lớn nhất thời trung đại.",key_text:"觀天之道，執天之行，盡矣。",use:"Giải nghĩa Âm Phù theo thiên cơ–nhân sự; tham khảo binh đạo, chính trị và tu tiên.",sources:["https://zh.wikisource.org/zh-hans/%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93%E7%96%8F","https://ctext.org/wiki.pl?if=gb&res=640834","https://wesleyac.com/dao/refs/komjathy2008.pdf"],textual_certainty:"high",notes:"batch30 · Grok-4.5 catalog-driven"},{dz:"DZ112",name_han:"黃帝陰符經註（張果）",name_vi:"Hoàng Đế Âm Phù Kinh Chú (Trương Quả)",bu:"洞真",author:"張果",era:"唐（玄宗朝）",topic:"philosophy",essence:"Chú của Trương Quả (Trương Quả Lão) phản bác chú 'giả thác yêu vu' của Lý Thuyên, chú trọng cơ biến tự nhiên và thể thiên dụng đạo. Dùng bản kinh dài hơn (~400 chữ), ảnh hưởng mạnh truyền bản đời sau. Thu Động Chân bộ Ngọc quyết loại.",key_text:"《陰符》自黃帝有之，蓋聖人體天用道之機也。",use:"Đối chiếu với sớ Lý Thuyên; học 'cơ' trong Âm Phù theo hướng đạo thuật thanh tịnh.",sources:["https://zh.wikisource.org/zh-hans/%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93%E8%A8%BB(%E5%BC%B5%E6%9E%9C)","https://zh.daoinfo.org/index.php?title=%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93%E6%B3%A8%EF%BC%88%E5%BC%B5%E6%9E%9C%EF%BC%89","https://fabriziopregadio.com/files/PREGADIO_and_ESPOSITO_Daozang_jiyao_Catalogue.pdf"],textual_certainty:"high",notes:"batch30 · Grok-4.5 catalog-driven"},{dz:"DZ108",name_han:"黃帝陰符經集註",name_vi:"Hoàng Đế Âm Phù Kinh Tập Chú",bu:"洞真",author:"题伊尹、太公、范蠡、鬼谷子、張良、諸葛亮、李筌等七家",era:"唐至宋（集注本）",topic:"philosophy",essence:"Tập chú bảy nhà, hợp binh pháp, mưu lược và đạo thuật giải Âm Phù. Không phải một tác giả, mà là hợp biên chú cổ được Đạo Tạng bảo tồn. Cho thấy kinh được đọc đa chiều: dưỡng sinh, trị quốc và chiến lược.",key_text:"天有五賊，見之者昌。",use:"So sánh các lớp chú giải cổ; nghiên cứu tiếp nhận Âm Phù trong đạo–binh–nho.",sources:["https://www.shidianguji.com/book/DZ0108","https://www.jstor.org/stable/26768560","https://crta.info/wiki/Daozang_-_DZ"],textual_certainty:"high",notes:"batch30 · Grok-4.5 catalog-driven"},{dz:"DZ127",name_han:"黃帝陰符經集解",name_vi:"Hoàng Đế Âm Phù Kinh Tập Giải (Viên Thục Chân)",bu:"洞真",author:"袁淑真",era:"北宋",topic:"philosophy",essence:"Tập giải ba quyển của Viên Thục Chân, dựa kinh 300 chữ hệ Lý Thuyên, chia thượng–trung–hạ thuật bản chỉ rồi sớ chi tiết. Tự tự nói 'y tam chương yếu nghĩa', hệ thống hóa diễn đạo–diễn pháp–diễn thuật. Bản Đạo Tạng hợp nhất thành một quyển.",key_text:"陰，暗也。符，合也。天機暗合於行事之機，故曰陰符。",use:"Đọc sâu cấu trúc ba chương Âm Phù; nghiên cứu chú giải Tống.",sources:["https://www.jstor.org/stable/26768560","https://www.shidianguji.com/book/DZ0127","https://zh.wikisource.org/zh-hans/%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93%E7%96%8F"],textual_certainty:"high",notes:"batch30 · Grok-4.5 catalog-driven"},{dz:"DZ125",name_han:"黃帝陰符經註（俞琰）",name_vi:"Hoàng Đế Âm Phù Kinh Chú (Du Diễm)",bu:"洞真",author:"俞琰",era:"元（13–14世纪）",topic:"cultivation",essence:"Chú nội đan của Du Diễm (người chú Chu Dịch Tham Đồng Khế nổi tiếng). Đọc Âm Phù như mật chỉ kim đan: thiên cơ là hỏa hậu, ngũ tặc là ngũ hành trong thân. Cầu nối kinh điển Đường–Tống với luyện đan đời Nguyên.",key_text:"觀天之道，執天之行，盡矣。",use:"Nội đan giải Âm Phù; đối chiếu với chú Trương Quả và sớ Lý Thuyên.",sources:["https://fabriziopregadio.com/files/PREGADIO_Dictionary_of_Taoist_Internal_Alchemy_SAMPLE.pdf","https://www.jstor.org/stable/26768560","https://crta.info/wiki/Daozang_-_DZ"],textual_certainty:"high",notes:"batch30 · Grok-4.5 catalog-driven"},{dz:"DZ759",name_han:"太上老君說常清靜經註（杜光庭）",name_vi:"Thái Thượng Lão Quân Thuyết Thường Thanh Tĩnh Kinh Chú (Đỗ Quang Đình)",bu:"洞神",author:"杜光庭",era:"唐末五代",topic:"cultivation",essence:"Chú bản sớm nhất còn lại của Thanh Tĩnh Kinh. Đỗ Quang Đình lấy nguyên khí giải 'thanh tĩnh', dung hợp trùng huyền và tu tâm. Kinh ngắn nhưng là khóa tụng nhật khóa Toàn Chân; chú này định hình cách đọc đời sau.",key_text:"清者元也，靜者氣也，經則法也。",use:"Nhật khóa tụng kinh; học tâm pháp thanh tĩnh và giải cấu trúc kinh.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E5%B8%B8%E6%B8%85%E9%9D%9C%E7%B6%93%E8%A8%BB%EF%BC%88%E6%9D%9C%E5%85%89%E5%BA%AD%EF%BC%89","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E5%B8%B8%E6%B8%85%E9%9D%9C%E7%B6%93%E6%9D%9C%E5%85%89%E5%BA%AD%E8%A8%BB","https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf"],textual_certainty:"high",notes:"batch30 · Grok-4.5 catalog-driven"},{dz:"DZ755",name_han:"太上老君說常清靜經註（李道純）",name_vi:"Thái Thượng Lão Quân Thuyết Thường Thanh Tĩnh Kinh Chú (Lý Đạo Thuần)",bu:"洞神",author:"李道純",era:"元（约13世纪末）",topic:"cultivation",essence:"Chú Toàn Chân–nội đan của Lý Đạo Thuần (Thanh Am), nối Thanh Tĩnh với 'hư vô' và đan đạo. Cùng hệ chú với Trung Hòa Tập, nhấn 'tâm tĩnh thì thiên địa quy'. Một trong các chú đời Nguyên được trích dẫn nhiều nhất.",key_text:"大道無形，生育天地；大道無情，運行日月。",use:"Tu tâm thanh tĩnh kết hợp nội đan; khóa tụng và lý giải nhật khóa.",sources:["https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf","https://wesleyac.com/dao/refs/komjathy2008.pdf","https://fabriziopregadio.com/files/PREGADIO_and_ESPOSITO_Daozang_jiyao_Catalogue.pdf"],textual_certainty:"high",notes:"batch30 · Grok-4.5 catalog-driven"},{dz:"DZ758",name_han:"太上老君說常清靜經註（侯善淵）",name_vi:"Thái Thượng Lão Quân Thuyết Thường Thanh Tĩnh Kinh Chú (Hầu Thiện Uyên)",bu:"洞神",author:"侯善淵",era:"金–元（约1200前后）",topic:"cultivation",essence:"Chú của Hầu Thiện Uyên thuộc dòng Toàn Chân phương Bắc, giải kinh theo chân tính–chân mệnh. Cùng nhóm chú DZ755–759, cho thấy Thanh Tĩnh Kinh trở thành kinh tâm của đạo sĩ đời Kim–Nguyên. Một quyển, Động Thần bộ Ngọc quyết.",key_text:"人能常清靜，天地悉皆歸。",use:"Luyện định thanh tĩnh; so sánh chú Toàn Chân các thế hệ.",sources:["https://www.jstor.org/stable/26768560","https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E5%B8%B8%E6%B8%85%E9%9D%9C%E7%B6%93"],textual_certainty:"high",notes:"batch30 · Grok-4.5 catalog-driven"},{dz:"DZ485",name_han:"金籙大齋啟盟儀",name_vi:"Kim Lục Đại Trai Khải Minh Nghi",bu:"洞玄",author:"不题撰人（宋科仪系统，或经杨杰、张商英等改编）",era:"宋",topic:"ritual",essence:"Nghi thức mở minh thệ khi lập Kim Lục đại trai—trai pháp cấp quốc gia, vì vua và thiên hạ. Trình bày thứ tự lập đàn, thệ ước, phân phẩm trai pháp (nội/ngoại). Thuộc nhóm khoa nghi Kim Lục trong Động Huyền bộ Oai nghi loại.",key_text:"建齋行道，威儀肅列於三元；分任設官，俯仰聿符於四極。",use:"Tham chiếu nghi Kim Lục; nghiên cứu trai đàn quốc gia và phân chức đạo sĩ.",sources:["https://zh.daoinfo.org/index.php?title=%E9%87%91%E7%B1%99%E5%A4%A7%E9%BD%8B%E5%95%9F%E7%9B%9F%E5%84%80","https://zh.wikisource.org/zh-hans/%E9%87%91%E7%B1%99%E5%A4%A7%E9%BD%8B%E5%95%9F%E7%9B%9F%E5%84%80","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch30 · Grok-4.5 catalog-driven"},{dz:"DZ490",name_han:"金籙設醮儀",name_vi:"Kim Lục Thiết Giao Nghi",bu:"洞玄",author:"不题撰人",era:"宋–明科仪传本",topic:"ritual",essence:"Nghi thiết giao (cúng tế) thuộc hệ Kim Lục, dùng sau khi hành trai để tạ thần. Cùng nhóm với giải đàn, phóng sinh, triều nghi Kim Lục. Phản ánh chuẩn hóa khoa nghi triều đình và đạo quán đời Tống–Minh.",key_text:"金籙設醮，告謝真靈，以報生成之德。",use:"Nghi giao tạ sau trai; so sánh với Hoàng Lục và Ngọc Lục.",sources:["https://crta.info/wiki/Daozang_-_DZ","https://www.jstor.org/stable/26768560","https://zh.daoinfo.org/index.php?title=%E9%87%91%E7%B1%99%E9%86%AE%E5%84%80"],textual_certainty:"high",notes:"batch30 · Grok-4.5 catalog-driven"},{dz:"DZ530",name_han:"洞玄靈寶玉籙簡文三元威儀自然真經",name_vi:"Động Huyền Linh Bảo Ngọc Lục Giản Văn Tam Nguyên Oai Nghi Tự Nhiên Chân Kinh",bu:"洞玄",author:"古灵宝经（东晋末–南朝初；陆修静《灵宝经目》已著录）",era:"东晋–南朝",topic:"ritual",essence:"Cổ Linh Bảo kinh về oai nghi tam nguyên, còn lại chủ yếu thiên Trung Nguyên Ngọc Lục. Quy định nghi phụng sư, tư kinh sư–tịch sư–độ sư, nguyện độ thất tổ. Nền tảng phân Kim Lục / Ngọc Lục / Hoàng Lục trong trai pháp Linh Bảo.",key_text:"中元玉籙簡文神仙品曰：奉師威儀，思經師，禮拜畢，次思籍師所在之方。",use:"Nghi truyền thụ và phụng sư; hiểu cấu trúc tam lục trai pháp.",sources:["https://zh.wikisource.org/zh-hans/%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E7%8E%89%E7%B1%99%E7%B0%A1%E6%96%87%E4%B8%89%E5%85%83%E5%A8%81%E5%84%80%E8%87%AA%E7%84%B6%E7%9C%9F%E7%B6%93","https://zh.daoinfo.org/index.php?title=%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E7%8E%89%E7%B1%99%E7%B0%A1%E6%96%87%E4%B8%89%E5%85%83%E5%A8%81%E5%84%80%E8%87%AA%E7%84%B6%E7%9C%9F%E7%B6%93","https://ctext.org/wiki.pl?if=gb&chapter=173204"],textual_certainty:"high",notes:"batch30 · Grok-4.5 catalog-driven"},{dz:"DZ1440",name_han:"皇經集註",name_vi:"Hoàng Kinh Tập Chú",bu:"续道藏",author:"周玄真（周玄貞）集註",era:"明",topic:"classic",essence:"Tập chú Ngọc Hoàng Bản Hành Tập Kinh (Hoàng Kinh), mười quyển, thuộc Vạn Lịch Tục Đạo Tạng. Hệ thống hóa văn bản, chú giải công đức tụng Ngọc Hoàng và thần học Ngọc Đế. Là chú bản Hoàng Kinh quan trọng nhất trong Đạo Tạng mở rộng.",key_text:"高上玉皇本行集經，乃諸天之主宰、萬聖之師宗。",use:"Tụng và giải Ngọc Hoàng Kinh; nghiên cứu tín ngưỡng Ngọc Đế đời Minh.",sources:["https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf","https://crta.info/wiki/Daozang_-_DZ","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch30 · Grok-4.5 catalog-driven"},{dz:"DZ1441",name_han:"元始天尊說東嶽化身濟生度死拔罪解冤保命玄範誥呪妙經",name_vi:"Nguyên Thủy Thiên Tôn Thuyết Đông Nhạc Hóa Thân Tế Sinh Độ Tử Bạt Tội Giải Oan Bảo Mệnh Huyền Phạm Cáo Chú Diệu Kinh",bu:"续道藏",author:"不题撰人",era:"明（万历续道藏）",topic:"民间信仰",essence:"Kinh–chú về Đông Nhạc Đại Đế: hóa thân tế sinh, độ tử, bạt tội, giải oan, bảo mệnh. Kết hợp huyền phạm và cáo chú, phục vụ tín ngưỡng Thái Sơn–Đông Nhạc trong dân gian và khoa nghi. Thuộc Tục Đạo Tạng, phản ánh thần học núi thiêng đời Minh.",key_text:"東嶽化身，濟生度死，拔罪解冤，保命延生。",use:"Cúng Đông Nhạc / Thái Sơn; giải oan độ vong và bảo mệnh dân gian.",sources:["https://crta.info/wiki/Daozang_-_DZ","https://www.jstor.org/stable/26768560","https://www.persee.fr/doc/asie_0766-1177_2017_num_26_1_1492"],textual_certainty:"high",notes:"batch30 · Grok-4.5 catalog-driven"},{dz:"DZ1476",name_han:"搜神記",name_vi:"Sưu Thần Ký（Đạo Tạng bản）",bu:"续道藏",author:"不题撰人（明代神谱类编，非干宝志怪原书）",era:"明（万历续道藏）",topic:"仙传",essence:"Phả lục thần linh sáu quyển trong Tục Đạo Tạng, khác Sưu Thần Ký của Can Bảo. Ghi tiểu sử và chức năng nhiều thần dân gian–đạo giáo (quan thánh, thành hoàng, tài thần, nhạc thần…). Nguồn tra cứu tín ngưỡng phổ thông đời Minh trong canon.",key_text:"神之興也，本乎天地；靈之著也，應乎人心。",use:"Tra thần phổ dân gian; đối chiếu Quan Đế, tài thần, nhạc thần với khoa nghi.",sources:["https://crta.info/wiki/Daozang_-_DZ","https://www.jstor.org/stable/26768560","https://blackmoonharbor.com/uploads/1/1/5/3/115363763/daoist_texts_in_translation._komjathy.pdf"],textual_certainty:"high",notes:"batch30 · Grok-4.5 catalog-driven"},{dz:"DZ149",name_han:"修真太極混元圖",name_vi:"Tu Chân Thái Cực Hỗn Nguyên Đồ",bu:"洞真",author:"蕭道存",era:"宋",topic:"cultivation",essence:"Sách đồ giải nội đan thời Tống, lấy hình Thái Cực–Hỗn Nguyên để chỉ đường luyện kim đan. Nhấn mạnh khí hóa ngũ tạng, phối âm dương và hỏa hầu theo đồ. Thuộc hệ sơ đồ tu chân gắn với truyền thừa Hoa Dương/thiên Thai.",key_text:"今作是圖，私自生歡。",use:"Đối chiếu sơ đồ khí huyết–đan điền khi học nội đan Nam Tông; tra hỏa hầu theo tháng.",sources:["https://zh.daoinfo.org/index.php?title=%E4%BF%AE%E7%9C%9F%E5%A4%AA%E6%A5%B5%E6%B7%B7%E5%85%83%E5%9C%96","https://www.shidianguji.com/zh/book/DZ0149","https://ctext.org/wiki.pl?if=gb&res=163685"],textual_certainty:"high",notes:"batch31 · Grok-4.5 catalog-driven"},{dz:"DZ150",name_han:"修真太極混元指玄圖",name_vi:"Tu Chân Thái Cực Hỗn Nguyên Chỉ Huyền Đồ",bu:"洞真",author:"不著撰人（宋）",era:"宋",topic:"cultivation",essence:"Bộ đồ quyết nội đan không đề tên tác giả, nghi đời Tống. Gồm các đồ thai tức, long hổ giao cấu, chu thiên hỏa hầu, trửu hậu phi kim tinh. Lấy ngũ tạng khí hóa và chu thiên vận hỏa làm trục.",key_text:"秘傳胎息訣有五門自然胎息訣第一。",use:"Học sơ đồ thai tức–hỏa hầu; đối chiếu với hệ Zhong-Lü/Nam Tông.",sources:["https://zh.daoinfo.org/index.php?title=%E4%BF%AE%E7%9C%9F%E5%A4%AA%E6%A5%B5%E6%B7%B7%E5%85%83%E6%8C%87%E7%8E%84%E5%9C%96","https://baike.baidu.com/item/%E4%BF%AE%E7%9C%9F%E5%A4%AA%E6%9E%81%E6%B7%B7%E5%85%83%E6%8C%87%E7%8E%84%E5%9B%BE/952326","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch31 · Grok-4.5 catalog-driven"},{dz:"DZ151",name_han:"金液還丹印證圖",name_vi:"Kim Dịch Hoàn Đan Ấn Chứng Đồ",bu:"洞真",author:"龍眉子",era:"南宋（序嘉定戊寅/1218）",topic:"cultivation",essence:"Sách đồ–thi ca nội đan của Long Mi Tử, tự thuật theo chỉ thầy, vẽ ngoại pháp tượng và nội pháp tượng. Giải chì–thủy ngân, hòa hợp, chân thổ, thủ thái, ôn dưỡng theo thứ tự tạo đan. Là bản đồ kinh điển của nam tông kim dịch hoàn đan.",key_text:"鉛汞明分兩，故有和合焉。和合成黃芽，故有真土焉。",use:"Đọc song song với Ngộ Chân thiên; dùng làm checklist thuật ngữ và thứ tự công phu.",sources:["https://fabriziopregadio.com/files/PREGADIO_and_ESPOSITO_Daozang_jiyao_Catalogue.pdf","https://ctext.org/wiki.pl?if=gb&res=863006","https://www.shidianguji.com/book/DZ0151"],textual_certainty:"high",notes:"batch31 · Grok-4.5 catalog-driven"},{dz:"DZ152",name_han:"修真歷驗鈔圖",name_vi:"Tu Chân Lịch Nghiệm Sao Đồ",bu:"洞真",author:"不著撰人（宋）",era:"宋",topic:"cultivation",essence:"Một quyển gồm mười hai đồ, mỗi đồ kèm luận ngắn về thái dược và hỏa hầu theo mười hai tháng. Mang tính lịch nghiệm–sao đồ, gần hệ Zhong-Lü/nam tông. Dùng để khóa nhịp luyện theo lịch tháng.",key_text:"集為圖論……略述十二月煉丹之採藥、火候要訣。",use:"Lập lịch hỏa hầu theo tháng; so với truyền đạo–bí pháp.",sources:["https://zh.daoinfo.org/index.php?title=%E4%BF%AE%E7%9C%9F%E6%AD%B7%E9%A9%97%E9%88%94%E5%9C%96","https://www.jstor.org/stable/26768560","https://crta.info/wiki/Daozang_-_DZ"],textual_certainty:"high",notes:"batch31 · Grok-4.5 catalog-driven"},{dz:"DZ153",name_han:"龍虎手鑑圖",name_vi:"Long Hổ Thủ Giám Đồ",bu:"洞真",author:"不著撰人",era:"宋–元",topic:"cultivation",essence:"Sách linh đồ nội đan lấy long–hổ làm pháp tượng, chỉ dẫn giao cấu, thăng giáng và giám định chân–giả. Nằm cụm linh đồ cùng các bản tu chân thái cực, kim dịch ấn chứng.",key_text:"null",use:"Tra pháp tượng long hổ khi đọc đan kinh nam tông.",sources:["https://www.jstor.org/stable/26768560","https://crta.info/wiki/Daozang_-_DZ","https://brill.com/display/book/9781684175161/BP000011.pdf"],textual_certainty:"partial",notes:"batch31 · Grok-4.5 catalog-driven"},{dz:"DZ155",name_han:"三才定位圖",name_vi:"Tam Tài Định Vị Đồ",bu:"洞真",author:"張商英等系（傳）",era:"北宋–南宋",topic:"philosophy",essence:"Đồ vũ trụ định vị thiên–địa–nhân, các tầng trời và ngôi vị thần tiên. Thuộc linh đồ vũ trụ luận, thường gắn với tấu trình triều Tống. Hữu ích cho phổ lục vị nghiệp và nghi thức bố trí thần vị.",key_text:"null",use:"Đối chiếu hệ tầng thiên giới và thần vị khi học phổ lục/linh đồ.",sources:["https://crta.info/wiki/Daozang_-_DZ","https://brill.com/display/book/9781684175161/BP000011.pdf","https://dokumen.pub/picturing-the-true-form-daoist-visual-culture-in-traditional-china-0674065735-9780674065734.html"],textual_certainty:"high",notes:"batch31 · Grok-4.5 catalog-driven"},{dz:"DZ156",name_han:"上清洞真九宮紫房圖",name_vi:"Thượng Thanh Động Chân Cửu Cung Tử Phòng Đồ",bu:"洞真",author:"上清系（不著撰人）",era:"六朝–唐宋傳本",topic:"cultivation",essence:"Đồ tồn tưởng thượng thanh về cửu cung và tử phòng trong thân/thiên. Chỉ dẫn vị trí cung thất, thần tồn và lộ trình thăng hư. Là chìa khóa thị giác cho hành pháp thượng thanh.",key_text:"null",use:"Học tồn tưởng cửu cung–tử phòng; đối chiếu với đại động/hoàng đình.",sources:["https://crta.info/wiki/Daozang_-_DZ","https://brill.com/display/book/9789004271647/B9789004271647_017.pdf","https://dokumen.pub/picturing-the-true-form-daoist-visual-culture-in-traditional-china-0674065735-9780674065734.html"],textual_certainty:"high",notes:"batch31 · Grok-4.5 catalog-driven"},{dz:"DZ683",name_han:"道德真經解",name_vi:"Đạo Đức Chân Kinh Giải",bu:"太玄",author:"陳象古",era:"宋",topic:"classic",essence:"Chú giải Đạo Đức chân kinh đời Tống của Trần Tượng Cổ, hai quyển, kinh văn không chia chương để nhấn mạnh đạo–đức hòa đồng. Lấy phục quy tự nhiên, thanh tịnh làm tông chỉ.",key_text:"道本真淳，理貴清淨。",use:"Đối chiếu chú Lão học Tống với các bản ngự chú/hội chú.",sources:["https://zh.daoinfo.org/index.php?title=%E9%81%93%E5%BE%B7%E7%9C%9F%E7%B6%93%E8%A7%A3%EF%BC%88%E9%99%B3%E8%B1%A1%E5%8F%A4%EF%BC%89","https://ctext.org/wiki.pl?if=gb&res=163933","https://crta.info/wiki/Daozang_-_DZ"],textual_certainty:"high",notes:"batch31 · Grok-4.5 catalog-driven"},{dz:"DZ687",name_han:"道德真經三解",name_vi:"Đạo Đức Chân Kinh Tam Giải",bu:"太玄",author:"鄧錡（玉賓子）",era:"元",topic:"classic",essence:"Chú Lão học nội đan đời Nguyên: mỗi chương giải theo ba lớp kinh–đạo–đức. Kết hợp nam tông (truyền Bạch Ngọc Thiềm) và toàn chân, lấy chân thường–tâm tính–đan pháp giải Lão. Kèm tự thuật đạo thống từ nguyên thủy đến bắc thất chân.",key_text:"太上老君，四極真人也。太者，大之極。上者，高之極。老者，壽之極。君者，人之極。",use:"Nghiên cứu Lão học toàn chân/nam tông; so với hội nguyên của Lý Đạo Thuần.",sources:["https://crta.info/wiki/Daozang_-_DZ","https://zh.daoinfo.org/index.php?title=%E9%81%93%E5%BE%B7%E7%9C%9F%E7%B6%93%E4%B8%89%E8%A7%A3%EF%BC%88%E9%84%A7%E9%8C%A1%EF%BC%89","https://zh.wikisource.org/wiki/%E9%81%93%E5%BE%B7%E7%9C%9F%E7%B6%93%E4%B8%89%E8%A7%A3","https://ctext.org/wiki.pl?if=gb&chapter=263633"],textual_certainty:"high",notes:"batch31 · Grok-4.5 catalog-driven"},{dz:"DZ702",name_han:"道德玄經原旨",name_vi:"Đạo Đức Huyền Kinh Nguyên Chỉ",bu:"太玄",author:"杜道堅",era:"元（約1294–1305）",topic:"classic",essence:"Bốn quyển chú Lão của Đỗ Đạo Kiên, nhấn mạnh nguyên chỉ huyền học, trị thân–trị quốc và đức tính thượng đức bất đức. Thuộc Lão học đạo sĩ Giang Nam đời Nguyên, ảnh hưởng lớn tới chú sớ đạo giáo.",key_text:"上德不德，是以有德。",use:"Đọc chú Lão Nguyên đại; tra khái niệm thượng đức/hạ đức.",sources:["http://www.chinaknowledge.de/Literature/Daoists/daozang.html","https://www.jstor.org/stable/26768560","https://zh.daoinfo.org/index.php?title=%E9%81%93%E5%BE%B7%E7%8E%84%E7%B6%93%E5%8E%9F%E6%97%A8%EF%BC%88%E6%9D%9C%E9%81%93%E5%A0%85%EF%BC%89","https://zh.wikisource.org/wiki/%E9%81%93%E5%BE%B7%E7%8E%84%E7%B6%93%E5%8E%9F%E6%97%A8"],textual_certainty:"high",notes:"batch31 · Grok-4.5 catalog-driven"},{dz:"DZ703",name_han:"玄經原旨發揮",name_vi:"Huyền Kinh Nguyên Chỉ Phát Huy",bu:"太玄",author:"杜道堅",era:"元",topic:"classic",essence:"Phần phát huy đi kèm Nguyên chỉ của Đỗ Đạo Kiên, triển khai sâu thêm nghĩa lý huyền kinh. Làm cầu nối giữa chú giải chương cú và diễn nghĩa triết–tu dưỡng.",key_text:"null",use:"Đọc sau Nguyên chỉ để nắm hệ Lão học Đỗ Đạo Kiên.",sources:["https://www.jstor.org/stable/26768560","http://www.chinaknowledge.de/Literature/Daoists/daozang.html","https://a.daorenjia.com/c15"],textual_certainty:"high",notes:"batch31 · Grok-4.5 catalog-driven"},{dz:"DZ714",name_han:"道德真經藏室纂微篇",name_vi:"Đạo Đức Chân Kinh Tàng Thất Toản Vi Thiên",bu:"太玄",author:"陳景元（碧虛子）",era:"北宋",topic:"classic",essence:"Mười quyển toản chú của Trần Cảnh Nguyên, tập hợp nghĩa vi diệu từ nhiều nhà chú Lão. Lấy hư tâm đãi vật, thường đạo làm tông, là cột mốc Lão học đạo giáo Bắc Tống.",key_text:"上篇明道以常道為宗。常道者，虛心以待物者也。",use:"Tra cứu chú sớ Lão học Tống; so với huyền đức toản sớ và các bản tập chú.",sources:["http://www.chinaknowledge.de/Literature/Daoists/daozang.html","https://zh.daoinfo.org/index.php?title=%E9%81%93%E5%BE%B7%E7%9C%9F%E7%B6%93%E8%97%8F%E5%AE%A4%E7%BA%82%E5%BE%AE%E7%AF%87%EF%BC%88%E9%99%B3%E6%99%AF%E5%85%83%EF%BC%89","https://ctext.org/library.pl?if=gb&res=84392","https://ctext.org/wiki.pl?if=en&chapter=965298"],textual_certainty:"high",notes:"batch31 · Grok-4.5 catalog-driven"},{dz:"DZ1046",name_han:"悟玄篇",name_vi:"Ngộ Huyền Thiên",bu:"太玄",author:"余洞真",era:"南宋（序1229）",topic:"cultivation",essence:"Thiên luận nội đan của Dư Động Chân, bàn hình hóa–khí hóa và đường vào huyền. Ngắn gọn, thiên về chỉ thuật công phu và nhận thức huyền cơ.",key_text:"null",use:"Nhập môn thuật ngữ nội đan Nam Tống; đọc kèm các thiên ngộ chân.",sources:["https://crta.info/wiki/Daozang_-_DZ","https://fabriziopregadio.com/files/PREGADIO_and_ESPOSITO_Daozang_jiyao_Catalogue.pdf","https://neidanwiki.com/index.php?title=Wuxuan_pian_%E6%82%9F%E7%8E%84%E7%AF%87","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch31 · Grok-4.5 catalog-driven"},{dz:"DZ1071",name_han:"原陽子法語",name_vi:"Nguyên Dương Tử Pháp Ngữ",bu:"太玄",author:"趙宜真（原陽子）",era:"元末明初",topic:"cultivation",essence:"Ngữ lục–pháp ngữ của Triệu Nghi Chân, trộn nội đan, đạo pháp và khuyến tu. Gồm ca kệ hoàn đan, tụng chân đạo quy nhất và đối đáp với các luyện sư. Phản ánh giao thoa toàn chân–thanh vi–tịnh minh.",key_text:"null",use:"Nghiên cứu pháp ngữ cuối Nguyên đầu Minh; đối chiếu với linh bảo quy không quyết.",sources:["https://crta.info/wiki/Daozang_-_DZ","https://www.jstor.org/stable/26768560","https://ctext.org/wiki.pl?if=gb&res=533229"],textual_certainty:"high",notes:"batch31 · Grok-4.5 catalog-driven"},{dz:"DZ1072",name_han:"金丹直指",name_vi:"Kim Đan Trực Chỉ",bu:"太玄",author:"周無所住",era:"南宋（序淳祐庚戌/1250）",topic:"cultivation",essence:"Một quyển gồm mười sáu tụng và đáp vấn, trực chỉ nam tông kim đan. Chịu ảnh hưởng Thiền, nhấn mạnh thân làm lô đỉnh, dược tại bản thân, tránh chi chi tiết rườm rà.",key_text:"爐鼎以身譬者。",use:"Học khẩu quyết ngắn gọn nam tông; so với kim đan vấn đáp trong tu chân thập thư.",sources:["https://crta.info/wiki/Daozang_-_DZ","https://brill.com/display/book/edcoll/9789004271647/B9789004271647_027.pdf","https://homeinmists.ilotus.org/DaoZang/Tiyao5.pdf"],textual_certainty:"high",notes:"batch31 · Grok-4.5 catalog-driven"},{dz:"DZ1257",name_han:"群仙要語纂集",name_vi:"Quần Tiên Yếu Ngữ Toản Tập",bu:"正一",author:"董瑾醇（董漌醇）",era:"元–明",topic:"类书",essence:"Toản tập lời cốt yếu của quần tiên về tu luyện nội đan, hai quyển. Thuộc loại thư–tuyển yếu, tiện tra khẩu quyết và câu danh ngôn đan đạo. Bổ sung cho các tổng tập như chư chân nội đan tập yếu.",key_text:"null",use:"Tra cứu trích yếu tiên gia; làm mục lục ý tưởng cho lớp học nội đan.",sources:["https://crta.info/wiki/Daozang_-_DZ","https://www.jstor.org/stable/26768560","https://homeinmists.ilotus.org/%E9%81%93%E8%97%8F%E5%8C%AF%E7%B7%A8/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F/%E9%81%93%E8%97%8F%E7%9B%AE%E9%8C%84/"],textual_certainty:"high",notes:"batch31 · Grok-4.5 catalog-driven"},{dz:"DZ1258",name_han:"諸真內丹集要",name_vi:"Chư Chân Nội Đan Tập Yếu",bu:"正一",author:"玄全子",era:"元",topic:"类书",essence:"Ba quyển tập yếu chư chân về nội đan do Huyền Toàn Tử biên. Gom ca kệ, khẩu quyết và chương yếu từ nhiều tiên gia, nhấn mạnh huyền tẫn, tính mệnh và bệnh của tu hành chỉ luyện mệnh.",key_text:"玄牝之門號金母，先天先地藏真土。",use:"Tuyển đọc cốt tủy nội đan đa nguồn; tra bệnh–dược của công phu.",sources:["https://crta.info/wiki/Daozang_-_DZ","https://zh.daoinfo.org/index.php?title=%E8%AB%B8%E7%9C%9F%E5%85%A7%E4%B8%B9%E9%9B%86%E8%A6%81","https://zh.wikisource.org/zh-hant/%E8%AB%B8%E7%9C%9F%E5%85%A7%E4%B8%B9%E9%9B%86%E8%A6%81"],textual_certainty:"high",notes:"batch31 · Grok-4.5 catalog-driven"},{dz:"DZ1465",name_han:"消搖墟經",name_vi:"Tiêu Dao Khư Kinh",bu:"续道藏",author:"洪自成（洪自誠）",era:"明（萬曆續道藏）",topic:"仙传",essence:"Hai quyển tiên truyện–tiểu dao chí thuộc Vạn Lịch tục đạo tạng, biên soạn bởi Hồng Tự Thành. Tập hợp hành trạng ẩn sĩ–chân tiên, mang màu phổ lục và tiêu dao chí. Bổ sung mảng phổ lục/tiên sử ít được phủ.",key_text:"蒙莊氏所稱消搖遊者，意在斯乎。",use:"Đọc tiểu sử tiên ẩn; đối chiếu với liệt tiên/lịch thế chân tiên.",sources:["https://crta.info/wiki/Daozang_-_DZ","https://www.jstor.org/stable/26768560","https://zh.wikisource.org/zh-hant/%E8%90%AC%E6%9B%86%E7%BA%8C%E9%81%93%E8%97%8F","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT08%E7%BA%8C%E9%81%93%E8%97%8F/CNDZ08-ALL/CNDZ0835%E6%B6%88%E9%81%99%E5%A2%9F%E7%B6%93/CNDZ0835-1%E6%B6%88%E9%81%99%E5%A2%9F%E7%B6%93%E5%8D%B7%E4%B8%8A.htm"],textual_certainty:"high",notes:"batch31 · Grok-4.5 catalog-driven"},{dz:"DZ033",name_han:"上清黃氣陽精三道順行經",name_vi:"Thượng Thanh Hoàng Khí Dương Tinh Tam Đạo Thuận Hành Kinh",bu:"洞真",author:"佚名（上清降授，託西城王君授魏華存）",era:"東晉–南朝（約4–5世紀）",topic:"cultivation",essence:"Kinh Thượng Thanh then chốt, còn gọi Tàng Thiên Ẩn Nguyệt, dạy đạo «thuận hành tam đạo» và «hoàng khí dương tinh» — tinh khí nhật nguyệt thất diệu. Hành giả theo tứ thời bát tiết tồn tư nhật thần, nguyệt thần, thất diệu đồng tử, phục phù tụng chú để tiêu tai, hợp đạo thành tiên. Đây là bản văn cốt lõi của hệ kinh Thượng Thanh, được Chân Cáo và Vô Thượng Bí Yếu trích dẫn.",key_text:"南極上元君曰：吾受高上順行三道之要，黃氣陽精之道",use:"Tồn tư nhật nguyệt thất diệu, phục hoàng khí dương tinh theo bát tiết; nền tảng quán tưởng Thượng Thanh.",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%8A%E6%B8%85%E9%BB%83%E6%B0%A3%E9%99%BD%E7%B2%BE%E4%B8%89%E9%81%93%E9%A0%86%E8%A1%8C%E7%B6%93&variant=zh-hant","https://zh.wikisource.org/zh-hant/%E4%B8%8A%E6%B8%85%E9%BB%83%E6%B0%A3%E9%99%BD%E7%B2%BE%E4%B8%89%E9%81%93%E9%A0%86%E8%A1%8C%E7%B6%93","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch32 · Grok-4.5 catalog-driven"},{dz:"DZ056",name_han:"太上玉珮金璫太極金書上經",name_vi:"Thái Thượng Ngọc Bội Kim Đang Thái Cực Kim Thư Thượng Kinh",bu:"洞真",author:"佚名（早期上清經典）",era:"東晉（約4世紀）",topic:"cultivation",essence:"Kinh Thượng Thanh sớm, còn gọi Ngọc Bội Kim Đang Thái Tiêu Ẩn Thư, thuật sự truyền thụ Ngọc Bội – Kim Đang nhị cảnh bảo văn từ Nguyên Thủy Thiên Vương. Dạy tồn tư tam nguyên cửu chân, phục phù dương phù âm phù, hợp nhị cảnh để bảo hình, đăng Thái Cực. Là bản «kim thư bí tự» trung tâm cho thực hành hồn phách, linh phi.",key_text:"玉珮金璫太極金書，玄真洞飛二景寶經",use:"Tồn tư ngọc bội kim đang, phục phù cửu thiên hồn tinh; tu bát tiết, bản mệnh nhật.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E7%8E%89%E4%BD%A9%E9%87%91%E7%92%AB%E5%A4%AA%E6%A5%B5%E9%87%91%E6%9B%B8%E4%B8%8A%E7%B6%93&variant=zh-hant","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E7%8E%89%E7%8F%AE%E9%87%91%E7%92%AB%E5%A4%AA%E6%A5%B5%E9%87%91%E6%9B%B8%E4%B8%8A%E7%B6%93","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch32 · Grok-4.5 catalog-driven"},{dz:"DZ184",name_han:"太真玉帝四極明科經",name_vi:"Thái Chân Ngọc Đế Tứ Cực Minh Khoa Kinh",bu:"洞真",author:"佚名（早期上清科律）",era:"東晉–南朝",topic:"戒律",essence:"Bộ khoa luật then chốt của Thượng Thanh, gọi tắt Tứ Cực Minh Khoa, năm quyển. Luật văn phân Thái Huyền đô thượng–hạ–tả–hữu–trung ngũ cung, mỗi cung hai mươi điều, tổng một trăm hai mươi điều do ngũ đế ngọc tư quân chưởng quản. Quy định truyền thụ, cấm kỵ, tội phạt và nghi thức thọ kinh; Lục Tu Tĩnh đã trích dẫn trong nghi truyền độ.",key_text:"太玄都四極明科曰：凡高上太真、玉皇帝君、玉清真人、萬仙眾聖、得道靈人，皆佩太真明科",use:"Tra cứu giới luật Thượng Thanh khi truyền kinh, thụ lục, kiểm soát tiết lộ bí văn.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E7%9C%9F%E7%8E%89%E5%B8%9D%E5%9B%9B%E6%A5%B5%E6%98%8E%E7%A7%91%E7%B6%93&variant=zh-hant","https://zh.wikisource.org/zh-hant/%E5%A4%AA%E7%9C%9F%E7%8E%89%E5%B8%9D%E5%9B%9B%E6%A5%B5%E6%98%8E%E7%A7%91%E7%B6%93","https://www.shidianguji.com/book/DZ0184"],textual_certainty:"high",notes:"batch32 · Grok-4.5 catalog-driven"},{dz:"DZ253",name_han:"金闕帝君三元真一經",name_vi:"Kim Khuyết Đế Quân Tam Nguyên Chân Nhất Kinh",bu:"洞真",author:"佚名（託涓子授青童君；析出自大有妙經）",era:"南北朝",topic:"cultivation",essence:"Cẩm nang tồn thủ tam nguyên chân nhất: thượng nhất là thiên đế trong đầu, trung nhất là đan hoàng giáng cung, hạ nhất là nguyên vương hạ đan điền. Giữ vững «nhất» thì tam nhất hiện, vân xa khả thặng, bạch nhật thăng thiên. Cũng thu vào Vân Cấp Thất Thiêm quyển 50; bản Anh dịch Method of Holding the Three Ones dựa trên kinh này.",key_text:"真人所以貴一為真者，上一為一身之天帝，中一為絳宮之丹皇",use:"Tồn thủ tam đan điền chân nhất; thực hành căn bản «thủ nhất» của Thượng Thanh.",sources:["https://zh.wikipedia.org/zh-hant/%E9%87%91%E9%97%95%E5%B8%9D%E5%90%9B%E4%B8%89%E5%85%83%E7%9C%9F%E4%B8%80%E7%B6%93","https://ctext.org/wiki.pl?if=gb&res=133090","https://www.shidianguji.com/zh/book/DZ0253"],textual_certainty:"high",notes:"batch32 · Grok-4.5 catalog-driven"},{dz:"DZ319",name_han:"洞玄靈寶本相運度劫期經",name_vi:"Động Huyền Linh Bảo Bản Tướng Vận Độ Kiếp Kỳ Kinh",bu:"洞玄",author:"佚名",era:"南北朝末–隋唐",topic:"classic",essence:"Cổ Linh Bảo kinh (hoặc tàn quyển Bản Tướng Kinh), Nguyên Thủy Thiên Tôn thuyết cho đạo sĩ Viêm Minh về nhân duyên phúc thọ, công đức, vận độ kiếp kỳ. Nói rõ nghiệp báo, tu trai, bố thí, tạo công đức để độ kiếp, an ổn qua kiếp nạn. Bổ sung chiều kích cứu độ – thời vận cho hệ Linh Bảo.",key_text:"濟人渴乏者，去住常安穩，始終無他苦",use:"Đọc để nắm quan niệm kiếp vận, công đức độ người trong giáo lý Linh Bảo.",sources:["https://zh.daoinfo.org/index.php?title=%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E6%9C%AC%E7%9B%B8%E9%81%8B%E5%BA%A6%E5%8A%AB%E6%9C%9F%E7%B6%93&variant=zh-hant","https://www.shidianguji.com/book/DZ0319","https://zh.wikisource.org/zh-hant/%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E6%9C%AC%E7%9B%B8%E9%81%8B%E5%BA%A6%E5%8A%AB%E6%9C%9F%E7%B6%93"],textual_certainty:"high",notes:"batch32 · Grok-4.5 catalog-driven"},{dz:"DZ321",name_han:"洞玄靈寶諸天世界造化經",name_vi:"Động Huyền Linh Bảo Chư Thiên Thế Giới Tạo Hóa Kinh",bu:"洞玄",author:"佚名",era:"南北朝–唐",topic:"philosophy",essence:"Kinh Linh Bảo bàn vũ trụ luận: cấu trúc chư thiên, thế giới, quá trình tạo hóa từ đạo khí đến vạn hữu. Liên hệ thiên giới – nhân gian, vận hành âm dương ngũ hành trong khung soteriology Linh Bảo. Bổ sung cho hệ «độ nhân – tạo hóa» bên cạnh Độ Nhân Kinh đã loại.",key_text:"null",use:"Tham chiếu vũ trụ quan, thiên giới đồ thức khi giải kinh Linh Bảo.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://ctext.org/searchbooks.pl?if=en&searchu=%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E8%AB%B8%E5%A4%A9%E4%B8%96%E7%95%8C%E9%80%A0%E5%8C%96%E7%B6%93","http://www.chinaknowledge.de/Literature/Daoists/daozang.html"],textual_certainty:"partial",notes:"batch32 · Grok-4.5 catalog-driven"},{dz:"DZ330",name_han:"太上洞玄靈寶真文要解上經",name_vi:"Thái Thượng Động Huyền Linh Bảo Chân Văn Yếu Giải Thượng Kinh",bu:"洞玄",author:"佚名",era:"東晉末–南朝",topic:"classic",essence:"Giải yếu về «chân văn» Linh Bảo: nguồn gốc, công năng, cách trì tụng và dùng ngũ phương chân văn. Kết nối ngũ lão xích thư, ngọc thiên, nghi ném long giản. Là cầu nối giữa bản văn phù triện và thực hành trai nghi – giải nghĩa.",key_text:"null",use:"Học giải nghĩa chân văn trước khi hành trai, đầu long giản, trì phù.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://a.daorenjia.com/c9","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT02%E6%B4%9E%E7%8E%84%E9%83%A8/CMT0201%E6%9C%AC%E6%96%87%E9%A1%9E/CMT0201ALL/"],textual_certainty:"partial",notes:"batch32 · Grok-4.5 catalog-driven"},{dz:"DZ352",name_han:"太上洞玄靈寶赤書玉訣妙經",name_vi:"Thái Thượng Động Huyền Linh Bảo Xích Thư Ngọc Quyết Diệu Kinh",bu:"洞玄",author:"佚名（古靈寶經之一）",era:"東晉末–南朝初",topic:"fu",essence:"Cổ Linh Bảo kinh, gọi tắt Xích Thư Ngọc Quyết; Lục Tu Tĩnh Linh Bảo Kinh Mục đã lục. Hai quyển dạy ngọc quyết (cách dùng) của ngũ phương xích thư chân văn: cáo thủy đế, ngũ nhạc trừ tội, cầu tiên, cùng chú pháp, đầu giản. Khác với Nguyên Thủy Ngũ Lão Xích Thư Ngọc Thiên Chân Văn Thiên Thư Kinh (bản văn phù); đây là «quyết» thực hành.",key_text:"爾時元始天尊、太上大道君、五老上帝、十方大神，會於南丹洞陽上館",use:"Thực hành xích thư: cáo đế, trừ tội, cầu tiên, phối hợp chân văn ngũ phương.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E8%B5%A4%E6%9B%B8%E7%8E%89%E8%A8%A3%E5%A6%99%E7%B6%93&variant=zh-hant","https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E8%B5%A4%E6%9B%B8%E7%8E%89%E8%A8%A3%E5%A6%99%E7%B6%93","https://ctext.org/wiki.pl?if=gb&res=987941"],textual_certainty:"high",notes:"batch32 · Grok-4.5 catalog-driven"},{dz:"DZ405",name_han:"上清紫精君皇初紫靈道君洞房上經",name_vi:"Thượng Thanh Tử Tinh Quân Hoàng Sơ Tử Linh Đạo Quân Động Phòng Thượng Kinh",bu:"洞玄",author:"佚名（南北朝上清經纂集）",era:"南北朝",topic:"cultivation",essence:"Kinh Động Phòng Thượng Thanh, tập hợp nhiều pháp tồn thần: Thái Tố Thượng Thanh trí đế quân ngũ thần khí pháp (mắt–tay–phế ngũ đồng tử), thất nguyên cửu thần động phòng bát giải môn, hồi nguyên ẩn đạo trừ tội. Nhấn mạnh tồn tư động phòng (khoang đầu) và bắc đẩu cửu tinh để an thần, phi tiên.",key_text:"null",use:"Tồn tư ngũ thần, cửu tinh động phòng; tu «động phòng» Thượng Thanh.",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%8A%E6%B8%85%E7%B4%AB%E7%B2%BE%E5%90%9B%E7%9A%87%E5%88%9D%E7%B4%AB%E9%9D%88%E9%81%93%E5%90%9B%E6%B4%9E%E6%88%BF%E4%B8%8A%E7%B6%93&variant=zh-hans","https://www.shidianguji.com/zh/book/DZ0405","https://zh.wikisource.org/wiki/%E4%B8%8A%E6%B8%85%E7%B4%AB%E7%B2%BE%E5%90%9B%E7%9A%87%E5%88%9D%E7%B4%AB%E9%9D%88%E9%81%93%E5%90%9B%E6%B4%9E%E6%88%BF%E4%B8%8A%E7%B6%93"],textual_certainty:"high",notes:"batch32 · Grok-4.5 catalog-driven"},{dz:"DZ523",name_han:"洞玄靈寶自然齋儀",name_vi:"Động Huyền Linh Bảo Tự Nhiên Trai Nghi",bu:"洞玄",author:"佚名（傳承陸修靜靈寶齋法）",era:"南朝–宋（今本多宋以後科儀形態）",topic:"ritual",essence:"Nghi thức Tự Nhiên Trai — một trong Lục Trai pháp Linh Bảo sớm (Lục Tu Tĩnh Ngũ Cảm Văn, Tống Văn Minh Thông Môn Luận đã nêu). Dùng cầu phúc tiêu tai, cứu độ chúng sinh: phát lô, lễ sư tồn niệm, tam niệm hương, quy mệnh thập phương vô cực đại đạo. Là mẫu nghi uy nghi «tự nhiên» căn bản cho trai đàn Linh Bảo.",key_text:"運玆初捻上香，歸身歸神歸命，十方無極大道太上三尊",use:"Hành Tự Nhiên Trai: cầu an, tiêu tai, độ người; tham chiếu cấu trúc phát lô–lễ sư.",sources:["https://zh.daoinfo.org/index.php?title=%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E8%87%AA%E7%84%B6%E9%BD%8B%E5%84%80&variant=zh-hant","https://zh.wikisource.org/zh-hant/%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E8%87%AA%E7%84%B6%E9%BD%8B%E5%84%80","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch32 · Grok-4.5 catalog-driven"},{dz:"DZ531",name_han:"洞玄靈寶鐘磬威儀經",name_vi:"Động Huyền Linh Bảo Chung Khánh Uy Nghi Kinh",bu:"洞玄",author:"佚名",era:"南北朝–唐",topic:"ritual",essence:"Chuyên luận uy nghi đánh chuông–khánh trong trai giao: thời khắc, số tiếng, phối tụng, tên các thần chung (độ mệnh, trường sinh, tiêu ma, phục tà…). Thái Thượng Đạo Quân tuyên bố mọi trai tiệc đều có thể dùng chung khánh để triệu chân, nhiếp ma, định nghi. Bổ sung «nhạc khí – uy nghi» cho khoa nghi Linh Bảo.",key_text:"四梵天中，有度命神鐘、長生靈鐘、濟生神鐘、消魔神鐘",use:"Quy chuẩn đánh chuông khánh trong trai đàn; tra tên thần chung, thời khắc.",sources:["https://zh.daoinfo.org/index.php?title=%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E9%90%98%E7%A3%AC%E5%A8%81%E5%84%80%E7%B6%93&variant=zh-hant","https://www.shidianguji.com/book/DZ0531","https://zh.wikisource.org/zh-hant/%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E9%8D%BE%E7%A3%AC%E5%A8%81%E5%84%80%E7%B6%93"],textual_certainty:"high",notes:"batch32 · Grok-4.5 catalog-driven"},{dz:"DZ586",name_han:"黃帝太乙八門入式訣",name_vi:"Hoàng Đế Thái Ất Bát Môn Nhập Thức Quyết",bu:"洞玄",author:"佚名",era:"唐–五代",topic:"占验",essence:"Ba quyển thuật số Thái Ất – bát môn: âm dương thuận nghịch, tam kỳ hợp môn, nhập xuất khứ trú, kèm Thái Ất bát môn nghịch thuận sinh tử đồ. Trung–hạ quyển thêm lục đinh ngọc nữ pháp, phù chú, tồn tư, vũ bộ trừ tai diệt tặc. Khác với Hoàng Đế Thái Nhất Bát Môn Nghịch Thuận Sinh Tử Quyết đã loại; đây là bản «nhập thức quyết» đầy đủ hơn trong Đạo tạng.",key_text:"甲子甲辰常起一，甲寅甲戌三宮出。甲申六宮甲午八，得之順行無不吉",use:"Chọn môn Thái Ất, định thuận nghịch sinh tử; phù lục đinh ngọc nữ hộ thân.",sources:["https://zh.daoinfo.org/index.php?title=%E9%BB%83%E5%B8%9D%E5%A4%AA%E4%B9%99%E5%85%AB%E9%96%80%E5%85%A5%E5%BC%8F%E8%A8%A3&variant=zh-hans","https://www.shidianguji.com/zh/book/DZ0586","https://zh.wikisource.org/wiki/%E9%BB%83%E5%B8%9D%E5%A4%AA%E4%B8%80%E5%85%AB%E9%96%80%E5%85%A5%E5%BC%8F%E8%A8%A3"],textual_certainty:"high",notes:"batch32 · Grok-4.5 catalog-driven"},{dz:"DZ830",name_han:"服氣精義論",name_vi:"Phục Khí Tinh Nghĩa Luận",bu:"洞神",author:"司馬承禎（天台白雲子）",era:"唐（8世紀）",topic:"服气",essence:"Luận phục khí hệ thống của Tư Mã Thừa Trinh: chín thiên (ngũ nha, phục khí, đạo dẫn, phù thủy, phục dược, thận kỵ, ngũ tạng, trị bệnh, bệnh hầu). Khẳng định khí là «cơ vi của Đạo», ăn khí thì thần thọ; tổng hợp hấp hà, đạo dẫn, phù thủy, phục dược thành lộ trình dưỡng sinh thực dụng. Cũng thấy trong Vân Cấp Thất Thiêm quyển 57.",key_text:"夫氣者，道之幾微也。幾而動之，微而用之，乃生一焉",use:"Học phục khí, ngũ nha, đạo dẫn, trị bệnh bằng khí; cẩm nang dưỡng sinh Đường Thượng Thanh.",sources:["https://zh.wikisource.org/zh-hant/%E6%9C%8D%E6%B0%A3%E7%B2%BE%E7%BE%A9%E8%AB%96","https://zh.daoinfo.org/wiki/%E6%9C%8D%E6%B0%A3%E7%B2%BE%E7%BE%A9%E8%AB%96","https://www.shidianguji.com/book/DZ0830"],textual_certainty:"high",notes:"batch32 · Grok-4.5 catalog-driven"},{dz:"DZ861",name_han:"太上六壬明鑑符陰經",name_vi:"Thái Thượng Lục Nhâm Minh Giám Phù Âm Kinh",bu:"洞神",author:"佚名（託孫臏–鬼谷–白猿）",era:"宋（約）",topic:"占验",essence:"Bốn quyển thuật Lục Nhâm – binh âm dương mang màu đạo giáo: hỗn nguyên thức, cửu tinh thức, thập can thức, tạo pháp phục khí giới, phù chú tồn thần. Tựa thuật Tôn Tẫn học quỷ cốc, bạch viên trao thư; dùng cho ẩn hình, phá tặc, hộ thân, chọn ngày. Là bản đạo kinh Lục Nhâm hiếm trong Chính Thống Đạo Tạng, khác với Lục Nhâm đại điển thế tục.",key_text:"昔孫臏與龐涓結義，而求師於鬼谷先生，學業軍旅戰鬥之事",use:"Phù Lục Nhâm, cửu tinh; binh pháp–hộ thân theo khung đạo thuật.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E5%85%AD%E5%A3%AC%E6%98%8E%E9%91%92%E7%AC%A6%E9%99%B0%E7%B6%93&variant=zh-hans","https://www.shidianguji.com/zh/book/DZ0861","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E5%85%AD%E5%A3%AC%E6%98%8E%E9%91%91%E7%AC%A6%E9%99%B0%E7%B6%93"],textual_certainty:"high",notes:"batch32 · Grok-4.5 catalog-driven"},{dz:"DZ1343",name_han:"洞真黃書",name_vi:"Động Chân Hoàng Thư",bu:"正一",author:"佚名（天師道；託老君授張陵）",era:"漢末–魏晉",topic:"房中",essence:"Cổ kinh Thiên Sư đạo về hoàng xích / hợp khí: «âm dương đại độ bát sinh chi pháp», dùng bát quái cửu cung, lục giáp, can chi chọn ngày giờ hợp khí, phối tồn thần, dẫn dẫn, cấm kỵ. Chân Cáo gọi là «trọc sinh hạ đạo»; Nguyên bản tám quyển, nay còn một quyển trong Chính Nhất bộ. Nguồn chính để hiểu «hoàng thư hợp khí» thời kỳ sớm.",key_text:"師曰：願分別天地大度八生之法，天地六合，人六合",use:"Nghiên cứu lịch sử hoàng xích; không khuyến thực hành; tra lịch kỵ hợp khí theo can chi.",sources:["https://zh.daoinfo.org/index.php?title=%E6%B4%9E%E7%9C%9F%E9%BB%83%E6%9B%B8&variant=zh-hant","https://www.shidianguji.com/book/DZ1343","https://zh.wikisource.org/zh-hans/%E6%B4%9E%E7%9C%9F%E9%BB%83%E6%9B%B8"],textual_certainty:"high",notes:"batch32 · Grok-4.5 catalog-driven"},{dz:"DZ1378",name_han:"上清金真玉光八景飛經",name_vi:"Thượng Thanh Kim Chân Ngọc Quang Bát Cảnh Phi Kinh",bu:"正一",author:"佚名（早期上清重要經典）",era:"東晉（約4世紀）",topic:"cultivation",essence:"Kinh Thượng Thanh trọng yếu: Cửu Thiên Trượng Nhân thụ Kim Chân Ngọc Quang từ Nguyên Thủy Thiên Vương, còn gọi Bát Cảnh Phi Kinh / Bát Tố Thượng Kinh / Hoát Lạc Thất Nguyên. Dạy phù «kim chân ngọc quang», tồn bát cảnh, hoát lạc thất nguyên để phi hành, diệt ma, đăng chân. Có bản Đôn Hoàng (P.2728, S.238…); Thượng Thanh Đại Động Chân Kinh Mục đã lục.",key_text:"九天丈人受太空靈都金真玉光於元始天王，名之八景飛經",use:"Trì phù kim chân ngọc quang, tồn bát cảnh; thực hành phi hành Thượng Thanh.",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%8A%E6%B8%85%E9%87%91%E7%9C%9F%E7%8E%89%E5%85%89%E5%85%AB%E6%99%AF%E9%A3%9B%E7%B6%93&variant=zh-hans","https://michaelstanley-baker.com/clarkes-complete-daoist-index/","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch32 · Grok-4.5 catalog-driven"},{dz:"DZ174",name_han:"金蓮正宗仙源像傳",name_vi:"Kim Liên Chính Tông Tiên Nguyên Tượng Truyện",bu:"洞真",author:"劉志玄、謝西蟾",era:"元（約1326）",topic:"仙传",essence:"Toàn Chân giáo sử có tranh chân dung: chép tiểu truyện Đông Hoa, Chính Dương, Thuần Dương và Thất Chân, kèm hình tượng để củng cố pháp phái. Là bản “tượng truyện” song song với Kim Liên Chính Tông Ký, nhấn mạnh hệ phả và uy tín giáo đoàn. Dùng để tra cứu huyền thoại Thất Chân và cách dựng phả hệ cuối Tống–Nguyên.",key_text:"金蓮正宗，仙源有像，七真之傳，昭昭可考。",use:"谱录·全真传记与像传",sources:["https://www.jstor.org/stable/26768560","http://www.chinaknowledge.de/Literature/Daoists/daozang.html"],textual_certainty:"high",notes:"batch33 · Grok-4.5 catalog-driven"},{dz:"DZ176",name_han:"玄風慶會錄",name_vi:"Huyền Phong Khánh Hội Lục",bu:"洞真",author:"移剌楚才（耶律楚材）記；丘處機答",era:"元（1232）",topic:"cultivation",essence:"Ghi lời Khâu Xử Cơ trả lời Thành Cát Tư Hãn về đạo dưỡng sinh: trọng bảo tinh khí, không dựa thuốc thảo. Phản ánh lập trường Toàn Chân phản đối phục thực ngoại đan. Nguồn chính cho quan hệ đạo–chính đầu Nguyên.",key_text:"服藥千朝，不如獨臥一宵。",use:"语录·全真与蒙元交涉",sources:["https://www.mdpi.com/2077-1444/14/6/814","https://brill.com/display/book/9789004193864/Bej.9789004192287.i-430_007.pdf"],textual_certainty:"high",notes:"batch33 · Grok-4.5 catalog-driven"},{dz:"DZ220",name_han:"無上玄元三天玉堂大法",name_vi:"Vô Thượng Huyền Nguyên Tam Thiên Ngọc Đường Đại Pháp",bu:"洞真",author:"路時中編",era:"南宋",topic:"ritual",essence:"Tổng tập đạo pháp Ngọc Đường 30 quyển: giới luật, phù lục, khảo triệu, tế độ. Thuộc dòng Thiên Tâm/Thần Tiêu thời Tống, kết hợp nội luyện và pháp thuật. Tài liệu then chốt về khảo triệu–trừ tà và “thiên luật” trong pháp phái.",key_text:"法不離道，道以法顯。",use:"道法·玉堂/天心考召",sources:["https://zh.wikisource.org/zh-hans/%E7%84%A1%E4%B8%8A%E7%8E%84%E5%85%83%E4%B8%89%E5%A4%A9%E7%8E%89%E5%A0%82%E5%A4%A7%E6%B3%95","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch33 · Grok-4.5 catalog-driven"},{dz:"DZ246",name_han:"西山群仙會真記",name_vi:"Tây Sơn Quần Tiên Hội Chân Ký",bu:"洞真",author:"題施肩吾；李竦等傳",era:"唐–宋（今本約北宋）",topic:"cultivation",essence:"Hệ thống hóa nội đan phái Chung–Lữ: tinh–khí–thần, ngũ hành, hỏa hầu. Dàn thành các “ký” hội chân trên Tây Sơn, ảnh hưởng sâu đến Trung–Lữ truyền đạo và nội đan hậu Tống. Bản nền để hiểu khung luyện dưỡng trước Toàn Chân.",key_text:"先修人道，方修仙道。",use:"内丹·钟吕系统",sources:["https://www.researchgate.net/publication/361290818_True_Record_of_the_Assembly_of_All_the_Immortals_on_West_Mountain_xishanqunxianhuizhenji_English_ms_version","https://purplecloudinstitute.com/wp-content/uploads/2023/08/Daoist-Texts-in-Western-Languages-%C2%A9-Purple-Cloud-Press-2023.pdf"],textual_certainty:"high",notes:"batch33 · Grok-4.5 catalog-driven"},{dz:"DZ1002",name_han:"周易參同契分章通真義",name_vi:"Chu Dịch Tham Đồng Khế Phân Chương Thông Chân Nghĩa",bu:"太玄",author:"彭曉（真一子）注",era:"五代後蜀",topic:"外丹",essence:"Chú giải Tham Đồng Khế chia chương, giải thuật ngữ lô hỏa, khảm ly, long hổ theo hướng đan đạo. Là bản chú ảnh hưởng nhất thời Đường–Tống, nền cho mọi sớ giải sau. Cốt tủy: dùng Dịch lý minh đan đạo.",key_text:"乾坤者，易之門戶，衆卦之父母。",use:"注疏·参同契",sources:["https://zh.wikisource.org/zh-hans/%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%E5%88%86%E7%AB%A0%E9%80%9A%E7%9C%9F%E7%BE%A9","http://www.chinaknowledge.de/Literature/Daoists/zhouyicantongqi.html"],textual_certainty:"high",notes:"batch33 · Grok-4.5 catalog-driven"},{dz:"DZ1100",name_han:"鳴鶴餘音",name_vi:"Minh Hạc Dư Âm",bu:"太平",author:"彭致中集",era:"元",topic:"cultivation",essence:"Tổng tập thơ từ đạo sĩ Toàn Chân và các chân nhân (gồm bài gán Tôn Bất Nhị). Vừa văn học vừa “khẩu quyết” tu hành bằng từ khúc. Nguồn chính cho thi văn Toàn Chân đời Nguyên.",key_text:"意馬心猿牢拴住，運上崑崙峯頂住。",use:"诗文集·全真词曲",sources:["https://louiskomjathy.com/wp-content/uploads/2021/12/SunBuer_Komjathy.pdf","https://simplelits.com/books/classical/classical-07054-%E9%B8%A3%E9%B9%A4%E4%BD%99%E9%9F%B3/2"],textual_certainty:"high",notes:"batch33 · Grok-4.5 catalog-driven"},{dz:"DZ1143",name_han:"草堂集",name_vi:"Thảo Đường Tập",bu:"太平",author:"王丹桂（白雲子）",era:"金末元初",topic:"cultivation",essence:"Thi tập đạo sĩ Toàn Chân Vương Đan Quế: ngâm vịnh ẩn cư, trừ vọng, chứng chân. Giọng mộc mạc, phản ánh đời sống tòng đạo ở Hoa Bắc. Bổ sung mảng “đệ tử thế hệ hai” ngoài Thất Chân.",key_text:"本來真性喚神仙。",use:"诗文集·全真",sources:["https://fabriziopregadio.com/files/PREGADIO_and_ESPOSITO_Daozang_jiyao_Catalogue.pdf","https://ctext.org/wiki.pl?if=gb&res=726712"],textual_certainty:"high",notes:"batch33 · Grok-4.5 catalog-driven"},{dz:"DZ1144",name_han:"自然集",name_vi:"Tự Nhiên Tập",bu:"太平",author:"鄧學可（傳）",era:"元",topic:"cultivation",essence:"Tập tản khúc (sanqu) đạo tình: nói hỏa hầu, kim đan, xuất thế bằng thể tài dân gian. Hiếm có trong Đạo tạng vì dùng nhạc phủ/tạp kịch điệu. Gợi đời sống phổ cập hóa Toàn Chân thời Nguyên.",key_text:"道妙玄微，先須要悟明心地。",use:"诗文集·全真散曲",sources:["https://zh.wikisource.org/zh-hans/%E8%87%AA%E7%84%B6%E9%9B%86","https://crta.info/wiki/%E8%87%AA%E7%84%B6%E9%9B%86_-_A224"],textual_certainty:"high",notes:"batch33 · Grok-4.5 catalog-driven"},{dz:"DZ1146",name_han:"葆光集",name_vi:"Bảo Quang Tập",bu:"太平",author:"尹志平",era:"元（尹志平 1169–1251）",topic:"cultivation",essence:"Thi văn và vài tắc ngữ lục của Doãn Chí Bình—tổ sư kế vị Khâu Xử Cơ. Nói công–hạnh song tu, thanh nhàn xuất thế. Song hành với Thanh Hòa chân nhân Bắc du ngữ lục.",key_text:"全真之教，專於性命道德之妙。",use:"诗文集·全真宗师",sources:["https://zh.daoinfo.org/index.php?title=%E8%91%86%E5%85%89%E9%9B%86&variant=zh-hans","https://ctext.org/library.pl?if=gb&res=84822"],textual_certainty:"high",notes:"batch33 · Grok-4.5 catalog-driven"},{dz:"DZ1232",name_han:"道門十規",name_vi:"Đạo Môn Thập Quy",bu:"正一",author:"張宇初",era:"明初（約1406前後）",topic:"戒律",essence:"Mười quy tắc chỉnh đốn đạo môn của Trương Vũ Sơ (Thiên sư đời 43): kinh điển, giới luật, pháp lục, trai tiếu, nội tu. Tuyên ngôn cải cách sau loạn Nguyên–Minh. Chuẩn mực cho giáo đoàn Chính Nhất đầu Minh.",key_text:"凡行持之士，必以戒行為先。",use:"戒律·教团规范",sources:["https://www.persee.fr/doc/asie_0766-1177_2016_num_25_1_1468","https://brill.com/display/book/9781684176540/BP000014.pdf"],textual_certainty:"high",notes:"batch33 · Grok-4.5 catalog-driven"},{dz:"DZ1234",name_han:"丹陽真人直言",name_vi:"Đan Dương Chân Nhân Trực Ngôn",bu:"正一",author:"馬鈺說；門人記",era:"金",topic:"cultivation",essence:"Bài giảng ngắn của Mã Ngọc: đoạn tham dục, giữ thanh tĩnh, công hạnh. Khác với Đan Dương chân nhân ngữ lục dài hơn—đây là “trực ngôn” cô đọng. Cửa vào tư tưởng Toàn Chân đời đầu.",key_text:"除情去欲， thrift and purity as the root of perfection.",use:"语录·全真七真",sources:["https://brill.com/downloadpdf/book/9789047421733/Bej.9789004160385.i-554_011.xml","https://fabriziopregadio.com/files/PREGADIO_and_ESPOSITO_Daozang_jiyao_Catalogue.pdf"],textual_certainty:"high",notes:"batch33 · Grok-4.5 catalog-driven"},{dz:"DZ1250",name_han:"冲虛通妙侍宸王先生家話",name_vi:"Xung Hư Thông Diệu Thị Thần Vương Tiên Sinh Gia Thoại",bu:"正一",author:"王文卿說；袁庭植編",era:"南宋",topic:"ritual",essence:"Gia thoại Vương Văn Khanh (Vương Thị Thần) về lôi pháp: hô phong hoán vũ, nội ngoại hợp nhất. Nguồn sơ cấp cho Thần Tiêu lôi pháp đời Tống. Kết nối pháp thuật với nội chứng.",key_text:"雷霆之機，不外吾身。",use:"道法·雷法口授",sources:["https://brill.com/downloadpdf/display/title/69792.pdf","http://www.rsd.fju.edu.tw/images/uploads/FJRS/40-05.pdf"],textual_certainty:"high",notes:"batch33 · Grok-4.5 catalog-driven"},{dz:"DZ1253",name_han:"道法心傳",name_vi:"Đạo Pháp Tâm Truyền",bu:"正一",author:"王惟一",era:"元（自序1294）",topic:"ritual",essence:"Luận lôi pháp và tâm pháp của Vương Duy Nhất: hợp Toàn Chân nội tu với Chính Nhất lôi pháp. Nhấn “pháp từ tâm sinh”, chân diên chân hống. Cầu nối nội đan–lôi pháp đời Nguyên.",key_text:"先天一物號真鉛。",use:"道法·雷法心法",sources:["https://fabriziopregadio.com/files/PREGADIO_and_ESPOSITO_Daozang_jiyao_Catalogue.pdf","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch33 · Grok-4.5 catalog-driven"},{dz:"DZ1256",name_han:"真仙直指語錄",name_vi:"Chân Tiên Trực Chỉ Ngữ Lục",bu:"正一",author:"玄全子編",era:"元（約14世紀）",topic:"cultivation",essence:"Tổng tập ngữ lục các chân tiên Toàn Chân (Mã, Khâu…). Chỉ thẳng định tức, trừ vọng, xuất ly. Nguồn chuẩn cho yulu Toàn Chân thời trung kỳ.",key_text:"做修行人，先要心定。",use:"语录·全真",sources:["https://brill.com/display/book/9789047421733/Bej.9789004160385.i-554_015.pdf","https://www.mdpi.com/2077-1444/14/6/814"],textual_certainty:"high",notes:"batch33 · Grok-4.5 catalog-driven"},{dz:"DZ1285",name_han:"翊聖保德傳",name_vi:"Dực Thánh Bảo Đức Truyện",bu:"正一",author:"王欽若奉敕編",era:"北宋（約1016）",topic:"仙传",essence:"Chép khải thị của Dực Thánh Bảo Đức chân quân (Hắc Sát) cho đạo sĩ Trương Thủ Chân: kiếm pháp trừ tà, trai tiếu, La Thiên đại tiếu. Tín ngưỡng quan phương đời Tống Chân Tông. Vừa cảm ứng lục vừa nghi thức nhà nước.",key_text:"翊我宋德，保茲下民。",use:"谱录·感应神启",sources:["https://www.jstor.org/stable/26768560","https://cscr.nccu.edu.tw/PageDoc/Detail?fid=7649&id=36571"],textual_certainty:"high",notes:"batch33 · Grok-4.5 catalog-driven"},{dz:"DZ1429",name_han:"長春真人西遊記",name_vi:"Trường Xuân Chân Nhân Tây Du Ký",bu:"续道藏",author:"李志常",era:"元（1228前後）",topic:"仙传",essence:"Ký sự Khâu Xử Cơ Tây hành yết kiến Thành Cát Tư Hãn: đường đi, vấn đạo, giáo hóa. Vừa đạo sử vừa tư liệu giao thông Trung–Á. Không nhầm với tiểu thuyết Tây Du.",key_text:"一言止殺，四海蒙恩。",use:"谱录·全真史传",sources:["https://www.jstor.org/stable/26768560","http://www.chinaknowledge.de/Literature/Daoists/changchunzhenrenxiyouji.html"],textual_certainty:"high",notes:"batch33 · Grok-4.5 catalog-driven"},{dz:"DZ072",name_han:"元始天尊濟度血湖真經",name_vi:"Nguyên Thủy Thiên Tôn Tế Độ Huyết Hồ Chân Kinh",bu:"洞真",author:"佚名",era:"宋元",topic:"cultivation|ritual",essence:"Kinh ba quyển thuộc hệ cứu độ độ u, thuật huyết hồ địa ngục dưới đáy biển Bắc Âm, nơi giam hồn sản vong, huyết thương. Nguyên Thủy Thiên Tôn vì Thái Ất Cứu Khổ tuyên pháp, ban chú và nghi thức tế độ để khô cạn huyết hồ, giải oan siêu thăng. Đây là bản kinh đạo giáo mô tả huyết hồ chi tiết nhất trong Chính Thống Đạo Tạng.",key_text:"爾時元始天尊在九清妙境三元寶宮",use:"Tụng trong khoa siêu độ sản vong, huyết hồ, giải oan phụ nữ; tham chiếu nghi độ u và văn hóa cứu khổ.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.daoinfo.org/index.php?title=%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E6%BF%9F%E5%BA%A6%E8%A1%80%E6%B9%96%E7%9C%9F%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E6%BF%9F%E5%BA%A6%E8%A1%80%E6%B9%96%E7%9C%9F%E7%B6%93","https://www.shidianguji.com/zh/book/DZ0072"],textual_certainty:"high",notes:"batch34 · Grok-4.5 catalog-driven"},{dz:"DZ215",name_han:"地府十王拔度儀",name_vi:"Địa Phủ Thập Vương Bạt Độ Nghi",bu:"洞真",author:"佚名",era:"宋元",topic:"ritual",essence:"Nghi thức một quyển siêu độ vong linh theo thập vương địa phủ, phối hợp Tam Thanh và Thái Ất Cứu Khổ Thiên Tôn. Lần lượt cúng dường mười cung (Thái Quảng, Sơ Giang, Tống Đế, Ngũ Quan, Diêm La, Biến Thành, Thái Sơn, Bình Đẳng, Đô Thị, Chuyển Luân) theo các kỵ nhật sau khi chết. Là cứ liệu then chốt về tín ngưỡng thập vương và khoa bạt độ trong đạo giáo.",key_text:"普獻無邊聖，香煙散大羅",use:"Nghi thức độ vong theo thập thất / bách nhật; nghiên cứu địa phủ thập vương và nghi lễ Tống–Nguyên.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.daoinfo.org/index.php?title=%E5%9C%B0%E5%BA%9C%E5%8D%81%E7%8E%8B%E6%8B%94%E5%BA%A6%E5%84%80&variant=zh-hant","https://zh.wikisource.org/zh-hant/%E5%9C%B0%E5%BA%9C%E5%8D%81%E7%8E%8B%E6%8B%94%E5%BA%A6%E5%84%80","https://www.shidianguji.com/book/DZ0215"],textual_certainty:"high",notes:"batch34 · Grok-4.5 catalog-driven"},{dz:"DZ075",name_han:"元始天尊說甘露昇天神咒妙經",name_vi:"Nguyên Thủy Thiên Tôn Thuyết Cam Lộ Thăng Thiên Thần Chú Diệu Kinh",bu:"洞真",author:"佚名",era:"宋元",topic:"ritual|mantra",essence:"Kinh ngắn thuộc hệ cứu độ: Nguyên Thủy giảng cho Tịnh Minh Nguyệt Quang Đồng Tử về chúng sinh tạo thập ác, sau chết đọa Phong Đô. Ban thần chú cam lộ và chú phá địa ngục thăng thiên để vong hồn được ẩm thực cam lộ, đoạn phiền não, xuất ly u đồ. Thường đi cùng các kinh huyết hồ, bạt tội trong khoa thí thực.",key_text:"茫茫酆都中，重重金剛山。靈寶無量光，洞照炎池煩",use:"Tụng chú cam lộ trong thí thực, siêu độ; phối hợp khoa phá ngục, pháp thực.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.daoinfo.org/index.php?title=%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E7%94%98%E9%9C%B2%E6%98%87%E5%A4%A9%E7%A5%9E%E5%92%92%E5%A6%99%E7%B6%93&variant=zh-hant","https://zh.wikisource.org/zh-hant/%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E7%94%98%E9%9C%B2%E6%98%87%E5%A4%A9%E7%A5%9E%E5%91%AA%E5%A6%99%E7%B6%93","https://ctext.org/wiki.pl?if=gb&chapter=168030"],textual_certainty:"high",notes:"batch34 · Grok-4.5 catalog-driven"},{dz:"DZ538",name_han:"太一救苦天尊說拔度血湖寶懺",name_vi:"Thái Nhất Cứu Khổ Thiên Tôn Thuyết Bạt Độ Huyết Hồ Bảo Sám",bu:"洞玄",author:"佚名",era:"北宋—宋元",topic:"ritual",essence:"Bảo sám chuyên về huyết hồ: Cứu Khổ Thiên Tôn ngồi đài sen chín sắc, thuật tội nghiệp sản vong, huyết thương, chiến trận, hình lục. Mô tả huyết hồ năm ngục (huyết nùng, huyết lãnh, huyết uế…), ban phù mệnh, cửu sắc tường quang làm khô huyết hồ, siêu thăng tội hồn. Là sám văn cốt lõi của khoa huyết hồ, bổ sung cho kinh tế độ huyết hồ.",key_text:"爾時，救苦天尊坐九色蓮臺，威光遍滿十方",use:"Sám hối, siêu độ sản vong và vong huyết thương; nghi thức bạt độ huyết hồ.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%80%E6%95%91%E8%8B%A6%E5%A4%A9%E5%B0%8A%E8%AA%AA%E6%8B%94%E5%BA%A6%E8%A1%80%E6%B9%96%E5%AF%B6%E6%87%BA","https://ctext.org/wiki.pl?if=en&chapter=368840&remap=gb"],textual_certainty:"high",notes:"batch34 · Grok-4.5 catalog-driven"},{dz:"DZ378",name_han:"太上救苦天尊說消愆滅罪經",name_vi:"Thái Thượng Cứu Khổ Thiên Tôn Thuyết Tiêu Khiên Diệt Tội Kinh",bu:"洞玄",author:"佚名",era:"唐宋",topic:"ritual|classic",essence:"Kinh cứu khổ nhấn mạnh tiêu khiên diệt tội: chúng sinh tạo thập ác ngũ nghịch, bất hiếu, phá trai sát sinh phải chịu quả báo u minh. Cứu Khổ Thiên Tôn khuyên tu trai bố thí, kiến công đức, triệu thỉnh thiên long địa kỳ, Diêm La, Thái Sơn phủ quân lượng công xá tội. Thuộc mạch cứu độ bạt tội, dùng rộng trong sám hối và khoa độ vong.",key_text:"爾時，救苦天尊設大慈悲，為諸眾生滅除一切罪業，救拔沈淪",use:"Tụng sám tiêu tội, khoa cứu khổ; nghi lễ xá tội độ vong.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%95%91%E8%8B%A6%E5%A4%A9%E5%B0%8A%E8%AA%AA%E6%B6%88%E6%84%86%E6%BB%85%E7%BD%AA%E7%B6%93&variant=zh-hant","https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%8A%E6%95%91%E8%8B%A6%E5%A4%A9%E5%B0%8A%E8%AA%AA%E6%B6%88%E6%84%86%E6%BB%85%E7%BD%AA%E7%B6%93"],textual_certainty:"high",notes:"batch34 · Grok-4.5 catalog-driven"},{dz:"DZ379",name_han:"太上說酆都拔苦愈樂妙經",name_vi:"Thái Thượng Thuyết Phong Đô Bạt Khổ Dũ Lạc Diệu Kinh",bu:"洞玄",author:"佚名",era:"唐宋",topic:"ritual|classic",essence:"Kinh giả thác Bạt Khổ Dũ Lạc Thiên Tôn tại thượng cảnh Phong Đô Đông Cực cung, phóng ngũ sắc viên quang chiếu mười phương. Thấy vô lượng chúng sinh khổ trên đao sơn, khuyên hồi tâm quy chính đạo, được xá tội thăng lên Tử Vi. Tập trung cứu độ linh hồn đọa Phong Đô, chuyển khổ thành vui.",key_text:"爾時，拔苦愈樂天尊，在酆都上境東極宮中，放五色圓光，照十方",use:"Siêu độ linh hồn Phong Đô; tụng trong khoa bạt khổ, phá ngục.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT02%E6%B4%9E%E7%8E%84%E9%83%A8/CMT0201%E6%9C%AC%E6%96%87%E9%A1%9E/CMT0201ALL/CH020164%E5%A4%AA%E4%B8%8A%E8%AA%AA%E9%85%86%E9%83%BD%E6%8B%94%E8%8B%A6%E6%84%88%E6%A8%82%E5%A6%99%E7%B6%93.htm","https://ctext.org/wiki.pl?if=gb&chapter=598363&remap=gb"],textual_certainty:"high",notes:"batch34 · Grok-4.5 catalog-driven"},{dz:"DZ373",name_han:"太上洞玄靈寶往生救苦妙經",name_vi:"Thái Thượng Động Huyền Linh Bảo Vãng Sinh Cứu Khổ Diệu Kinh",bu:"洞玄",author:"佚名",era:"唐宋—宋",topic:"ritual|classic",essence:"Kinh Linh Bảo về vãng sinh cứu khổ, nhấn mạnh nhờ oai thần Cứu Khổ và công đức tụng kinh, bố thí pháp thực để vong hồn thoát u đồ, được vãng sinh tịnh cảnh. Khác với bản “Thiên Tôn thuyết cứu khổ”, bản này gắn trực tiếp chủ đề vãng sinh–cứu khổ trong hệ độ u.",key_text:"null",use:"Khoa vãng sinh, thí thực, cứu khổ độ vong; đối chiếu các bản cứu khổ kinh.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.chinaknowledge.de/Literature/Daoists/daozang.html","https://zh.daoinfo.org/wiki/%E9%A6%96%E9%A1%B5"],textual_certainty:"partial",notes:"batch34 · Grok-4.5 catalog-driven"},{dz:"DZ076",name_han:"元始說功德法食往生經",name_vi:"Nguyên Thủy Thuyết Công Đức Pháp Thực Vãng Sinh Kinh",bu:"洞真",author:"佚名",era:"宋元",topic:"ritual",essence:"Kinh thuộc hệ pháp thực–vãng sinh: Nguyên Thủy giảng công đức thí thực, dùng pháp thực thanh tịnh nuôi dưỡng vong hồn, đoạn đói khát u minh, trợ duyên vãng sinh. Thường được ghép với huyết hồ, cam lộ, cửu u trong bộ ngũ kinh độ vong của Đạo Tạng.",key_text:"null",use:"Khoa thí thực, pháp thực vãng sinh; nghi thức cúng vong, siêu độ.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://upload.wikimedia.org/wikipedia/commons/a/af/NLC892-411999005947-5899_%E9%81%93%E8%97%8F_%E7%AC%AC154%E5%86%8A.pdf","https://www.shidianguji.com/zh/book/DZ0072"],textual_certainty:"high",notes:"batch34 · Grok-4.5 catalog-driven"},{dz:"DZ563",name_han:"太上靈寶淨明飛仙度人經法",name_vi:"Thái Thượng Linh Bảo Tịnh Minh Phi Tiên Độ Nhân Kinh Pháp",bu:"洞玄",author:"原題許旌陽釋（南宋—元淨明道）",era:"南宋—元",topic:"classic|philosophy|ritual",essence:"Kinh pháp cốt lõi Tịnh Minh: giả thác Hứa Tốn chú thích và diễn pháp Độ Nhân Kinh theo tông chỉ trung hiếu, tịnh minh. Năm quyển (kèm mục lục, thích lệ) kết hợp nội luyện, giới hạnh và độ nhân, là bản “Độ Nhân” của phái Tịnh Minh khác với Độ Nhân đại pháp chính thống.",key_text:"天地定位，陰陽協和，星辰順度，日月昭明",use:"Nghiên cứu Tịnh Minh đạo; tu học trung hiếu tịnh minh, pháp độ nhân phái Hứa Chân Quân.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%8A%E9%9D%88%E5%AF%B6%E6%B7%A8%E6%98%8E%E9%A3%9B%E4%BB%99%E5%BA%A6%E4%BA%BA%E7%B6%93%E6%B3%95","https://baike.baidu.com/item/%E5%A4%AA%E4%B8%8A%E7%81%B5%E5%AE%9D%E5%87%80%E6%98%8E%E9%A3%9E%E4%BB%99%E5%BA%A6%E4%BA%BA%E7%BB%8F%E6%B3%95/17625028","https://ctext.org/wiki.pl?if=en&chapter=809024&remap=gb"],textual_certainty:"high",notes:"batch34 · Grok-4.5 catalog-driven"},{dz:"DZ557",name_han:"太上靈寶淨明入道品",name_vi:"Thái Thượng Linh Bảo Tịnh Minh Nhập Đạo Phẩm",bu:"洞玄",author:"佚名（淨明道）",era:"南宋",topic:"classic|戒律",essence:"Phẩm nhập đạo của Tịnh Minh, quy định tư cách, giới hạnh, thứ bậc và nghi thức ban đầu khi vào phái. Nhấn mạnh tịnh minh tâm địa, trung hiếu làm gốc trước khi thụ pháp ấn, phù chương. Là cửa ngõ hiểu hệ thống “nhập đạo–thụ pháp” của Tịnh Minh bên cạnh Trung Hiếu Toàn Thư.",key_text:"null",use:"Quy trình nhập môn Tịnh Minh; đối chiếu giới phẩm và pháp ấn phái.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.chinaknowledge.de/Literature/Daoists/daozang.html","https://zh.daoinfo.org/wiki/%E9%A6%96%E9%A1%B5"],textual_certainty:"high",notes:"batch34 · Grok-4.5 catalog-driven"},{dz:"DZ562",name_han:"靈寶淨明新修九老神印伏魔祕法",name_vi:"Linh Bảo Tịnh Minh Tân Tu Cửu Lão Thần Ấn Phục Ma Bí Pháp",bu:"洞玄",author:"佚名（淨明道）",era:"南宋",topic:"ritual|fu",essence:"Bí pháp Tịnh Minh về cửu lão thần ấn phục ma: kết hợp thần ấn, phù lục và nghi thức trấn tà. Thuộc nhóm pháp ấn–phục ma của viện Linh Bảo Tịnh Minh, phản ánh thực tiễn hành pháp dân gian–giáo đoàn Tịnh Minh đời Tống.",key_text:"null",use:"Pháp ấn phục ma Tịnh Minh; nghiên cứu ấn chương, phù lục phái.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.chinaknowledge.de/Literature/Daoists/daozang.html","https://zh.daoinfo.org/wiki/%E9%A6%96%E9%A1%B5"],textual_certainty:"high",notes:"batch34 · Grok-4.5 catalog-driven"},{dz:"DZ768",name_han:"圖經衍義本草",name_vi:"Đồ Kinh Diễn Nghĩa Bản Thảo",bu:"洞神",author:"唐慎微、寇宗奭（許洪校）",era:"北宋—南宋（道藏合編本）",topic:"道医本草",essence:"Bản thảo học lớn trong Động Thần bộ: hợp biên chứng loại/bản thảo đồ kinh với Bản Thảo Diễn Nghĩa của Khấu Tông Thích, có đồ và diễn nghĩa dược vật. Đạo Tạng thu khoảng 42 quyển chính kèm tự lệ, là nguồn dược liệu–đạo y quan trọng gắn đạo quán và y phương.",key_text:"null",use:"Tra cứu dược tính, đạo y, ngoại đan dược liệu; lịch sử bản thảo.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.daoinfo.org/index.php?title=%E5%9C%96%E7%B6%93%E8%A1%8D%E7%BE%A9%E6%9C%AC%E8%8D%89&variant=zh-hant","https://ctext.org/wiki.pl?if=gb&res=424150","https://www.shidianguji.com/book/DZ0769"],textual_certainty:"high",notes:"batch34 · Grok-4.5 catalog-driven"},{dz:"DZ841",name_han:"孫真人攝養論",name_vi:"Tôn Chân Nhân Nhiếp Dưỡng Luận",bu:"洞神",author:"孫思邈（題）",era:"唐",topic:"道医本草|cultivation",essence:"Luận nhiếp dưỡng theo mười hai tháng: mỗi tháng tạng phủ thịnh suy khác nhau, điều chỉnh ngũ vị, khởi cư, kiêng kỵ (ví dụ tháng Giêng thận khí thụ bệnh, phế tạng khí vi). Văn thể gần Nguyệt Lệnh, khoảng 1500 chữ, là cẩm nang đạo y–dưỡng sinh gắn Tôn Tư Mạc trong Đạo Tạng.",key_text:"正月腎氣受病，肺藏氣微。宜減鹹酸增辛味，助腎補肺，安養胃氣",use:"Dưỡng sinh theo tháng; đạo y thời khí, điều tạng phủ.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.daoinfo.org/index.php?title=%E5%AD%AB%E7%9C%9F%E4%BA%BA%E6%94%9D%E9%A4%8A%E8%AB%96&variant=zh-hant","https://zh.wikisource.org/zh-hant/%E5%AD%AB%E7%9C%9F%E4%BA%BA%E6%94%9D%E9%A4%8A%E8%AB%96","https://www.shidianguji.com/book/DZ0841"],textual_certainty:"high",notes:"batch34 · Grok-4.5 catalog-driven"},{dz:"DZ1163",name_han:"孫真人備急千金要方",name_vi:"Tôn Chân Nhân Bị Cấp Thiên Kim Yếu Phương",bu:"太平",author:"孫思邈",era:"唐",topic:"道医本草",essence:"Bộ y phương lớn nhất được thu vào Đạo Tạng (Thái Bình bộ), gồm mục lục và chính văn nhiều quyển. Thu thập phương dược cấp cứu, nội ngoại phụ nhi, dưỡng sinh, thể hiện truyền thống “dược vương” Tôn Tư Mạc gắn đạo quán. Là cầu nối đạo y và y học lâm sàng Trung cổ.",key_text:"null",use:"Y phương lâm sàng, đạo y; tra cứu bị cấp phương và dưỡng sinh.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.chinaknowledge.de/Literature/Daoists/daozang.html","https://ctext.org/wiki.pl?if=gb&res=943783"],textual_certainty:"high",notes:"batch34 · Grok-4.5 catalog-driven"},{dz:"DZ307",name_han:"西嶽華山誌",name_vi:"Tây Nhạc Hoa Sơn Chí",bu:"洞真",author:"王處一（金大定癸卯序，1183）",era:"金",topic:"道教碑记宫观志",essence:"Sơn chí Hoa Sơn: thu thập phong huyệt, từ vũ, dược phẩm, tiên tích từ cựu Hoa Sơn ký, đồ kinh và liệt tiên truyện. Nhấn mạnh danh sơn chính thần phù trợ luyện dược, ghi cung quán, đan lô, bái đàn. Nguồn địa chí đạo giáo quan trọng về Tây Nhạc, khác với Mao Sơn chí đã được khai thác nhiều.",key_text:"凡古之士，合作神藥，必入名山福地，不止小山之中",use:"Địa chí đạo giáo, lịch sử cung quán Hoa Sơn; tham khảo đan dược danh sơn.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/wiki/%E8%A5%BF%E5%B6%BD%E8%8F%AF%E5%B1%B1%E8%AA%8C","https://crta.info/wiki/Daozang_-_DZ"],textual_certainty:"high",notes:"batch34 · Grok-4.5 catalog-driven"},{dz:"DZ972",name_han:"宮觀碑誌",name_vi:"Cung Quán Bi Chí",bu:"洞神",author:"佚名（元全真道士編）",era:"元",topic:"道教碑记宫观志",essence:"Tuyển tập chín bài bia cung quán đạo giáo: mở đầu bằng ký trùng tu Vương Mẫu cung của Đào Cốc đời Tống, các bài còn lại chủ yếu Kim–Nguyên (Thiên Trường quán, Huyền Đô bảo tạng, Hoàng lục đại tiếu, Thái Thanh cung, Trùng Dương thành đạo cung…). Tư liệu sử học then chốt về kiến trúc, giáo đoàn Toàn Chân và quan hệ triều đình–đạo quán.",key_text:"null",use:"Sử đạo giáo Kim–Nguyên; nghiên cứu bia ký, cung quán, Toàn Chân.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.daoinfo.org/index.php?title=%E5%AE%AE%E8%A7%80%E7%A2%91%E8%AA%8C&variant=zh-hans","http://en.daoinfo.org/wiki/Stele_Inscriptions_of_Temples_and_Monasteries"],textual_certainty:"high",notes:"batch34 · Grok-4.5 catalog-driven"},{dz:"DZ005",name_han:"太上無極總真文昌大洞仙經",name_vi:"Thái Thượng Vô Cực Tổng Chân Văn Xương Đại Động Tiên Kinh",bu:"洞真",author:"托名梓潼帝君降筆（劉安勝壇）",era:"南宋（乾道四年 1168 以降）",topic:"classic",essence:"Bản Đại Động gắn với Văn Xương/Đế Quân Tử Đồng, mô phỏng Thượng Thanh Đại Động và Độ Nhân, dùng tụng trì để khai hóa, tiêu kiếp, cầu lộc khoa cử. Là kinh trụ cột của hệ Văn Xương trong Chính Thống Đạo Tạng, khác hẳn Đại Động Thượng Thanh cổ.",key_text:"道言昔在龍漢劫初，元始天王出大洞玉經於高上大有玉清宮。",use:"Tụng kinh Văn Xương, nghi thức cầu công danh, nghiên cứu giáng bút Tống-Nguyên.",sources:["https://ctext.org/wiki.pl?if=gb&res=68211","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E7%84%A1%E6%A5%B5%E7%B8%BD%E7%9C%9F%E6%96%87%E6%98%8C%E5%A4%A7%E6%B4%9E%E4%BB%99%E7%B6%93","https://dao.crs.cuhk.edu.hk/Main/wp-content/uploads/2018/08/DAO6_07_Vincent-Goossaert.pdf"],textual_certainty:"high",notes:"batch35 · Grok-4.5 catalog-driven"},{dz:"DZ028",name_han:"元始天尊說梓潼帝君應驗經",name_vi:"Nguyên Thủy Thiên Tôn Thuyết Tử Đồng Đế Quân Ứng Nghiệm Kinh",bu:"洞真",author:"佚名",era:"元代頃",topic:"classic",essence:"Kinh ngắn kể công đức ứng nghiệm của Tử Đồng Đế Quân: hộ quốc, tiêu đạo tặc, bảo hộ canh tác và sinh hoạt. Bổ sung cho bản nguyện kinh, nhấn mạnh linh nghiệm dân gian hơn là triết lý huyền vi.",key_text:"常奉至真，永依玄教，以斯利益，遍悉莊嚴。",use:"Tụng cầu Văn Xương che chở, đối chiếu với Bản Nguyện Kinh.",sources:["https://www.jstor.org/stable/26768560","https://dao.crs.cuhk.edu.hk/Main/wp-content/uploads/2018/08/DAO7_03_Jihyun-Kim.pdf","https://zh.daoinfo.org/"],textual_certainty:"high",notes:"batch35 · Grok-4.5 catalog-driven"},{dz:"DZ099",name_han:"九天應元雷聲普化天尊玉樞寶經集注",name_vi:"Cửu Thiên Ứng Nguyên Lôi Thanh Phổ Hóa Thiên Tôn Ngọc Khu Bảo Kinh Tập Chú",bu:"洞真",author:"玄陽子（集注）",era:"元代",topic:"注疏杂",essence:"Tập chú Ngọc Khu Bảo Kinh, giải theo phù chú, lôi pháp và tiêu tai độ ách. Giải thích danh hiệu Lôi Thanh Phổ Hóa Thiên Tôn, cơ cấu Ngọc Khu viện và cách trì tụng. Bản chú quan trọng khi kinh gốc đã được phủ, không trùng tiêu đề kinh đơn.",key_text:"九者，陽數也，乃天道也。主於震宮，故東南有九炁之說也。",use:"Đọc kèm khi tụng Ngọc Khu, nghiên cứu Thần Tiêu Lôi pháp.",sources:["https://www.shidianguji.com/zh/book/DZ0099","https://zh.daoinfo.org/index.php?title=%E4%B9%9D%E5%A4%A9%E6%87%89%E5%85%83%E9%9B%B7%E8%81%B2%E6%99%AE%E5%8C%96%E5%A4%A9%E5%B0%8A%E7%8E%89%E6%A8%9E%E5%AF%B6%E7%B6%93%E9%9B%86%E6%B3%A8","https://zh.wikisource.org/zh-hans/%E4%B9%9D%E5%A4%A9%E6%87%89%E5%85%83%E9%9B%B7%E8%81%B2%E6%99%AE%E5%8C%96%E5%A4%A9%E5%B0%8A%E7%8E%89%E6%A8%9E%E5%AF%B6%E7%B6%93%E9%9B%86%E8%A8%BB"],textual_certainty:"high",notes:"batch35 · Grok-4.5 catalog-driven"},{dz:"DZ103",name_han:"玉清無極總真文昌大洞仙經注",name_vi:"Ngọc Thanh Vô Cực Tổng Chân Văn Xương Đại Động Tiên Kinh Chú",bu:"洞真",author:"衛琪（中陽子）",era:"元至大三年（1311）",topic:"注疏杂",essence:"Chú mười quyển cho Văn Xương Đại Động, kết hợp đồ thư Dịch học, Hà Lạc và nội đan. Hai quyển đầu là luận, tám quyển sau chú kinh; là lớp chú triết lý sâu nhất của hệ Văn Xương.",key_text:"null",use:"Đối chiếu khi đọc Đại Động Văn Xương, nghiên cứu Dịch-Đạo hợp lưu.",sources:["https://www.shidianguji.com/book/DZ0103","https://zh.daoinfo.org/index.php?title=%E7%8E%89%E6%B8%85%E7%84%A1%E6%A5%B5%E7%B8%BD%E7%9C%9F%E6%96%87%E6%98%8C%E5%A4%A7%E6%B4%9E%E4%BB%99%E7%B6%93%E6%B3%A8","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch35 · Grok-4.5 catalog-driven"},{dz:"DZ169",name_han:"清河內傳",name_vi:"Thanh Hà Nội Truyền",bu:"洞真",author:"佚名（文昌降傳系統）",era:"南宋（淳熙前後已行）",topic:"仙传",essence:"Nội truyện về nguồn gốc, hóa thân và đạo hạnh của Văn Xương/Tử Đồng, gắn với Thanh Hà. Là tài liệu truyền ký then chốt để hiểu sự hợp nhất thần Tử Đồng và tinh Văn Xương.",key_text:"null",use:"Nghiên cứu thần phổ Văn Xương, đối chiếu với Hóa Thư.",sources:["https://crta.info/wiki/%E6%B8%85%E6%B2%B3%E5%85%A7%E5%82%B3_-_DZ169","https://artmuseum.princeton.edu/art/collections/objects/57553","https://dao.crs.cuhk.edu.hk/Main/wp-content/uploads/2018/08/DAO6_07_Vincent-Goossaert.pdf"],textual_certainty:"high",notes:"batch35 · Grok-4.5 catalog-driven"},{dz:"DZ399",name_han:"太上洞玄靈寶天尊說救苦妙經註解",name_vi:"Thái Thượng Động Huyền Linh Bảo Thiên Tôn Thuyết Cứu Khổ Diệu Kinh Chú Giải",bu:"洞玄",author:"洞陽子",era:"宋元間",topic:"注疏杂",essence:"Chú Cứu Khổ Kinh theo hướng nội đan và thủy hỏa luyện độ vong hồn. Giải «救苦天尊遍滿十方界» thành khí-thần-luyện độ, phục vụ khoa nghi độ vong.",key_text:"爾時救苦天尊，遍滿十方界，常以威神力，救拔諸眾生。",use:"Học nghi độ vong, đọc kèm Cứu Khổ Kinh.",sources:["https://www.shidianguji.com/book/DZ0399","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E5%A4%A9%E5%B0%8A%E8%AA%AA%E6%95%91%E8%8B%A6%E5%A6%99%E7%B6%93%E6%B3%A8%E8%A7%A3","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT02%E6%B4%9E%E7%8E%84%E9%83%A8/CMT0203%E7%8E%89%E8%A8%A3%E9%A1%9E/CMT0203ALL/CH020305%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E5%A4%A9%E5%B0%8A%E8%AA%AA%E6%95%91%E8%8B%A6%E5%A6%99%E7%B6%93%E8%A8%BB%E8%A7%A3.htm"],textual_certainty:"high",notes:"batch35 · Grok-4.5 catalog-driven"},{dz:"DZ484",name_han:"金籙大齋宿啟儀",name_vi:"Kim Lục Đại Trai Túc Khải Nghi",bu:"洞玄",author:"佚名",era:"宋代頃",topic:"ritual",essence:"Khoa nghi túc khải (đêm trước) của Kim Lục đại trai: lễ sư, tồn niệm, khải cáo thập phương trước khi lập đàn chính. Dùng cho trai nghi cấp đế vương/quốc gia.",key_text:"各禮師存念如法。",use:"Tham chiếu khi dựng Kim Lục trai, nghiên cứu trình tự túc khải.",sources:["https://www.shidianguji.com/zh/book/DZ0484","https://zh.wikisource.org/zh-hans/%E9%87%91%E7%B1%99%E5%A4%A7%E9%BD%8B%E5%AE%BF%E5%95%9F%E5%84%80","https://zh.daoinfo.org/index.php?title=%E9%87%91%E7%B1%99%E5%A4%A7%E9%BD%8B%E5%AE%BF%E5%95%9F%E5%84%80"],textual_certainty:"high",notes:"batch35 · Grok-4.5 catalog-driven"},{dz:"DZ509",name_han:"黃籙救苦十齋轉經儀",name_vi:"Hoàng Lục Cứu Khổ Thập Trai Chuyển Kinh Nghi",bu:"洞玄",author:"佚名（金元全真氣息）",era:"南宋–金元",topic:"ritual",essence:"Khoa nghi mười lần tụng kinh để cứu độ vong linh, chủ thần Thái Ất Cứu Khổ. Mỗi độ có khải thỉnh–tụng kinh–hồi hướng; cuối có màu nội đan và tam giáo.",key_text:"此香，乾坤育質，日月凝華。",use:"Khoa độ vong Hoàng Lục, chuyển kinh cứu khổ.",sources:["https://www.shidianguji.com/book/DZ0509","https://zh.daoinfo.org/index.php?title=%E9%BB%83%E7%B1%99%E6%95%91%E8%8B%A6%E5%8D%81%E9%BD%8B%E8%BD%89%E7%B6%93%E5%84%80","https://zh.wikisource.org/zh-hans/%E9%BB%83%E7%B1%99%E6%95%91%E8%8B%A6%E5%8D%81%E9%BD%8B%E8%BD%89%E7%B6%93%E5%84%80"],textual_certainty:"high",notes:"batch35 · Grok-4.5 catalog-driven"},{dz:"DZ751",name_han:"太上玄靈北斗本命延生真經註解",name_vi:"Thái Thượng Huyền Linh Bắc Đẩu Bản Mệnh Diên Sinh Chân Kinh Chú Giải",bu:"洞神",author:"玄元真人",era:"宋元間",topic:"注疏杂",essence:"Chú giải Bắc Đẩu Bản Mệnh theo hướng thr thần–tinh tượng–bản mệnh, khác bản chú của Từ Đạo Linh (註). Giải cấu trúc cửu hoàng, trì tụng và phù tượng.",key_text:"null",use:"Đọc kèm Bắc Đẩu kinh, so sánh các chú bản.",sources:["https://www.jstor.org/stable/26768560","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E7%8E%84%E9%9D%88%E5%8C%97%E6%96%97%E6%9C%AC%E5%91%BD%E5%BB%B6%E7%94%9F%E7%9C%9F%E7%B6%93%E8%A8%BB%E8%A7%A3","https://fabriziopregadio.com/files/PREGADIO_and_ESPOSITO_Daozang_jiyao_Catalogue.pdf"],textual_certainty:"high",notes:"batch35 · Grok-4.5 catalog-driven"},{dz:"DZ754",name_han:"太上說玄天大聖真武本傳神咒妙經",name_vi:"Thái Thượng Thuyết Huyền Thiên Đại Thánh Chân Vũ Bản Truyện Thần Chú Diệu Kinh",bu:"洞神",author:"佚名（陳伀集疏本亦存）",era:"唐末–北宋流行",topic:"classic",essence:"Kể thần tích Chân Vũ/Huyền Thiên, thần chú tứ ngôn và công năng trấn yêu hộ quốc. Là kinh bản truyện cốt lõi của tín ngưỡng Võ Đang–Huyền Đế, ngoài hệ Khải Thánh Lục.",key_text:"仰啟玄天大聖者，北方壬癸至靈神。",use:"Tụng thần chú Chân Vũ, nghiên cứu thần phổ Huyền Thiên.",sources:["https://www.shidianguji.com/zh/book/DZ0754","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E8%AA%AA%E7%8E%84%E5%A4%A9%E5%A4%A7%E8%81%96%E7%9C%9F%E6%AD%A6%E6%9C%AC%E5%82%B3%E7%A5%9E%E5%91%AA%E5%A6%99%E7%B6%93","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E8%AA%AA%E7%8E%84%E5%A4%A9%E5%A4%A7%E8%81%96%E7%9C%9F%E6%AD%A6%E6%9C%AC%E5%82%B3%E7%A5%9E%E5%91%AA%E5%A6%99%E7%B6%93"],textual_certainty:"high",notes:"batch35 · Grok-4.5 catalog-driven"},{dz:"DZ762",name_han:"太上太清天童護命妙經註",name_vi:"Thái Thượng Thái Thanh Thiên Đồng Hộ Mệnh Diệu Kinh Chú",bu:"洞神",author:"侯善淵",era:"金朝",topic:"注疏杂",essence:"Chú Thiên Đồng Hộ Mệnh: mỗi câu kinh kèm tứ tuyệt thất ngôn, giải «thiên đạo–đồng đức» theo khí thanh dương và tu chân. Là lớp chú hộ mệnh quan trọng còn sót.",key_text:"天道者運為清陽之氣也，童德者動合純粹之真也。",use:"Đọc chú khi trì Thiên Đồng kinh.",sources:["https://www.shidianguji.com/book/DZ0762","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E5%A4%AA%E6%B8%85%E5%A4%A9%E7%AB%A5%E8%AD%B7%E5%91%BD%E5%A6%99%E7%B6%93%E8%A8%BB","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E5%A4%AA%E6%B8%85%E5%A4%A9%E7%AB%A5%E8%AD%B7%E5%91%BD%E5%A6%99%E7%B6%93%E8%A8%BB"],textual_certainty:"high",notes:"batch35 · Grok-4.5 catalog-driven"},{dz:"DZ959",name_han:"大明玄天上帝瑞應圖錄",name_vi:"Đại Minh Huyền Thiên Thượng Đế Thụy Ứng Đồ Lục",bu:"洞神",author:"佚名（永樂武當道士編）",era:"明永樂（約1412–1420s）",topic:"仙传",essence:"Ghi các điềm lành khi triều Minh xây dựng cung quán Võ Đang: hắc vân cảm ứng, lang mai trình thụy, thần lưu cự mộc… Kết hợp chiếu dụ, bi văn và hình vẽ, là sử liệu–thần tích Huyền Đế đời Minh.",key_text:"null",use:"Nghiên cứu Võ Đang, tín ngưỡng Chân Vũ triều Minh.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%A7%E6%98%8E%E7%8E%84%E5%A4%A9%E4%B8%8A%E5%B8%9D%E7%91%9E%E6%87%89%E5%9C%96%E9%8C%84","https://zh.wikisource.org/zh-hans/%E5%A4%A7%E6%98%8E%E7%8E%84%E5%A4%A9%E4%B8%8A%E5%B8%9D%E7%91%9E%E6%87%89%E5%9C%96%E9%8C%84","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch35 · Grok-4.5 catalog-driven"},{dz:"DZ961",name_han:"玄天上帝啟聖靈異錄",name_vi:"Huyền Thiên Thượng Đế Khải Thánh Linh Dị Lục",bu:"洞神",author:"徐世隆等（碑記彙編）",era:"元末明初彙集",topic:"仙传",essence:"Tập bi ký, chiếu chỉ về việc sùng tự Huyền Đế đời Nguyên (như tạo miếu Chân Vũ Đại Đô). Bổ sung cho Khải Thánh Lục bằng tư liệu hành chính–linh dị, không trùng tám quyển Khải Thánh.",key_text:"null",use:"Đối chiếu lịch sử sùng bái Chân Vũ Nguyên–Minh.",sources:["https://www.shidianguji.com/book/DZ0961","https://zh.daoinfo.org/index.php?title=%E7%8E%84%E5%A4%A9%E4%B8%8A%E5%B8%9D%E5%95%9F%E8%81%96%E9%9D%88%E7%95%B0%E9%8C%84","https://zh.wikisource.org/wiki/%E7%8E%84%E5%A4%A9%E4%B8%8A%E5%B8%9D%E5%95%9F%E8%81%96%E9%9D%88%E7%95%B0%E9%8C%84"],textual_certainty:"high",notes:"batch35 · Grok-4.5 catalog-driven"},{dz:"DZ1170",name_han:"太上老君說上七滅罪集福妙經",name_vi:"Thái Thượng Lão Quân Thuyết Thượng Thất Diệt Tội Tập Phúc Diệu Kinh",bu:"正一",author:"佚名",era:"唐代道經",topic:"classic",essence:"Kinh ngắn dạy vào ngày «thượng thất» (các ngày sao Bắc Đẩu giáng) tụng kinh, sám tội, chương kiếu cầu Bắc Đẩu tinh quân diên sinh trị bệnh. Nối kinh tinh đẩu với sám hối tập phúc.",key_text:"凡俗無知，上七真聖每月降在人間，可以消災懺罪，請福延生。",use:"Sám tội theo lịch sao, nghi Bắc Đẩu dân gian.",sources:["https://www.shidianguji.com/book/DZ1170","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E4%B8%8A%E4%B8%83%E6%BB%85%E7%BD%AA%E9%9B%86%E7%A6%8F%E5%A6%99%E7%B6%93","https://ctext.org/wiki.pl?if=gb&chapter=939443"],textual_certainty:"high",notes:"batch35 · Grok-4.5 catalog-driven"},{dz:"DZ1214",name_han:"高上大洞文昌司祿紫陽寶籙",name_vi:"Cao Thượng Đại Động Văn Xương Tư Lộc Tử Dương Bảo Lục",bu:"正一",author:"佚名（明初，言及張正常、張宇初等）",era:"明代",topic:"fu",essence:"Bảo lục Văn Xương: phả hệ, thánh cáo, phù lục, thần chú hai mươi tư phẩm. Dùng để thụ lục, cầu tư lộc khoa cử, củng cố thần cách «Văn Xương Tư Lộc Đế Quân».",key_text:"null",use:"Thụ lục Văn Xương, nghi cầu công danh.",sources:["https://www.shidianguji.com/zh/book/DZ1214","https://zh.daoinfo.org/index.php?title=%E9%AB%98%E4%B8%8A%E5%A4%A7%E6%B4%9E%E6%96%87%E6%98%8C%E5%8F%B8%E7%A5%BF%E7%B4%AB%E9%99%BD%E5%AF%B6%E7%B1%99","https://ctext.org/wiki.pl?if=gb&res=763846"],textual_certainty:"high",notes:"batch35 · Grok-4.5 catalog-driven"},{dz:"DZ1333",name_han:"洞真太上神虎玉經",name_vi:"Động Chân Thái Thượng Thần Hổ Ngọc Kinh",bu:"正一",author:"佚名（上清系）",era:"東晉（約4世紀）",topic:"fu",essence:"Kinh phù Thần Hổ thuộc thượng thanh sơ kỳ, ghi “Thần Hổ chân phù” do Thái chân Cửu thiên cha mẹ ban truyền. Dùng để chế phục quỷ mị, hộ thân khi hành đạo và triệu thỉnh lực sĩ. Là gốc cho hệ thần hổ truy nhiếp trong pháp sau này.",key_text:"王君曰：神虎真符，太真九天父母所出。",use:"Đọc khi học phù lục thượng thanh; tham khảo gốc cho pháp thần hổ/truy hồn.",sources:["https://zh.daoinfo.org/index.php?title=%E6%B4%9E%E7%9C%9F%E5%A4%AA%E4%B8%8A%E7%A5%9E%E8%99%8E%E7%8E%89%E7%B6%93","https://www.kanripo.org/ed/KR5g0142/ZTDZ/000","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch36 · Grok-4.5 catalog-driven"},{dz:"DZ1334",name_han:"洞真太上神虎隱文",name_vi:"Động Chân Thái Thượng Thần Hổ Ẩn Văn",bu:"正一",author:"佚名（上清系）",era:"東晉–南朝",topic:"mantra",essence:"Tụng chương ẩn văn dùng chung với phù Kim Hổ và Thần Hổ. Không phải kinh triết lý mà là kệ-chú phối hợp phù lục để tăng uy lực triệu thỉnh. Thuộc nhóm “ba kỳ bảo văn” thượng thanh.",key_text:"神虎隱文，金虎合用。",use:"Học cùng Thần Hổ Ngọc Kinh và Kim Thiên Hổ Phù; dùng trong nghi truy nhiếp.",sources:["https://zh.wikisource.org/zh-hant/%E6%B4%9E%E7%9C%9F%E5%A4%AA%E4%B8%8A%E7%A5%9E%E8%99%8E%E9%9A%B1%E6%96%87","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.daoinfo.org/index.php?title=%E6%B4%9E%E7%9C%9F%E5%A4%AA%E4%B8%8A%E7%A5%9E%E8%99%8E%E7%8E%89%E7%B6%93"],textual_certainty:"high",notes:"batch36 · Grok-4.5 catalog-driven"},{dz:"DZ1336",name_han:"洞真太上金篇虎符真文經",name_vi:"Động Chân Thái Thượng Kim Thiên Hổ Phù Chân Văn Kinh",bu:"正一",author:"佚名（上清系）",era:"東晉–南朝",topic:"fu",essence:"Truyền Kim Hổ chân phù của Thái Vi Thiên Đế Quân cho Kim Khuyết Đế Quân. Đeo phù (châu thư bạch tố, túi gấm tía) để chế mệnh quần linh. Được Vô Thượng Bí Yếu trích dẫn, xác nhận tư cách kinh thượng thanh cổ.",key_text:"右金虎真符，太微天帝君以傳金闕帝君，朱書白素，盛以紫錦囊。",use:"Nghiên cứu phù lục thượng thanh; tham chiếu khi đối chiếu hệ hổ phù/kim hổ.",sources:["https://zh.daoinfo.org/index.php?title=%E6%B4%9E%E7%9C%9F%E5%A4%AA%E4%B8%8A%E9%87%91%E7%AF%87%E8%99%8E%E7%AC%A6%E7%9C%9F%E6%96%87%E7%B6%93","https://ctext.org/wiki.pl?if=gb&res=474584","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch36 · Grok-4.5 catalog-driven"},{dz:"DZ1418",name_han:"元始說度酆都經",name_vi:"Nguyên Thủy Thuyết Độ Phong Đô Kinh",bu:"正一",author:"佚名",era:"南北朝末–隋唐",topic:"ritual",essence:"Còn gọi Thất Nguyên chân kinh: Nguyên Thủy Thiên Tôn truyền pháp lập đàn Bắc Đẩu thất chân để phục ma thu quỷ, siêu độ tội hồn Phong Đô. Nói rõ nghi thắp đèn, tụng chú và quan hệ với tam quan bắc phủ. Là kinh điển “Phong Đô pháp” ngắn gọn, thực dụng.",key_text:"爾時，元始天尊告五老上皇，及諸靈嶽諸方。",use:"Nghi cứu pháp độ vong/Phong Đô; tụng trong khoa bạt độ.",sources:["https://zh.daoinfo.org/index.php?title=%E5%85%83%E5%A7%8B%E8%AA%AA%E5%BA%A6%E9%85%86%E9%83%BD%E7%B6%93","https://zh.wikisource.org/wiki/%E5%85%83%E5%A7%8B%E8%AA%AA%E5%BA%A6%E9%85%86%E9%83%BD%E7%B6%93","https://ctext.org/wiki.pl?if=en&chapter=357629&remap=gb"],textual_certainty:"high",notes:"batch36 · Grok-4.5 catalog-driven"},{dz:"DZ780",name_han:"地祇上將溫太保傳",name_vi:"Địa Kỳ Thượng Tướng Ôn Thái Bảo Truyện",bu:"洞神",author:"黃公瑾（校正；南宋）",era:"南宋",topic:"仙传",essence:"Truyện thần địa kỳ Ôn Quỳnh (Ôn Thái Bảo, tự Tử Ngọc, Bình Dương Ôn Châu). Kể lai lịch, công diệt ma, nuốt thuốc ôn dịch thay dân và vị trí dưới Bắc Đế/Huyền Đế. Là văn bản gốc cho “địa kỳ pháp” và hệ ôn nguyên soái trong Lôi pháp/Thanh Vi.",key_text:"太保姓溫，名瓊，字子玉，乳名卓郎，溫州平陽縣人。",use:"Học thần phả địa kỳ; nền tảng cho khoa thỉnh Ôn soái/địa kỳ lôi.",sources:["https://zh.daoinfo.org/index.php?title=%E5%9C%B0%E7%A5%87%E4%B8%8A%E5%B0%87%E6%BA%AB%E5%A4%AA%E4%BF%9D%E5%82%B3","https://ctext.org/wiki.pl?if=gb&chapter=950284","https://www.shidianguji.com/book/DZ0780/chapter/DZ0780_1"],textual_certainty:"high",notes:"batch36 · Grok-4.5 catalog-driven"},{dz:"DZ585",name_han:"貫斗忠孝五雷武侯祕法",name_vi:"Quán Đẩu Trung Hiếu Ngũ Lôi Vũ Hầu Bí Pháp",bu:"洞玄",author:"張暉齋（元）；吳昇序",era:"元代",topic:"ritual",essence:"Lôi pháp “trung hiếu” lấy Gia Cát Vũ Hầu làm chủ soái sát phạt liệt lôi. Kết hợp ấn thần, Lạc thư cửu cung, triệu Ngũ hổ tướng và lôi binh để trừ tinh tà sơn tiêu. Tiêu biểu lôi pháp dân gian hóa thời Nguyên, nhấn mạnh trung hiếu làm gốc hành pháp.",key_text:"帝命我為通天煞伐烈雷大神，此陰陽神印也。",use:"Nghiên cứu lôi pháp hậu kỳ; tham khảo nghi triệu soái/trừ tà.",sources:["https://zh.wikisource.org/zh-hant/%E8%B2%AB%E6%96%97%E5%BF%A0%E5%AD%9D%E4%BA%94%E9%9B%B7%E6%AD%A6%E4%BE%AF%E7%A7%98%E6%B3%95","https://zh.daoinfo.org/index.php?title=%E8%B2%AB%E6%96%97%E5%BF%A0%E5%AD%9D%E4%BA%94%E9%9B%B7%E6%AD%A6%E4%BE%AF%E7%A7%98%E6%B3%95","https://www.kanripo.org/text/KR5b0290/000"],textual_certainty:"high",notes:"batch36 · Grok-4.5 catalog-driven"},{dz:"DZ71",name_han:"元始天尊說三官寶號經",name_vi:"Nguyên Thủy Thiên Tôn Thuyết Tam Quan Bảo Hiệu Kinh",bu:"洞真",author:"佚名",era:"宋–元",topic:"classic",essence:"Nguyên Thủy truyền cho Xích Cước Đại Tiên ba bảo hiệu: Thượng nguyên Thiên quan, Trung nguyên Địa quan, Hạ nguyên Thủy quan. Chủ trương trì tụng danh hiệu để tiêu tai, xá tội, giải ách. Kinh ngắn, phổ biến trong khoa Tam nguyên/Tam quan.",key_text:"上元一品賜福天官紫微大帝，中元二品赦罪地官清虛大帝，下元三品解厄水官洞陰大帝。",use:"Tụng hàng ngày/khoa Tam quan; học danh hiệu chuẩn của ba quan.",sources:["https://zh.daoinfo.org/index.php?title=%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E4%B8%89%E5%AE%98%E5%AF%B6%E8%99%9F%E7%B6%93","https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%8A%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E4%B8%89%E5%AE%98%E5%AF%B6%E8%99%9F","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch36 · Grok-4.5 catalog-driven"},{dz:"DZ44",name_han:"太上洞真五星祕授經",name_vi:"Thái Thượng Động Chân Ngũ Tinh Bí Thụ Kinh",bu:"洞真",author:"佚名",era:"唐宋（約）",topic:"classic",essence:"Kinh tinh tượng: mô tả ngũ tinh và chư tinh quân (kể cả La Hầu v.v.), hình tướng, chức tư họa phúc. Dạy cúng đồ hình, phụng dưỡng để hóa giải vận hạn. Bổ sung mảng “tinh thần” trong kinh văn tạp.",key_text:"羅睺真君，主九天之下一切諸惡，如世人運炁逢遇，多有災厄深重，宜弘善以迎之。",use:"Nghiên cứu tinh thần/ngũ tinh; tham khảo nghi cúng tinh.",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%9C%9F%E4%BA%94%E6%98%9F%E7%A7%98%E6%8E%88%E7%B6%93","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.shidianguji.com/zh/"],textual_certainty:"high",notes:"batch36 · Grok-4.5 catalog-driven"},{dz:"DZ101",name_han:"太上昇玄消災護命妙經註",name_vi:"Thái Thượng Thăng Huyền Tiêu Tai Hộ Mệnh Diệu Kinh Chú",bu:"洞真",author:"李道純",era:"宋末元初",topic:"cultivation",essence:"Chú giải kinh Hộ mệnh (khoảng 300 chữ) theo hướng trùng huyền và Toàn chân nội đan. Chia ba chương, lấy không–sắc, hữu–vô để giải “hộ mệnh” thành bảo toàn tính mệnh chân. Tiêu biểu chú sớ tạp thời Nguyên.",key_text:"爾時元始天尊在七寶林中，五明宮內，與無極聖衆俱。",use:"Đọc cùng bản kinh gốc; học cách Toàn chân giải kinh trọng huyền.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%98%87%E7%8E%84%E6%B6%88%E7%81%BE%E8%AD%B7%E5%91%BD%E5%A6%99%E7%B6%93%E8%A8%BB%EF%BC%88%E6%9D%8E%E9%81%93%E7%B4%94%EF%BC%89","https://ctext.org/wiki.pl?if=gb&res=213515","https://www.shidianguji.com/book/DZ0101/chapter/DZ0101_1"],textual_certainty:"high",notes:"batch36 · Grok-4.5 catalog-driven"},{dz:"DZ398",name_han:"洞玄靈寶自然九天生神章經註",name_vi:"Động Huyền Linh Bảo Tự Nhiên Cửu Thiên Sinh Thần Chương Kinh Chú",bu:"洞玄",author:"華陽復",era:"元代",topic:"cultivation",essence:"Chú ba quyển kinh Sinh thần chương (cổ Linh bảo). Giải cửu thiên chi khí kết thành hình thần, liên hệ thai nguyên và công tụng chương. Khác bản kinh gốc đã có trong danh sách loại trừ; đây là lớp chú sớ.",key_text:"生神玉章，上帝所以宣示好生之德也。",use:"Học sâu Sinh thần chương; đối chiếu với các bản giải nghĩa khác (Đổng Tư Tĩnh v.v.).",sources:["https://zh.wikisource.org/zh-hant/%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E8%87%AA%E7%84%B6%E4%B9%9D%E5%A4%A9%E7%94%9F%E7%A5%9E%E7%AB%A0%E7%B6%93%E8%A8%BB","https://ctext.org/wiki.pl?if=gb&chapter=130794","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch36 · Grok-4.5 catalog-driven"},{dz:"DZ1058",name_han:"無為清靜長生真人至真語錄",name_vi:"Vô Vi Thanh Tĩnh Trường Sinh Chân Nhân Chí Chân Ngữ Lục",bu:"太玄",author:"劉處玄（門人輯）",era:"金代",topic:"cultivation",essence:"Ngữ lục khoảng 80 điều của Trường Sinh chân nhân Lưu Xử Huyền (Toàn chân thất tử). Lấy đạo tính trường tồn, thanh tĩnh vô vi làm tông; mượn âm dương ngũ hành luận sinh tử–họa phúc. Bổ sung mảng ngữ lục Toàn chân ít được phủ.",key_text:"我聞道在域中，所宜馴致，仙居象外，不可苟求。",use:"Đọc song song Đan Dương/Tấn chân ngữ lục; học tông chỉ thanh tĩnh Toàn chân.",sources:["https://zh.wikisource.org/zh-hant/%E7%84%A1%E7%82%BA%E6%B8%85%E9%9D%9C%E9%95%B7%E7%94%9F%E7%9C%9F%E4%BA%BA%E8%87%B3%E7%9C%9F%E8%AA%9E%E9%8C%84","https://zh.daoinfo.org/index.php?title=%E7%84%A1%E7%82%BA%E6%B8%85%E9%9D%9C%E9%95%B7%E7%94%9F%E7%9C%9F%E4%BA%BA%E8%87%B3%E7%9C%9F%E8%AA%9E%E9%8C%84","https://ctext.org/wiki.pl?if=gb&res=383595"],textual_certainty:"high",notes:"batch36 · Grok-4.5 catalog-driven"},{dz:"DZ242",name_han:"紙舟先生全真直指",name_vi:"Chỉ Chu Tiên Sinh Toàn Chân Trực Chỉ",bu:"洞真",author:"金月巖編；黃公望傳",era:"元代",topic:"cultivation",essence:"Chỉ nam nội đan Toàn chân: “thất phản thất chân” (hình thần tương cố → hợp đạo) kèm đồ và kệ. Hạ thiên nói nhập thất tĩnh tọa và các cảnh nghiệm. Lấy “dĩ tâm ấn không, giác ngộ bổn chân” làm tông.",key_text:"夫全真之學，直究玄宗，乃單明向上大道。",use:"Tu nội đan Toàn chân; tham khảo lộ trình thất giai đoạn hình–thần.",sources:["https://zh.wikisource.org/wiki/%E7%B4%99%E8%88%9F%E5%85%88%E7%94%9F%E5%85%A8%E7%9C%9F%E7%9B%B4%E6%8C%87","https://ctext.org/wiki.pl?if=gb&res=858457","https://www.mdpi.com/2077-1444/14/7/861"],textual_certainty:"high",notes:"batch36 · Grok-4.5 catalog-driven"},{dz:"DZ447",name_han:"許真君仙傳",name_vi:"Hứa Chân Quân Tiên Truyện",bu:"洞玄",author:"佚名（淨明道士，元）",era:"元代",topic:"仙传",essence:"Truyện Hứa Tốn (Tịnh Dương chân quân): ngộ đạo từ việc săn hươu, làm huyện lệnh, trảm xà trị thủy, cả nhà phi thăng. Phản ánh thần phả Tịnh minh thời Nguyên (có tôn hiệu gia phong). Khác hẳn các truyện Tịnh minh đã loại trừ.",key_text:"真君生而穎悟，少小通疏，與物無忤。",use:"Học thần tích Hứa Tốn; nền tảng lịch sử–huyền thoại Tịnh minh.",sources:["https://zh.daoinfo.org/index.php?title=%E8%A8%B1%E7%9C%9F%E5%90%9B%E4%BB%99%E5%82%B3","https://zh.wikisource.org/zh-hant/%E8%A8%B1%E7%9C%9F%E5%90%9B%E4%BB%99%E5%82%B3","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch36 · Grok-4.5 catalog-driven"},{dz:"DZ1026",name_han:"天隱子",name_vi:"Thiên Ẩn Tử",bu:"太玄",author:"司馬承禎（述）",era:"唐代",topic:"philosophy",essence:"Tám thiên: Thần tiên–Dịch giản–Tiệm môn–Trai giới–An xứ–Tồn tưởng–Tọa vong–Thần giải. Chủ trương ai cũng có thể thành tiên nếu dưỡng linh khí theo thứ bậc tiệm tiến. Cùng hệ tư tưởng với Tọa vong luận của Tư Mã Thừa Trinh.",key_text:"神仙之道，以長生為本，長生之要，以養氣為先。",use:"Nhập môn tĩnh định/tọa vong; đọc trước hoặc song song Tọa vong luận.",sources:["https://zh.wikisource.org/zh-hant/%E5%A4%A9%E9%9A%B1%E5%AD%90","https://zh.daoinfo.org/index.php?title=%E5%A4%A9%E9%9A%B1%E5%AD%90","https://ctext.org/wiki.pl?if=gb&res=369514&remap=gb"],textual_certainty:"high",notes:"batch36 · Grok-4.5 catalog-driven"},{dz:"DZ1044",name_han:"化書",name_vi:"Hóa Thư",bu:"太玄",author:"譚峭（紫霄）",era:"五代",topic:"philosophy",essence:"Sáu quyển Đạo hóa–Thuật hóa–Đức hóa–Nhân hóa–Thực hóa–Kiểm hóa (110 chương). Lấy “hư–thần–khí–hình” luận biến hóa vũ trụ và trị quốc; phê nặng bóc lột, đề cao tiết kiệm–quân thực. Tác phẩm triết học Đạo giáo then chốt đời Ngũ đại (cũng có bản trong Tục tạng).",key_text:"道之委也，虛化神，神化氣，氣化形，形生而萬物所以塞也。",use:"Đọc triết Đạo giáo/trị thế; đối chiếu với Lão–Trang và tư tưởng kiểm ước.",sources:["https://zh.daoinfo.org/index.php?title=%E5%8C%96%E6%9B%B8","https://ctext.org/wiki.pl?if=gb&res=129486","https://zh.wikisource.org/zh-hant/%E5%8C%96%E6%9B%B8"],textual_certainty:"high",notes:"batch36 · Grok-4.5 catalog-driven"},{dz:"DZ15",name_han:"無上九霄玉清大梵紫微玄都雷霆玉經",name_vi:"Vô Thượng Cửu Tiêu Ngọc Thanh Đại Phạm Tử Vi Huyền Đô Lôi Đình Ngọc Kinh",bu:"洞真",author:"佚名（神霄系）",era:"北宋末（約）",topic:"ritual",essence:"Gọi tắt Lôi Đình Ngọc Kinh: Thần Tiêu Ngọc Thanh Chân Vương truyền, luận Lôi đình là then chốt trời đất, thưởng thiện phạt ác. Mô tả Cửu tiêu phủ, quan thuộc và chư lôi thần; cuối có chín đạo phù và chú tụng. Kinh gốc cho hệ thần tiêu lôi pháp.",key_text:"雷霆者，乃天地之樞機……非雷霆無以行其令。",use:"Nền tảng học thần tiêu/lôi pháp; tụng và nghiên cứu thần phổ lôi bộ.",sources:["https://zh.daoinfo.org/index.php?title=%E7%84%A1%E4%B8%8A%E4%B9%9D%E9%9C%84%E7%8E%89%E6%B8%85%E5%A4%A7%E6%A2%B5%E7%B4%AB%E5%BE%AE%E7%8E%84%E9%83%BD%E9%9B%B7%E9%9C%86%E7%8E%89%E7%B6%93","https://zh.wikisource.org/wiki/%E7%84%A1%E4%B8%8A%E4%B9%9D%E9%9C%84%E7%8E%89%E6%B8%85%E5%A4%A7%E6%A2%B5%E7%B4%AB%E5%BE%AE%E7%8E%84%E9%83%BD%E9%9B%B7%E9%9C%86%E7%8E%89%E7%B6%93","https://www.shidianguji.com/zh/book/DZ0015"],textual_certainty:"high",notes:"batch36 · Grok-4.5 catalog-driven"},{dz:"DZ647",name_han:"太上说转轮五道宿命因缘经",name_vi:"Thái Thượng Thuyết Chuyển Luân Ngũ Đạo Túc Mệnh Nhân Duyên Kinh",bu:"洞神",author:"佚名",era:"南北朝–唐（道经仿佛）",topic:"classic",essence:"Kinh nhân duyên túc mệnh, mượn khung chuyện Phật để Thái Thượng Lão Quân giảng nghiệp báo năm đường. Nói rõ nhân–quả, tái sinh, tội phúc, dùng làm kinh giáo hóa và sám hối. Được Komjathy/Pregadio xác nhận DZ 647 trong Chính thống Đạo tạng.",key_text:"尔时太上老君在迦维罗卫国精舍中，与诸天仙、地仙等一千二百五十人俱。",use:"Giảng nghiệp báo, tụng sám, nghiên cứu Đạo–Phật giao thoa.",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E8%AA%AA%E8%BD%89%E8%BC%AA%E4%BA%94%E9%81%93%E5%AE%BF%E5%91%BD%E5%9B%A0%E7%B7%A3%E7%B6%93","https://fabriziopregadio.com/files/PREGADIO_and_ESPOSITO_Daozang_jiyao_Catalogue.pdf","https://baike.baidu.com/item/%E5%A4%AA%E4%B8%8A%E8%AF%B4%E8%BD%AC%E8%BD%AE%E4%BA%94%E9%81%93%E5%AE%BF%E5%91%BD%E5%9B%A0%E7%BC%98%E7%BB%8F"],textual_certainty:"high",notes:"batch37 · Grok-4.5 catalog-driven"},{dz:"DZ648",name_han:"太上化道度世仙经",name_vi:"Thái Thượng Hóa Đạo Độ Thế Tiên Kinh",bu:"洞神",author:"佚名",era:"唐宋间",topic:"cultivation",essence:"Kinh một quyển, chia Hóa đạo phẩm, Ngũ hành phẩm, Huyền lý phẩm. Khuyên tu tâm luyện tính, thanh tâm quả dục, kết hợp đạo dẫn–thổ nạp để độ thế thành tiên. Văn ngắn, có chú, theo lối Thái Thượng cáo Tả Huyền chân nhân.",key_text:"化道品第一",use:"Tu tâm, đạo dẫn thổ nạp, giáo hóa độ thế.",sources:["https://www.shidianguji.com/zh/book/DZ0648","https://zh.daoinfo.org/wiki/%E5%A4%AA%E4%B8%8A%E5%8C%96%E9%81%93%E5%BA%A6%E4%B8%96%E4%BB%99%E7%B6%93","https://ctext.org/wiki.pl?if=gb&res=893396"],textual_certainty:"high",notes:"batch37 · Grok-4.5 catalog-driven"},{dz:"DZ660",name_han:"混元八景真经",name_vi:"Hỗn Nguyên Bát Cảnh Chân Kinh",bu:"洞神",author:"佚名（疑唐–五代）",era:"唐–五代",topic:"cultivation",essence:"Năm quyển, nói “bát cảnh” hỗn nguyên và thuật phòng trung/nội luyện theo lối hỗn nguyên chân nhân. Thuộc nhóm kinh ít được phủ trong tạng, liên hệ dưỡng sinh–âm dương hợp khí. Gọi Huyền Vũ chứ không xưng Chân Vũ, gợi niên đại trước khi “Chân Vũ” phổ biến.",key_text:"混元真人曰：夫天地以前，混沌之初，万汇未萌，空而无洞，只是虚无。",use:"Nghiên cứu phòng trung–dưỡng sinh hỗn nguyên; tham chiếu bát cảnh nội cảnh.",sources:["https://ctext.org/wiki.pl?if=gb&res=561634","https://zh.wikipedia.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F","https://homeinmists.ilotus.org/%E9%81%93%E8%97%8F%E5%8C%AF%E7%B7%A8/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F/%E9%81%93%E8%97%8F%E7%9B%AE%E9%8C%84/"],textual_certainty:"high",notes:"batch37 · Grok-4.5 catalog-driven"},{dz:"DZ825",name_han:"延陵先生集新旧服气经",name_vi:"Diên Lăng Tiên Sinh Tập Tân Cựu Phục Khí Kinh",bu:"洞神",author:"延陵先生集；桑榆子评",era:"唐末–五代",topic:"服气",essence:"Tập hợp hơn mười pháp phục khí cổ–kim (Diên Lăng, Trương Quả, Đàm Loan pháp sư…). Lấy thai tức–phục khí làm cốt, mô phỏng hô hấp trẻ sơ sinh để trường sinh. Schipper/Kohn xác nhận DZ 825; là nguồn quan trọng cho lịch sử đạo dẫn–phục khí thời Đường.",key_text:"上食新气，下泄旧气，使推陈而纳新也。",use:"Luyện phục khí, so sánh các phái khí pháp; tham chiếu dưỡng sinh.",sources:["https://www.shidianguji.com/book/DZ0825","https://zh.daoinfo.org/index.php?title=%E5%BB%B6%E9%99%B5%E5%85%88%E7%94%9F%E9%9B%86%E6%96%B0%E8%88%8A%E6%9C%8D%E6%B0%A3%E7%B6%93","https://zh.wikisource.org/zh-hans/%E5%BB%B6%E9%99%B5%E5%85%88%E7%94%9F%E9%9B%86%E6%96%B0%E8%88%8A%E6%9C%8D%E6%B0%A3%E7%B6%93"],textual_certainty:"high",notes:"batch37 · Grok-4.5 catalog-driven"},{dz:"DZ826",name_han:"诸真圣胎神用诀",name_vi:"Chư Chân Thánh Thai Thần Dụng Quyết",bu:"洞神",author:"佚名辑",era:"宋–元",topic:"胎息",essence:"Tổng tập khoảng ba mươi phép thai tức–ngự khí, gán cho Hải Thiềm, Viên Thiên Cương, Đạt Ma, Bão Phác tử… Nhấn mạnh thần khí hợp, “hình trung tử mẫu” (khí làm mẹ, thần làm con). Là sách tổng hợp thai tức quan trọng nhất trong tạng ngoài bản kinh Thai tức đơn.",key_text:"知至道者天不杀，服元炁者地不灭。夫至道者不远，祇在己身。",use:"Đối chiếu nhiều phái thai tức; luyện thần khí tương thủ.",sources:["https://www.shidianguji.com/book/DZ0826","https://zh.wikisource.org/zh-hans/%E8%AB%B8%E7%9C%9F%E8%81%96%E8%83%8E%E7%A5%9E%E7%94%A8%E8%A8%A3","https://zh.daoinfo.org/index.php?title=%E8%AB%B8%E7%9C%9F%E8%81%96%E8%83%8E%E7%A5%9E%E7%94%A8%E8%A8%A3"],textual_certainty:"high",notes:"batch37 · Grok-4.5 catalog-driven"},{dz:"DZ829",name_han:"胎息精微论",name_vi:"Thai Tức Tinh Vi Luận",bu:"洞神",author:"佚名（唐；或托司马承祯系）",era:"唐",topic:"胎息",essence:"Luận thai tức tinh vi: không chủ trương bịt mũi miệng cưỡng bách, mà an thần tĩnh tư, dưỡng khí tự nhiên. Phân biệt phàm tức (họng) và chân tức (căn/gót); lấy “thần ngự khí” làm then chốt. Có trích trong Vân Cấp Thất Thiêm q.58.",key_text:"凡人任自然之息至近而役之，其所利唯化食而已。",use:"Lý thuyết thai tức; chỉnh pháp hô hấp–tĩnh lự.",sources:["https://www.shidianguji.com/zh/book/DZ0829","https://zh.wikisource.org/wiki/%E8%83%8E%E6%81%AF%E7%B2%BE%E5%BE%AE%E8%AB%96","https://ctext.org/wiki.pl?if=gb&res=601583"],textual_certainty:"high",notes:"batch37 · Grok-4.5 catalog-driven"},{dz:"DZ831",name_han:"气法要妙至诀",name_vi:"Khí Pháp Yếu Diệu Chí Quyết",bu:"洞神",author:"佚名",era:"唐宋间",topic:"服气",essence:"Quyển một về khí pháp: lục khí (xuy, ha, hu, yết, hô, hi), điều khí, tiết khí, trợ đạo dẫn yết khí. Nói rõ từng hơi dùng để trừ hàn, phiền, đàm, lao, nhiệt… Kết hợp đạo dẫn–phục khí thành chuỗi thực hành ngắn, dễ áp dụng.",key_text:"吹去寒气，呵去烦气，噓去痰积，咽去痕劳，呼去温热。",use:"Lục khí trị liệu, điều tức, đạo dẫn phụ trợ.",sources:["https://www.shidianguji.com/zh/book/DZ0831","https://zh.wikisource.org/wiki/%E6%B0%A3%E6%B3%95%E8%A6%81%E5%A6%99%E8%87%B3%E8%A8%A3","https://zh.daoinfo.org/index.php?title=%E6%B0%A3%E6%B3%95%E8%A6%81%E5%A6%99%E8%87%B3%E8%A8%A3"],textual_certainty:"high",notes:"batch37 · Grok-4.5 catalog-driven"},{dz:"DZ835",name_han:"保生铭",name_vi:"Bảo Sinh Minh",bu:"洞神",author:"孙思邈（题）",era:"唐",topic:"养生",essence:"Minh ngắn về bảo sinh: tiết dục, tiết thực, thuận tứ thời, tránh quá lao. Gắn với hệ Tôn Tư Mạc trong Đạo tạng phương pháp loại. Kohn và các nghiên cứu dưỡng sinh trích dẫn như cương lĩnh “trung dung” trong sinh hoạt hàng ngày.",key_text:"null",use:"Checklist dưỡng sinh đời thường; giáo huấn tự trọng thân.",sources:["https://zh.wikisource.org/zh-hans/%E9%81%93%E8%97%8F_(%E5%9B%9B%E5%BA%AB%E5%85%A8%E6%9B%B8%E6%9C%AC)/%E5%85%A8%E8%A6%BD","https://homeinmists.ilotus.org/DaoZang/Tiyao4.pdf","https://journeytothewestresearch.com/wp-content/uploads/2023/07/Chinese-Healing-Exercises-The-Tradition-of-Daoyin-2008.pdf"],textual_certainty:"high",notes:"batch37 · Grok-4.5 catalog-driven"},{dz:"DZ836",name_han:"神仙食炁金柜妙录",name_vi:"Thần Tiên Thực Khí Kim Quỹ Diệu Lục",bu:"洞神",author:"京里/京黑先生（题）",era:"唐前后",topic:"服气",essence:"Ghi các pháp thực khí–tịch cốc–ngọa công hành khí, chia ngày âm dương, phục khí theo thời. CRTA/Komjathy định DZ 836; là kho “kim quỹ” về thực khí thần tiên, bổ sung cho hệ phục khí Đường.",key_text:"觉气如云行体中，经营周身，濡润形体。",use:"Thực khí, tịch cốc, ngọa công hành khí.",sources:["https://homeinmists.ilotus.org/%E9%81%93%E8%97%8F%E5%8C%AF%E7%B7%A8/%E6%B6%B5%E8%8A%AC%E6%A8%93-%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F/1533%E7%A8%AE%E7%B6%93%E6%9B%B8%E5%B0%8D%E6%87%89%E9%81%93%E8%97%8F%E5%9B%9B%E7%A8%AE%E7%89%88%E6%9C%AC%E4%B9%8B%E5%86%8A%E6%95%B8-%E9%A0%81%E7%A2%BC/","https://www.jstor.org/stable/26768560","https://zh.wikisource.org/zh-hans/%E9%81%93%E8%97%8F_(%E5%9B%9B%E5%BA%AB%E5%85%A8%E6%9B%B8%E6%9C%AC)/%E5%85%A8%E8%A6%BD"],textual_certainty:"high",notes:"batch37 · Grok-4.5 catalog-driven"},{dz:"DZ837",name_han:"枕中记",name_vi:"Chẩm Trung Ký",bu:"洞神",author:"孙思邈（系；与《摄养枕中方》相关）",era:"唐",topic:"养生",essence:"Sách dưỡng sinh “gối đầu giường”: tự thận, ưu úy, ẩm thực kiêng kỵ, đạo dẫn xoa mặt–yết tân, hành khí bế tức. Bản tạng liên hệ Tôn Tư Mạc; Vân Cấp Thất Thiêm q.33 có dị bản Nhiếp dưỡng chẩm trung phương.",key_text:"null",use:"Dưỡng sinh thực dụng, đạo dẫn–hành khí hàng ngày.",sources:["https://zh.daoinfo.org/index.php?title=%E6%9E%95%E4%B8%AD%E8%A8%98","https://zh.wikipedia.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F","https://ctext.org/wiki.pl?if=en&res=815250"],textual_certainty:"high",notes:"batch37 · Grok-4.5 catalog-driven"},{dz:"DZ840",name_han:"彭祖摄生养性论",name_vi:"Bành Tổ Nhiếp Sinh Dưỡng Tính Luận",bu:"洞神",author:"托名彭祖",era:"六朝–唐（辑本）",topic:"养生",essence:"Luận ngắn theo lời Bành Tổ: nhiếp sinh, dưỡng tính, tiết dục, thuận thời, giữ tinh–khí–thần. Kohn xếp vào nhóm “preserving life / nourishing inner nature”; là cương lĩnh thái độ sống hơn là công pháp dài.",key_text:"null",use:"Giáo huấn dưỡng tính; nguyên tắc trường thọ.",sources:["https://journeytothewestresearch.com/wp-content/uploads/2023/07/Chinese-Healing-Exercises-The-Tradition-of-Daoyin-2008.pdf","https://www.jstor.org/stable/26768560","https://zh.wikisource.org/zh-hans/%E9%81%93%E8%97%8F_(%E5%9B%9B%E5%BA%AB%E5%85%A8%E6%9B%B8%E6%9C%AC)/%E5%85%A8%E8%A6%BD"],textual_certainty:"high",notes:"batch37 · Grok-4.5 catalog-driven"},{dz:"DZ303",name_han:"紫阳真人内传",name_vi:"Tử Dương Chân Nhân Nội Truyện",bu:"洞真",author:"东晋华侨（托）；记周义山",era:"东晋（上清系）",topic:"仙传",essence:"Nội truyện Tử Dương chân nhân Chu Nghĩa Sơn: chu du danh sơn, gặp hơn ba mươi tiên chân, thụ kinh–phục khí, cuối cùng bạch nhật thăng thiên. Là mẫu hagiography Thượng Thanh sớm, nối “động thiên–động phòng” và truyền thừa kinh quyết. Schipper hệ thống định DZ 303.",key_text:"天无谓之空，山无谓之洞，人无谓之房也。",use:"Nghiên cứu tiên truyện Thượng Thanh; bản đồ hành hương–thụ pháp.",sources:["https://baike.baidu.com/item/%E7%B4%AB%E9%98%B3%E7%9C%9F%E4%BA%BA%E5%86%85%E4%BC%A0/23151517","https://www.sohu.com/a/482093734_260616","https://www.thepaper.cn/newsDetail_forward_21527351"],textual_certainty:"high",notes:"batch37 · Grok-4.5 catalog-driven"},{dz:"DZ452",name_han:"南岳九真人传",name_vi:"Nam Nhạc Cửu Chân Nhân Truyện",bu:"洞玄",author:"廖侁",era:"北宋",topic:"仙传",essence:"Truyện chín chân nhân nổi danh Nam Nhạc (Hành Sơn), do Liêu Thân biên định từ bản cũ của đạo sĩ Âu Dương Đạo Long. Thu Động huyền bộ phổ lục; là sử–truyện cao đạo địa phương, bổ sung cho hệ “sơn chí–tiên truyện” ít được phủ.",key_text:"南岳真人，名之著者有九。",use:"Tiên truyện địa phương; nghiên cứu Nam Nhạc đạo giáo.",sources:["https://zh.wikisource.org/zh-hans/%E5%8D%97%E5%B6%BD%E4%B9%9D%E7%9C%9F%E4%BA%BA%E5%82%B3","https://ctext.org/wiki.pl?if=gb&res=754405","https://baike.baidu.com/item/%E9%81%93%E8%97%8F%E7%9B%AE%E5%BD%95/1989063"],textual_certainty:"high",notes:"batch37 · Grok-4.5 catalog-driven"},{dz:"DZ224",name_han:"清微斋法",name_vi:"Thanh Vi Trai Pháp",bu:"洞真",author:"佚名（元代清微派）",era:"元",topic:"ritual",essence:"Hai quyển trai pháp Thanh Vi: tông phái lưu hệ (Linh Bảo–Đạo Đức–Chính Nhất quy Thanh Vi), khoa nghi đại trai, chương sớ–phù hịch, bài triệu. Nhấn mạnh chính tâm thành ý khi hành trì; là cẩm nang trai–tiến của phái Thanh Vi, khác với 《清微元降大法》《清微神烈秘法》 đã loại.",key_text:"null",use:"Trai khoa Thanh Vi; nghiên cứu nghi lễ–phù chương.",sources:["https://baike.baidu.com/item/%E6%B8%85%E5%BE%AE%E6%96%8B%E6%B3%95/23148618","https://ctext.org/wiki.pl?if=gb&res=573845","https://dao.crs.cuhk.edu.hk/Main/wp-content/uploads/2018/08/DAO7_03_Jihyun-Kim.pdf"],textual_certainty:"high",notes:"batch37 · Grok-4.5 catalog-driven"},{dz:"DZ1277",name_han:"道法宗旨图衍义",name_vi:"Đạo Pháp Tông Chỉ Đồ Diễn Nghĩa",bu:"正一",author:"邓柟纂图；章希贤衍义",era:"元（大德己亥，1299）",topic:"雷法",essence:"Hai quyển, hơn hai mươi đồ (nguyên thủy tổ kiếp, lôi đình hỗ dụng…), Chương Hy Hiền diễn nghĩa bằng tam giáo. Nói rõ nguyên lý lôi pháp và nội đan–hành pháp; “pháp hành tiên thiên đại đạo”. Là sách đồ giải lôi pháp độc lập, ngoài các tổng tập như Đạo pháp hội nguyên.",key_text:"至道之精，杳杳冥冥；至道之极，昏昏默默。",use:"Lý thuyết lôi pháp; đối chiếu đồ–quyết hành trì.",sources:["https://www.shidianguji.com/zh/book/DZ1277","https://zh.wikisource.org/zh-hans/%E9%81%93%E6%B3%95%E5%AE%97%E6%97%A8%E5%9C%96%E8%A1%8D%E7%BE%A9","https://zh.daoinfo.org/index.php?title=%E9%81%93%E6%B3%95%E5%AE%97%E6%97%A8%E5%9C%96%E8%A1%8D%E7%BE%A9"],textual_certainty:"high",notes:"batch37 · Grok-4.5 catalog-driven"},{dz:"DZ012",name_han:"高上玉皇本行經髓",name_vi:"Cao Thượng Ngọc Hoàng Bản Hành Kinh Tủy",bu:"洞真",author:"佚名",era:"宋–元（約）",topic:"classic",essence:"Bản tóm yếu (經髓) của Ngọc Hoàng Bản Hành Tập Kinh, cô đọng sự tích Ngọc Hoàng từ hỗn độn đến chứng đạo. Dùng tụng trì, nghi thức và học giáo lý Ngọc Hoàng, ngắn hơn bản tập kinh đầy đủ.",key_text:"志心皈命禮。太上彌羅無上天，妙有玄真境。",use:"Tụng ngắn Ngọc Hoàng; giáo lý; khóa sớm tối / nghi cầu phước",sources:["https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf","https://blackmoonharbor.com/uploads/1/1/5/3/115363763/daoist_texts_in_translation._komjathy.pdf"],textual_certainty:"high",notes:"batch38 · Grok-4.5 catalog-driven"},{dz:"DZ014",name_han:"高上玉皇胎息經",name_vi:"Cao Thượng Ngọc Hoàng Thai Tức Kinh",bu:"洞真",author:"佚名",era:"唐–宋（約）",topic:"cultivation",essence:"Kinh thai tức gắn danh hiệu Ngọc Hoàng, dạy điều tức, ôm nguyên, luyện thần. Cùng hệ thai tức trong Đạo tạng nhưng nhấn mạnh tinh thần 'thượng thanh–ngọc hoàng'.",key_text:"胎息者，如嬰兒在母腹中，不以口鼻呼吸。",use:"Nội luyện thai tức; tham chiếu khí công; tụng kèm tu dưỡng",sources:["https://blackmoonharbor.com/uploads/1/1/5/3/115363763/daoist_texts_in_translation._komjathy.pdf","https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf"],textual_certainty:"high",notes:"batch38 · Grok-4.5 catalog-driven"},{dz:"DZ197",name_han:"玉皇十七慈光燈儀",name_vi:"Ngọc Hoàng Thập Thất Từ Quang Đăng Nghi",bu:"洞玄",author:"佚名",era:"元–明初",topic:"ritual",essence:"Đăng nghi cúng mười bảy từ quang trước tòa Ngọc Hoàng, thắp đèn, lạy tán, tụng Tâm Ấn, phát nguyện. Thuộc nhóm đăng nghi Kim Lục, cầu phước, tiêu tai, 'hữu cầu tư ứng'.",key_text:"大神通光、大慈悲光、大喜捨光……無能勝光。",use:"Đăng nghi Ngọc Hoàng; cầu nguyện; nghi lễ ban đêm",sources:["https://zh.daoinfo.org/index.php?title=%E7%8E%89%E7%9A%87%E5%8D%81%E4%B8%83%E6%85%88%E5%85%89%E7%87%88%E5%84%80","https://www.researchgate.net/publication/273169426_TITLE_INDEX_TO_THEZHONGHUA_DAOZANG"],textual_certainty:"high",notes:"batch38 · Grok-4.5 catalog-driven"},{dz:"DZ199",name_han:"南斗延壽燈儀",name_vi:"Nam Đẩu Diên Thọ Đăng Nghi",bu:"洞真",author:"佚名",era:"元–明初",topic:"ritual",essence:"Đăng nghi cúng Nam Đẩu Lục Tư, thắp đèn lạy tán cầu tiêu tai, diên thọ, bảo mệnh. Phối hợp truyền thống 'Nam Đẩu chú sinh' trong ngũ đẩu kinh.",key_text:"南斗司錄，天相尊神。定生注祿，保命延生。",use:"Cầu thọ; đăng nghi sinh nhật / bản mệnh; phối Bắc Đẩu",sources:["https://zh.daoinfo.org/index.php?title=%E5%8D%97%E6%96%97%E5%BB%B6%E5%A3%BD%E7%87%88%E5%84%80","https://zh.wikisource.org/zh-hant/%E5%8D%97%E6%96%97%E5%BB%B6%E5%A3%BD%E7%87%88%E5%84%80"],textual_certainty:"high",notes:"batch38 · Grok-4.5 catalog-driven"},{dz:"DZ200",name_han:"北斗七元星燈儀",name_vi:"Bắc Đẩu Thất Nguyên Tinh Đăng Nghi",bu:"洞真",author:"佚名",era:"元–明初",topic:"ritual",essence:"Đăng nghi cúng Bắc Đẩu Thất Nguyên Tinh Quân, thắp bảy đèn theo thất tinh. Dùng cầu giải ách, tẩy tội, an tinh, thuộc hệ đăng nghi Kim Lục phổ biến.",key_text:"開明三景，九晨為梵炁之宗；回度五常，七政乃元綱之首。",use:"Bái đẩu; đăng nghi thất tinh; giải hạn sao",sources:["https://zh.wikisource.org/zh-hant/%E5%8C%97%E6%96%97%E4%B8%83%E5%85%83%E6%98%9F%E7%87%88%E5%84%80","https://cdn.singaporeccc.org.sg/sccc/uploads/2023/07/Nine-Emperor-Gods-Vol-1.pdf"],textual_certainty:"high",notes:"batch38 · Grok-4.5 catalog-driven"},{dz:"DZ201",name_han:"北斗本命延壽燈儀",name_vi:"Bắc Đẩu Bản Mệnh Diên Thọ Đăng Nghi",bu:"洞真",author:"佚名",era:"元–明初",topic:"ritual",essence:"Đăng nghi cúng Bản mệnh Tinh Quân trong hệ Bắc Đẩu: thắp đèn bản mệnh, sám hối tội khiên, cầu trường sinh bảo mệnh. Nhắm vận hạn cá nhân và tuổi thọ.",key_text:"元綱示像，迺垂上屬之科；梵炁經天，故有命星之宰。",use:"Bản mệnh đăng; cầu thọ; giải hạn cá nhân",sources:["https://zh.wikisource.org/wiki/%E5%8C%97%E6%96%97%E6%9C%AC%E5%91%BD%E5%BB%B6%E5%A3%BD%E7%87%88%E5%84%80","https://zh.daoinfo.org/index.php?title=%E5%8C%97%E6%96%97%E6%9C%AC%E5%91%BD%E5%BB%B6%E5%A3%BD%E7%87%88%E5%84%80"],textual_certainty:"high",notes:"batch38 · Grok-4.5 catalog-driven"},{dz:"DZ202",name_han:"三官燈儀",name_vi:"Tam Quan Đăng Nghi",bu:"洞真",author:"佚名",era:"元–明初",topic:"ritual",essence:"Đăng nghi cúng Thiên–Địa–Thủy Tam Quan Đại Đế: thắp đèn, tán tụng, cầu ban phúc, xá tội, giải ách. Gắn lịch nghi tam nguyên (thượng/trung/hạ nguyên).",key_text:"三官大帝，主宰三界，考校功過，賜福赦罪。",use:"Tam nguyên trai; cầu xá tội ban phúc; đăng nghi Tam Quan",sources:["https://www.researchgate.net/publication/273169426_TITLE_INDEX_TO_THEZHONGHUA_DAOZANG","https://a.daorenjia.com/c29"],textual_certainty:"high",notes:"batch38 · Grok-4.5 catalog-driven"},{dz:"DZ314",name_han:"三洞讚頌靈章",name_vi:"Tam Động Tán Tụng Linh Chương",bu:"洞真",author:"佚名",era:"唐–宋（約）",topic:"mantra",essence:"Tập tán tụng, linh chương thuộc hệ Tam Động: ca tụng tôn thần, kinh điển, dùng trong trai tiếu. Cung cấp văn bản nghi thức ca vịnh chuẩn cho đạo trường.",key_text:"志心皈命禮。三洞四輔，經教尊崇。",use:"Tán tụng trong trai tiếu; nghi ca vịnh; phụ trợ khóa tụng",sources:["https://www.jstor.org/stable/26768560","https://michaelstanley-baker.com/clarkes-complete-daoist-index/"],textual_certainty:"high",notes:"batch38 · Grok-4.5 catalog-driven"},{dz:"DZ448",name_han:"西山許真君八十五化錄",name_vi:"Tây Sơn Hứa Chân Quân Bát Thập Ngũ Hóa Lục",bu:"洞玄",author:"施岑（編）",era:"宋",topic:"仙传",essence:"Biên niên tám mươi lăm 'hóa' của Hứa Tốn (Tịnh Minh), kể độ thế, trừ yêu, truyền đạo ở Tây Sơn. Nền tảng truyện tích và giáo hóa Tịnh Minh trung hiếu.",key_text:"神仙可以學得，不死可以力致，信哉斯言也。",use:"Tiên truyện Hứa Chân Quân; Tịnh Minh; giáo dục trung hiếu",sources:["https://www.jstor.org/stable/26768560","http://www.ctcwri.idv.tw/CTCW-CJD/CJD02%E6%B4%9E%E7%8E%84%E9%83%A8/CJD0205%E6%B4%9E%E7%8E%84%E8%AD%9C%E9%8C%84/CJD0205ALL/CJD020507%E8%A5%BF%E5%B1%B1%E8%A8%B1%E7%9C%9F%E5%90%9B%E5%85%AB%E5%8D%81%E4%BA%94%E5%8C%96%E9%8C%84/CJD020507-1%E8%A5%BF%E5%B1%B1%E8%A8%B1%E7%9C%9F%E5%90%9B%E5%85%AB%E5%8D%81%E4%BA%94%E5%8C%96%E9%8C%84%E5%8D%B7%E4%B8%8A.pdf"],textual_certainty:"high",notes:"batch38 · Grok-4.5 catalog-driven"},{dz:"DZ449",name_han:"孝道吳許二真君傳",name_vi:"Hiếu Đạo Ngô Hứa Nhị Chân Quân Truyện",bu:"洞玄",author:"佚名",era:"宋–元（約）",topic:"仙传",essence:"Tiểu truyện Ngô Mãnh và Hứa Tốn trong dòng Hiếu Đạo / Tịnh Minh: nhấn trung hiếu, độ thế, trừ hại. Bổ sung cho hệ Hứa Chân Quân và giáo hiếu đạo.",key_text:"孝悌之道，通於神明，感格天地。",use:"Tiên truyện hiếu đạo; Tịnh Minh; giáo dục đạo đức",sources:["https://www.jstor.org/stable/26768560","https://crta.info/wiki/Daozang_-_DZ"],textual_certainty:"high",notes:"batch38 · Grok-4.5 catalog-driven"},{dz:"DZ450",name_han:"太極葛仙公傳",name_vi:"Thái Cực Cát Tiên Công Truyện",bu:"洞玄",author:"譚嗣先",era:"明（洪武前后；有朱綽序 1377）",topic:"仙传",essence:"Tiểu truyện Cát Huyền (Tiên Công): học đạo, luyện đan, truyền Linh Bảo, thăng tiên. Nối truyền thừa Linh Bảo và địa danh đạo giáo Giang Nam (Cú Dung, các quán miếu).",key_text:"仙公父素奉道法……通玄真人大羅天下降。",use:"Tiên truyện Cát Huyền; lịch sử Linh Bảo; nghiên cứu sơn chí / quán miếu",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E6%A5%B5%E8%91%9B%E4%BB%99%E5%85%AC%E5%82%B3","https://fabriziopregadio.com/files/PREGADIO_and_ESPOSITO_Daozang_jiyao_Catalogue.pdf"],textual_certainty:"high",notes:"batch38 · Grok-4.5 catalog-driven"},{dz:"DZ461",name_han:"上清骨髓靈文鬼律",name_vi:"Thượng Thanh Cốt Tủy Linh Văn Quỷ Luật",bu:"洞玄",author:"饒洞天定正；鄧有功重編",era:"北宋（天心派）",topic:"ritual",essence:"Luật lệ 'Khu tà viện' của Thiên Tâm chính pháp: quỷ luật, ngọc cách, nghi thức ấn, bộ cương, cáo thị. Mô hình hóa theo luật triều đình để chế phục thần tướng và tà quỷ.",key_text:"書曰天道福善禍淫，天命有德，天討有罪。",use:"Thiên Tâm chính pháp; khu tà; quy chế hành pháp đạo sĩ",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%8A%E6%B8%85%E9%AA%A8%E9%AB%93%E9%9D%88%E6%96%87%E9%AC%BC%E5%BE%8B","https://ctext.org/wiki.pl?if=gb&res=464785"],textual_certainty:"high",notes:"batch38 · Grok-4.5 catalog-driven"},{dz:"DZ616",name_han:"廣成集",name_vi:"Quảng Thành Tập",bu:"洞玄",author:"杜光庭",era:"唐末–五代",topic:"ritual",essence:"Văn tập Quảng Thành tiên sinh: biểu tấu, trai từ, tiếu từ (Kim lục, Hoàng lục, Bắc Đế, Nam Đẩu, bản mệnh, an trạch…). Vừa tư liệu lịch sử Đường–Thục vừa mẫu chư từ nghi thức.",key_text:"上都太清宮內供奉應制文章大德賜紫杜光庭撰。",use:"Soạn biểu sớ; nghiên cứu trai tiếu Đường–Ngũ đại; văn phong đạo sĩ",sources:["https://zh.daoinfo.org/index.php?title=%E5%BB%A3%E6%88%90%E9%9B%86","https://ctext.org/searchbooks.pl?if=gb&author=%E6%9D%9C%E5%85%89%E5%BA%AD"],textual_certainty:"high",notes:"batch38 · Grok-4.5 catalog-driven"},{dz:"DZ617",name_han:"太上宣慈助化章",name_vi:"Thái Thượng Tuyên Từ Trợ Hóa Chương",bu:"洞玄",author:"杜光庭（集）",era:"唐末–五代",topic:"ritual",essence:"Tập chương tấu 'tuyên từ trợ hóa': văn bản dâng sớ cầu thiên ân, trợ hóa dân sinh, dùng trong trai tiếu. Cùng hệ biểu chương với Quảng Thành tập.",key_text:"宣慈助化，上達天庭，下濟含靈。",use:"Chương tấu; sớ văn; nghi cầu ân trợ hóa",sources:["https://www.jstor.org/stable/26768560","https://michaelstanley-baker.com/clarkes-complete-daoist-index/"],textual_certainty:"high",notes:"batch38 · Grok-4.5 catalog-driven"},{dz:"DZ982",name_han:"太上三洞表文",name_vi:"Thái Thượng Tam Động Biểu Văn",bu:"正一",author:"佚名",era:"宋–元（約）",topic:"ritual",essence:"Tập biểu văn theo hệ Tam Động: mẫu dâng sớ, tấu thiên, dùng khi kiến đàn, truyền độ, cầu đảo. Tài liệu thực dụng cho hành pháp và nghi thức chính nhất.",key_text:"臣某誠惶誠恐，稽首頓首，百拜上奏。",use:"Biểu sớ; trai tiếu; hành pháp dâng tấu",sources:["https://www.jstor.org/stable/26768560","http://kanji.zinbun.kyoto-u.ac.jp/kanseki?record=data/FATOYO/tagged/105227047.dat&back=6"],textual_certainty:"high",notes:"batch38 · Grok-4.5 catalog-driven"},{dz:"DZ1015",name_han:"太玄金鎖流珠引",name_vi:"Thái Huyền Kim Tỏa Lưu Châu Dẫn",bu:"太玄",author:"題李淳風注並序（或宋元纂集）",era:"唐（題）／或晚唐–宋元纂",topic:"ritual",essence:"Bộ pháp thuật lớn (~29–30 quyển): bộ cương đạp đẩu, phù lục, tồn thần, thỉnh chương, khu tà trị bệnh, hợp Thượng Thanh và Chính Nhất. 'Kim tỏa' khóa hồn luyện phách; 'lưu châu' chỉ tinh đẩu / lưu chuyển theo châu.",key_text:"金鎖者，鎖魂煉魄，求生去死；堅身如金，留神繫鎖。",use:"Chính Nhất / Thượng Thanh hành pháp; bộ cương; khu tà; nghiên cứu nguồn Thiên Tâm",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E7%8E%84%E9%87%91%E9%8E%96%E6%B5%81%E7%8F%A0%E5%BC%95","https://ctext.org/wiki.pl?if=gb&res=321674"],textual_certainty:"high",notes:"batch38 · Grok-4.5 catalog-driven"},{dz:"DZ017",name_han:"太上說朝天謝雷真經",name_vi:"Thái Thượng thuyết triều thiên tạ lôi chân kinh",bu:"洞真",author:"佚名（宋元道士）",era:"宋—元",topic:"ritual",essence:"Kinh giả thác Thái Thượng Đạo Quân diễn thuyết phép triều thiên tạ lôi. Cho rằng sét đánh do phạm ba mươi sáu thiên điều do lôi công giám sát; bất trung bất hiếu, bất kính tam bảo, phí ngũ cốc đều chiêu lôi phạt. Người phạm nên đeo tụng kinh văn, lễ bái tinh đẩu, dùng ‘thiên tế’ phù đồ để giải tội, miễn đọa địa ngục.",key_text:"人不犯天條，天即降吉祥；若犯天條，必遭雷擊。",use:"Tụng trì tạ lôi tiêu tai; tham chiếu thần tiêu/lôi pháp; nghiên cứu đạo đức cảm ứng lôi bộ.",sources:["https://zh.daoinfo.org/index.php?title=太上說朝天謝雷真經&variant=zh-hant","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch39 · Grok-4.5 catalog-driven"},{dz:"DZ020",name_han:"三光注齡資福延壽妙經",name_vi:"Tam quang chú linh tư phúc duyên thọ diệu kinh",bu:"洞真",author:"佚名",era:"唐—宋",topic:"cultivation",essence:"Kinh ngắn khoảng hai trăm chữ, giả thác Đạo Quân nói pháp tu thân duyên linh. Lấy nhật–nguyệt–tinh ‘tam quang’ ứng với thân người; giữ nhĩ mục tỷ khẩu không loạn thì tinh phách tự luyện, tư phúc duyên thọ.",key_text:"道言：吾隱六合之內，處明堂之中。",use:"Tụng trì cầu thọ; nội luyện quán tưởng tam quang; tư liệu kinh tạp tiêu tai duyên thọ.",sources:["https://zh.daoinfo.org/index.php?title=三光注齡資福延壽妙經&variant=zh-hant","https://zh.wikisource.org/zh-hant/三光注齡資福延壽妙經","https://www.shidianguji.com/book/DZ0020"],textual_certainty:"high",notes:"batch39 · Grok-4.5 catalog-driven"},{dz:"DZ036",name_han:"太上太玄女青三元品誡拔罪妙經",name_vi:"Thái Thượng Thái Huyền Nữ Thanh tam nguyên phẩm giới bạt tội diệu kinh",bu:"洞真",author:"佚名",era:"南北朝末—隋唐",topic:"classic",essence:"Ba quyển, do thần tiên Thái Huyền Nữ Thanh truyền thuật chỉ của Nguyên Thủy Thiên Tôn về tam nguyên phẩm giới. Giải thích thượng nguyên thiên quan, trung nguyên địa quan, hạ nguyên thủy quan cùng các tào quan giám tội, chỉ đường sám hối bạt tội.",key_text:"至道玉帝，昔於龍漢初劫，在三天之上，與諸天上聖……演說三洞大法《三元品誡妙經》。",use:"Sám hối bạt tội theo tam nguyên; nghiên cứu giới luật Nữ Thanh; so với Tam nguyên phẩm giới hệ.",sources:["https://zh.daoinfo.org/index.php?title=太上太玄女青三元品戒拔罪妙經&variant=zh-hant","https://ctext.org/wiki.pl?if=gb&chapter=559800","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch39 · Grok-4.5 catalog-driven"},{dz:"DZ050",name_han:"太上說六甲直符保胎護命妙經",name_vi:"Thái Thượng thuyết lục giáp trực phù bảo thai hộ mệnh diệu kinh",bu:"洞真",author:"佚名",era:"唐—宋",topic:"mantra",essence:"Nguyên Thủy Thiên Tôn bảo尹喜: sản nạn do bất tín đạo, tà mị xâm phạm; thai phụ nên lập đạo tràng, tụng kinh, thỉnh lục giáp trực phù thần tướng hộ trì. Kèm danh hiệu lục giáp trực phù và phù lục bảo thai.",key_text:"六甲直符驅魘魅，六丁玉女護我身。",use:"Tụng trì bảo thai hộ mệnh; pháp sự sản khoa; nghiên cứu lục giáp trực phù.",sources:["https://zh.daoinfo.org/index.php?title=太上說六甲直符保胎護命妙經&variant=zh-hant","https://zh.wikisource.org/zh-hant/太上說六甲直符保胎護命妙經","https://www.shidianguji.com/book/DZ0050"],textual_certainty:"high",notes:"batch39 · Grok-4.5 catalog-driven"},{dz:"DZ053",name_han:"太上洞淵北帝天蓬護命消災神咒妙經",name_vi:"Thái Thượng động uyên Bắc Đế Thiên Bồng hộ mệnh tiêu tai thần chú diệu kinh",bu:"洞真",author:"佚名",era:"唐—宋",topic:"mantra",essence:"Thuộc hệ Động Uyên–Bắc Đế, lấy Thiên Bồng nguyên soái làm chủ hộ mệnh tiêu tai. Kết hợp thần chú, phù lệnh để trấn tà, hộ thân, tiêu tai chướng; nối truyền Động Uyên thần chú với Bắc Đế phục ma.",key_text:"太上洞淵北帝天蓬護命消災神咒妙經",use:"Tụng chú tiêu tai hộ mệnh; Bắc Đế/Thiên Bồng pháp; tham chiếu Động Uyên thần chú.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://ctext.org/library.pl?if=gb&collection=132"],textual_certainty:"partial",notes:"batch39 · Grok-4.5 catalog-driven"},{dz:"DZ181",name_han:"太上九真妙戒金籙度命拔罪妙經",name_vi:"Thái Thượng cửu chân diệu giới kim lục độ mệnh bạt tội diệu kinh",bu:"洞真",author:"佚名",era:"南北朝",topic:"classic",essence:"Nguyên Thủy Thiên Tôn vì Bắc Đế thỉnh cầu mà trao ‘kim lục bạch giản cửu chân diệu giới’ cùng cứu khổ chân phù, cứu tội nhân địa ngục. Chín giới khuyên trung quân, hiếu thân, từ tế chúng sinh, bất dâm bất đạo; thụ trì thì tiêu cửu u đại tội. Có bản Đôn Hoàng S.957.",key_text:"消九幽大罪，標名九宮。",use:"Thụ giới bạt tội độ u; kim lục trai sám; nghiên cứu giới luật Linh Bảo–Thượng Thanh.",sources:["https://zh.daoinfo.org/index.php?title=太上九真妙戒金籙度命拔罪妙經&variant=zh-hant","https://zh.wikisource.org/zh-hant/太上九真妙戒金籙度命拔罪妙經","https://www.shidianguji.com/book/DZ0181"],textual_certainty:"high",notes:"batch39 · Grok-4.5 catalog-driven"},{dz:"DZ189",name_han:"太上靈寶朝天謝罪大懺",name_vi:"Thái Thượng Linh Bảo triều thiên tạ tội đại sám",bu:"洞真",author:"佚名（南宋道士）",era:"南宋",topic:"ritual",essence:"Mười quyển sám văn giả thác Nguyên Thủy Thượng Đế hội quần tiên ở Đại La thiên, phân loại tội khiên nhân gian và đường triều thiên tạ tội. Dùng trong trai sám lớn: sám hối bất trung bất hiếu, bất kính tam quang, sát sinh, tham dâm… để giải oan tiêu tội.",key_text:"下元生人，死魂受考。為前生，不忠不孝……死魂報對，劫盡無解。",use:"Khoa nghi triều thiên tạ tội; hoàng lục/linh bảo sám pháp; nghiên cứu đạo đức nghiệp báo.",sources:["https://zh.daoinfo.org/index.php?title=太上靈寶朝天謝罪大懺&variant=zh-hant","https://ctext.org/wiki.pl?if=gb&chapter=424264","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch39 · Grok-4.5 catalog-driven"},{dz:"DZ191",name_han:"太上上清禳災延壽寶懺",name_vi:"Thái Thượng Thượng Thanh nhưỡng tai duyên thọ bảo sám",bu:"洞真",author:"佚名",era:"宋—元",topic:"ritual",essence:"Bảo sám thuộc bộ Thượng Thanh, thường xếp cùng ‘Tạ tội đăng chân’ và ‘Bạt tội thăng thiên’ thành bộ ba. Dùng trong đèn–sám–khoa nghi để nhưỡng tai, cầu duyên thọ, tiêu chướng.",key_text:"太上上清禳災延壽寶懺",use:"Sám pháp nhưỡng tai duyên thọ; đèn nghi/bảo sám; nghi lễ cầu an.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.daoinfo.org/index.php?title=Category:洞真部威儀類&variant=zh-hant"],textual_certainty:"partial",notes:"batch39 · Grok-4.5 catalog-driven"},{dz:"DZ218",name_han:"清微玄樞奏告儀",name_vi:"Thanh Vi huyền xu tấu cáo nghi",bu:"洞真",author:"佚名（清微派）",era:"元—明",topic:"ritual",essence:"Khoa nghi Thanh Vi tấu cáo Chân Nguyên Diệu Hóa Thiên Đế, Tử Thần Đại Hoa Thiên Đế, Thái Sơ Thiên Quân và tổ sư phái Thanh Vi. Tiết thứ: nhập đàn, niệm chú, phạn phù triệu tướng, nhiên đăng, giáng thần, tạ ân, phát nguyện—cầu bảo mệnh duyên niên, tiêu tai độ ách.",key_text:"清微玄樞奏告儀",use:"Tấu cáo Thanh Vi; hành trì đạo pháp phái Thanh Vi; nghiên cứu khoa nghi nguyên–minh.",sources:["https://zh.daoinfo.org/index.php?title=清微玄樞奏告儀&variant=zh-hant","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch39 · Grok-4.5 catalog-driven"},{dz:"DZ278",name_han:"清微丹訣",name_vi:"Thanh Vi đan quyết",bu:"洞真",author:"佚名（清微派道士）",era:"元",topic:"cultivation",essence:"Bốn chương: Ẩn chân hợp đạo, Nhập thất công phu, Lâm đàn triệu hợp, Phát dụng; kèm nội luyện phù đồ. Nối nội đan (luyện tinh–khí–thần) với ngoại dụng phù pháp; nhấn ‘đức giả đạo chi phù, thành giả pháp chi bản’, lấy chính khí hợp lôi tướng, thân đấu cương hợp thiên đấu cương.",key_text:"德者道之符，誠者法之本。",use:"Nội đan Thanh Vi; lôi pháp nội luyện; nghiên cứu hợp nhất đan–pháp.",sources:["https://zh.daoinfo.org/index.php?title=清微丹訣&variant=zh-hant","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch39 · Grok-4.5 catalog-driven"},{dz:"DZ316",name_han:"太上濟度章赦",name_vi:"Thái Thượng tế độ chương xá",bu:"洞真",author:"佚名",era:"唐（一說宋元）",topic:"ritual",essence:"Ba quyển biểu tấu: thượng–trung thu 32 chương (duyên sinh giải ách, tạ thổ an trạch, khiển dịch bảo bệnh, cầu tự, nhưỡng hỏa tai…) và thức quan thông dụng; hạ quyển các đại xá (Ngọc Thanh, Thanh Huyền, Ngọc Hoàng) để độ vong xá tội.",key_text:"延生解厄章",use:"Soạn chương biểu trai giảo; tế độ sinh tử; thư tín nghi thức đạo giáo.",sources:["https://zh.daoinfo.org/index.php?title=太上濟度章赦&variant=zh-hant","https://ctext.org/wiki.pl?if=gb&res=509608","https://www.shidianguji.com/book/DZ0316"],textual_certainty:"high",notes:"batch39 · Grok-4.5 catalog-driven"},{dz:"DZ357",name_han:"太上靈寶天尊說禳災度厄經",name_vi:"Thái Thượng Linh Bảo Thiên Tôn thuyết nhưỡng tai độ ách kinh",bu:"洞玄",author:"佚名",era:"不詳（中古—宋）",topic:"classic",essence:"Kinh cực ngắn (~200 chữ): Linh Bảo Thiên Tôn dạy thiện nam tín nữ gặp tai ách chỉ cần tụng kinh, hướng Ngọc Hoàng và đạo thánh chân sám hối thì nhưỡng tai độ ách, sở cầu như nguyện.",key_text:"只須念誦此經，向玉皇天尊大道聖真懺悔，即可禳災度厄。",use:"Tụng trì tiêu tai độ ách hàng ngày; kinh tạp phổ thông; nghi thức cầu an ngắn.",sources:["https://zh.daoinfo.org/index.php?title=太上靈寶天尊說禳災度厄經&variant=zh-hant","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch39 · Grok-4.5 catalog-driven"},{dz:"DZ400",name_han:"洞玄靈寶定觀經注",name_vi:"Động Huyền Linh Bảo định quán kinh chú",bu:"洞玄",author:"冷虛子（唐）",era:"唐",topic:"philosophy",essence:"Chú giải Định Quán Kinh: định là tâm định, quán là tuệ quán; tuần tự tĩnh tâm, đoạn dục, nhập định, sinh tuệ. Đỗ Quang Đình đã dẫn; là cầu nối tọa vong–định quán với triết học tu tâm Đường.",key_text:"夫定者，心定也；觀者，慧觀也。",use:"Tu định quán/tọa vong; chú sớ tâm tính; nghiên cứu Đạo–Thiền giao thiệp thời Đường.",sources:["https://zh.daoinfo.org/index.php?title=太上洞靈寶定觀經註（冷虛子）&variant=zh-hant","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch39 · Grok-4.5 catalog-driven"},{dz:"DZ408",name_han:"上清胎精記解結行事訣",name_vi:"Thượng Thanh thai tinh ký giải kết hành sự quyết",bu:"洞玄",author:"佚名",era:"東晉—南北朝",topic:"cultivation",essence:"Quyết pháp Thượng Thanh trích từ Cửu đan thượng hóa thai tinh trung ký: thân có thập nhị kết (thượng–trung–hạ mỗi bộ tứ kết). Theo bản mệnh nhật tồn thần, bái Nguyên Phụ Huyền Mẫu, đeo phù giải kết, luyện thai thành tiên.",key_text:"胞上部有四結，一結在泥丸中，二結在口中，三結在頰中，四結在目中。",use:"Hành trì giải kết tồn thần; tu thai tiên Thượng Thanh; nghiên cứu thai tinh giải kết.",sources:["https://zh.daoinfo.org/index.php?title=上清胎精記解結行事訣&variant=zh-hant","https://ctext.org/wiki.pl?if=gb&chapter=865343","https://www.shidianguji.com/zh/book/DZ0408"],textual_certainty:"high",notes:"batch39 · Grok-4.5 catalog-driven"},{dz:"DZ807",name_han:"天心正法修真道場設醮儀",name_vi:"Thiên Tâm chính pháp tu chân đạo tràng thiết giảo nghi",bu:"正一",author:"天心派（關聯鄧有功一系）",era:"北宋—南宋",topic:"ritual",essence:"Khoa nghi lập đạo tràng thiết giảo theo Thiên Tâm chính pháp. Phối hợp với Thượng Thanh Thiên Tâm chính pháp, Thượng Thanh cốt tủy linh văn quỷ luật: bố đàn, thỉnh tướng, thiết giảo, trấn tà trị quỷ theo hệ Thiên Tâm.",key_text:"天心正法修真道場設醮儀",use:"Thiết giảo Thiên Tâm; hành pháp trấn tà; nghiên cứu nghi thức phái Thiên Tâm.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch39 · Grok-4.5 catalog-driven"},{dz:"DZ1236",name_han:"太上出家傳度儀",name_vi:"Thái Thượng xuất gia truyền độ nghi",bu:"正一",author:"賈善翔",era:"北宋",topic:"ritual",essence:"Gia Thiện Tường biên tập nghi thức đạo sĩ xuất gia thụ giới. Phân hai nghĩa xuất gia: xả ân ái vào đạo, và tu chứng xuất ‘chư hữu chi gia’. Gồm đốt hương, lễ đế vương, tạ tổ tiên, từ phụ mẫu, thụ thập giới, niệm tam bảo, báo tứ ân, lễ tam sư.",key_text:"初出恩愛之家……出諸有之家。",use:"Truyền độ xuất gia; giới đàn; nghiên cứu chế độ pháp vị–thụ giới Tống.",sources:["https://zh.daoinfo.org/index.php?title=太上出家傳度儀&variant=zh-hant","https://zh.wikisource.org/zh-hans/太上出家传度仪","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch39 · Grok-4.5 catalog-driven"},{dz:"DZ068",name_han:"太上安鎮九壘龍神妙經",name_vi:"Thái Thượng An Trấn Cửu Lũy Long Thần Diệu Kinh",bu:"洞真",author:"佚名",era:"唐宋",topic:"经典杂",essence:"Kinh an trạch giả thác Nguyên Thủy Thiên Tôn giảng pháp trấn an long thần cửu lũy khi chúng sinh khởi tạo nhà cửa, động thổ phạm sát. Dạy cầu nguyện, phụng thỉnh thổ hoàng long thần để dứt tai ương, yên gia hộ mệnh. Là văn bản tiêu biểu về an trạch, an long trong Đạo tạng.",key_text:"太上元始天尊昔在洞陽天中，召集十方聖眾，俱來集會，講說妙法。",use:"Tụng đọc, nghi thức an trạch/động thổ, trấn long thần",sources:["https://zh.wikisource.org/zh-hant/太上安鎮九壘龍神妙經","https://zh.daoinfo.org/index.php?title=太上安鎮九壘龍神妙經","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://ctext.org/library.pl?if=en&res=83721"],textual_certainty:"high",notes:"batch40 · Grok-4.5 catalog-driven"},{dz:"DZ077",name_han:"太上玉華洞章拔亡度世昇仙妙經",name_vi:"Thái Thượng Ngọc Hoa Động Chương Bạt Vong Độ Thế Thăng Tiên Diệu Kinh",bu:"洞真",author:"杜長春",era:"金（熙宗前後）",topic:"经典杂",essence:"Kinh Kim triều do Đỗ Trường Xuân soạn, gồm nhiều “động chương” giảng cứu khổ bạt tội, độ vong thăng tiên. Nhấn mạnh giải thích u lao, cứu khổ bạt tội và hộ mệnh thai thai. Dùng trong pháp hội siêu độ, giải oan, dẫn dắt vong linh.",key_text:"爾時元始天尊在玉清境上",use:"Siêu độ, bạt vong, giải oan, tụng khoa nghi",sources:["https://zh.wikisource.org/zh-hant/太上玉華洞章拔亡度世昇仙妙經","https://zh.daoinfo.org/index.php?title=太上玉華洞章拔亡度世昇仙妙經","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://ctext.org/wiki.pl?if=gb&res=90402"],textual_certainty:"high",notes:"batch40 · Grok-4.5 catalog-driven"},{dz:"DZ166",name_han:"元始上真眾仙記",name_vi:"Nguyên Thủy Thượng Chân Chúng Tiên Ký",bu:"洞真",author:"託名葛洪（實南北朝上清系）",era:"南北朝",topic:"仙传",essence:"Còn gọi Chẩm Trung Thư; phổ lục tiên chân lấy Nguyên Thủy Thiên Vương làm gốc, xếp trật tự cung đệ, thượng thánh. Kết hợp vũ trụ khai tịch với hệ thần tiên, tiền thân quan trọng của Chân Linh Vị Nghiệp Đồ. Là chìa khóa hiểu phổ hệ thần tiên thượng thanh.",key_text:"洪歷觀天地之寶藏，上聖之宮第，至上之尊神仙圖記，猶未知極妙之根。",use:"Tra cứu phổ lục tiên chân, nghiên cứu thần hệ",sources:["https://zh.wikisource.org/zh-hant/元始上真眾仙記","https://zh.daoinfo.org/index.php?title=元始上真眾仙記","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.shidianguji.com/book/DZ0166"],textual_certainty:"high",notes:"batch40 · Grok-4.5 catalog-driven"},{dz:"DZ185",name_han:"赤松子中誡經",name_vi:"Xích Tùng Tử Trung Giới Kinh",bu:"洞真",author:"佚名（託赤松子）",era:"魏晉—不晚於宋",topic:"戒律",essence:"Kinh khuyến thiện giả thác Hiên Viên hỏi Xích Tùng Tử về họa phúc thiện ác. Thiên thần kiểm hiệu hành vi; liệt kê thiện hành, ác hành và quả báo. Ảnh hưởng truyền thống công quá cách và văn khuyến thiện đời sau.",key_text:"天雖高而察其下，行兇惡者必殃，行善事者必福。",use:"Khuyến thiện, giới luật, tự kiểm công quá",sources:["https://zh.wikisource.org/zh-hant/赤松子中誡經","https://zh.daoinfo.org/index.php?title=赤松子中誡經","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.shidianguji.com/book/DZ0185"],textual_certainty:"high",notes:"batch40 · Grok-4.5 catalog-driven"},{dz:"DZ187",name_han:"太清五十八願文",name_vi:"Thái Thanh Ngũ Thập Bát Nguyện Văn",bu:"洞真",author:"佚名",era:"六朝—唐宋",topic:"戒律",essence:"Văn nguyện gồm năm mươi tám điều: gặp cảnh đời (gia thất, tửu sắc, nghèo giàu…) thì phát nguyện độ mình và chúng sinh. Kết hợp giới hạnh với nguyện lực phổ độ, nền tảng tu tâm xuất gia/tại gia.",key_text:"若見居家妻子，當願一切早出愛獄，攝意奉戒。",use:"Tụng nguyện hằng ngày, rèn giới hạnh",sources:["https://zh.wikisource.org/zh-hans/太清五十八愿文","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.jstor.org/stable/26768560","https://crta.info/wiki/Daozang_-_DZ"],textual_certainty:"high",notes:"batch40 · Grok-4.5 catalog-driven"},{dz:"DZ213",name_han:"黃籙破獄燈儀",name_vi:"Hoàng Lục Phá Ngục Đăng Nghi",bu:"洞真",author:"佚名",era:"元—明初",topic:"科仪",essence:"Khoa nghi đèn trong Hoàng lục trai: đốt cửu u thần đăng, phá cửu u địa ngục để siêu độ vong linh. Kết hợp nghi đăng, chú nguyện và tưởng tượng chiếu phá u minh. Nghi thức then chốt của siêu độ phá ngục.",key_text:"陰陽成象，天地分形，晝夜既殊，昏明有異。",use:"Hoàng lục trai, phá ngục, siêu độ",sources:["https://zh.wikisource.org/zh-hant/黃籙破獄燈儀","https://zh.daoinfo.org/index.php?title=黃籙破獄燈儀","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.shidianguji.com/book/DZ0213"],textual_certainty:"high",notes:"batch40 · Grok-4.5 catalog-driven"},{dz:"DZ241",name_han:"碧虛子親傳直指",name_vi:"Bích Hư Tử Thân Truyền Trực Chỉ",bu:"洞真",author:"碧虛子（全真系）",era:"宋元",topic:"cultivation",essence:"Trực chỉ nội đan toàn chân: khẩu quyết thân truyền về tinh—khí—thần, hỏa hầu và phản bản hoàn nguyên. Văn phong súc tích, nhấn mạnh chỉ thẳng, ít hoa mỹ, phục vụ thực tu.",key_text:"null",use:"Nội đan toàn chân, tham chiếu khẩu quyết",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","http://www.chinaknowledge.de/Literature/Daoists/daozang.html","https://www.shidianguji.com/book/DZ0241","https://ctext.org/wiki.pl?if=en&res=dao"],textual_certainty:"partial",notes:"batch40 · Grok-4.5 catalog-driven"},{dz:"DZ245",name_han:"玉谿子丹經指要",name_vi:"Ngọc Khê Tử Đan Kinh Chỉ Yếu",bu:"洞真",author:"李簡易（玉谿子）",era:"宋",topic:"cultivation",essence:"Tác phẩm nội đan Tống: chỉ yếu đan kinh, dung hợp Nam tông và toàn chân. Giảng dược vật, hỏa hầu, tam quan và chứng nghiệm. Cẩm nang hệ thống cho người học đan đạo.",key_text:"null",use:"Học nội đan, đối chiếu Nam tông/toàn chân",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","http://www.chinaknowledge.de/Literature/Daoists/daozang.html","https://www.shidianguji.com/book/DZ0245","https://zh.daoinfo.org/"],textual_certainty:"partial",notes:"batch40 · Grok-4.5 catalog-driven"},{dz:"DZ291",name_han:"穆天子傳",name_vi:"Mục Thiên Tử Truyện",bu:"洞真",author:"先秦佚名（晉郭璞注）",era:"戰國寫本／西晉整理",topic:"仙传",essence:"Sách Trúc thư mộ Cấp huyện: du ký Chu Mục Vương tây tuần, hội Tây Vương Mẫu ở Dao Trì. Cầu nối sử ký, địa lý thần thoại và hình tượng cầu tiên. Nhập Đạo tạng như truyện tiên kỳ.",key_text:"null",use:"Đọc truyện tiên, nghiên cứu Tây Vương Mẫu/thần thoại",sources:["http://www.chinaknowledge.de/Literature/Novels/mutianzizhuan.html","http://www.chinaknowledge.de/Literature/Daoists/daozang.html","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikipedia.org/wiki/穆天子傳"],textual_certainty:"high",notes:"batch40 · Grok-4.5 catalog-driven"},{dz:"DZ292",name_han:"漢武帝內傳",name_vi:"Hán Vũ Đế Nội Truyện",bu:"洞真",author:"佚名（六朝；舊題班固/東方朔）",era:"魏晉南北朝",topic:"仙传",essence:"Truyện Hán Vũ Đế cầu tiên: hội Tây Vương Mẫu, dự yến đào tiên, nhận kinh phù. Văn biền ngẫu, gắn thượng thanh và huyền thoại cầu trường sinh. Mẫu mực truyện kỳ Đạo giáo.",key_text:"孝武皇帝好長生之術，常祭名山大澤以求神仙。",use:"Đọc huyền thoại cầu tiên, tham chiếu nghi tiếp thần",sources:["https://ctext.org/wiki.pl?if=gb&res=819624","https://zh.daoinfo.org/index.php?title=漢武帝內傳","http://www.chinaknowledge.de/Literature/Novels/hanwudineizhuan.html","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch40 · Grok-4.5 catalog-driven"},{dz:"DZ1124",name_han:"洞玄靈寶玄門大義",name_vi:"Động Huyền Linh Bảo Huyền Môn Đại Nghĩa",bu:"太平",author:"佚名",era:"隋唐之際",topic:"philosophy",essence:"Còn gọi Huyền Môn Đại Luận: tóm lược nghĩa lý Đạo giáo (tam động, tứ phụ, trai pháp…). Trình bày khái niệm “tam lục thất phẩm” trai nghi. Là cẩm nang nghĩa lý quan trọng thời Sui-Đường.",key_text:"null",use:"Học nghĩa lý, phân loại kinh giáo và trai pháp",sources:["https://zh.wikisource.org/zh-hant/洞玄靈寶玄門大義","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www11.ihp.sinica.edu.tw/storage/w2_file/2929XCnNBRN.pdf","https://ctext.org/"],textual_certainty:"high",notes:"batch40 · Grok-4.5 catalog-driven"},{dz:"DZ1126",name_han:"洞玄靈寶道學科儀",name_vi:"Động Huyền Linh Bảo Đạo Học Khoa Nghi",bu:"太平",author:"託太極太虛真人",era:"唐前後",topic:"科仪",essence:"Hai quyển, khoảng ba mươi lăm phẩm: ngôn ngữ, giảng tập, cấm tửu, kỵ huân tân, oai nghi xuất gia… Quy chuẩn sinh hoạt và giới luật đạo sĩ. Tài liệu then chốt về khoa giới đạo môn.",key_text:"出家之人，若道士，若女冠，在房在觀，與長德師尊有所言對。",use:"Giáo dục đạo sĩ, oai nghi, giới luật thường nhật",sources:["https://zh.wikisource.org/zh-hant/洞玄靈寶道學科儀","https://zh.daoinfo.org/index.php?title=洞玄靈寶道學科儀","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://ctext.org/wiki.pl?if=gb&res=549412"],textual_certainty:"high",notes:"batch40 · Grok-4.5 catalog-driven"},{dz:"DZ1265",name_han:"北帝七元紫庭延生祕訣",name_vi:"Bắc Đế Thất Nguyên Tử Đình Diên Sinh Bí Quyết",bu:"正一",author:"佚名（託葛仙翁受）",era:"六朝—北宋前",topic:"道法",essence:"Bí quyết tế thất nguyên Bắc Đế, tồn tư, hô danh, tụng chú để giải ách diên sinh, phi thăng tử đình. Gắn lễ đẩu, bắc đế pháp và hộ mệnh. Nền tảng pháp thuật bái đẩu/trừ dịch.",key_text:"吳赤烏二年，葛仙訪受之於太上老君。",use:"Bái đẩu, diên sinh, trấn dịch, tồn tư thất nguyên",sources:["https://zh.wikisource.org/zh-hant/北帝七元紫庭延生秘訣","https://zh.daoinfo.org/index.php?title=北帝七元紫庭延生秘訣","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.shidianguji.com/book/DZ1265"],textual_certainty:"high",notes:"batch40 · Grok-4.5 catalog-driven"},{dz:"DZ1273",name_han:"正一天師告趙昇口訣",name_vi:"Chính Nhất Thiên Sư Cáo Triệu Thăng Khẩu Quyết",bu:"正一",author:"佚名（託張陵告趙昇）",era:"南北朝",topic:"道法",essence:"Giả thác Trương Lăng truyền khẩu quyết cho đệ tử Triệu Thăng: Thái Thượng trao Chính nhất minh uy đạo, lập nhị thập tứ trị hóa tà tục. Nhấn mạnh dùng phù lục độ đời, trung thành chính nhất.",key_text:"天師告趙大夫曰，吾欲告子口訣，不忍言。",use:"Lịch sử chính nhất, khẩu quyết sư thừa, giáo giới",sources:["https://zh.wikisource.org/zh-hant/正一天師告趙昇口訣","https://zh.daoinfo.org/index.php?title=正一天師告趙昇口訣","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://ctext.org/wiki.pl?if=gb&res=348222"],textual_certainty:"high",notes:"batch40 · Grok-4.5 catalog-driven"},{dz:"DZ1283",name_han:"太上洞神行道授度儀",name_vi:"Thái Thượng Động Thần Hành Đạo Thụ Độ Nghi",bu:"正一",author:"佚名",era:"南北朝",topic:"科仪",essence:"Tập hợp nghi thức Động thần Tam Hoàng: túc khải, hành đạo, tế tế, thụ độ, triều lễ. Được Vô Thượng Bí Yếu trích dẫn. Tài liệu cổ về truyền độ và trai nghi tam hoàng.",key_text:"null",use:"Truyền độ, tam hoàng trai, hành đạo thụ lục",sources:["https://zh.wikisource.org/wiki/太上洞神行道授度儀","https://zh.daoinfo.org/index.php?title=太上洞神行道授度儀","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://ctext.org/wiki.pl?if=gb&res=962006"],textual_certainty:"high",notes:"batch40 · Grok-4.5 catalog-driven"},{dz:"DZ1311",name_han:"峴泉集",name_vi:"Hiện Tuyền Tập",bu:"正一",author:"張宇初",era:"明初（永樂前後）",topic:"仙传",essence:"Thi văn tập của Trương Vũ Sơ (thiên sư đời 43): luận đạo, thi phú, tạp trứ. Thể hiện tư tưởng chỉnh đốn đạo môn và học vấn chính nhất Minh sơ. Nguồn chính về cao đạo/thiên sư Minh.",key_text:"null",use:"Nghiên cứu thiên sư Trương Vũ Sơ, tư tưởng đạo giáo Minh",sources:["https://zh.wikisource.org/zh-hant/峴泉集","https://zh.daoinfo.org/index.php?title=峴泉集","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","http://www.chinaknowledge.de/Literature/Daoists/daozang.html"],textual_certainty:"high",notes:"batch40 · Grok-4.5 catalog-driven"},{dz:"DZ1454",name_han:"靈寶施食法",name_vi:"Linh Bảo Thí Thực Pháp",bu:"续道藏",author:"佚名",era:"宋元",topic:"经典杂",essence:"Pháp thí thực vong hồn thuộc Linh bảo: tịnh tam nghiệp chú, thổ địa chú, cứu khổ kinh, biến hóa pháp thực. Có thể hành nhật nhật hoặc ngày trai. Văn bản then chốt về pháp thực/siêu độ.",key_text:"此法能日日行之，惟好。恐未能長齋，但不食五辛及厭物醉酒，皆可。",use:"Thí thực, siêu độ, khoa nghi cứu khổ",sources:["https://zh.wikisource.org/zh-hant/靈寶施食法","https://zh.daoinfo.org/index.php?title=靈寶施食法","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://ctext.org/wiki.pl?if=gb&chapter=736377"],textual_certainty:"high",notes:"batch40 · Grok-4.5 catalog-driven"},{dz:"DZ848",name_han:"混俗頤生錄",name_vi:"Hỗn Tục Di Sinh Lục",bu:"洞神",author:"劉詞",era:"北宋",topic:"道医方",essence:"Sách dưỡng sinh thực dụng của ẩn sĩ Mao Sơn đời Tống, tổng kết kinh nghiệm sau khi chữa bệnh do ăn uống vô độ. Gồm mười chương về ăn uống, rượu, bốn mùa, lao phong, phòng sự và cấm kỵ. Chủ trương tiết dục, thuận tính, giữ hòa khí để trừ bệnh kéo dài tuổi thọ.",key_text:"今輒具消息樞要十章，題目曰《混俗頤生錄》。",use:"Tham chiếu dưỡng sinh bốn mùa, điều hòa ẩm thực và phòng bệnh theo lối đạo gia thế tục.",sources:["https://zh.daoinfo.org/index.php?title=%E6%B7%B7%E4%BF%97%E9%A0%A4%E7%94%9F%E9%8C%84","https://zh.wikisource.org/zh-hant/%E6%B7%B7%E4%BF%97%E9%A0%A4%E7%94%9F%E9%8C%84","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch41 · Grok-4.5 catalog-driven"},{dz:"DZ849",name_han:"保生要錄",name_vi:"Bảo Sinh Yếu Lục",bu:"洞神",author:"蒲虔貫",era:"五代後蜀 / 北宋",topic:"道医方",essence:"Luận nhiếp dưỡng bảo sinh chia tám môn: dưỡng thần khí, điều chi thể, y phục, cư xứ, dược thực, quả, cốc-thái, nhục. Văn giản, thiết thực, nhấn mạnh ăn uống tư dưỡng huyết khí và thói quen sinh hoạt hằng ngày.",key_text:"飲食者，所以資養人之血氣。",use:"Cẩm nang dưỡng sinh dân gian: ăn mặc, ở, dược thực theo đạo y.",sources:["https://zh.daoinfo.org/index.php?title=%E4%BF%9D%E7%94%9F%E8%A6%81%E9%8C%84","https://baike.baidu.com/item/%E4%BF%9D%E7%94%9F%E8%A6%81%E5%BD%95/6375642","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch41 · Grok-4.5 catalog-driven"},{dz:"DZ850",name_han:"修真祕錄",name_vi:"Tu Chân Bí Lục",bu:"洞神",author:"符度仁",era:"唐宋間",topic:"道医方",essence:"Sách thực liệu bảo kiện, chia các mục như Thực nghi, Nguyệt kỵ. Kết hợp cấm kỵ theo tháng với nguyên tắc ăn uống của người tu chân, thuộc dòng dưỡng tính–thực dưỡng trong Đạo tạng.",key_text:"前商州豐陽縣主簿符度仁纂",use:"Tra cứu thực liệu, cấm kỵ tháng và bảo kiện theo lối đạo gia.",sources:["https://zh.daoinfo.org/index.php?title=%E4%BF%AE%E7%9C%9F%E7%A7%98%E9%8C%84","https://zh.wikisource.org/zh-hant/%E4%BF%AE%E7%9C%9F%E7%A7%98%E9%8C%84","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch41 · Grok-4.5 catalog-driven"},{dz:"DZ766",name_han:"四氣攝生圖",name_vi:"Tứ Khí Nhiếp Sinh Đồ",bu:"洞神",author:"佚名",era:"晚唐–北宋",topic:"经典杂",essence:"Còn gọi Tứ quý nhiếp sinh đồ; kết hợp hình tạng phủ bốn mùa với phương thuốc, kiêng kỵ theo tiết khí. Mở đầu lấy trị bệnh–dưỡng người làm gốc, mô tả can xuân, tâm hạ, phế thu, thận đông cùng hồn phách và phương bảo sinh.",key_text:"夫理國者以養人為本，修身者以治病為先。",use:"Đối chiếu tạng khí bốn mùa, kiêng kỵ bát tiết và phương dưỡng sinh theo tháng.",sources:["https://zh.daoinfo.org/index.php?title=%E5%9B%9B%E6%B0%A3%E6%94%9D%E7%94%9F%E5%9C%96","https://ctext.org/wiki.pl?if=gb&chapter=490090","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch41 · Grok-4.5 catalog-driven"},{dz:"DZ933",name_han:"種芝草法",name_vi:"Chủng Chi Thảo Pháp",bu:"洞神",author:"佚名",era:"唐或更早（託黃帝/老子）",topic:"道医方",essence:"Kinh ngắn về phép trồng và phục thực linh chi theo bốn tiết lập xuân–hạ–thu–đông. Dùng tằng thanh, đan sa, hoàng kim, hùng hoàng chôn hố theo phương vị, trăm ngày sinh thanh/xích/hoàng/bạch chi; thuộc dòng phục thực–bản thảo đạo giáo.",key_text:"咨爾非人，皆知生之為樂，死之為惡，而莫知其所以自生也。",use:"Nghiên cứu phục thực, dược liệu chi thảo và nghi thức đạo y cổ.",sources:["https://zh.daoinfo.org/index.php?title=%E7%A8%AE%E8%8A%9D%E8%8D%89%E6%B3%95","https://zh.wikisource.org/zh-hant/%E7%A8%AE%E8%8A%9D%E8%8D%89%E6%B3%95","https://www.shidianguji.com/zh/book/DZ0933"],textual_certainty:"high",notes:"batch41 · Grok-4.5 catalog-driven"},{dz:"DZ1164",name_han:"急救仙方",name_vi:"Cấp Cứu Tiên Phương",bu:"太平",author:"佚名（含徐守貞等方）",era:"明（彙編；部分方或更早）",topic:"道医方",essence:"Bộ phương dược 11 quyển trong Chính thống Đạo tạng, gồm sản phụ cấp cứu, ngoại khoa ung thư–sang độc, và lao trại. Là kho phương cấp cứu mang màu sắc đạo y, cũng được Tứ khố toàn thư trích lục.",key_text:"背瘡治法發背廣一尺深一寸",use:"Tra cứu phương cấp cứu sản phụ, mụn nhọt, lao trại trong y–đạo giao thoa.",sources:["https://zh.daoinfo.org/index.php?title=%E6%80%A5%E6%95%91%E4%BB%99%E6%96%B9","https://ctext.org/wiki.pl?if=gb&res=145815","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch41 · Grok-4.5 catalog-driven"},{dz:"DZ1165",name_han:"仙傳外科祕方",name_vi:"Tiên Truyền Ngoại Khoa Bí Phương",bu:"太平",author:"楊清叟述、趙宜真集",era:"元末明初",topic:"道医方",essence:"Còn gọi Tiên truyền ngoại khoa tập nghiệm phương; 11 quyển chuyên ngoại khoa ung thư, phát bối, thuốc đắp ôn–nhiệt–lương. Kết tinh kinh nghiệm ngoại khoa được truyền trong giới đạo sĩ–y gia cuối Nguyên đầu Minh.",key_text:"敘論癰疽發背品",use:"Nghiên cứu ngoại khoa đạo y: ung thư, thuốc đắp và biến thông dùng thuốc.",sources:["https://zh.wikisource.org/zh-hans/%E4%BB%99%E5%82%B3%E5%A4%96%E7%A7%91%E7%A7%98%E6%96%B9","https://ctext.org/wiki.pl?if=gb&res=258085","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch41 · Grok-4.5 catalog-driven"},{dz:"DZ846",name_han:"太清經斷穀法",name_vi:"Thái Thanh Kinh Đoạn Cốc Pháp",bu:"洞神",author:"佚名",era:"六朝–唐（太清傳統）",topic:"道医方",essence:"Phương đoạn cốc (tịch cốc) thuộc hệ Thái Thanh: dùng tùng căn, phục linh và các hoàn dược để tuyệt ngũ cốc, khát thì uống nước. Nối tiếp truyền thống phục khí–tịch cốc của đạo giáo trung cổ.",key_text:"取東行松根，剝取白皮，細簁，飽食之，可絕穀，渴則飲水。",use:"Tham khảo pháp tịch cốc, phục dược thay lương thực trong dưỡng tính.",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E6%B8%85%E7%B6%93%E6%96%B7%E7%A9%80%E6%B3%95","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.daoinfo.org/index.php?title=%E7%A5%9E%E4%BB%99%E6%9C%8D%E9%A3%9F%E9%9D%88%E8%8D%89%E8%8F%96%E8%92%B2%E4%B8%B8%E6%96%B9%E5%82%B3"],textual_certainty:"high",notes:"batch41 · Grok-4.5 catalog-driven"},{dz:"DZ844",name_han:"神仙服食靈草菖蒲丸方傳",name_vi:"Thần Tiên Phục Thực Linh Thảo Xương Bồ Hoàn Phương Truyện",bu:"洞神",author:"佚名",era:"唐（言及大曆十四年）",topic:"道医方",essence:"Còn gọi Xương bồ truyện; ca ngợi xương bồ là thủy tinh, linh thảo thần tiên, kèm pháp hái theo ngày số trùng (3/3, 5/5…) và chế hoàn phục thực. Tiêu biểu cho nhánh dược phương–phục thực trong Đạo tạng.",key_text:"夫菖蒲者，水之精，神仙之靈草，大聖之珍方。",use:"Phương chế xương bồ hoàn, lịch hái thuốc và phục thực dưỡng sinh.",sources:["https://zh.daoinfo.org/index.php?title=%E7%A5%9E%E4%BB%99%E6%9C%8D%E9%A3%9F%E9%9D%88%E8%8D%89%E8%8F%96%E8%92%B2%E4%B8%B8%E6%96%B9%E5%82%B3","https://zh.wikisource.org/wiki/%E7%A5%9E%E4%BB%99%E6%9C%8D%E9%A3%9F%E9%9D%88%E8%8D%89%E8%8F%96%E8%92%B2%E4%B8%B8%E6%96%B9%E5%82%B3","https://ctext.org/wiki.pl?if=gb&res=696238"],textual_certainty:"high",notes:"batch41 · Grok-4.5 catalog-driven"},{dz:"DZ1022",name_han:"素問入式運氣論奧",name_vi:"Tố Vấn Nhập Thức Vận Khí Luận Áo",bu:"太玄",author:"劉溫舒",era:"北宋（元符二年序，約1099）",topic:"道医方",essence:"Ba quyển, 31 luận và nhiều đồ thức, giải ngũ vận lục khí từ Tố vấn để trị bệnh. Kết hợp can chi, ngũ hành, tuế vận–khách chủ; là cửa ngõ học vận khí y–đạo thời Tống, thu vào Thái huyền bộ.",key_text:"夫醫書者，乃三墳之經。",use:"Học ngũ vận lục khí, suy khí hậu–bệnh tà và định hướng trị liệu theo năm.",sources:["https://zh.daoinfo.org/index.php?title=%E7%B4%A0%E5%95%8F%E5%85%A5%E5%BC%8F%E9%81%8B%E6%B0%A3%E8%AB%96%E5%A5%A7","https://ctext.org/wiki.pl?if=gb&res=751859","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch41 · Grok-4.5 catalog-driven"},{dz:"DZ1023",name_han:"素問六氣玄珠密語",name_vi:"Tố Vấn Lục Khí Huyền Châu Mật Ngữ",bu:"太玄",author:"題啟玄子（託名王冰）",era:"唐–宋間（託唐）",topic:"杂占术数",essence:"Còn gọi Huyền châu mật ngữ; 17 quyển, 24 thiên, khai triển thất thiên đại luận về ngũ vận lục khí, khí hậu, dịch lệ, dược tính và cả chiêm hậu. Nối y lý với thiên văn–thuật số đạo giáo.",key_text:"使人能順天五行六氣者，可盡天年一百二十歲矣。",use:"Suy vận khí, phòng dịch, chiêm hậu thời khí và phối dược theo tư thiên tại tuyền.",sources:["https://zh.daoinfo.org/index.php?title=%E7%B4%A0%E5%95%8F%E5%85%AD%E6%B0%A3%E7%8E%84%E7%8F%A0%E5%AF%86%E8%AA%9E","https://ctext.org/wiki.pl?if=gb&res=214745","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch41 · Grok-4.5 catalog-driven"},{dz:"DZ857",name_han:"祕藏通玄變化六陰洞微遁甲真經",name_vi:"Bí Tàng Thông Huyền Biến Hóa Lục Âm Động Vi Độn Giáp Chân Kinh",bu:"洞神",author:"佚名（傳出劉罕；附趙普進表）",era:"北宋",topic:"杂占术数",essence:"Ba quyển về lục âm động vi–độn giáp, lục đinh ngọc nữ, nghi tấu cáo, lập đàn và phép ẩn hình, hành quân. Gắn thuật độn giáp với nghi quỹ đạo giáo, tiêu biểu cho nhánh phương thuật–chiêm hậu trong tạng.",key_text:"夫欲入道必先探賾玄微。",use:"Nghiên cứu độn giáp đạo giáo, lục đinh ngọc nữ và nghi lập đàn.",sources:["https://zh.daoinfo.org/index.php?title=%E7%A7%98%E8%97%8F%E9%80%9A%E7%8E%84%E8%AE%8A%E5%8C%96%E5%85%AD%E9%99%B0%E6%B4%9E%E5%BE%AE%E9%81%81%E7%94%B2%E7%9C%9F%E7%B6%93","https://ctext.org/wiki.pl?if=gb&res=727581","https://www.shidianguji.com/zh/book/DZ0857"],textual_certainty:"high",notes:"batch41 · Grok-4.5 catalog-driven"},{dz:"DZ1481",name_han:"法師選擇記",name_vi:"Pháp Sư Tuyển Trạch Ký",bu:"续道藏",author:"佚名",era:"明以前（萬曆續道藏）",topic:"杂占术数",essence:"Sách trạch cát một quyển trong Vạn lịch Tục Đạo tạng, thường đi kèm truyền thống Ngọc hạp ký. Dựa can chi, tinh tượng để chọn ngày giờ làm việc, lập trai, cầu phúc–tránh họa cho pháp sư và dân chúng.",key_text:"貞觀元年正月十五日",use:"Chọn ngày giờ nghi lễ, lập trai, xuất hành theo lịch đạo giáo.",sources:["https://www.shidianguji.com/zh/book/DZ1481","https://ctext.org/wiki.pl?if=gb&res=749253","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch41 · Grok-4.5 catalog-driven"},{dz:"DZ1298",name_han:"四聖真君靈籤",name_vi:"Tứ Thánh Chân Quân Linh Thiêm",bu:"正一",author:"佚名",era:"宋–明",topic:"杂占术数",essence:"Sách linh thiêm thờ Tứ Thánh (Thiên Bồng, Thiên Du, Dực Thánh, Chân Vũ). Mỗi quẻ có thơ–lời đoán họa phúc, thuộc loại bốc thiêm đạo quán dùng trong cầu tự, kiện tụng, bệnh tật.",key_text:"四聖真君靈籤",use:"Rút quẻ hỏi việc tại điện Tứ Thánh / Huyền Thiên.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://michaelstanley-baker.com/clarkes-complete-daoist-index/","https://www.daoist.org/BookSearch(test)/list016.asp?Page=66"],textual_certainty:"partial",notes:"batch41 · Grok-4.5 catalog-driven"},{dz:"DZ1387",name_han:"上清元始高上玉皇九天譜錄",name_vi:"Thượng Thanh Nguyên Thủy Cao Thượng Ngọc Hoàng Cửu Thiên Phổ Lục",bu:"正一",author:"佚名（上清傳統）",era:"南北朝–唐",topic:"神谱仙谱",essence:"Kinh–lục Thượng Thanh liệt kê thần danh, hiệu húy và linh phù các vị cửu thiên (Nguyên Thủy trượng nhân, Tư mệnh đạo quân…). Vừa là phổ thần vừa là chứng lục đeo mình, phản ánh giai vị tiên thánh thượng giới.",key_text:"上學先生王甲受氣合仙，清齋玄嶽，奉受玉篇。",use:"Tra phổ thần cửu thiên, hiệu húy và nghi thụ lục Thượng Thanh.",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%8A%E6%B8%85%E5%85%83%E5%A7%8B%E9%AB%98%E4%B8%8A%E7%8E%89%E7%9A%87%E4%B9%9D%E5%A4%A9%E8%AD%9C%E9%8C%84","https://zh.wikisource.org/wiki/%E4%B8%8A%E6%B8%85%E5%85%83%E5%A7%8B%E9%AB%98%E4%B8%8A%E7%8E%89%E7%9A%87%E4%B9%9D%E5%A4%A9%E8%B0%B1%E7%AE%93","https://ctext.org/wiki.pl?if=gb&res=841680"],textual_certainty:"high",notes:"batch41 · Grok-4.5 catalog-driven"},{dz:"DZ1296",name_han:"洞玄靈寶八節齋宿啟儀",name_vi:"Động Huyền Linh Bảo Bát Tiết Trai Túc Khải Nghi",bu:"正一",author:"佚名",era:"唐宋",topic:"经典杂",essence:"Nghi thức túc khải cho Bát tiết trai thuộc Linh Bảo lục trai: pháp sư đội mão, chấp giản, dẫn đạo chúng theo vị, cầu sám cho thất huyền và thân mình vào tám tiết khí trong năm. Là văn bản nghi lễ–rang giải theo lịch bát tiết còn ít được khai thác.",key_text:"法師冠帶，執簡。引道眾，依位幡花幢節。",use:"Tái dựng/nghiên cứu trai nghi bát tiết và sám hối theo lịch tiết khí.",sources:["https://zh.daoinfo.org/index.php?title=%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E5%85%AB%E7%AF%80%E9%BD%8B%E5%AE%BF%E5%95%9F%E5%84%80","https://zh.wikisource.org/wiki/%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E5%85%AB%E7%AF%80%E9%BD%8B%E5%AE%BF%E5%95%9F%E5%84%80","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch41 · Grok-4.5 catalog-driven"},{dz:"DZ1299",name_han:"玄真靈應寶籤",name_vi:"Huyền Chân Linh Ứng Bảo Thiêm",bu:"正一",author:"不詳（託文昌帝君）",era:"宋元以降／明刊入藏",topic:"杂占",essence:"Bộ linh thiêm ba quyển thuộc Chính nhất bộ, mượn danh Văn Xương Đế Quân để ban lời sấm quẻ. Mỗi quẻ gồm thi thơ, lời giải và răn thiện, dùng cho cầu tự, công danh, hôn nhân và họa phúc. Đây là điển hình linh thiêm đạo giáo dân gian được thu vào Chính thống đạo tạng.",key_text:"九天開化主宰文昌帝君寶誥",use:"Rút quẻ hỏi việc, răn thiện, cầu phúc giải nghi trong miếu đạo.",sources:["https://ctext.org/wiki.pl?if=gb&res=573285","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch42 · Grok-4.5 catalog-driven"},{dz:"DZ1300",name_han:"大慈好生九天衛房聖母元君靈應寶籤",name_vi:"Đại Từ Hảo Sinh Cửu Thiên Vệ Phòng Thánh Mẫu Nguyên Quân Linh Ứng Bảo Thiêm",bu:"正一",author:"不詳",era:"宋明之間",topic:"杂占",essence:"Linh thiêm chuyên về sinh nở, bảo thai và cầu tự, nhân danh Cửu Thiên Vệ Phòng Thánh Mẫu. Các quẻ khuyên hiếu thảo, hành thiện, tụng kinh và dùng phù bảo thai để mẹ con bình an. Phản ánh tín ngưỡng hộ sinh trong đạo giáo dân gian.",key_text:"天尊有敕救人民，帥將欽承闡聖靈。",use:"Cầu tự, bảo thai, xem quẻ khi lâm bồn, hộ mệnh sản phụ.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%A7%E6%85%88%E5%A5%BD%E7%94%9F%E4%B9%9D%E5%A4%A9%E8%A1%9B%E6%88%BF%E8%81%96%E6%AF%8D%E5%85%83%E5%90%9B%E9%9D%88%E6%87%89%E5%AF%B6%E7%B1%A4&variant=zh-hant","https://zh.wikisource.org/zh-hant/%E5%A4%A7%E6%85%88%E5%A5%BD%E7%94%9F%E4%B9%9D%E5%A4%A9%E8%A1%9B%E6%88%BF%E8%81%96%E6%AF%8D%E5%85%83%E5%90%9B%E9%9D%88%E6%87%89%E5%AF%B6%E7%B1%A4","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch42 · Grok-4.5 catalog-driven"},{dz:"DZ1301",name_han:"洪恩靈濟真君靈籤",name_vi:"Hồng Ân Linh Tế Chân Quân Linh Thiêm",bu:"正一",author:"不詳",era:"元明",topic:"杂占",essence:"Bộ linh thiêm thờ Hồng Ân Linh Tế Chân Quân (tín ngưỡng Giang Đông/Phúc Kiến–Đài loan liên hệ). Dùng rút quẻ cầu an, hỏi bệnh, công danh và gia đạo. Là nguồn quan trọng để nghiên cứu tín ngưỡng thần địa phương được chính thức hóa trong đạo tạng.",key_text:"null",use:"Rút quẻ cầu phúc, hỏi việc tại miếu Linh Tế Chân Quân.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.jstor.org/stable/26768560","https://brill.com/display/book/edcoll/9789004514263/BP000018.xml"],textual_certainty:"high",notes:"batch42 · Grok-4.5 catalog-driven"},{dz:"DZ1303",name_han:"扶天廣聖如意靈籤",name_vi:"Phù Thiên Quảng Thánh Như Ý Linh Thiêm",bu:"正一",author:"不詳",era:"宋元明",topic:"杂占",essence:"Linh thiêm “như ý” thuộc hệ quẻ đạo giáo trong Chính nhất bộ. Nội dung thiên về cát hung tổng quát, khuyên thiện và cầu xin đắc như ý. Cùng nhóm thiêm như Tứ Thánh, Huyền Chân, tạo thành cụm tài liệu bói quẻ chuẩn của đạo tạng.",key_text:"null",use:"Rút quẻ hỏi cát hung, cầu như ý, răn thiện.",sources:["https://www.jstor.org/stable/26768560","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://brill.com/display/book/edcoll/9789004514263/BP000018.xml"],textual_certainty:"high",notes:"batch42 · Grok-4.5 catalog-driven"},{dz:"DZ1305",name_han:"護國嘉濟江東王靈籤",name_vi:"Hộ Quốc Gia Tế Giang Đông Vương Linh Thiêm",bu:"正一",author:"傅燁（南宋；明人合編碑記）",era:"南宋寶慶間／明初合刊",topic:"杂占",essence:"Một trăm quẻ linh thiêm thờ Giang Đông Vương Thạch Cố (Gia Tế miếu Cám Châu). Mỗi quẻ có thất ngôn tuyệt cú kèm lời giải tứ ngôn/tam ngôn về họa phúc. Có kèm bia linh tích của Tống Liêm (1371), minh chứng thần địa phương được thu nạp vào đạo tạng.",key_text:"巍巍獨步向雲間，玉殿千官第一班。",use:"Rút quẻ hỏi việc, cầu hộ quốc an dân, nghiên cứu tín ngưỡng thổ thần Giang Tây.",sources:["https://zh.daoinfo.org/index.php?title=%E8%AD%B7%E5%9C%8B%E5%98%89%E6%BF%9F%E6%B1%9F%E6%9D%B1%E7%8E%8B%E9%9D%88%E7%B1%A4&variant=zh-hant","https://ctext.org/wiki.pl?if=gb&res=440234","https://www.shidianguji.com/book/DZ1305"],textual_certainty:"high",notes:"batch42 · Grok-4.5 catalog-driven"},{dz:"DZ727",name_han:"文始真經注",name_vi:"Văn Thủy Chân Kinh Chú",bu:"太玄",author:"牛道淳",era:"元（約大德三年前後，fl. 1299）",topic:"注疏",essence:"Chú giải Quan Doãn Tử / Văn Thủy chân kinh theo hướng toàn chân–huyền học đời Nguyên. Giải nghĩa các thiên “Nhất tự”, “Nhị trụ”… bằng ngôn ngữ nội đan và tâm tính. Là bản chú quan trọng bên cạnh Văn Thủy chân kinh ngôn ngoại chỉ.",key_text:"null",use:"Đọc chú để hiểu triết lý Quan Doãn Tử và đường lối toàn chân.",sources:["https://brill.com/display/book/9789004193864/Bej.9789004192287.i-430_007.pdf","https://brill.com/display/book/9789004271647/B9789004271647_018.pdf","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch42 · Grok-4.5 catalog-driven"},{dz:"DZ728",name_han:"文始真經言外旨",name_vi:"Văn Thủy Chân Kinh Ngôn Ngoại Chỉ",bu:"太玄",author:"陳顯微",era:"南宋（嘉定–寶祐間，fl. 1223–1254）",topic:"注疏",essence:"Chú sớ chín quyển của Trần Hiển Vi về Văn Thủy chân kinh, nhấn mạnh “ngôn ngoại chi chỉ” — ý ngoài lời. Kết hợp huyền học Lão–Trang với nội đan Nam Tống, được coi là chú bản chuẩn của Quan Doãn Tử trong đạo tạng.",key_text:"道無形無聲，而天地萬物生焉。",use:"Nghiên cứu chú sớ Quan Doãn Tử, triết học huyền học và nội đan.",sources:["https://ctext.org/wiki.pl?if=gb&res=746629","https://ctext.org/library.pl?if=gb&res=84406","https://fabriziopregadio.com/files/PREGADIO_and_ESPOSITO_Daozang_jiyao_Catalogue.pdf"],textual_certainty:"high",notes:"batch42 · Grok-4.5 catalog-driven"},{dz:"DZ748",name_han:"通玄真經纘義",name_vi:"Thông Huyền Chân Kinh Toản Nghĩa",bu:"太玄",author:"杜道堅",era:"元初（杜道堅，1237–1318）",topic:"注疏",essence:"Chú giải Thông huyền chân kinh (Văn Tử) của Đỗ Đạo Kiên, gồm thập nhị quyển kèm thích âm. Hệ thống hóa nghĩa lý Văn Tử theo Lão học và chính giáo đạo sĩ đời Tống–Nguyên. Có quan hệ với truyền thừa “Huyền nguyên thập tử” và văn nhân như Triệu Mạnh Phủ.",key_text:"null",use:"Đọc chú Văn Tử, nghiên cứu Lão học đời Tống–Nguyên.",sources:["https://www.jstor.org/stable/26768560","https://www.researchgate.net/publication/361290726_Portraits_of_the_Ten_Masters_of_the_Mysterious_Origin_xuanyuanshizitu_English_ms_version","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch42 · Grok-4.5 catalog-driven"},{dz:"DZ749",name_han:"通玄真經注",name_vi:"Thông Huyền Chân Kinh Chú",bu:"太玄",author:"朱弁",era:"金／宋金之際",topic:"注疏",essence:"Bản chú Thông huyền chân kinh của Chu Biện, khác với Toản nghĩa của Đỗ Đạo Kiên. Tập trung giải nghĩa văn bản Văn Tử theo truyền thống nghĩa sớ, bổ sung lớp chú giải sớm hơn trong hệ Thái huyền bộ.",key_text:"null",use:"Đối chiếu các bản chú Văn Tử trong đạo tạng.",sources:["https://www.jstor.org/stable/26768560","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","http://www.homeinmists.com/new_uploaded.htm"],textual_certainty:"high",notes:"batch42 · Grok-4.5 catalog-driven"},{dz:"DZ794",name_han:"正一解厄醮儀",name_vi:"Chính Nhất Giải Ách Giao Nghi",bu:"洞神",author:"不詳",era:"南北朝至唐（約隋唐定型）",topic:"道法符咒秘诀",essence:"Nghi thức giao tế Chính nhất để giải ách, bệnh tật và tai ương theo ngày bản mệnh. Cúng Bắc Đẩu, ngũ phương đế, tư mệnh tư lục và lục thập giáp tử thần, dùng đèn dầu, gạo mệnh, muối đậu. Là nghi giải tai chuẩn của truyền thừa Thiên sư.",key_text:"凡人算盡陽九陰八災憂不寧者依法禳之轉禍為福",use:"Làm giao giải ách, cầu an bản mệnh, chữa bệnh theo nghi Chính nhất.",sources:["https://ctext.org/wiki.pl?if=gb&res=573808","https://www.mdpi.com/2077-1444/16/12/1555","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch42 · Grok-4.5 catalog-driven"},{dz:"DZ802",name_han:"正一醮墓儀",name_vi:"Chính Nhất Giao Mộ Nghi",bu:"洞神",author:"不詳",era:"南北朝至唐",topic:"道法符咒秘诀",essence:"Nghi giao tế mộ phần theo pháp Chính nhất, an trấn âm trạch, giải phạm mộ khí. Thường đi cùng các nghi giao trạch, xuất quan, giải ách trong hệ Thiên sư. Phản ánh nghi lễ tang–mộ của đạo sĩ địa phương.",key_text:"null",use:"Giao mộ, an táng, giải phạm mộ địa, trấn âm trạch.",sources:["https://www.jstor.org/stable/26768560","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/zh-hans/%E9%81%93%E8%97%8F_(%E5%9B%9B%E5%BA%AB%E5%85%A8%E6%9B%B8%E6%9C%AC)/%E5%85%A8%E8%A6%BD"],textual_certainty:"high",notes:"batch42 · Grok-4.5 catalog-driven"},{dz:"DZ809",name_han:"太上三五傍救醮五帝斷殟儀",name_vi:"Thái Thượng Tam Ngũ Bàng Cứu Giao Ngũ Đế Đoạn Ôn Nghi",bu:"洞神",author:"不詳",era:"唐宋",topic:"道法符咒秘诀",essence:"Nghi giao bàng cứu thỉnh Ngũ Đế để đoạn ôn dịch, thu bắt tà quỷ gây ôn chẩn. Liệt kê các loại quỷ dịch tặc, bại quân tử tướng, hạ lỵ ung thũng… để thu phục. Thuộc nhóm nghi trị bệnh–trừ ôn của pháp Chính nhất/Tam ngũ.",key_text:"夫人家忽逢天災厄難，家口癭疔，經一日五日者",use:"Giao trừ ôn dịch, trị bệnh tà, cầu cứu hộ khi nhà có ôn chẩn.",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E4%B8%89%E4%BA%94%E5%82%8D%E6%95%91%E9%86%AE%E4%BA%94%E5%B8%9D%E6%96%B7%E6%AE%9F%E5%84%80","https://homeinmists.ilotus.org/%E9%81%93%E8%97%8F%E5%8C%AF%E7%B7%A8/%E6%B6%B5%E8%8A%AC%E6%A8%93-%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F/1533%E7%A8%AE%E7%B6%93%E6%9B%B8%E5%B0%8D%E6%87%89%E9%81%93%E8%97%8F%E5%9B%9B%E7%A8%AE%E7%89%88%E6%9C%AC%E4%B9%8B%E5%86%8A%E6%95%B8-%E9%A0%81%E7%A2%BC/","https://thesis.lib.nccu.edu.tw/thesis/detail/f42fbeff5bf8a47dd1dfd9d730fd9c3b/"],textual_certainty:"high",notes:"batch42 · Grok-4.5 catalog-driven"},{dz:"DZ810",name_han:"太上消災祈福醮儀",name_vi:"Thái Thượng Tiêu Tai Kỳ Phúc Giao Nghi",bu:"洞神",author:"不詳",era:"唐宋",topic:"道法符咒秘诀",essence:"Nghi giao tiêu tai cầu phúc của Thái thượng, bố trí đàn, thỉnh thần, dâng sớ và tạ ân. Dùng cho nhà cửa bất an, tuổi hạn, cầu an tổng quát. Bổ sung cho các nghi giải ách–đoạn ôn trong Động thần bộ uy nghi.",key_text:"null",use:"Giao tiêu tai, cầu phúc an nhà, giải hạn.",sources:["https://www.jstor.org/stable/26768560","https://homeinmists.ilotus.org/%E9%81%93%E8%97%8F%E5%8C%AF%E7%B7%A8/%E6%B6%B5%E8%8A%AC%E6%A8%93-%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F/1533%E7%A8%AE%E7%B6%93%E6%9B%B8%E5%B0%8D%E6%87%89%E9%81%93%E8%97%8F%E5%9B%9B%E7%A8%AE%E7%89%88%E6%9C%AC%E4%B9%8B%E5%86%8A%E6%95%B8-%E9%A0%81%E7%A2%BC/","https://zh.wikisource.org/zh-hans/%E9%81%93%E8%97%8F_(%E5%9B%9B%E5%BA%AB%E5%85%A8%E6%9B%B8%E6%9C%AC)/%E5%85%A8%E8%A6%BD"],textual_certainty:"high",notes:"batch42 · Grok-4.5 catalog-driven"},{dz:"DZ654",name_han:"太上洞神天公消魔護國經",name_vi:"Thái Thượng Động Thần Thiên Công Tiêu Ma Hộ Quốc Kinh",bu:"洞神",author:"不詳",era:"唐宋",topic:"经典杂",essence:"Kinh Động thần ba quyển thỉnh Thiên Công tiêu ma, hộ quốc an dân. Nối thần quyền thiên đình với cầu đảo hộ quốc, có yếu tố sấm chú và nghi thỉnh cầu. Được trích dẫn trong nghiên cứu trai giáo và nghi hộ quốc đời Đường–Tống.",key_text:"null",use:"Tụng kinh cầu hộ quốc, tiêu ma, nghiên cứu thần học Thiên Công.",sources:["https://www.jstor.org/stable/26768560","https://www11.ihp.sinica.edu.tw/storage/w2_file/2929XCnNBRN.pdf","https://nccur.lib.nccu.edu.tw/handle/140.119/76213"],textual_certainty:"high",notes:"batch42 · Grok-4.5 catalog-driven"},{dz:"DZ753",name_han:"北斗七元金玄羽章",name_vi:"Bắc Đẩu Thất Nguyên Kim Huyền Vũ Chương",bu:"洞神",author:"不詳",era:"唐（約初唐至盛唐）",topic:"经典杂",essence:"Kinh–phù chương về thất nguyên Bắc Đẩu, kèm phù hình “vũ chương” (cánh lông) tương ứng từng sao. Dùng trong tồn tư, đái phù và nghi cầu mệnh liên quan Bắc Đẩu. Schipper định niên đại khoảng đầu Đường; hình phù gần với một số chú Bắc Thần–Bắc Đẩu.",key_text:"null",use:"Đái phù Bắc Đẩu, cầu mệnh diên sinh, nghiên cứu phù chương thất tinh.",sources:["https://www.mdpi.com/2077-1444/16/12/1555","https://www.jstor.org/stable/26768560","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch42 · Grok-4.5 catalog-driven"},{dz:"DZ606",name_han:"南嶽總勝集",name_vi:"Nam Nhạc Tổng Thắng Tập",bu:"洞玄",author:"陳田夫",era:"南宋（約1163–1164）",topic:"仙传杂",essence:"Địa chí–thắng tích núi Hành Sơn (Nam Nhạc) do Trần Điền Phu biên soạn đời Nam Tống. Ghi chép động thiên, cung quán, chân nhân, bi ký và truyền thuyết tu tiên tại Nam Nhạc. Vừa là sơn chí vừa là tư liệu tiên truyện–thánh địa quan trọng.",key_text:"null",use:"Nghiên cứu địa lý thánh địa, tiên truyện Nam Nhạc, lịch sử cung quán.",sources:["https://www.jstor.org/stable/26768560","https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf","https://fabriziopregadio.com/files/PREGADIO_and_ESPOSITO_Daozang_jiyao_Catalogue.pdf"],textual_certainty:"high",notes:"batch42 · Grok-4.5 catalog-driven"},{dz:"DZ054",name_han:"太上洞淵辭瘟神咒妙經",name_vi:"Thái Thượng Động Uyên Từ Ôn Thần Chú Diệu Kinh",bu:"洞真",author:"佚名",era:"唐宋（約唐至宋元）",topic:"ritual",essence:"Kinh chuyên trị ôn dịch trong hệ Động Uyên thần chú. Nguyên Thủy Thiên Tôn dạy Động Uyên Thiên Tôn: ôn dịch do dân bất kính Tam Bảo, nên lập đàn, tụng kinh, thỉnh hành bệnh thần vương và sứ giả ngũ đế thu ôn nhiếp độc. Đây là kinh hộ mệnh – trị ôn thực dụng trong đạo pháp dân gian.",key_text:"若能轉此經，鬼禍悉潛藏。",use:"Tụng kinh / lập đàn tống ôn, trị ôn dịch, hộ nhà hộ mệnh",sources:["https://zh.wikisource.org/wiki/太上洞淵辭瘟神呪妙經","https://zh.daoinfo.org/index.php?title=太上洞淵辭瘟神咒妙經","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch43 · Grok-4.5 catalog-driven"},{dz:"DZ303",name_han:"純陽帝君神化妙通紀",name_vi:"Thuần Dương Đế Quân Thần Hóa Diệu Thông Kỷ",bu:"洞真",author:"苗善時",era:"元",topic:"仙传",essence:"Toàn Chân đạo sĩ Miêu Thiện Thời biên soạn truyện Lã Động Tân (Thuần Dương Đế Quân), dự định 120 hóa, nay còn khoảng 95. Gồm gia thế, ngộ đạo, thử ma, ẩn hóa độ thế; điểm hóa nhiều nhân vật Nho–Đạo. Văn phong gần truyền kỳ, là nguồn quan trọng về Lã Tổ trong đạo tạng.",key_text:"或以神通誘掖塵俗，或以藥物救濟善良。",use:"Đọc truyện tiên, nghiên cứu Lã Tổ / Toàn Chân huyền thoại",sources:["https://zh.daoinfo.org/index.php?title=純陽帝君神化妙通記","https://zh.wikisource.org/wiki/純陽帝君神化妙通紀","https://ctext.org/wiki.pl?if=gb&res=261129"],textual_certainty:"high",notes:"batch43 · Grok-4.5 catalog-driven"},{dz:"DZ328",name_han:"太上洞玄靈寶護諸童子經",name_vi:"Thái Thượng Động Huyền Linh Bảo Hộ Chư Đồng Tử Kinh",bu:"洞玄",author:"佚名",era:"唐宋",topic:"classic",essence:"Kinh Linh Bảo hộ mệnh–hộ đồng: người đời phạm ác tinh xấu túy khi ra vào cửa, tụng kinh thì Bắc Đẩu thất tinh đồng tử, ngũ thần đồng tử và thập phương thiện đồng tử đến hộ vệ. Cầu tự, bảo trường niên, tiêu tai giáng phúc cho nam nữ và trẻ nhỏ.",key_text:"凡人居世，命屬北斗，七星三台，輔弼華蓋，本命星官。",use:"Tụng hộ đồng, cầu tự, tiêu tai tinh sát",sources:["https://zh.daoinfo.org/index.php?title=太上洞玄靈寶護諸童子經","https://zh.wikisource.org/wiki/太上洞玄靈寶護諸童子經","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch43 · Grok-4.5 catalog-driven"},{dz:"DZ333",name_han:"靈寶天尊說祿庫受生經",name_vi:"Linh Bảo Thiên Tôn Thuyết Lộc Khố Thụ Sinh Kinh",bu:"洞玄",author:"佚名",era:"隋唐",topic:"classic",essence:"Linh Bảo Thiên Tôn giảng: lúc đầu thai đã vay tiền lộc khố thụ sinh ở địa phủ; trả đủ thì phú quý, nợ thì bần tiện. Khuyên bố thí, thiết trai tụng kinh, đốt trả thụ sinh tiền theo thập nhị cung khố quan. Nền tảng tư tưởng “ký khố / hoàn thư” dân gian.",key_text:"十方一切眾生，命屬天曹，身擊地府，當得人身之日，曾於地府所屬冥司，借貸祿庫受生錢財。",use:"Khoa nghi hoàn thụ sinh, giải nợ âm, cầu lộc thọ",sources:["https://zh.daoinfo.org/index.php?title=靈寶天尊說祿庫受生經","https://zh.wikisource.org/wiki/靈寶天尊說祿庫受生經","https://ctext.org/wiki.pl?if=gb&chapter=636644"],textual_certainty:"high",notes:"batch43 · Grok-4.5 catalog-driven"},{dz:"DZ358",name_han:"太上神咒延壽妙經",name_vi:"Thái Thượng Thần Chú Diên Thọ Diệu Kinh",bu:"洞玄",author:"佚名",era:"唐宋",topic:"mantra",essence:"Kinh ngắn (khoảng hơn 200 chữ) giả thác Nguyên Thủy Thiên Tôn cứu hộ ích toán, tế thân mệnh bệnh khổ. Tụng kinh–đeo phù phá ngũ hư lục hao, ác mộng, phục liên chú trớ; lục trai thập trực, Giáp Tý Canh Thân tụng niệm thì diên niên ích toán, ôn dịch không vào nhà.",key_text:"爾時，元始天尊救護益算，濟人身命，疾病苦厄。",use:"Tụng ngắn hàng ngày, diên thọ, giải hạn năm tháng",sources:["https://zh.daoinfo.org/index.php?title=太上神呪延壽妙經","https://zh.wikisource.org/wiki/太上神呪延壽妙經","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch43 · Grok-4.5 catalog-driven"},{dz:"DZ363",name_han:"太上召諸神龍安鎮墳墓經",name_vi:"Thái Thượng Triệu Chư Thần Long An Trấn Phần Mộ Kinh",bu:"洞玄",author:"佚名",era:"唐宋",topic:"ritual",essence:"Kinh Động Huyền triệu chư thần long an trấn phần mộ: dùng trong nghi trấn mộ, an long mạch, dẹp quỷ tà quấy nhiễu âm phần. Bổ sung nhóm kinh an trạch–an mộ–trấn trạch trong tạng, gắn phong thủy–đạo pháp.",key_text:"null",use:"An trấn phần mộ, triệu long thần trấn táng",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.daoinfo.org/wiki/Special:Search?search=太上召諸神龍安鎮墳墓經"],textual_certainty:"partial",notes:"batch43 · Grok-4.5 catalog-driven"},{dz:"DZ383",name_han:"太上七星神咒經",name_vi:"Thái Thượng Thất Tinh Thần Chú Kinh",bu:"洞玄",author:"佚名",era:"唐宋",topic:"mantra",essence:"Kinh thần chú Bắc Đẩu thất tinh trong Động Huyền. Dùng tụng chú thất nguyên để tiêu tai, hộ mệnh, trấn tà; thuộc nhóm kinh chú tinh tú ngắn gọn, song hành với Hư Hoàng bảo sinh và các đèn nghi Bắc Đẩu.",key_text:"null",use:"Tụng chú thất tinh, hộ mệnh tiêu tai",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch43 · Grok-4.5 catalog-driven"},{dz:"DZ384",name_han:"太上虛皇保生神咒經",name_vi:"Thái Thượng Hư Hoàng Bảo Sinh Thần Chú Kinh",bu:"洞玄",author:"佚名",era:"唐宋",topic:"mantra",essence:"Thần chú kinh lấy Hư Hoàng Thiên Tôn làm chủ bảo sinh. Nhấn mạnh hộ mệnh, bảo thai, trừ tà độc bằng chú lực; cùng nhóm thất tinh–bảo sinh trong Động Huyền, phục vụ khoa nghi hộ mệnh dân gian.",key_text:"null",use:"Chú bảo sinh, hộ mệnh, trừ tà",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch43 · Grok-4.5 catalog-driven"},{dz:"DZ629",name_han:"太上北斗二十八章經",name_vi:"Thái Thượng Bắc Đẩu Nhị Thập Bát Chương Kinh",bu:"洞神",author:"佚名",era:"宋",topic:"classic",essence:"Giả thác Bắc Đẩu nguyên quân (thất nguyên + tả phụ hữu bật) truyền cho Hán Minh Đế ở Chung Nam Sơn. Hai mươi tám chương: bảy chương thất tinh quân dạy trị thân trị quốc; các chương sau nói lễ tụng thất nguyên, tiêu tai giải ách, diên sinh ích toán, giữ đạo bình đẳng.",key_text:"一名貪狼，二名巨門，三名祿存，四名文曲，五名廉貞，六名武曲，七名破軍也。",use:"Lễ tụng Bắc Đẩu, diên sinh bảo mệnh, tu thân trị gia",sources:["https://zh.daoinfo.org/index.php?title=太上北斗二十八章經","https://zh.wikisource.org/wiki/太上北斗二十八章經","https://ctext.org/wiki.pl?if=gb&res=532315"],textual_certainty:"high",notes:"batch43 · Grok-4.5 catalog-driven"},{dz:"DZ630",name_han:"太上老君說救生真經",name_vi:"Thái Thượng Lão Quân Thuyết Cứu Sinh Chân Kinh",bu:"洞神",author:"佚名",era:"唐宋",topic:"classic",essence:"Lão Quân ở Tử Vi cung lưu ly thất bảo điện nói pháp cứu sinh bảo mệnh. Khuyên trai giới, tồn niệm chân kinh để tiêu tai thích oan, diên niên ích toán; lục giáp lục đinh, thiên quan hộ vệ. Kinh hộ mệnh phổ thông trong Động Thần bộ.",key_text:"太上老君說此真經，救生保命，永無災障。",use:"Tụng cứu sinh, tiêu tai thích oan, diên thọ",sources:["https://zh.daoinfo.org/index.php?title=太上老君說救生真經","https://zh.wikisource.org/wiki/太上老君說救生真經","https://ctext.org/library.pl?if=gb&res=84310"],textual_certainty:"high",notes:"batch43 · Grok-4.5 catalog-driven"},{dz:"DZ650",name_han:"太上老君說長生益筭妙經",name_vi:"Thái Thượng Lão Quân Thuyết Trường Sinh Ích Toán Diệu Kinh",bu:"洞神",author:"佚名",era:"唐宋",topic:"classic",essence:"Lão Quân thuyết trường sinh ích toán (益筭): tụng trì, phụng đạo để tăng thọ số, tiêu tai bảo mệnh. Khác với kinh “ích toán thần phù” (DZ672); thuộc nhóm kinh diên thọ–bảo mệnh Động Thần, bổ sung lớp kinh tạp hộ mệnh chưa khai thác nhiều.",key_text:"null",use:"Tụng diên thọ, ích toán, bảo mệnh",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://crta.info/wiki/Daozang_-_DZ"],textual_certainty:"high",notes:"batch43 · Grok-4.5 catalog-driven"},{dz:"DZ652",name_han:"太上老君說解釋咒詛經",name_vi:"Thái Thượng Lão Quân Thuyết Giải Thích Chú Trớ Kinh",bu:"洞神",author:"佚名",era:"唐宋",topic:"ritual",essence:"Lão Quân truyền Doãn Hỷ pháp giải chú trớ yểm mị. Người bị ác nhân chú trớ: tắm nước thơm, lập đạo tràng, thỉnh tam động đạo sĩ chuyển tụng kinh này thì bệnh lành, chú giải; triệu ngũ đế bộ tùng binh mã trừ tà, truy yểm cổ, phúc thọ kéo dài. Kinh “giải phạm / giải chú” điển hình.",key_text:"無始以來，諸仙聖眾救度群生……驅蕩妖邪，解釋呪詛，凶殃散滅，吉瑞扶持。",use:"Giải chú trớ, yểm mị, tiểu nhân khẩu thiệt",sources:["https://zh.daoinfo.org/index.php?title=太上老君說解釋呪詛經","https://zh.wikisource.org/wiki/太上老君說解釋呪詛經","https://www.shidianguji.com/book/DZ0652"],textual_certainty:"high",notes:"batch43 · Grok-4.5 catalog-driven"},{dz:"DZ655",name_han:"太上說紫微神兵護國消魔經",name_vi:"Thái Thượng Thuyết Tử Vi Thần Binh Hộ Quốc Tiêu Ma Kinh",bu:"洞神",author:"佚名",era:"唐宋",topic:"ritual",essence:"Lão Quân tại Tử Vi thượng cung nói: Phong Đô lục động ma quỷ gây ôn, quỷ khí hại dân. Sắc Hư Nguy nhị tú hóa Chân Vũ, thống lĩnh thiên binh hàng ma ở Phong Đô sơn; sau phong Bắc Cực tổng thống Huyền Thiên đại tướng. Thần thoại Chân Vũ sớm, gắn hộ quốc tiêu ma–trừ ôn.",key_text:"爾時太上老君以上皇二年建辰之月八日，於紫微上宮……說紫微神呪靈寶大有自然神兵護國消魔品。",use:"Hộ quốc tiêu ma, trừ ôn, sùng bái Chân Vũ / Bắc Đế",sources:["https://zh.daoinfo.org/index.php?title=太上說紫微神兵護國消魔經","https://zh.wikisource.org/wiki/太上說紫微神兵護國消魔經","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch43 · Grok-4.5 catalog-driven"},{dz:"DZ657",name_han:"太上洞神五星諸宿日月混常經",name_vi:"Thái Thượng Động Thần Ngũ Tinh Chư Tú Nhật Nguyệt Hỗn Thường Kinh",bu:"洞神",author:"佚名",era:"宋元",topic:"杂占",essence:"Còn gọi Nhật Nguyệt Hỗn Thường Kinh. Bắc Đẩu, thất diệu, nhị thập bát tú đều có tinh tinh hóa thân vào ngày chủ: thầy bói, đạo sĩ, đồng tử, lão mẫu… Người nhận ra thì cầu gì được nấy, hoặc được quan lộc, hoặc tiên thuật. Kể Thái Công, Trương Lương, Gia Cát, Lý Thuần Phong gặp tinh tinh; mang màu sắc tạp chiếm–thức tinh.",key_text:"北斗之星，太一之精，常以四孟元日為卜人，遊於聚落之處。",use:"Nhận thức tinh tú hóa thân, cầu tài lộc quan chức, tạp chiếm tinh tượng",sources:["https://zh.daoinfo.org/index.php?title=太上洞神五星諸宿日月混常經","https://zh.wikisource.org/wiki/太上洞神五星諸宿日月混常經","https://ctext.org/wiki.pl?if=gb&chapter=955706"],textual_certainty:"high",notes:"batch43 · Grok-4.5 catalog-driven"},{dz:"DZ673",name_han:"無上三元鎮宅靈籙",name_vi:"Vô Thượng Tam Nguyên Trấn Trạch Linh Lục",bu:"洞神",author:"佚名（假託金明七真）",era:"南北朝末–隋唐",topic:"fu",essence:"Lục trấn trạch trong Động Thần thần phù: Nguyên Thủy Thái Thượng Ngọc Hoàng truyền “Vô thượng tam nguyên an trấn trạch lục” cho Kim Minh thất chân. An lục nơi đường hộ, tam thiên trấn phòng đại tướng suất binh bảo trạch trừ tà. Sinh giả môn hộ cát trinh, tử giả thăng hóa thiên đường.",key_text:"今故以上元天官上靈檢神築鬼收魔攝精大籙，以持相付，即名曰《無上三元安鎮宅籙》也。",use:"An lục trấn trạch, trừ tà hộ nhà",sources:["https://zh.daoinfo.org/index.php?title=無上三元鎮宅靈籙","https://zh.wikisource.org/wiki/無上三元鎮宅靈籙","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch43 · Grok-4.5 catalog-driven"},{dz:"DZ1475",name_han:"易林",name_vi:"Dịch Lâm (Tiêu Thị Dịch Lâm)",bu:"续道藏",author:"焦贛（焦延壽）",era:"西漢（萬曆續道藏收入）",topic:"杂占",essence:"Tiêu Diên Thọ (Tiêu Cán) soạn; Tùy chí 16 quyển, bản tạng 10 quyển; thu vào Vạn Lịch tục đạo tạng. Mỗi quẻ Dịch biến 64, tổng 4096 quẻ, mỗi quẻ kèm vần 3–4 chữ đoán cát hung. Thuộc tượng số–chiêm hậu Hán đại (Mạnh Hỷ–Kinh Phòng), là kinh điển tạp chiếm “Dịch Lâm / Tiêu Thị” trong đạo tạng.",key_text:"null",use:"Chiêm bốc Dịch Lâm, đoán cát hung theo 4096 quẻ biến",sources:["https://zh.daoinfo.org/index.php?title=易林（焦贛）","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://ctext.org/wiki.pl?if=gb&res=479115"],textual_certainty:"high",notes:"batch43 · Grok-4.5 catalog-driven"},{dz:"DZ621",name_han:"太上玄靈斗姆大聖元君本命延生心經",name_vi:"Thái Thượng Huyền Linh Đẩu Mẫu Đại Thánh Nguyên Quân Bản Mệnh Diên Sinh Tâm Kinh",bu:"洞神",author:"佚名",era:"宋（約南宋）",topic:"classic",essence:"Kinh xưng Đẩu Mẫu là mẹ của Bắc Đẩu, tỏa ánh sáng dược lực để điều hòa ngũ hành, giải tai ách, bảo thai, trị bệnh và luyện độ quỷ thần. Văn bản ngắn, dùng trì tụng, gắn với tín ngưỡng Đẩu Mẫu và Cửu Hoàng.",key_text:"斗姆上靈光圓大天寶月，中有騫樹，色瑩瑠璃。",use:"Trì tụng cầu bản mệnh, giải ách, bảo sinh và lễ Đẩu Mẫu/Cửu Hoàng.",sources:["https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%8A%E7%8E%84%E9%9D%88%E6%96%97%E5%A7%86%E5%A4%A7%E8%81%96%E5%85%83%E5%90%9B%E6%9C%AC%E5%91%BD%E5%BB%B6%E7%94%9F%E5%BF%83%E7%B6%93","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E7%8E%84%E9%9D%88%E6%96%97%E5%A7%86%E5%A4%A7%E8%81%96%E5%85%83%E5%90%9B%E6%9C%AC%E5%91%BD%E5%BB%B6%E7%94%9F%E5%BF%83%E7%B6%93","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch44 · Grok-4.5 catalog-driven"},{dz:"DZ193",name_han:"玉皇宥罪錫福寶懺",name_vi:"Ngọc Hoàng Hựu Tội Tích Phúc Bảo Sám",bu:"洞真",author:"題雷霆猛吏都督辛漢臣",era:"元—明初",topic:"ritual",essence:"Bảo sám thỉnh Ngọc Hoàng xá tội, ban phúc; thuộc hệ sám pháp sấm sét (雷懺). Dùng trong đàn tràng sám hối, giải oan, cầu phước cho người sống và vong linh.",key_text:"玉皇宥罪錫福寶懺",use:"Nghi thức sám hối, xá tội, cầu phước, thường phối hợp lễ Ngọc Hoàng.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf","https://fabriziopregadio.com/files/PREGADIO_and_ESPOSITO_Daozang_jiyao_Catalogue.pdf"],textual_certainty:"high",notes:"batch44 · Grok-4.5 catalog-driven"},{dz:"DZ194",name_han:"高上玉皇滿願寶懺",name_vi:"Cao Thượng Ngọc Hoàng Mãn Nguyện Bảo Sám",bu:"洞真",author:"佚名",era:"宋—明",topic:"ritual",essence:"Sám nghi hướng Ngọc Hoàng để viên mãn nguyện cầu, tẩy tội và cầu phúc. Thuộc nhóm nghi thức sám hối Ngọc Hoàng trong Đạo tạng, dùng cho đàn tràng nguyện cầu cá nhân hoặc công đức.",key_text:"高上玉皇滿願寶懺",use:"Sám hối, mãn nguyện, cầu phúc; dùng trong nghi lễ Ngọc Hoàng.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT01%E6%B4%9E%E7%9C%9F%E9%83%A8/CMT0107%E5%A8%81%E5%84%80%E9%A1%9E/CMT0107ALL/CH010706%E9%AB%98%E4%B8%8A%E7%8E%89%E7%9A%87%E6%BB%BF%E9%A1%98%E5%AF%B6%E6%87%BA/CH010706%E9%AB%98%E4%B8%8A%E7%8E%89%E7%9A%87%E6%BB%BF%E9%A1%98%E5%AF%B6%E6%87%BA.htm","https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf"],textual_certainty:"high",notes:"batch44 · Grok-4.5 catalog-driven"},{dz:"DZ337",name_han:"太上洞玄靈寶十號功德因緣妙經",name_vi:"Thái Thượng Động Huyền Linh Bảo Thập Hiệu Công Đức Nhân Duyên Diệu Kinh",bu:"洞玄",author:"佚名",era:"隋—唐",topic:"classic",essence:"Thái Thượng đạo quân giải thích mười hiệu của Nguyên Thủy Thiên Tôn (Vô thượng đạo, Nguyên thủy, Thái cực… Thiên tôn) và công đức nhân duyên trì tụng. Nhấn mạnh công đức danh hiệu và quả vị thăng tiên.",key_text:"所言無上道者，乃是元始天尊道果成時……故名無上道。",use:"Trì tụng công đức, giảng nghĩa danh hiệu Thiên Tôn, giáo hóa nhân duyên.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E5%8D%81%E8%99%9F%E5%8A%9F%E5%BE%B7%E5%9B%A0%E7%B7%A3%E5%A6%99%E7%B6%93","https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E5%8D%81%E8%99%9F%E5%8A%9F%E5%BE%B7%E5%9B%A0%E7%B7%A3%E5%A6%99%E7%B6%93","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch44 · Grok-4.5 catalog-driven"},{dz:"DZ544",name_han:"太上慈悲九幽拔罪懺",name_vi:"Thái Thượng Từ Bi Cửu U Bạt Tội Sám",bu:"洞玄",author:"佚名",era:"唐—宋",topic:"ritual",essence:"Sám pháp mười quyển: Nguyên Thủy Thiên Tôn dạy lễ thập phương ứng hiệu Thiên Tôn, sám hối tội nghiệp (báng đạo, bất hiếu, sát đạo dâm…), bạt tội cửu u, cứu vong và lợi ích người sống. Trọng tâm nghi thức độ vong, giải oan.",key_text:"爾時元始天尊，時遊十方世界，天上地下無所不經。",use:"Sám hối bạt tội, độ vong cửu u, nghi thức tang tế và siêu độ.",sources:["https://zh.daoinfo.org/wiki/%E5%A4%AA%E4%B8%8A%E6%85%88%E6%82%B2%E4%B9%9D%E5%B9%BD%E6%8B%94%E7%BD%AA%E6%87%BA","https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%8A%E6%85%88%E6%82%B2%E4%B9%9D%E5%B9%BD%E6%8B%94%E7%BD%AA%E6%87%BA/1","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch44 · Grok-4.5 catalog-driven"},{dz:"DZ1282",name_han:"高上神霄宗師受經式",name_vi:"Cao Thượng Thần Tiêu Tông Sư Thụ Kinh Thức",bu:"正一",author:"佚名（神霄派）",era:"北宋末",topic:"ritual",essence:"Nghi thức truyền kinh của phái Thần Tiêu: liệt kê kinh lục bí tàng phủ Thần Tiêu, pháp thức thụ kinh, gắn với bối cảnh Tống Huy Tông và Lâm Linh Tố. Là tư liệu then chốt về truyền thừa và danh mục kinh Thần Tiêu.",key_text:"《高上神霄靈寶度人經》六十一卷，並出於神霄東極華堂瓊室之中。",use:"Thụ kinh, lập đàn Thần Tiêu, nghiên cứu truyền thừa đạo pháp Bắc Tống.",sources:["https://zh.daoinfo.org/index.php?title=%E9%AB%98%E4%B8%8A%E7%A5%9E%E9%9C%84%E5%AE%97%E5%B8%AB%E5%8F%97%E7%B6%93%E5%BC%8F","https://zh.wikisource.org/zh-hans/%E9%AB%98%E4%B8%8A%E7%A5%9E%E9%9C%84%E5%AE%97%E5%B8%AB%E5%8F%97%E7%B6%93%E5%BC%8F","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch44 · Grok-4.5 catalog-driven"},{dz:"DZ1274",name_han:"玄和子十二月卦金訣",name_vi:"Huyền Hòa Tử Thập Nhị Nguyệt Quái Kim Quyết",bu:"正一",author:"玄和子",era:"唐—宋",topic:"cultivation",essence:"Ghép mười hai quẻ tiêu tức (phục, lâm, thái… khôn) với mười hai tháng để định hỏa hầu luyện kim đan. Vừa mang tính thuật số/dịch lý vừa là bí quyết hỏa hầu ngoại/nội đan theo chu kỳ năm.",key_text:"復卦初爻起一陽，子時符節轉天罡。",use:"Định hỏa hầu theo tháng–quẻ; tham chiếu luyện đan và lịch pháp.",sources:["https://zh.wikisource.org/zh-hans/%E7%8E%84%E5%92%8C%E5%AD%90%E5%8D%81%E4%BA%8C%E6%9C%88%E5%8D%A6%E9%87%91%E8%A8%A3","https://ctext.org/wiki.pl?if=gb&chapter=127440","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch44 · Grok-4.5 catalog-driven"},{dz:"DZ901",name_han:"石藥爾雅",name_vi:"Thạch Dược Nhĩ Nhã",bu:"洞神",author:"梅彪",era:"唐（元和元年，806）",topic:"外丹",essence:"Từ điển dược liệu luyện đan: tập hợp hơn 150 dược thạch và tên ẩn (隐名), mô phỏng thể lệ Nhĩ Nhã. Công cụ tra cứu then chốt cho ngoại đan và lịch sử hóa dược.",key_text:"石藥爾雅",use:"Giải mã tên ẩn dược liệu ngoại đan; tra cứu thuật ngữ luyện đan.",sources:["https://zh.daoinfo.org/index.php?title=%E7%9F%B3%E8%97%A5%E7%88%BE%E9%9B%85","https://baike.baidu.com/item/%E7%9F%B3%E8%8D%AF%E5%B0%94%E9%9B%85/8453892","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch44 · Grok-4.5 catalog-driven"},{dz:"DZ925",name_han:"丹方鑑源",name_vi:"Đan Phương Giám Nguyên",bu:"洞神",author:"獨孤滔（紫閣山叟）",era:"唐末—南唐",topic:"外丹",essence:"Cẩm nang phân loại dược liệu ngoại đan và hoàng bạch thuật theo từng nhóm (kim ngân, hoàng, sa, phàn, thanh…). Giải thích tính chất, phản ứng và cách dùng; mang tính cẩm nang thực hành.",key_text:"麩金。出漢江、昌江、五溪，或如麩子形。",use:"Tra cứu dược liệu luyện đan, phân loại khoáng dược ngoại đan.",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%B9%E6%96%B9%E9%91%91%E6%BA%90","https://ctext.org/wiki.pl?if=gb&res=316846","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch44 · Grok-4.5 catalog-driven"},{dz:"DZ899",name_han:"大丹記",name_vi:"Đại Đan Ký",bu:"洞神",author:"題魏伯陽（疑隋唐人偽託）",era:"隋—唐",topic:"外丹",essence:"Bàn ngoại đan, trọng tâm tính chất chì–thủy ngân và lý luận luyện đại đan. Được mục lục Tống đại ghi nhận; là văn bản ngắn về huyền lý và thực tiễn lô hỏa.",key_text:"大丹記",use:"Nghiên cứu lý luận chì–thủy ngân và hỏa hầu ngoại đan.",sources:["https://zh.daoinfo.org/wiki/%E5%A4%A7%E4%B8%B9%E8%A8%98","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf"],textual_certainty:"high",notes:"batch44 · Grok-4.5 catalog-driven"},{dz:"DZ948",name_han:"神仙養生祕術",name_vi:"Thần Tiên Dưỡng Sinh Bí Thuật",bu:"洞神",author:"題劉景先傳；抱一子（陳顯微）校正",era:"唐宋（宋校正）",topic:"道医",essence:"Tập khoảng bốn mươi phương thuật dưỡng sinh và bí phương: ngoại đan, hoàng bạch, phục thực, trừ bệnh. Vừa mang tính y phương vừa là bí thuật trường sinh của đạo môn.",key_text:"神仙養生祕術",use:"Tham khảo phương dược dưỡng sinh, phục thực, bí thuật trường sinh.",sources:["https://zh.daoinfo.org/index.php?title=%E7%A5%9E%E4%BB%99%E9%A4%8A%E7%94%9F%E7%A7%98%E8%A1%93","https://zh.wikisource.org/zh-hans/%E7%A5%9E%E4%BB%99%E9%A4%8A%E7%94%9F%E7%A7%98%E8%A1%93","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch44 · Grok-4.5 catalog-driven"},{dz:"DZ932",name_han:"白雲仙人靈草歌",name_vi:"Bạch Vân Tiên Nhân Linh Thảo Ca",bu:"洞神",author:"佚名（題白雲仙人）",era:"唐前後",topic:"道医",essence:"Thơ–ca liệt kê linh thảo, thảo dược thần hiệu dùng phục thực và chữa bệnh theo truyền thống tiên dược. Gắn với hệ thống bản thảo–phục thực trong Đạo tạng.",key_text:"白雲仙人靈草歌",use:"Nhận biết linh thảo, tham khảo phục thực và y phương thảo dược.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf","https://zh.wikisource.org/zh-hans/%E9%81%93%E8%97%8F_(%E5%9B%9B%E5%BA%AB%E5%85%A8%E6%9B%B8%E6%9C%AC)/%E5%85%A8%E8%A6%BD"],textual_certainty:"high",notes:"batch44 · Grok-4.5 catalog-driven"},{dz:"DZ601",name_han:"金華赤松山志",name_vi:"Kim Hoa Xích Tùng Sơn Chí",bu:"洞玄",author:"倪守約",era:"南宋末",topic:"仙传",essence:"Sơn chí núi Xích Tùng (Kim Hoa, Chiết Giang): truyền thuyết Hoàng Sơ Bình–Hoàng Sơ Khởi (Hoàng Đại Tiên), linh tích, cung quán, nhân vật và chế cáo. Nguồn chính cho tín ngưỡng Hoàng Đại Tiên và danh sơn Kim Hoa.",key_text:"余自齠齔，慕希夷氏之風，覬為葛天氏之民。",use:"Nghiên cứu danh sơn, tiên truyện Hoàng Đại Tiên, lịch sử cung quán.",sources:["https://zh.daoinfo.org/index.php?title=%E9%87%91%E8%8F%AF%E8%B5%A4%E6%9D%BE%E5%B1%B1%E5%BF%97","https://zh.wikisource.org/zh-hant/%E9%87%91%E8%8F%AF%E8%B5%A4%E6%9D%BE%E5%B1%B1%E5%BF%97","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch44 · Grok-4.5 catalog-driven"},{dz:"DZ782",name_han:"大滌洞天記",name_vi:"Đại Địch Động Thiên Ký",bu:"洞神",author:"鄧牧",era:"Tống mạt—Nguyên sơ",topic:"仙传",essence:"Ba quyển ghi động thiên Đại Địch (Hàng Châu): sơn thủy, cung quán, tiên tích và truyền thừa đạo sĩ. Là động thiên ký quan trọng, xếp thứ 24 trong hệ thống 36 động thiên.",key_text:"洞天三十六所，仙官所領，為天帝下府。今大滌玄蓋洞天，其二十有四也。",use:"Địa lý đạo giáo, nghiên cứu động thiên phúc địa và lịch sử Hàng Châu.",sources:["https://zh.wikisource.org/wiki/%E5%A4%A7%E6%BB%8C%E6%B4%9E%E5%A4%A9%E8%A8%98","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf"],textual_certainty:"high",notes:"batch44 · Grok-4.5 catalog-driven"},{dz:"DZ969",name_han:"天壇王屋山聖跡記",name_vi:"Thiên Đàn Vương Ốc Sơn Thánh Tích Ký",bu:"洞神",author:"杜光庭等（輯）",era:"Đường—Nguyên（có tựa/phần của Đỗ Quang Đình）",topic:"仙传",essence:"Tập thánh tích núi Vương Ốc–Thiên Đàn (động thiên số một): truyền thuyết Hoàng Đế–Tây Vương Mẫu, bia ký, thi văn các triều. Tư liệu then chốt về danh sơn và động thiên hệ.",key_text:"謹按《道藏龜山白玉上經》具列所在去處，十大洞天內一王屋山清虛小有之洞。",use:"Nghiên cứu động thiên, lịch sử Vương Ốc Sơn, tiên tích và bia ký.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%A9%E5%A3%87%E7%8E%8B%E5%B1%8B%E5%B1%B1%E8%81%96%E8%B7%A1%E8%A8%98","https://ctext.org/wiki.pl?if=gb&res=439883","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch44 · Grok-4.5 catalog-driven"},{dz:"DZ453",name_han:"南嶽小錄",name_vi:"Nam Nhạc Tiểu Lục",bu:"洞玄",author:"李冲昭",era:"Đường（cuối thế kỷ 9）",topic:"仙传",essence:"Sơn lục ngắn về Hành Sơn (Nam Nhạc): ngũ phong, cung quán, đàn viện, tiên tích bay thăng. Một trong số ít sơn ký Đường còn nguyên vẹn, giá trị địa lý–lịch sử cao.",key_text:"撮而直書，總成一卷，目為《南嶽小錄》。",use:"Địa chí Nam Nhạc, nghiên cứu danh sơn và cung quán đời Đường.",sources:["https://zh.wikisource.org/zh-hans/%E5%8D%97%E5%B6%BD%E5%B0%8F%E9%8C%84","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf"],textual_certainty:"high",notes:"batch44 · Grok-4.5 catalog-driven"},{dz:"DZ190",name_han:"太上玉清謝罪登真寶懺",name_vi:"Thái Thượng Ngọc Thanh Tạ Tội Đăng Chân Bảo Sám",bu:"洞真",author:"佚名",era:"唐宋",topic:"ritual",essence:"Bảo sám thuộc Động Chân bộ, mượn lời Thái Thượng dạy nam nữ quan pháp thân sám hối túc oan vãng nghiệp. Lễ năm mươi vị Ngọc Thanh Thiên Tôn để tiêu tai tạ tội, mong đăng chân, danh ghi kim cách. Là sám nghi cầu chứng đạo chứ không chỉ cầu phước thế gian.",key_text:"若不懺除，夙冤往業，終不得位列玉庭，名標金格。",use:"Sám hối đăng chân; tiêu nghiệp cầu chứng; nghi thức Động Chân",sources:["https://zh.daoinfo.org/wiki/%E5%A4%AA%E4%B8%8A%E7%8E%89%E6%B8%85%E8%AC%9D%E7%BD%AA%E7%99%BB%E7%9C%9F%E5%AF%B6%E6%87%BA","https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%8A%E7%8E%89%E6%B8%85%E8%AC%9D%E7%BD%AA%E7%99%BB%E7%9C%9F%E5%AF%B6%E6%87%BA","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch45 · Grok-4.5 catalog-driven"},{dz:"DZ192",name_han:"太上泰清拔罪昇天寶懺",name_vi:"Thái Thượng Thái Thanh Bạt Tội Thăng Thiên Bảo Sám",bu:"洞真",author:"佚名",era:"唐宋",topic:"ritual",essence:"Bảo sám Động Chân bộ: Nguyên Thủy Thiên Tôn thuyết pháp tại Thủy Thanh thiên, phóng quang phổ chiếu thập phương. Chuyên bạt tội vong hồn, cầu siêu thăng thoát Bắc Phong ngục khảo. Nhấn mạnh oan đối do nghiệp đời trước, nhờ sám lễ mà giải kết thăng thiên.",key_text:"爾時元始天尊於始青天中，座碧玉寶蓮劫仞之臺，與無鞅聖眾。",use:"Siêu độ vong hồn; bạt tội thăng thiên; sám độ u minh",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B3%B0%E6%B8%85%E6%8B%94%E7%BD%AA%E6%98%87%E5%A4%A9%E5%AF%B6%E6%87%BA","https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%8A%E6%B3%B0%E6%B8%85%E6%8B%94%E7%BD%AA%E6%98%87%E5%A4%A9%E5%AF%B6%E6%87%BA","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch45 · Grok-4.5 catalog-driven"},{dz:"DZ195",name_han:"九天應元雷聲普化天尊玉樞寶懺",name_vi:"Cửu Thiên Ứng Nguyên Lôi Thanh Phổ Hóa Thiên Tôn Ngọc Xu Bảo Sám",bu:"洞真",author:"佚名",era:"宋元",topic:"ritual",essence:"Sám văn hướng Cửu Thiên Ứng Nguyên Lôi Thanh Phổ Hóa Thiên Tôn (Lôi Tổ) sám hối cầu xá tội ban phúc. Kết hợp quy mệnh tam bảo, chư thiên tôn và Lôi bộ chư thần. Là sám nghi Lôi pháp phổ biến, thường hành cùng kinh Ngọc Xu.",key_text:"法事如儀。具職臣姓誠惶誠恐稽首頓首再拜奏啟。",use:"Sám Lôi Tổ; tiêu nghiệp cầu an; nghi Lôi pháp",sources:["https://zh.daoinfo.org/index.php?title=%E4%B9%9D%E5%A4%A9%E6%87%89%E5%85%83%E9%9B%B7%E8%81%B2%E6%99%AE%E5%8C%96%E5%A4%A9%E5%B0%8A%E7%8E%89%E6%A8%9E%E5%AF%B6%E6%87%BA","https://zh.wikisource.org/zh-hant/%E4%B9%9D%E5%A4%A9%E6%87%89%E5%85%83%E9%9B%B7%E8%81%B2%E6%99%AE%E5%8C%96%E5%A4%A9%E5%B0%8A%E7%8E%89%E6%A8%9E%E5%AF%B6%E6%87%BA","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch45 · Grok-4.5 catalog-driven"},{dz:"DZ196",name_han:"雷霆玉樞宥罪法懺",name_vi:"Lôi Đình Ngọc Xu Hựu Tội Pháp Sám",bu:"洞真",author:"佚名",era:"宋元",topic:"ritual",essence:"Pháp sám đồng quyển với Ngọc Xu Bảo Sám, nội dung tương cận nhưng văn cú khác. Quy mệnh cúng dường Lôi Thanh Phổ Hóa Thiên Tôn, sám hối tội khiên, cầu Lôi đình xá tội hộ trì. Bổ sung hệ sám nghi thần tiêu Lôi pháp.",key_text:"惟於劫仞，感通端自於一心。",use:"Hựu tội Lôi đình; sám pháp Ngọc Xu; cầu an khang",sources:["https://zh.daoinfo.org/index.php?title=%E9%9B%B7%E9%9C%86%E7%8E%89%E6%A8%9E%E5%AE%A5%E7%BD%AA%E6%B3%95%E6%87%BA","https://zh.wikisource.org/zh-hant/%E9%9B%B7%E9%9C%86%E7%8E%89%E6%A8%9E%E5%AE%A5%E7%BD%AA%E6%B3%95%E6%87%BA","https://www.shidianguji.com/book/DZ0196"],textual_certainty:"high",notes:"batch45 · Grok-4.5 catalog-driven"},{dz:"DZ217",name_han:"太乙火府奏告祈禳儀",name_vi:"Thái Ất Hỏa Phủ Tấu Cáo Kỳ Nhương Nghi",bu:"洞真",author:"佚名",era:"宋元",topic:"ritual",essence:"Khoa nghi Lôi pháp Thái Ất Hỏa Phủ: đốt phù tịnh uế, tấu cáo Tam Thanh, Bắc Đẩu, chư chân, thắp đèn cầu đảo. Dùng cầu phong điều vũ thuận, quốc thái dân an, tiêu tai kỳ nhương. Kết nối pháp Hỏa Phủ với nghi tấu cáo.",key_text:"太虛無體，淨穢皆空。妄覺一生，塵緣競起。既非真境，即是魔宮。是故行持，先當蕩滌。",use:"Tấu cáo Hỏa Phủ; kỳ đảo cầu mưa; Lôi pháp hành trì",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B9%99%E7%81%AB%E5%BA%9C%E5%A5%8F%E5%91%8A%E7%A5%88%E7%A6%B3%E5%84%80","https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B9%99%E7%81%AB%E5%BA%9C%E5%A5%8F%E5%91%8A%E7%A5%88%E7%A6%B3%E5%84%80","https://www.shidianguji.com/book/DZ0217"],textual_certainty:"high",notes:"batch45 · Grok-4.5 catalog-driven"},{dz:"DZ533",name_han:"太上靈寶上元天官消愆滅罪懺",name_vi:"Thái Thượng Linh Bảo Thượng Nguyên Thiên Quan Tiêu Khiên Diệt Tội Sám",bu:"洞玄",author:"佚名",era:"唐宋",topic:"ritual",essence:"Một trong bộ ba sám Tam Quan (Thượng/Trung/Hạ nguyên). Chuyên lễ Thượng Nguyên Nhất Phẩm Thiên Quan, tiêu khiên diệt tội, cầu ban phúc. Là bảo sám Tam quan then chốt trong hệ Linh Bảo uy nghi, bổ sung cho các kinh Tam quan đã có.",key_text:"爾時元始天尊在九土無極世界，廣演妙法。",use:"Sám Thiên Quan; tiêu tội ban phúc; Tam nguyên sám lễ",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E9%9D%88%E5%AF%B6%E4%B8%89%E5%85%83%E4%B8%89%E5%AE%98%E6%B6%88%E6%84%86%E6%BB%85%E7%BD%AA%E6%87%BA","https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%8A%E9%9D%88%E5%AF%B6%E4%B8%AD%E5%85%83%E5%9C%B0%E5%AE%98%E6%B6%88%E6%84%86%E6%BB%85%E7%BD%AA%E6%87%BA","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch45 · Grok-4.5 catalog-driven"},{dz:"DZ539",name_han:"青玄救苦寶懺",name_vi:"Thanh Huyền Cứu Khổ Bảo Sám",bu:"洞玄",author:"佚名",era:"宋元",topic:"ritual",essence:"Bảo sám hướng Thanh Hoa Trường Lạc giới và Đông Cực diệu nghiêm cung, lễ Thái Ất Cứu Khổ Thiên Tôn. Dùng trong trai độ, cầu cứu khổ bạt vong, soi sáng u đồ. Nằm trong hệ cứu khổ siêu độ của Linh Bảo.",key_text:"伏以青華長樂界，本無聲無色之天；東極妙嚴宮，有大慈大悲之父。",use:"Cứu khổ bạt độ; trai độ vong linh; lễ Thái Ất",sources:["https://zh.wikisource.org/zh-hant/%E9%9D%92%E7%8E%84%E6%95%91%E8%8B%A6%E5%AF%B6%E6%87%BA","http://www.ctcwri.idv.tw/INDEXA2/A202/A202X/A20291.html","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch45 · Grok-4.5 catalog-driven"},{dz:"DZ541",name_han:"東嶽大生寶懺",name_vi:"Đông Nhạc Đại Sinh Bảo Sám",bu:"洞玄",author:"佚名",era:"元代",topic:"ritual",essence:"Sám lễ Đông Nhạc Thiên Tề Đại Sinh Nhân Thánh Đế, thần chủ Âm ty, nắm thọ yểu và chưởng quản chư ngục. Cầu xá tội, hộ quốc, bảo dân; gắn tín ngưỡng Thái Sơn với sám nghi đạo giáo.",key_text:"向來朝修禮懺，並已周圓。回謝東嶽天齊大生仁聖帝，岱嶽一切威靈。",use:"Lễ Đông Nhạc; sám tội hộ mệnh; cầu quốc an",sources:["https://zh.daoinfo.org/index.php?title=%E6%9D%B1%E5%B6%BD%E5%A4%A7%E7%94%9F%E5%AF%B6%E6%87%BA","https://ctext.org/wiki.pl?if=gb&chapter=185908","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch45 · Grok-4.5 catalog-driven"},{dz:"DZ543",name_han:"太上慈悲道場消災九幽懺",name_vi:"Thái Thượng Từ Bi Đạo Tràng Tiêu Tai Cửu U Sám",bu:"洞玄",author:"題葛玄纂集；序李含光",era:"唐代（八世紀）",topic:"ritual",essence:"Mười quyển, bốn mươi ba phẩm; tựa Cát Huyền soạn, Lư Hàm Quang làm tự. Tập yếu tam động, nói nhân quả tội báo, lễ thập phương thiên tôn, sám hối tiêu tai, bạt độ cửu u thất tổ. Khác với Thái Thượng Từ Bi Cửu U Bạt Tội Sám (DZ544).",key_text:"《太上慈悲道場消災九幽懺》者，始自太極左仙公葛元，於後漢桓帝時，居天台上虞山隱身修行。",use:"Tiêu tai cửu u; bạt độ tổ tiên; đạo tràng đại sám",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%85%88%E6%82%B2%E9%81%93%E5%A0%B4%E6%B6%88%E7%81%BD%E4%B9%9D%E5%B9%BD%E6%87%BA","https://ctext.org/wiki.pl?if=gb&res=895696","https://www.shidianguji.com/book/DZ0543"],textual_certainty:"high",notes:"batch45 · Grok-4.5 catalog-driven"},{dz:"DZ1450",name_han:"中天紫微星真寶懺",name_vi:"Trung Thiên Tử Vi Tinh Chân Bảo Sám",bu:"续道藏",author:"佚名",era:"明代",topic:"ritual",essence:"Thu vào Vạn Lịch Tục Đạo Tạng. Triều lễ Bắc Cực Tử Vi Đại Đế, Thái Dương, Thái Âm, ngũ đẩu và nhị thập bát tú. Cầu tinh quân giáng phúc xá tội, đãng trừ tam nghiệp, thanh tịnh lục căn. Bổ sung mảng bảo sám Tử Vi.",key_text:"伏以乾坤大德，廣覆載於羣生；日月光明，普照臨於萬彙。",use:"Sám Tử Vi; lễ tinh đẩu; cầu phúc xá tội",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%AD%E5%A4%A9%E7%B4%AB%E5%BE%AE%E6%98%9F%E7%9C%9F%E5%AF%B6%E6%87%BA","https://ctext.org/wiki.pl?if=gb&chapter=462465","https://www.shidianguji.com/book/DZ1450"],textual_certainty:"high",notes:"batch45 · Grok-4.5 catalog-driven"},{dz:"DZ451",name_han:"雲阜山申仙翁傳",name_vi:"Vân Phụ Sơn Thân Tiên Ông Truyện",bu:"洞玄",author:"佚名",era:"宋元（記唐申泰芝）",topic:"仙传",essence:"Phổ lục Động Huyền: truyện Thân Thái Chi (Thân Tiên Ông), đạo sĩ đời Đường, thụ Kim đan hỏa long đại thành pháp. Ghi thần dị, linh nghiệm và chứng nghiệm sự thực, thuộc hệ tiên truyện danh sơn/tổ sư địa phương.",key_text:"仙翁申姓，名泰芝，字廣祥。家世洛陽人，譜係出于周時申伯之裔。",use:"Nghiên cứu tiên truyện; tín ngưỡng Thân Tiên Ông; sử đạo sĩ Đường",sources:["https://zh.daoinfo.org/index.php?title=%E9%9B%B2%E9%98%9C%E5%B1%B1%E7%94%B3%E4%BB%99%E7%BF%81%E5%82%B3","https://zh.wikisource.org/wiki/%E9%9B%B2%E9%98%9C%E5%B1%B1%E7%94%B3%E4%BB%99%E7%BF%81%E5%82%B3","https://www.shidianguji.com/zh/book/DZ0451"],textual_certainty:"high",notes:"batch45 · Grok-4.5 catalog-driven"},{dz:"DZ595",name_han:"江淮異人錄",name_vi:"Giang Hoài Dị Nhân Lục",bu:"洞玄",author:"吳淑",era:"北宋",topic:"仙传",essence:"Ngô Thục biên soạn, ghi khoảng hai mươi lăm dị nhân Giang Hoài thời Đường mạt–Nam Đường–Tống sơ: đạo lưu, hiệp khách, thuật sĩ. Lối bút ký thần dị có căn sử; bổ sung mảng tiên truyện địa phương ngoài các tập tiên giám lớn.",key_text:"是編所紀，多道流俠客術士之事，凡唐代二人，南唐二十三人。",use:"Tiên truyện dị nhân; sử đạo thuật Giang Hoài; tư liệu phương sĩ",sources:["http://www.ctcwri.idv.tw/CTCW-CMTS/CMT02%E6%B4%9E%E7%8E%84%E9%83%A8/CMT0210%E8%A8%98%E5%82%B3%E9%A1%9E/CMT0210ALL/CH021006%E6%B1%9F%E6%B7%AE%E7%95%B0%E4%BA%BA%E9%8C%84.htm","https://zh.wikisource.org/zh-hans/%E6%B1%9F%E6%B7%AE%E7%95%B0%E4%BA%BA%E9%8C%84","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch45 · Grok-4.5 catalog-driven"},{dz:"DZ903",name_han:"純陽呂真人藥石製",name_vi:"Thuần Dương Lã Chân Nhân Dược Thạch Chế",bu:"洞神",author:"佚名（託呂洞賓）",era:"唐宋",topic:"道医",essence:"Thảo mộc dược điển ngoại đan: hơn sáu mươi loại long nha thảo dược, mỗi vị kèm ca quyết. Nói phục chế ngũ kim bát thạch, điểm hóa đồng thủy ngân. Giao thoa đạo y – bào chế – ngoại đan.",key_text:"天寶龍芽赤芹草，中第一假成真遇有緣。伏製五金並八石，會點頑銅軟似綿。",use:"Bào chế long nha; phục kim thạch; ngoại đan dược liệu",sources:["https://zh.daoinfo.org/index.php?title=%E7%B4%94%E9%99%BD%E5%91%82%E7%9C%9F%E4%BA%BA%E8%97%A5%E7%9F%B3%E8%A3%BD","https://zh.wikisource.org/zh-hant/%E7%B4%94%E9%99%BD%E5%91%82%E7%9C%9F%E4%BA%BA%E8%97%A5%E7%9F%B3%E8%A3%BD","https://ctext.org/wiki.pl?if=gb&chapter=316211"],textual_certainty:"high",notes:"batch45 · Grok-4.5 catalog-driven"},{dz:"DZ946",name_han:"太極真人雜丹藥方",name_vi:"Thái Cực Chân Nhân Tạp Đan Dược Phương",bu:"洞神",author:"佚名",era:"唐代（約）",topic:"外丹",essence:"Hai mươi bốn phương đan hoàng bạch, liệt dược lượng và phép luyện. Có hợp lục nhất nê pháp, dụng khu pháp, luyện lô. Thuộc chúng thuật Động Thần, tư liệu thực tiễn ngoại đan – dược thạch.",key_text:"大凡男子所傳受，志心堅意，護靜身心，用藥州土，固濟如法，依鑪匱用火斤兩燒鍛。萬不失一。",use:"Ngoại đan phương; hoàng bạch thuật; dược thạch luyện chế",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E6%A5%B5%E7%9C%9F%E4%BA%BA%E9%9B%9C%E4%B8%B9%E8%97%A5%E6%96%B9","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E6%A5%B5%E7%9C%9F%E4%BA%BA%E9%9B%9C%E4%B8%B9%E8%97%A5%E6%96%B9","https://www.shidianguji.com/book/DZ0946"],textual_certainty:"high",notes:"batch45 · Grok-4.5 catalog-driven"},{dz:"DZ1444",name_han:"元始天尊說藥王救八十一難真經",name_vi:"Nguyên Thủy Thiên Tôn Thuyết Dược Vương Cứu Bát Thập Nhất Nạn Chân Kinh",bu:"续道藏",author:"佚名",era:"明代",topic:"道医",essence:"Tục Đạo Tạng: Nguyên Thủy đáp Cứu Khổ chân nhân, nêu duyên khởi bệnh nạn và tám mươi mốt nạn do Linh Ứng Dược Vương (Biển Thước) cứu. Hướng đạo y – hộ mệnh, tụng kinh cầu giải bệnh nạn.",key_text:"夫上古之人，遵崇大道，修省本源。不殺不害，不嫉不妬，不欲不貪，不淫不盜。",use:"Cầu Dược Vương; tụng giải bệnh nạn; đạo y tín ngưỡng",sources:["https://zh.wikisource.org/zh-hant/%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E8%97%A5%E7%8E%8B%E6%95%91%E5%85%AB%E5%8D%81%E4%B8%80%E9%9B%A3%E7%9C%9F%E7%B6%93","https://www.shidianguji.com/book/DZ1444","https://ctext.org/wiki.pl?if=en&chapter=757263&remap=gb"],textual_certainty:"high",notes:"batch45 · Grok-4.5 catalog-driven"},{dz:"DZ1445",name_han:"碧霞元君護國庇民普濟保生妙經",name_vi:"Bích Hà Nguyên Quân Hộ Quốc Tị Dân Phổ Tế Bảo Sinh Diệu Kinh",bu:"续道藏",author:"佚名",era:"明代",topic:"仙传",essence:"Kinh Tục Đạo Tạng về Bích Hà Nguyên Quân (Thái Sơn thiên tiên ngọc nữ). Nguyên Thủy thuyết: nguyên quân chủ sinh hóa, hộ quốc tị dân, thưởng thiện phạt ác. Cốt lõi tín ngưỡng nữ thần địa phương Thái Sơn trong chính tạng.",key_text:"大慈天仙聖，劫初證上真。化身為救苦，發願度天人。",use:"Lễ Bích Hà Nguyên Quân; hộ sinh bảo mệnh; tín ngưỡng Thái Sơn",sources:["https://zh.daoinfo.org/index.php?title=%E7%A2%A7%E9%9C%9E%E5%85%83%E5%90%9B%E8%AD%B7%E5%9C%8B%E5%BA%87%E6%B0%91%E6%99%AE%E6%BF%9F%E4%BF%9D%E7%94%9F%E7%9C%9F%E7%B6%93","https://zh.wikisource.org/zh-hant/%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AC%E7%A2%A7%E9%9C%9E%E5%85%83%E5%90%9B%E8%AD%B7%E5%9C%8B%E5%BA%87%E6%B0%91%E6%99%AE%E6%BF%9F%E4%BF%9D%E7%94%9F%E5%A6%99%E7%B6%93","https://ctext.org/wiki.pl?if=gb&res=640640"],textual_certainty:"high",notes:"batch45 · Grok-4.5 catalog-driven"},{dz:"DZ221",name_han:"无上三天玉堂正宗高奔内景玉书",name_vi:"Vô Thượng Tam Thiên Ngọc Đường Chính Tông Cao Bôn Nội Cảnh Ngọc Thư",bu:"洞真",author:"路时中（编）",era:"北宋末—南宋初",topic:"cultivation",essence:"Kinh pháp phái Thiên Tâm – Ngọc Đường, do Lộ Thời Trung biên soạn, chuyên bàn tồn tư Tam Quang (nhật tinh, nguyệt hoa, Cang khí) cùng thuật phi bôn nhật nguyệt, phi đẩu bôn thần. Nhấn mạnh tam quang không cầu bên ngoài mà là chân khí tự có trong thân; hành giả tồn tư nội cảnh, nuốt phù tụng chú để hồi dương hoán cốt, bạch nhật đăng thần. Đây là cầu nối quan trọng giữa thuật tồn tư Thượng Thanh cổ và pháp thuật Thiên Tâm đời Tống.",key_text:"回陽換骨，白日登晨",use:"Nội luyện tồn tư nhật nguyệt Bắc Đẩu; nghiên cứu Thiên Tâm – Ngọc Đường pháp",sources:["https://zh.daoinfo.org/index.php?title=%E7%84%A1%E4%B8%8A%E4%B8%89%E5%A4%A9%E7%8E%89%E5%A0%82%E6%AD%A3%E5%AE%97%E9%AB%98%E5%A5%94%E5%85%A7%E6%99%AF%E7%8E%89%E6%9B%B8&variant=zh-hans","https://www.jstor.org/stable/26768560","https://simple.taolibrary.com/category95.aspx"],textual_certainty:"high",notes:"batch46 · Grok-4.5 catalog-driven"},{dz:"DZ1199",name_han:"太上说青玄雷令法行因地妙经",name_vi:"Thái Thượng Thuyết Thanh Huyền Lôi Lệnh Pháp Hành Nhân Địa Diệu Kinh",bu:"正一",author:"撰人不详",era:"宋—元",topic:"ritual",essence:"Kinh thuộc Chính nhất bộ, thuật công đức và thần uy Ôn Nguyên soái (Thanh Huyền Địa Lôi). Xưng Ôn soái là tinh Bính Đinh, Hỏa đế chi thần, đời Hán hóa thân làm Dực Linh tướng quân, mặt xanh tóc đỏ, nắm phong lôi, trợ pháp cứu dân. Tàng mật truyền «hiệu lệnh linh phù ngũ nhạc tổng ấn» gọi là «Thanh Huyền địa lôi»; tụng kinh tiêu tai trừ bệnh, an dân bảo cảnh.",key_text:"掌握風雷，助法救民",use:"Tụng trì phụng Ôn Nguyên soái; nghiên cứu địa kỳ / lôi pháp Ôn bộ",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E8%AA%AA%E9%9D%92%E7%8E%84%E9%9B%B7%E4%BB%A4%E6%B3%95%E8%A1%8C%E5%9B%A0%E5%9C%B0%E5%A6%99%E7%B6%93&variant=zh-hans","https://en.daoinfo.org/wiki/On_the_Origin_of_the_Religious_Practice_of_the_Green-Black_Thunder_Commander,_a_Scripture_Spoken_by_the_Most_High","https://simple.taolibrary.com/category95.aspx"],textual_certainty:"partial",notes:"batch46 · Grok-4.5 catalog-driven"},{dz:"DZ1432",name_han:"太上中道妙法莲华经",name_vi:"Thái Thượng Trung Đạo Diệu Pháp Liên Hoa Kinh",bu:"续道藏",author:"撰人不详",era:"南北朝末—隋唐（约）",topic:"classic",essence:"Kinh đầu Vạn lịch Tục Đạo tạng, mười quyển, phỏng Pháp Hoa Phật giáo nhưng lấy Nguyên Thủy Thiên Tôn thuyết pháp, độ thoát thập cực ngũ vô gian tội. Lấy trung đạo, liên hoa, giải thoát, báo ứng, hóa quỷ nhân đạo làm trục; kết hợp giới thiện, tụng trì, cứu khổ, tiêu tai. Là kinh điển đại thừa hóa đạo giáo quan trọng trong Tục tạng.",key_text:"爾時，元始天尊昔於大羅天上廣化天宮，會諸天仙眾，說十極解脫五無間罪。",use:"Tụng trì độ thoát; nghiên cứu ảnh hưởng Phật–Đạo và Tục Đạo tạng",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E4%B8%AD%E9%81%93%E7%8E%85%E6%B3%95%E8%93%AE%E8%8F%AF%E7%B6%93","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E4%B8%AD%E9%81%93%E5%A6%99%E6%B3%95%E8%93%AE%E8%8F%AF%E7%B6%93&variant=zh-hans","https://www.shidianguji.com/book/DZ1432"],textual_certainty:"high",notes:"batch46 · Grok-4.5 catalog-driven"},{dz:"DZ1433",name_han:"太上元始天尊说宝月光皇后圣母孔雀明王经",name_vi:"Thái Thượng Nguyên Thủy Thiên Tôn Thuyết Bảo Nguyệt Quang Hoàng Hậu Thánh Mẫu Khổng Tước Minh Vương Kinh",bu:"续道藏",author:"撰人不详",era:"元—明",topic:"mantra",essence:"Kinh Tục tạng phỏng Mật giáo Khổng Tước Minh Vương, xưng Bảo Nguyệt Quang Hoàng Hậu Thánh Mẫu đồng thể với Phật Khổng Tước Như Lai. Nội dung gồm sấm chú, thỉnh ngũ phương thiên vương, giải oan tiêu tai, hộ mệnh diên thọ; đề cao Chính nhất đạo sĩ tụng kinh lễ sám. Phản ánh hỗn dung Phật–Đạo và tín ngưỡng Thánh Mẫu / Minh Vương đời Minh.",key_text:"道言：爾時，元始天尊在大羅天上，清微天宮，浮黎國土，玉羅寶臺之上，放九色祥光。",use:"Tụng trì tiêu tai giải oan; nghi lễ thỉnh Khổng Tước Minh Vương / Thánh Mẫu",sources:["https://ctext.org/wiki.pl?if=gb&chapter=158251","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E5%85%83%E5%A7%8B%E5%A4%A9%E5%B0%8A%E8%AA%AA%E5%AF%B6%E6%9C%88%E5%85%89%E7%9A%87%E5%90%8E%E8%81%96%E6%AF%8D%E5%A4%A9%E5%B0%8A%E5%AD%94%E9%9B%80%E6%98%8E%E7%8E%8B%E7%B6%93&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E8%90%AC%E6%9B%86%E7%BA%8C%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch46 · Grok-4.5 catalog-driven"},{dz:"DZ1434",name_han:"圣母孔雀明王尊经启白仪",name_vi:"Thánh Mẫu Khổng Tước Minh Vương Tôn Kinh Khải Bạch Nghi",bu:"续道藏",author:"撰人不详",era:"明",topic:"ritual",essence:"Nghi thức khải bạch đi kèm Khổng Tước Minh Vương kinh trong Vạn lịch Tục Đạo tạng. Quy định trình tự mở kinh, thỉnh Thánh Mẫu / Minh Vương, xưng tán, hồi hướng trước khi tụng chính kinh. Là khoa nghi thực dụng cho đạo đàn Chính nhất đời Minh khi hành trì kinh Khổng Tước.",key_text:"null",use:"Khoa nghi khải thỉnh trước khi tụng Khổng Tước Minh Vương kinh",sources:["https://zh.wikisource.org/zh-hans/%E8%90%AC%E6%9B%86%E7%BA%8C%E9%81%93%E8%97%8F","https://simple.taolibrary.com/category95.aspx","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT08%E7%BA%8C%E9%81%93%E8%97%8F/CH08-C.htm"],textual_certainty:"high",notes:"batch46 · Grok-4.5 catalog-driven"},{dz:"DZ1443",name_han:"太上元阳上帝无始天尊说火车王灵官真经",name_vi:"Thái Thượng Nguyên Dương Thượng Đế Vô Thủy Thiên Tôn Thuyết Hỏa Xa Vương Linh Quan Chân Kinh",bu:"续道藏",author:"撰人不详",era:"明",topic:"ritual",essence:"Kinh Tục tạng chuyên phụng Vương Linh Quan (Hỏa Xa Vương Linh Quan), hộ pháp của Tát Thủ Kiên / Tây Hà phái. Thuật bản hạnh, uy lực trừng tà, hộ giáo hộ đàn; gắn với hệ thống lôi pháp, giám đàn, trục quỷ đời Minh. Bổ sung cho tín ngưỡng Vương linh quan trong chính đàn và dân gian.",key_text:"null",use:"Tụng trì phụng Vương Linh Quan; hộ đàn trấn tà",sources:["https://zh.wikisource.org/zh-hans/%E8%90%AC%E6%9B%86%E7%BA%8C%E9%81%93%E8%97%8F","https://simple.taolibrary.com/category95.aspx","https://baike.baidu.com/item/%E4%B8%87%E5%8E%86%E7%BB%AD%E9%81%93%E8%97%8F/4719666"],textual_certainty:"high",notes:"batch46 · Grok-4.5 catalog-driven"},{dz:"DZ1446",name_han:"太上大圣朗灵上将护国妙经",name_vi:"Thái Thượng Đại Thánh Lãng Linh Thượng Tướng Hộ Quốc Diệu Kinh",bu:"续道藏",author:"撰人不详",era:"明",topic:"ritual",essence:"Kinh hộ quốc trong Tục tạng, phụng Đại Thánh Lãng Linh Thượng Tướng. Nội dung cầu bảo quốc an dân, tiêu tai tập phúc, phản ánh xu hướng đạo kinh «cảm ứng – hộ quốc – linh nghiệm» đời Minh, gắn với thần tướng võ dũng trong hệ thống thần điện.",key_text:"null",use:"Tụng trì cầu hộ quốc tiêu tai",sources:["https://zh.wikisource.org/zh-hans/%E8%90%AC%E6%9B%86%E7%BA%8C%E9%81%93%E8%97%8F","https://simple.taolibrary.com/category95.aspx","https://baike.baidu.com/item/%E4%B8%87%E5%8E%86%E7%BB%AD%E9%81%93%E8%97%8F/4719666"],textual_certainty:"high",notes:"batch46 · Grok-4.5 catalog-driven"},{dz:"DZ1448",name_han:"太上洞玄灵宝五显灵观华光本行妙经",name_vi:"Thái Thượng Động Huyền Linh Bảo Ngũ Hiển Linh Quan Hoa Quang Bản Hạnh Diệu Kinh",bu:"续道藏",author:"撰人不详",era:"宋—明",topic:"仙传",essence:"Kinh bản hạnh Ngũ Hiển Linh Quan / Hoa Quang Đại đế trong Tục tạng (cũng liên hệ Ngũ Thông – Hoa Quang tín ngưỡng Giang Nam). Thuật lai lịch, công đức hiển hóa, bảo dân trừ ôn; phản ánh sự chính thống hóa thần dân gian vào Đạo tạng đời Minh. Khác với các bài chú / thánh hiệu Ngũ Hiển rời rạc, đây là kinh bản hạnh có hệ thống.",key_text:"null",use:"Tụng trì phụng Ngũ Hiển / Hoa Quang; nghiên cứu thần dân gian nhập tạng",sources:["https://zh.wikisource.org/zh-hans/%E8%90%AC%E6%9B%86%E7%BA%8C%E9%81%93%E8%97%8F","https://simple.taolibrary.com/category95.aspx","https://baike.baidu.com/item/%E4%B8%87%E5%8E%86%E7%BB%AD%E9%81%93%E8%97%8F/4719666"],textual_certainty:"high",notes:"batch46 · Grok-4.5 catalog-driven"},{dz:"DZ1449",name_han:"太上说通真高皇解冤经",name_vi:"Thái Thượng Thuyết Thông Chân Cao Hoàng Giải Oan Kinh",bu:"续道藏",author:"撰人不详",era:"明",topic:"ritual",essence:"Kinh giải oan thuộc Tục tạng, lấy Thông Chân Cao Hoàng làm chủ tôn cứu độ. Dùng để giải túc oan, triệt kết, tiêu tai độ vong; nằm trong nhóm kinh sám «giải oan – bạt độ – cảm ứng» rất thịnh ở đạo giáo dân gian Minh–Thanh.",key_text:"null",use:"Tụng trì giải oan triệt kết; khoa nghi độ vong",sources:["https://zh.wikisource.org/zh-hans/%E8%90%AC%E6%9B%86%E7%BA%8C%E9%81%93%E8%97%8F","https://simple.taolibrary.com/category95.aspx","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT08%E7%BA%8C%E9%81%93%E8%97%8F/CH08-C.htm"],textual_certainty:"high",notes:"batch46 · Grok-4.5 catalog-driven"},{dz:"DZ1451",name_han:"紫皇炼度玄科",name_vi:"Tử Hoàng Luyện Độ Huyền Khoa",bu:"续道藏",author:"撰人不详",era:"元—明",topic:"ritual",essence:"Khoa nghi luyện độ lấy Tử Hoàng làm chủ tôn trong Tục tạng. Quy định trình tự lập đàn, chiêu hồn, luyện độ siêu thăng; kế thừa truyền thống Linh Bảo hoàng lục / tế luyện nhưng đóng gói thành huyền khoa gọn, tiện dùng cho đạo sĩ đời Minh.",key_text:"null",use:"Khoa nghi luyện độ siêu vong; tham chiếu nghi thức Tử Hoàng đàn",sources:["https://zh.wikisource.org/zh-hans/%E8%90%AC%E6%9B%86%E7%BA%8C%E9%81%93%E8%97%8F","https://simple.taolibrary.com/category95.aspx","https://baike.baidu.com/item/%E4%B8%87%E5%8E%86%E7%BB%AD%E9%81%93%E8%97%8F/4719666"],textual_certainty:"high",notes:"batch46 · Grok-4.5 catalog-driven"},{dz:"DZ1452",name_han:"先天斗母奏告玄科",name_vi:"Tiên Thiên Đẩu Mẫu Tấu Cáo Huyền Khoa",bu:"续道藏",author:"撰人不详",era:"元—明",topic:"ritual",essence:"Huyền khoa tấu cáo Tiên Thiên Đẩu Mẫu (Đấu Mẫu) trong Tục tạng. Dùng trong nghi thỉnh Đẩu Mẫu, tấu sớ cầu mệnh, tiêu tai diên thọ; gắn với tín ngưỡng Bắc Đẩu – Đẩu Mẫu và các khoa nghi tấu cáo đời Tống–Minh. Bổ sung cho hệ Đẩu pháp / lôi pháp lấy Đẩu Mẫu làm tổ.",key_text:"null",use:"Tấu cáo Đẩu Mẫu; nghi thỉnh Bắc Đẩu / Đẩu mệnh",sources:["https://zh.wikisource.org/zh-hans/%E8%90%AC%E6%9B%86%E7%BA%8C%E9%81%93%E8%97%8F","https://simple.taolibrary.com/category95.aspx","https://baike.baidu.com/item/%E4%B8%87%E5%8E%86%E7%BB%AD%E9%81%93%E8%97%8F/4719666"],textual_certainty:"high",notes:"batch46 · Grok-4.5 catalog-driven"},{dz:"DZ1456",name_han:"北斗九皇隐讳经",name_vi:"Bắc Đẩu Cửu Hoàng Ẩn Húy Kinh",bu:"续道藏",author:"撰人不详",era:"唐宋—明",topic:"mantra",essence:"Kinh ẩn húy Cửu Hoàng Bắc Đẩu trong Tục tạng, truyền danh hiệu bí mật, thần chú và cách trì niệm các sao Bắc Đẩu. Phục vụ tồn tư, tụng húy, cầu mệnh diên thọ; là mắt xích quan trọng của Đẩu pháp, khác các kinh Bắc Đẩu bản mệnh đã được liệt kê ở lớp trước.",key_text:"null",use:"Trì ẩn húy Cửu Hoàng; Đẩu pháp cầu mệnh",sources:["https://zh.wikisource.org/zh-hans/%E8%90%AC%E6%9B%86%E7%BA%8C%E9%81%93%E8%97%8F","https://simple.taolibrary.com/category95.aspx","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT08%E7%BA%8C%E9%81%93%E8%97%8F/CH08-C.htm"],textual_certainty:"high",notes:"batch46 · Grok-4.5 catalog-driven"},{dz:"DZ1248",name_han:"三十代天师虚靖先生语录",name_vi:"Tam Thập Đại Thiên Sư Hư Tĩnh Tiên Sinh Ngữ Lục",bu:"正一",author:"张继先（虚靖）语；门人辑",era:"北宋末—南宋",topic:"philosophy",essence:"Ngữ lục Trương Kế Tiên (Hư Tĩnh Thiên sư đời thứ 30 Long Hổ sơn). Gồm lời dạy về đạo pháp, tâm tính, chính nhất pháp lục và thái độ hành pháp; phản ánh tư tưởng Chính nhất khi giao thoa với lôi pháp Thần Tiêu đời Tống. Là nguồn chính nghiên cứu Hư Tĩnh và thiên sư đạo trung cổ.",key_text:"null",use:"Nghiên cứu tư tưởng Trương Kế Tiên / Chính nhất trung cổ",sources:["https://simple.taolibrary.com/category95.aspx","http://www.chinaknowledge.de/Literature/Daoists/daozang.html","https://zh.daoinfo.org/index.php?title=%E9%81%93%E6%B3%95%E6%9C%83%E5%85%83&variant=zh-hans"],textual_certainty:"partial",notes:"batch46 · Grok-4.5 catalog-driven"},{dz:"DZ1204",name_han:"太上三天正法经",name_vi:"Thái Thượng Tam Thiên Chính Pháp Kinh",bu:"正一",author:"撰人不详",era:"六朝—唐宋",topic:"classic",essence:"Kinh Chính nhất thuật chính pháp Tam Thiên (Ngọc Thanh, Thượng Thanh, Thái Thanh / hoặc hệ tam thiên giáo pháp). Liên hệ truyền thừa thiên sư, chính pháp trục tà, lập giáo; cung cấp khung «chính pháp» đối lập với tà đạo, phù hợp nghiên cứu lịch sử Chính nhất và quan niệm chính–tà trong đạo giáo.",key_text:"null",use:"Nghiên cứu chính pháp Thiên sư / khung chính–tà",sources:["https://simple.taolibrary.com/category95.aspx","http://www.chinaknowledge.de/Literature/Daoists/daozang.html","https://upload.wikimedia.org/wikipedia/commons/f/f1/SSID-10489785_%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F%E7%9B%AE%E9%8C%84%E7%B4%A2%E5%BC%95.pdf"],textual_certainty:"partial",notes:"batch46 · Grok-4.5 catalog-driven"},{dz:"DZ1202",name_han:"道要灵祇神鬼品经",name_vi:"Đạo Yếu Linh Kỳ Thần Quỷ Phẩm Kinh",bu:"正一",author:"撰人不详",era:"六朝—唐宋",topic:"ritual",essence:"Kinh phẩm loại hệ thống hóa linh kỳ, thần quỷ trong chính pháp. Liệt kê danh phẩm thần quỷ, chức năng, cách nhận diện và đối trị; mang tính «loại thư – pháp thuật» phục vụ hành pháp, triệu khiển, trấn tà. Rất hữu ích cho nghiên cứu thần phổ và pháp thuật Chính nhất.",key_text:"null",use:"Tra cứu phẩm loại thần quỷ; hành pháp trấn tà",sources:["https://simple.taolibrary.com/category95.aspx","http://www.chinaknowledge.de/Literature/Daoists/daozang.html","https://upload.wikimedia.org/wikipedia/commons/f/f1/SSID-10489785_%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F%E7%9B%AE%E9%8C%84%E7%B4%A2%E5%BC%95.pdf"],textual_certainty:"partial",notes:"batch46 · Grok-4.5 catalog-driven"},{dz:"DZ247",name_han:"会真集",name_vi:"Hội Chân Tập",bu:"洞真",author:"王吉昌",era:"金—元",topic:"cultivation",essence:"Tác phẩm nội đan / hội chân của Vương Cát Xương, năm quyển, thuộc Động chân bộ phương pháp loại. Bàn hợp nhất tinh khí thần, hội chân hoàn nguyên, kết hợp lý luận và khẩu quyết tu luyện; tiêu biểu cho dòng đan đạo phương Bắc thời Kim–Nguyên, khác các ngữ lục Toàn chân đã liệt kê trước.",key_text:"null",use:"Nội đan hội chân; nghiên cứu đan đạo Kim–Nguyên",sources:["https://simple.taolibrary.com/category95.aspx","http://www.chinaknowledge.de/Literature/Daoists/daozang.html","https://www.jstor.org/stable/26768560"],textual_certainty:"partial",notes:"batch46 · Grok-4.5 catalog-driven"},{dz:"DZ1471",name_han:"儒门崇理折衷堪舆完孝录",name_vi:"Nho Môn Sùng Lý Chiết Trung Kham Dư Hoàn Hiếu Lục",bu:"续道藏",author:"佚名",era:"明",topic:"方术",essence:"Sách kham dư (phong thủy) mang khẩu vị Nho giáo, “sùng lý chiết trung”, gắn chọn đất mộ với hiếu đạo “hoàn hiếu”. Tám quyển, tiêu biểu cho sự hòa trộn Nho–Đạo trong thuật số dân gian Minh. Dùng chọn huyệt, an táng, bàn lý khí hình thế.",key_text:"null",use:"Chọn đất mộ, phong thủy hiếu đạo, tham khảo thuật kham dư",sources:["https://zh.wikisource.org/zh-hans/%E8%90%AC%E6%9B%86%E7%BA%8C%E9%81%93%E8%97%8F","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT08%E7%BA%8C%E9%81%93%E8%97%8F/CH08-C.htm"],textual_certainty:"high",notes:"batch47b · Grok-4.5 (1 new after DZ#-dedup; 续道藏 range已覆盖)"},{dz:"DZ688",name_han:"道德真經直解（邵若愚）",name_vi:"Đạo Đức Chân Kinh Trực Giải (Thiệu Nhược Ngu)",bu:"太玄",author:"邵若愚",era:"南宋",topic:"philosophy|老学",essence:"Bản “trực giải” đời Tống, chú trọng nghĩa thẳng, tránh phô trương huyền đàm. Giải Lão theo hướng thực tiễn tu thân–xử thế, kết hợp khí tượng Tống Nho. Phù hợp người muốn đọc chú giải rõ ràng, gần văn bản.",key_text:"直以經義解之，不事穿鑿。",use:"Đối chiếu với các bản tập chú/tập giải; dùng khi cần chú giải Tống giản minh.",sources:["https://zh.daoinfo.org/wiki/道德真經直解（邵若愚）","https://ctext.org/wiki.pl?if=gb&res=961750","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://baike.baidu.com/item/道德经/327138"],textual_certainty:"high",notes:"batch48 · Grok-4.5 focused 太玄老学注疏"},{dz:"DZ692",name_han:"道德真經新註（李約）",name_vi:"Đạo Đức Chân Kinh Tân Chú (Lý Ước)",bu:"太玄",author:"李約",era:"唐",topic:"philosophy|老学",essence:"Lý Ước chú “mới” theo hướng thanh tâm dưỡng khí, an gia bảo quốc. Nổi tiếng tranh luận cú đọc “人法地地，法天天，法道道，法自然”, phản đối cách đọc “năm đại”. Nhấn mạnh vô tư như trời–đất–đạo.",key_text:"人法地地，法天天，法道道，法自然。",use:"Nghiên cứu dị giải cú pháp chương 25 và Lão học trị thế đời Đường.",sources:["https://zh.wikisource.org/wiki/道德真經新註","https://zh.daoinfo.org/wiki/道德真經新註（李約）","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/wiki/道德真經新注序"],textual_certainty:"high",notes:"batch48 · Grok-4.5 focused 太玄老学注疏"},{dz:"DZ694",name_han:"道德真經疏義（趙志堅）",name_vi:"Đạo Đức Chân Kinh Sớ Nghĩa (Triệu Chí Kiên)",bu:"太玄",author:"趙志堅",era:"唐",topic:"philosophy|老学",essence:"Sớ nghĩa Trùng huyền đời Đường (khuyết quyển đầu). Dùng thể lệ “khai đề–thích nghĩa” của Trùng huyền học, lấy “phục quy chân tính” làm tông. Tiếp nối dòng Lão học huyền đàm thời Đường trung–vãn.",key_text:"以重玄家復歸真性說為宗旨。",use:"Đọc khi khảo sát Trùng huyền học và các sớ Lão khuyết quyển trong Đạo tạng.",sources:["https://zh.daoinfo.org/wiki/道德真經疏義（趙志堅）","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://a.daorenjia.com/c15","https://zh.daoinfo.org/wiki/Category:洞神部玉訣類"],textual_certainty:"high",notes:"batch48 · Grok-4.5 focused 太玄老学注疏"},{dz:"DZ695",name_han:"道德真經集解（趙秉文）",name_vi:"Đạo Đức Chân Kinh Tập Giải (Triệu Bỉnh Văn)",bu:"太玄",author:"趙秉文",era:"金",topic:"philosophy|老学",essence:"Tập giải đời Kim, thu thập nhiều nhà (Vương Bật, Huyền Tông, Lục Hy Thanh, Huy Tông, Tô Triệt, Tư Mã Quang, Lã Huệ Khanh, Vương Bàng…). Chủ trương đạo–đức tương tu, không tách cứng thượng/hạ thiên. Giá trị tư liệu cao cho Lão học Tống–Kim.",key_text:"道與德相須而不相離。",use:"Tra cứu dị chú nhiều đời; so sánh các trường phái chú Lão trước Kim.",sources:["https://zh.daoinfo.org/wiki/道德真经集解（赵秉文）","https://ctext.org/wiki.pl?if=gb&res=812932","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.daoist.org/BookSearch(test)/list006.asp?Page=64"],textual_certainty:"high",notes:"batch48 · Grok-4.5 focused 太玄老学注疏"},{dz:"DZ696",name_han:"道德真經全解（時雍）",name_vi:"Đạo Đức Chân Kinh Toàn Giải (Thời Ung)",bu:"太玄",author:"時雍",era:"金",topic:"philosophy|老学",essence:"Bản “toàn giải” đời Kim, giải trọn văn Lão theo hướng Đạo giáo–triết lý. Nhấn mạnh thông suốt toàn kinh, không chỉ trích đoạn. Phản ánh Lão học phương Bắc thời Kim trong Đạo tạng.",key_text:"全解道德，通貫上下。",use:"Đối chiếu với tập giải Triệu Bỉnh Văn; nghiên cứu Lão học Kim.",sources:["https://zh.daoinfo.org/wiki/道德真經全解（時雍）","https://www.ctcwri.idv.tw/CTCW-CMDD.htm","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.daoist.org/BookSearch(test)/list006.asp?Page=64"],textual_certainty:"high",notes:"batch48 · Grok-4.5 focused 太玄老学注疏"},{dz:"DZ698",name_han:"道德真經章句訓頌（張嗣成）",name_vi:"Đạo Đức Chân Kinh Chương Cú Huấn Tụng (Trương Tự Thành)",bu:"太玄",author:"張嗣成（第三十九代天師）",era:"元（至治二年，1322）",topic:"philosophy|老学",essence:"Thiên sư Trương Tự Thành dùng văn vần (tứ–ngũ–thất ngôn) để “huấn tụng” từng chương. Kết hợp nghĩa lý Đạo giáo Chính Nhất với dưỡng tinh–khí–thần, song tu tính mệnh. Hình thức dễ tụng, đặc sắc Lão học Thiên sư đời Nguyên.",key_text:"太上老君，道大而德宏，守約而施博。",use:"Đọc tụng, khảo cứu Lão học Thiên sư phái và diễn nghĩa vần hóa.",sources:["https://zh.daoinfo.org/wiki/道德真經章句訓頌（張嗣成）","https://zh.wikisource.org/wiki/道德真經章句訓頌","https://www.kanripo.org/text/KR5c0085/002","https://ctext.org/wiki.pl?if=gb&res=586834"],textual_certainty:"high",notes:"batch48 · Grok-4.5 focused 太玄老学注疏"},{dz:"DZ705",name_han:"道德真經集解（董思靖）",name_vi:"Đạo Đức Chân Kinh Tập Giải (Đổng Tư Tĩnh)",bu:"太玄",author:"董思靖",era:"南宋（淳祐丙午，1246）",topic:"philosophy|老学",essence:"Đạo sĩ Tuyền Châu Đổng Tư Tĩnh tập giải, kèm âm thích kế thừa–biến đổi Lục Đức Minh. Kết hợp trích chú cổ với lựa chọn âm nghĩa riêng. Là bản tập giải Đạo giáo Nam Tống quan trọng (khác Triệu Bỉnh Văn).",key_text:"經名：道德真經集解。又名：太上老子道德經集解。",use:"Nghiên cứu âm nghĩa–tập chú Nam Tống; so với bản tập giải Kim–Nguyên.",sources:["https://baike.baidu.com/item/道德真经集解/17619563","https://zh.daoinfo.org/wiki/道德真經集解（董思靖）","https://ctext.org/library.pl?if=en&res=84385","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch48 · Grok-4.5 focused 太玄老学注疏"},{dz:"DZ710",name_han:"道德真經注疏（原題顧歡）",name_vi:"Đạo Đức Chân Kinh Chú Sớ (nguyên đề Cố Hoan)",bu:"太玄",author:"原題顧歡（實多為唐–宋集注；或與張君相《三十家》相關）",era:"南齊名義 / 唐宋輯成",topic:"philosophy|老学",essence:"Tám quyển chú sớ, đề Cố Hoan nhưng học giới coi là tập chú nhiều đời (Vương Bật, Huyền Tông, Thành Huyền Anh… có thể lẫn). Bảo tồn mảnh chú cổ thất lạc, giá trị tư liệu hơn là “một tác giả”.",key_text:"舊題吳郡徵士顧歡述。",use:"Khai thác dị chú cổ; đối chiếu với các bản đơn chú chính danh.",sources:["https://zh.daoinfo.org/wiki/道德真經注疏（原題顧歡）","https://zh.wikisource.org/wiki/道德真經注疏","https://www.shidianguji.com/book/DZ0710","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch48 · Grok-4.5 focused 太玄老学注疏"},{dz:"DZ1209",name_han:"太上正一盟威法籙",name_vi:"Thái Thượng Chính Nhất minh uy pháp lục",bu:"正一",author:"佚名",era:"南北朝",topic:"fu",essence:"Tập hợp khoảng mười bốn bậc pháp lục sơ kỳ Thiên sư đạo, gồm đồng tử lục, xích quan trảm tà lục, nhị thập tứ trị khí lục, hộ thân tương quân lục v.v. Mỗi lục kê danh hiệu công tào, tướng lại, ngọc nữ và lời thệ thụ lục. Đặc biệt có phẩm trảm tà và hộ thân dùng để trừ tinh quái, định tam hồn thất phách.",key_text:"請受三五赤官斬邪支兵，定三魂，安七魄。",use:"Thụ lục, hành pháp trảm tà, hộ thân, trị bệnh dân",sources:["https://www.shidianguji.com/book/DZ1209","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%AD%A3%E4%B8%80%E7%9B%9F%E5%A8%81%E6%B3%95%E7%B1%99&variant=zh-hant","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT07%E6%AD%A3%E4%B9%99%E9%83%A8/CMT07ALL/CH07018%E5%A4%AA%E4%B8%8A%E6%AD%A3%E4%B8%80%E7%9B%9F%E5%A8%81%E6%B3%95%E7%B1%99.htm"],textual_certainty:"high",notes:"batch49 · Grok-4.5 focused 正一符箓法术"},{dz:"DZ1210",name_han:"正一法文十籙召儀",name_vi:"Chính Nhất pháp văn thập lục triệu nghi",bu:"正一",author:"佚名",era:"南北朝",topic:"ritual",essence:"Tàn quyển của hệ Chính Nhất pháp văn, chép nghi thức triệu thỉnh linh quan thuộc mười bậc pháp lục sơ kỳ. Gồm nguyên mệnh xích lục, thanh giáp lục cùng nhiều lục khác và phần lục thập giáp tử thần danh. Dùng để điều khiển lại binh theo lục đã thụ, là nền nghi triệu tướng của Chính Nhất.",key_text:"null",use:"Triệu thỉnh lục trung quan tướng khi hành pháp, thụ lục",sources:["https://www.shidianguji.com/book/DZ1210","https://zh.daoinfo.org/index.php?title=%E6%AD%A3%E4%B8%80%E6%B3%95%E6%96%87%E5%8D%81%E7%B1%99%E5%8F%AC%E5%84%80&variant=zh-hant","https://brill.com/display/book/9781684170869/BP000012.pdf"],textual_certainty:"high",notes:"batch49 · Grok-4.5 focused 正一符箓法术"},{dz:"DZ1211",name_han:"正一法文傳都功版儀",name_vi:"Chính Nhất pháp văn truyền đô công bản nghi",bu:"正一",author:"佚名",era:"南北朝",topic:"ritual",essence:"Nghi thức minh thệ truyền thụ đô công bản — chức vị cao nhất trong hệ nhị thập tứ trị của Thiên sư đạo. Đô công thống lãnh các trị, được quyền truyền trị cho người; sách nhấn mạnh không thụ bản thì không được truyền trị. Đây là văn kiện then chốt về phẩm trật và pháp quyền truyền thừa Chính Nhất.",key_text:"正一道士，奉道有功，應補治職。",use:"Truyền thụ đô công, thăng phẩm trị chức, xác lập quyền truyền lục",sources:["https://www.shidianguji.com/book/DZ1211","https://zh.daoinfo.org/index.php?title=%E6%AD%A3%E4%B8%80%E6%B3%95%E6%96%87%E5%82%B3%E9%83%BD%E5%8A%9F%E7%89%88%E5%84%80&variant=zh-hant","https://brill.com/display/book/9781684170869/BP000012.pdf"],textual_certainty:"high",notes:"batch49 · Grok-4.5 focused 正一符箓法术"},{dz:"DZ1212",name_han:"醮三洞真文五法正一盟威籙立成儀（張萬福）",name_vi:"Tiếu tam động chân văn ngũ pháp Chính Nhất minh uy lục lập thành nghi",bu:"正一",author:"張萬福",era:"唐（約八世紀）",topic:"ritual",essence:"Khoa nghi tế tiếu do Trương Vạn Phúc biên soạn, dùng để cúng tế các bậc lục Thượng Thanh, Linh Bảo chân văn, bát cảnh ngũ pháp và Chính Nhất minh uy lục. Có các tiết thiết đàn, giải uế, phát lô, xuất linh quan, tụng chúc. Là mẫu hình lập thành nghi cho việc phụng lục liên tông phái thời Đường.",key_text:"凡醮者所以薦誠於天地祈福於真靈",use:"Thiết tiếu phụng lục, tạ thần sau thụ lục, cầu phúc trừ tai",sources:["https://www.shidianguji.com/book/DZ1212","https://zh.daoinfo.org/index.php?title=%E9%86%AE%E4%B8%89%E6%B4%9E%E7%9C%9F%E6%96%87%E4%BA%94%E6%B3%95%E6%AD%A3%E4%B8%80%E7%9B%9F%E5%A8%81%E7%B1%99%E7%AB%8B%E6%88%90%E5%84%80&variant=zh-hant","https://ctext.org/wiki.pl?if=gb&res=399488"],textual_certainty:"high",notes:"batch49 · Grok-4.5 focused 正一符箓法术"},{dz:"DZ1213",name_han:"太上玄天真武無上將軍籙",name_vi:"Thái Thượng Huyền Thiên Chân Vũ vô thượng tướng quân lục",bu:"正一",author:"佚名（明初正一道）",era:"明初",topic:"fu",essence:"Pháp lục Chính Nhất thời Minh, lấy Huyền Thiên Chân Vũ đại tướng làm chủ, lãnh binh trừ ma hộ mệnh. Gồm thỉnh lục pháp từ, danh tướng, thần chú và nghi bái thụ tại long hổ sơn Thiên sư môn hạ. Phù hợp tín chúng cầu bảo mệnh, diệt ma, tiêu tai.",key_text:"保命護身，延生度厄，辟除魔魅，斷滅不祥。",use:"Thụ lục Chân Vũ, hộ thân trừ ma, cầu thọ",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E7%8E%84%E5%A4%A9%E7%9C%9F%E6%AD%A6%E7%84%A1%E4%B8%8A%E5%B0%87%E8%BB%8D%E7%B1%99&variant=zh-hant","https://ctext.org/wiki.pl?if=gb&chapter=177063","http://www.ctcwri.idv.tw/CTCW-XDJDQJ/CH07022%E5%A4%AA%E4%B8%8A%E7%8E%84%E5%A4%A9%E7%9C%9F%E6%AD%A6%E7%84%A1%E4%B8%8A%E5%B0%87%E8%BB%8D%E7%B1%99.htm"],textual_certainty:"high",notes:"batch49 · Grok-4.5 focused 正一符箓法术"},{dz:"DZ1216",name_han:"太上正一延生保命籙",name_vi:"Thái Thượng Chính Nhất diên sinh bảo mệnh lục",bu:"正一",author:"佚名（明初正一道）",era:"明初",topic:"fu",essence:"Pháp lục diên sinh bảo mệnh của Chính Nhất thời Minh, liên hệ bản mệnh Bắc Đẩu tinh quân và thỉnh lục pháp từ. Dùng để tu thân luyện kỷ, bảo mệnh tiêu tai, cầu thọ; có nghi bái thụ, lập thệ tam quan. Cùng hệ với các lục minh uy sơ kỳ nhưng hình thức đã biến đổi rõ sang thời Minh.",key_text:"拜受太上正一延生保命祕籙一階",use:"Thụ lục cầu thọ, bảo mệnh tiêu tai, hộ trì bản mệnh",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%AD%A3%E4%B8%80%E5%BB%B6%E7%94%9F%E4%BF%9D%E5%91%BD%E7%B1%99&variant=zh-hant","https://ctext.org/wiki.pl?if=gb&chapter=889408","https://www.daoisms.com.cn/2016/13/00/11332/"],textual_certainty:"high",notes:"batch49 · Grok-4.5 focused 正一符箓法术"},{dz:"DZ1242",name_han:"正一法文法籙部儀",name_vi:"Chính Nhất pháp văn pháp lục bộ nghi",bu:"正一",author:"佚名",era:"南北朝",topic:"ritual",essence:"Tàn quyển Chính Nhất pháp văn chép các nghi minh thệ liên quan pháp lục, như hoàng tố tam minh đăng đàn nghi và các nghi đồng loại. Dùng khi đăng đàn thụ lục, kết minh với sư và thiên địa. Cung cấp khung nghi thức bộ pháp lục trong hệ thống thụ giới lục của Thiên sư.",key_text:"null",use:"Đăng đàn thụ lục, kết minh thệ, nghi thức truyền pháp",sources:["https://zh.daoinfo.org/index.php?title=%E6%AD%A3%E4%B8%80%E6%B3%95%E6%96%87%E6%B3%95%E7%B1%99%E9%83%A8%E5%84%80&variant=zh-hant","https://brill.com/display/book/9781684170869/BP000012.pdf","https://ctext.org/wiki.pl?if=gb&chapter=205667"],textual_certainty:"high",notes:"batch49 · Grok-4.5 focused 正一符箓法术"},{dz:"DZ1243",name_han:"正一法文太上外籙儀",name_vi:"Chính Nhất pháp văn Thái Thượng ngoại lục nghi",bu:"正一",author:"佚名",era:"南北朝",topic:"ritual",essence:"Nghi thức truyền thụ các bậc ngoại lục sơ cấp cho đạo sĩ và tín chúng (kể cả phụ nữ, hạ nhân, tứ di trong khung nghi cổ). Chép quy tắc lập trị, bái kính, thụ lục hậu tạ ân chương. Là cửa vào phẩm trật Chính Nhất trước khi tiến lên các lục nội cao hơn.",key_text:"null",use:"Thụ ngoại lục sơ cấp, nhập đạo, tạ ân sau thụ",sources:["https://zh.daoinfo.org/index.php?title=%E6%AD%A3%E4%B8%80%E6%B3%95%E6%96%87%E5%A4%AA%E4%B8%8A%E5%A4%96%E7%B1%99%E5%84%80&variant=zh-hans","https://brill.com/display/book/9781684170869/BP000012.pdf","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E4%B8%80%E6%B3%95%E6%96%87%E5%A4%AA%E4%B8%8A%E5%A4%96%E7%B1%99%E5%84%80"],textual_certainty:"high",notes:"batch49 · Grok-4.5 focused 正一符箓法术"},{dz:"DZ1244",name_han:"受籙次第法信儀",name_vi:"Thụ lục thứ đệ pháp tín nghi",bu:"正一",author:"佚名",era:"唐前後",topic:"ritual",essence:"Liệt kê pháp tín (vật cúng minh thệ) cho từng bậc thụ kinh lục: từ sơ thụ đạo, tứ bộ cấm khí, đạo đức kinh, đến động thần, linh bảo, thượng thanh. Đồng thời nêu thứ tự pháp vị: Chính Nhất → đạo đức → … → thượng thanh. Là sổ tay chuẩn cho nghi thụ lục và phẩm trật đạo sĩ trung cổ.",key_text:"null",use:"Chuẩn bị pháp tín, xác định thứ tự thụ lục và pháp vị",sources:["https://www.shidianguji.com/book/DZ1244","https://zh.daoinfo.org/index.php?title=%E5%8F%97%E7%B1%99%E6%AC%A1%E7%AC%AC%E6%B3%95%E4%BF%A1%E5%84%80&variant=zh-hant","https://ctext.org/wiki.pl?if=gb&res=782937"],textual_certainty:"high",notes:"batch49 · Grok-4.5 focused 正一符箓法术"},{dz:"DZ1287",name_han:"正一法文經護國醮海品",name_vi:"Chính Nhất pháp văn kinh hộ quốc tiếu hải phẩm",bu:"正一",author:"佚名",era:"南北朝",topic:"ritual",essence:"Tàn quyển Chính Nhất pháp văn chuyên về nghi tiếu tế biển / hộ quốc. Phản ánh pháp sự cầu quốc thái dân an và trấn hải của Thiên sư đạo sơ kỳ. Là một mắt xích quan trọng trong sự phát triển nghi tiếu độc lập ngoài trai pháp Linh Bảo.",key_text:"null",use:"Tiếu tế hộ quốc, cầu an biển cả, trấn thủy tai",sources:["https://zh.daoinfo.org/index.php?title=%E6%AD%A3%E4%B8%80%E6%B3%95%E6%96%87%E7%B6%93%E8%AD%B7%E5%9C%8B%E9%86%AE%E6%B5%B7%E5%93%81&variant=zh-hant","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://michaelstanley-baker.com/clarkes-complete-daoist-index/"],textual_certainty:"high",notes:"batch49 · Grok-4.5 focused 正一符箓法术"},{dz:"DZ998",name_han:"周易参同契发挥",name_vi:"Chu Dịch Tham Đồng Khế Phát Huy",bu:"太玄",author:"俞琰（全阳子）",era:"宋末元初 / 13th–14th c.",topic:"cultivation",essence:"Dụ Diễm lấy một thân thủy hỏa âm dương để phát huy chỉ thú nội đan của Tham Đồng Khế. Hiệu đính nhiều bản (Thục, Việt, Cát, Tiền Đường), dẫn Lưu Hải Thiềm, Trương Bá Đoan, Tiết Đạo Quang, Trần Nê Hoàn. Nhấn mạnh kim đan tức một âm một dương, một thái cực.",key_text:"以一身之水火阴阳发挥丹道",use:"Đọc Tham Đồng Khế theo hệ Nam tông + Dịch học Tống Nguyên; tra hỏa hầu và thân trung chi Dịch.",sources:["https://zh.daoinfo.org/index.php?title=%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%E7%99%BC%E6%8F%AE%EF%BC%88%E5%8E%9F%E9%A1%8C%E4%BF%9E%E7%90%B0%EF%BC%89","https://zh.wikisource.org/zh-hans/%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%E7%99%BC%E6%8F%AE","https://ctext.org/wiki.pl?if=gb&res=515554"],textual_certainty:"high",notes:"batch50 · Grok-4.5 focused 内丹经典注疏"},{dz:"DZ1000",name_han:"周易参同契解",name_vi:"Chu Dịch Tham Đồng Khế Giải",bu:"太玄",author:"陈显微（抱一子）",era:"南宋 / 13th c. (宝庆 1225–1227)",topic:"cultivation",essence:"Trần Hiển Vi giải Tham Đồng Khế theo Nam tông: càn khôn là thiên địa trong thân, khảm ly là nhật nguyệt trong thân. Càn khôn thăng giáng làm hậu, khảm ly phối hợp làm cơ. Dẫn Trần Đoàn, Lưu Hải Thiềm, Trương Bá Đoan.",key_text:"金丹之道，象乾坤以为体，法日月以为用",use:"Học tượng pháp thân-thiên địa khi đọc Tham Đồng Khế; đối chiếu Nam tông.",sources:["https://zh.daoinfo.org/index.php?title=%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%E8%A7%A3%EF%BC%88%E9%99%B3%E9%A1%AF%E5%BE%AE%EF%BC%89","https://zh.wikisource.org/zh-hans/%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%E8%A7%A3","https://ctext.org/wiki.pl?if=gb&res=837954"],textual_certainty:"high",notes:"batch50 · Grok-4.5 focused 内丹经典注疏"},{dz:"DZ1001",name_han:"周易参同契注（储华谷）",name_vi:"Chu Dịch Tham Đồng Khế Chú (Trữ Hoa Cốc)",bu:"太玄",author:"储华谷",era:"北宋末–南宋初 / 12th c.",topic:"cultivation",essence:"Trữ Hoa Cốc chia Tham Đồng Khế thành bốn mươi chương, chú ngắn gọn. Lấy càn khôn làm đỉnh thất, nhật nguyệt làm vận dụng, sáu mươi bốn quẻ giải hỏa hầu thăng giáng. Nội đan gần Trương Bá Đoan, văn minh bạch.",key_text:"以乾坤为鼎室，以日月为运用",use:"Bản chú Tham Đồng Khế dễ đọc; học hỏa hầu theo hào tượng.",sources:["https://zh.daoinfo.org/index.php?title=%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%EF%BC%88%E5%84%B2%E8%8F%AF%E8%B0%B7%EF%BC%89","https://zh.wikisource.org/zh-hans/%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%E8%A8%BB_(%E5%84%B2%E8%8F%AF%E8%B0%B7)","https://www.shidianguji.com/zh/book/DZ1008"],textual_certainty:"high",notes:"batch50 · Grok-4.5 focused 内丹经典注疏"},{dz:"DZ995",name_han:"周易参同契考异",name_vi:"Chu Dịch Tham Đồng Khế Khảo Dị",bu:"太玄",author:"朱熹（空同道士邹䜣）",era:"南宋 / 1197 (庆元丁巳)",topic:"cultivation",essence:"Chu Hi hiệu khảo dị văn Tham Đồng Khế, kèm tiên chú. Cho rằng sách mượn nạp giáp để gửi hỏa hầu tiến thoái, không chỉ để minh Dịch. Thiên về nội đan nhưng đôi chỗ nghi ngoại đan; nối Đồ thư Dịch học với Tham Đồng Khế.",key_text:"参同契本不为明易，姑借此纳甲之法，以寓其行持进退之候",use:"Đối chiếu dị văn; hiểu cách Nho gia đọc đan kinh; nền cho hậu thế.",sources:["https://zh.daoinfo.org/index.php?title=%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%E8%80%83%E7%95%B0%EF%BC%88%E6%9C%B1%E7%86%B9%EF%BC%89","https://zh.wikisource.org/wiki/%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%E8%80%83%E7%95%B0","https://baike.baidu.com/item/%E5%91%A8%E6%98%93%E5%8F%82%E5%90%8C%E5%A5%91%E8%80%83%E5%BC%82/8240029"],textual_certainty:"high",notes:"batch50 · Grok-4.5 focused 内丹经典注疏"},{dz:"DZ994",name_han:"周易参同契注（无名氏·内丹）",name_vi:"Chu Dịch Tham Đồng Khế Chú (Vô Danh Thị · nội đan)",bu:"太玄",author:"无名氏（疑北宋道士）",era:"北宋 / 10th–11th c.",topic:"cultivation",essence:"Bản chú vô danh ở映字号, phân chương gần Bành Hiểu, kiêng húy '匡' đời Tống. Giải theo nội đan: '又当明内丹以养己，使安静于虚无之境.' Phụ Đỉnh khí ca.",key_text:"又当明内丹以养己，使安静于虚无之境",use:"Đối chiếu Bành Hiểu; lấy góc nội đan sớm của Tham Đồng Khế.",sources:["https://zh.daoinfo.org/index.php?title=%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%E8%A8%BB%EF%BC%88%E4%BD%9A%E5%90%8D%E6%B0%8F%EF%BC%89","https://zh.daoinfo.org/wiki/%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%E8%A8%BB%EF%BC%88%E4%BD%9A%E5%90%8D%E6%B0%8F%EF%BC%89","https://ctext.org/library.pl?if=gb&res=84683"],textual_certainty:"high",notes:"batch50 · Grok-4.5 focused 内丹经典注疏"},{dz:"DZ993",name_han:"周易参同契注（阴真人）",name_vi:"Chu Dịch Tham Đồng Khế Chú (Âm Chân Nhân)",bu:"太玄",author:"原题长生阴真人（唐人託名阴长生）",era:"唐 / 7th–9th c.",topic:"cultivation",essence:"Nguyên đề Âm Chân Nhân chú; Trần Quốc Phù khảo là Đường nhân thác danh. Giải thiên ngoại đan (thần phù, cửu chuyển, kim dịch), nhưng là bản chú Tham Đồng Khế cổ trong Đạo tạng, quan trọng để so sánh lộ trình nội–ngoại.",key_text:"朱化为汞，汞变为金，金变为砂，砂化为丹，故曰还丹",use:"Đọc để phân biệt lớp ngoại đan lịch sử của Tham Đồng Khế; đối chiếu các bản nội đan.",sources:["https://zh.daoinfo.org/index.php?title=%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%EF%BC%88%E9%99%B0%E7%9C%9F%E4%BA%BA%EF%BC%89","https://zh.wikisource.org/wiki/%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%E8%A8%BB_(%E9%99%B0%E9%95%B7%E7%94%9F)","https://zh.daoinfo.org/wiki/%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%EF%BC%88%E9%99%B0%E7%9C%9F%E4%BA%BA%EF%BC%89"],textual_certainty:"high",notes:"batch50 · Grok-4.5 focused 内丹经典注疏"},{dz:"DZ997",name_han:"周易参同契注（无名氏·容帙）",name_vi:"Chu Dịch Tham Đồng Khế Chú (Vô Danh Thị · Dung trật)",bu:"太玄",author:"无名氏（近人或考徐从事/萧先生系）",era:"唐–五代 / 8th–10th c.",topic:"cultivation",essence:"Bản chú hai quyển ở容字号, không đề danh. Trần Quốc Phù khảo Đường–Ngũ Đại. Thiên ngoại đan hoàng bạch: đan thành tím đỏ mới là đại dược, hóa ngũ kim mới phục. Khác hẳn bản内丹 DZ994.",key_text:"色若不紫赤，不名为大药",use:"Đối chiếu lịch sử giải thích Tham Đồng Khế theo hoàng bạch thuật; không dùng làm chỉ nam nội đan.",sources:["https://zh.daoinfo.org/index.php?title=%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%E6%B3%A8%EF%BC%88%E7%84%A1%E5%90%8D%E6%B0%8F%EF%BC%89","https://www.academia.edu/144642057/_%E9%81%93%E8%97%8F_%E5%AE%B9%E5%B8%99_%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%E8%A8%BB_%E6%A0%A1%E8%AE%80%E8%A8%98","https://zh.daoinfo.org/wiki/%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%E6%B3%A8%EF%BC%88%E7%84%A1%E5%90%8D%E6%B0%8F%EF%BC%89"],textual_certainty:"high",notes:"batch50 · Grok-4.5 focused 内丹经典注疏"},{dz:"DZ999",name_han:"周易参同契释疑",name_vi:"Chu Dịch Tham Đồng Khế Thích Nghi",bu:"太玄",author:"俞琰（全阳子）",era:"宋末元初 / 13th–14th c.",topic:"cultivation",essence:"Phụ bản của Phát huy: Dụ Diễm biện nghi phân chương, dị văn và lối chú cũ (nhất là Bành Hiểu). Thiên đề cao Chu Hi, chỉnh lý văn bản Tham Đồng Khế trước khi phát huy nghĩa nội đan.",key_text:"《周易参同契》上、中、下三篇，合而观之，其辞错乱，本不可以分章也",use:"Đọc kèm Phát huy; tra dị văn và phương pháp phân chương.",sources:["https://zh.daoinfo.org/wiki/%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%E9%87%8B%E7%96%91%EF%BC%88%E5%8E%9F%E9%A1%8C%E4%BF%9E%E7%90%B0%EF%BC%89","https://zh.wikisource.org/zh-hans/%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%E9%87%8B%E7%96%91","https://ctext.org/wiki.pl?if=gb&res=515554"],textual_certainty:"high",notes:"batch50 · Grok-4.5 focused 内丹经典注疏"},{dz:"DZ143",name_han:"紫阳真人悟真直指详说三乘秘要",name_vi:"Tử Dương Chân Nhân Ngộ Chân Trực Chỉ Tường Thuyết Tam Thừa Bí Yếu",bu:"洞真",author:"翁葆光（无名子）",era:"南宋 / 12th–13th c.",topic:"cultivation",essence:"Ông Bảo Quang thuật 'trực chỉ' Ngộ Chân Thiên theo tam thừa: luyện kim đan (cường binh), vận hỏa kim dịch (phú quốc), cửu chuyển đại hoàn (thần tiên bão nhất). Không thuộc nhóm chú sớ/tam chú/chú thích/giảng nghĩa đã loại; là bản tổng thuyết Nam tông âm dương.",key_text:"上卷以炼金丹为强兵战胜之术，中卷以运火金液丹为富国安民之法，下卷以九转大还丹为神仙抱一之道",use:"Nắm khung tam thừa khi học Ngộ Chân; đối chiếu hệ Ông Bảo Quang.",sources:["https://zh.daoinfo.org/index.php?title=%E7%B4%AB%E9%99%BD%E7%9C%9F%E4%BA%BA%E6%82%9F%E7%9C%9F%E7%9B%B4%E6%8C%87%E8%A9%B3%E8%AA%AA%E4%B8%89%E4%B9%98%E7%A7%98%E8%A6%81","https://zh.wikisource.org/zh-hans/%E7%B4%AB%E9%99%BD%E7%9C%9F%E4%BA%BA%E6%82%9F%E7%9C%9F%E7%9B%B4%E6%8C%87%E8%A9%B3%E8%AA%AA%E4%B8%89%E4%B9%98%E7%A7%98%E8%A6%81","https://ctext.org/library.pl?if=gb&res=83796","https://homeinmists.ilotus.org/%E9%81%93%E8%97%8F%E5%8C%AF%E7%B7%A8/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F/%E9%81%93%E8%97%8F%E7%9B%AE%E9%8C%84/"],textual_certainty:"high",notes:"batch50 · Grok-4.5 focused 内丹经典注疏"},{dz:"DZ431",name_han:"黄庭内景五脏六腑补泻图",name_vi:"Hoàng Đình Nội Cảnh Ngũ Tạng Lục Phủ Bổ Tả Đồ",bu:"洞玄",author:"胡愔（见素子）",era:"唐 / 大中二年 (848)",topic:"cultivation",essence:"Hồ Âm lấy chương tâm thần Hoàng Đình Nội Cảnh, sắp phổi–tim–gan–tỳ–thận–đởm, kết hợp y lý và đạo dẫn thổ nạp. Mỗi tạng có đồ, bệnh chứng, bổ tả, thổ nạp—chú giải thực hành hóa Hoàng Đình theo tạng phủ.",key_text:"五脏者，为人形之主。一脏损则病生，五脏损则神灭",use:"Luyện dưỡng theo tạng phủ; nối Hoàng Đình với đạo dẫn y đạo.",sources:["https://zh.daoinfo.org/index.php?title=%E9%BB%83%E5%BA%AD%E5%85%A7%E6%99%AF%E4%BA%94%E8%87%9F%E5%85%AD%E8%85%91%E8%A3%9C%E7%80%89%E5%9C%96","https://www.shidianguji.com/zh/book/DZ0432","https://ctext.org/wiki.pl?if=gb&res=163956"],textual_certainty:"high",notes:"batch50 · Grok-4.5 focused 内丹经典注疏"},{dz:"DZ990",name_han:"古文龙虎经注疏",name_vi:"Cổ Văn Long Hổ Kinh Chú Sớ",bu:"太玄",author:"王道",era:"南宋 / 淳熙十二年 (1185)",topic:"cultivation",essence:"Vương Đạo chú sớ Cổ văn Long Hổ Kinh (hệ Tham Đồng Khế), lấy Tham Đồng Khế chứng nghĩa. Mượn thuật ngữ ngoại đan nói nội đan: chân chì chân thủy ngân là tinh thái âm–khí thái dương, không phải ngũ kim bát thạch. Phụ đồ chu thiên hỏa hầu.",key_text:"真铅真汞，非指五金八石……而是采取太阴之精，诱会太阳之炁",use:"Đọc cặp với Tham Đồng Khế; học pháp tượng long hổ / chu thiên hỏa hầu.",sources:["https://zh.daoinfo.org/index.php?title=%E5%8F%A4%E6%96%87%E9%BE%8D%E8%99%8E%E7%B6%93%E8%A8%BB%E7%96%8F","https://zh.wikisource.org/zh-hans/%E5%8F%A4%E6%96%87%E9%BE%8D%E8%99%8E%E7%B6%93%E8%A8%BB%E7%96%8F","https://www.shidianguji.com/book/DZ0996"],textual_certainty:"high",notes:"batch50 · Grok-4.5 focused 内丹经典注疏"},{dz:"DZ578",name_han:"攝生纂錄",name_vi:"Nhiếp Sinh Toản Lục",bu:"洞玄",author:"王仲丘",era:"Đường",topic:"养生",essence:"Vương Trọng Khâu biên soạn, thu thập các phép nhiếp sinh về ẩm thực, tứ thời, đạo dẫn và phòng bị tật bệnh. Nội dung mang tính thực dụng, nhấn mạnh điều chỉnh sinh hoạt hằng ngày để giữ tinh khí thần. Thuộc nhóm sách dưỡng sinh thực tiễn trong Đạo tạng.",key_text:"null",use:"Tham khảo khung nhiếp sinh đời Đường về ăn uống, tứ thời và đạo dẫn.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://crta.info/wiki/Daozang_-_DZ","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch51 · Grok-4.5 focused 道医方书"},{dz:"DZ842",name_han:"抱朴子養生論",name_vi:"Bão Phác Tử Dưỡng Sinh Luận",bu:"洞神",author:"葛洪",era:"Tấn",topic:"养生",essence:"Cát Hồng ví thân người như một nước: thần là vua, huyết là thần, khí là dân; trị thân như trị quốc. Luận về giữ thần, điều khí, tiết dục và phòng bị tổn hại để trường sinh. Văn bản ngắn nhưng khái quát triết lý dưỡng sinh Đạo giáo.",key_text:"抱朴子曰：一人之身，一國之象也。",use:"Đọc nền tảng triết lý dưỡng sinh Cát Hồng, so sánh thân–quốc.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/zh-hant/%E6%8A%B1%E6%9C%B4%E5%AD%90%E9%A4%8A%E7%94%9F%E8%AB%96","https://ctext.org/library.pl?if=gb&res=84520"],textual_certainty:"high",notes:"batch51 · Grok-4.5 focused 道医方书"},{dz:"DZ853",name_han:"養生辯疑訣",name_vi:"Dưỡng Sinh Biện Nghi Quyết",bu:"洞神",author:"施肩吾",era:"Đường",topic:"养生",essence:"Thi Kiên Ngô biện chính các nghi vấn về dưỡng sinh và nội luyện, phân biệt chân pháp với vọng truyền. Nhấn mạnh tinh khí thần và điều độ sinh hoạt hơn là cầu kỳ. Văn quyết ngắn, mang tính phản biện và chỉ đạo thực tu.",key_text:"null",use:"Đọc để phân biệt chân–ngụy trong dưỡng sinh và tránh lệch pháp.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://crta.info/wiki/Daozang_-_DZ","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch51 · Grok-4.5 focused 道医方书"},{dz:"DZ1427",name_han:"太清道林攝生論",name_vi:"Thái Thanh Đạo Lâm Nhiếp Sinh Luận",bu:"正一",author:"不詳（或題支遁/道林）",era:"Ngụy–Tấn trở đi",topic:"养生",essence:"Luận nhiếp sinh toàn diện: ăn uống, ngủ nghỉ, đạo dẫn, phòng phòng sự và tứ thời. Nhấn mạnh “biết dưỡng tính” quan trọng hơn chỉ phục dược. Nhiều đoạn gần với chương dưỡng tính trong Thiên Kim, phản ánh giao thoa đạo–y.",key_text:"真人曰：雖常餌藥而不知養性之術，亦難以長生也。",use:"Học nguyên tắc nhiếp sinh: không chỉ phục dược mà phải dưỡng tính.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://dollyyang.com/taiqing-daolin-shesheng-lun-%E5%A4%AA%E6%B8%85%E9%81%93%E6%9E%97%E6%94%9D%E7%94%9F%E8%AB%96-discussion-of-conserving-health-according-to-daolin-dz-1427/","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E6%B8%85%E9%81%93%E6%9E%97%E6%94%9D%E7%94%9F%E8%AB%96"],textual_certainty:"high",notes:"batch51 · Grok-4.5 focused 道医方书"},{dz:"DZ587",name_han:"黃帝太一八門入式祕訣",name_vi:"Hoàng Đế Thái Nhất bát môn nhập thức bí quyết",bu:"洞玄",author:"佚名",era:"唐–五代",topic:"方術",essence:"Bản biệt truyền về Thái Nhất/kỳ môn bát môn, khác hẳn Hoàng Đế Thái Ất bát môn nhập thức quyết (DZ586) về văn tự. Gồm chú xuất nhập thiên môn–địa hộ, lục nghi kích hình, tam kỳ nhập mộ, cùng các pháp lục đinh ngọc nữ, ẩn hình, kỳ môn bố cục.",key_text:"天門開泰，六甲扶持，金鎖玉鑰，速□莫違。",use:"Bố cục kỳ môn/Thái Nhất bát môn, chọn hướng–thời và nghi pháp ẩn hình.",sources:["https://zh.daoinfo.org/index.php?title=%E9%BB%83%E5%B8%9D%E5%A4%AA%E4%B8%80%E5%85%AB%E9%96%80%E5%85%A5%E5%BC%8F%E7%A7%98%E8%A8%A3&variant=zh-hant","https://www.shidianguji.com/zh/book/DZ0587","https://ctext.org/wiki.pl?if=gb&res=200458","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch52 · Grok-4.5 focused 杂占术数"},{dz:"DZ858",name_han:"太上洞神玄妙白猿真經",name_vi:"Thái Thượng Động Thần huyền diệu Bạch Viên chân kinh",bu:"洞神",author:"佚名",era:"宋代（約）",topic:"方術",essence:"Kinh binh gia–đạo thuật mang màu lục nhâm/độn giáp, chia năm thức (như lục giáp thần tiễn). Kết hợp niệm chú, thổi khí, viết phù lục giáp với bố cục thức pháp để cầu thắng trận, trấn yểm. Tiêu biểu cho lớp sách ‘bạch viên/lục đinh’ trong Động thần phương pháp.",key_text:"null",use:"Binh pháp–độn giáp/lục nhâm phù chú, trấn yểm và chọn thời xuất quân.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%A5%9E%E7%8E%84%E5%A6%99%E7%99%BD%E7%8C%BF%E7%9C%9F%E7%B6%93&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&res=511964","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch52 · Grok-4.5 focused 杂占术数"},{dz:"DZ1289",name_han:"六十甲子本命元辰曆",name_vi:"Lục thập Giáp Tý bản mệnh nguyên thần lịch",bu:"正一",author:"佚名",era:"隋唐（約；近《隋志》元辰曆）",topic:"占驗",essence:"Lịch lộc mệnh thuần túy: mỗi ngày trong lục thập giáp tý có thần bản mệnh trực nhật, tinh tú và số tùng quan. Tra ngày sinh (bản mệnh nguyên thần) là biết thần chủ mệnh và sao tương ứng để luận vận. Thuật này đã có từ Hán–Ngụy, thịnh từ Tùy–Đường.",key_text:"甲子本命王文卿，從官十八人，貪狼星元辰。",use:"Tra thần bản mệnh–nguyên thần theo ngày sinh, luận lộc mệnh.",sources:["https://zh.daoinfo.org/index.php?title=%E5%85%AD%E5%8D%81%E7%94%B2%E5%AD%90%E6%9C%AC%E5%91%BD%E5%85%83%E8%BE%B0%E6%9B%86&variant=zh-hant","https://zh.wikisource.org/zh-hant/%E5%85%AD%E5%8D%81%E7%94%B2%E5%AD%90%E6%9C%AC%E5%91%BD%E5%85%83%E8%BE%B0%E6%9B%86","https://www.shidianguji.com/book/DZ1289","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch52 · Grok-4.5 focused 杂占术数"},{dz:"DZ1325",name_han:"洞真太上八素真經占候入定妙訣",name_vi:"Động Chân Thái Thượng bát tố chân kinh chiêm hậu nhập định diệu quyết",bu:"正一",author:"佚名",era:"東晉–南朝",topic:"占候",essence:"Một trong các quyết của Bát Tố chân kinh phái Thượng thanh: dạy xem thời–tượng (chiêm hậu) để chọn lúc nhập định tọa chiếu. Không phải bói thế tục thuần túy mà là lịch–tượng phục vụ nội tu: quan sát khí hậu, tinh tượng, tiết lệnh rồi định giờ nhập tĩnh.",key_text:"null",use:"Chọn thời nhập định theo chiêm hậu thiên tượng–tiết khí.",sources:["https://zh.wikisource.org/zh-hans/%E6%B4%9E%E7%9C%9F%E5%A4%AA%E4%B8%8A%E5%85%AB%E7%B4%A0%E7%9C%9F%E7%B6%93%E5%8D%A0%E5%80%99%E5%85%A5%E5%AE%9A%E5%A6%99%E8%A8%A3","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.daorenjia.com/dztu-115"],textual_certainty:"high",notes:"batch52 · Grok-4.5 focused 杂占术数"},{dz:"DZ1425",name_han:"靈信經旨",name_vi:"Linh Tín kinh chỉ",bu:"正一",author:"佚名（託師曠、劉根等）",era:"漢–六朝系統，道藏合編本",topic:"占驗",essence:"Hai thiên tạp chiêm: Linh Tín kinh chỉ (Sư Khoáng thời Tấn Bình công) gồm hàng trăm câu sấm bốn chữ đoán điềm qua tai–mắt–tâm–thần; Lưu Căn chân nhân linh tín kinh gồm mười hai điều linh nghiệm. Là sách ‘trưng triệu/cảm ứng’ hơn là thức bàn.",key_text:"null",use:"Đoán cát hung theo điềm báo thân thể–cảm ứng, sấm ngữ.",sources:["https://zh.daoinfo.org/index.php?title=%E9%9D%88%E4%BF%A1%E7%B6%93%E6%97%A8&variant=zh-hans","https://ctext.org/library.pl?if=en&res=85098","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","http://www.homeinmists.com/DaoCanon1.htm"],textual_certainty:"high",notes:"batch52 · Grok-4.5 focused 杂占术数"},{dz:"DZ306",name_han:"太華希夷志",name_vi:"Thái Hoa Hi Di Chí",bu:"洞真",author:"張輅",era:"元",topic:"山志",essence:"Trương Lộ biên hai quyển về Hoa Sơn và Trương Bá Đoan (Trần Hy Di). Ghi ẩn tu, giai thoại triều Tống–Nguyên và thắng tích Thái Hoa. Kết hợp sơn chí với tiên truyện của một cao đạo danh tiếng.",key_text:"希夷先生姓陳名摶字圖南",use:"Đối chiếu với Tây Nhạc Hoa sơn chí; nghiên cứu cult Trần Đoàn và địa lý thiêng Hoa Sơn.",sources:["https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F","https://michaelstanley-baker.com/clarkes-complete-daoist-index/","http://www.homeinmists.com/TaoistCanon.html"],textual_certainty:"high",notes:"batch53 · Grok-4.5 focused 仙传/名山志"},{dz:"DZ600",name_han:"梅仙觀記",name_vi:"Mai Tiên Quan Ký",bu:"洞玄",author:"楊智遠等",era:"元",topic:"宫观志",essence:"Ghi chép về Mai Tiên Quán và truyền thuyết Mai Phúc (Mai Tử Chân) đắc đạo. Kết hợp quán chí, tiên tích và bia ký, tiêu biểu cho loại cung quán chí địa phương trong Đạo tạng.",key_text:"梅仙者，漢南昌尉梅福也",use:"Nghiên cứu cult Mai Phúc và mô hình cung quán chí Tống–Nguyên.",sources:["https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf","https://www.jstor.org/stable/26768560","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch53 · Grok-4.5 focused 仙传/名山志"},{dz:"DZ602",name_han:"仙都志",name_vi:"Tiên Đô Chí",bu:"洞玄",author:"陳性定",era:"元",topic:"山志",essence:"Trần Tính Định soạn hai quyển về Tiên Đô sơn (Chiết Giang), thắng cảnh, động phủ, cung quán và tiên tích. Là sơn chí Đạo giáo điển hình gắn danh sơn với lịch sử tu đạo địa phương.",key_text:"仙都山，古名縉雲山",use:"Địa lý thiêng Chiết Đông; so sánh với Thiên Thai sơn chí và Tứ Minh động thiên.",sources:["https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf","https://crta.info/wiki/Daozang_-_DZ","https://www.shidianguji.com/book/NA05256/chapter/1kyb3ogz6iosv"],textual_certainty:"high",notes:"batch53 · Grok-4.5 focused 仙传/名山志"},{dz:"DZ603",name_han:"天台山志",name_vi:"Thiên Thai Sơn Chí",bu:"洞玄",author:"不詳（元明道藏本）",era:"元–明（道藏本）",topic:"山志",essence:"Một quyển về Thiên Thai sơn—trung tâm Thượng Thanh/Tư Mã Thừa Trinh. Ghi phong cảnh, động phủ, quán vũ, tiên tích và liên hệ Phật–Đạo. Nguồn chuẩn cho địa lý thiêng Thiên Thai trong Đạo tạng.",key_text:"天台山者，蓋宗極之峻嶺",use:"Nghiên cứu Thiên Thai như thánh địa Đạo giáo; liên hệ Tư Mã Thừa Trinh và Tọa vong luận.",sources:["https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf","https://ctext.org/wiki.pl?if=gb&chapter=904454","https://crta.info/wiki/Daozang_-_DZ"],textual_certainty:"high",notes:"batch53 · Grok-4.5 focused 仙传/名山志"},{dz:"DZ604",name_han:"龍瑞觀禹穴陽明洞天圖經",name_vi:"Long Thụy Quan Vũ Huyệt Dương Minh Động Thiên Đồ Kinh",bu:"洞玄",author:"李宗諤等（宋）",era:"北宋",topic:"山志",essence:"Đồ kinh về Long Thụy Quán, Vũ huyệt và Dương Minh động thiên (Hội Kê/Thiệu Hưng). Kết hợp bản đồ–địa chí–tiên tích, thuộc dòng đồ kinh danh sơn Tống.",key_text:"陽明洞天，在會稽山",use:"Nghiên cứu hệ động thiên 36/72 và cung quán Chiết Đông đời Tống.",sources:["https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf","https://www.jstor.org/stable/26768560","https://www.shidianguji.com/book/NA05256/chapter/1kyb3ogz6iosv"],textual_certainty:"high",notes:"batch53 · Grok-4.5 focused 仙传/名山志"},{dz:"DZ605",name_han:"四明洞天丹山圖詠集",name_vi:"Tứ Minh Động Thiên Đan Sơn Đồ Vịnh Tập",bu:"洞玄",author:"木元虛撰、賀知章注（傳統題署）",era:"唐–宋（傳本）",topic:"山志",essence:"Tập đồ–vịnh về Tứ Minh động thiên/Đan sơn (Chiết Giang), truyền gắn Mộc Nguyên Hư và chú của Hạ Tri Chương. Kết hợp thi vịnh, đồ họa và địa linh, hiếm trong loại sơn chí Đạo tạng.",key_text:"四明洞天，乃天下名山",use:"Nghiên cứu thi văn địa linh và hình ảnh hóa động thiên Tứ Minh.",sources:["https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf","https://www.jstor.org/stable/26768560","https://www.shidianguji.com/book/NA05256/chapter/1kyb3ogz6iosv"],textual_certainty:"high",notes:"batch53 · Grok-4.5 focused 仙传/名山志"},{dz:"DZ778",name_han:"華蓋山浮丘王郭三真君事實",name_vi:"Hoa Cái Sơn Phù Khâu Vương Quách Tam Chân Quân Sự Thực",bu:"洞玄",author:"沈庭瑞、黃彌堅等",era:"宋–元",topic:"仙传",essence:"Thẩm Đình Thụy, Hoàng Di Kiên v.v. biên sáu quyển về Phù Khâu công, Vương, Quách tam chân quân ở Hoa Cái sơn (Giang Tây). Ghi sự tích, hiển linh, triều phong và nghi cúng địa phương.",key_text:"死而有靈之謂神，長生不死之謂仙",use:"Nghiên cứu cult sơn thần–chân quân địa phương và hagiography tập thể.",sources:["https://www.jstor.org/stable/26768560","https://crta.info/wiki/Daozang_-_DZ","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch53 · Grok-4.5 focused 仙传/名山志"},{dz:"DZ779",name_han:"唐葉真人傳",name_vi:"Đường Diệp Chân Nhân Truyện",bu:"洞玄",author:"不詳（題唐葉法善傳）",era:"唐–宋（道藏本）",topic:"仙传",essence:"Tiểu truyện Diệp Pháp Thiện (葉法善), đạo sĩ triều Đường, pháp lục, phụ chính và giai thoại du nguyệt cung với Huyền Tông. Nguồn hagiography quan trọng về đạo sĩ cung đình thịnh Đường.",key_text:"真人姓葉名法善字道元一字太素本南陽人也",use:"Nghiên cứu Đạo giáo cung đình Đường; đối chiếu với Cựu/Tân Đường thư Diệp Pháp Thiện truyện.",sources:["https://www.jstor.org/stable/26768560","https://zh.wikisource.org/zh-hans/%E9%81%93%E8%97%8F_(%E5%9B%9B%E5%BA%AB%E5%85%A8%E6%9B%B8%E6%9C%AC)/%E5%85%A8%E8%A6%BD","https://baike.baidu.com/item/%E5%8F%B6%E6%B3%95%E5%96%84/5505743"],textual_certainty:"high",notes:"batch53 · Grok-4.5 focused 仙传/名山志"},{dz:"DZ055",name_han:"高上太霄琅书琼文帝章经",name_vi:"Cao Thượng Thái Tiêu Lang Thư Quỳnh Văn Đế Chương Kinh",bu:"洞真",author:"khuyết danh (Thượng Thanh ngụy điển/apocrypha liên hệ Đại Động)",era:"六朝",topic:"cultivation|上清|宝诀",essence:"Chín chương tán tụng Chín Vương Nguyên Thiên Thượng Thanh, kèm tự phù tinh khí Cửu Thiên. Khắc hạt táo, đeo để sai ngũ nhạc, trục tà; gắn “hội phong” và công thức Đại Động.",key_text:"null",use:"Tụng chương·đeo phù·trục tà; phụ trợ tụng Đại Động.",sources:["https://www.jstor.org/stable/26768560","https://archive.org/stream/daozang/Franciscus+Verellen%2C+Kristofer+Schipper+%28editors%29-The+Taoist+Canon+%E2%80%93+A+Historical+Companion+to+the+Daozang_+Vol.+1_+Antiquity+through+the+Middle+Ages++-University+Of+Chicago+Press+%282004%29_djvu.txt","https://dao.crs.cuhk.edu.hk/Main/wp-content/uploads/2018/08/DAO7_03_Jihyun-Kim.pdf"],textual_certainty:"high",notes:"batch54 · Grok-4.5 focused 洞真上清core"},{dz:"DZ081",name_han:"洞真太微黄书天帝君石景金阳素经",name_vi:"Động Chân Thái Vi Hoàng Thư Thiên Đế Quân Thạch Cảnh Kim Dương Tố Kinh",bu:"洞真",author:"mảnh Thái Vi Hoàng Thư (tiền–Thượng Thanh, hậu thu vào canon)",era:"六朝（先于杨羲而入上清）",topic:"cultivation|服气|外丹|上清",essence:"Mảnh quyển 7 Hoàng Thư Thái Vi: thai tức, phục tinh nhật (thạch cảnh kim dương), kèm phù. Thuật ngữ “thạch cảnh kim dương” chỉ tinh mặt trời trong hệ Thượng Thanh.",key_text:"null",use:"Thai tức·phục nhật tinh; phụ nghi Thượng Thanh.",sources:["https://archive.org/stream/daozang/Franciscus+Verellen%2C+Kristofer+Schipper+%28editors%29-The+Taoist+Canon+%E2%80%93+A+Historical+Companion+to+the+Daozang_+Vol.+1_+Antiquity+through+the+Middle+Ages++-University+Of+Chicago+Press+%282004%29_djvu.txt","http://www.chinaknowledge.de/Literature/Daoists/daozang.html"],textual_certainty:"high",notes:"batch54 · Grok-4.5 focused 洞真上清core"},{dz:"DZ082",name_han:"上清洞真元经五籍符",name_vi:"Thượng Thanh Động Chân Huyền Kinh Ngũ Tịch Phù",bu:"洞真",author:"khuyết danh (mảnh Thái Đan Ẩn Thư)",era:"六朝",topic:"cultivation|fu|上清",essence:"Năm phù-tịch của Thái Đan Ẩn Thư (Thái Ất Đế Quân), bổ sung phần phù thiếu trong bản Động Chân huyền kinh. Liên hệ pháp “giải kết” thai kết, gỡ nút sinh tử trong thân.",key_text:"null",use:"Phù tịch·giải kết thai; phối Thái Đan Ẩn Thư.",sources:["https://archive.org/stream/daozang/Franciscus+Verellen%2C+Kristofer+Schipper+%28editors%29-The+Taoist+Canon+%E2%80%93+A+Historical+Companion+to+the+Daozang_+Vol.+1_+Antiquity+through+the+Middle+Ages++-University+Of+Chicago+Press+%282004%29_djvu.txt","https://dokumen.pub/a-library-of-clouds-the-scripture-of-the-immaculate-numen-and-the-rewriting-of-daoist-texts-082488292x-9780824882921.html"],textual_certainty:"high",notes:"batch54 · Grok-4.5 focused 洞真上清core"},{dz:"DZ083",name_han:"白羽黑翮灵飞玉符",name_vi:"Bạch Vũ Hắc Hột Linh Phi Ngọc Phù",bu:"洞真",author:"khuyết danh (thời kỳ mặc khải Thượng Thanh)",era:"东晋—六朝",topic:"fu|cultivation|上清",essence:"Năm ngọc phù (ngũ phương) dưới uy bạch/hắc phượng; dùng cho nghi “phi bộ thăng huyền” (bước Đẩu). Liên hệ Phi Hành Cửu Thần Ngọc Kinh và hệ Linh Phi.",key_text:"null",use:"Phù ngũ phương·bước Đẩu·phi hành thăng huyền.",sources:["https://archive.org/stream/daozang/Franciscus+Verellen%2C+Kristofer+Schipper+%28editors%29-The+Taoist+Canon+%E2%80%93+A+Historical+Companion+to+the+Daozang_+Vol.+1_+Antiquity+through+the+Middle+Ages++-University+Of+Chicago+Press+%282004%29_djvu.txt","https://www.persee.fr/doc/asie_0766-1177_2004_num_14_1_1212"],textual_certainty:"high",notes:"batch54 · Grok-4.5 focused 洞真上清core"},{dz:"DZ084",name_han:"上清琼宫灵飞六甲左右上符",name_vi:"Thượng Thanh Quỳnh Cung Linh Phi Lục Giáp Tả Hữu Thượng Phù",bu:"洞真",author:"khuyết danh (bản Thượng Thanh của phù lục giáp cổ)",era:"东晋（Zhen'gao chứng）",topic:"fu|cultivation|上清",essence:"Phù triệu Linh Phi ngọc nữ phụ trách ngày lục giáp; một danh “ngọc tinh chân quyết”. Xác thực trong Chân Cáo; dùng thỉnh mệnh diên toán, sai linh.",key_text:"左右灵飞六甲符，一名玉精真诀。",use:"Thụ lục·triệu giáp nữ·diên thọ·sai linh.",sources:["https://www.shidianguji.com/book/DZ0084/chapter/1k1t1xqenlc8j","https://www.cuhk.edu.hk/ics/journal/articles/v67p063.pdf","https://www.persee.fr/doc/asie_0766-1177_2004_num_14_1_1212"],textual_certainty:"high",notes:"batch54 · Grok-4.5 focused 洞真上清core"},{dz:"DZ085",name_han:"太上洞真经洞章",name_vi:"Thái Thượng Động Chân Kinh Động Chương",bu:"洞真",author:"khuyết danh",era:"唐",topic:"fu|mantra|上清",essence:"Tập phù–chú nhỏ trong canon Thượng Thanh: Động Chương phù trục thi trong thân (sáng–tối); thêm phù thất tinh Bắc Đẩu và Thái Ất, chú diệt tà.",key_text:"null",use:"Hàng ngày đeo/tụng phù trục thi·hộ thân.",sources:["https://archive.org/stream/daozang/Franciscus+Verellen%2C+Kristofer+Schipper+%28editors%29-The+Taoist+Canon+%E2%80%93+A+Historical+Companion+to+the+Daozang_+Vol.+1_+Antiquity+through+the+Middle+Ages++-University+Of+Chicago+Press+%282004%29_djvu.txt","http://www.chinaknowledge.de/Literature/Daoists/daozang.html"],textual_certainty:"high",notes:"batch54 · Grok-4.5 focused 洞真上清core"},{dz:"DZ104",name_han:"上清大洞真经玉诀音义",name_vi:"Thượng Thanh Đại Động Chân Kinh Ngọc Quyết Âm Nghĩa",bu:"洞真",author:"陈景元",era:"北宋（11世纪）",topic:"classic|玉诀|上清",essence:"Ngọc quyết–âm nghĩa cho Đại Động: chú âm, giải nghĩa, ghi dị bản Mao Sơn. Là chìa khóa đọc bản Mao Sơn (DZ6) và so dị bản “Đại Động khẩu quyết”.",key_text:"妙音九彻，眞聲高唱，文炁與玉虛參玄。",use:"Chú giải·hiệu đính·thực tu tụng Đại Động.",sources:["https://www.jstor.org/stable/26768560","https://ctext.org/wiki.pl?if=gb&res=966018","https://dao.crs.cuhk.edu.hk/Main/wp-content/uploads/2018/08/DAO7_03_Jihyun-Kim.pdf"],textual_certainty:"high",notes:"batch54 · Grok-4.5 focused 洞真上清core"},{dz:"DZ128",name_han:"太上求仙定录尺素真诀玉文",name_vi:"Thái Thượng Cầu Tiên Định Lục Xích Tố Chân Quyết Ngọc Văn",bu:"洞真",author:"thác danh Tây Vương Mẫu / kim mẫu",era:"六朝",topic:"ritual|真诀|上清",essence:"Tập ngọc văn–xích tố (lụa định thước) dùng khi thụ lục Thượng Thanh sau đại minh thệ. Chứng thư truyền thụ, định hạng cầu tiên; pha trộn văn tự Thượng Thanh–Linh Bảo.",key_text:"null",use:"Thụ lục·truyền kinh cấp Thượng Thanh.",sources:["https://archive.org/stream/daozang/Franciscus+Verellen%2C+Kristofer+Schipper+%28editors%29-The+Taoist+Canon+%E2%80%93+A+Historical+Companion+to+the+Daozang_+Vol.+1_+Antiquity+through+the+Middle+Ages++-University+Of+Chicago+Press+%282004%29_djvu.txt","https://homeinmists.ilotus.org/%E9%81%93%E8%97%8F%E5%8C%AF%E7%B7%A8/%E6%B6%B5%E8%8A%AC%E6%A8%93-%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F/1533%E7%A8%AE%E7%B6%93%E6%9B%B8%E5%B0%8D%E6%87%89%E9%81%93%E8%97%8F%E5%9B%9B%E7%A8%AE%E7%89%88%E6%9C%AC%E4%B9%8B%E5%86%8A%E6%95%B8-%E9%A0%81%E7%A2%BC/"],textual_certainty:"high",notes:"batch54 · Grok-4.5 focused 洞真上清core"},{dz:"DZ129",name_han:"太霄琅书琼文帝章诀",name_vi:"Thái Tiêu Lang Thư Quỳnh Văn Đế Chương Quyết",bu:"洞真",author:"khuyết danh",era:"六朝",topic:"ritual|宝诀|上清",essence:"Quyết nghi: chép kinh, lễ vật đệ tử khi thụ kinh, quy tắc nghi thức—tương ứng quyển 5 Động Chân Thái Thượng Thái Tiêu Lang Thư. Cùng DZ55 là mục 30 mục lục Đại Động.",key_text:"null",use:"Nghi truyền kinh·thụ lục·quy chế sao chép.",sources:["https://www.jstor.org/stable/26768560","https://dokumen.pub/a-library-of-clouds-the-scripture-of-the-immaculate-numen-and-the-rewriting-of-daoist-texts-082488292x-9780824882921.html","https://archive.org/stream/daozang/Franciscus+Verellen%2C+Kristofer+Schipper+%28editors%29-The+Taoist+Canon+%E2%80%93+A+Historical+Companion+to+the+Daozang_+Vol.+1_+Antiquity+through+the+Middle+Ages++-University+Of+Chicago+Press+%282004%29_djvu.txt"],textual_certainty:"high",notes:"batch54 · Grok-4.5 focused 洞真上清core"},{dz:"DZ133",name_han:"太上洞房内经注",name_vi:"Thái Thượng Động Phòng Nội Kinh Chú",bu:"洞真",author:"kinh cổ + chú khuyết danh (≤7 c.)",era:"六朝—隋唐初",topic:"cultivation|上清",essence:"Tụng tán thần Động Phòng (cung não). Chân Cáo gợi nguồn tiền Thượng Thanh; chú dẫn Sư Linh–Thái Đan Ẩn Thư. Bản hiện ngắn hơn trích trong Thư Nhất ngũ lão bảo kinh.",key_text:"null",use:"Tồn tư cung não·động phòng; đọc kèm chú.",sources:["https://archive.org/stream/daozang/Franciscus+Verellen%2C+Kristofer+Schipper+%28editors%29-The+Taoist+Canon+%E2%80%93+A+Historical+Companion+to+the+Daozang_+Vol.+1_+Antiquity+through+the+Middle+Ages++-University+Of+Chicago+Press+%282004%29_djvu.txt","https://en.wikipedia.org/wiki/Zhengao"],textual_certainty:"high",notes:"batch54 · Grok-4.5 focused 洞真上清core"},{dz:"DZ164",name_han:"上清三尊谱录",name_vi:"Thượng Thanh Tam Tôn Phổ Lục",bu:"洞真",author:"truyền hệ Kim Minh Thất Chân / đệ tử huyền ký",era:"唐前后",topic:"ritual|仙传|上清",essence:"Phổ lục liên hệ Tam Tôn (hóa thân Tam Bảo) với kinh Tam Động. Xác nhận tổ sư thần truyền, chỉ thị sao chép–cúng kính phổ lục trong khung Thượng Thanh–Linh Bảo–Tam Hoàng.",key_text:"null",use:"Phổ lục tông hệ·thờ Tam Tôn·truyền thừa.",sources:["https://archive.org/stream/daozang/Franciscus+Verellen%2C+Kristofer+Schipper+%28editors%29-The+Taoist+Canon+%E2%80%93+A+Historical+Companion+to+the+Daozang_+Vol.+1_+Antiquity+through+the+Middle+Ages++-University+Of+Chicago+Press+%282004%29_djvu.txt","https://dao.crs.cuhk.edu.hk/Main/wp-content/uploads/2018/08/DAO7_03_Jihyun-Kim.pdf"],textual_certainty:"partial",notes:"batch54 · Grok-4.5 focused 洞真上清core"},{dz:"DZ179",name_han:"太微灵书紫文仙忌真记上经",name_vi:"Thái Vi Linh Thư Tử Văn Tiên Kỵ Chân Ký Thượng Kinh",bu:"洞真",author:"khuyết danh (mảnh Linh Thư Tử Văn nguyên Thượng Thanh)",era:"东晋",topic:"戒律|紫文|上清",essence:"Mảnh Linh Thư Tử Văn về giới cấm tiên: dâm, tửu, thịt theo bản mệnh/cha mẹ, kỵ phương Bắc… Phạm giới làm hỏng “tiên tướng”. Truyền bởi Thanh Đồng.",key_text:"第一勿好淫，淫则魂液外漏，精光枯竭，神燋魄散。",use:"Giới luật người thụ Linh Thư Tử Văn; giữ tướng tiên.",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E5%BE%AE%E9%9D%88%E6%9B%B8%E7%B4%AB%E6%96%87%E4%BB%99%E5%BF%8C%E7%9C%9F%E8%A8%98%E4%B8%8A%E7%B6%93","https://ctext.org/wiki.pl?if=gb&res=233068","https://ctext.org/wiki.pl?if=en&chapter=528771&remap=gb"],textual_certainty:"high",notes:"batch54 · Grok-4.5 focused 洞真上清core"},{dz:"DZ322",name_han:"太上靈寶天地運度自然妙經",name_vi:"Thái Thượng Linh Bảo Thiên Địa Vận Độ Tự Nhiên Diệu Kinh",bu:"洞玄",author:"佚名",era:"南北朝–隋唐",topic:"classic|philosophy",essence:"Giảng vận độ thiên địa, chu kỳ kiếp vận và trật tự tự nhiên theo quan điểm Linh Bảo. Liên hệ vận hành vũ trụ với tu trì và độ nhân, nhấn mạnh thuận theo khí vận để tránh tai kiếp. Thuộc nhóm kinh vận độ trong Động Huyền bộ.",key_text:"null",use:"Đọc để hiểu kiếp vận, phối hợp với nghi cầu an và tu hành thuận thời.",sources:["https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://ctext.org/wiki.pl?if=gb&res=1"],textual_certainty:"high",notes:"batch55 · Grok-4.5 focused 洞玄灵宝core"},{dz:"DZ345",name_han:"太上洞玄靈寶誡業本行上品妙經",name_vi:"Thái Thượng Động Huyền Linh Bảo Giới Nghiệp Bản Hành Thượng Phẩm Diệu Kinh",bu:"洞玄",author:"佚名（古靈寶經）",era:"東晉末–南朝初",topic:"戒律|philosophy",essence:"Thuộc hệ cổ Linh Bảo, luận nghiệp báo, giới cấm và bản hạnh đạo sĩ. Khuyên giữ giới để dứt nghiệp, tu hành thượng phẩm hướng tới độ mình và độ người. Bổ sung cho nhóm giới luật–khuyến giới Động Huyền.",key_text:"null",use:"Giảng giới nghiệp, giáo hóa đạo sĩ, nền cho nghi sám hối.",sources:["https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","http://www.ctcwri.idv.tw/CTCW-MTS/CMT000.htm"],textual_certainty:"high",notes:"batch55 · Grok-4.5 focused 洞玄灵宝core"},{dz:"DZ346",name_han:"太上洞玄靈寶真一勸誡法輪妙經",name_vi:"Thái Thượng Động Huyền Linh Bảo Chân Nhất Khuyến Giới Pháp Luân Diệu Kinh",bu:"洞玄",author:"佚名（仙公系靈寶）",era:"東晉末–南朝",topic:"戒律|classic",essence:"Kinh khuyến giới hệ tiên công Linh Bảo, lấy pháp luân chân nhất để khuyên răn đạo hạnh. Liên hệ truyền thừa pháp luân với giới hạnh và chuyển thần nhập định. Thường được nghiên cứu cùng các bản CT347–348, CT455.",key_text:"null",use:"Khuyến giới, giảng pháp luân, tu học truyền thừa Linh Bảo.",sources:["https://dao.crs.cuhk.edu.hk/Main/wp-content/uploads/2022/09/DAO14_06_%E5%BC%B5%E8%B6%85%E7%84%B6.pdf","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch55 · Grok-4.5 focused 洞玄灵宝core"},{dz:"DZ349",name_han:"太上洞玄靈寶法燭經",name_vi:"Thái Thượng Động Huyền Linh Bảo Pháp Chúc Kinh",bu:"洞玄",author:"佚名（或託陸修靜系統）",era:"南北朝末–隋唐",topic:"ritual|cultivation",essence:"Lấy pháp làm quy củ và chúc (đuốc) làm ánh sáng để soi tối, chỉnh tà. Mười chương giảng trai giới, tĩnh tư, hình–khí–thần hợp nhất, thường gắn với nghi thắp đèn và trai pháp Linh Bảo.",key_text:"法者，規矩之謂，總稱曰法。規圓矩方，萬物從之得正。燭者，有光之物，佐月嗣日，開昏朗闇。",use:"Trai giới, đèn pháp, tu tâm định chí trong khoa nghi Linh Bảo.",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E6%B3%95%E7%87%AD%E7%B6%93","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E6%B3%95%E7%87%AD%E7%B6%93","https://www.shidianguji.com/book/DZ0349"],textual_certainty:"high",notes:"batch55 · Grok-4.5 focused 洞玄灵宝core"},{dz:"DZ350",name_han:"太上洞玄靈寶智慧觀身經",name_vi:"Thái Thượng Động Huyền Linh Bảo Trí Tuệ Quán Thân Kinh",bu:"洞玄",author:"佚名",era:"南北朝–隋唐",topic:"cultivation|philosophy",essence:"Giảng quán thân bằng trí tuệ Linh Bảo: quán thân bất tịnh, vô thường để đoạn chấp, sinh tuệ. Kết hợp thiền quán với giới hạnh, hướng tới giải thoát và độ thế.",key_text:"null",use:"Thiền quán, tu tuệ, giáo hóa thân tâm trong pháp môn Linh Bảo.",sources:["https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.shidianguji.com/book/DZ0349"],textual_certainty:"partial",notes:"batch55 · Grok-4.5 focused 洞玄灵宝core"},{dz:"DZ374",name_han:"太上洞玄靈寶救苦妙經",name_vi:"Thái Thượng Động Huyền Linh Bảo Cứu Khổ Diệu Kinh",bu:"洞玄",author:"佚名",era:"南北朝–唐",topic:"ritual|mantra",essence:"Kinh cứu khổ trung tâm hệ Linh Bảo: xưng tụng Cứu Khổ Thiên Tôn, dùng hồng danh và chân ngôn để cứu hồn u đồ, tiêu tội, sinh thiên. Được tụng rộng trong công khóa, trai đàn và nghi độ vong.",key_text:"null",use:"Công khóa, cứu khổ, độ vong, sám hối.",sources:["https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.shidianguji.com/zh/book/DZ0388"],textual_certainty:"high",notes:"batch55 · Grok-4.5 focused 洞玄灵宝core"},{dz:"DZ388",name_han:"太上洞玄靈寶五符序",name_vi:"Thái Thượng Động Huyền Linh Bảo Ngũ Phù Tự",bu:"洞玄",author:"佚名（古靈寶；《抱朴子》已引）",era:"魏晉（約成，東晉分卷）",topic:"fu|cultivation",essence:"Cổ kinh phù pháp Linh Bảo (còn gọi Linh Bảo Ngũ Phù Kinh): ngũ phương phù, phục khí ngũ phương, ăn tinh nhật nguyệt, nghi cầu tiên. Định hình vai trò thiên văn–thần phù–linh đồ trong kinh điển Linh Bảo sau này.",key_text:"符者，經也。子長口訣，清齋三日，而致五方天帝，誠之盡矣，則真人必降。",use:"Phù lục, phục khí, nhập sơn, cầu tiên, nền tảng ngũ phù.",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E4%BA%94%E7%AC%A6%E5%BA%8F","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E4%BA%94%E7%AC%A6%E5%BA%8F","https://ctext.org/wiki.pl?if=gb&res=993764"],textual_certainty:"high",notes:"batch55 · Grok-4.5 focused 洞玄灵宝core"},{dz:"DZ396",name_han:"洞玄靈寶自然九天生神章經解義",name_vi:"Động Huyền Linh Bảo Tự Nhiên Cửu Thiên Sinh Thần Chương Kinh Giải Nghĩa",bu:"洞玄",author:"董思靖",era:"南宋（淳祐十二年/1252）",topic:"classic|cultivation",essence:"Chú giải bốn quyển của Đổng Tư Tĩnh (Tuyền Châu) về Cửu Thiên Sinh Thần Chương Kinh. Phân chương giải nghĩa sinh thần, tam bảo và ứng dụng nghi thức, phản ánh tiếp nhận Tống đại đối với cổ Linh Bảo.",key_text:"null",use:"Học chú sớ Sinh Thần Chương, hỗ trợ tụng kinh và nghi sinh thần.",sources:["https://zh.daoinfo.org/index.php?title=%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E8%87%AA%E7%84%B6%E4%B9%9D%E5%A4%A9%E7%94%9F%E7%A5%9E%E7%AB%A0%E7%B6%93%E8%A7%A3%E7%BE%A9","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch55 · Grok-4.5 focused 洞玄灵宝core"},{dz:"DZ454",name_han:"太上洞玄靈寶上品戒經",name_vi:"Thái Thượng Động Huyền Linh Bảo Thượng Phẩm Giới Kinh",bu:"洞玄",author:"佚名",era:"南北朝",topic:"戒律",essence:"Kinh giới thượng phẩm hệ Linh Bảo: Thiên Tôn trao cho Đạo Quân trí tuệ thượng phẩm giới pháp. Nhấn mạnh thọ giới, hồi hướng thập phương, làm nền đạo hạnh trước khi hành trai khoa.",key_text:"爾時天尊……所授太上道君智慧上品大戒法文，於時道君受戒，首體投地，回心十方，思念三尊。",use:"Thọ giới, giáo giới đạo sĩ, chuẩn bị hành trai.",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E4%B8%8A%E5%93%81%E6%88%92%E7%B6%93","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch55 · Grok-4.5 focused 洞玄灵宝core"},{dz:"DZ651",name_han:"太上洞神三元妙本福寿真经",name_vi:"Thái Thượng Động Thần Tam Nguyên Diệu Bản Phúc Thọ Chân Kinh",bu:"洞神",author:"佚名",era:"宋–元",topic:"ritual",essence:"Kinh Động Thần gắn tín ngưỡng Tam Nguyên (Thiên–Địa–Thủy quan) với cầu phúc thọ, tiêu tai. Nhấn mạnh bản nguyên diệu huyền của đạo và công đức sám hối, bố thí, trì tụng. Dùng trong nghi thức cầu thọ và trấn an.",key_text:"null",use:"Cầu phúc thọ, nghi Tam Nguyên, trì tụng tiêu tai",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch56b · Grok-4.5 focused 洞神core"},{dz:"DZ803",name_han:"太上洞神三皇仪",name_vi:"Thái Thượng Động Thần Tam Hoàng Nghi",bu:"洞神",author:"佚名",era:"南北朝",topic:"ritual",essence:"Nghi thức truyền thụ và hành trì kinh pháp Tam Hoàng thuộc Động Thần. Ghi trình tự lập đàn, thỉnh thần, trao kinh–lục, và các tiết mục nghi quỹ. Là văn bản nghi lễ then chốt của hệ Tam Hoàng.",key_text:"null",use:"Truyền độ Tam Hoàng, lập đàn Động Thần",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F","https://dao.crs.cuhk.edu.hk/Main/%E4%B8%AD%E5%BF%83%E5%87%BA%E7%89%88/%E4%B8%89%E7%9A%87%E7%B6%93/"],textual_certainty:"high",notes:"batch56b · Grok-4.5 focused 洞神core"},{dz:"DZ854",name_han:"太上三皇宝斋神仙上录经",name_vi:"Thái Thượng Tam Hoàng Bảo Trai Thần Tiên Thượng Lục Kinh",bu:"洞神",author:"佚名",era:"南北朝–隋唐",topic:"ritual",essence:"Kinh ghi nghi Tam Hoàng bảo trai và cách làm tín vật, hương châu, trọng tiêu thủy. Kết hợp trai giới với cầu tiên, hộ sinh, độ thất thế. Là văn bản phương pháp–uy nghi then chốt của hệ Động Thần Tam Hoàng.",key_text:"黄帝曰：凡学士精心愿乐，勤道求生",use:"Trai nghi Tam Hoàng, chế tín vật, cầu tiên",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E4%B8%89%E7%9A%87%E5%AF%B6%E9%BD%8B%E7%A5%9E%E4%BB%99%E4%B8%8A%E9%8C%84%E7%B6%93","https://ctext.org/wiki.pl?if=gb&res=521411","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch56b · Grok-4.5 focused 洞神core"},{dz:"DZ855",name_han:"太清金阙玉华仙书八极神章三皇内秘文",name_vi:"Thái Thanh Kim Khuyết Ngọc Hoa Tiên Thư Bát Cực Thần Chương Tam Hoàng Nội Bí Văn",bu:"洞神",author:"佚名",era:"唐宋",topic:"方术",essence:"Văn bí truyền hệ Tam Hoàng, gồm thần chương bát cực và nội văn dùng trong triệu thỉnh, hộ thân, biến hóa. Mang tính phù–chú–lục mạnh, gắn thuật số và hành pháp. Thuộc nhóm phương thuật Động Thần liên quan Tam Hoàng nội văn.",key_text:"null",use:"Phù chú, triệu thỉnh, hành pháp bí truyền",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch56b · Grok-4.5 focused 洞神core"},{dz:"DZ869",name_han:"思印气诀法",name_vi:"Tư Ấn Khí Quyết Pháp",bu:"洞神",author:"佚名",era:"唐–宋",topic:"cultivation",essence:"Pháp quyết kết hợp tư tưởng (tồn tư), ấn quyết và luyện khí. Dạy dùng tâm ấn–thủ ấn phối hợp hô hấp để tụ khí, hộ thân, và hành pháp. Nằm cuối dải phương pháp Động Thần, mang tính thực hành mật truyền.",key_text:"null",use:"Tồn tư, kết ấn, luyện khí hành pháp",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/zh-hans/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch56b · Grok-4.5 focused 洞神core"},{dz:"DZ745",name_han:"南華真經註疏",name_vi:"Nam Hoa Chân Kinh Chú Sớ",bu:"洞神",author:"郭象注、成玄英疏",era:"西晉注／唐初疏（7世紀）",topic:"classic",essence:"Bản chú sớ quan trọng nhất của Trang tử trong Đạo tạng: phần chú của Quách Tượng thuộc huyền học Ngụy–Tấn (độc hóa, tự đắc); sớ của Thành Huyền Anh mở rộng sang trọng huyền (song khiển, huyền chi hựu huyền). Vừa là kinh điển triết học vừa là nền tảng tu dưỡng tọa vong, vô tâm.",key_text:"玄之又玄，遣之又遣。",use:"Đọc khi muốn nắm mạch huyền học–trọng huyền qua chú sớ Trang; đối chiếu với các bản khẩu nghĩa, nghĩa hải đời Tống.",sources:["https://zh.wikisource.org/wiki/%E5%8D%97%E8%8F%AF%E7%9C%9F%E7%B6%93%E8%A8%BB%E7%96%8F","https://www.shidianguji.com/zh/book/DZ0745","https://ctext.org/wiki.pl?if=gb&res=832812"],textual_certainty:"high",notes:"batch57 · Grok-4.5 focused 太玄部"},{dz:"DZ743",name_han:"南華真經新傳",name_vi:"Nam Hoa Chân Kinh Tân Truyền",bu:"洞神",author:"王雱",era:"Bắc Tống (11 thế kỷ)",topic:"classic",essence:"Chú Trang theo thể lệ nghĩa lý kiểu Quách Tượng, không sa vào huấn hỗ từng chữ; mỗi thiên có đề giải tóm đại chỉ. Vương Bàng (con Vương An Thạch) kết hợp Lão–Trang với Phật–Nho, văn gọn mà thiên về siêu việt hình danh.",key_text:"無我則無心，無心則不物於物。",use:"So sánh cách Tống Nho–Đạo đọc Trang với chú sớ Quách/Thành; hữu ích khi nghiên cứu tiếp nhận Trang đời Tống.",sources:["https://www.shidianguji.com/book/DZ0743","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch57 · Grok-4.5 focused 太玄部"},{dz:"DZ735",name_han:"南華真經口義",name_vi:"Nam Hoa Chân Kinh Khẩu Nghĩa",bu:"洞神",author:"林希逸",era:"Nam Tống",topic:"classic",essence:"Bản “khẩu nghĩa” (giảng nghĩa miệng thầy) của Lâm Hy Dật, thuộc truyền thừa Phúc Kiến (Trần Tảo, Lâm Quang Triều). Lời bình bạch, dễ hiểu, thỉnh thoảng dẫn Phật thư để soi Trang, nhấn mạnh đại chỉ hơn là khảo chứng văn tự.",key_text:"null",use:"Bản nhập môn Trang trong Đạo tạng nhờ ngôn ngữ trực bạch; đối chiếu với Nghĩa hải toản vi và chú sớ Thành Huyền Anh.",sources:["https://www.shidianguji.com/book/DZ0735","https://zh.wikisource.org/zh-hans/%E5%8D%97%E8%8F%AF%E7%9C%9F%E7%B6%93%E5%8F%A3%E7%BE%A9","https://ctext.org/wiki.pl?if=gb&res=51376"],textual_certainty:"high",notes:"batch57 · Grok-4.5 focused 太玄部"},{dz:"DZ734",name_han:"南華真經義海纂微",name_vi:"Nam Hoa Chân Kinh Nghĩa Hải Toản Vi",bu:"洞神",author:"褚伯秀",era:"Nam Tống (khoảng 1270)",topic:"classic",essence:"Tập chú quy mô lớn (106 quyển): họp Quách Tượng, Lữ Huệ Khanh, Lâm Nghi Độc, Trần Cảnh Nguyên, Vương Bàng, Lâm Hy Dật… rồi tự thêm “tự thuyết”. Là “biển nghĩa” để so sánh các dòng chú Trang đời Tống và trước đó.",key_text:"null",use:"Tra cứu đối chiếu nhiều nhà chú Trang trong một bản; nguồn chính cho sử chú sớ Nam Hoa.",sources:["https://zh.wikisource.org/wiki/%E5%8D%97%E8%8F%AF%E7%9C%9F%E7%B6%93%E7%BE%A9%E6%B5%B7%E7%BA%82%E5%BE%AE","https://zh.daoinfo.org/index.php?title=%E5%8D%97%E8%8F%AF%E7%9C%9F%E7%B6%93%E7%BE%A9%E6%B5%B7%E7%BA%82%E5%BE%AE%EF%BC%88%E8%A4%9A%E4%BC%AF%E7%A7%80%EF%BC%89","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch57 · Grok-4.5 focused 太玄部"},{dz:"DZ736",name_han:"南華真經章句音義",name_vi:"Nam Hoa Chân Kinh Chương Cú Âm Nghĩa",bu:"洞神",author:"陳景元",era:"Bắc Tống (hoàn thành khoảng 1084)",topic:"classic",essence:"Trần Cảnh Nguyên (Bích Hư tử) chia 33 thiên Trang thành 255 chương, đặt tên theo đại chỉ từng chương, chú trọng âm nghĩa và phân chương. Cùng hệ với các bản chương cú / dư sự của ông, phục vụ đọc–đọc tụng–khảo chứng văn bản.",key_text:"null",use:"Dùng khi cần phân chương, âm nghĩa và cấu trúc câu của Nam Hoa; bổ sung cho chú sớ nghĩa lý.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://en.wikipedia.org/wiki/Glossary_of_Zhuangzi_exegesis"],textual_certainty:"high",notes:"batch57 · Grok-4.5 focused 太玄部"},{dz:"DZ742",name_han:"南華真經循本",name_vi:"Nam Hoa Chân Kinh Tuần Bản",bu:"洞神",author:"羅勉道",era:"Tống–Nguyên",topic:"classic",essence:"Chú Trang theo hướng “tuần bản”: trở về nghĩa gốc văn kinh, giảm pha trộn Phật–Nho quá mức. La Miện Đạo cố gắng giữ mạch nghĩa Lão–Trang thuần hơn so với một số bản khẩu nghĩa đời Tống.",key_text:"null",use:"Đối trọng với các chú Trang “hội thông tam giáo”; đọc khi muốn góc nhìn tuần bản.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","http://www.ctcwri.idv.tw/CTCW-CJNF.htm"],textual_certainty:"high",notes:"batch57 · Grok-4.5 focused 太玄部"},{dz:"DZ731",name_han:"沖虛至德真經解",name_vi:"Xung Hư Chí Đức Chân Kinh Giải",bu:"洞神",author:"江遹",era:"Tống",topic:"classic",essence:"Chú Liệt tử theo phong cách nghĩa lý siêu dật, bắt chước thể lệ Quách Tượng chú Trang hơn là huấn hỗ chi tiết. Nhấn mạnh hư tĩnh, an mệnh, và các ngụ ngôn triết học trong tám thiên Xung Hư.",key_text:"null",use:"Bản chú Liệt tử chính trong Đạo tạng để đọc song song với Nam Hoa chú sớ; hữu ích cho chủ đề an mệnh–tri hư.",sources:["https://zh.daoinfo.org/index.php?title=%E6%B2%96%E8%99%9B%E8%87%B3%E5%BE%B7%E7%9C%9F%E7%B6%93%E8%A7%A3%EF%BC%88%E6%B1%9F%E9%81%B9%EF%BC%89","https://baike.baidu.com/item/%E5%86%B2%E8%99%9A%E8%87%B3%E5%BE%B7%E7%9C%9F%E7%BB%8F%E8%A7%A3/2559314","https://ctext.org/wiki.pl?if=gb&res=327849"],textual_certainty:"high",notes:"batch57 · Grok-4.5 focused 太玄部"},{dz:"DZ733",name_han:"沖虛至德真經四解",name_vi:"Xung Hư Chí Đức Chân Kinh Tứ Giải",bu:"洞神",author:"高守元（集）",era:"Kim",topic:"classic",essence:"Tập hợp bốn hệ giải Liệt tử (thường gồm Trương Trạm, Lư Trọng Huyền và các chú Tống) thành “tứ giải”, 20 quyển. Cho phép so sánh lớp lớp nghĩa huyền học–Đạo giáo trên cùng một đoạn kinh.",key_text:"null",use:"Bản đối chiếu nhiều chú Liệt trong một sách; dùng khi làm chú giải so sánh hoặc tra cứu dị giải.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf"],textual_certainty:"high",notes:"batch57 · Grok-4.5 focused 太玄部"},{dz:"DZ747",name_han:"洞靈真經註",name_vi:"Động Linh Chân Kinh Chú",bu:"洞神",author:"何璨",era:"Đường–Tống (khoảng thế kỷ 10)",topic:"classic",essence:"Chú bản Động Linh chân kinh (tức Kháng Thương tử / Canh Tang tử)—một trong “tứ tử chân kinh” đời Đường. Nội dung thiên về đạo trị, nông, binh, hiền thần; chú của Hà Xán làm rõ lớp nghĩa chính trị–đạo thuật gắn với truyền thống Lão–Trang.",key_text:"null",use:"Hoàn thiện bộ tứ tử (Trang–Liệt–Văn–Kháng Thương) trong Đạo tạng; đọc khi nghiên cứu “tứ tử chân kinh” thời Đường.",sources:["https://zh.daoinfo.org/index.php?title=%E6%B4%9E%E9%9D%88%E7%9C%9F%E7%B6%93%E6%B3%A8%EF%BC%88%E4%BD%95%E7%92%A8%EF%BC%89","https://ctext.org/library.pl?if=en&res=84425","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch57 · Grok-4.5 focused 太玄部"},{dz:"DZ1028",name_han:"無能子",name_vi:"Vô Năng Tử",bu:"太玄",author:"無能子（ẩn danh）",era:"Đường mạt (khoảng 887)",topic:"philosophy",essence:"Tác phẩm triết học Đạo gia cuối Đường, 3 quyển 34 thiên, viết trong loạn Hoàng Sào. Chủ trương vô tâm, nhậm vận, phê phán “thánh quá” và phân biệt sang hèn; giọng điệu phê phán xã hội mạnh trong dòng tử thư Đạo.",key_text:"null",use:"Đọc như tử thư Đạo phê phán sau loạn lạc; so với Hóa thư, Tọa vong về vô vi–vô tâm.",sources:["https://www.shidianguji.com/book/DZ1028","https://zh.daoinfo.org/index.php?title=%E7%84%A1%E8%83%BD%E5%AD%90","https://ctext.org/library.pl?if=gb&res=84704"],textual_certainty:"high",notes:"batch57 · Grok-4.5 focused 太玄部"},{dz:"DZ1029",name_han:"玄真子外篇",name_vi:"Huyền Chân Tử Ngoại Thiên",bu:"太玄",author:"張志和",era:"Đường (thế kỷ 8)",topic:"philosophy",essence:"Tác phẩm còn lại (3 thiên: Bích Hư, Nhạc Chước, Đào chi linh) của Trương Chí Hòa (Yên Ba điếu đồ). Luận về nhất thể hóa sai biệt, không phân mỹ–xấu, thiện–ác; phong vị triết học–văn chương gần Lão–Trang và ẩn dật.",key_text:"null",use:"Đọc như tử thư ẩn sĩ Đường; bổ sung cho dòng “tử” trong Thái huyền bộ ngoài tứ tử.",sources:["https://www.shidianguji.com/book/DZ1029","https://baike.baidu.com/item/%E7%8E%84%E7%9C%9F%E5%AD%90%E5%A4%96%E7%AF%87/20112990","https://zh.daoinfo.org/wiki/%E7%8E%84%E7%9C%9F%E5%AD%90%E5%A4%96%E7%AF%87"],textual_certainty:"high",notes:"batch57 · Grok-4.5 focused 太玄部"},{dz:"DZ1027",name_han:"素履子",name_vi:"Tố Lý Tử",bu:"太玄",author:"張弧",era:"Đường",topic:"philosophy",essence:"Tử thư 3 quyển trong Thái huyền bộ, lấy tượng “tố lý” (đi trên đường giản dị ngay thẳng) để bàn đạo xử thế–tu thân theo tinh thần Dịch–Đạo. Thuộc nhóm tử thư triết lý được đưa vào Đạo tạng cùng Vô Năng, Huyền Chân.",key_text:"null",use:"Đọc trong chùm tử thư Thái huyền (cùng Vô Năng tử, Huyền Chân tử) về đạo xử thế–hành đạo.",sources:["https://louiskomjathy.com/wp-content/uploads/2022/01/DaozangYaojiXuankanIndex_Komjathy.pdf","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch57 · Grok-4.5 focused 太玄部"},{dz:"DZ1038",name_han:"心目論",name_vi:"Tâm Mục Luận",bu:"太玄",author:"吳筠",era:"Đường (thế kỷ 8)",topic:"cultivation",essence:"Đối thoại giữa Tâm và Mục: mắt kéo ra ngoài dục cảnh, tâm phải làm chủ để trở về hư tĩnh. Ngô Quân (Tông Huyền tiên sinh) nối mạch tọa vong–thanh tĩnh đời Đường, nhấn mạnh thu nhiếp căn trần trong tu dưỡng.",key_text:"null",use:"Đọc như luận ngắn về thu tâm–chế dục; cặp với Tọa vong luận, Thiên Ẩn tử (đã cover) trong hệ Ngô Quân–Tư Mã Thừa Trinh.",sources:["https://ctext.org/library.pl?if=en&res=84714","https://blackmoonharbor.com/uploads/1/1/5/3/115363763/daoist_texts_in_translation._komjathy.pdf"],textual_certainty:"high",notes:"batch57 · Grok-4.5 focused 太玄部"},{dz:"DZ1102",name_han:"太平經聖君秘旨",name_vi:"Thái Bình Kinh Thánh Quân Bí Chỉ",bu:"太平",author:"傳閭丘方遠節錄（原題傳上相青童君）",era:"唐末五代（約9–10世紀）",topic:"cultivation",essence:"Đây là bản trích yếu trọng tâm từ truyền thống Thái Bình, tập trung vào pháp «thủ nhất» (守一) và quan hệ tinh–khí–thần. Văn bản cô đọng triết lý trị bình và dưỡng sinh của Thái Bình Kinh thành chỉ quyết thực tu. Đây là cầu nối giữa kinh Thái Bình cổ và hệ tu trì đời sau.",key_text:"一之為本，萬事皆行；子知一，萬事畢矣。",use:"Nghiên cứu pháp thủ nhất Thái Bình; đối chiếu với Thái Bình Kinh/Thái Bình Kinh Sao; khung lý luận dưỡng sinh tinh–khí–thần.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://ctext.org/library.pl?if=gb&res=84778","https://zh.wikisource.org/wiki/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch58 · Grok-4.5 focused 太平部/类书"},{dz:"DZ1107",name_han:"太上靈寶首入淨明四規明鑑經",name_vi:"Thái Thượng Linh Bảo Thủ Nhập Tịnh Minh Tứ Quy Minh Giám Kinh",bu:"太平",author:"Tịnh Minh phái (tương truyền liên hệ Hứa Tốn hệ)",era:"Tống (thế kỷ 12–13)",topic:"philosophy",essence:"Kinh nhập môn Tịnh Minh, đặt «tứ quy minh giám» làm chuẩn đạo đức–tu luyện. Nhấn mạnh trung hiếu, thanh tĩnh và soi xét nội tâm như gương sáng. Là cầu nối giữa giáo nghĩa Tịnh Minh và thực hành hàng ngày.",key_text:"null",use:"Nhập môn giáo nghĩa Tịnh Minh; đối chiếu với Tịnh Minh trung hiếu toàn thư và các kinh Tịnh Minh khác.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E9%9D%88%E5%AF%B6%E9%A6%96%E5%85%A5%E6%B7%A8%E6%98%8E%E5%9B%9B%E8%A6%8F%E6%98%8E%E9%91%91%E7%B6%93","https://zh.wikisource.org/wiki/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch58 · Grok-4.5 focused 太平部/类书"},{dz:"DZ1109",name_han:"太上靈寶淨明中黃八柱經",name_vi:"Thái Thượng Linh Bảo Tịnh Minh Trung Hoàng Bát Trụ Kinh",bu:"太平",author:"Tịnh Minh phái",era:"Tống",topic:"cultivation",essence:"Kinh Tịnh Minh lấy «trung hoàng» và «bát trụ» làm khung vững chắc cho thân–tâm–giáo. Kết hợp hình ảnh vũ trụ nội tại với chuẩn mực trung chính. Bổ sung chiều kích khí pháp/cấu trúc cho hệ Tịnh Minh.",key_text:"null",use:"Nghiên cứu khí luận và khung «bát trụ» Tịnh Minh; ghép với tứ quy minh giám.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E9%9D%88%E5%AF%B6%E6%B7%A8%E6%98%8E%E4%B8%AD%E9%BB%83%E5%85%AB%E6%9F%B1%E7%B6%93","https://zh.wikisource.org/wiki/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch58 · Grok-4.5 focused 太平部/类书"},{dz:"DZ1115",name_han:"太上洞玄靈寶本行因緣經",name_vi:"Thái Thượng Động Huyền Linh Bảo Bản Hành Nhân Duyên Kinh",bu:"太平",author:"Linh Bảo hệ (cổ Linh Bảo, Lục triều)",era:"Nam–Bắc triều (thế kỷ 4–5)",topic:"philosophy",essence:"Cặp với Bản Hành Túc Duyên, giải thích nhân duyên bản hành của đạo sĩ và chúng sinh. Nhấn mạnh nghiệp–duyên, công đức và đường trở về đạo. Là kinh giáo nghĩa quan trọng của cổ Linh Bảo về «vì sao phải tu».",key_text:"null",use:"Đọc cặp với Bản Hành Túc Duyên; nghiên cứu nhân duyên luận Linh Bảo.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E6%9C%AC%E8%A1%8C%E5%9B%A0%E7%B7%A3%E7%B6%93","https://zh.wikisource.org/wiki/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch58 · Grok-4.5 focused 太平部/类书"},{dz:"DZ1120",name_han:"太上洞玄靈寶中和經",name_vi:"Thái Thượng Động Huyền Linh Bảo Trung Hòa Kinh",bu:"太平",author:"Linh Bảo/Thăng Huyền hệ",era:"Lục triều–Đường",topic:"philosophy",essence:"Kinh lấy «trung hòa» làm gốc điều hòa thiên–địa–nhân và thân–tâm. Liên hệ mật thiết với Thăng Huyền nội giáo và các sớ nghị về trung hòa. Đại diện hướng đạo giáo nghĩa lý quân bình, không cực đoan hữu/không.",key_text:"null",use:"Nghiên cứu khái niệm trung hòa trong Linh Bảo–Thăng Huyền; đọc cùng sớ nghị DZ1122.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E4%B8%AD%E5%92%8C%E7%B6%93","https://zh.wikisource.org/wiki/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch58 · Grok-4.5 focused 太平部/类书"},{dz:"DZ1131",name_han:"太上妙法本相經",name_vi:"Thái Thượng Diệu Pháp Bản Tướng Kinh",bu:"太平",author:"khuyết danh",era:"Đường hoặc trước",topic:"philosophy",essence:"Kinh bàn về «bản tướng» diệu pháp—tướng gốc của đạo và các pháp môn. Thuộc lớp nghĩa lý tổng quát trong Thái Bình bộ, bổ sung cho hệ bách khoa/định nghĩa khái niệm. Hữu ích khi dựng bản đồ thuật ngữ đạo giáo trung cổ.",key_text:"null",use:"Thuật ngữ học đạo giáo; đối chiếu với loại thư định nghĩa như Đạo giáo nghĩa xu/Đạo điển luận.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E5%A6%99%E6%B3%95%E6%9C%AC%E7%9B%B8%E7%B6%93","https://zh.wikisource.org/wiki/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch58 · Grok-4.5 focused 太平部/类书"},{dz:"DZ1133",name_han:"上方靈寶無極至道開化真經",name_vi:"Thượng Phương Linh Bảo Vô Cực Chí Đạo Khai Hóa Chân Kinh",bu:"太平",author:"khuyết danh",era:"Tống hoặc trước",topic:"philosophy",essence:"Kinh «khai hóa» vô cực chí đạo, trình bày đạo như nguồn giáo hóa phổ quát. Nằm cụm Thượng Phương Linh Bảo trong Thái Bình bộ, nghiêng về nghĩa lý vũ trụ–giáo hóa. Cùng hệ với Thượng Phương quân thiên diễn phạm chân kinh.",key_text:"null",use:"Vũ trụ luận và giáo hóa luận; đọc cặp DZ1134.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/wiki/%E4%B8%8A%E6%96%B9%E9%9D%88%E5%AF%B6%E7%84%A1%E6%A5%B5%E8%87%B3%E9%81%93%E9%96%8B%E5%8C%96%E7%9C%9F%E7%B6%93","https://zh.wikisource.org/wiki/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch58 · Grok-4.5 focused 太平部/类书"},{dz:"DZ1135",name_han:"太平兩同書",name_vi:"Thái Bình Lưỡng Đồng Thư",bu:"太平",author:"羅隱（一說吳筠）",era:"Đường mạt (thế kỷ 9)",topic:"philosophy",essence:"Mười cặp đối lập (quý tiện, cường nhược, lợi tổn…) được luận theo tinh thần «lưỡng giả đồng xuất nhi dị danh». Kết hợp Nho–Đạo để nói thống nhất mâu thuẫn và trị thế. Tên «Thái Bình» khớp bộ Thái Bình và chủ đề trị bình.",key_text:"夫一氣所化，陽尊而陰卑；三才肇分，天高而地下。",use:"Triết học đối đãi–thống nhất; tư tưởng chính trị–đạo giáo Đường mạt; đối chiếu Đạo Đức Kinh.",sources:["https://www.shidianguji.com/book/DZ1135","https://zh.wikisource.org/wiki/%E5%A4%AA%E5%B9%B3%E5%85%A9%E5%90%8C%E6%9B%B8","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch58 · Grok-4.5 focused 太平部/类书"},{dz:"DZ1136",name_han:"洞玄靈寶左玄論",name_vi:"Động Huyền Linh Bảo Tả Huyền Luận",bu:"太平",author:"khuyết danh",era:"Đường–Tống",topic:"philosophy",essence:"Luận «tả huyền» trong khung Linh Bảo, triển khai nghĩa lý huyền học theo hướng biện giải. Thuộc lớp luận thuyết nghĩa lý Thái Bình bộ, gần các văn bản Trùng Huyền/huyền đàm. Bổ sung cho hệ luận–sớ không chỉ kinh–khoa.",key_text:"null",use:"Huyền học và biện luận đạo; đọc cùng Bản Tế, Đạo thể luận, Tam luận nguyên chỉ.",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/wiki/%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E5%B7%A6%E7%8E%84%E8%AB%96","https://zh.wikisource.org/wiki/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F"],textual_certainty:"high",notes:"batch58 · Grok-4.5 focused 太平部/类书"},{dz:"DZ092",name_han:"元始无量度人上品妙经注解（薛季昭）",name_vi:"Nguyên Thủy Vô Lượng Độ Nhân Thượng Phẩm Diệu Kinh Chú Giải (Tiết Quý Chiêu)",bu:"洞真",author:"薛季昭",era:"元（大德）",topic:"注疏",essence:"Chú Độ Nhân Kinh theo hướng cổ chú, giải chữ nghĩa và chương cú rõ ràng, dễ tụng đọc. Không nghiêng mạnh nội đan như các chú Nam Tống, mà tổng hợp tiền nhân thành một nhà. Có tiến kinh biểu và hậu ký về dòng truyền.",key_text:"天不爱道，世得见经。",use:"Nhập môn tụng và hiểu nghĩa đen Độ Nhân Kinh.",sources:["https://zh.daoinfo.org/index.php?title=%E5%85%83%E5%A7%8B%E7%84%A1%E9%87%8F%E5%BA%A6%E4%BA%BA%E4%B8%8A%E5%93%81%E5%A6%99%E7%B6%93%E8%A8%BB%E8%A7%A3&variant=zh-hans","https://www.shidianguji.com/book/DZ0092","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT01%E6%B4%9E%E7%9C%9F%E9%83%A8/CMT0103%E7%8E%89%E8%A8%A3%E9%A1%9E/CMT0103ALL/CH010307%E5%85%83%E5%A7%8B%E7%84%A1%E9%87%8F%E5%BA%A6%E4%BA%BA%E4%B8%8A%E5%93%81%E5%A6%99%E7%B6%93%E8%A8%BB%E8%A7%A3/CH010307-1%E5%8D%B7%E4%B8%8A.htm"],textual_certainty:"high",notes:"batch59 · Grok-4.5 focused 经典注疏"},{dz:"DZ093",name_han:"太上洞玄灵宝无量度人上品经法（陈椿荣）",name_vi:"Thái Thượng Động Huyền Linh Bảo Vô Lượng Độ Nhân Thượng Phẩm Kinh Pháp (Trần Xuân Vinh)",bu:"洞真",author:"陈椿荣",era:"北宋末–南宋",topic:"注疏",essence:"Tập chú–giải pháp tụng Độ Nhân Kinh theo hướng nội tu và chỉ quyết. Chia đoạn chú chi tiết, kèm quẻ, đồ, phù chú và khẩu quyết. Ảnh hưởng lớn đến các chú sau như Tiêu Ứng Sẩu, Thanh Nguyên chân nhân, Trương Vũ Sơ.",key_text:"政和御注",use:"Nghiên cứu nghi tụng và pháp môn nội tu gắn với Độ Nhân.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E7%84%A1%E9%87%8F%E5%BA%A6%E4%BA%BA%E4%B8%8A%E5%93%81%E7%B6%93%E6%B3%95&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&res=948278&remap=gb","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT01%E6%B4%9E%E7%9C%9F%E9%83%A8/CMT0103%E7%8E%89%E8%A8%A3%E9%A1%9E/CMT0103ALL/CH010308%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E7%84%A1%E9%87%8F%E5%BA%A6%E4%BA%BA%E4%B8%8A%E5%93%81%E5%A6%99%E7%B6%93%E6%B3%95/CH010308-5%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E7%84%A1%E9%87%8F%E5%BA%A6%E4%BA%BA%E4%B8%8A%E5%93%81%E7%B6%93%E6%B3%95%E5%8D%B7%E4%B9%8B%E4%BA%94.htm"],textual_certainty:"high",notes:"batch59 · Grok-4.5 focused 经典注疏"},{dz:"DZ113",name_han:"黄帝阴符经解（蹇昌辰）",name_vi:"Hoàng Đế Âm Phù Kinh Giải (Kiển Xương Thần)",bu:"洞真",author:"蹇昌辰",era:"北宋",topic:"注疏",essence:"Giải Âm Phù theo hư tĩnh tự nhiên của Lão học, kết hợp dưỡng sinh và cơ trời–việc người. Dùng bản hơn bốn trăm chữ, chia chương; cho rằng ba trăm lời do Huyền Nữ trao, trăm lời do Hoàng Đế diễn. Nhấn mạnh “lý quy ư tự đắc”.",key_text:"藏微隐妙，该天括地，其经简，其义深，理归于自得者也。",use:"Đọc Âm Phù theo hướng triết–dưỡng sinh Bắc Tống.",sources:["https://zh.daoinfo.org/index.php?title=%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93%E8%A7%A3%EF%BC%88%E8%B9%87%E6%98%8C%E8%BE%B0%EF%BC%89&variant=zh-hans","https://zh.wikisource.org/wiki/%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93%E8%A7%A3","http://simple.taolibrary.com/category/category94/c94015.htm"],textual_certainty:"high",notes:"batch59 · Grok-4.5 focused 经典注疏"},{dz:"DZ114",name_han:"黄帝阴符经注解（任照一）",name_vi:"Hoàng Đế Âm Phù Kinh Chú Giải (Nhậm Chiếu Nhất)",bu:"洞真",author:"任照一",era:"北宋",topic:"注疏",essence:"Chú bản ba trăm chữ, không chia chương; định nghĩa “âm” là ẩn, “phù” là hợp, tức thiên đạo và nhân đạo ngầm khớp. Lấy “quan thiên chi đạo, chấp thiên chi hành” làm cương lĩnh tu hành và dụng thế.",key_text:"阴者，暗也；符者，合也。",use:"Hiểu khung thiên–nhân hợp nhất của Âm Phù.",sources:["https://www.shidianguji.com/book/DZ0114","https://ctext.org/wiki.pl?if=gb&chapter=584390&remap=gb","https://zh.wikisource.org/zh-hans/%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93"],textual_certainty:"high",notes:"batch59 · Grok-4.5 focused 经典注疏"},{dz:"DZ115",name_han:"黄帝阴符经注（黄居真）",name_vi:"Hoàng Đế Âm Phù Kinh Chú (Hoàng Cư Chân)",bu:"洞真",author:"黄居真",era:"宋",topic:"注疏",essence:"Chú Âm Phù một quyển trong Động chân bộ ngọc quyết loại. Giải theo mạch đạo gia dụng cơ và tu thân, bổ sung dải chú Tống đại cạnh Kiển Xương Thần và Nhậm Chiếu Nhất.",key_text:"观天之道，执天之行，尽矣。",use:"Đối chiếu chú Tống về Âm Phù.",sources:["https://zh.daoinfo.org/index.php?title=%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93%E8%A8%BB%EF%BC%88%E9%BB%83%E5%B1%85%E7%9C%9F%EF%BC%89&variant=zh-hans","https://baike.baidu.com/item/%E9%81%93%E8%97%8F%E7%9B%AE%E5%BD%95/1989063","https://a.daorenjia.com/c17"],textual_certainty:"high",notes:"batch59 · Grok-4.5 focused 经典注疏"},{dz:"DZ116",name_han:"黄帝阴符经注（沈亚夫）",name_vi:"Hoàng Đế Âm Phù Kinh Chú (Thẩm Á Phu)",bu:"洞真",author:"沈亚夫",era:"北宋",topic:"注疏",essence:"Chú chia ba chương, cùng dòng với các chú Tống lấy cơ trời–đạo thuật làm trục. Thường được in chung hệ với chú Thái thị; nhấn mạnh động tĩnh và dụng cơ.",key_text:"天性，人也；人心，机也。",use:"So sánh chú chia chương với các bản không chia chương.",sources:["https://zh.daoinfo.org/index.php?title=%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93%E6%B3%A8%EF%BC%88%E6%B2%88%E4%BA%9E%E5%A4%AB%EF%BC%89&variant=zh-hans","http://www.taolibrary.com/category/category94/c94003.htm","https://zh.wikisource.org/zh-hans/%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93"],textual_certainty:"high",notes:"batch59 · Grok-4.5 focused 经典注疏"},{dz:"DZ118",name_han:"黄帝阴符经解义（萧真宰）",name_vi:"Hoàng Đế Âm Phù Kinh Giải Nghĩa (Tiêu Chân Tể)",bu:"洞真",author:"萧真宰",era:"宋",topic:"注疏",essence:"Giải nghĩa theo lối nghĩa lý sâu, dùng hình ảnh “tam đạo” (trời–vật–người) và phân biệt tặc/đạo để bàn dưỡng tính toàn chân. Bản hiện tồn khuyết chú thượng chương nhưng vẫn là chú sớ quan trọng thời Tống.",key_text:"盖养性全真之道，在于无失其则而已。",use:"Đọc Âm Phù theo hướng nghĩa lý và đạo sinh.",sources:["https://zh.daoinfo.org/index.php?title=%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93%E8%A7%A3%E7%BE%A9%EF%BC%88%E8%95%AD%E7%9C%9F%E5%AE%B0%EF%BC%89&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&chapter=787120&remap=gb","https://zh.wikisource.org/wiki/%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93%E8%A7%A3%E7%BE%A9"],textual_certainty:"high",notes:"batch59 · Grok-4.5 focused 经典注疏"},{dz:"DZ119",name_han:"阴符经三皇玉诀（原题轩辕黄帝）",name_vi:"Âm Phù Kinh Tam Hoàng Ngọc Quyết (nguyên đề Hiên Viên Hoàng Đế)",bu:"洞真",author:"金人託名轩辕黄帝（广成子、天真皇人答问体）",era:"金",topic:"注疏",essence:"Hình thức vấn đáp: Hoàng Đế hỏi, Quảng Thành Tử và Thiên Chân Hoàng Nhân giải. Chia ba quyển Thiên–Địa–Nhân hoàng, cốt lõi luyện tinh khí thần và nội đan trường sinh. Là chú sớ giả thác nhưng có mặt trong Đạo tạng và được dẫn từ đời Kim.",key_text:"观天之道，执天之行，尽矣。",use:"Nghiên cứu Âm Phù theo khung tam hoàng và nội đan.",sources:["https://zh.daoinfo.org/index.php?title=%E9%99%B0%E7%AC%A6%E7%B6%93%E4%B8%89%E7%9A%87%E7%8E%89%E8%A8%A3%EF%BC%88%E5%8E%9F%E9%A1%8C%E8%BB%92%E8%BD%85%E9%BB%83%E5%B8%9D%EF%BC%89&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93"],textual_certainty:"high",notes:"batch59 · Grok-4.5 focused 经典注疏"},{dz:"DZ121",name_han:"黄帝阴符经注（唐淳）",name_vi:"Hoàng Đế Âm Phù Kinh Chú (Đường Thuần)",bu:"洞真",author:"唐淳（金陵道人）",era:"宋金之际",topic:"注疏",essence:"Dùng bản khoảng năm trăm chữ, chia ba chương; trước dẫn tiền nhân, sau phụ kiến riêng, chủ nội đan. Có tự năm Chính Đại Kỷ Sửu (1229), phản ánh dòng chú toàn chân–nội đan.",key_text:"观天之道，执天之行，尽矣。",use:"Đọc Âm Phù theo nội đan Tống–Kim.",sources:["https://zh.daoinfo.org/index.php?title=%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93%E6%B3%A8%EF%BC%88%E5%94%90%E6%B7%B3%EF%BC%89&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93"],textual_certainty:"high",notes:"batch59 · Grok-4.5 focused 经典注疏"},{dz:"DZ126",name_han:"黄帝阴符经夹颂解注（王道渊）",name_vi:"Hoàng Đế Âm Phù Kinh Giáp Tụng Giải Chú (Vương Đạo Uyên)",bu:"洞真",author:"王道渊（王玠，混然子）",era:"元",topic:"注疏",essence:"Chú kèm tụng, lấy âm dương–thái cực làm then chốt giải “âm phù”. Bản hơn bốn trăm chữ, chia quyển không chia chương; kết hợp giải nghĩa và kệ tụng để truyền nội đan.",key_text:"夫阴符者，一阴一阳之谓也。",use:"Tu và tụng Âm Phù theo dòng hỗn nhiên tử.",sources:["https://zh.daoinfo.org/index.php?title=%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93%E5%A4%BE%E9%A0%8C%E8%A7%A3%E8%A8%BB%EF%BC%88%E7%8E%8B%E9%81%93%E6%B7%B5%EF%BC%89&variant=zh-hans","http://www.taolibrary.com/category/category94/c94009.htm","https://a.daorenjia.com/daozang17-758"],textual_certainty:"high",notes:"batch59 · Grok-4.5 focused 经典注疏"},{dz:"DZ752",name_han:"太上老君说常清静经注（王元晖）",name_vi:"Thái Thượng Lão Quân Thuyết Thường Thanh Tịnh Kinh Chú (Vương Nguyên Huy)",bu:"洞神",author:"王元晖（白玉蟾分章正误）",era:"元（皇庆元年前后）",topic:"注疏",essence:"Dựa bản Bạch Ngọc Thiềm chia năm chương (tiên thiên đại đạo, tạo hóa tự nhiên…), chú bằng ngữ nội đan và đồ giải. Giải Thanh Tĩnh Kinh thành khẩu quyết tu tâm hợp đạo, không chỉ nghĩa văn.",key_text:"太者，无也；上者，极也；说者，开化也。常清静者，虚无大道，自然生成。",use:"Tu tính–mệnh qua Thanh Tĩnh theo Nam tông–toàn chân.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E5%B8%B8%E6%B8%85%E9%9D%9C%E7%B6%93%E8%A8%BB%EF%BC%88%E7%8E%8B%E5%85%83%E6%9A%89%EF%BC%89&variant=zh-hans","https://www.shidianguji.com/zh/book/DZ0757","https://ctext.org/library.pl?if=gb&res=84436&remap=gb"],textual_certainty:"high",notes:"batch59 · Grok-4.5 focused 经典注疏"},{dz:"DZ968",name_han:"太上老君说常清静经颂注（刘通微）",name_vi:"Thái Thượng Lão Quân Thuyết Thường Thanh Tịnh Kinh Tụng Chú (Lưu Thông Vi)",bu:"洞神",author:"刘通微（默然子）",era:"金",topic:"注疏",essence:"Chú bằng ngũ ngôn tụng, dung hợp đạo–thiền: trừng tâm khiển dục, thanh tĩnh thường tịch. Khuyên bỏ tham sân si, tu giới định tuệ để lục dục bất sinh. Thể loại tụng chú khác hẳn các chú văn xuôi.",key_text:"大道无形，生育天地。",use:"Tụng niệm và tu tâm theo lối toàn chân.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E5%B8%B8%E6%B8%85%E9%9D%9C%E7%B6%93%E9%A0%8C%E8%A8%BB%EF%BC%88%E5%8A%89%E9%80%9A%E5%BE%AE%EF%BC%89&variant=zh-hans","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT03%E6%B4%9E%E7%A5%9E%E9%83%A8/CMT0311%E8%AE%9A%E9%A0%8C%E9%A1%9E/CMT0311ALL/CH031101%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E5%B8%B8%E6%B8%85%E9%9D%9C%E7%B6%93%E9%A0%8C%E8%A8%BB/CH031101-1%E5%A4%AA%E4%B8%8A%E8%80%81%E5%90%9B%E8%AA%AA%E5%B8%B8%E6%B8%85%E9%9D%9C%E7%B6%93%E9%A0%8C%E8%A8%BB.htm","https://ctext.org/wiki.pl?if=gb&res=876387&remap=gb"],textual_certainty:"high",notes:"batch59 · Grok-4.5 focused 经典注疏"},{dz:"DZ024",name_han:"元始天尊說生天得道經",name_vi:"Nguyên Thủy Thiên Tôn Thuyết Sinh Thiên Đắc Đạo Kinh",bu:"洞真",author:"佚名",era:"唐–宋 / 約7–12 thế kỷ",topic:"经典",essence:"Nguyên Thủy Thiên Tôn tại Đại La thiên, Ngọc Kinh sơn, giảng pháp môn “sinh thiên đắc đạo”: tĩnh lục căn, tịnh bát thức, không ngũ uẩn, chứng diệu tam nguyên. Kinh ngắn nhưng cô đọng tư tưởng nội quan – hư tĩnh để siêu sinh. Có bản tụng giải (Sinh Thiên Kinh Tụng Giải) chứng tỏ từng được dùng trong tu trì và độ vong nhẹ.",key_text:"安寂六根，淨照八識，空其五蘊，證妙三元",use:"Tụng tĩnh tâm, tu “sinh thiên”, hỗ trợ độ vong nhẹ và công khóa",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.daoist.org/BookSearch(test)/list010.asp?Page=61","https://zh.wikisource.org/zh-hans/Page:Gujin_Tushu_Jicheng,_Volume_511_(1700-1725).djvu/28","https://homeinmists.ilotus.org/%E4%B8%B9%E7%B6%93%E9%81%93%E6%9B%B8/%E5%85%B6%E4%BB%96%E4%B8%B9%E7%B6%93%E9%81%93%E6%9B%B8%E7%AD%89/%E3%80%8A%E6%B8%85%E9%9D%9C%E7%B6%93%E3%80%8B%E6%96%87%E6%9C%AC%E6%A0%A1%E8%A8%82/%E5%A4%AA%E4%B8%8A%E5%A4%A9%E5%B0%8A%E8%AA%AA%E7%94%9F%E5%A4%A9%E5%BE%97%E9%81%93%E7%B6%93/"],textual_certainty:"high",notes:"batch60 · Grok-4.5 focused 经典本文杂"},{dz:"DZ026",name_han:"太上九天延祥滌厄四聖妙經",name_vi:"Thái Thượng Cửu Thiên Diên Tường Địch Ách Tứ Thánh Diệu Kinh",bu:"洞真",author:"佚名",era:"宋 / 約10–13 thế kỷ",topic:"经典",essence:"Nguyên Thủy Thiên Tôn tại Thủy Thanh thiên giảng về “Tứ Thánh” hộ pháp, trừ tà, địch ách và diên tường. Chỉ ra tai nạn do tham tranh, khẩu thị tâm phi, đố kỵ; khuyên trì tụng, mật niệm văn chú để Tứ Tướng cứu hộ. Có phù trong bản tạng; dùng trong nghi cầu an, trừ tà, ít phổ biến hơn Bắc Đẩu hay Cứu Khổ.",key_text:"爾時，元始天尊在始青天中，玉都之闕，靈臺之上，放五色光明",use:"Tụng trừ tà, địch ách, cầu an; nghi thỉnh Tứ Thánh hộ trì",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E4%B9%9D%E5%A4%A9%E5%BB%B6%E7%A5%A5%E6%BB%8C%E5%8E%84%E5%9B%9B%E8%81%96%E5%A6%99%E7%B6%93&variant=zh-hant","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT01%E6%B4%9E%E7%9C%9F%E9%83%A8/CMT0101%E6%9C%AC%E6%96%87%E9%A1%9E/CMT0101ALL/CNDZ010126%E5%A4%AA%E4%B8%8A%E4%B9%9D%E5%A4%A9%E5%BB%B6%E7%A5%A5%E6%BB%8C%E5%8E%84%E5%9B%9B%E8%81%96%E5%A6%99%E7%B6%93.htm","https://www.daoist.org/BookSearch(test)/list010.asp?Page=61"],textual_certainty:"high",notes:"batch60 · Grok-4.5 focused 经典本文杂"},{dz:"DZ065",name_han:"太上真一報父母恩重經",name_vi:"Thái Thượng Chân Nhất Báo Phụ Mẫu Ân Trọng Kinh",bu:"洞真",author:"佚名",era:"隋唐 / 約6–9 thế kỷ",topic:"经典",essence:"Nguyên Thủy Thiên Tôn kể cho Thượng Trí tiên nhân về ân nặng cha mẹ: ký thai, nuôi dưỡng, lo lắng. Khuyên con cái lập trai, tụng kinh, tạo công đức để báo ân, tiêu tai và siêu độ song thân đã mất. Là bản “báo phụ mẫu ân trọng” chính thống của Động Chân, khác với các bản dân gian sau này.",key_text:"null",use:"Báo hiếu, cầu an cho cha mẹ, siêu độ song thân, nghi hiếu đạo",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E7%9C%9F%E4%B8%80%E5%A0%B1%E7%88%B6%E6%AF%8D%E6%81%A9%E9%87%8D%E7%B6%93&variant=zh-hant","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT01%E6%B4%9E%E7%9C%9F%E9%83%A8/CMT0101%E6%9C%AC%E6%96%87%E9%A1%9E/CMT0101ALL/CNDZ010165%E5%A4%AA%E4%B8%8A%E7%9C%9F%E4%B8%80%E5%A0%B1%E7%88%B6%E6%AF%8D%E6%81%A9%E9%87%8D%E7%B6%93.htm","https://ctext.org/wiki.pl?if=gb&res=382746&remap=gb"],textual_certainty:"high",notes:"batch60 · Grok-4.5 focused 经典本文杂"},{dz:"DZ326",name_han:"太上洞玄靈寶觀妙經",name_vi:"Thái Thượng Động Huyền Linh Bảo Quan Diệu Kinh",bu:"洞玄",author:"佚名",era:"唐–宋 / 約7–12 thế kỷ",topic:"经典",essence:"Kinh ngắn về thiền định Đạo giáo: muốn “quan diệu thành chân” phải bỏ tà hạnh, dứt ngoại sự, chỉ diệt động tâm không diệt tĩnh tâm, ngưng không tâm không ngưng hữu tâm. Mô tả “tâm ngũ thời” và “thân thất hậu” (từ chân định đến luyện thần hợp đạo). Cốt tủy nội tu, triết lý sâu nhưng kinh văn rất ngắn và ít được nhắc rộng.",key_text:"夫欲觀妙成真，先去邪僻之行。外事都絕，然後澄靜其心",use:"Tọa quan, tĩnh tâm, tu định; tham khảo tiến trình “thất hậu” đắc đạo",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E8%A7%80%E5%A6%99%E7%B6%93","https://www.daoist.org/BookSearch(test)/list016.asp?Page=17","http://www.ctcwri.idv.tw/CTCW-HFL/HFL02%E6%B4%9E%E7%8E%84%E9%83%A8/HFL0201%E6%9C%AC%E6%96%87%E9%A1%9E/HFL0201ALL/HFL020110%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E8%A7%80%E5%A6%99%E7%B6%93/0201-079-3-2%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E5%A4%A9%E5%B0%8A%E8%A7%80%E5%A6%99%E7%B6%93.pdf"],textual_certainty:"high",notes:"batch60 · Grok-4.5 focused 经典本文杂"},{dz:"DZ327",name_han:"太上洞玄靈寶天尊說大通經",name_vi:"Thái Thượng Động Huyền Linh Bảo Thiên Tôn Thuyết Đại Thông Kinh",bu:"洞玄",author:"佚名",era:"唐宋 / 約7–12 thế kỷ",topic:"经典",essence:"Kinh cực ngắn (~100 chữ), chia ba chương Chân Không – Huyền Lý – Huyền Diệu, từ phong gần Thanh Tịnh Kinh nhưng độc lập. Nói về tiên thiên vô hình, hậu thiên vô thể, tĩnh là tính, động là tâm; hướng tới “đại thông” huyền diệu bất khả tư nghị. Có chú của Lý Đạo Thuần (Thái Thượng Đại Thông Kinh chú), chứng minh vị thế kinh điển nhỏ trong toàn chân / nội đan.",key_text:"先天而生生而無形後天而存存而無體",use:"Tụng tĩnh tâm, tham huyền, nội quán; đọc kèm chú giải nội đan",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E5%A4%A9%E5%B0%8A%E8%AA%AA%E5%A4%A7%E9%80%9A%E7%B6%93","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B4%9E%E9%9D%88%E5%AF%B6%E5%A4%A9%E5%B0%8A%E8%AA%AA%E5%A4%A7%E9%80%9A%E7%B6%93&variant=zh-hans","http://www.ctcwri.idv.tw/CTCW-HFL/HFL02%E6%B4%9E%E7%8E%84%E9%83%A8/HFL0201%E6%9C%AC%E6%96%87%E9%A1%9E/HFL0201ALL/HFL020111%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E5%A4%A9%E5%B0%8A%E8%AA%AA%E5%A4%A7%E9%80%9A%E7%B6%93/0201-079-3-3%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E5%A4%A9%E5%B0%8A%E8%AA%AA%E5%A4%A7%E9%80%9A%E7%B6%93.pdf"],textual_certainty:"high",notes:"batch60 · Grok-4.5 focused 经典本文杂"},{dz:"DZ625",name_han:"太上說東斗主筭護命妙經",name_vi:"Thái Thượng Thuyết Đông Đẩu Chủ Toán Hộ Mệnh Diệu Kinh",bu:"洞神",author:"佚名（託太上老君授正一天師）",era:"北宋初 / 約10–11 thế kỷ",topic:"经典",essence:"Lão Quân truyền cho Chính Nhất Thiên Sư về Đông Đẩu Đế Quân “chủ toán diên niên”: giám hình hồn, tước tử thượng sinh, độ tam đồ ngũ khổ bát nạn. Liệt năm chân quân Đông Đẩu (Thương Linh Diên Sinh…), hướng dẫn tụng hướng đông, cúng quả hoa, sám tội cầu thọ. Nằm trong hệ Ngũ Đẩu, ít nổi hơn Bắc Đẩu kinh nhưng là bản chính tạng độc lập.",key_text:"吾今復為汝說玉靈瑤篇，東斗帝君之名，主算延年，使傳下世",use:"Tụng cúng Đông Đẩu, cầu thọ, tước tử thượng sinh, sám tội diên mệnh",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%8A%E8%AA%AC%E6%9D%B1%E6%96%97%E4%B8%BB%E7%AE%97%E8%AD%B7%E5%91%BD%E5%A6%99%E7%B6%93","https://www.daoist.org/BookSearch(test)/list016.asp","https://crta.info/wiki/Daozang_-_DZ"],textual_certainty:"high",notes:"batch60 · Grok-4.5 focused 经典本文杂"},{dz:"DZ626",name_han:"太上說西斗記名護身妙經",name_vi:"Thái Thượng Thuyết Tây Đẩu Ký Danh Hộ Thân Diệu Kinh",bu:"洞神",author:"佚名（託太上老君）",era:"北宋初 / 約10–11 thế kỷ",topic:"经典",essence:"Cùng hệ Ngũ Đẩu với Nam–Bắc–Đông–Trung Đẩu: Lão Quân giảng Tây Đẩu “ký danh hộ thân”, ghi tên vào sổ sống, hộ vệ thân thể khỏi tai họa. Thường tụng trong nghi cúng sao, cầu an theo phương vị Tây. Ít được nhắc riêng so với Bắc Đẩu / Nam Đẩu, nhưng là kinh chính thống Động Thần bộ, có DZ# xác nhận trong mục lục Schipper–Pregadio.",key_text:"null",use:"Tụng cúng Tây Đẩu, ký danh hộ thân, cầu an theo phương vị",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://www.daoist.org/BookSearch(test)/list016.asp","https://crta.info/wiki/Daozang_-_DZ","https://zh.wikisource.org/zh-hant/%E5%A4%AA%E4%B8%8A%E8%AA%AC%E6%9D%B1%E6%96%97%E4%B8%BB%E7%AE%97%E8%AD%B7%E5%91%BD%E5%A6%99%E7%B6%93"],textual_certainty:"high",notes:"batch60 · Grok-4.5 focused 经典本文杂"},{dz:"DZ1400",name_han:"上清黄庭养神经",name_vi:"Thượng Thanh Hoàng Đình Dưỡng Thần Kinh",bu:"正一",author:"佚名",era:"唐宋间",topic:"cultivation|黄庭",essence:"Giải “Hoàng Đình diệu nghĩa”, khuyên phụ dưỡng thần, biết động tĩnh xuất xứ để thân tâm an tĩnh. Có phần trích Hoàng Đình nội cảnh bí yếu lục giáp duyên thân và Hoàng Đình kinh quyết. Thuộc hệ giải–quyết nuôi thần theo Hoàng Đình.",key_text:"道言：昔於蕊珠宫中，听闻黄庭妙义。",use:"Luyện dưỡng thần; kết hợp lục giáp–tồn tư.",sources:["https://www.shidianguji.com/zh/book/DZ1400","https://zh.daoinfo.org/index.php?title=%E4%B8%8A%E6%B8%85%E9%BB%83%E5%BA%AD%E9%A4%8A%E7%A5%9E%E7%B6%93&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&chapter=485579"],textual_certainty:"high",notes:"batch61 · Grok-4.5 focused 黄庭经注疏"},{dz:"DZ1402",name_han:"上清黄庭五脏六腑真人玉轴经",name_vi:"Thượng Thanh Hoàng Đình Ngũ Tạng Lục Phủ Chân Nhân Ngọc Trục Kinh",bu:"正一",author:"佚名",era:"唐宋间",topic:"cultivation|黄庭",essence:"Diễn nghĩa Hoàng Đình theo ngũ tạng lục phủ, mỗi tạng có thần chủ và pháp đạo dưỡng. Thiên về dẫn khí–dưỡng tạng hơn chú văn tự từng câu. Là nhánh thực hành tạng phủ của hệ Hoàng Đình.",key_text:"五藏者，五神之府，含生之器。",use:"Đối chiếu tạng thần; luyện đạo dẫn–bổ tả theo tạng.",sources:["https://www.shidianguji.com/book/DZ1402/chapter/DZ1402_1","https://zh.daoinfo.org/index.php?title=%E4%B8%8A%E6%B8%85%E9%BB%83%E5%BA%AD%E5%85%A7%E6%99%AF%E4%BA%94%E8%87%9F%E5%85%AD%E8%85%91%E7%9C%9F%E4%BA%BA%E7%8E%89%E8%BB%B8%E7%B6%93&variant=zh-hans","https://ctext.org/wiki.pl?if=gb&chapter=958802"],textual_certainty:"high",notes:"batch61 · Grok-4.5 focused 黄庭经注疏"},{dz:"null",name_han:"黄庭经秘义（冷谦）",name_vi:"Hoàng Đình Kinh Bí Nghĩa (Lãnh Khiêm)",bu:"续道藏外/藏外",author:"冷谦（澹园）",era:"明",topic:"cultivation|黄庭",essence:"Chú giải Hoàng Đình Nội Cảnh theo hướng đan đạo, văn gọn, nhấn bí quyết tam thừa. Không vào Chính Thống Đạo Tạng; truyền bản in–chép đời sau. Được xếp trong danh sách chú bản Minh quan trọng.",key_text:"黄庭玉经，为仙传秘密之文，原不可注。",use:"Đọc Nội Cảnh theo lối Minh đan; tham chiếu bí nghĩa.",sources:["https://zh.wikisource.org/zh-hans/%E9%BB%83%E5%BA%AD%E7%B6%93%E7%A7%98%E7%BE%A9","https://baike.baidu.com/item/%E9%BB%84%E5%BA%AD%E7%BB%8F/6240400","https://homeinmists.ilotus.org/docs/B001.pdf"],textual_certainty:"high",notes:"batch61 · Grok-4.5 focused 黄庭经注疏"},{dz:"null",name_han:"黄庭内景经秘解（李一元）",name_vi:"Hoàng Đình Nội Cảnh Kinh Bí Giải (Lý Nhất Nguyên)",bu:"续道藏外/藏外",author:"李一元",era:"明",topic:"cultivation|黄庭",essence:"Bản giải Nội Cảnh (và có bản Ngoại Cảnh bí giải) đời Minh, in Vạn Lịch. Thiên “bí giải” mở nghĩa ẩn của tồn thần–luyện khí. Không có DZ Schipper; lưu trong sưu tập đạo thư sau này.",key_text:"null",use:"Đối chiếu chú Minh với Lương Khâu Tử.",sources:["https://homeinmists.ilotus.org/%E4%B8%B9%E7%B6%93%E9%81%93%E6%9B%B8/%E9%BB%83%E5%BA%AD%E7%B6%93/","https://baike.baidu.com/item/%E9%BB%84%E5%BA%AD%E7%BB%8F/6240400","https://homeinmists.ilotus.org/docs/B001.pdf"],textual_certainty:"high",notes:"batch61 · Grok-4.5 focused 黄庭经注疏"},{dz:"null",name_han:"黄庭内景玉经注解（汪旦）",name_vi:"Hoàng Đình Nội Cảnh Ngọc Kinh Chú Giải (Uông Đán)",bu:"续道藏外/藏外",author:"汪旦",era:"明·嘉靖",topic:"cultivation|黄庭",essence:"Hai quyển chú giải Nội Cảnh ngọc kinh, bản khắc Minh Gia Tĩnh. Thuộc dòng chú Nho–Đạo sĩ đại đọc kinh Hoàng Đình. Xác thực qua mục lục sưu tập đạo thư, không có số DZ.",key_text:"null",use:"Đối bản Minh; tra nghĩa từ–câu.",sources:["https://homeinmists.ilotus.org/%E4%B8%B9%E7%B6%93%E9%81%93%E6%9B%B8/%E9%BB%83%E5%BA%AD%E7%B6%93/","https://homeinmists.ilotus.org/%E6%9B%B4%E6%96%B0%E7%B4%80%E9%8C%84/2021%E5%B9%B402%E6%9C%8806%E6%97%A5%E6%9B%B4%E6%96%B0/","https://zh.wikipedia.org/zh-hans/%E9%BB%84%E5%BA%AD%E7%BB%8F"],textual_certainty:"partial",notes:"batch61 · Grok-4.5 focused 黄庭经注疏"},{dz:"null",name_han:"太上黄庭内景玉经童注（邵穆生）",name_vi:"Thái Thượng Hoàng Đình Nội Cảnh Ngọc Kinh Đồng Chú (Thiệu Mục Sinh)",bu:"续道藏外/藏外",author:"邵穆生",era:"明",topic:"cultivation|黄庭",essence:"Bản “đồng chú” Nội Cảnh kèm đồ thuyết, thiên phổ cập. Ghi trong mục lục Trung Hoa Đạo Kinh Tinh Yếu. Không thuộc Chính Thống Đạo Tạng.",key_text:"null",use:"Nhập môn Nội Cảnh; dùng cùng đồ thuyết.",sources:["https://homeinmists.ilotus.org/docs/B001.pdf","https://www.shidianguji.com/book/NGJ892412000005822231519/chapter/1lr0pdof5fg22","https://baike.baidu.com/item/%E9%BB%84%E5%BA%AD%E7%BB%8F/6240400"],textual_certainty:"partial",notes:"batch61 · Grok-4.5 focused 黄庭经注疏"},{dz:"null",name_han:"黄庭经注（蒋国祚）",name_vi:"Hoàng Đình Kinh Chú (Tưởng Quốc Tộ)",bu:"道藏辑要",author:"蒋国祚",era:"清",topic:"cultivation|黄庭",essence:"Chú Hoàng Đình Nội Cảnh và Ngoại Cảnh, thu vào Đạo Tạng Tập Yếu (vĩ tập). Giải theo đan đạo–dưỡng sinh đời Thanh, dễ đọc hơn chú Đường. Không có số Schipper DZ.",key_text:"null",use:"Đọc bộ Nội+Ngoại đời Thanh; so với Lương Khâu Tử.",sources:["https://homeinmists.ilotus.org/%E9%81%93%E8%97%8F%E5%8C%AF%E7%B7%A8/%E9%81%93%E8%97%8F%E8%BC%AF%E8%A6%81/%E9%81%93%E8%97%8F%E8%BC%AF%E8%A6%81-%E6%B8%85%E8%94%A3%E5%85%83%E5%BA%AD%E8%BC%AF/","https://zh.wikipedia.org/zh-hans/%E9%BB%84%E5%BA%AD%E7%BB%8F","https://www.diancang.xyz/xuanxuewushu/20754/376817.html"],textual_certainty:"high",notes:"batch61 · Grok-4.5 focused 黄庭经注疏"},{dz:"null",name_han:"太上黄庭经发微（董德宁）",name_vi:"Thái Thượng Hoàng Đình Kinh Phát Vi (Đổng Đức Ninh)",bu:"藏外（道贯真源）",author:"董德宁",era:"清",topic:"cultivation|黄庭",essence:"Hai quyển phát vi, giải nghĩa thông suốt, thường dùng làm bản tham hiệu cho Nội Cảnh. Nằm trong Đạo Quán Chân Nguyên; không có DZ. Được đánh giá dễ học, phù hợp người mới.",key_text:"null",use:"Học nghĩa cơ bản; hiệu khảo dị bản.",sources:["https://zh.wikisource.org/zh-hans/%E9%BB%83%E5%BA%AD%E5%85%A7%E6%99%AF%E7%B6%93","https://zh.wikipedia.org/zh-hans/%E9%BB%84%E5%BA%AD%E7%BB%8F","http://www.ctcwri.idv.tw/INDEXA3/A302/A3001-A3100/A3005/A3-05001.htm"],textual_certainty:"high",notes:"batch61 · Grok-4.5 focused 黄庭经注疏"},{dz:"null",name_han:"黄庭经解（刘一明）",name_vi:"Hoàng Đình Kinh Giải (Lưu Nhất Minh)",bu:"藏外（道书十二种）",author:"刘一明（悟元子）",era:"清·乾嘉",topic:"cultivation|黄庭",essence:"Giải Hoàng Đình theo nội đan Toàn Chân: Hoàng Đình là “trung/hư vô”, cảnh chỉ là cành lá. Phản đối chấp hình tượng tạng phủ, quy về thủ trung–dưỡng cốc thần. Bản chuẩn trong Đạo Thư Thập Nhị Chủng.",key_text:"黄庭经即演说“中”之道也。",use:"Đọc theo hướng đan đạo; phá chấp “cảnh”.",sources:["https://zh.wikisource.org/zh-hans/%E9%BB%83%E5%BA%AD%E7%B6%93%E8%A7%A3","https://zh.wikipedia.org/zh-hans/%E9%BB%84%E5%BA%AD%E7%BB%8F","http://www.ctcwri.idv.tw/INDEXA3/A302/A3001-A3100/A3005/A3-05001.htm"],textual_certainty:"high",notes:"batch61 · Grok-4.5 focused 黄庭经注疏"},{dz:"null",name_han:"黄庭经注解（李涵虚）",name_vi:"Hoàng Đình Kinh Chú Giải (Lý Hàm Hư)",bu:"藏外（太上十三经注解）",author:"李涵虚（李西月）",era:"清",topic:"cultivation|黄庭",essence:"Chú Hoàng Đình trong Thái Thượng Thập Tam Kinh Chú Giải, dòng Tây phái. Kết hợp nội đan Tây phái với văn Hoàng Đình; hay dùng phân chương Ngoại Cảnh. Không vào Đạo Tạng Minh.",key_text:"null",use:"Học Tây phái; so chương Ngoại Cảnh.",sources:["https://zh.wikipedia.org/zh-hans/%E9%BB%84%E5%BA%AD%E7%BB%8F","https://zh.wikisource.org/zh-hant/%E5%9C%93%E5%B6%A0%E5%85%A7%E7%AF%87/%E5%A4%AA%E4%B8%8A%E5%8D%81%E4%B8%89%E7%B6%93%E6%B3%A8%E8%A7%A3","https://zh.wikisource.org/zh-hans/%E9%BB%83%E5%BA%AD%E5%A4%96%E6%99%AF%E7%B6%93"],textual_certainty:"high",notes:"batch61 · Grok-4.5 focused 黄庭经注疏"},{dz:"null",name_han:"黄庭外景阴符经合注（石和阳）",name_vi:"Hoàng Đình Ngoại Cảnh Âm Phù Kinh Hợp Chú (Thạch Hòa Dương)",bu:"藏外",author:"石和阳（嵩阴子）",era:"清",topic:"cultivation|黄庭",essence:"Hợp chú Hoàng Đình Ngoại Cảnh với Âm Phù Kinh, nhấn đan đạo–âm phù tương thông. Bản khắc/trùng khắc được sưu tầm; không có DZ Schipper.",key_text:"null",use:"Đối Ngoại Cảnh với Âm Phù; luyện hợp tham.",sources:["https://zh.wikipedia.org/zh-hans/%E9%BB%84%E5%BA%AD%E7%BB%8F","https://homeinmists.ilotus.org/%E9%81%93%E8%97%8F%E5%8C%AF%E7%B7%A8/%E9%81%93%E8%97%8F%E7%B2%BE%E8%8F%AF/%E9%81%93%E8%97%8F%E7%B2%BE%E8%8F%AF%E7%9B%AE%E9%8C%84/%E3%80%8A%E9%81%93%E8%97%8F%E7%B2%BE%E8%8F%AF%E3%80%8B%E5%85%A8%E5%A5%97%E5%8D%81%E4%B8%83%E9%9B%86%E7%9B%AE%E9%8C%84/%E3%80%8A%E9%81%93%E8%97%8F%E7%B2%BE%E8%8F%AF%E3%80%8B%E7%9B%AE%E9%8C%84%E5%8D%81%E4%B8%83%E9%9B%86%E4%B9%8B%E4%B8%89/","https://www.daoist.org/BookSearch(test)/Download_area/series_024.pdf"],textual_certainty:"high",notes:"batch61 · Grok-4.5 focused 黄庭经注疏"},{dz:"null",name_han:"参同契阐幽（朱元育）",name_vi:"Tham Đồng Khế Xiển U (Chu Nguyên Dục)",bu:"道藏辑要",author:"朱元育（云阳道人）",era:"清康熙",topic:"cultivation",essence:"Vân Dương đạo nhân Chu Nguyên Dục hội thông Nho–Thích–Đạo để xiển Tham Đồng Khế, coi sách là «vạn cổ đan kinh vương» chỉ tính mệnh căn nguyên. Bản trọng yếu trong Trùng san Đạo tạng tập yếu, thường in kèm Ngộ Chân Thiên xiển u.",key_text:"此书出自汉代，伯阳魏祖假卦爻法象以显性命根源。",use:"Chú giải Thanh đại dung hợp tam giáo; đọc cùng Ngộ Chân xiển u của cùng tác giả.",sources:["https://zh.wikisource.org/zh-hans/%E5%8F%83%E5%90%8C%E5%A5%91%E9%97%A1%E5%B9%BD","https://ctext.org/wiki.pl?if=gb&res=429076","https://baike.baidu.com/item/%E5%8F%82%E5%90%8C%E5%A5%91%E9%98%90%E5%B9%BD%C2%B7%E6%82%9F%E7%9C%9F%E7%AF%87%E9%98%90%E5%B9%BD/56585191"],textual_certainty:"high",notes:"batch62 · Grok-4.5 内丹经典藏外/辑要注疏"},{dz:"null",name_han:"悟真直指（刘一明）",name_vi:"Ngộ Chân Trực Chỉ (Lưu Nhất Minh)",bu:"藏外·道书十二种",author:"刘一明（悟元子）",era:"清（约18–19世纪）",topic:"cultivation",essence:"Ngộ Nguyên tử Lưu Nhất Minh (Long môn) chú Ngộ Chân Thiên theo hướng tính mệnh song tu, thanh hư tinh luyện, phản đối chấp tướng và tà pháp. Thu vào Đạo thư thập nhị chủng / Chỉ nam châm, là chú tàng ngoại tiêu biểu nhất đời Thanh.",key_text:"null",use:"Hệ Long môn hiểu Ngộ Chân; cặp với Kim Đan tứ bách tự giải của cùng tác giả.",sources:["https://zh.wikisource.org/zh-hans/%E6%82%9F%E7%9C%9F%E7%9B%B4%E6%8C%87","https://ctext.org/wiki.pl?if=gb&res=269636","https://zh.wikisource.org/zh-hans/%E9%81%93%E6%9B%B8%E5%8D%81%E4%BA%8C%E7%A8%AE"],textual_certainty:"high",notes:"batch62 · Grok-4.5 内丹经典藏外/辑要注疏"},{dz:"null",name_han:"周易参同契测疏（陆西星）",name_vi:"Chu Dịch Tham Đồng Khế Trắc Sớ (Lục Tây Tinh)",bu:"藏外·方壶外史",author:"陆西星（潜虚子）",era:"明",topic:"cultivation",essence:"Tổ Đông phái Lục Tây Tinh «trắc sớ» Tham Đồng Khế trong Phương Hồ ngoại sử, lời thẳng rõ hơn cổ chú. Kết hợp tính mệnh song tu, thiên nguyên kiêm nhân nguyên; cùng bộ còn Ngộ Chân tiểu tự, Kim Đan tứ bách tự trắc sớ.",key_text:"null",use:"Nghiên cứu pháp mạch Đông phái và chú minh bạch đời Minh.",sources:["https://www.shuge.org/view/fang_hu_wai_shi/","https://baike.baidu.com/item/%E4%B8%87%E5%8F%A4%E4%B8%B9%E7%BB%8F%E7%8E%8B%3C%E5%91%A8%E6%98%93%E5%8F%82%E5%90%8C%E5%A5%91%3E%E4%B8%89%E5%8D%81%E5%9B%9B%E5%AE%B6%E6%B3%A8%E9%87%8A%E9%9B%86%E8%90%83/12377924","https://zh.wikipedia.org/wiki/%E6%82%9F%E7%9C%9F%E7%AF%87"],textual_certainty:"high",notes:"batch62 · Grok-4.5 内丹经典藏外/辑要注疏"},{dz:"null",name_han:"周易参同契正义（董德宁）",name_vi:"Chu Dịch Tham Đồng Khế Chính Nghĩa (Đổng Đức Ninh)",bu:"藏外·道贯真源",author:"董德宁",era:"清乾隆",topic:"cultivation",essence:"Đổng Đức Ninh soạn Chính nghĩa ba quyển, khắc trong Đạo quán chân nguyên (Càn long 53). Chú Tham Đồng theo hướng nội đan «chính nghĩa» rõ ràng, thường được xếp vào nhóm chú Thanh đại quan trọng; ông cũng có Ngộ Chân Thiên chính nghĩa.",key_text:"null",use:"Đối chiếu chú Thanh «chính thống» với Xiển u (Chu) và Trắc sớ (Lục).",sources:["https://baike.baidu.com/item/%E4%B8%87%E5%8F%A4%E4%B8%B9%E7%BB%8F%E7%8E%8B%3C%E5%91%A8%E6%98%93%E5%8F%82%E5%90%8C%E5%A5%91%3E%E4%B8%89%E5%8D%81%E5%9B%9B%E5%AE%B6%E6%B3%A8%E9%87%8A%E9%9B%86%E8%90%83/12377924","http://www.xy980.net/xq07/KW1757.htm","https://zh.wikipedia.org/wiki/%E6%82%9F%E7%9C%9F%E7%AF%87"],textual_certainty:"high",notes:"batch62 · Grok-4.5 内丹经典藏外/辑要注疏"},{dz:"null",name_han:"参同契脉望（陶素耜）",name_vi:"Tham Đồng Khế Mạch Vọng (Đào Tố Tứ)",bu:"藏外·道书五种",author:"陶素耜（存存子）",era:"清康熙",topic:"cultivation",essence:"Tồn Tồn tử Đào Tố Tứ chú Tham Đồng Khế ba quyển, cùng Ngộ Chân ước chú hợp thành Đạo thư ngũ chủng. Thuộc mạch nhân nguyên (liên hệ Tôn Giáo Loan), ảnh hưởng Tây phái Lý Hàm Hư; Mạch vọng nghĩa là «nhìn mạch đan đạo».",key_text:"null",use:"Đọc mạch nhân nguyên đời Thanh; tham chiếu Đạo khiếu đàm (Lý Hàm Hư).",sources:["https://baike.baidu.com/item/%E9%99%B6%E7%B4%A0%E8%80%9C/14690107","http://www.xy980.net/xq07/KW1757.htm","https://zhuanlan.zhihu.com/p/368199859"],textual_certainty:"high",notes:"batch62 · Grok-4.5 内丹经典藏外/辑要注疏"},{dz:"null",name_han:"悟真篇集注（仇兆鳌）",name_vi:"Ngộ Chân Thiên Tập Chú (Cừu Triệu Ngao)",bu:"藏外",author:"仇兆鳌（知几子）",era:"清",topic:"cultivation",essence:"Tri Cơ tử Cừu Triệu Ngao tập chú Ngộ Chân Thiên, thu khoảng 25 nhà (Trương Vị, Lý Văn Chúc, Bành Hảo Cổ, Đào Tố Tứ…). Thiên lệch Nam tông âm dương, là từ thư chú sớ lớn đời Thanh để tra cứu dị giải.",key_text:"null",use:"Tra cứu dị chú nhiều nhà; so sánh phái thanh tu vs song tu.",sources:["https://zhuanlan.zhihu.com/p/368199859","https://zh.wikipedia.org/wiki/%E6%82%9F%E7%9C%9F%E7%AF%87","https://baike.baidu.com/item/%E9%99%B6%E7%B4%A0%E8%80%9C/14690107"],textual_certainty:"high",notes:"batch62 · Grok-4.5 内丹经典藏外/辑要注疏"},{dz:"null",name_han:"金丹四百字注释（闵一得）",name_vi:"Kim Đan Tứ Bách Tự Chú Thích (Mẫn Nhất Đắc)",bu:"藏外·古书隐楼藏书",author:"闵一得（懒云）",era:"清",topic:"cultivation",essence:"Lãn Vân Mẫn Nhất Đắc (Long môn) chú thích Kim Đan Tứ Bách Tự trong cổ thư Ẩn lâu tàng thư. Giải theo tinh–khí–thần và hỏa hầu Long môn trung hậu kỳ, bổ sung cho chú Hoàng Tự Như và Lưu Nhất Minh.",key_text:"七以火数，九乃金数，以火炼金，返本還元，谓之金丹。",use:"Hệ Ẩn lâu / Long môn đọc Tứ bách tự; so với chú Tống và Lưu Ngộ Nguyên.",sources:["https://zh.wikisource.org/wiki/%E9%87%91%E4%B8%B9%E5%9B%9B%E7%99%BE%E5%AD%97","https://ctext.org/wiki.pl?if=gb&chapter=456536","https://zh.wikisource.org/wiki/%E9%87%91%E4%B8%B9%E5%9B%9B%E7%99%BE%E5%AD%97_(%E9%BB%83%E8%87%AA%E5%A6%82%E6%B3%A8)"],textual_certainty:"high",notes:"batch62 · Grok-4.5 内丹经典藏外/辑要注疏"},{dz:"null",name_han:"崔公入药镜注（傅金铨）",name_vi:"Thôi Công Nhập Dược Kính Chú (Phó Kim Thuyên)",bu:"藏外",author:"傅金铨（济一子）",era:"清",topic:"cultivation",essence:"Tế Nhất tử Phó Kim Thuyên chú Nhập Dược Kính: phân biệt «dược» (trị bệnh, trúc cơ) và «đan» (thần hóa). Nhấn mạnh bổ túc hình khí trước rồi luyện tinh hóa khí, cơ thành vô lậu mới hoàn đan—pháp trình hậu thiên rõ ràng đời Thanh.",key_text:"丹者神化之道，药乃治病之方。",use:"Học trình tự trúc cơ–đắc dược–hoàn đan theo chú Thanh.",sources:["https://zh.wikisource.org/zh-hans/%E5%B4%94%E5%85%AC%E5%85%A5%E8%97%A5%E9%8F%A1%E6%B3%A8","https://www.daoisms.com.cn/2013/11/12/16983/","https://ctext.org/wiki.pl?if=en&chapter=890541&remap=gb"],textual_certainty:"high",notes:"batch62 · Grok-4.5 内丹经典藏外/辑要注疏"},{dz:"null",name_han:"天仙正理直论",name_vi:"Thiên Tiên Chính Lý Trực Luận",bu:"藏外·伍柳仙宗",author:"伍守阳（冲虚子）",era:"明末崇祯（约1639）",topic:"cultivation",essence:"Bộ luận nội đan cốt lõi của phái Ngũ Liễu, trình bày chín chương “trực luận” về tiên thiên–hậu thiên, dược vật, đỉnh khí, hỏa hậu, luyện kỷ, trúc cơ, luyện dược, phục khí và thai tức. Nhấn mạnh chỉ có thần khí mới là chánh lý thiên tiên, quét sạch phòng thuật và tà pháp. Đây là cẩm nang thực tu được in trong *Ngũ Liễu Tiên Tông*, không thuộc Chính Thống Đạo Tạng.",key_text:"仙道简易，只神炁二者而已。",use:"Đọc song song với *Tiên Phật Hợp Tông* khi học hệ Ngũ Liễu: lấy lý luận cốt tủy rồi đối chiếu cảnh nghiệm thực tu.",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%A9%E4%BB%99%E6%AD%A3%E7%90%86%E7%9B%B4%E8%AB%96%E5%A2%97%E8%A8%BB","https://ctext.org/wiki.pl?if=gb&res=174956&remap=gb","https://baike.baidu.com/item/%E5%A4%A9%E4%BB%99%E6%AD%A3%E7%90%86%E7%9B%B4%E8%AE%BA/815500"],textual_certainty:"high",notes:"batch63 · Grok-4.5 道藏辑要/藏外 major 内丹"},{dz:"null",name_han:"仙佛合宗语录",name_vi:"Tiên Phật Hợp Tông Ngữ Lục",bu:"道藏辑要·藏外（伍柳仙宗）",author:"伍守阳（冲虚子）",era:"明末清初",topic:"cultivation",essence:"Ngữ lục đối đáp chi tiết về toàn bộ công phu nội đan: hoàn hư ban đầu, chân ý, thủy nguyên thanh trọc, chỉ hỏa, thái đại dược, quá quan phục thực, thủ trung, xuất thần. Chủ trương “tiên Phật hợp tông”, dùng thuật ngữ Thiền–Phật để làm rõ đan đạo. Được thu vào *Trùng san Đạo Tạng Tập Yếu* và hợp khắc *Ngũ Liễu Tiên Tông*.",key_text:"真药物，即真精也。",use:"Sổ tay thực hành sau khi nắm *Thiên Tiên Chính Lý*: đối chiếu từng tiết công cảnh với khẩu quyết sư truyền.",sources:["https://zh.wikisource.org/zh-hans/%E4%BB%99%E4%BD%9B%E5%90%88%E5%AE%97%E8%AA%9E%E9%8C%84","https://ctext.org/wiki.pl?if=gb&res=471343&remap=gb","https://baike.baidu.com/item/%E4%BB%99%E4%BD%9B%E5%90%88%E5%AE%97%E8%AF%AD%E5%BD%95/951680"],textual_certainty:"high",notes:"batch63 · Grok-4.5 道藏辑要/藏外 major 内丹"},{dz:"null",name_han:"金仙证论",name_vi:"Kim Tiên Chứng Luận",bu:"藏外·伍柳仙宗",author:"柳华阳",era:"清乾隆–嘉庆",topic:"cultivation",essence:"Tác phẩm đại biểu của Liễu Hoa Dương, chứng minh công phu luyện đan bằng ngôn ngữ thẳng: luyện kỷ, tiểu chu thiên dược vật, đỉnh khí, phong hỏa, hiệu nghiệm. Kế thừa và phổ biến pháp mạch Ngũ Liễu, nhấn mạnh khí mạch–chu thiên và cảnh nghiệm rõ ràng cho người mới. Hợp khắc với *Tuệ Mệnh Kinh* trong *Ngũ Liễu Tiên Tông*.",key_text:"金丹之道，从阳生时，凝神入气穴。",use:"Dùng làm hướng dẫn thực tu tiểu chu thiên; đối chiếu với *Thiên Tiên Chính Lý* để hiểu hệ Ngũ Liễu.",sources:["https://zh.wikisource.org/zh-hans/%E9%87%91%E4%BB%99%E8%AD%89%E8%AB%96","https://ctext.org/wiki.pl?if=gb&chapter=1967955&remap=gb","https://baike.baidu.com/item/%E4%BC%8D%E6%9F%B3%E4%BB%99%E5%AE%97/60039617"],textual_certainty:"high",notes:"batch63 · Grok-4.5 道藏辑要/藏外 major 内丹"},{dz:"null",name_han:"慧命经",name_vi:"Tuệ Mệnh Kinh",bu:"藏外·伍柳仙宗",author:"柳华阳",era:"清乾隆–嘉庆",topic:"cultivation",essence:"Kinh luận dung hợp Thiền–Đạo, luận về tuệ mệnh (thần–khí / tính–mệnh) và đường vào Phật–Tiên. Chỉ rõ không được tuệ mệnh thì không thể “lậu tận”, nhấn mạnh thần tức tính, khí tức mệnh. Cùng *Kim Tiên Chứng Luận* tạo thành cốt lõi pháp Liễu Hoa Dương trong *Ngũ Liễu Tiên Tông*.",key_text:"成佛作祖是本性灵光，不得慧命漏尽不能了道。",use:"Đọc để hiểu “tiên Phật hợp tông” và quan hệ tính–mệnh trước khi vào công phu khí mạch.",sources:["https://zh.wikisource.org/zh-hans/%E6%85%A7%E5%91%BD%E7%B6%93","https://ctext.org/searchbooks.pl?if=gb&author=%E6%9F%B3%E8%8F%AF%E9%99%BD&remap=gb","https://baike.baidu.com/item/%E4%BC%8D%E6%9F%B3%E4%BB%99%E5%AE%97/60039617"],textual_certainty:"high",notes:"batch63 · Grok-4.5 道藏辑要/藏外 major 内丹"},{dz:"null",name_han:"修真辩难",name_vi:"Tu Chân Biện Nan",bu:"藏外·道书十二种",author:"刘一明（悟元子）",era:"清乾嘉",topic:"cultivation",essence:"Tác phẩm đối thoại thầy–trò của Lưu Nhất Minh, giải đáp hàng loạt nghi vấn: đạo là gì, âm dương nội ngoại, huyền quan nhất khiếu, nội dược–ngoại dược, chân diên chân hồng. Hệ thống hóa lý luận toàn chân Long Môn, được thu vào *Đạo Thư Thập Nhị Chủng* (còn gọi *Chỉ Nam Châm*).",key_text:"然虽无形而能生形，无象而能生象。",use:"Sách nhập môn lý luận đan đạo Lưu Nhất Minh; đọc trước *Tu Chân Cửu Yếu* và *Tu Chân Hậu Biện*.",sources:["https://zh.wikisource.org/zh-hans/%E4%BF%AE%E7%9C%9F%E8%BE%AF%E9%9B%A3","https://zh.daoinfo.org/index.php?title=%E9%81%93%E6%9B%B8%E5%8D%81%E4%BA%8C%E7%A8%AE&variant=zh-hans","https://baike.baidu.com/item/%E9%81%93%E4%B9%A6%E5%8D%81%E4%BA%8C%E7%A7%8D/4742432"],textual_certainty:"high",notes:"batch63 · Grok-4.5 道藏辑要/藏外 major 内丹"},{dz:"null",name_han:"修真九要",name_vi:"Tu Chân Cửu Yếu",bu:"藏外·道书十二种",author:"刘一明（悟元子）",era:"清嘉庆三年（1798）",topic:"cultivation",essence:"Chín yếu chỉ theo thứ tự: khán phá thế sự, tích đức, tận tâm cùng lý, phỏng sư, luyện kỷ trúc cơ, hòa hợp âm dương, thẩm minh hỏa hậu, ngoại dược liễu mệnh, nội dược liễu tính. Là “thang bậc” thực tiễn cho người mới, từ công–hạnh đến tính mệnh song tu, không nằm trong Chính Thống Đạo Tạng.",key_text:"修真之道乃天下第一件大事，亦天下第一件难事。",use:"Checklist thực tu: kiểm từng bước từ thế sự–đức hạnh đến liễu mệnh–liễu tính.",sources:["https://zh.wikisource.org/zh-hans/%E4%BF%AE%E7%9C%9F%E4%B9%9D%E8%A6%81","https://zh.wikisource.org/zh-hans/%E9%81%93%E6%9B%B8%E5%8D%81%E4%BA%8C%E7%A8%AE","https://ctext.org/searchbooks.pl?if=gb&author=%E5%8A%89%E4%B8%80%E6%98%8E"],textual_certainty:"high",notes:"batch63 · Grok-4.5 道藏辑要/藏外 major 内丹"},{dz:"null",name_han:"神室八法",name_vi:"Thần Thất Bát Pháp",bu:"藏外·道书十二种",author:"刘一明（悟元子）",era:"清乾嘉",topic:"cultivation",essence:"Lấy “thần thất” (tâm) làm đỉnh lò, lấy tám đức cương–nhu–thành–tín–hòa–tĩnh–hư–linh làm vật liệu xây dựng. Dung hợp Nho–Đạo, xem tu tâm là nền tảng đan đạo. Thuộc nhóm trước thuật của *Đạo Thư Thập Nhị Chủng*.",key_text:"信之一法，乃神室之椽瓦。",use:"Tu dưỡng đạo đức–tâm tính song song với công phu khí; nền tảng “xây thần thất” trước khi luyện đan.",sources:["https://zh.wikisource.org/wiki/%E7%A5%9E%E5%AE%A4%E5%85%AB%E6%B3%95","https://zh.daoinfo.org/index.php?title=%E9%81%93%E6%9B%B8%E5%8D%81%E4%BA%8C%E7%A8%AE&variant=zh-hans","https://baike.baidu.com/item/%E9%81%93%E4%B9%A6%E5%8D%81%E4%BA%8C%E7%A7%8D/4742432"],textual_certainty:"high",notes:"batch63 · Grok-4.5 道藏辑要/藏外 major 内丹"},{dz:"null",name_han:"象言破疑",name_vi:"Tượng Ngôn Phá Nghi",bu:"藏外·道书十二种",author:"刘一明（悟元子）",era:"清乾嘉",topic:"cultivation",essence:"Phá nghi đan kinh “tượng ngôn” (nói bằng hình tượng): thuận nghịch, dược vật, hỏa hậu, thai trung diện mục, luyện kỷ trúc cơ, thiên lương chân tâm… Kết hợp *Dịch* lý và đồ thuyết để chỉ chính đạo, quét bàng môn. Hai quyển, thuộc *Đạo Thư Thập Nhị Chủng*.",key_text:"丹经万卷皆象言也。",use:"Đọc để giải mã ẩn dụ đan kinh, tránh chấp chữ–chấp tượng khi học *Ngộ Chân* / *Tham Đồng*.",sources:["https://zh.wikisource.org/wiki/%E8%B1%A1%E8%A8%80%E7%A0%B4%E7%96%91","https://ctext.org/wiki.pl?if=gb&res=588953&remap=gb","https://zh.wikisource.org/zh-hans/%E9%81%93%E6%9B%B8%E5%8D%81%E4%BA%8C%E7%A8%AE"],textual_certainty:"high",notes:"batch63 · Grok-4.5 道藏辑要/藏外 major 内丹"},{dz:"null",name_han:"通关文",name_vi:"Thông Quan Văn",bu:"藏外·道书十二种",author:"刘一明（悟元子）",era:"清乾嘉",topic:"philosophy",essence:"Liệt khoảng năm mươi “quan” thế sự (sắc dục, ân ái, vinh quý, tài lợi…) để người học “thông quan”–khán phá vọng chấp trước khi vào đan đạo. Mang màu sắc Nho–Phật mạnh, xem đoạn duyên thế sự là bước khởi của tu chân. Hai quyển trong *Đạo Thư Thập Nhị Chủng*.",key_text:"先将世事齐放下，后把道理细研精。",use:"Đọc đầu khóa học đan đạo: kiểm các chấp trước đời sống trước khi bàn dược–hỏa.",sources:["https://zh.wikisource.org/wiki/%E9%80%9A%E9%97%9C%E6%96%87","https://zh.daoinfo.org/index.php?title=%E9%81%93%E6%9B%B8%E5%8D%81%E4%BA%8C%E7%A8%AE&variant=zh-hans","https://baike.baidu.com/item/%E9%81%93%E4%B9%A6%E5%8D%81%E4%BA%8C%E7%A7%8D/4742432"],textual_certainty:"high",notes:"batch63 · Grok-4.5 道藏辑要/藏外 major 内丹"},{dz:"null",name_han:"道窍谈",name_vi:"Đạo Khiếu Đàm",bu:"藏外·圆峤内篇（西派）",author:"李涵虚（李西月）",era:"清道光–咸丰",topic:"cultivation",essence:"Tác phẩm cốt lõi Tây phái Lý Hàm Hư, luận khai quan triển khiếu, trúc cơ luyện kỷ, hậu thiên thứ tự, nội ngoại nhị dược, huyền quan nhất khiếu, hà xa, chân tâm. Phân tầng rõ hậu thiên–tiên thiên, tiểu dược–đại dược. Được Trần Anh Ninh hiệu đính; thu trong *Viên Kiệu Nội Thiên*, tàng ngoại.",key_text:"知内不知外，无以通关窍。收外不收内，无以固根源。",use:"Cẩm nang lý–pháp Tây phái: đọc kỹ chương huyền quan, dược vật, hà xa trước khi vào *Tam Xa Bí Chỉ*.",sources:["https://zh.wikisource.org/zh-hans/%E5%9C%93%E5%B6%A0%E5%85%A7%E7%AF%87/%E9%81%93%E7%AB%85%E8%AB%87","https://baike.baidu.com/item/%E9%81%93%E7%AA%8D%E8%B0%88/841972","https://ctext.org/wiki.pl?if=gb&chapter=76766&remap=gb"],textual_certainty:"high",notes:"batch63 · Grok-4.5 道藏辑要/藏外 major 内丹"},{dz:"null",name_han:"三车秘旨",name_vi:"Tam Xa Bí Chỉ",bu:"藏外·圆峤内篇（西派）",author:"李涵虚（李西月）",era:"清道光–咸丰",topic:"cultivation",essence:"Giải “tam xa” (ba hà xa): vận khí (tiểu chu thiên), vận tinh (ngọc dịch hà xa), tinh khí kiêm vận (đại chu tiên thiên). Chỉ thứ tự khai quan trúc cơ–đắc dược kết đan–thất phản cửu hoàn. Cùng *Đạo Khiếu Đàm* là cặp bí chỉ Tây phái, tàng ngoại, không có trong Chính Thống Đạo Tạng.",key_text:"三车者，三件河车也。第一件运气，即小周天子午运火也。",use:"Thực hành hà xa theo ba tầng sau khi đã hiểu lý trong *Đạo Khiếu Đàm*.",sources:["https://zh.wikisource.org/zh-hans/%E5%9C%93%E5%B6%A0%E5%85%A7%E7%AF%87/%E4%B8%89%E8%BB%8A%E7%A7%98%E6%97%A8","https://baike.baidu.com/item/%E9%81%93%E7%AA%8D%E8%B0%88/841972","https://zh.wikisource.org/zh-hans/%E5%9C%93%E5%B6%A0%E5%85%A7%E7%AF%87/%E9%81%93%E7%AB%85%E8%AB%87"],textual_certainty:"high",notes:"batch63 · Grok-4.5 道藏辑要/藏外 major 内丹"},{dz:"null",name_han:"玄肤论",name_vi:"Huyền Phu Luận",bu:"藏外·方壶外史",author:"陆西星（潜虚子、方壶外史）",era:"明隆庆元年（1567）",topic:"cultivation",essence:"Hai mươi thiên luận tự thuật của tổ Đông phái Lục Tây Tinh: tam nguyên, nội ngoại dược, âm dương hỗ tàng, tiên hậu thiên, diên hồng, nguyên tinh khí thần, tính mệnh, thần thất, hà xa, ngưng thần, chân tức, hỏa phù… Tự xưng “huyền lý phu thiển”, nhưng là khung lý đan song tu Đông phái. Thu trong *Phương Hồ Ngoại Sử*.",key_text:"丹有三元，皆可了命。",use:"Đọc để nắm lý Đông phái (tam nguyên, nhân nguyên đan pháp) trước khi vào *Kim Đan Tựu Chính Thiên*.",sources:["https://zh.wikisource.org/zh-hans/%E7%8E%84%E8%86%9A%E8%AB%96","https://ctext.org/library.pl?if=gb&res=105977&remap=gb","https://zh.wikisource.org/zh-hans/%E6%96%B9%E5%A3%BA%E5%A4%96%E5%8F%B2"],textual_certainty:"high",notes:"batch63 · Grok-4.5 道藏辑要/藏外 major 内丹"},{dz:"null",name_han:"金丹就正篇",name_vi:"Kim Đan Tựu Chính Thiên",bu:"藏外·方壶外史",author:"陆西星（潜虚子）",era:"明嘉靖–万历",topic:"cultivation",essence:"Ba thiên “tựu chính” của Lục Tây Tinh, kể duyên ngộ Lữ Tổ và chỉnh lại chánh pháp kim đan, nhấn mạnh tính mệnh song tu và nhân nguyên đan pháp. Cùng *Huyền Phu Luận* là trước thuật gốc Đông phái trong *Phương Hồ Ngoại Sử*, tàng ngoại.",key_text:"嘉靖丁未，偶以因缘遭际，得遇法祖吕公于北海之草堂。",use:"Đối chiếu với *Huyền Phu Luận* để nắm “tựu chính” và lập trường Đông phái.",sources:["https://zh.wikisource.org/zh-hant/%E9%87%91%E4%B8%B9%E5%B0%B1%E6%AD%A3%E7%AF%87","https://ctext.org/library.pl?if=gb&res=109907","https://zh.wikisource.org/zh-hans/%E6%96%B9%E5%A3%BA%E5%A4%96%E5%8F%B2"],textual_certainty:"high",notes:"batch63 · Grok-4.5 道藏辑要/藏外 major 内丹"},{dz:"null",name_han:"悟真篇阐幽",name_vi:"Ngộ Chân Thiên Xiển U",bu:"道藏辑要",author:"朱元育（云阳道人）",era:"清康熙–乾隆",topic:"classic",essence:"Chú giải *Ngộ Chân Thiên* của Trương Bá Đoan theo quan điểm đan đạo Bắc–Nam dung thông. Cùng *Tham Đồng Khế Xiển U* (đã loại khỏi danh sách này) là cặp “xiển u” nổi tiếng của Chu Nguyên Dục, được thu vào *Trùng san Đạo Tạng Tập Yếu*, không có DZ# Chính Thống.",key_text:"《悟真篇》者，宋紫阳真人天台张平叔所撰也。",use:"Chú giải chuẩn *Ngộ Chân* thời Thanh; so sánh với *Ngộ Chân Trực Chỉ* (Lưu Nhất Minh) để thấy khác biệt xiển thích.",sources:["https://zh.wikisource.org/zh-hans/%E6%82%9F%E7%9C%9E%E7%AF%87%E9%97%A1%E5%B9%BD","https://ctext.org/wiki.pl?if=en&chapter=171925&remap=gb","https://baike.baidu.com/item/%E5%8F%82%E5%90%8C%E5%A5%91%E9%98%90%E5%B9%BD%C2%B7%E6%82%9F%E7%9C%9F%E7%AF%87%E9%98%90%E5%B9%BD/56585191"],textual_certainty:"high",notes:"batch63 · Grok-4.5 道藏辑要/藏外 major 内丹"},{dz:"null",name_han:"天仙心传",name_vi:"Thiên Tiên Tâm Truyền",bu:"藏外·古书隐楼藏书",author:"闵一得（小艮、懒云子）",era:"清道光（约1834）",topic:"cultivation",essence:"Trước thuật / biên soạn quan trọng của Mẫn Nhất Đắc trong *Cổ Thư Ẩn Lâu Tàng Thư*, thuật công phu “thiên tiên hỗn hóa”, kết hợp đan đạo Long Môn với “vân triện”, chân ngôn. Phản ánh đặc sắc phái Kim Cái–Long Môn thời Thanh, tàng ngoại, không thuộc Chính Thống Đạo Tạng.",key_text:"运限无常，世运之通否，道运之明晦，其机由人。",use:"Nghiên cứu đan pháp Mẫn Nhất Đắc / Kim Cái; đọc trong bối cảnh *Cổ Thư Ẩn Lâu Tàng Thư* và *Đạo Tạng Tục Biên*.",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%A9%E4%BB%99%E5%BF%83%E5%82%B3","http://www.ctcwri.idv.tw/CTCW-D2/D2-05%E4%BA%94%E5%8A%83-72/D20512%E5%8F%A4-11/D2051203%E5%8F%A4%E6%9B%B8%E9%9A%B1%E6%A8%93%E8%97%8F%E6%9B%B8.htm","https://baike.baidu.com/item/%E5%8F%A4%E4%B9%A6%E9%9A%90%E6%A5%BC%E8%97%8F%E4%B9%A6/9879254"],textual_certainty:"high",notes:"batch63 · Grok-4.5 道藏辑要/藏外 major 内丹"},{dz:"null",name_han:"性命法诀明指",name_vi:"Tính Mệnh Pháp Quyết Minh Chỉ",bu:"藏外（千峰先天派）",author:"赵避尘（千峰老人、顺一子）",era:"民国（1933）",topic:"cultivation",essence:"Tác phẩm “minh chỉ” của Triệu Tị Trần (Thiên Phong lão nhân), công khai khẩu quyết Long Môn tính mệnh song tu theo bốn tay: luyện tinh hóa khí, luyện khí hóa thần, luyện thần hoàn hư, luyện hư hợp đạo. Dùng bạch thoại, kết hợp giải thích sinh lý hiện đại; sáng lập Thiên Phong Tiên Thiên phái, hoàn toàn tàng ngoại.",key_text:"安神祖窍。",use:"Sổ tay thực tu hiện đại hệ Long Môn/Thiên Phong; đối chiếu với Ngũ Liễu để thấy khác biệt “minh chỉ” và “tiên Phật hợp tông”.",sources:["https://ctext.org/wiki.pl?if=gb&res=304131&remap=gb","https://baike.baidu.com/item/%E6%80%A7%E5%91%BD%E6%B3%95%E8%AF%80/22746600","https://baike.baidu.com/item/%E8%B5%B5%E9%81%BF%E5%B0%98/2529141"],textual_certainty:"high",notes:"batch63 · Grok-4.5 道藏辑要/藏外 major 内丹"},{dz:"null",name_han:"金盖心灯",name_vi:"Kim Cái Tâm Đăng",bu:"藏外·古书隐楼藏书/龙门金盖山",author:"闵一得",era:"清嘉庆—道光（约1810s–1830s）",topic:"仙传",essence:"Min Nhất Đắc biên soạn theo thể kỷ truyện, ghi chép hơn trăm đạo sĩ Long Môn từ đời một đến đời mười bốn, lấy Kim Cái Sơn Chiết Giang làm trục. Vì các sử phái như Bát Giám đã thất truyền, đây là tư liệu cốt lõi để khảo chứng truyền thừa Long Môn và tâm pháp Kim Cái.",key_text:"null",use:"Nghiên cứu sử phái Long Môn / bản đồ truyền thừa Kim Cái Sơn",sources:["https://baike.baidu.com/item/%E9%87%91%E7%9B%96%E5%BF%83%E7%81%AF/55516811","https://zh.daoinfo.org/index.php?title=%E9%87%91%E8%93%8B%E5%BF%83%E7%87%88&variant=zh-hans","https://zh.wikisource.org/zh-hans/Author:%E9%96%94%E4%B8%80%E5%BE%97"],textual_certainty:"high",notes:"batch64 · Grok-4.5 藏外/辑要 continuation"},{dz:"null",name_han:"古法养生十三则阐微",name_vi:"Cổ Pháp Dưỡng Sinh Thập Tam Tắc Xiển Vi",bu:"藏外·古书隐楼藏书",author:"闵一得",era:"清嘉庆戊寅（1818）",topic:"cultivation",essence:"Min Nhất Đắc giải thích mười ba tắc dưỡng sinh cổ, từ nắm cố, điều tâm, du thần thủy phủ đến động tĩnh bất nhị. Giọng văn thô sơ nhưng nghĩa sâu, cố ý tránh ẩn dụ long hổ/hỏa hầu phức tạp, chỉ thẳng công phu thực tiễn và các lỗi thường gặp của người mới.",key_text:"两手握固，闭目冥心。",use:"Nhập môn tĩnh công Long Môn / phòng lỗi dưỡng sinh",sources:["https://zh.wikisource.org/zh-hans/%E5%8F%A4%E6%B3%95%E9%A4%8A%E7%94%9F%E5%8D%81%E4%B8%89%E5%89%87%E9%97%A1%E5%BE%AE","https://baike.baidu.com/item/%E5%85%BB%E7%94%9F%E5%8D%81%E4%B8%89%E5%88%99%E9%98%90%E5%BE%AE/12689129","https://ctext.org/wiki.pl?if=gb&res=195080"],textual_certainty:"high",notes:"batch64 · Grok-4.5 藏外/辑要 continuation"},{dz:"null",name_han:"大道论（张三丰）",name_vi:"Đại Đạo Luận (Trương Tam Phong)",bu:"道藏辑要·张三丰先生全集",author:"张三丰（李西月重编本）",era:"明（文传）；清道光辑刊",topic:"philosophy",essence:"Ba thiên thượng/trung/hạ bàn về vô cực–thái cực, sinh thiên địa nhân vật, và đường thành tiên. Đây là phần lý luận then chốt trong Trương Tam Phong Toàn Tập, nối tư tưởng Đạo Đức với nội đan.",key_text:"大道者，统生天、生地、生人、生物而名，含阴阳动静之机，具造化玄微之理。",use:"Nền triết học Vũ Đương / khung lý luận nội đan",sources:["https://zh.wikisource.org/zh-hans/%E5%BC%B5%E4%B8%89%E4%B8%B0%E5%85%88%E7%94%9F%E5%85%A8%E9%9B%86/%E5%8D%B73","https://ctext.org/wiki.pl?if=gb&res=993393&remap=gb","https://zh.daoinfo.org/index.php?title=%E5%BC%B5%E4%B8%89%E4%B8%B0%E5%85%88%E7%94%9F%E5%85%A8%E9%9B%86&variant=zh-hans"],textual_certainty:"high",notes:"batch64 · Grok-4.5 藏外/辑要 continuation"},{dz:"null",name_han:"玄机直讲（张三丰）",name_vi:"Huyền Cơ Trực Giảng (Trương Tam Phong)",bu:"道藏辑要·张三丰先生全集",author:"张三丰（李西月重编本）",era:"明（文传）；清道光辑刊",topic:"cultivation",essence:"Gồm các bài như Luyện đan hỏa hầu thuyết, Hoàn hoàn chứng nghiệm, Phục thực đại đan, chỉ thẳng hỏa hầu và chứng nghiệm. Bổ sung phần thực tu cho Đại Đạo Luận trong cùng toàn tập.",key_text:"null",use:"Hỏa hầu / chứng nghiệm thực tu",sources:["https://zh.wikisource.org/zh-hans/%E5%BC%B5%E4%B8%89%E4%B8%B0%E5%85%88%E7%94%9F%E5%85%A8%E9%9B%86/%E5%8D%B73","https://ctext.org/wiki.pl?if=gb&res=993393&remap=gb","https://dao.crs.cuhk.edu.hk/Main/wp-content/uploads/2020/11/Daoist_newsletter_issue54.pdf"],textual_certainty:"high",notes:"batch64 · Grok-4.5 藏外/辑要 continuation"},{dz:"null",name_han:"无根树（词·张三丰）",name_vi:"Vô Căn Thụ (Từ·Trương Tam Phong)",bu:"道藏辑要·张三丰先生全集 / 藏外道书",author:"张三丰",era:"明（传）；清刊全集",topic:"cultivation",essence:"Hai mươi bốn khúc từ lấy cây vô căn làm ẩn dụ: thân người dễ tàn như cây không rễ, cần nghịch tu để nối nhánh non. Lý Hàm Hư, Lưu Nhất Minh đều có chú; cùng Ngộ Chân thiên là hai đỉnh từ–thi nội đan.",key_text:"无根树，花正幽，贪恋红尘谁肯修？",use:"Khẩu quyết thi từ / nghịch tu cảnh tỉnh",sources:["https://zh.wikisource.org/zh-hans/%E7%84%A1%E6%A0%B9%E6%A8%B9","https://baike.baidu.com/item/%E6%97%A0%E6%A0%B9%E6%A0%91/9575105","https://ctext.org/wiki.pl?if=gb&res=993393&remap=gb"],textual_certainty:"high",notes:"batch64 · Grok-4.5 藏外/辑要 continuation"},{dz:"null",name_han:"七破论",name_vi:"Thất Phá Luận",bu:"藏外·方壶外史（东派）",author:"陆西星",era:"明万历前后",topic:"philosophy",essence:"Bảy thiên trong Phương Hồ Ngoại Sử, đả phá tà thuật và kiến giải sai lệch đương thời (phá mê, phá vọng…). Cùng Kim Đan Đại Chỉ Đồ kết thúc toàn tập, định ranh giới chính–tà của Đông phái.",key_text:"null",use:"Biện tà / lập cương lĩnh Đông phái",sources:["https://zh.wikisource.org/zh-hans/%E6%96%B9%E5%A3%BA%E5%A4%96%E5%8F%B2","https://baike.baidu.com/item/%E4%B8%83%E7%A0%B4%E8%AE%BA/17618167","https://www.shuge.org/view/fang_hu_wai_shi/"],textual_certainty:"high",notes:"batch64 · Grok-4.5 藏外/辑要 continuation"},{dz:"null",name_han:"金丹大旨图",name_vi:"Kim Đan Đại Chỉ Đồ",bu:"藏外·方壶外史（东派）",author:"陆西星",era:"明万历前后",topic:"cultivation",essence:"Tám đồ hình + thuyết minh tóm tắt cương lĩnh kim đan: từ vô cực tiên thiên đến dược vật–hỏa hầu. Lục Tây Tinh tự nói ‘cử cương thuyết ước’, dùng đồ thay văn dài.",key_text:"金丹之道，至易至简，有所安排布置，则涉邪伪而非自然。",use:"Sơ đồ tổng quan Đông phái / giảng cương",sources:["https://zh.wikisource.org/zh-hant/%E9%87%91%E4%B8%B9%E5%A4%A7%E6%97%A8%E5%9C%96","https://ctext.org/wiki.pl?if=en&chapter=1324137&remap=gb","https://www.shuge.org/view/fang_hu_wai_shi/"],textual_certainty:"high",notes:"batch64 · Grok-4.5 藏外/辑要 continuation"},{dz:"null",name_han:"老子道德经玄览",name_vi:"Lão Tử Đạo Đức Kinh Huyền Lãm",bu:"藏外·方壶外史（东派）",author:"陆西星",era:"明",topic:"classic",essence:"Chú sớ Đạo Đức Kinh theo hướng nội đan–huyền học Đông phái, hai quyển thượng/hạ. Cùng Âm Phù trắc sớ và Tham Đồng trắc sớ tạo bộ ‘đạo thư đo sớ’ của Lục Tây Tinh.",key_text:"null",use:"Đọc Đạo Đức qua lăng kính Đông phái",sources:["https://zh.wikisource.org/zh-hans/%E6%96%B9%E5%A3%BA%E5%A4%96%E5%8F%B2","https://baike.baidu.com/item/%E6%96%B9%E5%A3%B6%E5%A4%96%E5%8F%B2/4742448","https://crta.info/wiki/%E6%96%B9%E5%A3%BA%E5%A4%96%E5%8F%B2%E5%8F%A2%E7%B7%A8_-_K129"],textual_certainty:"high",notes:"batch64 · Grok-4.5 藏外/辑要 continuation"},{dz:"null",name_han:"周易阐真",name_vi:"Chu Dịch Xiển Chân",bu:"藏外·道书十二种",author:"刘一明",era:"清乾嘉",topic:"classic",essence:"Năm quyển lấy đan đạo giải Dịch: ‘Đan đạo tức Dịch đạo’. Cùng Khổng Dịch Xiển Chân tạo Dịch Lý Xiển Chân, là trụ cột Dịch–đan của Lưu Nhất Minh.",key_text:"null",use:"Dịch học nội đan / lý luận hỏa hầu quẻ",sources:["https://zh.wikisource.org/zh-hans/%E9%81%93%E6%9B%B8%E5%8D%81%E4%BA%8C%E7%A8%AE","https://baike.baidu.com/item/%E9%81%93%E4%B9%A6%E5%8D%81%E4%BA%8C%E7%A7%8D/4742432","https://zh.daoinfo.org/index.php?title=%E9%81%93%E6%9B%B8%E5%8D%81%E4%BA%8C%E7%A8%AE&variant=zh-hans"],textual_certainty:"high",notes:"batch64 · Grok-4.5 藏外/辑要 continuation"},{dz:"null",name_han:"西游原旨",name_vi:"Tây Du Nguyên Chỉ",bu:"藏外·道书十二种",author:"刘一明",era:"清乾嘉",topic:"classic",essence:"Đọc Tây Du Ký như kinh đan: ‘tam giáo nhất gia, tính mệnh song tu’. Có tự, độc pháp, ca và chú từng hồi; ảnh hưởng lớn dòng ‘Tây Du đan thư’ đời sau.",key_text:"西游一书，为邱真君著作，人皆艳闻乐道，而未有能知其原旨者。",use:"Ẩn dụ văn học–đan đạo / giáo khoa allegory",sources:["https://zh.wikisource.org/zh-hans/%E8%A5%BF%E9%81%8A%E5%8E%9F%E6%97%A8","https://ctext.org/wiki.pl?if=gb&res=505146","https://zh.daoinfo.org/index.php?title=%E9%81%93%E6%9B%B8%E5%8D%81%E4%BA%8C%E7%A8%AE&variant=zh-hans"],textual_certainty:"high",notes:"batch64 · Grok-4.5 藏外/辑要 continuation"},{dz:"null",name_han:"悟道录",name_vi:"Ngộ Đạo Lục",bu:"藏外·道书十二种",author:"刘一明",era:"清乾嘉",topic:"philosophy",essence:"Hai quyển: tám mươi mốt đề từ hiện tượng trời–đất–người (trời cao đất dày, trẻ thơ thiên chân…) điểm ngộ tu đạo, kèm Thán đạo ca. Phong cách ‘tức vật ngộ lý’, dễ tiếp cận hơn biện nạn huyền.",key_text:"null",use:"Thiền–đạo khẩu quyết đời thường / khuyến tu",sources:["https://zh.wikisource.org/zh-hans/%E9%81%93%E6%9B%B8%E5%8D%81%E4%BA%8C%E7%A8%AE","https://baike.baidu.com/item/%E9%81%93%E4%B9%A6%E5%8D%81%E4%BA%8C%E7%A7%8D/4742432","https://zh.daoinfo.org/index.php?title=%E9%81%93%E6%9B%B8%E5%8D%81%E4%BA%8C%E7%A8%AE&variant=zh-hans"],textual_certainty:"high",notes:"batch64 · Grok-4.5 藏外/辑要 continuation"},{dz:"null",name_han:"敲爻歌直解",name_vi:"Xao Hào Ca Trực Giải",bu:"藏外·道书十二种",author:"刘一明",era:"清乾嘉",topic:"cultivation",essence:"Chú thẳng Xao Hào Ca (truyền Lữ Tổ), giải hào–hỏa hầu và tiến thoái. Nằm nhóm chú đan kinh của Lưu (cùng Bách tự bi, Vô căn thụ giải).",key_text:"null",use:"Hỏa hầu ca chú / đối chiếu Lữ Tổ",sources:["https://zh.wikisource.org/zh-hans/%E9%81%93%E6%9B%B8%E5%8D%81%E4%BA%8C%E7%A8%AE","https://baike.baidu.com/item/%E9%81%93%E4%B9%A6%E5%8D%81%E4%BA%8C%E7%A7%8D/4742432","https://zh.daoinfo.org/index.php?title=%E9%81%93%E6%9B%B8%E5%8D%81%E4%BA%8C%E7%A8%AE&variant=zh-hans"],textual_certainty:"high",notes:"batch64 · Grok-4.5 藏外/辑要 continuation"},{dz:"null",name_han:"道书一贯真机易简录",name_vi:"Đạo Thư Nhất Quán Chân Cơ Dịch Giản Lục",bu:"藏外·济一子证道秘书/道书十七种",author:"傅金铨",era:"清嘉庆癸酉（1813）序",topic:"cultivation",essence:"Nhiều quyển hệ thống ‘chân cơ nhất quán’: pháp tài lữ địa, đỉnh lô phù hỏa, luyện kỷ trúc cơ, tri thời thái dược… Giọng ‘chí giản chí dị’, là bản tổng cương đan pháp song tu của Phù Kim Thuyên.",key_text:"真正至道，至简至易。",use:"Cương mục Đông/Tịnh Minh song tu / tra cứu tiết độ",sources:["https://ctext.org/wiki.pl?if=gb&res=675903&remap=gb","https://zh.daoinfo.org/index.php?title=%E5%82%85%E9%87%91%E9%8A%93&variant=zh-hans","https://zh.wikisource.org/zh-hant/%E6%BF%9F%E4%B8%80%E5%AD%90%E9%81%93%E6%9B%B8%E5%8D%81%E4%B8%83%E7%A8%AE"],textual_certainty:"high",notes:"batch64 · Grok-4.5 藏外/辑要 continuation"},{dz:"null",name_han:"赤水吟",name_vi:"Xích Thủy Ngâm",bu:"藏外·济一子道书十七种",author:"傅金铨",era:"清嘉庆—道光",topic:"cultivation",essence:"Thi ca đan đạo tự soạn trong Tế Nhất Tử Đạo Thư Thập Thất Chủng. Dùng thi ngôn truyền huyền, cùng Bôi Khê Lục và các chú đỉnh lô tạo phong cách ‘thi–đan’ của Phù.",key_text:"null",use:"Khẩu quyết thi ca / đối chiếu thực tu Phù phái",sources:["https://zh.wikisource.org/zh-hant/%E6%BF%9F%E4%B8%80%E5%AD%90%E9%81%93%E6%9B%B8%E5%8D%81%E4%B8%83%E7%A8%AE","https://baike.baidu.com/item/%E5%82%85%E9%87%91%E9%93%A8/5975971","https://zh.daoinfo.org/index.php?title=%E5%82%85%E9%87%91%E9%8A%93&variant=zh-hans"],textual_certainty:"high",notes:"batch64 · Grok-4.5 藏外/辑要 continuation"},{dz:"null",name_han:"性命要旨",name_vi:"Tính Mệnh Yếu Chỉ",bu:"藏外·西派体真山人",author:"汪东亭（汪启濩）",era:"清光绪十三年（1887）",topic:"cultivation",essence:"Tác phẩm đại diện Tây phái thanh tịnh môn: nêu huyền quan, thái dược, tiểu–đại chu thiên, thập nguyệt thai, xuất thần; có thiên tịch tà. Chống ‘tai tiếp’ ngoại cầu, nhấn ‘dược tại gia trung’.",key_text:"大道起手，在乎性命，两者合一，得其把柄。",use:"Thực tu Tây phái / đối chiếu Ngũ Liễu",sources:["https://zh.wikisource.org/wiki/%E6%80%A7%E5%91%BD%E8%A6%81%E6%97%A8","https://baike.baidu.com/item/%E6%80%A7%E5%91%BD%E8%A6%81%E6%97%A8/4341256","https://www.daoist.org/BookSearch(test)/list012/88-75.pdf"],textual_certainty:"high",notes:"batch64 · Grok-4.5 藏外/辑要 continuation"},{dz:"null",name_han:"孙不二女功内丹次第诗注",name_vi:"Tôn Bất Nhị Nữ Công Nội Đan Thứ Đệ Thi Chú",bu:"藏外·仙学（陈撄宁早期）",author:"陈撄宁（注孙不二诗）",era:"民国前期（约1930s）",topic:"cultivation",essence:"Chú mười bốn bài thơ nữ đan của Tôn Bất Nhị (Toàn Chân Bắc Tông). Phân biệt công phu nam–nữ, khai nữ tông hiện đại; cùng Hoàng Đình Kinh Giảng Nghĩa là hai trụ nữ đan sớm của Trần.",key_text:"null",use:"Nữ đan thứ tự / nghiên cứu tiên học cận–hiện đại",sources:["https://zhuanlan.zhihu.com/p/368448761","https://taiwan.yin-xian.com/index.php/2010-10-05-07-04-00/2017-02-20-07-18-18/736-2015-06-04-14-40-25","https://prolife.666forum.com/t314-topic"],textual_certainty:"high",notes:"batch64 · Grok-4.5 藏外/辑要 continuation"},{dz:"null",name_han:"老子翼",name_vi:"Lão Tử Dực",bu:"藏外·老学注疏",author:"焦竑",era:"明",topic:"classic",essence:"Tiêu Hằng (Tiêu Hoành) biên tập các chú giải Đạo Đức Kinh từ Hán đến Minh, kèm bình luận. Đây là bộ sưu tập chú Lão quan trọng nhất thời Minh, bảo tồn nhiều dị bản và kiến giải. Thuộc tàng ngoại, không có số DZ trong Chính Thống Đạo Tạng.",key_text:"道冲而用之或不盈，渊兮似万物之宗。",use:"Đối chiếu nhiều chú Lão qua các đời; nghiên cứu lịch sử chú giải Đạo Đức Kinh",sources:["https://ctext.org/wiki.pl?if=gb&res=143905","https://zh.wikipedia.org/wiki/%E7%84%A6%E5%BC%98"],textual_certainty:"high",notes:"batch65 · Grok-4.5 藏外/辑要 老学+全真"},{dz:"null",name_han:"道德经注（王夫之）",name_vi:"Đạo Đức Kinh Chú (Vương Phu Chi)",bu:"藏外·老学注疏",author:"王夫之",era:"清",topic:"philosophy",essence:"Vương Phu Chi chú Đạo Đức Kinh với tư duy triết học sâu, phê phán huyền học suông và nhấn mạnh thực tiễn. Bản chú phản ánh học phong Minh–Thanh, dung hòa Lão học với kinh nghiệm lịch sử. Thuộc tàng ngoại, bản văn lưu trong di cảo Vương Thuyền Sơn.",key_text:"有物混成，先天地生。",use:"Nghiên cứu triết học Lão Tử thời Thanh; đối chiếu với chú huyền đan",sources:["https://zh.wikisource.org/wiki/%E8%80%81%E5%AD%90%E8%A1%8D","https://baike.baidu.com/item/%E8%80%81%E5%AD%90%E8%A1%8D"],textual_certainty:"partial",notes:"batch65 · Grok-4.5 藏外/辑要 老学+全真"},{dz:"null",name_han:"道德宝章",name_vi:"Đạo Đức Bảo Chương",bu:"藏外·老学注疏/全真南宗",author:"白玉蟾",era:"南宋",topic:"cultivation",essence:"Bạch Ngọc Thiềm chú Đạo Đức Kinh theo hướng nội đan Nam Tông, coi kinh văn là mật chỉ tu luyện. Văn chú ngắn gọn, thiên về đan đạo và tâm tính. Đây là tác phẩm lão học tiêu biểu của Toàn Chân Nam Tông ngoài/biên tàng.",key_text:"谷神不死，是谓玄牝。",use:"Đọc Lão qua lăng kính nội đan Nam Tông; tham khảo tu luyện tâm tính",sources:["https://ctext.org/wiki.pl?if=gb&res=615481","https://zh.wikipedia.org/wiki/%E7%99%BD%E7%8E%89%E8%9F%BE"],textual_certainty:"high",notes:"batch65 · Grok-4.5 藏外/辑要 老学+全真"},{dz:"null",name_han:"道德经解（李道纯）",name_vi:"Đạo Đức Kinh Giải (Lý Đạo Thuần)",bu:"藏外·老学注疏/全真",author:"李道纯",era:"元",topic:"cultivation",essence:"Lý Đạo Thuần giải Đạo Đức Kinh theo hướng đan đạo Toàn Chân, dung hợp tam giáo. Chú trọng trung hòa, hư tĩnh và luyện kỷ. Thuộc dòng chú Lão đan học Nguyên đại, thường lưu trong tập tác của ông và tàng ngoại/tập yếu.",key_text:"致虚极，守静笃。",use:"Tu luyện theo chỉ trung hòa; kết hợp Lão học với nội đan Toàn Chân",sources:["https://ctext.org/wiki.pl?if=gb&res=276152","https://zh.wikipedia.org/wiki/%E6%9D%8E%E9%81%93%E7%B4%94"],textual_certainty:"high",notes:"batch65 · Grok-4.5 藏外/辑要 老学+全真"},{dz:"null",name_han:"青天歌注释（王道渊）",name_vi:"Thanh Thiên Ca Chú Thích (Vương Đạo Uyên)",bu:"藏外·全真北宗",author:"王道渊",era:"明",topic:"cultivation",essence:"Vương Đạo Uyên chú thích bài Thanh Thiên Ca của Khâu Xử Cơ, giải mã hình tượng đan đạo. Làm rõ ý chỉ “thanh thiên” là bản thể hư minh và công phu phản chiếu. Thuộc dòng chú giải Toàn Chân Bắc Tông tàng ngoại/truyền bản.",key_text:"青天莫起浮云障，云起青天遮万象。",use:"Đọc ca quyết Bắc Tông; liên hệ tâm tính với nội đan",sources:["https://zh.wikisource.org/wiki/%E9%9D%92%E5%A4%A9%E6%AD%8C","https://baike.baidu.com/item/%E9%9D%92%E5%A4%A9%E6%AD%8C"],textual_certainty:"high",notes:"batch65 · Grok-4.5 藏外/辑要 老学+全真"},{dz:"null",name_han:"五篇灵文（邱长春注）",name_vi:"Ngũ Thiên Linh Văn (Khâu Trường Xuân chú)",bu:"藏外/辑要·全真北宗",author:"王重阳（文）/丘处机（注）",era:"金元",topic:"cultivation",essence:"Ngũ Thiên Linh Văn được truyền là mật chỉ Vương Trùng Dương, có chú của Khâu Xử Cơ. Luận về linh dược, hỏa hầu và phản bản hoàn nguyên theo Bắc Tông. Thuộc nhóm kinh điển mật truyền Toàn Chân, lưu trong tàng ngoại và Đạo Tạng Tập Yếu.",key_text:"金液还丹，在乎真水真火。",use:"Nghiên cứu mật chỉ nội đan Bắc Tông; đối chiếu với Ngộ Chân thiên",sources:["https://baike.baidu.com/item/%E4%BA%94%E7%AF%87%E7%81%B5%E6%96%87","https://zh.wikipedia.org/wiki/%E5%85%A8%E7%9C%9F%E6%95%99"],textual_certainty:"partial",notes:"batch65 · Grok-4.5 藏外/辑要 老学+全真"},{dz:"null",name_han:"仙道还元真经",name_vi:"Tiên Đạo Hoàn Nguyên Chân Kinh",bu:"古书隐楼藏书",author:"闵一得（辑传）",era:"清",topic:"cultivation",essence:"Kinh văn trong hệ Cổ Thư Ẩn Lâu, do Mẫn Nhất Đắc biên truyền, luận hoàn nguyên tiên đạo. Kết hợp tâm truyền Long Môn với chỉ dẫn công phu thực tiễn. Thuộc tàng ngoại tập thành thời Thanh, không thuộc Chính Thống Đạo Tạng.",key_text:"还元者，复其先天之真也。",use:"Tu theo hệ Mẫn Nhất Đắc/Long Môn; đối chiếu với Thiên Tiên Tâm Truyền",sources:["https://baike.baidu.com/item/%E5%8F%A4%E4%B9%A6%E9%9A%90%E6%A5%BC%E8%97%8F%E4%B9%A6","https://zh.wikipedia.org/wiki/%E9%96%94%E4%B8%80%E5%BE%97"],textual_certainty:"partial",notes:"batch65 · Grok-4.5 藏外/辑要 老学+全真"},{dz:"null",name_han:"泄天机",name_vi:"Tiết Thiên Cơ",bu:"古书隐楼藏书",author:"黄元吉（传）/闵一得系传本",era:"清",topic:"cultivation",essence:"Luận đan đạo “tiết lộ thiên cơ” theo lối vấn đáp, giải thích huyền quan, dược vật, hỏa hầu. Có truyền bản gắn hệ Cổ Thư Ẩn Lâu và các bản tàng ngoại Thanh đại. Văn phong trực tiếp, thiên về chỉ dẫn thực tu hơn huyền thoại.",key_text:"天机不可轻泄，然不开示则道绝。",use:"Học đan quyết vấn đáp; tham khảo công phu hỏa hầu",sources:["https://baike.baidu.com/item/%E6%B3%84%E5%A4%A9%E6%9C%BA","https://zh.wikipedia.org/wiki/%E9%BB%83%E5%85%83%E5%90%89"],textual_certainty:"partial",notes:"batch65 · Grok-4.5 藏外/辑要 老学+全真"},{dz:"null",name_han:"乐育堂语录",name_vi:"Lạc Dục Đường Ngữ Lục",bu:"藏外·全真/内丹",author:"黄元吉",era:"清",topic:"cultivation",essence:"Ngữ lục của Hoàng Nguyên Cát dạy đệ tử tại Lạc Dục Đường, giải thích tính mệnh song tu theo lối dễ hiểu. Nhấn mạnh đạo khí, hư tâm và công phu hàng ngày. Đây là kinh điển nội đan Thanh đại nổi tiếng, thuộc tàng ngoại.",key_text:"修道之人，先贵虚心。",use:"Đọc ngữ lục thực tu; nhập môn tính mệnh song tu dễ tiếp cận",sources:["https://baike.baidu.com/item/%E4%B9%90%E8%82%B2%E5%A0%82%E8%AF%AD%E5%BD%95","https://zh.wikipedia.org/wiki/%E9%BB%83%E5%85%83%E5%90%89"],textual_certainty:"high",notes:"batch65 · Grok-4.5 藏外/辑要 老学+全真"},{dz:"null",name_han:"道门语要",name_vi:"Đạo Môn Ngữ Yếu",bu:"道藏辑要/藏外",author:"黄元吉",era:"清",topic:"cultivation",essence:"Hoàng Nguyên Cát tóm yếu ngữ đạo môn, luận về đạo thể, công phu và xử thế. Văn ngắn, súc tích, dùng làm cẩm nang nhập môn cho đệ tử. Thường được xếp cạnh Lạc Dục Đường Ngữ Lục trong truyền bản tàng ngoại/tập yếu.",key_text:"道在目前，人自远之。",use:"Tóm tắt tinh yếu đạo môn; học kèm Lạc Dục Đường Ngữ Lục",sources:["https://baike.baidu.com/item/%E9%81%93%E9%97%A8%E8%AF%AD%E8%A6%81","https://zh.wikipedia.org/wiki/%E9%BB%83%E5%85%83%E5%90%89"],textual_certainty:"high",notes:"batch65 · Grok-4.5 藏外/辑要 老学+全真"},{dz:"null",name_han:"黄庭经讲义（陈撄宁）",name_vi:"Hoàng Đình Kinh Giảng Nghĩa (Trần Anh Ninh)",bu:"藏外·仙学（陈撄宁系）",author:"陈撄宁（圆顿子）",era:"民国（约1933–1934）",topic:"cultivation",essence:"Trần Anh Ninh dùng quan điểm Tiên học hiện đại giảng rõ nội–ngoại cảnh Hoàng Đình, nhấn mạnh trung cung hư không và tàng tinh dưỡng thần. Tác phẩm tách kỹ thuật tu luyện khỏi khung nghi lễ thuần tôn giáo, trở thành giáo trình nền của tiên học cận đại.",key_text:"黄乃土色，土位中央；庭乃阶前空地，名为黄庭，即表示中空之意。",use:"Nhập môn Hoàng Đình và lý luận Tiên học Trần Anh Ninh; đối chiếu nội–ngoại cảnh, trung cung, tàng tinh.",sources:["https://baike.baidu.com/item/%E3%80%8A%E9%BB%84%E5%BA%AD%E7%BB%8F%E3%80%8B%E8%AE%B2%E4%B9%89/55753286","https://baike.baidu.com/item/%E9%BB%84%E5%BA%AD%E7%BB%8F/6240400","https://taiwan.yin-xian.com/index.php/2010-10-05-07-04-00/2017-02-20-07-18-18/736-2015-06-04-14-40-25"],textual_certainty:"high",notes:"batch66 · Grok-4.5 藏外 仙学/千峰/西派/古书隐楼"},{dz:"null",name_han:"灵源大道歌白话注解（陈撄宁）",name_vi:"Linh Nguyên Đại Đạo Ca Bạch Thoại Chú Giải (Trần Anh Ninh)",bu:"藏外·仙学（陈撄宁系）",author:"陈撄宁（圆顿子）；原诗曹文逸",era:"民国（1938）",topic:"cultivation",essence:"Chú giải bạch thoại bài Linh Nguyên Đại Đạo Ca của Tào Văn Dật, nhấn mạnh thần khí hỗn hợp, bất ngoại trì và đạo dễ biết khó làm. Trần Anh Ninh coi đây là pháp môn ổn định, phổ độ nhất trong tiên đạo.",key_text:"神是性兮气是命，神不外驰气自定。",use:"Tu tĩnh công và tính mệnh sơ cấp; bài ca thực hành an toàn của tiên học cận đại.",sources:["https://baike.baidu.com/item/%E3%80%8A%E7%81%B5%E6%BA%90%E5%A4%A7%E9%81%93%E6%AD%8C%E3%80%8B%E7%99%BD%E8%AF%9D%E6%B3%A8%E8%A7%A3/55754179","https://crta.info/wiki/%E9%9D%88%E6%BA%90%E5%A4%A7%E9%81%93%E6%AD%8C%E7%99%BD%E8%A9%B1%E8%A8%BB%E8%A7%A3_-_K77","https://zh.wikisource.org/zh-hans/%E9%9D%88%E6%BA%90%E5%A4%A7%E9%81%93%E6%AD%8C"],textual_certainty:"high",notes:"batch66 · Grok-4.5 藏外 仙学/千峰/西派/古书隐楼"},{dz:"null",name_han:"口诀钩玄录（陈撄宁）",name_vi:"Khẩu Quyết Câu Huyền Lục (Trần Anh Ninh)",bu:"藏外·仙学（陈撄宁系）",author:"陈撄宁（据黄元吉《道德经讲义》《乐育堂语录》钩玄）",era:"民国（约1930s，《扬善半月刊》）",topic:"cultivation",essence:"Trần Anh Ninh trích yếu khẩu quyết từ Hoàng Nguyên Cát, làm rõ huyền quan nhất khiếu và công pháp thiên nguyên. Bản sơ tập đăng trên Dương Thiện bán nguyệt san; vì sợ lậu thiên cơ nên chưa hoàn thành toàn bộ.",key_text:"本集内容，概依清朝光绪时代江西丰城黄元吉先生所撰《道德经讲义》并《乐育堂语录》二书为根据。",use:"Thực tu khẩu quyết phái ẩn tiên / Hoàng Nguyên Cát qua lăng kính Tiên học.",sources:["https://zhuanlan.zhihu.com/p/714099874","https://www.daoisms.com.cn/2025/30/23/118811/","https://play.google.com/store/books/details/%E9%99%B3%E6%94%96%E5%AF%A7_%E9%99%B3%E6%94%96%E5%AF%A7%E6%96%87%E9%9B%86%E4%B8%80?id=PqH6DwAAQBAJ"],textual_certainty:"high",notes:"batch66 · Grok-4.5 藏外 仙学/千峰/西派/古书隐楼"},{dz:"null",name_han:"卫生生理学明指（赵避尘）",name_vi:"Vệ Sinh Sinh Lý Học Minh Chỉ (Triệu Tị Trần)",bu:"藏外·千峰先天派",author:"赵避尘（千峰老人、顺一子）",era:"民国（约1930s；与《性命法诀明指》同期系统）",topic:"道医养生",essence:"Triệu Tị Trần dùng sinh lý học và giải phẫu cận đại giải thích tinh khí thần, hoàn tinh bổ não. Bổ sung cho Tính Mệnh Pháp Quyết Minh Chỉ, nhấn mạnh “chân vệ sinh” và hình ảnh hóa đường khí.",key_text:"null",use:"Đối chiếu đan đạo–y sinh hiện đại; vệ sinh thân thể và tính mệnh song tu.",sources:["https://baike.baidu.com/item/%E5%8D%AB%E7%94%9F%E7%94%9F%E7%90%86%E5%AD%A6%E6%98%8E%E6%8C%87/22692958","https://baike.baidu.com/item/%E8%B5%B5%E9%81%BF%E5%B0%98/2529141","https://www.daoist.org/BookSearch(test)/list012/84-84.pdf"],textual_certainty:"high",notes:"batch66 · Grok-4.5 藏外 仙学/千峰/西派/古书隐楼"},{dz:"null",name_han:"教外别传（汪东亭）",name_vi:"Giáo Ngoại Biệt Truyền (Uông Đông Đình)",bu:"藏外·西派（体真山人）",author:"汪东亭（体真山人）",era:"清–民初（约晚年，六十岁前后）",topic:"cultivation",essence:"Tác phẩm hậu kỳ của Uông Đông Đình, đả phá tài tiếp/âm dương sai lệch, nhấn mạnh giáo ngoại biệt truyền và tiên thiên nhất điểm chân dương. Đánh dấu chuyển hướng tư tưởng so với Tính Mệnh Yếu Chỉ.",key_text:"null",use:"Tây phái hậu kỳ; biện chính song tu–thanh tu và giáo ngoại bí truyền.",sources:["https://baike.baidu.com/item/%E6%80%A7%E5%91%BD%E8%A6%81%E6%97%A8/4341256","https://www.daoist.org/BookSearch(test)/list012/88-75.pdf","http://ab.newdu.com/book/b1931.html"],textual_certainty:"high",notes:"batch66 · Grok-4.5 藏外 仙学/千峰/西派/古书隐楼"},{dz:"null",name_han:"天乐集（徐颂尧）",name_vi:"Thiên Lạc Tập (Từ Tụng Nghiêu)",bu:"藏外·西派（海印子）",author:"徐颂尧（海印子、玄静居士）",era:"民国（约1930–1960s；今存残本约八卷）",topic:"cultivation",essence:"Hải Ấn tử Từ Tụng Nghiêu kết hợp khẩu quyết Tây phái Uông Đông Đình với Nho–Thích, bàn huyền quan, tiểu–đại chu thiên, tâm tức. Bản túc bản hàng chục quyển thất lạc thời Cách mạng Văn hóa; bản hiện hành là di cảo quan trọng.",key_text:"null",use:"Tây phái cận đại; huyền quan thể dụng, tâm tức tương y, hợp tham thiền–đan.",sources:["https://baike.baidu.com/item/%E5%A4%A9%E4%B9%90%E9%9B%86/12340134","https://baike.baidu.com/item/%E5%A4%A9%E4%B9%90%E9%9B%86%EF%BC%9A%E9%81%93%E6%95%99%E8%A5%BF%E6%B4%BE%E6%B5%B7%E5%8D%B0%E5%AD%90%E5%86%85%E4%B8%B9%E4%BF%AE%E7%82%BC%E5%85%B8%E7%B1%8D/16359909","https://www.daoisms.com.cn/2018/17/09/6737/"],textual_certainty:"high",notes:"batch66 · Grok-4.5 藏外 仙学/千峰/西派/古书隐楼"},{dz:"null",name_han:"太上十三经注解（李涵虚）",name_vi:"Thái Thượng Thập Tam Kinh Chú Giải (Lý Hàm Hư)",bu:"藏外·西派（圆峤内篇/道言十五种）",author:"李涵虚（李西月、长乙山人）",era:"清咸丰前后",topic:"classic",essence:"Lý Hàm Hư chú giải hệ kinh Thái Thượng (Đạo Đức, Âm Phù, Hoàng Đình ngoại cảnh, Thanh Tĩnh, Ngọc Xu v.v.), đặt nền kinh điển cho Tây phái. Thuộc nhóm “Đạo ngôn thập ngũ chủng” đã lưu hành trước Đạo Khiếu Đàm / Tam Xa Bí Chỉ.",key_text:"《十三经注解》，皆老子书也。《道德》一注，最为精详。",use:"Tây phái kinh chú; Đạo Đức–Âm Phù–Hoàng Đình theo hệ Lý Hàm Hư.",sources:["https://zh.wikisource.org/zh-hans/%E5%9C%93%E5%B6%A0%E5%85%A7%E7%AF%87/%E5%A4%AA%E4%B8%8A%E5%8D%81%E4%B8%89%E7%B6%93%E6%B3%A8%E8%A7%A3","https://ctext.org/wiki.pl?if=gb&chapter=692136","https://baike.baidu.com/item/%E5%9C%86%E5%B3%A4%E5%86%85%E7%AF%87%EF%BC%9A%E9%81%93%E6%95%99%E8%A5%BF%E6%B4%BE%E6%9D%8E%E6%B6%B5%E8%99%9A%E5%86%85%E4%B8%B9%E4%BF%AE%E7%82%BC%E7%A7%98%E7%B1%8D/9001418"],textual_certainty:"high",notes:"batch66 · Grok-4.5 藏外 仙学/千峰/西派/古书隐楼"},{dz:"null",name_han:"碧苑坛经（龙门心法）",name_vi:"Bích Uyển Đàn Kinh (Long Môn Tâm Pháp)",bu:"藏外·古书隐楼藏书 / 全真龙门",author:"王常月演；施守平纂；闵一得订正",era:"清初讲戒（康熙二年），闵一得订入《古书隐楼藏书》",topic:"戒律",essence:"Ngữ lục thuyết giới của Vương Thường Nguyệt tại Kim Lăng Bích Uyển: tam quy y, sám hối, trì giới, thanh tĩnh thân tâm. Khẳng định “dục tu tiên đạo, tiên tu nhân đạo”, là kinh điển trung hưng Long Môn.",key_text:"欲修仙道，先修人道；人道不修，仙道远矣。",use:"Giới luật Long Môn; tâm pháp xuất gia và “nhân đạo–tiên đạo”.",sources:["https://zh.wikisource.org/zh-hans/%E7%A2%A7%E8%8B%91%E5%A3%87%E7%B6%93","https://baike.baidu.com/item/%E7%A2%A7%E8%8B%91%E5%9D%9B%E7%BB%8F/17617082","https://ctext.org/wiki.pl?if=gb&res=195080"],textual_certainty:"high",notes:"batch66 · Grok-4.5 藏外 仙学/千峰/西派/古书隐楼"},{dz:"null",name_han:"上品丹法节次（闵一得续纂）",name_vi:"Thượng Phẩm Đan Pháp Tiết Thứ (Mẫn Nhất Đắc tục soạn)",bu:"藏外·古书隐楼藏书",author:"李德洽原述；闵一得续纂",era:"清（收入《古书隐楼藏书》第七册）",topic:"cultivation",essence:"Mười hai tiết thứ thượng phẩm: luyện kỷ tồn thành → trúc cơ → khảm ly → thái dược → chu thiên → càn khôn → dưỡng thai → di thần → hoàn hư → hợp đạo. Mẫn Nhất Đắc hiệu đính, phân biệt thượng–trung–hạ phẩm.",key_text:"尝观红尘之中，纷纷扰扰，大抵皆汨于利欲……必先存诚以炼己。",use:"Thứ đệ nội đan Long Môn/Kim Cái; lộ trình thượng phẩm có chú Mẫn.",sources:["https://zh.wikisource.org/zh-hans/%E4%B8%8A%E5%93%81%E4%B8%B9%E6%B3%95%E7%AF%80%E6%AC%A1","https://ctext.org/wiki.pl?if=gb&res=195080","https://zh.wikisource.org/zh-hans/%E5%8F%A4%E6%9B%B8%E9%9A%B1%E6%A8%93%E8%97%8F%E6%9B%B8"],textual_certainty:"high",notes:"batch66 · Grok-4.5 藏外 仙学/千峰/西派/古书隐楼"},{dz:"null",name_han:"吕祖师三尼医世功诀（闵一得）",name_vi:"Lữ Tổ Sư Tam Ni Y Thế Công Quyết (Mẫn Nhất Đắc)",bu:"藏外·古书隐楼藏书 / 道医",author:"托名吕祖；沈一炳授；闵一得重述并注",era:"清（古书隐楼藏书第五册）",topic:"道医养生",essence:"“Tam Ni” = Trọng Ni–Mâu Ni–Thanh Ni; y thế tức thân thế bất nhị: trị thân tức trị thế. Kết hợp nội đan với công đức “thân quốc đồng trị”, đặc sắc tư tưởng y thế của Mẫn Nhất Đắc.",key_text:"三尼者，仲尼，牟尼，青尼也。世，世界也。按此世字，兼身而言，乃是即身以医世也。",use:"Đạo y / y thế; thân–quốc đồng trị và công quyết nội luyện.",sources:["https://zh.wikisource.org/zh-hans/%E5%91%82%E7%A5%96%E5%B8%AB%E4%B8%89%E5%B0%BC%E9%86%AB%E4%B8%96%E5%8A%9F%E8%A8%A3","https://ctext.org/wiki.pl?if=gb&chapter=3213891","https://baike.baidu.com/item/%E5%90%95%E7%A5%96%E5%B8%88%E4%B8%89%E5%B0%BC%E5%8C%BB%E4%B8%96%E8%AF%B4%E8%BF%B0/17626942"],textual_certainty:"high",notes:"batch66 · Grok-4.5 藏外 仙学/千峰/西派/古书隐楼"},{dz:"null",name_han:"西王母女修正途十则（闵一得注）",name_vi:"Tây Vương Mẫu Nữ Tu Chính Đồ Thập Tắc (Mẫn Nhất Đắc chú)",bu:"藏外·古书隐楼藏书 / 女丹",author:"托名西王母/吕祖；沈太虚授；闵一得注正",era:"清（古书隐楼藏书第十册）",topic:"内丹女丹",essence:"Mười tắc nữ tu chính đồ: từ giới luật, dưỡng chân đến hoàn đan, dành riêng sinh lý nữ. Mẫn Nhất Đắc chú chính, thuộc hệ nữ đan thanh tu (thái âm luyện hình).",key_text:"纯阳子誓渡众生，已有《九皇丹经注》，为男子修仙之津梁。",use:"Nữ đan thanh tu; thập tắc chính lộ và giới nữ tu.",sources:["https://zh.wikisource.org/wiki/%E8%A5%BF%E7%8E%8B%E6%AF%8D%E5%A5%B3%E4%BF%AE%E6%AD%A3%E9%80%94%E5%8D%81%E5%89%87","https://zh.wikisource.org/zh-hans/%E5%8F%A4%E6%9B%B8%E9%9A%B1%E6%A8%93%E8%97%8F%E6%9B%B8","http://www.taoist.org.cn/showInfoContent.do?id=1861&p=%27p%27"],textual_certainty:"high",notes:"batch66 · Grok-4.5 藏外 仙学/千峰/西派/古书隐楼"},{dz:"null",name_han:"壶天性果女丹十则",name_vi:"Hồ Thiên Tính Quả Nữ Đan Thập Tắc",bu:"道藏辑要·女丹合编（贺龙骧辑）",author:"托名华藏山清烈古佛；收入贺龙骧《女丹合编》",era:"清（光绪三十二年/1906 二仙庵重刻道藏辑要）",topic:"内丹女丹",essence:"Mười giai đoạn nữ đan có hệ thống: dưỡng chân hóa khí, luyện hình, trảm xích long… Phân biệt nam dương hạ tiết / nữ dương thượng thăng, lấy linh chi vú làm dược.",key_text:"男子阳从下泄，女子阳从上升；男子体刚，女子体柔……用乳房灵脂变化气质，久久运炼，自然赤反为白，血化为气。",use:"Nữ đan thứ đệ; hợp biên nữ tu trong Đạo tạng tập yếu.",sources:["https://zh.wikisource.org/wiki/%E5%A5%B3%E4%B8%B9%E5%90%88%E7%B7%A8%E9%81%B8%E6%B3%A8","https://ctext.org/wiki.pl?if=gb&chapter=904386","https://jicheng.tw/tcm/book/%E5%A5%B3%E4%B8%B9%E5%90%88%E7%B7%A8%E9%81%B8%E8%A8%BB/index.html"],textual_certainty:"high",notes:"batch66 · Grok-4.5 藏外 仙学/千峰/西派/古书隐楼"},{dz:"null",name_han:"敲蹻洞章（刘名瑞）",name_vi:"Xao Khiêu Động Chương (Lưu Danh Thụy)",bu:"藏外·全真南无派（盼蟾子道书三种）",author:"刘名瑞（盼蟾子、敲蹻道人）",era:"清–民初（1839–1931）",topic:"cultivation",essence:"Tông sư đời thứ 20 Nam Vô phái (Toàn Chân) viết về nội đan, dưỡng sinh và tâm pháp ẩn tu tại Đào Nguyên quán. Cùng Đạo Nguyên Tinh Vi là di sản Nam Vô hiếm hoi ngoài chính tạng.",key_text:"null",use:"Toàn Chân Nam Vô phái; nội đan và dưỡng sinh ẩn tu.",sources:["https://baike.baidu.com/item/%E6%95%B2%E8%B9%BB%E6%B4%9E%E7%AB%A0/10554850","https://crta.info/wiki/%E6%95%B2%E8%B9%BB%E6%B4%9E%E7%AB%A0_-_K69","https://baike.baidu.com/item/%E5%8D%97%E6%97%A0%E6%B4%BE/9709261"],textual_certainty:"high",notes:"batch66 · Grok-4.5 藏外 仙学/千峰/西派/古书隐楼"},{dz:"null",name_han:"道源精微歌（刘名瑞）",name_vi:"Đạo Nguyên Tinh Vi Ca (Lưu Danh Thụy)",bu:"藏外·全真南无派（盼蟾子道书三种）",author:"刘名瑞（盼蟾子）",era:"清–民初",topic:"cultivation",essence:"Ca quyết trình bày nguồn đạo, tính mệnh và công pháp Nam Vô phái. Cùng Xao Khiêu Động Chương cấu thành “Phán Thiềm tử đạo thư tam chủng”, nối mạch Toàn Chân Bắc phái chi phái.",key_text:"null",use:"Lý luận và khẩu quyết Nam Vô; đối chiếu Long Môn–Nam Vô.",sources:["https://baike.baidu.com/item/%E5%8D%97%E6%97%A0%E6%B4%BE/9709261","https://zh.daoinfo.org/index.php?title=%E5%8D%97%E7%84%A1%E6%B4%BE&variant=zh-hans","https://www.daojiao.ltd/daojiaorenwu/569.html"],textual_certainty:"high",notes:"batch66 · Grok-4.5 藏外 仙学/千峰/西派/古书隐楼"},{dz:"null",name_han:"壺天性果女丹十則",name_vi:"Hồ Thiên Tính Quả Nữ Đan Thập Tắc",bu:"道藏辑要·女丹合编（藏外）",author:"不詳（賀龍驤輯入）",era:"清·光緒（刊）/前代傳本",topic:"cultivation",essence:"Nữ đan thập tắc trong *Nữ Đan Hợp Biên*, nhấn mạnh nữ tiên luyện hình rồi mới luyện bản nguyên. Bước đầu «dưỡng chân hóa khí», «cửu chuyển luyện hình», rồi hỏa phù, thai tức, cho tới di thần xuất xác. Phân biệt rõ nam «hàng bạch hổ» và nữ «trảm xích long».",key_text:"男子陽從下洩，女子陽從上升；男子體剛，女子體柔。",use:"Nữ đan cơ bản: trảm xích long, luyện hình hóa khí theo thứ tự mười tắc.",sources:["https://zh.wikisource.org/wiki/%E5%A5%B3%E4%B8%B9%E5%90%88%E7%B7%A8%E9%81%B8%E6%B3%A8","https://ctext.org/wiki.pl?if=gb&chapter=904386&remap=gb","https://jicheng.tw/tcm/book/%E5%A5%B3%E4%B8%B9%E5%90%88%E7%B7%A8%E9%81%B8%E8%A8%BB/index.html"],textual_certainty:"high",notes:"batch67 · Grok-4.5 藏外 女丹/辑要/科仪/道医"},{dz:"null",name_han:"女金丹",name_vi:"Nữ Kim Đan",bu:"道藏辑要·女丹合编（藏外）",author:"用中貞一子（序光緒壬辰）",era:"清·光緒",topic:"cultivation",essence:"Kinh nữ đan hệ thống: giới quy, thu tâm, dưỡng tính, dưỡng khí, ngưng thần, rồi «trảm long», hình ẩn, cầu đan, luyện kỷ. Phân biệt khí huyệt nữ ở nhũ phòng, không nhầm huyệt rốn nam. Sau trảm xích long, hỏa hầu tham chiếu nam đan.",key_text:"大道不問男女，皆能有成，故男子道成為真人；女子道成為元君。",use:"Khóa nữ tu từ giới quy đến trảm long, luyện kỷ, hoàn đan.",sources:["https://zh.wikisource.org/wiki/%E5%A5%B3%E4%B8%B9%E5%90%88%E7%B7%A8%E9%81%B8%E6%B3%A8","https://ctext.org/wiki.pl?if=gb&res=151647","https://jicheng.tw/tcm/book/%E5%A5%B3%E4%B8%B9%E5%90%88%E7%B7%A8%E9%81%B8%E8%A8%BB/index.html"],textual_certainty:"high",notes:"batch67 · Grok-4.5 藏外 女丹/辑要/科仪/道医"},{dz:"null",name_han:"坤寧經（增演真一坤寧妙經）",name_vi:"Khôn Ninh Kinh",bu:"道藏辑要·坤缘觉路／女丹合编（藏外）",author:"倪受真（傳本）",era:"清·咸豐前後（約1857）",topic:"cultivation",essence:"Kinh nữ tu gắn Văn Xương cung, giảng đức hạnh, tĩnh định và mệnh công nữ. Được khắc trong *Khôn Duyên Giác Lộ* cùng *Khôn Nguyên Kinh*, rồi hợp vào *Nữ Đan Hợp Biên*. Trọng giới hạnh trước khi bàn trảm xích long.",key_text:"null",use:"Nữ đan kết hợp giới–đức–mệnh; tham chiếu cùng *Khôn Nguyên Kinh*.",sources:["https://baike.baidu.com/item/%E5%9D%A4%E5%AE%81%E7%BB%8F/5115076","https://ctext.org/wiki.pl?if=gb&chapter=888461","https://zh.daoinfo.org/index.php?title=%E5%A5%B3%E4%B8%B9"],textual_certainty:"high",notes:"batch67 · Grok-4.5 藏外 女丹/辑要/科仪/道医"},{dz:"null",name_han:"孫不二元君女功內丹次第詩（孫不二元君法語）",name_vi:"Tôn Bất Nhị Nguyên Quân Nữ Công Nội Đan Thứ Đệ Thi",bu:"藏外（女丹／全真）",author:"孫不二（清靜散人）",era:"金·大定（約1175–1182）",topic:"cultivation",essence:"Mười bốn bài ngũ ngôn của Bắc thất chân Tôn Bất Nhị, trình bày thứ tự nữ đan: thu tâm, dưỡng khí, hành công, trảm long, dưỡng đan, thai tức… Ngôn gọn, ý sâu; đời sau chú giải nhiều (không kể bản chú đã liệt).",key_text:"本是無為始，何期落後天。",use:"Đọc thuộc thứ tự nữ công nội đan; đối chiếu với *Nữ Kim Đan*, *Hồ Thiên Thập Tắc*.",sources:["http://www.ctcwri.idv.tw/CTCW-D2/D2-10%E5%8D%81%E5%8A%83-185/0D2-10%E5%8D%81%E5%8A%83-185XX/D210034%E5%AD%AB-64/D210034%E5%AD%ABXX/D21003431%E5%AD%AB%E4%B8%8D%E4%BA%8C%E5%85%83%E5%90%9B%E6%B3%95%E8%AA%9E.htm","https://zh.wikisource.org/zh-hant/%E5%A5%B3%E5%AD%90%E4%B8%B9%E7%B6%93%E5%BD%99%E7%B7%A8","https://crta.info/wiki/%E5%AD%AB%E4%B8%8D%E4%BA%8C%E5%A5%B3%E4%B8%B9%E8%A9%A9%E8%A8%BB_-_K78"],textual_certainty:"high",notes:"batch67 · Grok-4.5 藏外 女丹/辑要/科仪/道医"},{dz:"null",name_han:"女丹合編",name_vi:"Nữ Đan Hợp Biên",bu:"重刊道藏辑要（藏外汇辑）",author:"賀龍驤輯",era:"清·光緒乙巳（1905）",topic:"cultivation",essence:"Tùng thư nữ đan do Hạ Long Tương biên từ hơn mười bản, khắc tại Nhị Tiên Am cùng *Đạo Tạng Tập Yếu*. Có *Hồ Thiên Thập Tắc*, *Nữ Kim Đan*, *Khôn Nguyên/Khôn Ninh*… Tựa «Thông tục tự» phân biệt rõ tính–hình–công pháp nam/nữ.",key_text:"男先煉本元，後煉形質。女先煉形質，後煉本元。",use:"Tổng tập nữ đan chuẩn để tra cứu và tu tập theo hệ thống.",sources:["https://zh.wikisource.org/wiki/%E5%A5%B3%E4%B8%B9%E5%90%88%E7%B7%A8%E9%81%B8%E6%B3%A8","https://ctext.org/wiki.pl?if=gb&res=151647","https://www.kanripo.org/ed/KR5i0109/CK-KZ/"],textual_certainty:"high",notes:"batch67 · Grok-4.5 藏外 女丹/辑要/科仪/道医"},{dz:"null",name_han:"唱道真言",name_vi:"Xướng Đạo Chân Ngôn",bu:"道藏辑要（藏外）",author:"南極仙翁傳／鶴臞子集",era:"清（輯要本）",topic:"cultivation",essence:"Danh tác luyện tâm trong nội đan: trước thấy «tính trường sinh bất tử», sau mới tu mệnh. Nghiêng tĩnh tu, điều tâm hư tịch, luyện hình và đan trên nền tâm đã định. Thu vào *Trọng San Đạo Tạng Tập Yếu*.",key_text:"先要人見了長生不死之性，而後修長生不死之命。",use:"Luyện tâm–tính làm cửa vào; phối hợp với kinh mệnh công.",sources:["https://zh.wikisource.org/zh-hans/%E5%94%B1%E9%81%93%E7%9C%9E%E8%A8%80","https://ctext.org/wiki.pl?if=gb&res=455928","https://taolibrary.com/category/category86/c86001.htm"],textual_certainty:"high",notes:"batch67 · Grok-4.5 藏外 女丹/辑要/科仪/道医"},{dz:"null",name_han:"玄宗正旨",name_vi:"Huyền Tông Chính Chỉ",bu:"道藏辑要（藏外）",author:"託名呂純陽傳本",era:"明清（輯要收）",topic:"philosophy",essence:"Tác phẩm huyền chỉ nội đan/tính mệnh trong *Đạo Tạng Tập Yếu* (Đẩu tập), cùng hệ Lữ Tổ giáng bút–truyền bản. Nêu «chính chỉ» huyền tông, đối chiếu *Kim Hoa*, *Xướng Đạo*. Không thuộc Chính Thống Đạo Tạng.",key_text:"null",use:"Đọc cùng *Kim Hoa Tông Chỉ*, *Xướng Đạo Chân Ngôn* để nắm huyền chỉ.",sources:["https://zh.wikisource.org/zh-hans/%E9%87%8D%E5%88%8A%E9%81%93%E8%97%8F%E8%BC%AF%E8%A6%81","http://www.homeinmists.com/DaoZangJiYaoContents.htm","https://simple.taolibrary.com/category97.aspx"],textual_certainty:"high",notes:"batch67 · Grok-4.5 藏外 女丹/辑要/科仪/道医"},{dz:"null",name_han:"心傳述證錄",name_vi:"Tâm Truyền Thuật Chứng Lục",bu:"道藏辑要（藏外）",author:"梅芳老人輯",era:"清·嘉慶八年（1803）",topic:"philosophy",essence:"Tuyển thuật «thánh học tâm truyền» gắn đạo tổ vô cực với tâm học, chứng nghiệm nội chứng. Khắc lại năm 1803, thu vào *Tập Yếu* (Quỷ tập). Phản ánh xu hướng tam giáo tâm truyền đời Thanh.",key_text:"無極之眞非有非空。",use:"Tâm truyền–nội chứng; bổ sung lớp lý cho đan đạo.",sources:["http://www.ctcwri.idv.tw/CTCW-DZJY/CTDZJY23/NewDZJY23/CTDZJY230701.pdf","https://commons.wikimedia.org/wiki/File:CADAL06030390_%E5%BF%83%E5%82%B3%E8%BF%B0%E8%AD%89%E9%8C%84.djvu","https://crta.info/wiki/%E5%BF%83%E5%82%B3%E8%BF%B0%E8%AD%89%E9%8C%84_-_A246"],textual_certainty:"high",notes:"batch67 · Grok-4.5 藏外 女丹/辑要/科仪/道医"},{dz:"null",name_han:"廣成儀制",name_vi:"Quảng Thành Nghi Chế",bu:"藏外道書·儀範（全真科仪）",author:"陳復慧（雲峰羽客）",era:"清·乾隆",topic:"ritual",essence:"Tùng thư khoa nghi Long Môn Thanh Thành, mượn hiệu Quảng Thành tiên sinh (Đỗ Quang Đình). Gồm tấu sớ, trai tiếu, đàn nghi thực dụng sơn môn Tứ Xuyên. *Tàng Ngoại Đạo Thư* in đủ; trước đó bí truyền.",key_text:"null",use:"Thực hành khoa nghi toàn chân: tấu–thỉnh–trai–tiếu theo bản sơn môn.",sources:["https://baike.baidu.com/item/%E5%B9%BF%E6%88%90%E4%BB%AA%E5%88%B6/3964682","https://taolibrary.com/category107.aspx","http://www.homeinmists.com/Extra_TaoSutra_Contents.htm"],textual_certainty:"high",notes:"batch67 · Grok-4.5 藏外 女丹/辑要/科仪/道医"},{dz:"null",name_han:"上清靈寶濟度大成金書",name_vi:"Thượng Thanh Linh Bảo Tế Độ Đại Thành Kim Thư",bu:"藏外道書·儀範（大成金書）",author:"林靈真編／周思得重修",era:"元–明宣德（1432重修）",topic:"ritual",essence:"Bốn mươi quyển, hai mươi môn: tổng tập khoa nghi Linh Bảo Đông Hoa – tế sinh độ vong, kim lục, hoàng lục, luyện độ. Chu Tư Đắc bổ đính đời Tuyên Đức; không vào Chính Thống Đạo Tạng; *Tàng Ngoại* công bố.",key_text:"null",use:"Tra cứu/tổ chức trai tiếu Linh Bảo quy mô lớn.",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%8A%E6%B8%85%E9%9D%88%E5%AF%B6%E6%BF%9F%E5%BA%A6%E5%A4%A7%E6%88%90%E9%87%91%E6%9B%B8","https://baike.baidu.com/item/%E4%B8%8A%E6%B8%85%E7%81%B5%E5%AE%9D%E6%B5%8E%E5%BA%A6%E5%A4%A7%E6%88%90%E9%87%91%E4%B9%A6/850436","https://homeinmists.ilotus.org/%E9%81%93%E8%97%8F%E5%8C%AF%E7%B7%A8/%E8%97%8F%E5%A4%96%E9%81%93%E6%9B%B8/%E4%B8%8A%E6%B8%85%E9%9D%88%E5%AF%B6%E6%BF%9F%E5%BA%A6%E5%A4%A7%E6%88%90%E9%87%91%E6%9B%B8/"],textual_certainty:"high",notes:"batch67 · Grok-4.5 藏外 女丹/辑要/科仪/道医"},{dz:"null",name_han:"懺法大觀",name_vi:"Sám Pháp Đại Quan",bu:"道藏辑要（藏外科仪）",author:"柳守元等編",era:"清中後期",topic:"ritual",essence:"Sáu quyển, khoảng 32 bộ sám khoa (thượng tự Tam Thanh Tứ Ngự đến lôi ôn chư bộ). Bù chỗ *Đạo Tạng* thiếu sám pháp đầy đủ; bản thông hành trong *Trọng San Đạo Tạng Tập Yếu*.",key_text:"粵自太上開闡道門，懺法之流傳也遠矣。",use:"Sám hối, tạ tội, báo ân trong trai đàn đời Thanh–cận đại.",sources:["https://zh.wikisource.org/zh-hans/%E6%87%BA%E6%B3%95%E5%A4%A7%E8%A7%80","https://zh.daoinfo.org/index.php?title=%E6%87%BA%E6%B3%95%E5%A4%A7%E8%A7%80","https://ctext.org/library.pl?if=gb&res=96890"],textual_certainty:"high",notes:"batch67 · Grok-4.5 藏外 女丹/辑要/科仪/道医"},{dz:"null",name_han:"活人心法（臞仙活人心法）",name_vi:"Hoạt Nhân Tâm Pháp",bu:"藏外（道医养生）",author:"朱權（臞仙、涵虛子）",era:"明·洪武–永樂（14世紀末）",topic:"道医",essence:"Hai quyển: trị tâm, đạo dẫn, lục tự quyết, tứ quý dưỡng sinh, ẩm thực bổ dưỡng; hạ quyển phương dược. Ninh Hiến vương dung đạo–y–dưỡng sinh; tranh minh họa và phương thực dụng.",key_text:"null",use:"Dưỡng sinh đạo gia: trị tâm, đạo dẫn, lục tự, thời lệnh.",sources:["https://baike.baidu.com/item/%E6%B4%BB%E4%BA%BA%E5%BF%83%E6%B3%95/2921060","https://hongyeshan.com/post/692.html","https://homeinmists.ilotus.org/%E7%B6%B2%E7%AB%99%E5%85%AC%E5%91%8A/%E9%81%93%E5%AE%B6%E8%B3%87%E8%A8%8A/%E9%A4%8A%E7%94%9F%E4%BF%AE%E9%8D%8A/"],textual_certainty:"high",notes:"batch67 · Grok-4.5 藏外 女丹/辑要/科仪/道医"},{dz:"null",name_han:"福壽丹書（五福萬壽丹書）",name_vi:"Phúc Thọ Đan Thư",bu:"藏外（道医养生）",author:"龔居中（如虛子）",era:"明末",topic:"道医",essence:"An dưỡng, diên linh, phục thực, huyền tu, thanh lạc – tổng hợp dưỡng sinh đạo–y. Tác giả Thái y viện, kiêm nội đan–đạo dẫn; cùng *Hồng Lô Điểm Tuyết* phản ánh «thập đạo cửu y».",key_text:"null",use:"Dưỡng sinh tổng hợp: cư xứ, phục thực, huyền tu, phòng bệnh.",sources:["https://jicheng.tw/tcm/book/%E7%A6%8F%E5%A3%BD%E4%B8%B9%E6%9B%B8/index.html","https://baike.baidu.com/item/%E9%BE%9A%E5%B1%85%E4%B8%AD/602607","http://www.taoist.org.cn/showInfoContent.do?id=4502&p=%27p%27"],textual_certainty:"high",notes:"batch67 · Grok-4.5 藏外 女丹/辑要/科仪/道医"},{dz:"null",name_han:"紅爐點雪（痰火點雪）",name_vi:"Hồng Lô Điểm Tuyết",bu:"藏外（道医）",author:"龔居中",era:"明·崇禎三年（1630）",topic:"道医",essence:"Chuyên thư lao trại (phế lao/đàm hỏa): bệnh cơ, biện chứng, phương dược, dự phòng–điều hộ. Gắn đạo y «dĩ hỏa tiêu đàm» với dưỡng sinh thanh tâm quả dục.",key_text:"若能清心寡慾，久久行之，百病不生。",use:"Đạo y trị lao; kết hợp thanh tâm, ẩm thực, dược phương.",sources:["https://baike.baidu.com/item/%E7%BA%A2%E7%82%89%E7%82%B9%E9%9B%AA/6758974","https://jicheng.tw/tcm/book/%E7%97%B0%E7%81%AB%E9%BB%9E%E9%9B%AA/index.html","https://baike.baidu.com/item/%E9%BE%9A%E5%B1%85%E4%B8%AD/602607"],textual_certainty:"high",notes:"batch67 · Grok-4.5 藏外 女丹/辑要/科仪/道医"},{dz:"null",name_han:"三界伏魔关圣帝君忠孝忠义真经",name_vi:"Tam giới phục ma Quan Thánh đế quân trung hiếu trung nghĩa chân kinh",bu:"道藏辑要/藏外",author:"托名关圣帝君（传宋孙奭编述、张守订）",era:"明清流通（托名较早）",topic:"ritual",essence:"Kinh khuyên thiện của Quan Thánh, nhấn trung hiếu trung nghĩa, điều chỉnh chí hướng và khí số. Là bản kinh quan trọng trong tín ngưỡng Quan Đế ngoài chính tạng.",key_text:"人生在世，贵尽忠孝节义等事，方于人道无愧。",use:"tụng Quan Đế, tu thân, pháp hội trung nghĩa",sources:["https://zh.wikisource.org/zh-hans/%E4%B8%89%E7%95%8C%E4%BC%8F%E9%AD%94%E9%97%9C%E8%81%96%E5%B8%9D%E5%90%9B%E5%BF%A0%E5%AD%9D%E5%BF%A0%E7%BE%A9%E7%9C%9F%E7%B6%93","https://ctext.org/library.pl?if=gb&res=98074","https://taolibrary.com/category/category86/c86023.htm"],textual_certainty:"high",notes:"batch68 · Grok-4.5 藏外/续道藏 mixed"},{dz:"null",name_han:"关圣帝君大解冤经",name_vi:"Quan Thánh đế quân đại giải oan kinh",bu:"藏外",author:"托名关圣帝君",era:"明清—近代流通",topic:"ritual",essence:"Kinh giải oan, tịnh tâm khẩu thân, cầu Quan Thánh hóa giải oan nghiệt. Thuộc dòng kinh pháp phổ biến trong tín ngưỡng Quan Đế dân gian.",key_text:"急急如律令。",use:"giải oan, sám hối, đàn tràng Quan Đế",sources:["https://zh.wikisource.org/zh-hans/%E9%97%9C%E8%81%96%E5%B8%9D%E5%90%9B%E5%A4%A7%E8%A7%A3%E5%86%A4%E7%B6%93","https://zh.wikisource.org/wiki/%E9%97%9C%E8%81%96%E5%B8%9D%E5%90%9B%E5%A4%A7%E8%A7%A3%E5%86%A4%E7%B6%93"],textual_certainty:"partial",notes:"batch68 · Grok-4.5 藏外/续道藏 mixed"},{dz:"DZ1469",name_han:"天皇至道太清玉册",name_vi:"Thiên hoàng chí đạo Thái Thanh ngọc sách",bu:"续道藏",author:"朱权（臞仙）",era:"明正统九年（1444）",topic:"类书",essence:"Bách khoa đạo giáo đời Minh: vũ trụ, tông phái, giới luật, trai giao, cung quán, pháp khí, tu chân. Do Ninh vương Chu Quyền biên.",key_text:"余谓世有非常之人，而能行非常之事。",use:"tham khảo chế độ đạo môn, khoa nghi danh vật",sources:["https://zh.wikisource.org/zh-hans/%E5%A4%A9%E7%9A%87%E8%87%B3%E9%81%93%E5%A4%AA%E6%B8%85%E7%8E%89%E5%86%8A","https://zh.daoinfo.org/index.php?title=%E5%A4%A9%E7%9A%87%E8%87%B3%E9%81%93%E5%A4%AA%E6%B8%85%E7%8E%89%E5%86%8A&variant=zh-hant","https://ctext.org/wiki.pl?if=gb&res=715094"],textual_certainty:"high",notes:"batch68 · Grok-4.5 藏外/续道藏 mixed"},{dz:"null",name_han:"太上玄门早坛功课经",name_vi:"Thái Thượng huyền môn tảo đàn công khóa kinh",bu:"道藏辑要",author:"全真道众集（明清定型）",era:"明末清初定型",topic:"ritual",essence:"Công khóa sáng của Toàn Chân: tụng kinh bảo cáo, tịnh tâm hành trì hàng ngày. Nền tảng tu trì tòng lâm đạo quán.",key_text:"窃以金书玉笈，为入道之门墙；讽经诵咒，乃修仙之径路。",use:"công khóa sáng, nhật tụng cung quán",sources:["https://ctext.org/wiki.pl?if=gb&chapter=2405631","https://baike.baidu.com/item/%E7%8E%84%E9%97%A8%E6%97%A5%E8%AF%B5%E6%97%A9%E5%9D%9B%E5%8A%9F%E8%AF%BE%E7%BB%8F/17619343","http://www.homeinmists.com/DaoZangJiYaoContents2.htm"],textual_certainty:"high",notes:"batch68 · Grok-4.5 藏外/续道藏 mixed"},{dz:"null",name_han:"太上玄门晚坛功课经",name_vi:"Thái Thượng huyền môn vãn đàn công khóa kinh",bu:"道藏辑要",author:"全真道众集（明清定型）",era:"明末清初定型",topic:"ritual",essence:"Công khóa tối Toàn Chân, đối ứng sớm khóa. Tụng kinh sám nguyện, thu tâm dưỡng khí, chuẩn bị tịnh dạ.",key_text:"大道洞玄虚，有念无不契。炼质入仙真，遂成金刚体。",use:"công khóa tối, nhật tụng cung quán",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E7%8E%84%E9%96%80%E6%99%9A%E5%A3%87%E5%8A%9F%E8%AA%B2%E7%B6%93","https://ctext.org/wiki.pl?if=gb&chapter=2405631","http://www.homeinmists.com/DaoZangJiYaoContents2.htm"],textual_certainty:"high",notes:"batch68 · Grok-4.5 藏外/续道藏 mixed"},{dz:"null",name_han:"玄坛赵元帅财神经",name_vi:"Huyền đàn Triệu nguyên soái tài thần kinh",bu:"藏外",author:"不详（民间扶鸾/道门流通）",era:"近代定本流通（源出明清赵玄坛信仰）",topic:"ritual",essence:"Kinh Võ Tài thần Triệu Công Minh: quản tài nguyên, thưởng thiện phạt ác, ngũ lộ tài thần. Dùng tụng ngày mùng 5 và lễ tài thần.",key_text:"吾是玄坛赵天君，财帛府中我为尊。天下财源吾掌管，富贵穷通由我定。",use:"tụng Tài thần, cầu tài hành thiện",sources:["https://zh.wikisource.org/wiki/%E8%B2%A1%E7%A5%9E%E7%B6%93","https://dao-world.org/2021/04/25/%E7%8E%84%E5%9D%9B%E8%B5%B5%E5%A4%A7%E5%85%83%E5%B8%85%E8%B4%A2%E7%A5%9E%E7%BB%8F-xuan-tan-zhao-da-yuan-shuai-cai-shen-jing/","https://zh.wikipedia.org/wiki/%E7%8E%84%E5%A3%87%E7%9C%9F%E5%90%9B"],textual_certainty:"partial",notes:"batch68 · Grok-4.5 藏外/续道藏 mixed"},{dz:"null",name_han:"太上感应篇注（惠栋）",name_vi:"Thái Thượng Cảm Ứng Thiên chú (Huệ Đống)",bu:"藏外善书",author:"惠栋",era:"清·乾隆",topic:"philosophy",essence:"Bản chú giải học thuật Nho gia của Thái Thượng Cảm Ứng Thiên do Huệ Đống soạn. Kết hợp khảo chứng kinh sử với đạo đức thiện thư, nhấn mạnh báo ứng thiện ác. Là một trong những bản chú có ảnh hưởng nhất ngoài chính thống đạo tạng.",key_text:"祸福无门，惟人自召。",use:"Thiện thư / đạo đức khuyến thiện, tham khảo chú giải học thuật",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E6%84%9F%E6%87%89%E7%AF%87","https://ctext.org/wiki.pl?if=gb&res=803497"],textual_certainty:"high",notes:"batch69 · Grok-4.5 藏外 niches"},{dz:"null",name_han:"玉历宝钞",name_vi:"Ngọc Lịch Bảo Sao",bu:"藏外善书",author:"托名淡痴道人传",era:"清（前身宋元传说）",topic:"philosophy",essence:"Thiện thư mô tả thập điện Diêm Vương và địa ngục báo ứng, kết hợp Phật-Đạo dân gian. Lan truyền mạnh từ thời Thanh, dùng để khuyến thiện, răn ác qua hình ảnh địa phủ.",key_text:"善恶到头终有报，只争来早与来迟。",use:"Thiện thư / giáo hóa dân gian về báo ứng",sources:["https://zh.wikisource.org/wiki/%E7%8E%89%E6%9B%86%E5%AF%B6%E9%88%94","https://baike.baidu.com/item/%E7%8E%89%E5%8E%86%E5%AE%9D%E9%92%9E"],textual_certainty:"high",notes:"batch69 · Grok-4.5 藏外 niches"},{dz:"null",name_han:"吕祖全书",name_vi:"Lữ Tổ Toàn Thư",bu:"藏外/全真内丹",author:"刘体恕等辑",era:"清·乾隆",topic:"cultivation",essence:"Tổng tập lớn các trước tác và giáng bút gán cho Lữ Động Tân: nội đan, thiện thư, thi phú, chú giải. Là nguồn chính ngoài tạng về Lữ Tổ và truyền thừa toàn chân-đan đạo hậu kỳ.",key_text:"性命双修，形神俱妙。",use:"Nội đan / Lữ Tổ tín ngưỡng / nghiên cứu toàn chân",sources:["https://zh.wikisource.org/wiki/%E5%91%82%E7%A5%96%E5%85%A8%E6%9B%B8","https://ctext.org/wiki.pl?if=gb&res=142105"],textual_certainty:"high",notes:"batch69 · Grok-4.5 藏外 niches"},{dz:"null",name_han:"遵生八笺",name_vi:"Tuân Sinh Bát Tiên",bu:"藏外道教医学/养生",author:"高濂",era:"明·万历",topic:"养生",essence:"Bách khoa dưỡng sinh Minh đại: thanh tu diệu luận, tứ thời điều nhiếp, khởi cư an lạc, diên niên khước bệnh, ẩm soạn phục thực, yên nhàn thanh thưởng, linh bí đan dược, trần ngoại hà xa. Hòa Nho-Đạo-y học.",key_text:"人之生也，皆由养而得之。",use:"Dưỡng sinh / đạo dẫn / y đạo tàng ngoại",sources:["https://zh.wikisource.org/wiki/%E9%81%B5%E7%94%9F%E5%85%AB%E7%AC%8A","https://ctext.org/wiki.pl?if=gb&res=241530"],textual_certainty:"high",notes:"batch69 · Grok-4.5 藏外 niches"},{dz:"null",name_han:"寿世保元",name_vi:"Thọ Thế Bảo Nguyên",bu:"藏外道教医学/方书",author:"龚廷贤",era:"明·万历",topic:"养生",essence:"Phương thư y học Minh đại gắn mạnh với dưỡng sinh đạo giáo: nội ngoại phụ nhi, tiên đan diên thọ. Được đạo giáo dân gian và y quán dùng rộng ngoài tạng.",key_text:"保元者，保其元气也。",use:"Y đạo / dưỡng sinh / phương thư",sources:["https://zh.wikisource.org/wiki/%E5%A3%BD%E4%B8%96%E4%BF%9D%E5%85%83","https://baike.baidu.com/item/%E5%AF%BF%E4%B8%96%E4%BF%9D%E5%85%83"],textual_certainty:"high",notes:"batch69 · Grok-4.5 藏外 niches"},{dz:"DZ219",name_han:"靈寶無量度人上經大法",name_vi:"Linh Bảo Vô Lượng Độ Nhân Thượng Kinh Đại Pháp",bu:"洞真",author:"佚名（宋元符籙道士彙編）",era:"宋元（成書約宋–明初）",topic:"ritual",essence:"Bộ đại pháp 72 quyển lấy Kinh Độ Nhân làm trục, tập hợp phù lục, trai nghi, tồn tư và luyện độ cứu vong của phái Linh Bảo. Phần độ sinh giải kinh từng câu kèm phù đồ; phần độ tử có nghi phá ngục, cứu vong. Đây là tổng tập pháp thuật Linh Bảo lớn nhất trong Đạo tạng, dùng cho nghi thức độ người sống và người chết.",key_text:"道言昔於始青天中",use:"Nghi thức độ nhân, phù lục, trai khoa Linh Bảo; tham khảo hệ thống pháp thuật cứu độ.",sources:["https://zh.wikisource.org/zh-hans/%E9%9D%88%E5%AF%B6%E7%84%A1%E9%87%8F%E5%BA%A6%E4%BA%BA%E4%B8%8A%E7%B6%93%E5%A4%A7%E6%B3%95","https://zh.daoinfo.org/index.php?title=%E9%9D%88%E5%AF%B6%E7%84%A1%E9%87%8F%E5%BA%A6%E4%BA%BA%E4%B8%8A%E7%B6%93%E5%A4%A7%E6%B3%95","https://www.shidianguji.com/zh/book/DZ0219","https://taolibrary.com/category95.aspx"],textual_certainty:"high",notes:"batch70 · Grok-4.5 focused DZ200-300"},{dz:"DZ226",name_han:"紫元君授道傳心法",name_vi:"Tử Nguyên Quân Thụ Đạo Truyền Tâm Pháp",bu:"洞真",author:"原題長生陰真人注",era:"晚唐–北宋（約）",topic:"cultivation",essence:"Một quyển nội đan tâm pháp, nguyên đề Âm chân nhân chú, luận đạo truyền tâm theo Tử Nguyên quân. Trích Âm Phù kinh, chủ trương nội đan chân chính, phản đối ngoại đan và phục khí hình thức. Nhấn mạnh khẩu quyết tâm truyền hơn văn tự.",key_text:"null",use:"Nội đan tâm pháp; so sánh với Âm Phù–nội đan truyền thống.",sources:["https://zh.wikisource.org/zh-hans/%E7%B4%AB%E5%85%83%E5%90%9B%E6%8E%88%E9%81%93%E5%82%B3%E5%BF%83%E6%B3%95","https://zh.daoinfo.org/index.php?title=%E7%B4%AB%E5%85%83%E5%90%9B%E6%8E%88%E9%81%93%E5%82%B3%E5%BF%83%E6%B3%95","https://www.jstor.org/stable/26768560"],textual_certainty:"high",notes:"batch70 · Grok-4.5 focused DZ200-300"},{dz:"DZ227",name_han:"真龍虎九仙經",name_vi:"Chân Long Hổ Cửu Tiên Kinh",bu:"洞真",author:"原題羅公遠、葉靜能注",era:"唐（託）/唐宋",topic:"cultivation",essence:"Kinh nội đan về long hổ, cửu tiên, nguyên đề La Công Viễn và Diệp Tĩnh Năng chú. Giảng luyện khí, điều tức, tránh tán loạn và vọng tưởng; dùng số cửu và hô hấp để điều hòa long hổ. Thuộc nhóm đan kinh ngắn trong Động chân phương pháp loại.",key_text:"無散亂，無煩怒，無起著，無妄想，無貪愛。",use:"Nội đan hô hấp–long hổ; tham khảo chú giải La–Diệp.",sources:["http://www.ctcwri.idv.tw/CTCW-CMTS/CMT01%E6%B4%9E%E7%9C%9F%E9%83%A8/CMT0108%E6%96%B9%E6%B3%95%E9%A1%9E/CMT0108ALL/CH010809%E7%9C%9F%E9%BE%8D%E8%99%8E%E4%B9%9D%E4%BB%99%E7%B6%93.htm","https://ctext.org/wiki.pl?if=gb&chapter=829751","https://taolibrary.com/category95.aspx"],textual_certainty:"high",notes:"batch70 · Grok-4.5 focused DZ200-300"},{dz:"DZ233",name_han:"還丹眾仙論",name_vi:"Hoàn Đan Chúng Tiên Luận",bu:"洞真",author:"楊在（抱腹山人）",era:"北宋皇祐四年（1052）",topic:"外丹",essence:"Một quyển do Dương Tại biên soạn năm Hoàng Hựu 4, tập hợp hơn ba mươi gia thuyết hoàn đan đời Đường–Tống. Bảo tồn nhiều đan quyết cổ đã thất truyền; luận chân chì, chân thủy ngân, hoa trì, hoàng nha, hà xa. Vừa mang dấu ấn ngoại đan vừa chuyển sang ngôn ngữ nội đan.",key_text:"粵還丹者，華池為初也。華池之中，能生神水。",use:"Nghiên cứu lịch sử hoàn đan; trích dẫn đan quyết thất truyền.",sources:["https://zh.wikisource.org/zh-hans/%E9%82%84%E4%B8%B9%E7%9C%BE%E4%BB%99%E8%AB%96","https://ctext.org/library.pl?if=gb&res=83885","https://baike.baidu.com/item/%E8%BF%98%E4%B8%B9%E4%BC%97%E4%BB%99%E8%AE%BA/23146231"],textual_certainty:"high",notes:"batch70 · Grok-4.5 focused DZ200-300"},{dz:"DZ254",name_han:"大洞金華玉經",name_vi:"Đại Động Kim Hoa Ngọc Kinh",bu:"洞真",author:"佚名（上清系）",era:"六朝–唐（約）",topic:"cultivation",essence:"Kinh phương pháp Thượng Thanh liên quan Đại Động, giảng kim hoa ẩn thư, đế quân thượng nguyện, huyền mẫu bát gian. Nhấn mạnh trước khi thụ Đại Động chi quyết phải tụng đế quân nguyện và trai giới. Bổ trợ hệ Đại Động chân kinh trong Động chân phương pháp loại.",key_text:"夫得受大洞之訣，洞一上道雌一合變，當先誦帝君上願、玄母八間金華隱書。",use:"Nghi truyền thụ và tụng nguyện hệ Đại Động.",sources:["https://zh.wikisource.org/wiki/%E5%A4%A7%E6%B4%9E%E9%87%91%E8%8F%AF%E7%8E%89%E7%B6%93","https://taolibrary.com/category/category96/c960120.htm","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch70 · Grok-4.5 focused DZ200-300"},{dz:"DZ290",name_han:"廣黃帝本行記",name_vi:"Quảng Hoàng Đế Bản Hành Ký",bu:"洞真",author:"王瓘",era:"唐（廣明二年記事止）",topic:"仙传",essence:"Tiên truyện về Hoàng Đế cầu đạo thành tiên do Vương Quán soạn; Tân Đường thư chép ba quyển, Đạo tạng chỉ còn hạ quyển. Kể Hoàng Đế trị thiên hạ xong đi tìm ẩn sĩ: thụ Tam Hoàng nội văn, Cửu nhự phương, vấn đạo Quảng Thành tử, luyện đan, thừa long thăng thiên. Tổng hợp Trang tử, Liệt tiên truyện, sử ký và đạo điển.",key_text:"黃帝以天下既理，物用具備，乃尋真訪隱，問道求仙，冀獲長生久視。",use:"Tiên truyện Hoàng Đế; nghiên cứu tín ngưỡng Hoàng Đế và Đạo giáo.",sources:["https://zh.wikisource.org/zh-hans/%E5%BB%A3%E9%BB%83%E5%B8%9D%E6%9C%AC%E8%A1%8C%E8%A8%98","https://zh.daoinfo.org/index.php?title=%E5%BB%A3%E9%BB%83%E5%B8%9D%E6%9C%AC%E8%A1%8C%E8%A8%98","https://ctext.org/wiki.pl?if=gb&chapter=317526","https://baike.baidu.com/item/%E5%B9%BF%E9%BB%84%E5%B8%9D%E6%9C%AC%E8%A1%8C%E8%AE%B0/23146036"],textual_certainty:"high",notes:"batch70 · Grok-4.5 focused DZ200-300"},{dz:"DZ520",name_han:"太上靈寶玉匱明真大齋懺方儀",name_vi:"Thái Thượng Linh Bảo Ngọc Quỹ Minh Chân Đại Trai Sám Phương Nghi",bu:"洞玄",author:"杜光庭",era:"Đường mạt–Ngũ đại (thế kỷ 9–10)",topic:"ritual",essence:"Khoa nghi sám hối cho Đại trai Linh Bảo “Ngọc quỹ Minh chân”, do Đỗ Quang Đình biên định. Thứ tự quy lễ thập phương thiên tôn, sám tạ tội khiên để bạt độ u hồn và tiêu tai cho trại chủ. Đây là bản “đại trai” song hành với nghi sám phương ngắn hơn cùng hệ.",key_text:"廣成先生杜光庭刪定",use:"Dùng khi lập Minh chân đại trai: quy lễ thập phương, sám hối, cầu bạt độ cửu huyền.",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E9%9D%88%E5%AF%B6%E7%8E%89%E5%8C%B1%E6%98%8E%E7%9C%9F%E5%A4%A7%E9%BD%8B%E6%87%BA%E6%96%B9%E5%84%80","https://zh.daoinfo.org/wiki/%E5%A4%AA%E4%B8%8A%E9%9D%88%E5%AF%B6%E7%8E%89%E5%8C%B1%E6%98%8E%E7%9C%9F%E5%A4%A7%E9%BD%8B%E6%87%BA%E6%96%B9%E5%84%80%EF%BC%88%E6%9D%9C%E5%85%89%E5%BA%AD%E4%BF%AE%EF%BC%89","https://ctext.org/wiki.pl?if=gb&res=932797","https://michaelstanley-baker.com/clarkes-complete-daoist-index/"],textual_certainty:"high",notes:"batch71 · Grok-4.5 focused DZ520-600"},{dz:"DZ521",name_han:"太上靈寶玉匱明真大齋言功儀",name_vi:"Thái Thượng Linh Bảo Ngọc Quỹ Minh Chân Đại Trai Ngôn Công Nghi",bu:"洞玄",author:"杜光庭",era:"Đường mạt–Ngũ đại (thế kỷ 9–10)",topic:"ritual",essence:"Nghi thức “ngôn công” (báo công, tạ tạ) đặt ở phần kết của Linh Bảo Cửu u Minh chân Ngọc quỹ thiên thần bạt độ đại trai. Pháp sư tâu lên công đức trai đàn, xin chứng giám và ban ân. Bổ sung trọn bộ quy trình sau sám phương (DZ520).",key_text:"太上靈寶玉匱明真大齋言功儀",use:"Kết thúc đại trai Minh chân: trình tấu công đức, giải đàn, cầu chứng minh.",sources:["https://www.shidianguji.com/zh/book/DZ0521","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT02%E6%B4%9E%E7%8E%84%E9%83%A8/CMT0207%E5%A8%81%E5%84%80%E9%A1%9E/CMT0207ALL/CH0207076%E5%A4%AA%E4%B8%8A%E9%9D%88%E5%AF%B6%E7%8E%89%E5%8C%B1%E6%98%8E%E7%9C%9F%E5%A4%A7%E9%BD%8B%E8%A8%80%E5%8A%9F%E5%84%80.htm","https://michaelstanley-baker.com/clarkes-complete-daoist-index/"],textual_certainty:"high",notes:"batch71 · Grok-4.5 focused DZ520-600"},{dz:"DZ522",name_han:"洞玄靈寶自然券儀",name_vi:"Động Huyền Linh Bảo Tự Nhiên Khoán Nghi",bu:"洞玄",author:"không rõ (khoảng Bắc triều)",era:"Bắc triều / khoảng thế kỷ 5–6",topic:"ritual",essence:"Khoa nghi truyền thụ “tự nhiên khoán” thuộc hệ Linh Bảo trung minh. Quy định cách cấp khoán khế khi thụ kinh pháp Tự nhiên, khẳng định liên minh đạo–đệ tử. Là mắt xích quan trọng giữa truyền kinh và lập trai.",key_text:"洞玄度靈寶自然券儀",use:"Dùng trong nghi truyền thụ khoán khế Linh Bảo Tự nhiên cho đạo sĩ.",sources:["https://zh.daoinfo.org/wiki/%E6%B4%9E%E7%8E%84%E5%BA%A6%E9%9D%88%E5%AF%B6%E8%87%AA%E7%84%B6%E5%88%B8%E5%84%80","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT02%E6%B4%9E%E7%8E%84%E9%83%A8/CMT0207%E5%A8%81%E5%84%80%E9%A1%9E/CMT0207ALL/CH0207077%E6%B4%9E%E7%8E%84%E5%BA%A6%E9%9D%88%E5%AF%B6%E8%87%AA%E7%84%B6%E5%88%B8%E5%84%80.htm","https://michaelstanley-baker.com/clarkes-complete-daoist-index/"],textual_certainty:"high",notes:"batch71 · Grok-4.5 focused DZ520-600"},{dz:"DZ525",name_han:"太上洞淵三昧神咒齋懺謝儀",name_vi:"Thái Thượng Động Uyên Tam Muội Thần Chú Trai Sám Tạ Nghi",bu:"洞玄",author:"杜光庭 (sạn định)",era:"Đường mạt (thế kỷ 9–10)",topic:"ritual",essence:"Nghi sám tạ khi tụng Thái Thượng Động Uyên Tam Muội Thần Chú Kinh cho tư gia. Quy lễ thập phương “Vô cực Thái thượng chí chân… tam động thiên tôn”, sám tội, đoạn ma ôn, cầu an quốc hộ dân. Thuộc nhóm khoa nghi Động Uyên do Đỗ Quang Đình chỉnh.",key_text:"臣等志心歸命，敬禮東方無極太上至真上上太一君三洞天尊。",use:"Trai tư gia: tụng thần chú Động Uyên, sám tạ, tiêu ôn, bảo hộ.",sources:["https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E6%B7%B5%E4%B8%89%E6%98%A7%E7%A5%9E%E5%91%AA%E9%BD%8B%E6%87%BA%E8%AC%9D%E5%84%80","https://www.shidianguji.com/book/DZ0525","https://zh.daoinfo.org/wiki/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E6%B7%B5%E4%B8%89%E6%98%A7%E7%A5%9E%E5%91%AA%E9%BD%8B%E6%87%BA%E8%AC%9D%E5%84%80","https://ctext.org/wiki.pl?if=gb&res=988819"],textual_certainty:"high",notes:"batch71 · Grok-4.5 focused DZ520-600"},{dz:"DZ527",name_han:"太上洞淵三昧神咒齋十方懺儀",name_vi:"Thái Thượng Động Uyên Tam Muội Thần Chú Trai Thập Phương Sám Nghi",bu:"洞玄",author:"杜光庭 (sạn định)",era:"Đường mạt (thế kỷ 9–10)",topic:"ritual",essence:"Chuyên nghi sám hối thập phương trong trai thần chú Động Uyên. Bổ sung DZ525–526 thành bộ: sám tạ – thanh đán hành đạo – thập phương sám. Nhấn mạnh hướng phương vị quy mệnh và cầu đoạn ma ôn.",key_text:"太上洞淵三昧神咒齋十方懺儀",use:"Sám hối thập phương trong trai Động Uyên, cầu giải oan và bảo hộ.",sources:["https://michaelstanley-baker.com/clarkes-complete-daoist-index/","https://zh.daoinfo.org/wiki/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E6%B7%B5%E4%B8%89%E6%98%A7%E7%A5%9E%E5%91%AA%E9%BD%8B%E6%87%BA%E8%AC%9D%E5%84%80","https://www.shidianguji.com/book/DZ0525"],textual_certainty:"high",notes:"batch71 · Grok-4.5 focused DZ520-600"},{dz:"DZ529",name_han:"靈寶五經提綱",name_vi:"Linh Bảo Ngũ Kinh Đề Cương",bu:"洞玄",author:"không rõ (khoảng Đường–Tống)",era:"Đường–Tống",topic:"ritual",essence:"Đề cương phúng tụng “ngũ kinh” để tiến độ vong linh trong trai nghi Linh Bảo. Giải ý chỉ các kinh như Cửu thiên sinh thần chương…, kết hợp phu tọa pháp sự và nguyện cầu siêu thăng. Vừa là cương yếu kinh, vừa là khoa nghi tiến độ.",key_text:"太上微言在五經，五經垂世若丹青。丁寧試為重宣演，解脫亡靈出夜扃。",use:"Trai tiến độ: phúng ngũ kinh theo đề cương, nguyện giải thoát vong linh.",sources:["https://zh.wikisource.org/wiki/%E9%9D%88%E5%AF%B6%E4%BA%94%E7%B6%93%E6%8F%90%E7%B6%B1","https://zh.daoinfo.org/wiki/%E9%9D%88%E5%AF%B6%E4%BA%94%E7%B6%93%E6%8F%90%E7%B6%B1","https://michaelstanley-baker.com/clarkes-complete-daoist-index/"],textual_certainty:"high",notes:"batch71 · Grok-4.5 focused DZ520-600"},{dz:"DZ593",name_han:"歷代崇道記",name_vi:"Lịch Đại Sùng Đạo Ký",bu:"洞玄",author:"杜光庭",era:"Đường Hy Tông Trung Hòa 4 (884)",topic:"仙传",essence:"Ghi các đời đế vương sùng phụng Đạo giáo: dựng cung quán, khai độ đạo sĩ, linh dị liên quan vương triều. Biên năm 884, tấu tiến; vừa sử đạo, vừa tuyên giáo. Nằm Động huyền ký truyền loại.",key_text:"中和四年十二月十五日上都太清宮文章應制弘教大師賜紫道士臣杜光庭上進",use:"Nghiên cứu lịch sử sùng đạo; tư liệu cung quán và ân mệnh triều đình.",sources:["https://zh.daoinfo.org/wiki/%E6%AD%B7%E4%BB%A3%E5%B4%87%E9%81%93%E8%A8%98","https://www.shidianguji.com/book/DZ0593","https://michaelstanley-baker.com/clarkes-complete-daoist-index/"],textual_certainty:"high",notes:"batch71 · Grok-4.5 focused DZ520-600"},{dz:"DZ1315",name_han:"太上洞神太元河图三元仰谢仪",name_vi:"Thái Thượng Động Thần Thái Nguyên Hà Đồ Tam Nguyên Ngưỡng Tạ Nghi",bu:"正一",author:"không rõ",era:"Tống",topic:"ritual",essence:"Nghi thức ngưỡng tạ Tam Nguyên dựa trên Hà Đồ và truyền thống Động Thần Thái Nguyên. Dùng trong khoa nghi tạ ơn thiên địa, giải trừ tai ách theo chu kỳ tam nguyên. Phản ánh sự dung hợp Hà Đồ số thuật với nghi lễ đạo giáo.",key_text:"三元开化，河图出图，仰谢玄恩。",use:"Khoa nghi ngưỡng tạ, giải ách và nghi lễ Tam Nguyên/Hà Đồ.",sources:["https://ctext.org/daoism","https://dao.crs.cuhk.edu.hk/","https://zh.wikipedia.org/wiki/道藏"],textual_certainty:"partial",notes:"batch72 · Grok-4.5 focused DZ1300-1420"},{dz:"DZ1320",name_han:"灵宝净明天枢都司法院须知法文",name_vi:"Linh Bảo Tịnh Minh Thiên Khu Đô Tư Pháp Viện Tu Tri Pháp Văn",bu:"正一",author:"truyền thống Tịnh Minh",era:"Nam Tống–Nguyên",topic:"ritual",essence:"Pháp văn hướng dẫn thực hành của Thiên Khu Đô Tư Pháp Viện thuộc phái Tịnh Minh Linh Bảo. Quy định thủ tục, chức vụ và nghi thức hành pháp trong hệ thống tòa án thiên đình huyền học. Quan trọng để hiểu tổ chức pháp viện và khoa nghi Tịnh Minh.",key_text:"天枢都司，统摄万灵，明彰赏罚。",use:"Nghiên cứu tổ chức pháp viện thiên đình và nghi thức phái Tịnh Minh.",sources:["https://ctext.org/wiki.pl?if=en&res=803495","https://baike.baidu.com/item/净明道","https://dao.crs.cuhk.edu.hk/"],textual_certainty:"partial",notes:"batch72 · Grok-4.5 focused DZ1300-1420"},{dz:"DZ1321",name_han:"灵宝净明院教师周真公起请画一",name_vi:"Linh Bảo Tịnh Minh Viện Giáo Sư Chu Chân Công Khởi Thỉnh Họa Nhất",bu:"正一",author:"周真公 (Chu Chân Công)",era:"Nam Tống",topic:"ritual",essence:"Văn kiện khởi thỉnh và quy định (họa nhất) do giáo sư Chu Chân Công của viện Tịnh Minh soạn. Ghi lại đề nghị chuẩn hóa nghi thức và quy chế hành đạo Tịnh Minh. Nguồn sử liệu trực tiếp về tổ chức và cải cách nghi lễ phái Tịnh Minh thời Tống.",key_text:"起请画一，以明教法，用正科仪。",use:"Nghiên cứu lịch sử phái Tịnh Minh, quy chế giáo sư và khoa nghi chuẩn hóa.",sources:["https://zh.wikipedia.org/wiki/淨明道","https://ctext.org/daoism","https://dao.crs.cuhk.edu.hk/"],textual_certainty:"partial",notes:"batch72 · Grok-4.5 focused DZ1300-1420"},{dz:"DZ1322",name_han:"太上灵宝净明法印式",name_vi:"Thái Thượng Linh Bảo Tịnh Minh Pháp Ấn Thức",bu:"正一",author:"truyền thống Tịnh Minh",era:"Nam Tống–Nguyên",topic:"fu",essence:"Mẫu thức và quy cách khắc dùng pháp ấn của phái Linh Bảo Tịnh Minh. Mô tả hình dạng, chữ khắc và công dụng các ấn dùng trong hành pháp. Tài liệu kỹ thuật quan trọng về ấn phù trong pháp thuật chính nhất/Tịnh Minh.",key_text:"法印者，通真达灵之信也。",use:"Tham chiếu mẫu ấn pháp, phù lục và hành pháp Tịnh Minh.",sources:["https://ctext.org/daoism","https://baike.baidu.com/item/净明忠孝道","https://dao.crs.cuhk.edu.hk/"],textual_certainty:"partial",notes:"batch72 · Grok-4.5 focused DZ1300-1420"},{dz:"DZ1323",name_han:"太上灵宝净明秘法篇",name_vi:"Thái Thượng Linh Bảo Tịnh Minh Bí Pháp Thiên",bu:"正一",author:"truyền thống Tịnh Minh",era:"Nam Tống–Nguyên",topic:"cultivation",essence:"Bí pháp tu trì và hành pháp cốt lõi của phái Linh Bảo Tịnh Minh, nhấn mạnh trung hiếu và thanh tĩnh. Kết hợp nội luyện với khoa nghi cứu thế. Phản ánh đặc sắc đạo Tịnh Minh: tu thân lấy trung hiếu làm gốc, pháp thuật làm dụng.",key_text:"净明者，无幽不烛，纤尘不污。",use:"Tu trì Tịnh Minh, nghiên cứu bí pháp và đạo đức trung hiếu trong đạo giáo.",sources:["https://zh.wikipedia.org/wiki/淨明道","https://ctext.org/daoism","https://dao.crs.cuhk.edu.hk/"],textual_certainty:"partial",notes:"batch72 · Grok-4.5 focused DZ1300-1420"},{dz:"DZ1324",name_han:"灵宝净明新修九老神印伏魔秘法",name_vi:"Linh Bảo Tịnh Minh Tân Tu Cửu Lão Thần Ấn Phục Ma Bí Pháp",bu:"正一",author:"truyền thống Tịnh Minh",era:"Nam Tống–Nguyên",topic:"fu",essence:"Bí pháp phục ma dùng Cửu Lão Thần Ấn trong hệ Tịnh Minh được tân tu. Mô tả ấn pháp, chú tụng và nghi thức hàng phục tà ma. Tiêu biểu cho pháp thuật trừ tà kết hợp ấn phù của truyền thống Linh Bảo Tịnh Minh.",key_text:"九老神印，威震魔庭，邪魔束首。",use:"Pháp thuật phục ma, ấn pháp và nghi thức trừ tà Tịnh Minh.",sources:["https://ctext.org/daoism","https://baike.baidu.com/item/净明道","https://dao.crs.cuhk.edu.hk/"],textual_certainty:"partial",notes:"batch72 · Grok-4.5 focused DZ1300-1420"},{dz:"DZ1335",name_han:"许真君受炼形神上清毕道法要节文",name_vi:"Hứa Chân Quân Thụ Luyện Hình Thần Thượng Thanh Tất Đạo Pháp Yếu Tiết Văn",bu:"正一",author:"truyền thống Hứa Tốn / Tịnh Minh",era:"Tống–Nguyên",topic:"cultivation",essence:"Tiết yếu pháp luyện hình thần và tất đạo Thượng Thanh gắn với Hứa Chân Quân (Hứa Tốn). Nêu các bước thụ luyện, chuyển hóa hình thần hướng tới thành đạo. Nối truyền thống nội đan/thượng thanh với sùng bái Hứa Chân Quân của phái Tịnh Minh.",key_text:"形神受炼，上清毕道，白日飞升。",use:"Tu luyện hình thần, pháp yếu tất đạo và nghiên cứu truyền thừa Hứa Chân Quân.",sources:["https://zh.wikipedia.org/wiki/許遜","https://ctext.org/daoism","https://dao.crs.cuhk.edu.hk/"],textual_certainty:"partial",notes:"batch72 · Grok-4.5 focused DZ1300-1420"},{dz:"DZ1345",name_han:"北帝说豁落七元经",name_vi:"Bắc Đế Thuyết Khoát Lạc Thất Nguyên Kinh",bu:"正一",author:"không rõ (kinh Bắc Đế)",era:"Đường–Tống",topic:"mantra",essence:"Kinh Bắc Đế giảng về thất nguyên (bảy ngôi sao Bắc Đẩu) và pháp khoát lạc. Liên hệ tinh tú Bắc Đẩu với chú pháp, cứu độ và trừ tà. Quan trọng trong hệ thống Bắc Đế–Bắc Đẩu của đạo giáo trung cổ.",key_text:"七元豁落，斗中真灵，回光照映。",use:"Kinh chú Bắc Đẩu/Bắc Đế, nghi thức thất nguyên và cứu độ.",sources:["https://ctext.org/daoism","https://baike.baidu.com/item/北帝","https://dao.crs.cuhk.edu.hk/"],textual_certainty:"partial",notes:"batch72 · Grok-4.5 focused DZ1300-1420"},{dz:"DZ1347",name_han:"七元真诀语驱疫秘经",name_vi:"Thất Nguyên Chân Quyết Ngữ Khu Dịch Bí Kinh",bu:"正一",author:"không rõ",era:"Tống",topic:"mantra",essence:"Bí kinh dùng chân quyết và ngữ chú của thất nguyên để khu trừ ôn dịch. Kết hợp tinh lực Bắc Đẩu với pháp thuật trị ôn, cứu dân. Phản ánh vai trò y tế tôn giáo và khoa nghi chống dịch trong đạo tạng chính nhất.",key_text:"七元真诀，驱瘟伐疫，救护生民。",use:"Khoa nghi khu ôn, chú pháp thất nguyên và nghiên cứu trị dịch đạo giáo.",sources:["https://ctext.org/daoism","https://dao.crs.cuhk.edu.hk/","https://zh.wikipedia.org/wiki/道藏"],textual_certainty:"partial",notes:"batch72 · Grok-4.5 focused DZ1300-1420"},{dz:"DZ979",name_han:"明真破妄章頌",name_vi:"Minh Chân Phá Vọng Chương Tụng",bu:"洞神",author:"張繼先",era:"北宋（三十代天師）",topic:"cultivation",essence:"Bảy ngôn tuyệt cú của Trương Kế Tiên: từ đạo sinh thiên địa nhân đến thân tam bảo, tâm hợp thần. Phá vọng chấp, chỉ ra chân cơ lôi pháp trong thân.",key_text:"真心動處是雷機，神合神兮妙更奇",use:"Đối chiếu tâm – thần – lôi pháp; phá mê chấp ngoại cầu",sources:["https://zh.daoinfo.org/index.php?title=%E6%98%8E%E7%9C%9F%E7%A0%B4%E5%A6%84%E7%AB%A0%E9%A0%8C&variant=zh-hans","https://zh.wikisource.org/wiki/%E6%98%8E%E7%9C%9F%E7%A0%B4%E5%A6%84%E7%AB%A0%E9%A0%8C","https://ctext.org/wiki.pl?if=gb&res=793000","https://www.shidianguji.com/book/DZ0979"],textual_certainty:"high",notes:"batch73 · Grok-4.5 focused DZ960-1000"},{dz:"DZ984",name_han:"玄精碧匣靈寶聚玄經",name_vi:"Huyền Tinh Bích Hạp Linh Bảo Tụ Huyền Kinh",bu:"太玄",author:"佚名",era:"唐–宋（太玄部）",topic:"classic",essence:"Kinh Thái Huyền bộ, lấy huyền tinh – bích hạp làm tượng tụ linh bảo. Nói về tụ huyền khí, tinh hoa đạo thể làm nền triết cho dưỡng sinh và huyền học.",key_text:"null",use:"Đọc nền Thái Huyền; tham chiếu tụ khí – huyền quan",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://homeinmists.ilotus.org/%E9%81%93%E8%97%8F%E5%8C%AF%E7%B7%A8/%E6%AD%A3%E7%B5%B1%E9%81%93%E8%97%8F/%E9%81%93%E8%97%8F%E7%9B%AE%E9%8C%84/","https://taolibrary.com/category95.aspx"],textual_certainty:"partial",notes:"batch73 · Grok-4.5 focused DZ960-1000"},{dz:"DZ985",name_han:"太上洞玄靈寶三一五氣真經",name_vi:"Thái Thượng Động Huyền Linh Bảo Tam Nhất Ngũ Khí Chân Kinh",bu:"太玄",author:"佚名（託黃帝–皇人）",era:"南北朝–唐",topic:"cultivation",essence:"Kinh thủ Tam Nhất (nê hoàn, giáng cung, đan điền) và thực ngũ nha / ngũ khí. Nối thân–quốc, bảo khí toàn hình, kết hợp long thai kim dịch cửu chuyển với thủ nhất.",key_text:"必欲長生，三一當明",use:"Thực hành thủ nhất, phục khí ngũ nha; nền nội dưỡng",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E4%B8%89%E4%B8%80%E4%BA%94%E6%B0%A3%E7%9C%9F%E7%B6%93&variant=zh-hant","https://zh.wikisource.org/zh-hans/%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E7%81%B5%E5%AE%9D%E4%B8%89%E4%B8%80%E4%BA%94%E6%B0%94%E7%9C%9F%E7%BB%8F","https://ctext.org/wiki.pl?if=gb&res=180568","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf"],textual_certainty:"high",notes:"batch73 · Grok-4.5 focused DZ960-1000"},{dz:"DZ986",name_han:"太上清靜元洞真文玉字妙經",name_vi:"Thái Thượng Thanh Tĩnh Nguyên Động Chân Văn Ngọc Tự Diệu Kinh",bu:"太玄",author:"佚名",era:"唐–宋",topic:"cultivation",essence:"Kinh Thái Huyền nhấn mạnh thanh tĩnh nguyên động, chân văn ngọc tự. Dùng tĩnh làm gốc, văn tự huyền làm phù ấn nội dưỡng.",key_text:"null",use:"Kết hợp tụng kinh thanh tĩnh với quán tưởng chân văn",sources:["https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://homeinmists.ilotus.org/docs/cnTaoSutra_contents.htm","https://taolibrary.com/category95.aspx"],textual_certainty:"partial",notes:"batch73 · Grok-4.5 focused DZ960-1000"},{dz:"DZ987",name_han:"太上洞玄靈寶天關經",name_vi:"Thái Thượng Động Huyền Linh Bảo Thiên Quan Kinh",bu:"太玄",author:"佚名",era:"南北朝–隋唐",topic:"philosophy",essence:"Thuật vũ trụ từ thái dịch, thái sơ đến tứ phạm tam giới; Lão Quân là nguyên khí phụ mẫu. Mở khung thiên quan – nhân đạo cho tu luyện siêu thăng.",key_text:"null",use:"Nền vũ trụ luận; hiểu thiên quan – tầng giới trong tu tiên",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E5%A4%A9%E9%97%9C%E7%B6%93&variant=zh-hant","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E6%B4%9E%E7%8E%84%E9%9D%88%E5%AF%B6%E5%A4%A9%E9%97%9C%E7%B6%93&variant=zh-hans"],textual_certainty:"high",notes:"batch73 · Grok-4.5 focused DZ960-1000"},{dz:"DZ988",name_han:"上清無英真童合遊內變玉經",name_vi:"Thượng Thanh Vô Anh Chân Đồng Hợp Du Nội Biến Ngọc Kinh",bu:"太玄",author:"佚名（上清系）",era:"東晉–南朝",topic:"cultivation",essence:"Pháp tồn tư Vô Anh chân đồng – thần quân trong thân, hợp du nội biến. Cổ pháp thượng thanh quán tưởng thân thần để biến hóa nội cảnh.",key_text:"null",use:"Thực hành tồn tư nội thần; đối chiếu đại động – thân thần",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%8A%E6%B8%85%E7%84%A1%E8%8B%B1%E5%90%88%E6%B8%B8%E5%85%A7%E8%AE%8A%E7%8E%89%E7%B6%93&variant=zh-hant","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://taolibrary.com/category95.aspx"],textual_certainty:"high",notes:"batch73 · Grok-4.5 focused DZ960-1000"},{dz:"DZ989",name_han:"上清神寶洞房真諱上經",name_vi:"Thượng Thanh Thần Bảo Động Phòng Chân Húy Thượng Kinh",bu:"太玄",author:"佚名（又名青童道君列紀）",era:"東晉–南朝",topic:"cultivation",essence:"Kinh thượng thanh sớm: Kim Khuyết đế quân truyền Thanh Đồng đạo quân về thần bảo động phòng và chân húy. Cốt lõi tồn tư động phòng – nội cảnh.",key_text:"null",use:"Nghiên cứu thượng thanh tồn tư; danh húy – cung thất trong thân",sources:["https://zh.daoinfo.org/index.php?title=%E4%B8%8A%E6%B8%85%E7%A5%9E%E5%AF%B6%E6%B4%9E%E6%88%BF%E7%9C%9F%E8%AB%B1%E4%B8%8A%E7%B6%93&variant=zh-hant","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://taolibrary.com/category95.aspx"],textual_certainty:"high",notes:"batch73 · Grok-4.5 focused DZ960-1000"},{dz:"DZ991",name_han:"太上長文大洞靈寶幽玄上品妙經",name_vi:"Thái Thượng Trường Văn Đại Động Linh Bảo U Huyền Thượng Phẩm Diệu Kinh",bu:"太玄",author:"佚名",era:"晚唐–五代",topic:"内丹",essence:"Nội đan kinh (trường văn đại động), 19 chương. Lấy u huyền làm tông, nói hỏa hầu, tinh khí thần theo lối đại động chuyển sang nội đan.",key_text:"null",use:"Đọc nền nội đan u huyền; đối chiếu đại động – kim đan",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E9%95%B7%E6%96%87%E5%A4%A7%E6%B4%9E%E9%9D%88%E5%AF%B6%E5%B9%BD%E7%8E%84%E4%B8%8A%E5%93%81%E5%A6%99%E7%B6%93&variant=zh-hans","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E9%95%B7%E6%96%87%E5%A4%A7%E6%B4%9E%E9%9D%88%E5%AF%B6%E5%B9%BD%E7%8E%84%E4%B8%8A%E5%93%81%E5%A6%99%E7%B6%93&variant=zh-hant"],textual_certainty:"high",notes:"batch73 · Grok-4.5 focused DZ960-1000"},{dz:"DZ992",name_han:"太上長文大洞靈寶幽玄上品妙經發揮",name_vi:"Thái Thượng Trường Văn Đại Động Linh Bảo U Huyền Thượng Phẩm Diệu Kinh Phát Huy",bu:"太玄",author:"佚名",era:"宋（註《長文大洞經》）",topic:"内丹",essence:"Chú giải kinh trên theo chế độ 30 ngày: mỗi ngày một thiên, kèm tụng/tán. Làm rõ hỏa hầu nội đan u huyền vốn ẩn áo.",key_text:"null",use:"Thực tu theo lịch 30 ngày; giảng hỏa hầu nội đan",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E9%95%B7%E6%96%87%E5%A4%A7%E6%B4%9E%E9%9D%88%E5%AF%B6%E5%B9%BD%E7%8E%84%E4%B8%8A%E5%93%81%E5%A6%99%E7%B6%93%E7%99%BC%E6%8F%AE&variant=zh-hant","https://www.goldenelixir.com/files/Index_of_Zhengtong_Daozang.pdf","https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E9%95%B7%E6%96%87%E5%A4%A7%E6%B4%9E%E9%9D%88%E5%AF%B6%E5%B9%BD%E7%8E%84%E4%B8%8A%E5%93%81%E5%A6%99%E7%B6%93&variant=zh-hans"],textual_certainty:"high",notes:"batch73 · Grok-4.5 focused DZ960-1000"},{dz:"null",name_han:"悟真篇小序（陆西星）",name_vi:"Ngộ Chân Thiên Tiểu Tự (Lục Tây Tinh)",bu:"藏外",author:"陆西星（潜虚子/陆潜虚）",era:"明（16世纪）",topic:"cultivation",essence:"Chú giải ngắn gọn của Đông phái đan đạo về 《悟真篇》, nhấn mạnh âm dương song tu và dược vật hỏa hầu. Tác phẩm nằm trong 《方壶外史》, giải thơ từ của Trương Bá Đoan theo hướng “khán thiên chi đạo, chấp thiên chi hành”. Được các nhà chú sau như Thù Chiêu Ngao, Đào Tố Tự trích dẫn nhiều.",key_text:"先命后性，以有为而造无为",use:"Đọc song song với 《玄肤论》《金丹就正篇》 để nắm khung Đông phái giải Ngộ Chân.",sources:["https://zh.wikipedia.org/wiki/%E6%82%9F%E7%9C%9F%E7%AF%87","https://www.daoisms.com.cn/2018/17/09/6740/"],textual_certainty:"high",notes:"batch74 · Grok-4.5 悟真/参同注疏藏外"},{dz:"null",name_han:"悟真篇正义（董德宁）",name_vi:"Ngộ Chân Thiên Chính Nghĩa (Đổng Đức Ninh)",bu:"藏外",author:"董德宁（元真子）",era:"清（乾隆）",topic:"cultivation",essence:"Chú 《悟真篇》 theo hướng “chính nghĩa”: phá nghi, bài trừ bàng môn, quy về đan đạo chính thống. Giải từng chương, nhấn mạnh tiên lập đỉnh khí, minh dược vật, hậu minh hỏa hầu. Cùng thời với 《周易参同契正义》 của ông (bản 参同 đã nằm danh sách loại trừ).",key_text:"称曰正义者，为使读者破疑攫微，学归正道",use:"Dùng khi cần bản chú rõ ràng, chống tà thuyết; so với Lưu Nhất Minh và Chu Nguyên Dục.",sources:["https://zh.wikipedia.org/wiki/%E6%82%9F%E7%9C%9F%E7%AF%87","https://zhuanlan.zhihu.com/p/368199859"],textual_certainty:"high",notes:"batch74 · Grok-4.5 悟真/参同注疏藏外"},{dz:"null",name_han:"悟真篇解（彭好古）",name_vi:"Ngộ Chân Thiên Giải (Bành Hảo Cổ)",bu:"藏外",author:"彭好古（一壑居士）",era:"明（万历前后）",topic:"cultivation",essence:"Chú giải 《悟真篇》 thời Minh, thu vào 《藏外道书》; thiên về âm dương đan pháp và giải ẩn ngữ long hổ–diên hoắc. Cùng hệ với chú 《入药镜》 và 《参同契》 của ông trong các bản 《道藏精华录》.",key_text:"null",use:"Đối chiếu Đông phái/âm dương phái với chú thuần tu; xem song song bản trong 《藏外道书》.",sources:["https://zhuanlan.zhihu.com/p/368199859","https://www.daoist.org/BookSearch(test)/list012/84-70.pdf"],textual_certainty:"high",notes:"batch74 · Grok-4.5 悟真/参同注疏藏外"},{dz:"null",name_han:"悟真篇翼（甄淑）",name_vi:"Ngộ Chân Thiên Dực (Chân Thục)",bu:"藏外",author:"甄淑",era:"明",topic:"cultivation",essence:"Bản “dực” (cánh phụ) chú 《悟真篇》 thời Minh, được liệt trong các đề yếu nhị thập ngũ gia chú. Nghiêng về song tu ẩn dụ long hổ tương ứng, giải các câu về “diên mỹ” và dược vật. Là một trong các chú bản Minh ít được in lại nhưng được tư liệu học thuật trích dẫn.",key_text:"null",use:"Tham khảo xu hướng chú song tu thời Minh; đối chiếu Bành Hảo Cổ và Lục Tây Tinh.",sources:["https://zhuanlan.zhihu.com/p/368199859","https://www.daoist.org/BookSearch(test)/list012/84-70.pdf"],textual_certainty:"partial",notes:"batch74 · Grok-4.5 悟真/参同注疏藏外"},{dz:"null",name_han:"悟真篇约注（陶素耜）",name_vi:"Ngộ Chân Thiên Ước Chú (Đào Tố Tự)",bu:"藏外",author:"陶素耜",era:"清（康熙前后）",topic:"cultivation",essence:"Bản “ước chú” (chú tóm) 《悟真篇》, lược giải cốt yếu dược hỏa và tiên thiên chân diên. Cùng dòng lý luận với 《参同契脉望》(bản 参同 đã loại trừ), chịu ảnh hưởng Lục Tây Tinh. Đặt tên từng bài thơ theo chủ đề tu luyện (danh lợi hư ảo, sớm cầu đại dược…).",key_text:"null",use:"Đọc khi cần bản chú gọn, nhấn tiên thiên chân diên; so với Thù Chiêu Ngao.",sources:["http://simple.taolibrary.com/category/category76/c76062.htm","https://ctext.org/library.pl?if=gb&title=%E6%82%9F%E7%9C%9F%E7%AF%87"],textual_certainty:"high",notes:"batch74 · Grok-4.5 悟真/参同注疏藏外"},{dz:"null",name_han:"悟真篇注解（张位）",name_vi:"Ngộ Chân Thiên Chú Giải (Trương Vị)",bu:"藏外",author:"张位",era:"明",topic:"cultivation",essence:"《续文献通考》 ghi 《悟真篇注解》 ba quyển cùng 《周易参同契注解》 ba quyển của Trương Vị. Là chú bản quan viên–đạo sĩ thời Minh, được liệt trong nhị thập ngũ gia chú Ngộ Chân. Góp phần truyền bá Ngộ Chân ngoài hệ 《道藏》 chính thống.",key_text:"null",use:"Tham khảo hệ chú Minh quan phương; đối chiếu Bành Hảo Cổ, Lý Văn Chúc.",sources:["https://zhuanlan.zhihu.com/p/368199859","https://ctext.org/wiki.pl?if=en&chapter=680054&remap=gb"],textual_certainty:"high",notes:"batch74 · Grok-4.5 悟真/参同注疏藏外"},{dz:"null",name_han:"周易参同契分章注（陈致虚）",name_vi:"Chu Dịch Tham Đồng Khế Phân Chương Chú (Trần Trí Hư)",bu:"藏外",author:"陈致虚（上阳子）",era:"元（14世纪）",topic:"cultivation",essence:"Chia 《参同契》 thành 35 chương mà chú; chính thống 《道藏》 không thu, có bản 《四库全书》. Chủ trương “đan thư đa bất khả tín, đắc chân quyết giả tất dĩ Tham Đồng, Ngộ Chân vi chủ”. Phát huy Nam Tông nội đan: tiên thiên chân nhất chi khí, luyện hợp âm dương khảm ly, kiêm minh tâm kiến tính.",key_text:"丹书多不可信，得真诀者要必以《参同契》为主",use:"Bản chú nguyên quan trọng nhất ngoài hệ Bành Hiểu/Dũ Diễm; đọc với 《悟真篇三注》 của ông.",sources:["https://zh.daoinfo.org/index.php?title=%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%E5%88%86%E7%AB%A0%E6%B3%A8%EF%BC%88%E9%99%B3%E8%87%B4%E8%99%9B%EF%BC%89&variant=zh-hans","https://zh.wikisource.org/wiki/%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91%E5%88%86%E7%AB%A0%E6%B3%A8_(%E5%9B%9B%E5%BA%AB%E5%85%A8%E6%9B%B8%E6%9C%AC)/%E5%85%A8%E8%A6%BD"],textual_certainty:"high",notes:"batch74 · Grok-4.5 悟真/参同注疏藏外"},{dz:"null",name_han:"古文周易参同契集解（蒋一彪）",name_vi:"Cổ Văn Chu Dịch Tham Đồng Khế Tập Giải (Tưởng Nhất Bưu)",bu:"藏外",author:"蒋一彪",era:"明",topic:"cultivation",essence:"Tập giải theo “thạch hàm cổ bản” (bản cải biên Đỗ Nhất Thành), thu chú Bành Hiểu, Trần Hiển Vi, Trần Trí Hư, Dũ Diễm… Tạo khung đối chiếu đa gia cho “cổ văn” Tham Đồng. 《四库》 và các tùng thư như 《津逮秘书》 có truyền bản.",key_text:"null",use:"Dùng khi đối chiếu dị bản “cổ văn” Tham Đồng; không nhầm với bản Bành Hiểu chính thống.",sources:["https://zh.wikipedia.org/zh-hans/%E5%91%A8%E6%98%93%E5%8F%82%E5%90%8C%E5%A5%91","https://www.biblio.nhat-nam.ru/Wei_Boyang.pdf"],textual_certainty:"high",notes:"batch74 · Grok-4.5 悟真/参同注疏藏外"},{dz:"null",name_han:"古本周易参同契集注（仇兆鳌）",name_vi:"Cổ Bản Chu Dịch Tham Đồng Khế Tập Chú (Thù Chiêu Ngao)",bu:"藏外",author:"仇兆鳌",era:"清（康熙）",topic:"cultivation",essence:"Tập chú “cổ bản” Tham Đồng (cùng hệ thạch hàm), khác với 《悟真篇集注》 đã loại trừ. Thu nhiều thuyết Lục Tây Tinh–Đông phái về dược vật hỏa hầu, tiên thiên chân diên. “Lệ ngôn” nêu rõ tiêu chuẩn phân tiên/hậu thiên.",key_text:"null",use:"Bản tập chú Thanh học giả; đọc song với 《悟真篇集注》 cùng tác giả để so phương pháp.",sources:["https://zh.wikipedia.org/zh-hans/%E5%91%A8%E6%98%93%E5%8F%82%E5%90%8C%E5%A5%91","https://www.daoisms.com.cn/2018/17/09/6740/"],textual_certainty:"high",notes:"batch74 · Grok-4.5 悟真/参同注疏藏外"},{dz:"null",name_han:"周易参同契章句（李光地）",name_vi:"Chu Dịch Tham Đồng Khế Chương Cú (Lý Quang Địa)",bu:"藏外",author:"李光地",era:"清（康熙）",topic:"cultivation",essence:"Bản “chương cú” của đại Nho Lý Quang Địa, thu trong 《榕村全集》. Giải Tham Đồng theo hướng Nho–Đạo giao thiệp, chú trọng văn lý và cấu trúc chương cú hơn là khẩu quyết mật truyền. Đại diện nhánh chú giải học giả quan phương thời Thanh.",key_text:"null",use:"Đối chiếu chú đan gia thuần túy với chú Nho thần; hữu ích khi nghiên cứu tiếp nhận Tham Đồng ngoài đạo môn.",sources:["https://zh.wikipedia.org/zh-hans/%E5%91%A8%E6%98%93%E5%8F%82%E5%90%8C%E5%A5%91","http://www.lsqn.cn/story/LSGS/200703/67992_2.html"],textual_certainty:"high",notes:"batch74 · Grok-4.5 悟真/参同注疏藏外"},{dz:"null",name_han:"古文周易参同契注（袁仁林）",name_vi:"Cổ Văn Chu Dịch Tham Đồng Khế Chú (Viên Nhân Lâm)",bu:"藏外",author:"袁仁林",era:"清",topic:"cultivation",essence:"Chú bản “cổ văn” Tham Đồng thời Thanh, nằm trong danh lục chú gia cổ–cận đại. Thiên về giải ngôn từ và cấu trúc dị bản cổ văn, bổ sung cho hệ Tưởng Nhất Bưu–Thù Chiêu Ngao.",key_text:"null",use:"Tham khảo khi làm việc với dị bản “cổ văn”; so với Tưởng Nhất Bưu tập giải.",sources:["http://www.lsqn.cn/story/LSGS/200703/67992_2.html","https://homeinmists.ilotus.org/%E4%B8%B9%E7%B6%93%E9%81%93%E6%9B%B8/%E9%AD%8F%E4%BC%AF%E9%99%BD-%E5%91%A8%E6%98%93%E5%8F%83%E5%90%8C%E5%A5%91/"],textual_certainty:"partial",notes:"batch74 · Grok-4.5 悟真/参同注疏藏外"},{dz:"null",name_han:"周易参同契笺注（王文禄）",name_vi:"Chu Dịch Tham Đồng Khế Tiên Chú (Vương Văn Lộc)",bu:"藏外",author:"王文禄",era:"明",topic:"cultivation",essence:"《周易参同契笺注》 một quyển và 《古文参同契相类解》 một quyển của Vương Văn Lộc thời Minh. “Tiên chú” mang tính trích giải–bổ chú ngắn, thuộc dòng chú nội đan Minh. Được các tổng mục Tham Đồng liệt kê cùng Trương Vị, Tưởng Nhất Bưu.",key_text:"null",use:"Bản chú ngắn thời Minh; dùng làm đối chiếu văn bản với hệ Bành–Dũ–Trần.",sources:["http://www.lsqn.cn/story/LSGS/200703/67992_2.html","https://zh.wikipedia.org/zh-hans/%E5%91%A8%E6%98%93%E5%8F%82%E5%90%8C%E5%A5%91"],textual_certainty:"high",notes:"batch74 · Grok-4.5 悟真/参同注疏藏外"},{dz:"null",name_han:"崔公入药镜注释（李攀龙）",name_vi:"Thôi Công Nhập Dược Kính Chú Thích (Lý Phan Long)",bu:"藏外",author:"李攀龙（沧溟）",era:"明",topic:"cultivation",essence:"Chú 《入药镜》 của Lý Phan Long (Thương Minh), in cùng chú Vương Đạo Uyên và Bành Hảo Cổ trong 《道藏精华录》. Giải chi tiết “ứng triều–ứng tinh”, hỏa hầu sóc vọng, và tiên thiên nhất khí. Bổ sung góc nhìn văn nhân–đạo sĩ cho cốt tủy 246 chữ của Thôi Hy Phạm.",key_text:"先天一炁金丹祖，虚无久是先天母",use:"Đọc bộ ba chú 《道藏精华录》 (Vương/Lý/Bành); đối chiếu 《崔公入药镜测疏》 Lục Tây Tinh.",sources:["https://ctext.org/wiki.pl?if=en&chapter=890541&remap=gb","https://www.daoisms.com.cn/2013/11/12/16983/"],textual_certainty:"high",notes:"batch74 · Grok-4.5 悟真/参同注疏藏外"},{dz:"null",name_han:"崔公入药镜测疏（陆西星）",name_vi:"Thôi Công Nhập Dược Kính Trắc Sớ (Lục Tây Tinh)",bu:"藏外",author:"陆西星（潜虚子）",era:"明（16世纪）",topic:"cultivation",essence:"Sớ giải Đông phái cho 《入药镜》, thu 《藏外道书》 quyển 5. Chỉ “dược tổ” là tiên thiên chân nhất chi khí; luận âm dương đỉnh lô, hỏa hầu thái dược, và “khinh khinh vận, mặc mặc cử”. Khác hẳn bản 《参同契测疏》 đã loại trừ—đây là sớ riêng cho Nhập Dược Kính.",key_text:"夫学道之人，大要先识药祖，所谓药祖，乃鸿蒙始判之炁",use:"Văn bản cốt lõi Đông phái về Nhập Dược Kính; đọc với 《悟真篇小序》 cùng tác giả.",sources:["https://zh.daoinfo.org/index.php?title=%E5%B4%94%E5%85%AC%E5%85%A5%E8%97%A5%E9%8F%A1%E6%B8%AC%E7%96%8F&variant=zh-hans","https://zh.wikisource.org/zh-hans/%E5%B4%94%E5%85%AC%E5%85%A5%E8%97%A5%E9%8F%A1%E6%B8%AC%E7%96%8F"],textual_certainty:"high",notes:"batch74 · Grok-4.5 悟真/参同注疏藏外"},{dz:"null",name_han:"黄庭内外玉景经解（蒋慎修）",name_vi:"Hoàng Đình Nội Ngoại Ngọc Cảnh Kinh Giải (Tưởng Thận Tu)",bu:"洞玄",author:"蒋慎修",era:"北宋",topic:"cultivation",essence:"Nguyên đề “triều tán đại phu… thần Tưởng Thận Tu thượng tiến”. 《通志·艺文略》 ghi mười quyển; bản 《正统道藏》洞玄部玉诀类 chỉ còn tàn một quyển. Giải cả nội–ngoại cảnh, nhấn “tích tinh lũy khí nãi thành chân”, nối Hoàng Đình với dưỡng sinh–tồn thần.",key_text:"仙人道士非有神，积精累气乃成真",use:"Bản tàn Đạo tạng quan trọng ngoài Lương Khâu Tử/Lưu Xử Huyền; đối chiếu 《云笈七签》 vụ Thành Tử.",sources:["https://zh.daoinfo.org/index.php?title=%E9%BB%83%E5%BA%AD%E5%85%A7%E5%A4%96%E7%8E%89%E6%99%AF%E7%B6%93%E8%A7%A3%EF%BC%88%E8%94%A3%E6%85%8E%E4%BF%AE%EF%BC%89&variant=zh-hans","http://www.ctcwri.idv.tw/CTCW-CMTS/CMT02%E6%B4%9E%E7%8E%84%E9%83%A8/CMT0203%E7%8E%89%E8%A8%A3%E9%A1%9E/CMT0203ALL/CH020309%E9%BB%83%E5%BA%AD%E5%85%A7%E5%A4%96%E7%8E%89%E6%99%AF%E7%B6%93%E8%A7%A3.htm"],textual_certainty:"high",notes:"batch74 · Grok-4.5 悟真/参同注疏藏外"},{dz:"null",name_han:"太上黄庭外景经注（务成子）",name_vi:"Thái Thượng Hoàng Đình Ngoại Cảnh Kinh Chú (Vụ Thành Tử)",bu:"太玄",author:"务成子（隋唐道士，托名）",era:"隋–唐",topic:"cultivation",essence:"Chú 《太上黄庭外景经》 nguyên đề Vụ Thành Tử, thu chủ yếu trong 《云笈七签》 quyển 12 (và các bản 《道藏精华》). Nhấn bảo tinh tích khí, tồn thần thủ nhất, thường thủ đan điền; hợp nghĩa gốc ngoại cảnh. Khác hẳn chú Lương Khâu Tử và Lưu Xử Huyền đã loại trừ.",key_text:"黄庭经者，盖老君之所作也",use:"Bản chú cổ nhất còn dùng được cho Ngoại cảnh; đối chiếu Lương Khâu Tử và Tưởng Thận Tu.",sources:["https://zh.daoinfo.org/index.php?title=%E5%A4%AA%E4%B8%8A%E9%BB%83%E5%BA%AD%E5%A4%96%E6%99%AF%E7%8E%89%E7%B6%93%E6%B3%A8%EF%BC%88%E5%8B%99%E6%88%90%E5%AD%90%EF%BC%89&variant=zh-hans","https://zh.wikipedia.org/zh-hans/%E9%BB%84%E5%BA%AD%E7%BB%8F"],textual_certainty:"high",notes:"batch74 · Grok-4.5 悟真/参同注疏藏外"},{dz:"null",name_han:"老子衍（王夫之）",name_vi:"Lão Tử Diễn (Vương Phu Chi)",bu:"太玄",author:"王夫之（船山）",era:"明末清初 / 17th century",topic:"老学",essence:"Không phải bản chú theo kiểu chương-cú thông thường, mà là diễn ý, phê phán các chú xưa gán Nho–Phật vào Lão. Vương Phu Chi ‘vào doanh lũy’ của Lão Tử để chỉ chỗ thiên lệch (kích tục, ngẫu kiến, tạc tuệ), đồng thời vẫn thừa nhận giá trị trị thế–bảo thân. Là bản diễn triết độc lập, khác hẳn *Đạo Đức Kinh chú* cùng tác giả đã bị loại.",key_text:"可者不常，常者無可。",use:"Đọc khi cần bản Lão học phê phán–diễn nghĩa đời Thanh, so với Vương Bật / Tô Triệt / Tiêu Hoành.",sources:["https://zh.wikisource.org/wiki/%E8%88%B9%E5%B1%B1%E9%81%BA%E6%9B%B8/%E8%80%81%E5%AD%90%E8%A1%8D","https://ctext.org/wiki.pl?if=gb&res=3667734"],textual_certainty:"high",notes:"batch75 · Grok-4.5 老庄藏外注疏"},{dz:"null",name_han:"老子本义（魏源）",name_vi:"Lão Tử Bản Nghĩa (Nguỵ Nguyên)",bu:"太玄",author:"魏源",era:"清 / 19th century",topic:"老学",essence:"Bản chú–giải Lão nổi tiếng đời Thanh, nhấn mạnh *Lão Tử* là sách cứu thế chứ không chỉ hư vô xuất thế. Nguỵ Nguyên nối đạo–trị thân–trị nhân, phản đối diễn giải thuần huyền hoặc thuần Phật hóa. Là mốc Lão học cận đại, thường được nêu cạnh *Lão Tử Diễn* và các bản khảo dị.",key_text:"老子之书，上之可以明道，中之可以治身，推之可以治人。",use:"Dùng làm khung ‘Lão học cứu thế’ khi đối chiếu chú giải chính trị–xã hội đời Thanh.",sources:["https://ctext.org/library.pl?if=gb&res=2504","https://zh.wikipedia.org/zh-hans/%E8%80%81%E5%AD%90_(%E6%9B%B8)"],textual_certainty:"high",notes:"batch75 · Grok-4.5 老庄藏外注疏"},{dz:"null",name_han:"老子道德经解（憨山德清）",name_vi:"Lão Tử Đạo Đức Kinh Giải (Hám Sơn Đức Thanh)",bu:"太玄",author:"釋德清（憨山）",era:"明 / 16th–17th century",topic:"老学",essence:"Chú *Đạo Đức Kinh* của cao tăng Hám Sơn, dùng khung Phật–Thiền (chân tâm, Như Lai tạng) để nhiếp Lão. Tác phẩm hoàn thành sau nhiều năm tham cứu, đi đôi với *Trang Tử nội thiên chú* của cùng tác giả. Là bản ‘nhiếp Lão nhập Phật’ tiêu biểu đời Minh, ngoài *Chính thống Đạo tạng*.",key_text:"上德不德，是以有德。",use:"Tham chiếu khi nghiên cứu hội thông Tam giáo / Lão học qua lăng kính Thiền đời Minh.",sources:["https://zh.wikisource.org/zh-hans/%E8%80%81%E5%AD%90%E9%81%93%E5%BE%B7%E7%B6%93%E8%A8%BB","https://book.bfnn.org/books2/1731.htm"],textual_certainty:"high",notes:"batch75 · Grok-4.5 老庄藏外注疏"},{dz:"null",name_han:"道德经注释（黄元吉）",name_vi:"Đạo Đức Kinh Chú Thích (Hoàng Nguyên Cát)",bu:"太玄",author:"黄元吉（黄裳）",era:"清 / 19th century (xuất bản 光绪十年)",topic:"老学",essence:"Còn gọi *Đạo Đức Kinh tinh nghĩa*: mỗi chương trước nói thường đạo / thế pháp, sau chuyển sang đan đạo–nội luyện. Hoàng Nguyên Cát dung Nho–Đạo, coi *Đạo Đức Kinh* là khẩu quyết kim đan. Là chú Lão nội đan có ảnh hưởng lớn đời Thanh–cận đại, không thuộc *Chính thống Đạo tạng*.",key_text:"三教之道，圣道而已。",use:"Đọc khi cần chú Lão theo hướng nội đan–tu luyện (huyền quan, thủ trung).",sources:["https://zh.wikisource.org/wiki/%E9%81%93%E5%BE%B7%E7%B6%93%E6%B3%A8%E9%87%8B_(%E9%BB%83%E5%85%83%E5%90%89)","https://ctext.org/wiki.pl?if=gb&res=782272"],textual_certainty:"high",notes:"batch75 · Grok-4.5 老庄藏外注疏"},{dz:"null",name_han:"老子集解（薛蕙）",name_vi:"Lão Tử Tập Giải (Tiết Huệ)",bu:"太玄",author:"薛蕙",era:"明 / 16th century",topic:"老学",essence:"Tập giải *Lão Tử* theo thứ tự 81 chương bản Vương Bật: trước âm nghĩa từ khóa, sau dẫn chú cũ và kiến giải riêng. Là bản Lão học văn–triết đời Minh được thư mục và *Lão Tử tích thành* ghi nhận, không nằm trong danh chú *Chính thống Đạo tạng* đã loại.",key_text:"null",use:"Dùng làm bản tập giải trung gian giữa Vương Bật và các chú Minh–Thanh.",sources:["https://ctext.org/library.pl?if=en&res=2503","https://www.shuge.org/view/laozi_ji_jie/"],textual_certainty:"high",notes:"batch75 · Grok-4.5 老庄藏外注疏"},{dz:"null",name_han:"老子说略（张尔岐）",name_vi:"Lão Tử Thuyết Lược (Trương Nhĩ Kỳ)",bu:"太玄",author:"张尔岐",era:"清初 / 17th century",topic:"老学",essence:"Bản thuyết–giải Lão ngắn gọn của Trương Nhĩ Kỳ (học giả Sơn Đông, bạn–đồng thời với Cố Viêm Võ). Nằm trong *Lão Tử tích thành* và các thư mục Lão học Thanh sơ. Thiên về nghĩa lý–chương cú súc tích, thuộc tàng ngoại.",key_text:"null",use:"Đọc nhanh để nắm khung Lão học Thanh sơ, đối chiếu với *Lão Tử Diễn* và *Lão Tử Bản nghĩa*.",sources:["https://homeinmists.ilotus.org/%E4%B8%B9%E7%B6%93%E9%81%93%E6%9B%B8/%E8%80%81%E5%AD%90-%E9%81%93%E5%BE%B7%E7%B6%93/%E8%80%81%E5%AD%90%E9%9B%86%E6%88%90%E7%9B%AE%E9%8C%84/","https://baike.baidu.com/item/%E9%81%93%E5%BE%B7%E7%BB%8F/327138"],textual_certainty:"high",notes:"batch75 · Grok-4.5 老庄藏外注疏"},{dz:"null",name_han:"老子章义（姚鼐）",name_vi:"Lão Tử Chương Nghĩa (Diêu Nại)",bu:"太玄",author:"姚鼐",era:"清 / 18th–19th century",topic:"老学",essence:"Chú *Lão Tử* theo chương nghĩa của Diêu Nại (Đồng Thành phái). Nghiêng về văn lý–nghĩa chương, làm sạch các phụ hội quá mức, thuộc dòng Lão học văn nhân đời Thanh. Được *Lão Tử tích thành* và các tổng mục chú Lão ghi nhận.",key_text:"null",use:"Tham chiếu khi cần bản Lão học văn nhân–chương pháp, so với Tiêu Hoành và Nguỵ Nguyên.",sources:["https://homeinmists.ilotus.org/%E4%B8%B9%E7%B6%93%E9%81%93%E6%9B%B8/%E8%80%81%E5%AD%90-%E9%81%93%E5%BE%B7%E7%B6%93/%E8%80%81%E5%AD%90%E9%9B%86%E6%88%90%E7%9B%AE%E9%8C%84/","https://baike.baidu.com/item/%E9%81%93%E5%BE%B7%E7%BB%8F/327138"],textual_certainty:"high",notes:"batch75 · Grok-4.5 老庄藏外注疏"},{dz:"null",name_han:"老子道德经评点（严复）",name_vi:"Lão Tử Đạo Đức Kinh Bình Điểm (Nghiêm Phục)",bu:"太玄",author:"严复",era:"清末民初 / late 19th–early 20th century",topic:"老学",essence:"Bình điểm *Đạo Đức Kinh* của Nghiêm Phục, nối Hoàng–Lão với tư tưởng dân chủ–chính trị cận đại (dài mà không tể, vô vi). Không phải chú huyền giáo truyền thống mà là Lão học cải cách–du nhập Tây học. Có trong *Lão Tử tích thành* và các mục lục chú Lão cận đại.",key_text:"夫黄老之道，民主之国之所用也。",use:"Đọc khi khảo Lão học hiện đại hóa / chính trị học cuối Thanh.",sources:["https://ctext.org/wiki.pl?if=en&browse=1835","https://baike.baidu.com/item/%E9%81%93%E5%BE%B7%E7%BB%8F/327138"],textual_certainty:"high",notes:"batch75 · Grok-4.5 老庄藏外注疏"},{dz:"null",name_han:"南华真经副墨（陆西星）",name_vi:"Nam Hoa Chân Kinh Phó Mặc (Lục Tây Tinh)",bu:"太玄",author:"陆西星（方壶外史）",era:"明 / 16th century",topic:"庄学",essence:"Chú *Trang Tử* (Nam Hoa) của Lục Tây Tinh, xem *Nam Hoa* như chú sớ của *Đạo Đức Kinh*, lấy ‘thường vô hữu’ và ‘xuất vi ư bất vi’ phá chấp. Tiêu Thiên Thạch coi đây là đỉnh Trang học Kim–Nguyên–Minh. Tàng ngoại; khác hẳn *Đạo Đức chân kinh huyền lãm* (đã loại) dù cùng tác giả.",key_text:"南华者，《道德经》之注疏也。",use:"Đọc song song với *Đạo Đức Kinh* khi cần Trang học nội đan–nghĩa lý đời Minh.",sources:["https://zh.wikisource.org/wiki/%E5%8D%97%E8%8F%AF%E7%9C%9F%E7%B6%93%E5%89%AF%E5%A2%A8","https://ctext.org/library.pl?if=gb&res=94791"],textual_certainty:"high",notes:"batch75 · Grok-4.5 老庄藏外注疏"},{dz:"null",name_han:"庄子因（林云铭）",name_vi:"Trang Tử Nhân (Lâm Vân Minh)",bu:"太玄",author:"林云铭",era:"清初 / 17th century",topic:"庄学",essence:"Sáu quyển chú–bình *Trang Tử* theo nhãn quan văn chương–‘pháp’ của Lâm Vân Minh. Nổi tiếng nhờ phân tích cấu trúc–tu từ, phân chân ngụy, ảnh hưởng rộng (kể cả dư ba văn học). Tiền Mục nhận là đường lối trị Trang theo văn pháp, tàng ngoại.",key_text:"null",use:"Học chương pháp–kết cấu *Trang Tử*; so với Tuyên Dĩnh và Hồ Văn Anh.",sources:["https://baike.baidu.com/item/%E5%BA%84%E5%AD%90%E5%9B%A0/1955406","https://ctext.org/wiki.pl?if=gb&res=978550"],textual_certainty:"high",notes:"batch75 · Grok-4.5 老庄藏外注疏"},{dz:"null",name_han:"南华经解（宣颖）",name_vi:"Nam Hoa Kinh Giải (Tuyên Dĩnh)",bu:"太玄",author:"宣颖",era:"清 / 18th century",topic:"庄学",essence:"Chú giải *Nam Hoa kinh* nổi tiếng đời Thanh của Tuyên Dĩnh: lược–giải theo tiết, nhấn mạnh cấu trúc toàn thiên và mạch ý. Được Wikipedia và ctext ghi nhận là bản Trang học Thanh đại tiêu biểu, ngoài *Chính thống Đạo tạng*.",key_text:"null",use:"Đọc khi cần bản giải nghĩa rõ mạch, dễ theo dõi toàn bộ nội–ngoại–tạp thiên.",sources:["https://baike.baidu.com/item/%E5%8D%97%E5%8D%8E%E7%BB%8F%E8%A7%A3/5208551","https://ctext.org/wiki.pl?if=gb&res=8483001"],textual_certainty:"high",notes:"batch75 · Grok-4.5 老庄藏外注疏"},{dz:"null",name_han:"庄子独见（胡文英）",name_vi:"Trang Tử Độc Kiến (Hồ Văn Anh)",bu:"太玄",author:"胡文英",era:"清 / 18th century (Càn Long)",topic:"庄学",essence:"33 quyển chú–giải *Trang Tử*, tên lấy từ ‘độc kiến hiểu yên’ (*Thiên địa*). Kết hợp huấn hỗ–văn bình; nổi tiếng với nhận định ‘Trang Tử mắt cực lạnh, lòng cực nóng’. Bản Trang học phê bình văn–tâm lý đời Thanh, tàng ngoại.",key_text:"庄子眼极冷，心肠最热。",use:"Dùng khi phân tích giọng văn–tình cảm và ‘độc kiến’ từng thiên *Trang Tử*.",sources:["https://baike.baidu.com/item/%E5%BA%84%E5%AD%90%E7%8B%AC%E8%A7%81/1955785","https://baike.baidu.com/item/%E5%BA%84%E5%AD%90/8074"],textual_certainty:"high",notes:"batch75 · Grok-4.5 老庄藏外注疏"},{dz:"null",name_han:"庄子雪（陆树芝）",name_vi:"Trang Tử Tuyết (Lục Thụ Chi)",bu:"太玄",author:"陆树芝",era:"清 / Gia Khánh (xuất bản khoảng 1796–1820)",topic:"庄学",essence:"Tác phẩm nghiên cứu–chú bình *Trang Tử* của Lục Thụ Chi đời Thanh; bản Gia Khánh Văn Tuyển lâu làm đểi bản, được Hoa Đông Sư Phạm điểm hiệu. Nằm trong dòng bình điểm Trang học Thanh đại, tàng ngoại, khác các bản *Chính thống Đạo tạng* đã liệt kê.",key_text:"null",use:"Bổ sung góc nhìn bình điểm Thanh đại bên cạnh Lâm Vân Minh–Tuyên Dĩnh–Hồ Văn Anh.",sources:["https://baike.baidu.com/item/%E5%BA%84%E5%AD%90%E9%9B%AA/7259727","https://zh.wikipedia.org/wiki/%E8%8E%8A%E5%AD%90_(%E6%9B%B8)"],textual_certainty:"high",notes:"batch75 · Grok-4.5 老庄藏外注疏"},{dz:"null",name_han:"庄子集解（王先谦）",name_vi:"Trang Tử Tập Giải (Vương Tiên Khiêm)",bu:"太玄",author:"王先谦",era:"清末 / late 19th century",topic:"庄学",essence:"Tập giải *Trang Tử* súc tích của Vương Tiên Khiêm: chọn lọc chú cũ, thêm kiến giải, dễ đọc hơn *Tập thích*. Là bản nhập môn–tham khảo học thuật chuẩn cuối Thanh, thuộc tàng ngoại / học án cận đại, không phải chú *Chính thống Đạo tạng*.",key_text:"null",use:"Bản đọc chính khi cần chú giải gọn, đối chiếu nhanh với Quách Tượng–Thành Huyền Anh.",sources:["https://zh.wikipedia.org/wiki/%E8%8E%8A%E5%AD%90_(%E6%9B%B8)","https://ctext.org/wiki.pl?if=gb&chapter=26"],textual_certainty:"high",notes:"batch75 · Grok-4.5 老庄藏外注疏"},{dz:"null",name_han:"庄子集释（郭庆藩）",name_vi:"Trang Tử Tập Thích (Quách Khánh Phiên)",bu:"太玄",author:"郭庆藩",era:"清末 / late 19th century",topic:"庄学",essence:"Tập thích đồ sộ: gom Quách Tượng chú, Thành Huyền Anh sớ, thêm huấn hỗ–dị văn của học giả Thanh. Được Trung Hoa thư cục điểm hiệu (Vương Hiếu Ngư), trở thành bản học thuật chuẩn cận–hiện đại. Tàng ngoại / tập thích khảo cứ, không trùng các chú *Đạo tạng* đã loại.",key_text:"null",use:"Tra cứu dị văn–chú sớ cổ khi làm nghiên cứu văn bản *Trang Tử*.",sources:["https://zh.wikisource.org/wiki/%E8%8E%8A%E5%AD%90%E9%9B%86%E9%87%8B","https://ctext.org/wiki.pl?if=gb&res=795476"],textual_certainty:"high",notes:"batch75 · Grok-4.5 老庄藏外注疏"}],t=new Set;function c(n){let h=n,i=2;for(;t.has(h);)h=`${n}_${i++}`;return t.add(h),h}const e=a.filter(n=>n&&n.name_han&&Array.isArray(n.sources)&&n.sources.length>=2).map(n=>({id:c("DZ_"+(n.name_han||"").replace(/[^一-龥]/g,"")),layer:"daozang",name_han:n.name_han,name_vi:n.name_vi||"",school:`${n.bu||"道藏"} bộ`+(n.author?` · ${n.author}`:"")+(n.era?` · ${n.era}`:""),han_text:n.key_text||"",meaning:n.essence||"",use:n.use||"",sources:Array.isArray(n.sources)?n.sources.filter(Boolean):[],textual_certainty:n.textual_certainty||"partial",bu:n.bu||"",author:n.author||"",era:n.era||"",topic:n.topic||"",notes:(n.dz?`道藏 ${n.dz}`:"道藏 kinh")+(n.notes?" · "+n.notes:"")}));export{e as D};
